INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73ko0001eh0s0t2v279k', 'COLCHOES DOCTORS', 'colchoes-doctors', NULL, 'Casa e Construção', 'MÓVEIS', 'industria de colchão, distribui produtos por ela fabricados', 2020, 2020, NULL, '2026-04-01 02:00:00.190', '2025-08-05 22:20:24.024', 38, NULL, 1, 2010, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/47f8d381-c91b-4f3c-8022-cde0f3d41767.png', 1, NULL, NULL, '2025-09-22 15:33:53.000', 'https://franquias.portaldofranchising.com.br/franquia-colchoes-doctors-casa-e-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73kx0002eh0s4qyjorou', 'STAR POINT', 'star-point', NULL, 'Moda', 'Vestuários', 'Rede de lojas especializadas na comercialização de equipamentos de surf e skate, acessórios moda praia e surfwear', 2000, 2005, '[\"https://www.youtube.com/watch?v=false\"]', '2026-04-01 02:00:00.205', '2025-08-05 22:20:24.033', 39, NULL, 1, 1982, 'A Star Point é uma rede de lojas franqueadas especializada na comercialização de produtos masculinos e femininos moda praia, surf e skate, e possui as mais renomadas marcas nacionais e internacionais. O mix de produtos é composto por camisetas, calças, bermudas, jaquetas, biquínis, maiôs, óculos, relógios, tênis, pranchas e equipamentos de surf e skate. \nDesde 1984, a Star Point é apontada como a melhor surf shop em todas as pesquisas das principais revistas de surf no país. Em 2004 foi reconhecida como a “Loja do Ano” por um colégio eleitoral composto por representantes da mídia e entidades do setor, fato que se repetiu em 2006. Em 2010 conquistou o Prêmio de Design que premia arquitetura e ambientação de loja, promovido pela ABF / Retail Design Institute (RDI), prêmio também conquistado em 2012. Ainda em 2010 o prêmio \"Os melhores da Praia” concedido pela revista Alma Surf fato que se repetiu também em 2011.      \nDesde 2000 a Star Point resolveu expandir seus limites e formatou um projeto de franquia e como não poderia deixar de ser, o sucesso se repetiu nessas lojas, que multiplicam, a cada dia, o conceito de uma \"surf shop for real surfers\". A Star Point conta com lojas situadas nos melhores shoppings do Brasil. Como empresa franqueadora conquistou em 2011 o selo de excelência em franchising pela ABF (Associação Brasileira de Franchising) e o prêmio Alshop (Associação Brasileira de Lojistas de Shoppings) na categoria moda surf. \nA contínua busca por inovações e tendências, acompanhadas de um atendimento com excelência, tornam a Star Point uma referência em seu segmento. A Star Point oferece uma série de vantagens aos franqueados, como a assessoria na seleção de ponto comercial, planejamento financeiro, suporte e treinamento para equipe, além de ações de marketing. \nA Star Point busca candidatos para as principais cidades do País.', NULL, 'SÃO PAULO', 1, NULL, 11, NULL, NULL, '2026-03-08 16:10:54.263', 'https://franquias.portaldofranchising.com.br/franquia-star-point-vestuario/', NULL, NULL, '[]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '435000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
