INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73lf0004eh0skexuazlc', 'FARMÁCIA PERSONALE', 'farmacia-personale', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'A Personale é a maior rede de farmácias de manipulação genuinamente paraense com mais de 30 anos de experiência. Nossa maior vocação é CUIDAR! Temos o compromisso de levar mais saúde para as pessoas.', 2020, 2021, NULL, '2026-04-01 02:00:00.243', '2025-08-05 22:20:24.052', 41, NULL, 1, 1989, '', NULL, 'PARÁ', 1, NULL, 6, NULL, NULL, '2026-03-08 16:12:05.011', 'https://franquias.portaldofranchising.com.br/franquia-farmacia-personale/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73ll0005eh0sfyvwydkc', 'SPIDER KICK', 'spider-kick', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Studio de treinamento funcional com elementos da preparação física do Anderson Silva, que utiliza a metodologia HIIT e monitoramento cardíaco do cliente durante toda a experiência de treino.', 2021, 2021, '[\"https://www.youtube.com/watch?v=qT_dOTOzBZ4\"]', '2026-04-01 02:00:00.256', '2025-08-05 22:20:24.058', 42, NULL, 1, 2020, 'A SPIDER KICK nasceu da parceria entre o maior campeão de todos os tempos no MMA, Anderson Silva, e a experiência de um dos maiores nomes do fitness nacional, Fernando Nero, que dentre suas realizações empreendedoras de sucesso fundou e geriu, durante os quatro primeiros anos, a Bluefit, a segunda maior rede do país.    \nÉ um modelo de microacademia especializada capaz de proporcionar o melhor custo-benefício aos alunos e a possibilidade de alta rentabilidade aos franqueados. \nOferece sessões de treino previamente agendadas, com duração de até 60 minutos, sob o método de treinamento intervalado de alta intensidade, que utiliza elementos das artes marciais, realiza o controle de frequência cardíaca do aluno como forma de estimulá-lo a atingir seus objetivos e, ainda, utiliza a tecnologia a favor da experiência do aluno. \nTodas as aulas são planejadas e testadas previamente e seu conteúdo varia diariamente, alternando exercícios, grupos musculares, movimentos, tempo, intervalo, carga, velocidade. \nOs treinos nunca se repetem, porém, por se tratar de um Sistema de Franquia, no mesmo dia todas as unidades devem realizar exatamente o mesmo treino, promovendo assim uma troca de experiência entre os alunos e profissionais, os quais deverão ter seu registro ativo no Conselho Federal/Regional de Educação Física. \nPeriodicamente, e a critério exclusivo da franqueadora, as atividades propostas na metodologia poderão sofrer alteração conforme demanda do mercado.  \nPor se tratar de um modelo de microacademias especializadas, as unidades SPIDER KICK atendem um número pré-determinado de alunos ao mesmo tempo, cujos treinos devem ser agendados por meio de um aplicativo específico. \nA precificação das unidades é feita com base em pesquisa de mercado e da concorrência. Por isso, o franqueado deverá seguir rigorosamente as orientações estabelecidas pela franqueadora.  Sob a ótica do consumidor, os principais diferenciais da SPIDER KICK são:\n(a) oferecer um treino de alta intensidade com monitoramento cardíaco durante toda a sessão, permitindo ao aluno controlar a intensidade e observar seu próprio desempenho; e\n(b) utilizar os elementos de artes marciais na sessão de treino, empoderando o aluno e criando um maior senso de equipe. Além disso, sob a ótica do parceiro franqueado, ainda temos, como principais diferenciais:\n(c) o valor de investimento acessível com possibilidade de grande rentabilidade;\n(d) a oferta dos melhores pontos e regiões aos franqueados, eliminando qualquer conflito por território; e\n(e) a possibilidade de financiamento das obras para instalação da unidade franqueada (exclusivamente para os candidatos que forem elegíveis a critério da franqueadora, após análise documental e de capacidade de pagamento). \nTodo o conceito do negócio, identidade visual, padronização de processos, recrutamento e treinamento de profissionais, política comercial, oferta de serviços e procedimentos operacionais foram cuidadosamente planejados para gerar escalabilidade e disponibilizar ao franqueado um modelo fácil de operar e com grande atratividade ao consumidor. \nCom um aprendizado desenvolvido sobre os diferentes modelos de microacademias existentes no Brasil e no mundo, a SPIDER KICK traz ao mercado um formato atrativo para diferentes territórios e perfis de investidor. As unidades são instaladas em regiões de alto fluxo de pessoas e devem ter área construída entre 250 m² e 400 m², em pavimento único, podendo ser uma loja de rua ou localizada em centros comerciais e shopping centers.  \nTodo o know how desenvolvido pela franqueadora é repassado aos franqueados por meio do sistema de franquia SPIDER KICK, que visa capacitar os franqueados para operar uma unidade com o mais alto padrão de qualidade, entregando uma experiência exclusiva aos alunos.   O sistema de franquias SPIDER KICK disponibiliza ao seu franqueado: Suporte completo na escolha do ponto comercial. Caderno Técnico de Arquitetura e Escritório(s) de Arquitetura homologado(s) para a confecção do projeto arquitetônico e compatibilização deste com os projetos complementares. Análise dos relatórios de obra e construção com o objetivo de garantir o padrão arquitetônico SPIDER KICK. Fornecedores homologados para a execução da obra, bem como para a compra dos materiais e equipamentos necessários à instalação de uma unidade. Treinamento Inicial (Operacional e Técnico) para o gestor e os colaboradores da primeira equipe da unidade franqueada, bem como plataforma para Educação Continuada, que inclui treinamento aos novos colaboradores. Manual de Operações para assegurar a transferência de know how sobre como operar uma unidade franqueada SPIDER KICK; Recomendação de precificação adequada para cada praça. Sessões de treino (workouts) pré-determinados para que no mesmo dia sejam aplicados simultaneamente em todas as unidades SPIDER KICK. Planejamento de Marketing inaugural, comunicação visual padronizada, acompanhamento de performance digital e gerenciamento de toda a estratégia de comunicação do franqueado com o consumidor final. Sistema operacional (software de gestão) previamente homologado pela franqueadora. Consultoria de campo, auditoria e relatórios periódicos de indicadores de desempenho.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/df5e1384-b8ee-4631-8ff0-7340a93e522e.jpg', 5, NULL, NULL, '2026-03-08 17:05:34.672', 'https://franquias.portaldofranchising.com.br/franquia-spider-kick/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '370000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73ls0006eh0sbltth6xt', 'BRASIL CANADÁ - EDUCAÇÃO BILÍNGUE', 'brasil-canada-educacao-bilingue', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'O Brasil Canadá – Educação Bilíngue é uma rede de escolas que atua há 20 anos com ensino infantil e fundamental através de uma proposta eficaz e de altíssima qualidade.', 2017, 2019, NULL, '2026-04-01 02:00:00.268', '2025-08-05 22:20:24.064', 43, NULL, 1, 2000, '', NULL, 'SÃO PAULO', 1, NULL, 6, NULL, NULL, '2026-03-08 17:25:56.418', 'https://franquias.portaldofranchising.com.br/franquia-brasil-canada-educacao-bilingue/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73lx0007eh0sy4dmr2p3', 'CYMACO', 'cymaco', NULL, 'Casa e Construção', 'Construção e Reforma', 'Prestação de serviços para a construção civil/ Sistema de Construções Inteligentes', 2008, 2010, NULL, '2026-04-01 02:00:00.280', '2025-08-05 22:20:24.070', 44, NULL, 1, 2000, 'FRANQUIA Sabemos que a decisão de ter uma franquia, vai além de valores financeiros. A ESCOLHA DA FRANQUIA, antes de tudo deve ser baseada em AFINIDADE COM A ÁREA E COMPROMETIMENTO de ambas partes, para que o negócio traga um ótimo resultado. E é por isso que nós temos o compromisso de levar para você, uma marca sólida, preparada e de SUCESSO. Fazer parte da CYMACO, é poder contar com toda a expertise de 40 anos de presença no mercado, constante inovação e suporte para grandes obras feitas por uma empresa que já é fortemente estabelecida e em constante desenvolvimento. Estamos presentes em 5 estados do Brasil em 8 unidades. O Setor da construção é responsável por 60% da composição do PIB total da cadeia produtiva da construção, somada a 5,7% de serviços (Fonte: ABRAMAT FGV 2018). O aumento da demanda de reparos e melhorias nos imóveis, tem tornado esse número ainda mais expressivo. A CYMACO oferece SERVIÇOS - que englobam Manutenção Predial e Retrofit - e CONSTRUÇÕES INTELIGENTES. Sendo um franqueado CYMACO você pode optar por um desses dois tipos de franquia. Mas vamos te explicar abaixo o que é tudo isso.  MANUTENÇÃO PREDIAL MANUTENÇÃO PREDIAL são todas as atividades de manutenção de prédios ou empreendimentos, relativos à pequenas reformas, reparos, recuperação estrutural,  manutenções preventivas necessárias que impedem o surgimento de problemas, manutenções corretivas, como resolver infiltrações, trocar pastilhas, pintar o prédio entre outros problemas que toda estrutura pode ter.  RETROFIT O RETROFIT é a renovação de um condomínio, casa ou loja, onde há significativas modificações que vão além daquelas pequenas reformas. Vai desde troca de elevadores, modernização de sistemas elétricos, hidráulicos, atualização dos sistemas de segurança até a modificação da fachada, para a modernização também estética do prédio. Esse serviço surgiu na Europa com o intuito de se modernizarem os prédios mais antigos para melhorar a sua funcionalidade, aspecto e segurança. Essa técnica chegou ao Brasil e a Cymaco tem orgulho em ser a empresa que mais executou Retrofit no Brasil. O resultado? MORADORES SATISFEITOS, IMÓVEL MAIS ECONÔMICO E MUITO MAIS VALORIZADO. Nem você sabia que essa modernização era tão forte, não é mesmo?  CONSTRUÇÕES INTELIGENTES Então vamos para as CONSTRUÇÕES INTELIGENTES. Imagine uma obra que demora 60% a menos do tempo convencional e tem 80% na redução da mão de obra. Estamos falando das construções inteligentes. A Construção Inteligente consiste na produção em escala, de paredes e lajes em concreto armado levando para a obra paredes prontas e rebocadas.  Este sistema utiliza os mesmos materiais do sistema convencional, com a vantagem de incorporar às paredes e lajes os dutos e as tubulações e fazer toda a obra em menos tempo, com MENOS MÃO DE OBRA E MENOR CUSTO. A Construção Inteligente influencia diretamente no gasto de todas as fases da obra, por isso ela DIMINUI EM 40% O INVESTIMENTO por metro quadrado construído e ainda otimiza a utilização de materiais fazendo cair em 20% O DESPERDÍCIO DE MATERIAIS e é também uma alternativa para a construção e para a dificuldade em contratação de mão de obra. Veja algumas etapas do processo:  *dependendo do tamanho das obras Se você é engenheiro ou arquiteto a CYMACO com certeza é a franquia certa para você! Mas se você não é da área, pode ficar tranquilo: é necessário apenas que você tenha na franquia um engenheiro contratado. Clique no formulário abaixo ou visite o nosso site para falar diretamente com o nosso Diretor e ter mais informações sobre a franquia que ajuda a TRANSFORMAR e CONSTRUIR a vida dos brasileiros! MAIS SUCESSO, MAIS CYMACO.', NULL, 'SANTA CATARINA', 1, NULL, 9, NULL, NULL, '2026-03-08 16:42:08.572', 'https://franquias.portaldofranchising.com.br/franquia-cymaco/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '310000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73m40008eh0sa9ccwkdb', 'FOLLOW ME', 'follow-me', NULL, 'Educação', 'Idiomas', 'Escola de Idiomas', 2023, 2023, NULL, '2026-04-01 02:00:00.292', '2025-08-05 22:20:24.076', 45, NULL, 1, 2019, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/428c1af0-a3fb-43c4-b765-de9986d81525.jpg', 2, NULL, NULL, '2026-03-09 14:26:49.673', 'https://franquias.portaldofranchising.com.br/franquia-follow-me/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73m90009eh0s4echl139', 'ATHUS', 'athus', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escolas de Ensino de Idiomas Método próprio de Inglês', 2004, 2018, '[\"https://www.youtube.com/watch?v=rm3fbdAqw6Y\",\"https://www.youtube.com/watch?v=wS2e8HqCgOk\",\"https://www.youtube.com/watch?v=60lHumNQEn4\",\"https://www.youtube.com/watch?v=-Xo-8nhKJtc\"]', '2026-04-01 02:00:00.304', '2025-08-05 22:20:24.082', 46, NULL, 1, 2004, 'Foi com objetivo de atender uma enorme demanda para o ensino de Inglês de forma diferenciada, e também de construir um sistema de franchising que trouxesse o sucesso empresarial para os futuros Franqueados, que em 2004 foi fundada a ATHUS. No primeiro momento, a rede ATHUS cresceu baseada exclusivamente na grandiosa qualidade de seu método. Os primeiros Franqueados foram pessoas que, em sua maioria, eram professores de Inglês experientes e que se encantaram pela nova maneira de ensinar Inglês que o método ATHUS permitia. Paralelamente, a FRANQUEADORA buscava incessantemente desenvolver sistemas de gestão da Unidade, captação de alunos, e formas de transformar cada Unidade ATHUS numa fábrica de grande satisfação para os alunos e excelentes lucros para o FRANQUEADO. Com isso, a experiência da FRANQUEADORA em captação de alunos e gestão de Unidades se multiplicou. Foi aí que no início de 2006, a ATHUS passou a ofertar aos consumidores, de forma inédita, um menu de cursos, trazendo opções aos alunos. Este foi um grande marco, que resultou em grande melhora nos lucros de todas as Unidades da rede. E é esta experiência, este método e este know-how, que exigiu da FRANQUEADORA, cinco anos de pesquisa e por enquanto mais quatorze anos de atividades com a marca, que se oferta de maneira organizada no sistema de franchising ATHUS. Todos esses anos se transferem ao FRANQUEADO pelo contrato de franquia, com o treinamento inicial e posteriores treinamentos propiciados pela FRANQUEADORA conforme cada fase por que passe a Unidade Franqueada.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/614e7d2b-9e2e-4a7f-b9e4-2160f42c1573.jpg', 29, NULL, NULL, '2026-03-08 16:44:11.491', 'https://franquias.portaldofranchising.com.br/franquia-athus/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '82000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
