INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73nx000keh0sn5u0iwed', 'SALINAS', 'salinas', NULL, 'Moda', 'Acessórios Pessoais', 'A Salinas é uma marca de beachwear qualidade premium made in Rio de Janeiro, que se comunica através de uma linguagem descontraída.', 2002, 2023, NULL, '2026-04-01 02:00:00.439', '2025-08-05 22:20:24.141', 57, NULL, 1, 1982, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/382f0874-e67f-47e2-8aff-cd5f1db6d021.jpeg', 27, NULL, NULL, '2026-03-08 17:32:20.728', 'https://franquias.portaldofranchising.com.br/franquia-salinas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '350000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73o2000leh0s0qnm7d6b', 'SUSHI EM CASA', 'sushi-em-casa', NULL, 'Alimentação', 'Bares e Restaurantes', 'Modelo baseado em delivery de comida japonesa, com possibilidade de extensões para retirada e consumo no local;', 2019, 2023, '[\"https://www.youtube.com/watch?v=vn8MlyN1ZNs\",\"https://www.youtube.com/watch?v=q9VxQiMit7I\"]', '2026-04-01 02:00:00.451', '2025-08-05 22:20:24.146', 58, NULL, 1, 2019, 'Em meados de 2007, durante um intercâmbio na Austrália, nosso sócio fundador Bruno teve a oportunidade de conhecer novos amigos japoneses que o introduziram à culinária oriental. Inspirado por suas experiências práticas nessa terra estrangeira, Bruno retornou ao Brasil e imediatamente começou a ministrar cursos sobre a arte de fazer sushi. Com o tempo, sua paixão pela culinária japonesa o levou a realizar eventos em diferentes ocasiões, incluindo casamentos, formaturas e aniversários. Diante da crescente demanda, Bruno decidiu arriscar algo novo em 2015, inaugurando o Sushi em Casa Delivery dentro de seu condomínio. O objetivo era oferecer aos alunos e clientes o melhor da culinária japonesa, entregando-a diretamente em suas casas. O sucesso dessa iniciativa foi notável e, em 2018, juntamente com seus sócios, iniciou-se o processo de expansão da marca. Atualmente, o Sushi em Casa conta com dez unidades, sendo seis localizadas no interior de São Paulo, uma em Jundiaí e três em São Paulo capital.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f2bc5c97-ec00-4802-998a-835fb8a977b2.jpg', 10, NULL, NULL, '2026-03-08 17:32:43.420', 'https://franquias.portaldofranchising.com.br/franquia-sushi-em-casa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73o7000meh0sk4btx1bd', 'SEGCREDI', 'segcredi', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Serviços financeiros, crédito consignado, financiamentos e refinanciamentos, crédito pessoal, cartões de crédito e consórcio.', 2017, 2018, NULL, '2026-04-01 02:00:00.462', '2025-08-05 22:20:24.151', 59, NULL, 1, 2017, 'A Segcredi faz parte do Grupo Zanon - Holding de Franquias que possui alta experiência no mercado de franchising, atua em vários segmentos e está presente em todo o território brasileiro. Atualmente o Grupo Zanon é responsável por comercializar mais de 1.500 unidades dentre as 6 marcas consolidadas no Brasil: Segcredi, Seguralta, Los Mex, Derma Nail, Bionatus e Belinda.\nA Segcredi atingiu mais de 100 unidades com 1 mês de atuação graças ao know how na área de franquias. Oferecemos soluções financeiras aos nossos clientes através de consórcios e os mais diversos produtos financeiros, como crédito consignado, financiamento de veículos, crédito pessoal, entre outros. \nTrabalhamos com parceiros homologados e credenciados, assim disponibilizamos diversas opções de produtos com o objetivo de proporcionar a chance de organizar a vida financeira, além de abrir espaço para idealizar objetivos e realizar sonhos.  TRANQUILIDADE FINANCEIRA NÃO TEM PREÇO. \nPODE CONTAR COM A GENTE. \nTemos 2 modelos de negócio, faça sua escolha para o caminho do sucesso!! \nStandard | Office | \nParticipe do mercado que supera a marca de R$20 bi em movimentações, cresce acima de 11,5% ao ano e tenha um negócio com baixo capital de giro e custo operacional com rápido retorno do seu investimento e todo suporte que somente o Grupo Zanon pode te oferecer.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f1995f4e-a712-4744-80a6-344f78d14165.jpg', NULL, NULL, NULL, '2026-03-08 17:33:25.263', 'https://franquias.portaldofranchising.com.br/franquia-segcredi/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73od000neh0s3lr0kmyn', 'ELAV LAVANDERIA', 'elav-lavanderia', NULL, 'Limpeza e Conservação', 'Lavanderia', 'Lavanderia inovadora, especialista em gerar economia e qualidade para clientes e franqueados. Atendemos a famílias, segmentos específicos de empresas e lavagens avulsas.', 2019, 2020, '[\"https://www.youtube.com/watch?v=q0mCsPcytiQ\",\"https://www.youtube.com/watch?v=Lik4v6-6MQw\",\"https://www.youtube.com/watch?v=TFPPVqhntxE\",\"https://www.youtube.com/watch?v=050uMWdKejc\"]', '2026-04-01 02:00:00.473', '2025-08-05 22:20:24.157', 60, NULL, 1, 2015, 'A eLav Lavanderia® nasceu em 2019 quando surgiu, por parte do empresário Fernando Reis Vigato, a ideia de construir um modelo de lavanderia especializada, com alta qualidade e preços acessíveis. Analisando o mercado, o empresário percebeu uma crescente busca pelo serviço de lavanderia especializada, com base em um novo estilo de vida onde a praticidade e qualidade é cada vez mais a prioridade na vida das pessoas de classe B, AB e A. Apesar das vantagens em contratar uma lavanderia e da tendência crescente desse segmento, Fernando percebeu que a maioria das lavanderias praticavam um preço muito alto e pouco acessível para pessoas de classe média, com baixa qualidade de atendimento e prestação de serviços. Quando o empresário iniciou no ramo, em 2015, começou a rever os processos operacionais para entregar o melhor serviço de lavanderia do mercado, ao mesmo tempo baratear o valor do serviço, ajustando a configuração das máquinas, comprando novos equipamentos, usufruindo da tecnologia e dos sistemas para agilizar a operação e economizar nos custos. Ganhando mercado e se destacando na cidade de Varginha-MG, origem da eLav, Fernando decidiu em 2019 formatar o modelo de franquias, compartilhando know-how especializado. Desde então, a franquia eLav cresce a cada ano, hoje atingindo mais de 140 unidades, em todo o Brasil. A eLav é uma marca que se destaca no mercado de lavanderias especializadas, com uma entrega de alto nível de qualidade a um valor acessível a seus clientes. Nosso diferencial está na transferência de know-how, de donos de lavanderia, com mais de 140 unidades e suporte ao franqueado em todas as áreas fundamentais para o sucesso do negócio: suporte operacional, de implantação, de marketing e bem-estar. Nosso posicionamento de mercado é um grande diferencial, pois atingimos as classes B, AB e A, tendo como principal público a classe AB que é onde há o maior crescimento no número de novos usuários do serviço de lavanderia.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/66c721bf-9049-4b22-bb22-6ce4b46219ed.png', 87, NULL, NULL, '2026-03-08 17:34:17.858', 'https://franquias.portaldofranchising.com.br/franquia-elav-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
