INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73on000peh0sg778i9jm', 'DNA IMOVEIS', 'dna-imoveis', NULL, 'Casa e Construção', 'Serviços e Imobiliárias', 'Intermediação na compra e venda de imóveis', 2022, 2023, NULL, '2026-04-01 02:00:00.495', '2025-08-05 22:20:24.168', 62, NULL, 1, 1995, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/252e668a-c58f-45b8-910f-5546344c65cd.png', 1, NULL, NULL, '2026-03-08 17:35:40.099', 'https://franquias.portaldofranchising.com.br/franquia-dna-imoveis-casa-e-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73os000qeh0sx6yungjz', 'VIVA EVENTOS', 'viva-eventos', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e Recreação', 'Empresa de produção de eventos de formaturas. Auxilia os clientes na gestão e na contratação dos serviços', 2012, 2013, '[\"https://www.youtube.com/watch?v=FpsWFhiFCNQ\",\"https://www.youtube.com/watch?v=Yq0BvJksHZY\",\"https://www.youtube.com/watch?v=fR3nFvvOjzo\",\"https://www.youtube.com/watch?v=7eZ4otq1N9o\",\"https://www.youtube.com/watch?v=Hje6sx5xN3s\"]', '2026-04-01 02:00:00.509', '2025-08-05 22:20:24.173', 63, NULL, 1, 2007, 'Por que ser um Franqueado VIVA EVENTOS? Já pensou em fazer parte de um mercado dinâmico, em franco crescimento e que pode dobrar de tamanho na próxima década? Melhor ainda: Se posicionar neste mercado através de uma marca forte, que alia tecnologia e know-how para entregar produtos e serviços de alta qualidade, proporcionando felicidade e satisfação de seus clientes! O mercado de eventos cresceu mais de 14% no último ano e a VIVA Eventos está em pleno processo de expansão nacional, selecionado franqueados que possam levar a marca e a sua cultura para todos as regiões do país. Para garantir a qualidade do serviço prestado por todos os franqueados, a rede tem um setor de inovação voltado para novos produtos e serviços, o VIVA Lab; uma universidade corporativa focada em treinamentos EAD para aperfeiçoamento dos franqueados e de suas equipes (VIVA Academy); software próprio de gestão para garantir maior eficiência administrativa e financeira; aplicativo exclusivo para gestão do fundo de formatura pelos formandos; sistema financeiro online próprio para uso do cliente final; setor de qualidade; modelo de festas personalizadas, as Privates VIVA; e portfólio exclusivo de itens de decoração para formaturas. A capilaridade do modelo VIVA permite que todos os diferenciais e novos produtos sejam rapidamente aderidos por toda a rede e disponibilizado aos clientes.     História da franquia VIVA EVENTOS\n  A VIVA Eventos nasceu de uma inquietação... ou melhor, de cinco. Com a insatisfação natural de empreendedores e o espírito revolucionário típico dos jovens, cinco amigos passaram a criar diversos eventos universitários, sempre apostando no lançamento de novos produtos e inovações no mercado. E foram justamente essas inovações a mola propulsora da VIVA Eventos. Percebendo que o mercado de empresas de formatura não era muito aberto a mudanças, resolveram eles próprios criar uma empresa que agregasse criatividade, e profissionalismo. Assim, em 2007 nascia em Juiz de Fora (MG) a VIVA Eventos, com a promessa de revolucionar o mercado de formaturas da região – e, posteriormente, de todo o Brasil. O clima descontraído da empresa, aliado à sensibilidade no relacionamento com clientes, colaboradores e fornecedores, fez da VIVA Eventos um sucesso imediato. Nos primeiros oito meses de funcionamento a empresa se tornou líder de mercado em tempo recorde. Atendendo atualmente a mais de 200 cidades, com 24 franquias em 5 estados do Sudeste e do Sul do Brasil, a VIVA Eventos, originada em Juiz de Fora (MG), é a primeira rede de franquias de festas de formatura do país. Com gestão financeira inovadora, a empresa traz a atmosfera – e a postura – das startups para dentro de seu modelo de negócios com aposta em metodologias ágeis, baseada no uso da tecnologia, para levar sua expertise em formaturas a todas as regiões brasileiras. Com o mercado cada vez mais profissionalizado, é preciso dedicação redobrada para entregar festas de excelência. E é nesse contexto que a VIVA Eventos se destaca por meio da inovação tecnológica. A empresa foi fundada em 2007 e se tornou referência no ramo. Em 2012, quando se associou à ABF (Associação Brasileira de Franchising), a empresa não identificou nenhum modelo de negócios semelhante no mundo. De lá para cá a empresa cresce a uma taxa superior a 40% ao ano. Nos planos de crescimento da empresa, está a presença em todos os estados brasileiros até 2023, alcançando 80 franquias. A VIVA Eventos é hoje seguramente a maior empresa de formaturas do Brasil e o principal case de sucesso na área, sendo uma referência no mercado nacional. Marca forte, associada a robustez e credibilidade, mas sem perder o espírito jovial e inovador que fez com que a empresa chegasse tão longe em tão pouco tempo.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/562609c7-9098-4399-aac1-dc84c9359724.jpg', 38, NULL, NULL, '2026-03-08 17:36:06.067', 'https://franquias.portaldofranchising.com.br/franquia-viva-eventos-entretenimento-e-lazer/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73oz000reh0svu40n55l', 'CASA DAS CUECAS', 'casa-das-cuecas', NULL, 'Moda', 'Vestuários', 'Loja de vestuário masculino especializada em Underwear e Homewear, do infantil ao plus size.', 2005, 2006, NULL, '2026-04-01 02:00:00.523', '2025-08-05 22:20:24.179', 64, NULL, 1, 1968, 'A CASA DAS CUECAS é uma das principais marcas de moda masculina do mercado brasileiro. Fundada em 1968, a marca conta com 51 anos de história, sendo conhecida no mercado como líder em seu segmento e mantendo há 5 décadas seu maior compromisso: oferecer sempre o mais alto padrão de qualidade em todos os produtos, garantindo máximo conforto e bem-estar a todos os consumidores. A CASA DAS CUECAS comercializa com exclusividade os produtos da marca UW, criada para trazer diferenciação ao mercado e atender as necessidades de um público masculino bastante exigente. Com peças que vão da cama à rua, a franquia CASA DAS CUECAS oferece praticidade, versatilidade e conforto para todos os momentos do dia do homem. Do infantil ao plus size, do underwear ao outwear, para cuecas de todos os tamanhos, estilos e preferências.  Com o objetivo de provar que não é necessário abrir mão do conforto para estar bem vestido nas mais variadas situações, a CASA DAS CUECAS apresenta um amplo portfólio de produtos para usar fora de casa, como camisetas, bermudas, calças e blusas de moletom, além das linhas térmica e praia.  Atualmente a CASA DAS CUECAS conta com a força do Grupo MARCYN na operação, trazendo ainda mais solidez, capacidade industrial e financeira, além de profissionais experientes e qualificados. O grupo MARCYN foi fundado em 1983 pela família Zaborowsky e já está em sua 3ª geração à frente do negócio.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4f1a0475-b2c2-4d2d-8036-0ffd78f72e32.svg', 33, NULL, NULL, '2026-03-08 17:37:47.061', 'https://franquias.portaldofranchising.com.br/franquia-casa-das-cuecas-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
