INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73pn000veh0spx6mewjf', 'ANIMAL FARMA MANIPULAÇÃO VETERINÁRIA', 'animal-farma-manipulacao-veterinaria', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'FARMÁCIA DE MANIPULAÇÃO VETERINÁRIA', 2010, 2024, NULL, '2026-04-01 02:00:00.575', '2025-08-05 22:20:24.203', 68, NULL, 1, 2008, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b21c0a63-3776-459c-8da3-78473a4401d9.svg', 9, NULL, NULL, '2026-03-08 17:39:17.667', 'https://franquias.portaldofranchising.com.br/franquia-animal-farma-manipulacao-veterinaria-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '240000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73pv000weh0svlbznik6', 'MAGIC FEET', 'magic-feet', NULL, 'Moda', 'Calçados', 'CALÇADOS, TÊNIS, ACESSÓRIOS EM GERAL COMO BOLSAS, MOCHILAS, BOLAS,MEIAS E CONFECÇÕES INFANTIS E INFANTO JUVENIS', 2008, 2009, NULL, '2026-04-01 02:00:00.587', '2025-08-05 22:20:24.212', 69, NULL, 1, 2008, 'Fundada em 2008, pelo Grupo Afeet, a Franquia Magic Feet é a maior rede de lojas de calçados infantis do Brasil e fruto da oportunidade detectada pela companhia de lançar um player forte no nicho infantil. \nA rede oferece diversos estilos para crianças de 0 a 10 anos, atendimento personalizado e grande variedade de produtos das principais marcas do mercado como Nike, adidas, Puma, Converse, Vans, Asics, Tip Toey Joey, Pampili, Skechers e Crocs. \nAlém disso, a Magic Feet proporciona experiência ímpar ao público-usuário (criança) e público-decisor (adulto), por meio de constante revitalização das unidades e capacitação da equipe de atendimento.  \nO layout e a atmosfera das lojas são pensados para o mundo infantil de modo a criar uma experiência mágica no momento da compra. Atualmente, a rede possui 50 lojas distribuídas nos principais Shoppings Centers em oito estados brasileiros: São Paulo, Minas Gerais, Rio de Janeiro, Espírito Santo, Paraná, Pernambuco, Piauí e Amazonas.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c78b92e5-8801-4c23-89dd-d48bab800ea3.jpg', 12, NULL, NULL, '2026-03-08 17:39:42.954', 'https://franquias.portaldofranchising.com.br/franquia-magic-feet-calcados-e-tenis-infantis/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1a5cc210-9f1c-475a-8b79-d48e721d927e.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73q2000xeh0s3tfa5re1', 'ACTIONCOACH BRASIL', 'actioncoach-brasil', NULL, 'Educação', 'Treinamento Profissional e Capacitação', 'Coaching Empresarial (Business Coaching) para pequenas e médias empresas', 1997, 2008, '[\"https://www.youtube.com/watch?v=aOxXC5CkhnQ\",\"https://www.youtube.com/watch?v=kb4vsBf-YU4\",\"https://www.youtube.com/watch?v=DfO_7iguTCc\"]', '2026-04-01 02:00:00.600', '2025-08-05 22:20:24.218', 70, NULL, 1, 1993, 'Adquirir uma franquia ActionCOACH é a oportunidade de investimento ideal para quem busca um negócio B2B que ofereça um ótimo retorno do investimento, fluxo de caixa constante e escalabilidade, mas que além de tudo isso, se transforme em um negócio do qual você possa se orgulhar impacto positivo que gera nas PMEs da sua região. A ActionCOACH nasceu em 1993 com a ideia de ajudar os pequenos e médios empresários a melhorarem seus resultados, otimizar seus negócios e melhorar sua qualidade de vida, tendo de volta seu tempo livre. Seu fundador, Brad Sugars, inicia então um programa de treinamento em toda a Austrália. Ele realizava importantes seminários que contavam com a participação de 2.000 empresários por evento. Em pouco tempo, a ActionCOACH consegue se posicionar em tal nível que sua fama começa a crescer até chegar à Nova Zelândia, Ásia e Estados Unidos. A ActionCOACH tornou-se franquia em 1997. A partir de então conseguiu uma rápida expansão que nos levou a estar presente hoje nos 5 continentes e em mais de 80 países e com mais de 1.000 franqueados.  Durante as últimas 2 décadas, a franquia ActionCOACH recebeu vários reconhecimentos por publicações de prestígio como Entrepreneur, Forbes, Franchise Direct, Franchise Review, Elite Franchise, entre outros, obtendo o selo de excelência ABF por mais de 10 anos consecutivos. - Exclusividade Territorial: Um território que tenha no mínimo 30.000 empresas registradas e com um número ilimitado de coaches empregados. - Valor do Investimento é cotado em Dólares, então será respeitado a cotação do dia. Investimento: $ 95.000,00 USD (Dólares); $ 150.000,00 totais.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b21873b0-903c-4f2b-9826-5acc2cedb64e.jpg', 27, NULL, NULL, '2026-03-08 17:40:23.726', 'https://franquias.portaldofranchising.com.br/franquia-actioncoach-brasil-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '555000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73q7000yeh0s7jljrem7', 'OPHICINA E OPHICINA FOOTWEAR', 'ophicina-e-ophicina-footwear', NULL, 'Moda', 'VESTUÁRIO', 'A marca OPHICINA existe no mercado de confecções desde 1996, sempre associada à moda casual, surfwear e streetwear, tanto feminina quanto masculina. Em suas diversas linhas de roupas e acessórios.', 2013, 2022, NULL, '2026-04-01 02:00:00.612', '2025-08-05 22:20:24.224', 71, NULL, 1, 1996, '', NULL, 'SÃO PAULO', 1, NULL, 78, NULL, NULL, '2025-08-20 17:41:45.000', 'https://franquias.portaldofranchising.com.br/franquia-ophicina-e-ophicina-footwear-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73qf000zeh0six7e9t04', 'ALÉM DO OLHAR', 'alem-do-olhar', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A Além do Olhar é especialista em cuidados com a beleza, contemplando estética facial e corporal. Uma franquia completa na área da beleza com os mais diversos serviços e tratamentos.', 2016, 2021, '[\"https://www.youtube.com/watch?v=6UCKv6GsLn4\",\"https://www.youtube.com/watch?v=4yijzmNxGM4\",\"https://www.youtube.com/watch?v=0l-dtscYBk0\",\"https://www.youtube.com/watch?v=e0I57FRMksA\"]', '2026-04-01 02:00:00.624', '2025-08-05 22:20:24.231', 72, NULL, 1, 2014, 'A Além do Olhar existe por causa do sonho da Rose. A vida da nossa fundadora se transformou após se tornar gerente de vendas na Avon, onde trabalhou por cinco anos. \nNela teve a ideia de empreender no ramo da beleza e então, em 2014, pediu demissão da multinacional para seguir com seu sonho de empreender. Com o dinheiro da rescisão da Avon abriu a primeira unidade da Além do Olhar. A ideia do projeto era criar um ambiente aconchegante que em nada lembrasse os salões de belezas, com bolos e cafés. Hoje seu maior desejo é espalhar esse conhecimento ao mundo e transformar a vida de milhares de mulheres, que assim como ela, sonham em ter seu próprio negócio. Além do Olhar se diferencia no mercado por que amadurece junto de nossas clientes e entende suas necessidades como prioridades. \nCresce à medida que nossas especialistas crescem, incentivando-as constantemente. \nReconhecemos a importância do carinho ao longo prazo, com atenção personalizada. Somos defensores da beleza real e despretensiosa \nUtilizamos da tecnologia e dos bioestimuladores para atingirmos a melhor versão de nossas pacientes. \nSomos não ao exagero e portanto não ao preenchimento desnecessário US$ 124,7 BI. Hoje o mercado de estética lidera  \nÉ o que deve movimentar o setor até 2028 e expandir a uma taxa de 9.8% entre 2021 e 2028. O Brasil é o 4° lugar fica somente atrás de EUA, China e Japão no mercado de estética. \nÉ um dos maiores do mundo! 1.5 MI de procedimentos estéticos por ano no Brasil, movimentando mais de R$ 48 BI no país. 560% De crescimento entre os anos 2018 a 2022, em relação aos anos anteriores, no Brasil.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a38aad86-33b0-4a2d-aaa2-a3f57b7c6c5e.jpg', 30, NULL, NULL, '2026-03-08 17:41:29.135', 'https://franquias.portaldofranchising.com.br/franquia-alem-do-olhar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '180001', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
