INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73qu0011eh0sc7hlky3t', 'BEST MARKET', 'best-market', NULL, 'Alimentação', 'Mercados e Distribuição', 'Soluções de minimercado para condomínios e empresas, com modelo de autoatendimento que permite ao cliente realizar todo o processo de compra de forma independente, funcionando 24 horas por dia.', 2023, 2024, NULL, '2026-04-01 02:00:00.656', '2025-08-05 22:20:24.246', 74, NULL, 1, 2021, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/63160860-da56-44a3-99d1-836a4bc71830.svg', 40, NULL, NULL, '2026-03-08 17:42:50.969', 'https://franquias.portaldofranchising.com.br/franquia-best-market-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73r10012eh0s20r909sy', 'COMPANHIA DO CHURRASCO', 'companhia-do-churrasco', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fornecimento de refeições no sistema \"comida a quilo\" Especializado em churrasco.', 2013, 2013, '[\"https://www.youtube.com/watch?v=hdZXlCciQtA\",\"https://www.youtube.com/watch?v=3_JtDiiNQlE\"]', '2026-04-01 02:00:00.671', '2025-08-05 22:20:24.253', 75, NULL, 1, 2005, 'Há 10 anos no mercado de alimentação, o restaurante Companhia do Churrasco foi desenvolvido visando atender ao paladar do público brasileiro, cada vez mais exigente, servindo produtos de alta qualidade e excelência. Um modelo de restaurante focado em um segmento de mercado pouco explorado no fast food: Uma churrascaria na modalidade à quilo, destinada as praças de alimentação dos shopping Centers.', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5351f9c7-5d5b-42cb-a9c7-dd7f2120bf21.jpg', 31, NULL, NULL, '2026-03-08 17:43:15.140', 'https://franquias.portaldofranchising.com.br/franquia-companhia-do-churrasco/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/345b2b11-c3ca-4b06-9d91-9d2f2c80139f.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '550000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73r90013eh0sjeazxnut', 'IMPÉRIO HAMBURGUERIA', 'imperio-hamburgueria', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'Hamburgueria artesanal, com foco em SMASH Burguer,! #vocefazpartedesseimperio', 2024, 2024, NULL, '2026-04-01 02:00:00.685', '2025-08-05 22:20:24.261', 76, NULL, 1, 2020, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ab27e9d1-b72f-466a-b1c0-f4891319c60a.png', NULL, NULL, NULL, '2024-09-13 11:02:19.000', 'https://franquias.portaldofranchising.com.br/franquia-imperio-hamburgueria-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73rf0014eh0sal5m9zr6', 'MULTIFILMES WINDOW FILM', 'multifilmes-window-film', NULL, 'Serviços Automotivos', 'Locação de veículos', 'Rede especializada na instalação de películas de controle solar, segurança e decorativas. Proteção de pintura-PPF e envelopamento em geral. Linhas de produtos de alta performance, com marca própria.', 2015, 2021, '[\"https://www.youtube.com/watch?v=gJwo_aMizaA\",\"https://www.youtube.com/watch?v=0IOA_CC98lA\",\"https://www.youtube.com/watch?v=PgkSDV5ujc8\",\"https://www.youtube.com/watch?v=5f0F1EiHRRg\"]', '2026-04-01 02:00:00.699', '2025-08-05 22:20:24.267', 77, NULL, 1, 1999, 'A Marca MULTIFILMES surgiu como resultado da árdua luta de seu Presidente, Júnior Ruciretta, que entrou para o mundo do trabalho desde a infância. Foi coletor de reciclados na rua, empacotador em supermercados, entregador de panfletos e vendedor de Coca-Cola em semáforos. \nAinda muito jovem, teve a oportunidade de trabalhar no ramo de aplicação de películas em automóveis. Pelos seus serviços, recebia um salário mínimo mensal. Certa vez, por um descuido ocasional, acabou quebrando o vidro de um veículo quando estava aplicando a película. O dono do negócio exigiu o ressarcimento do prejuízo através dos serviços de Ruciretta, o qual trabalhou meses sem remuneração. Depois de haver quitado o prejuízo, o jovem foi dispensado e recebeu apenas R$80,00 a título de acerto trabalhista. \nCom esse valor em mãos e seu espírito empreendedor, criou a MULTIFILMES na modalidade delivery, já que não possuía condições financeiras para locar um espaço para os carros. Iniciou comprando três películas automotivas e saiu em busca de clientes. A estratégia deu certo, e Ruciretta foi multiplicando a compra de películas à medida que conquistava novos clientes. \nEm 2001, em razão do contínuo crescimento da clientela, foi necessária a locação de um espaço nos fundos de uma oficina para estocar os produtos. Ruciretta dedicou-se arduamente ao seu projeto como empreendedor, trabalhando incansavelmente todos os dias até tarde da noite, em finais de semana e também feriados. \nSua dedicação garantiu-lhe a crescente conquista de novos clientes. Em 2003, apenas dois anos após alugar um espaço físico para a MULTIFILMES, o jovem empreendedor firmou sua primeira parceria com uma concessionária de Ribeirão Preto. Novas parcerias surgiram até o impressionante número de 14 (quatorze) concessionárias, totalizando cerca de 600 (seiscentos) carros atendidos por mês. Ficou evidente que seria necessário expandir o negócio para atender a todos de modo eficiente e adequado. Quatro funcionários foram contratados para auxiliá-lo e o fundo da oficina, local desprovido de internet, foi trocado por uma sala maior. \nAtento aos interesses de seu público, percebeu que a maioria dos clientes pertencia às classes A e B, e estes se encontravam na zona sul de Ribeirão Preto, distante de onde a MULTIFILMES tinha sede. Em razão disso, em 2015, instalou a loja que hoje figura como Unidade Modelo da empresa em região nobre da Cidade. Preocupado com a melhoria constante dos serviços prestados, passou a oferecer produtos de melhor qualidade. Introduziu entre eles a película de alta performance, até então distribuída por uma única empresa no Brasil. Desse modo, a MULTIFILMES tornou-se pioneira no interior do Estado de São Paulo na aplicação desse tipo de película. \nEm 2017 a MULTIFILMES ousou um pouco mais e expandiu o negócio para os Estados Unidos. Ruciretta estava apostando alto na aplicação da película de alta performance dentro e fora do Brasil e não contava com a reviravolta que estava por vir: seu Fornecedor optou por dar exclusividade do produto a outro cliente, deixando o jovem empresário sem escolha. Como consequência, as finanças da MULTIFILMES levaram Ruciretta de volta à estaca zero. \nCom alma empreendedora e a incansável vontade de vencer, o empresário continuou dedicando-se ao trabalho e agora também à pesquisa de um novo Fornecedor. Seus esforços foram recompensados quando ele encontrou uma película de alta performance diferenciada para o mercado. Seu produto, então com a marca MULTIFILMES, surpreendeu os clientes em razão do custo-benefício e vem conquistando um mercado cada vez maior.  \nCom visão estratégica, Ruciretta ampliou suas opções de mercado e inseriu papéis de parede na linha de produtos da empresa. Tais estratégias garantiram a retomada do sucesso da MULTIFILMES, que, em 2019, expandiu os negócios para outras 03 (três) Unidades. \nAssim como em um ano atípico como 2020, nossa estratégia de expansão foi um sucesso, seguimos no mesmo caminho, hoje contamos com 35 franquias vendidas, em processo de abertura, sendo uma própria em Ribeirão Preto. Nossa expectativa é inaugurar mais 100 franquias até o final de 2021. \nAtualmente, a Unidade Modelo atende cerca de 300 (trezentos) carros e 100 (cem) arquiteturas por mês, perfazendo um lucro de mais de R$1,5 milhão de reais. Nos Estados Unidos, o faturamento anual é de cerca de $72 mil dólares. O crescimento da MULTIFILMES mantém-se acelerado, pois supera as expectativas dos clientes ao oferecer produtos e serviços com qualidade totalmente diferenciada no mercado. \nSe você se identifica com essa característica de inovação, presente no DNA da MULTIFILMES, junte-se ao nosso time e prepare-se para o sucesso!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/98a3201a-3db5-44b0-ab6a-687e4c6afecc.jpg', 22, NULL, NULL, '2026-03-08 17:43:52.445', 'https://franquias.portaldofranchising.com.br/franquia-multifilmes-window-film/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '129990', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73rl0015eh0suspag5vg', 'MINHA LAVANDERIA', 'minha-lavanderia', NULL, 'Limpeza e Conservação', 'Lavanderia', 'Lavanderia Ecológica, com alta tecnologia e produtos para cuidados com o vestuário e a casa.', 1994, 2012, '[\"https://www.youtube.com/watch?v=owlZexaxVB8\",\"https://www.youtube.com/watch?v=KUS21-NFzu0\",\"https://www.youtube.com/watch?v=3_GQd1WyBMg\"]', '2026-04-01 02:00:00.716', '2025-08-05 22:20:24.273', 78, NULL, 1, 1994, 'Com serviços de lavanderia especializada, aliando tecnologia e sustentabilidade, e um modelo de negócio enxuto, a Minha Lavanderia traz segurança e solidez para seu investimento. \nTemos o orgulho de compartilhar que nunca fechamos uma operação. Com foco em qualidade e ecologia, a Minha Lavanderia aliou o que existe de mais moderno e tecnológico em lavanderia, com uma solução sustentável para lavar as roupas: o Wetcleaning.  \nO resultado são peças mais limpas e cheirosas, e o meio ambiente preservado. Tudo isso, com preços competitivos no mercado.  \nHoje a Minha Lavanderia é uma marca valorizada e reconhecida pela qualidade dos serviços e credibilidade da rede. \nCom mais de 100.000 mil consumidores ativos no Brasil temos um índice de satisfação dos nossos serviços acima de 94% com base em quem já utilizou. \nA Franquia possui 12 anos no mercado e oferece a nossos franqueados 4 fontes de renda em um único negócio. \nLavanderia completa, tingimento profissional, renovação de couro e venda de mais de 100 produtos inovadores.\n   \nO Grupo Restaura é formado por três marcas especializadas em cuidar bem das suas roupas e da sua alimentação: a Restaura Jeans, a Minha Lavanderia e a DNA Natural. Atualmente são mais de 230 unidades em todo o país e mais de 28 anos de experiência e resultados em franchising. \nQuer saber mais sobre essa história de sucesso? Vem com a gente!  Na Minha Lavanderia temos um Suporte 360, ou seja, um suporte completo. \nComo franqueado você contará com uma equipe especialista nas mais diversas áreas de negócio para dar segurança em todas as fases, da implantação à operação da sua franquia.    Conheça mais do modelo de negócio e dos indicadores financeiros. Faça seu cadastro agora mesmo!', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5652b4a4-b907-4f89-8456-776b34cc9cee.jpg', 58, NULL, NULL, '2026-03-08 17:46:49.894', 'https://franquias.portaldofranchising.com.br/franquia-minha-lavanderia/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c14ed816-00a4-4d95-a89f-e04991492533.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a4b0d3e1-9739-4af4-b6bc-1eb2c6b08c02.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/31dd52d4-84a4-46e9-a112-0a66aa4778d8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f9911b44-7f1d-4979-ba17-c89e5f57314e.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73rq0016eh0smq6rmqf0', 'ECHOSIS', 'echosis', NULL, 'Comunicação, Informática e Eletrônicos', 'Comunicação e Mídia', 'A Echosis é uma Franquia de Marketing Digital Home Based que atua com serviços digitais como Redes Sociais, Google Adwords, Geração de Leads, Marketing de Automação, Geração de Conteúdo e Outros.', 2016, 2018, '[\"https://www.youtube.com/watch?v=U-cD6DRwJW0\",\"https://www.youtube.com/watch?v=s4PxynYAiiA\",\"https://www.youtube.com/watch?v=AO42a6gcUsA\",\"https://www.youtube.com/watch?v=5NYaqAJP80w\"]', '2026-04-01 02:00:00.731', '2025-08-05 22:20:24.278', 79, NULL, 1, 2010, 'Fundada em 2010, a Echosis começou atuando no desenvolvimento de jogos e dois anos mais tarde se posicionou no mercado como especialista em marketing digital e soluções online. \nPresente em todo o país, a Echosis também possui uma unidade nos EUA, que nos proporcionou durante 3 anos consecutivos o prêmio de franquia internacional pela ABF.  \nEspecialista em estratégias digitais, a Echosis oferece diversos serviços para empresas que desejam crescer na internet, como E-mail Marketing, Social Media, Geração de Conteúdo, Google Adwords, Otimização SEO, Remarketing, Google Shopping, entre outros. O modelo da franquia é home based, ou seja, não é necessário investir em um ponto comercial, podendo trabalhar diretamente de casa, sem gastar com aluguel, funcionários e outras despesas extras. \nAinda, é possível organizar seus próprios horários e contar com uma agenda flexível, ideal para quem deseja conciliar o emprego com a gestão da franquia, sendo uma segunda fonte de renda. A Echosis é a opção ideal para quem deseja começar o próprio negócio e atuar em um dos segmentos que mais cresce no mundo. Ficou interessado na franquia de marketing digital Echosis? Preencha o formulário para que a gente possa conversar melhor e esclarecer todas as suas dúvidas sobre este modelo de negócio!', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b9cd3ef1-8551-4fc0-9571-e9abd5339519.jpg', 25, NULL, NULL, '2026-03-08 17:48:00.948', 'https://franquias.portaldofranchising.com.br/franquia-echosis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '44000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73rx0017eh0sk19t33qj', 'SAMELLO', 'samello', NULL, 'Moda', 'Calçados', 'COMÉRCIO DE CALÇADOS E ACESSÓRIOS DE COURO EM GERAL', 1999, 2001, NULL, '2026-04-01 02:00:00.747', '2025-08-05 22:20:24.285', 80, NULL, 1, 1926, 'ABRA UMA LOJA SAMELLO   E INAUGURE UMA FASE DE BONS NEGÓCIOS NA SUA VIDA      HISTÓRIA \nA Franquia Samello sempre se destacou entre as maiores e mais conceituadas marcas de calçados masculinos do país e se posicionou no mercado como uma grande lançadora de tendências. Entre suas ações pioneiras estão o lançamento dos mocassins na década de 40, dos drivers na década de 70 e na de 80, os deckshoes. \nCom mais de 90 anos de atividade, a empresa é reconhecida como uma das mais experientes do mercado. Utiliza de matéria-prima da maior qualidade em seus calçados prezando o refinamento nos acabamentos. Este cuidado sempre fez parte da filosofia Samello.  SAMELLO FRANCHISING \nO sistema de franquia pode ser considerado como o grande marco da Samello nos anos 90. A marca consolidou-se no sistema de varejo, inaugurando lojas em todo o país que comercializam exclusivamente a marca Samello, todas norteadas pelos conceitos de diferenciais do negócio e foco no consumidor final.  MARCA \nA marca Samello reflete o estilo de vida de pessoas bem sucedidas, bem informadas e exigentes. Apreciam design, qualidade e estilo diferenciado. \nUma marca que se apresenta através de um espírito brasileiro sofisticado e cosmopolita que é refletido num design chique e moderno. \nSempre com uma visão aprimorada em suas coleções, a Samello traduz nos seus produtos a qualidade tradicional e lança o novo que as pessoas desejam.  OPORTUNIDADE \nInvista em um negócio de futuro, lastreado em uma das marcas mais reconhecidas no segmento de calçados e acessórios de couro. \nA marca que durante sua trajetória sempre inovou em design e estilo, posicionando-se no mercado como lançadora de tendência, agora estará na frente de uma loja que pode ser sua.  FRANQUIA \nA franquia da Samello atua no segmento de moda, na linha de calçados e acessórios de couro, como cintos, meias, carteiras, etc, tendo como foco principal a venda de calçados masculinos.       OBJETIVOS \n- Atender de forma mais eficaz todos os consumidores da marca.\n- Buscar a excelência dos serviços de venda e pós-venda a um público cada vez mais exigente que faz questão de um atendimento personalizado e qualificado.\n- Ampliar e sedimentar a percepção do conceito Samello, resultando, assim, no fortalecimento de nossa marca e de nossos parceiros junto aos consumidores.  FRANQUEADOR \n- A Samello fornece a seus franqueados todo o composto de seus produtos, sempre sob critério do franqueador, garantindo a padronização da rede.\n- Assegura, através de treinamento, a preparação de seus parceiros para a gestão da franquia sob a perspectiva mercadológica, operacional, legal e de recursos humanos.\n- Na fase de negociação a Samello fornece todo o apoio necessário, desde a definição do ponto, passando pela montagem completa da loja até o fornecimento de materiais promocionais para a sua inauguração.\n- Adicionalmente a Samello colocará à disposição do franqueado um consultor de campo, cuja principal função é a de acompanhar e facilitar a gestão da franquia.\n- Oferece ainda treinamentos de atendimento e produto para facilitar o processo de venda, material sobre as tendências de moda, além de apoio no desenvolvimento de ações de marketing local.  PROJETO ARQUITETÔNICO \n- A loja Samello é totalmente padronizada, visando conceitos como modernidade, conforto e identificação com os produtos e clientes.\n- O projeto arquitetônico da franquia Samello é modular, facilitando sua adaptação a diversas situações.\n- O layout da loja, no padrão da franqueadora, será apresentado ao franqueador ainda em fase de negociação.          \nAgora você já tem as principais informações sobre nosso sistema de franchising. Para dar inicio a uma parceria de futuro entre em contato com a Samello.  SAMELLO FRANCHISING LTDA\nRua Coronel Tamarindo, 2300\n14405-140 - Franca/SP - Brasil\n0800 34 1010 - (16) 3711-2400 - (16) 3711-2550', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b1024a1f-713b-481c-b6aa-21cb8940e7f6.jpg', 2, NULL, NULL, '2026-03-08 17:48:59.693', 'https://franquias.portaldofranchising.com.br/franquia-samello-calcados/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c333c1b3-3f73-4652-ae81-276480734199.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9469751c-3bb6-4d06-b3b5-4c8bec4cc5ad.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2284336d-7f52-4ad2-9b79-9d8034034be9.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '440000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
