INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73sv001deh0se7ahvaht', 'FAST ESCOVA', 'fast-escova', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Somos uma rede de franquia especializada em escova. Realizamos procedimentos sem hora marcada, com uma vasta gama de produtos para tratamento in loco, e home care.', 2018, 2022, NULL, '2026-04-01 02:00:00.838', '2025-08-05 22:20:24.319', 86, NULL, 1, 2018, 'Já imaginou ter a sua própria franquia de beleza com alta demanda de clientes todos os dias? Na franquia Fast Escova isso é realidade. Mais de 160 franquias comercializadas Presente em todos os estados do Brasil Suporte ao franqueado desde a implantação Custo operacional baixo e alta lucratividade Inovação: atendimento sem hora marcada Você não precisa entender de beleza: a gente te ensina tudo   UM NOVO MERCADO: MAIS FORTE E ALTAMENTE RENTÁVEL O Brasil é o 3º maior mercado consumidor de beleza, atrás somente dos EUA e China. As franquias de beleza ocupam a 2º posição entre as franquias mais lucrativas do Brasil. A procura por produtos e serviços que oferecem autoestima e bem-estar é uma crescente no país e no mundo. A franquia Fast Escova criou uma novo nicho dentro deste mercado, atingindo um público amplo e muito fiel.   INVESTIMENTO 50% ABAIXO DA MÉDIA DE FRANQUIAS DE BELEZA E 3 FORMAS DE GANHO Ao comprar uma franquia Fast Escova você tem acesso ao nosso know-how de operação completo e já formatado, além de contar com um suporte da franqueadora em todos os momentos desde a implantação até o dia-a-dia do negócio! Prestação de Serviços de Beleza\n\tEscova, Hidratação, Penteado e Maquiagem. Opções de Serviços por Assinatura\n\tFature com compras recorrentes, recebendo uma mensalidade. Venda de Produtos de Marca Própria\n\tMaravilhosos produtos de Upsell exclusivo para nossos franqueados. FUNDADA EM 2018, FRANQUIA FAST ESCOVA É UM SUCESSO E JÁ ULTRAPASSOU A MARCA DE 160 UNIDADES VENDIDAS NO BRASIL!', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c11dcbd8-0e9e-4517-a7ed-1bbe5d942a33.png', 168, NULL, NULL, '2026-03-08 17:52:38.995', 'https://franquias.portaldofranchising.com.br/franquia-fast-escova/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73t0001eeh0sn1thyrab', 'VACCINI', 'vaccini', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Clínica de Vacinação', 2003, 2008, NULL, '2026-04-01 02:00:00.850', '2025-08-05 22:20:24.324', 87, NULL, 1, 1993, '', NULL, 'RIO DE JANEIRO', 1, NULL, 24, NULL, NULL, '2026-03-08 17:53:31.556', 'https://franquias.portaldofranchising.com.br/franquia-vaccini-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '234500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73t5001feh0swul53ikx', 'VIZINHANDO BOTECAGEM DE RAIZ', 'vizinhando-botecagem-de-raiz', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Vizinhando é o quintal dos bairros! O melhor boteco para se sentir em casa, curtir a vida sem amarras, ser feliz despretensiosamente, tudo isso com muito sabor, irreverência e chopp trincando.', 2015, 2015, '[\"https://www.youtube.com/watch?v=-Hm9-EcSRgk\"]', '2026-04-01 02:00:00.860', '2025-08-05 22:20:24.330', 88, NULL, 1, 2014, 'O Vizinhando é a mistura ideal de bar e restaurante. Mais que um destino casual, somos o quintal dos bairros. Aqui a cerveja é sempre gelada e os pratos são bem servidos, com aquele gostinho e criatividade que só um bom vizinho tem a oferecer. É um lugar onde você pode confiar e se sentir verdadeiramente à vontade. Acreditamos que não precisamos de muito: enquanto a cerveja estiver gelada e o espeto gostoso, estaremos mais que felizes. Nossas saideiras são daquelas de três rodadas. Buscamos a diversão na vida e não somos muito a favor de regras. Queremos fazer parte da história das pessoas, criando memórias gostosas, de muitas risadas e calor no coração. O Vizinhando existe para promover (re)encontros.\n  POR QUE SER UM FRANQUEADO VIZINHANDO? O Vizinhando é uma marca do Grupo Alento Franchising, franqueadora do ramo de alimentação que ainda possui outras marcas como Billy The Grill, o Naa! Sushi Bar e também a Cloud Kitchen Brazil, a nossa cozinha na nuvem, um negócio totalmente voltado para delivery com oito marcas conglomeradas. Nosso grupo nasceu em 2010 e já conta com mais de 50 lojas franqueadas. Mais de 50% da nossa rede franqueada possui duas ou mais unidades do negócio. Se você quiser saber mais sobre nossa rede, entre em contato com a gente através dos nossos contatos no topo desta página.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8f45dee5-7ffd-4de8-adf3-6851bc327abc.jpg', 15, NULL, NULL, '2026-03-08 17:54:26.381', 'https://franquias.portaldofranchising.com.br/franquia-vizinhando-botecagem-de-raiz-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73ta001geh0s59jn0omc', 'LUKRO', 'lukro', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Franquia home office , plataforma de gestão completa e 100% online para lojas e restaurantes. Solução inovadora do segmento de ampla expansão. Com app de delivery,Pdv, fiscal, financeiro e muito mais.', 2021, 2022, '[\"https://www.youtube.com/watch?v=tS9zXCDVCGg\",\"https://www.youtube.com/watch?v=dPwMvUo3kmk\"]', '2026-04-01 02:00:00.871', '2025-08-05 22:20:24.334', 89, NULL, 1, 2017, 'O lukro é a sua oportunidade de empreender no formato home office e com baixo investimento, zero capital de giro e zero capital de instalação,  retorno do investimento em até 90 dias. Uma franquia que você terá acesso a vários produtos para comercializar no formato b2b. Imagine todos os comércios, lojistas, varejos, bares e restaurantes do seu bairro da cidade e outros estados serem seus clientes e gerar uma receita recorrente e vitalícia para sua franquia?  Ter uma franquia lukro é se tornar parte de uma empresa com 3 certificações internacionais ISO 27001 / ISO 27701 / GTPW . uma empresa consolidada com 20 anos de mercado.  Além disso, ele também é uma franquia pertencente à Associação Brasileira de Franchising (ABF). Com esse sistema o franqueado tem a oportunidade de comercializar uma plataforma de gestão simplificada, que traz eficiência para as principais tarefas diárias de uma empresa, seja ela de pequeno, médio ou grande porte.  Lukro redefiniu a gestão empresarial, introduzindo um sistema moderno que revoluciona os processos de gestão que eleva a eficiência. Seja parte da vanguarda da inovação! *FORMAS DE GANHOS*\n100% do valor de implantação do franqueado!\nvalor medio de implatação de R$1,000 \nvenda media 7 vendas mes \n7.000 mil de implatação mês esses ganhos podem ser superiores  *GANHOS RECORRENTES* \ncada clientes que entra na carteira gera uma recorrência das mensalidades de 40% \nvalor medio das mensalidades R$200,00  50 clientes recorrência R$ 4,000\n100 clientes recorrência R$ 8,000\n200 clientes recorrência R$ 16,000  Uma franquia que você pode empreender apartir de casa, e montar seu time de vendas e parceiros para prospecção de novos clientes.  As parceiras com contadores, associações. RECEBA LISTAS DE CLIENTES A CADA 15 DAIS PARA VOCE PROSPECTAR A PARTIR DE CASA.  CDL ABRASEL FECOMERCIO tenha na prateleira de produtos da franquia lukro outros produtos para gerar mais receita recorrentes como certificados digitais e Representante comercial STONE.', NULL, 'MATO GROSSO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/36a2f4f8-4e35-4691-b168-9a5962725613.jpg', 12, NULL, NULL, '2026-03-08 17:55:14.379', 'https://franquias.portaldofranchising.com.br/franquia-lukro/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73tg001heh0s86mnmcbx', 'CEAB ACADEMY 360', 'ceab-academy-360', NULL, 'Educação', 'EDUCAÇÃO', 'O CEAB (Centro Educacional de Aviação do Brasil) é uma instituição de ensino especializada na formação de profissionais para o setor de aviação.', 2024, 2024, NULL, '2026-04-01 02:00:00.882', '2025-08-05 22:20:24.341', 90, NULL, 1, 1998, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/84f18a52-efac-4588-822d-90378801f11d.svg', NULL, NULL, NULL, '2025-09-09 15:03:48.000', 'https://franquias.portaldofranchising.com.br/franquia-ceab-academy-360-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73tl001ieh0snbpn0umc', 'IT\'S GRILL EXPRESS', 'it-s-grill-express', NULL, 'Alimentação', 'Bares e Restaurantes', 'Com o objetivo de oferecer cortes e carnes especiais dentro da praça de alimentação, a It’s Grill traz uma seleção de acompanhamentos diferenciados, pratos executivos, risotos e saladas.', 2011, 2018, NULL, '2026-04-01 02:00:00.894', '2025-08-05 22:20:24.346', 91, NULL, 1, 2011, 'As carnes nobres vêm ocupando espaço relevante na mesa dos brasileiros, que têm cada vez mais levado a experiência vivida na alta gastronomia para o seu dia a dia. De olho nesta tendência de consumo, a It’s Grill Express foi idealizada e implantada em 2011, tendo como premissa o desenvolvimento de um fast food focado em grelhados que se diferenciasse dos padrões já existentes no mercado. A ideia em trazer para o fast food o mesmo corte e sabor servidos na alta gastronomia foi sucesso absoluto pela imediata aceitação do público, decorrente do preço e, especialmente, apelo nutricional do cardápio. Para quem aprecia carne fresca, macia e suculenta, vai encontrar cortes especiais de Picanha, Mignon, T Boné, Entrecot, entre outros, além de acompanhamentos, risotos e saladas. E para atender o mais variado tipo e perfil de consumidor, também são servidos pratos executivos. O cardápio é preparado com insumos de primeiríssima linha e de procedências reconhecidas no mercado. Nossos clientes demonstram bastante satisfação na relação custo x benefício e reconhecem como justo o preço praticado. Atualmente a rede conta com 7 lojas em Curitiba, nos Shoppings Mueller, Curitiba, Barigui, Pátio Batel, Palladium, Estação e Jockey Plaza, e em breve chegará ao Shopping Boulevard Curitiba.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7508a118-1da1-4272-9c9a-a45117b63dab.jpg', 12, NULL, NULL, '2026-03-08 17:56:40.499', 'https://franquias.portaldofranchising.com.br/franquia-its-grill-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
