INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73uo001oeh0s3woraj9s', 'HOTEL 10', 'hotel-10', NULL, 'Hotelaria e Turismo', 'Hospedagem', 'Hotéis Padronizados', 2003, 2013, NULL, '2026-04-01 02:00:00.963', '2025-08-05 22:20:24.384', 97, NULL, 1, 2003, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1b7ba94b-1b06-403a-9354-8cdcb46e6243.png', 10, NULL, NULL, '2026-03-08 17:59:07.809', 'https://franquias.portaldofranchising.com.br/franquia-hotel-10-hotelaria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73uu001peh0sodp849nr', 'ISLA BOLSAS', 'isla-bolsas', NULL, 'Moda', 'Vestuários', 'Bolsas e clutches únicas e atemporais. Através do garimpo pelas mais nobres e sofisticadas matérias-primas, surgem formas exclusivas que logo viram objetos de desejo para mulheres de todas as idades.', 2019, 2021, '[\"https://www.youtube.com/watch?v=GUbNRSae5L4\"]', '2026-04-01 02:00:00.975', '2025-08-05 22:20:24.391', 98, NULL, 1, 2007, 'Fundada em 2007 pela mineira Silvia Monteiro, a Isla é uma marca consolidada no mercado de luxo, reconhecida por suas bolsas exclusivas, sofisticadas e atemporais. \nO design autoral, o uso de materiais nobres e o cuidado artesanal colocaram a Isla em destaque desde sua linha festa — e hoje, a marca oferece um mix completo de produtos, que acompanham a mulher em todos os momentos, da praia ao dia a dia. Em 2020, ampliamos nosso propósito com uma linha sustentável, feita a partir de resíduos têxteis e tecimento manual, promovendo inclusão social por meio do trabalho de artesãs locais. \nPresente em lojas nos melhores shoppings do país, multimarcas renomadas e marketplaces de luxo no Brasil e no exterior, a Isla é sinônimo de elegância com consciência.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8bd08ce3-9a31-4271-b2fa-ab5af27af848.jpg', 9, NULL, NULL, '2026-03-08 17:59:31.207', 'https://franquias.portaldofranchising.com.br/franquia-isla-bolsas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '445000', NULL, NULL, NULL, '45000', NULL, '40', '2', '350000', '50000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73v2001qeh0szskgptgb', 'PIZZA VIGNOLI', 'pizza-vignoli', NULL, 'Alimentação', 'Bares e Restaurantes', 'Restaurante especializado em pizza e culinária italiana, tendo operações em formato de restaurante a la carte, e fast casual no formato expresso.', 2016, 2018, NULL, '2026-04-01 02:00:00.986', '2025-08-05 22:20:24.399', 99, NULL, 1, 2004, '', NULL, 'CEARÁ', 1, NULL, 10, NULL, NULL, '2026-03-08 18:00:08.805', 'https://franquias.portaldofranchising.com.br/franquia-pizza-vignoli/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73va001reh0s4qvcwl68', 'LIG LIG', 'lig-lig', NULL, 'Alimentação', 'Bares e Restaurantes', 'COMIDA CHINESA', 1994, 1989, '[\"https://www.youtube.com/watch?v=hgqHH1KRe1Y\",\"https://www.youtube.com/watch?v=E6eLCO8OkhY\",\"https://www.youtube.com/watch?v=5cnBWoMgmMc\",\"https://www.youtube.com/watch?v=aqVfhqx_Ek8\",\"https://www.youtube.com/watch?v=2dvkhW9DdBU\"]', '2026-04-01 02:00:00.999', '2025-08-05 22:20:24.406', 100, NULL, 1, 1992, 'A VERDADEIRA COMIDA CHINESA ABRE SUAS PORTAS   Em 1992, Thomas Liu recebeu a proposta de se tornar sócio fundador de um negócio que já era sucesso na América: o delivery de comida chinesa.  Filho de chineses e apaixonado pela culinária do país, Thomas aceitou a oferta e se tornou sócio do Lig-Lig, o primeiro delivery de comida chinesa do Brasil.  Com o crescimento natural da rede, Thomas assumiu a direção do negócio, comprou a parte de seus sócios e hoje comanda 27 lojas, sendo três próprias.  UM PEDACINHO DA CHINA NO BRASIL  Um dos principais diferenciais da Lig-Lig é a disseminação da cultura chinesa.  Atualmente, Thomas Liu também é o chef de cozinha da rede e elabora todas suas receitas baseadas nos condimentos e demais ingredientes utilizados na China.  Além disso, o chef também segue os quatro mandamentos da culinária chinesa, que são: \ncor, perfume, paladar e apresentação esmerada.  Pratos coloridos, aromatizados por temperos e condimentos em profusão e cuidadosamente equilibrados para agradar não apenas ao paladar, mas também ao olfato e à visão, além de um rigoroso controle de qualidade e processo, que são o grande diferencial do Lig-Lig.  As inovações do Lig-Lig em publicidade, social media e tecnologia são constantes. \nExecutamos um planejamento de marketing que conecta ações de mídia, digital e offline.  Em 25 anos de rede, nos tornamos uma rede consolidada e sabemos que são os laços fortes que solidificam o sistema. Assim, tratamos nossos franqueados com muito respeito e atenção e atribuímos nosso constante sucesso à parceria construída nessa relação.  VALORES LIG-LIG  Divulgar a cultura chinesa Parceria e relação de qualidade com os franqueados Padronização de processos Laços fortes: o sucesso dos franqueados, é o nosso sucesso Trabalho focado na rentabilidade do franqueado', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/626ab54c-6f7b-46b7-a7a2-84435844eaa7.png', 33, NULL, NULL, '2026-03-08 18:00:30.375', 'https://franquias.portaldofranchising.com.br/franquia-lig-lig-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '422000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
