INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73vt001ueh0sumvwa0gs', 'HASHI EXPRESS', 'hashi-express', NULL, 'Alimentação', 'Bares e Restaurantes', 'Alimentação: Gourmet Oriental.', 2015, 2016, NULL, '2026-04-01 02:00:01.033', '2025-08-05 22:20:24.426', 103, NULL, 1, 2012, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7d884ff1-85d6-4c8d-b1ca-f76e2f7c7b50.jpg', 10, NULL, NULL, '2026-03-08 18:02:11.943', 'https://franquias.portaldofranchising.com.br/franquia-hashi-express-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73vz001veh0sf0zdk0az', 'CAFÉ DO FEIRANTE', 'cafe-do-feirante', NULL, 'Alimentação', 'Bares e Restaurantes', 'CAFETERIA E LANCHES', 2007, 2009, NULL, '2026-04-01 02:00:01.043', '2025-08-05 22:20:24.432', 104, NULL, 1, 2000, 'O SABOR QUE TEM HISTÓRIA Poucos lugares conseguem ser tão charmosos quanto uma cafeteria.  A franquia do Café do Feirante consiste em um negócio que comercializa história, tradição e sabor. O ambiente acolhedor, as diversidades de produtos, a escolha dos móveis, das cores, do cardápio, da arquitetura, estimulam novos hábitos nos consumidores, que cada vez mais se sentem atraídos pelo espaço. O Café do Feirante traz consigo os sabores tradicionalmente brasileiros, resgatando sensações, aromas e o prazer de apreciar um alimento caseiro, preparado com produtos selecionados e de ótima qualidade. O Café do Feirante prima pela valorização do cliente, pelo respeito e pela qualidade de seus produtos e serviços. Presente no mercado há mais de 10 anos, inaugurou sua primeira loja na cidade de Marília, interior de São Paulo.  Atualmente a Rede conta com várias lojas e busca parceiros capacitados para dar continuidade ao processo de expansão em um segmento que não pára de crescer. O Café do Feirante possui um conceito simples, inspirador e genuinamente brasileiro. O ambiente alegre, que remete ao campo, à fazenda, permite ao cliente viver esse conceito, inclusive através do mix variado, como: produtos caseiros, doces, salgados, lanches especiais, bebidas quentes e geladas à base de café, chás, sucos e muito mais, que agrada a todos os paladares, do mais simples ao mais exigente. Para isso, seleciona ingredientes de qualidade e combinam sabores que são uma verdadeira tentação.   Faça parte dessa tradição. Seja um franqueado!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f17b58dd-ecf4-459e-b6a4-4024c3605533.svg', 11, NULL, NULL, '2026-03-08 18:02:34.054', 'https://franquias.portaldofranchising.com.br/franquia-cafe-do-feirante/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73w5001weh0sh1dcilik', 'BOULANGERIE CARIOCA', 'boulangerie-carioca', NULL, 'Alimentação', 'PADARIAS', 'Somos a Boulangerie Carioca. Um pedacinho da França e do Mundo aqui no Brasil.', 2016, 2018, NULL, '2026-04-01 02:00:01.055', '2025-08-05 22:20:24.437', 105, NULL, 1, 2015, 'Conheça a Boulangerie Carioca – A boulangerie pâtisserie com receitas irresistíveis direto da França A Boulangerie Carioca foi planejada para mudar o mercado de panificação no Brasil. Fundada em 2015, no Rio de Janeiro, ela vem encantando clientes todos os dias com suas deliciosas receitas e ambientes aconchegantes. Investir na Boulangerie Carioca é aceitar fazer parte de um time que tem como objetivo levar um pedaço da França para todos os cantos do país. E entender que um simples café da manhã parisiense com um toque carioca pode fazer toda a diferença na vida de alguém. A marca oferece produtos fresquinhos da mais alta qualidade, com fermentação artesanal e natural que fazem toda a diferença para o negócio. E com um ambiente aconchegante e acolhedor como as padarias francesas, a Boulangerie Carioca se destaca no mercado e conquista clientes todos os dias. Nossos franqueados amam fazer parte da Boulangerie Carioca! Confira depoimentos de quem tem uma franquia Boulangerie Carioca e venha fazer parte dessa história.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/48873f53-8b95-4fc1-8916-56e1ef07ceb5.jpg', 3, NULL, NULL, '2025-09-22 15:02:24.000', 'https://franquias.portaldofranchising.com.br/franquia-boulangerie-carioca/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73wc001xeh0s7dfootfe', 'BENDITO COOKIES E BROWNIES', 'bendito-cookies-e-brownies', NULL, 'Alimentação', 'Docerias, Padarias e Cafés', 'Somos uma rede de cafés com especialização em confeitaria gourmet, cookies, brownies, salgados, tortas, bolos. Produção própria e exclusiva.', 2017, 2019, NULL, '2026-04-01 02:00:01.067', '2025-08-05 22:20:24.445', 106, NULL, 1, 2013, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6a912791-c3e3-4204-a35f-a508a5b83e3f.png', 7, NULL, NULL, '2026-03-08 18:04:03.458', 'https://franquias.portaldofranchising.com.br/franquia-bendito-cookies-e-brownies/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73wo001zeh0sgbqq1bvj', 'SR. ESPETTO', 'sr-espetto', NULL, 'Alimentação', 'Bares e Restaurantes', 'Rede de Franquias que ser espetos de churrasco e deliciosos acompanhamento, atendendo ao períodos de almoço e também happy hour.', 2015, 2018, '[\"https://www.youtube.com/watch?v=HMvFyD_zJJ8\",\"https://www.youtube.com/watch?v=7s87zNEZx_Y\",\"https://www.youtube.com/watch?v=qbRR-sFDxMo\",\"https://www.youtube.com/watch?v=efGCk6CXj_Q\"]', '2026-04-01 02:00:01.077', '2025-08-05 22:20:24.457', 108, NULL, 1, 2015, 'O Sr. Espetto é um projeto do campeão mundial do UFC, Maurício Shogun Rua e surgiu como uma oportunidade de investimento para quem ama churrasco. \nA partir disso, criamos o conceito da loja: espetos e acompanhamentos prontos para saborear. \nTudo isso sem trabalho algum. E com um modelo inovador, com baixíssima manipulação de alimentos, operação super simples e embalagens modernas e individualizadas.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/14f29481-07ae-4381-91b0-87e3a040c034.jpeg', 48, NULL, NULL, '2026-03-08 18:04:43.981', 'https://franquias.portaldofranchising.com.br/franquia-sr-espetto/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73wt0020eh0shvubooeh', 'MAX SUSHI JAPANESE FOOD', 'max-sushi-japanese-food', NULL, 'Alimentação', 'Bares e Restaurantes', 'Restaurante de Comida Japonesa Presencial e Delivery', 2008, 2012, '[\"https://www.youtube.com/watch?v=_XWIhsY3p-g\"]', '2026-04-01 02:00:01.088', '2025-08-05 22:20:24.462', 109, NULL, 1, 2007, 'A Max Sushi restaurante de comidas tipicamente japonesa. Fundada em novembro de 2007, inovou no mercado atuando no modo fast food, garantindo rapidez, versatilidade, variedade, qualidade, e principalmente, escolha, uma vez que é o próprio cliente quem monta seu prato. Sua primeira loja, localizada no Shopping Boungainville em Goiânia, logo de início superou todas as expectativas, seu faturamento esperado para 3 anos foram alçados em apenas 6 meses de operação, e isso por si só é surpreendente. Porém, o público ficou tão entusiasmado que a proposta de franquia foi inevitável. A rede Max Sushi em 5 anos de mercado, conta com franquias em 9 estados do Brasil com um total de 13 lojas, ganhando prêmios de empreendedorismo e de melhores resultados em vendas. Sua história tem traços de grandes conquistas e surpresas. Em meio a abertura de lojas com filas enormes de mais de 70 clientes e salva de palmas inesperadas em inauguração de expansão. Obteve resultados surpreendentes com anos de crescimento maiores de 400%. Os produtos têm características originais da culinária japonesa e chinesa com diferencial no sabor e presteza no atendimento. Na Max Sushi a comida é por quilo, o que permite aos clientes liberdade de escolha, onde saboreiam o que quiserem na quantia desejada com qualidade de alto padrão em boas práticas de higiene e manipulação de alimentos. Seus sonhos são ainda maiores para os próximos anos e espera que mais colaboradores e clientes possam fazer parte dessa história.', NULL, 'GOIÁS', 1, NULL, 8, NULL, NULL, '2026-03-08 18:05:13.637', 'https://franquias.portaldofranchising.com.br/franquia-max-sushi-japanese-food-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '55000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73wz0021eh0si7ogtjoi', 'CARTAO EXAME BR', 'cartao-exame-br', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Cartão de desconto ou benefícios para área da saúde', 2022, 2022, NULL, '2026-04-01 02:00:01.099', '2025-08-05 22:20:24.467', 110, NULL, 1, 2022, 'Somos uma central de agendamento de consultas, exames laboratoriais e imagem com valores acessíveis. Trabalhamos com parceiros homologados, assim disponibilizamos diversas opções de clínicas, laboratórios e consultórios que farão o atendimento dos clientes que possuem o CARTÃO EXAME. Nossa missão é ser a melhor opção para quem não tem plano de saúde e necessite de serviços com qualidade, rapidez e valores acessíveis.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0a5c72c8-a561-49d6-9f12-bceb009cafb7.jpg', 2, NULL, NULL, '2026-03-08 18:06:06.507', 'https://franquias.portaldofranchising.com.br/franquia-cartao-exame-br/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '25000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73x40022eh0s4m8bow81', 'STYLEBAR', 'stylebar', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Estéticos e Bem-Estar', 'Bar de Beleza de conceito easy beauty e cosméticos de marca própria', 2019, 2021, '[\"https://www.youtube.com/watch?v=jgG4CeDBgd4\"]', '2026-04-01 02:00:01.110', '2025-08-05 22:20:24.472', 111, NULL, 1, 2018, 'Há cinco anos nasceu a franquia Stylebar. Nossa primeira unidade foi aberta na Alameda Lorena no Jardins em São Paulo. Com o conceito Easy Beauty veio de encontro às necessidades da mulher moderna quando se trata de beleza e autoestima. Proporciona serviços de cabelo, maquiagem e unhas de forma rápida, ágil e com muita facilidade. Não precisa de horário marcado, mas funciona com agendamentos também. Nunca fecha! O Stylebar resolve o problema das mulheres que precisam de serviços de beleza aos domingos e feriados. Beleza não tem hora! Possui uma linha de produtos 100% naturais e embalagens recicláveis. O compromisso com a sustentabilidade é um dos pilares da marca.', NULL, 'SÃO PAULO', 1, NULL, 7, NULL, NULL, '2026-03-08 18:06:40.825', 'https://franquias.portaldofranchising.com.br/franquia-stylebar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73x90023eh0s7uan5gg5', 'GRUPO MEDNET MEDICINA E SEGURANÇA DO TRABALHO', 'grupo-mednet-medicina-e-seguranca-do-trabalho', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Medicina e Segurança do Trabalho.', 2006, 2012, NULL, '2026-04-01 02:00:01.123', '2025-08-05 22:20:24.477', 112, NULL, 1, 1994, 'Fundada em 1994 na cidade de Americana/SP, no coração da Região Metropolitana de Campinas, a MEDNET Saúde Ocupacional dedica-se à prestação de serviços ocupacionais, com realização de exames clínicos, audiométricos, laboratoriais, cardiológicos, oftalmológicos, radiológicos, e demais especialidades envolvidas nas atividades laborais de seus clientes. A empresa atende as demandas de vários clientes por todo o território nacional, desde instituições privadas a instituições governamentais e autarquias. Através de constante pesquisa, estudo, e investimento em tecnologia o Grupo MEDNET busca a perfeição em seus serviços. A empresa conta com uma equipe de profissionais capacitados e certificados que são sujeitos a constantes treinamentos para atualização e aprimoramento que permite que ultrapassemos os resultados esperados pelos nossos clientes. Uma das razões que tornam o Grupo MEDNET uma empresa líder em seu segmento é sua atitude arrojada e desbravadora, estando sempre à frente de seu tempo, prevendo tendências e se antecipando a elas. Nessa linha foi que o Grupo MEDNET em 2002 criou a divisão SEGNET, especializada na área de segurança do trabalho, com uma ampla equipe de profissionais, composta de engenheiros e técnicos de segurança do trabalho em constante reciclagem e capacitação, proporcionando aos nossos clientes a facilidade de poder contar com todos os serviços de medicina e segurança do trabalho centralizados em um único fornecedor. O resultado desta união é mais agilidade e melhor qualidade nos serviços prestados. Como resposta a grande aceitação do mercado, o Grupo MEDNET instalou unidades em polos estratégicos de negócio, para poder atender cada vez melhor os seus clientes. Este também foi o embrião da MEDNET Franchising. Com o gerenciamento remoto destas unidades regionais, foram aprimoradas as ferramentas e os processos para a abertura de unidades franqueadas. Como próximo passo, foi inaugurada em 2006 a unidade Limeira, pioneira como unidade franqueada. Desde então o sistema tem se aperfeiçoado e novas unidades franqueadas foram inauguradas. Por todos estes motivos que o Grupo MEDNET é a escolha ideal quando se busca eficiência na área de Saúde Ocupacional e Segurança do Trabalho.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c02ddd4c-5e31-422a-af1c-c89717504b46.jpg', 58, NULL, NULL, '2026-03-08 18:07:19.926', 'https://franquias.portaldofranchising.com.br/franquia-mednet-medicina-e-seguranca-do-trabalho/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '120000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73xe0024eh0s0fwrlw0l', 'LOCEXPRESS', 'locexpress', NULL, 'Casa e Construção', 'Construção e Reforma', 'Locação de máquinas e equipamentos para construção civil', 2020, 2022, '[\"https://www.youtube.com/watch?v=F9bMDdGP1HM\"]', '2026-04-01 02:00:01.133', '2025-08-05 22:20:24.482', 113, NULL, 1, 2020, 'Invista em um mercado essencial, recorrente e com demanda constante. Se você busca uma franquia em um setor essencial, com modelo validado e grande potencial de crescimento, a LocExpress é a oportunidade ideal. Saiba o porquê: A LocExpress é uma rede de franquias especializada na locação de máquinas e equipamentos para obras, reformas e manutenções — um setor diretamente ligado à construção civil, um setor essencial para a economia do nosso país. Com mais de 65 unidades no Brasil e mais de 40 anos de experiência no segmento, a LocExpress oferece um modelo seguro, estruturado, validado e preparado para expansão nacional. Números do investimento Investimento inicial a partir de R$ 275 mil* Faturamento médio mensal estimado acima de R$ 100 mil* Retorno projetado: 24 a 36 meses* Lucratividade potencial: até 40%* *Valores variam conforme cidade e modelo de operação. Um negócio baseado em receita recorrente Na LocExpress, o equipamento não é vendido apenas uma vez. Ele é alugado hoje, amanhã e inúmeras outras vezes, gerando fluxo de caixa constante e previsibilidade de faturamento. Isso significa mais estabilidade, maior controle financeiro e possibilidade real de crescimento orgânico, sem depender de financiamentos bancários. Você não começa sozinho O franqueado recebe suporte completo desde o primeiro dia: Apoio na escolha e aprovação do ponto Implantação completa da operação Compra direta com fornecedores homologados Treinamento técnico e comercial Sistemas de gestão completos Suporte contínuo da franqueadora Além disso, trata-se de uma operação enxuta, com necessidade reduzida de equipe em comparação a muitos outros segmentos. Você busca um investimento em que você possa trabalhar de segunda a sexta-feira, em horário comercial, e tenha o final de semana livre para lazer e família? Com a LocExpress, você conquista isso!', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f8aa37bc-e7a0-45bc-83f8-71a5afe7d6fb.png', 31, NULL, NULL, '2026-03-08 18:08:35.759', 'https://franquias.portaldofranchising.com.br/franquia-locexpress/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '325000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73xk0025eh0so40hsz6c', 'LOCAGORA', 'locagora', NULL, 'Serviços Automotivos', 'Locação de veículos', 'Líder nacional em franquias de aluguel de motos. Unindo duas formas de negócios mais rentáveis - franquias e locomoção.', 2022, 2023, NULL, '2026-04-01 02:00:01.144', '2025-08-05 22:20:24.488', 114, NULL, 1, 2022, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/edea1313-7329-4a24-bdd5-96b502e2a9fc.png', 145, NULL, NULL, '2026-03-09 14:35:54.369', 'https://franquias.portaldofranchising.com.br/franquia-locagora-servicos-automotivos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
