INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73y10028eh0szfo5zh3m', 'LET\'S EAT', 'let-s-eat', NULL, 'Alimentação', 'Bares e Restaurantes', 'Criada para proporcionar uma experiência única, o Let\'s Eat surgiu inspirado nos tradicionais casual dining americanos e possui um menu que inclui burgers, american BBQ e comida mexicana.', 2014, 2021, NULL, '2026-04-01 02:00:01.175', '2025-08-05 22:20:24.506', 117, NULL, 1, 2010, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4e8991f0-1c28-454d-bd71-2bbc6199c135.png', 14, NULL, NULL, '2026-03-08 18:10:31.444', 'https://franquias.portaldofranchising.com.br/franquia-lets-eat-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '340000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73y90029eh0syzba1ke6', 'CTRL+PLAY', 'ctrl-play', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Rede de escolas de tecnologia e inovação.', 2016, 2024, NULL, '2026-04-01 02:00:01.186', '2025-08-05 22:20:24.513', 118, NULL, 1, 2015, 'A Ctrl+Play é uma rede de franquias de tecnologia e inovação que oferece cursos de robótica e programação para o público a partir de 7 anos. Com metodologias de ensino exclusivas e recursos tecnológicos avançados, os alunos podem desenvolver habilidades em programação, robótica, criação de jogos, modelagem 3D e aprender conceitos de lógica de forma dinâmica, divertida e envolvente, proporciona uma experiência de aprendizado estimulante e enriquecedora. A escola faz parte do grupo CNA+ desde novembro de 2023 e, atualmente, conta com mais de 100 unidades em operação. A Ctrl+Play também é uma das marcas franqueadoras integrantes da Associação Brasileira do Franchising (ABF).', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/91c81d52-8322-4194-87cb-fba9ff5ac7d4.svg', 81, NULL, NULL, '2026-03-08 18:10:52.665', 'https://franquias.portaldofranchising.com.br/franquia-ctrlplay-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
