INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73yl002beh0s2usga8qh', 'VRD GESTÃO DE BENEFÍCIOS', 'vrd-gestao-de-beneficios', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Gestão e comercialização de seguros diversos, planos de saúde, Odontológico, benefícios, consórcios e financiamentos.', 2022, 2022, NULL, '2026-04-01 02:00:01.212', '2025-08-05 22:20:24.525', 120, NULL, 1, 2009, '', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/15a3b2cf-9638-48c9-b2e6-1f889c7e853e.png', 2, NULL, NULL, '2025-11-27 10:06:05.000', 'https://franquias.portaldofranchising.com.br/franquia-vrd-gestao-de-beneficios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '20000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73yq002ceh0stz7bzwvi', 'S.A. CASA DO SUSHI', 's-a-casa-do-sushi', NULL, 'Alimentação', 'Bares e Restaurantes', 'BUFFET DE COMIDA JAPONESA - SUSHI', 2019, 2022, '[\"https://www.youtube.com/watch?v=iJVUjCrN7mk\"]', '2026-04-01 02:00:01.227', '2025-08-05 22:20:24.531', 121, NULL, 1, 2017, 'Olá, somos a S.A. Casa do Sushi e Restaurante LTDA.\n  Estamos no mercado desde 2017 no ramo de comida japonesa. \nVisando a necessidade do mercado de trazer a culinária oriental, para o maior número de pessoas, de forma acessível a todos com qualidade e baixo custo, inauguramos nosso primeiro restaurante na cidade de Camboriú-SC. \nO sucesso de nosso negócio foi tamanho que buscamos a expansão, e à medida em que a demanda aumentava, tornamo-nos franqueadores.\n  Hoje, contamos com 25 unidades espalhadas por Santa Catarina, Paraná e também São Paulo, são elas: Itapema-SC, Camboriú-SC, São José dos Pinhais-PR, Araquari-SC, Castro-PR, São José-SC, Tijucas-SC, Paranaguá-PR, Ponta Grossa-PR, Joinville-SC nos bairros Zona Sul e Iririú, Jaraguá do Sul-SC, Colombo-PR, Brusque-SC, Araucária-PR, Londrina-PR, União da Vitória-PR, Pinhais-PR, Maringá-PR, Praia Grande-SP, Curitiba-PR nos bairros Alto da XV, Novo Mundo, Mercês e Sítio Cercado.\n  Em todas as franquias buscamos manter nossa essência e qualidade, fornecendo um ambiente acolhedor, com atendimento diferenciado e preço justo, o comprometimento em garantir a satisfação de nossos clientes é nossa prioridade.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b7b5f880-bb9c-4945-b5dd-29015ab3060e.jpg', 27, NULL, NULL, '2026-03-08 18:12:10.122', 'https://franquias.portaldofranchising.com.br/franquia-sa-casa-do-sushi/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '210000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73yv002deh0sf720z68s', 'JÚPITER', 'jupiter', NULL, 'Casa e Construção', 'MANUTENÇÃO', 'Desentupidora', 2014, 2015, NULL, '2026-04-01 02:00:01.240', '2025-08-05 22:20:24.536', 122, NULL, 1, 1984, '', NULL, 'SÃO PAULO', 1, NULL, NULL, NULL, NULL, '2025-09-03 09:52:47.000', 'https://franquias.portaldofranchising.com.br/franquia-jupiter-limpeza/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '202226.4', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73z1002eeh0s4retiiw9', 'ARTWALK', 'artwalk', NULL, 'Moda', 'Calçados', 'TÊNIS CASUAIS/SNEAKERS, DAS PRINCIPAIS MARCAS MUNDIAIS ALÉM DE ACESSÓRIOS COMO BONÉS, CAMISETAS E MEIAS', 2006, 2009, NULL, '2026-04-01 02:00:01.266', '2025-08-05 22:20:24.541', 123, NULL, 1, 2006, 'Fundada em 2006, a Franquia Artwalk pertence ao Grupo Afeet, que, à época, percebeu a falta de um player forte em seu nicho no país, detectando a oportunidade de implementar uma rede de sneaker stores no Brasil. \nA Artwalk é focada em calçados de moda, casuais e sneakers, e disponibiliza ainda um mix complementar de ‘Ts’(camisetas), caps (bonés), meias descoladas e mochilas. \nOferece aos seus clientes, que buscam estilo e atitude na hora de comprar um tênis, um mix de produtos atualizado com as tendências internacionais e, como diferencial, a melhor experiência de compra em um ambiente diferenciado, com vendedores especializados na ‘cultura sneaker’. \nEntre as marcas comercializadas pela rede estão Nike, adidas Originals, Vans, Converse, New Balance, Puma, Reebok, New Era, Jansport, Sprayground e Stance. \nAtualmente, a Artwalk, além da loja virtual, possui 38 lojas distribuídas nos principais Shoppings de sete estados brasileiros: São Paulo, Rio de Janeiro, Minas Gerais, Espírito Santo, Paraná, Bahia e Pernambuco.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9eee7036-ffaa-4169-9ee6-804d885e746f.jpg', 73, NULL, NULL, '2026-03-08 18:13:23.673', 'https://franquias.portaldofranchising.com.br/franquia-artwalk-acessorios-pessoais-calcados-e-tenis/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/855a73c1-dcac-4920-a91b-357afc599c3b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7c1e7c86-feba-4a0b-a245-d3cf68a42651.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73z7002feh0sl1d746nx', 'CHICKEN TOWN', 'chicken-town', NULL, 'Alimentação', 'Bares e Restaurantes', 'É uma rede de franquia de frango frito empanado do estilo Americano, que tem origens inglesas e entrou no mercado para trazer algo inovador na receita de frango frito que fosse crocante e suculento.', 2019, 2021, '[\"https://www.youtube.com/watch?v=wHbNLyCs0qY\",\"https://www.youtube.com/watch?v=7mVuYQ-R-Nk\",\"https://www.youtube.com/watch?v=i3sifbo-yCc\",\"https://www.youtube.com/watch?v=gpLDjdJD0h0\"]', '2026-04-01 02:00:01.284', '2025-08-05 22:20:24.547', 124, NULL, 1, 2019, 'Aposte na melhor franquia de delivery do Brasil Confira as vantagens de ter uma franquia Chicken Town de Frango Frito Empanado. 100% Focado em Delivery Operação simples e otimizada Treinamento Teóricos e Práticos Marketing Integrado Alta Rentabilidade Baixo Investimento Suporte de Implantação Produtos Bem Avaliados Somos associados ABF (Associação Brasileira de Franchising)  A Chicken Town é uma rede de franquia de frango frito empanado do estilo Americano que atua no segmento de alimentação, com foco em delivery e refeições rápidas, estilo fast food. Nasceu em Uberlândia cidade do interior de Minas Gerais, está no mercado desde 2019. Com apenas dois anos de operação, já possui mais de 21 unidades distribuídas pelo país, sua meta para 2022 é mais que dobrar o número de unidades. Nossos produtos Conheça a qualidade incomparável e crocância dos nossos produtos com uma receita inglesa ultrassecreta. Além de contar com uma excelente qualidade, trabalhamos com diversas opções servindo porções individuais até combos que atendem diversas pessoas, ideal para promover o encontro de amigos, reuniões de família, confraternizações de empresas etc. Aos franqueados, a Chicken Town garante treinamento completo para preservação de qualidade nos serviços, marketing e atendimentos da rede. O empreendedor investe em um modelo de negócio já testado e consolidado no segmento de alimentação, com bons índices de rentabilidade. A franqueadora auxilia na praticidade da gestão dos modelos de franquia, além de treinamentos teóricos e práticos. Aos interessados em um modelo de franquia da rede, a Chicken Town disponibiliza três modalidades de investimento. Dark Kitchen, que é um modelo onde o restaurante funciona exclusivamente para o serviço de delivery. Ou seja, não possui instalações para refeição no local, como salão, mesas e cadeiras.  O investimento aproximado é de 75 mil reais. Delivery, requer que o ponto comercial tenha dimensões mínimas de até 35 metros quadrados, possui atendimento presencial / balcão (para pedido e retirada), mas não possui espaço para refeição no local. O investimento aproximado é de 85 mil reais. Standard com área exigida acima de 35 m², com espaço completo para refeição no local e Delivery. O investimento aproximado é de 120 mil reais. Em todos os modelos de franquia a Chicken Town auxilia no apoio presencial e treinamento completo. O modelo de logística elaborado pela Chicken Town permite que a rede esteja por todo o Brasil, hoje atuamos em SP, MG, ES, GO e SC.', NULL, 'SÃO PAULO', 1, NULL, 17, NULL, NULL, '2026-03-08 18:14:06.891', 'https://franquias.portaldofranchising.com.br/franquia-chicken-town/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '115000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73ze002geh0scd2amaa9', 'CASA DA OMA MORADA PARA IDOSAS(OS)', 'casa-da-oma-morada-para-idosas-os', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Hospedagem de Idosos', 2021, 2022, NULL, '2026-04-01 02:00:01.302', '2025-08-05 22:20:24.555', 125, NULL, 1, 2020, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/80456129-63df-481d-ab93-a5c40d5c3d20.jpeg', 5, NULL, NULL, '2025-10-10 10:21:53.000', 'https://franquias.portaldofranchising.com.br/franquia-casa-da-oma-morada-para-idosos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73zj002heh0sycumzxbm', 'OLHAR CERTO', 'olhar-certo', NULL, 'Saúde, Beleza e Bem Estar', 'SERVIÇOS MÉDICOS', 'Nós, da Olhar Certo, acreditamos na democratização da oftalmologia e temos o objetivo de levar saúde ocular de qualidade, com condições acessíveis, a milhares de brasileiros.', 2019, 2020, NULL, '2026-04-01 02:00:01.316', '2025-08-05 22:20:24.560', 126, NULL, 1, 2019, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5b67f9c3-b152-4086-9837-6102303bfa9c.jpg', 19, NULL, NULL, '2025-01-28 13:45:36.000', 'https://franquias.portaldofranchising.com.br/franquia-olhar-certo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73zq002ieh0s6ds5s2a8', 'ÓPTICA CENTER BY RCP', 'optica-center-by-rcp', NULL, 'Saúde, Beleza e Bem Estar', 'ÓTICAS', 'Rede Óptica Center única rede de ótica com 4 canais de faturamento, b2b, b2c e vendas online, nosso modelo de franquia é altamente lucrativo', 2019, 2021, '[\"https://www.youtube.com/watch?v=hCq7CETL8qo\"]', '2026-04-01 02:00:01.330', '2025-08-05 22:20:24.566', 127, NULL, 1, 2007, 'A franquia Óptica Center by RCP, fundada por Roberto Pedroso, é uma das principais redes de óticas no Brasil, destacando-se pela sua inovação e liderança tanto no mercado B2C quanto B2B. Com 17 anos de história, a empresa introduziu conceitos importantes no setor, como a Campanha da Boa Visão e o desenvolvimento de óculos de segurança com lentes de grau, beneficiando milhares de colaboradores em mais de 400 empresas. Desde que entrou no franchising em 2019, a Óptica Center teve um crescimento impressionante de cerca de 300% até 2024, consolidando-se como uma marca forte no cenário nacional. Em 2021, tornou-se membro da ABF - Associação Brasileira do Franchising, reforçando seu compromisso com a qualidade e a excelência. Atualmente, a rede conta com 55 unidades e oferece três modelos de loja: Tradicional, Prime e Fast. A Óptica Center se posiciona como uma excelente oportunidade de investimento, convidando interessados a agendar uma reunião para conhecer mais sobre como se tornar parte dessa franquia em expansão.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7850251d-d7e8-4a33-81d6-fd8da6e7629a.jpg', 34, NULL, NULL, '2025-09-09 12:24:22.000', 'https://franquias.portaldofranchising.com.br/franquia-optica-center-by-rcp/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0f61ced8-b529-4eb5-9148-be853033b726.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
