INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza740p002neh0s9uycd5li', 'OLHO VIVO VISTORIAS', 'olho-vivo-vistorias', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'PRESTAÇÃO DE SERVIÇOS DE VISTORIAS PARA TRANSFERÊNCIA, REGULARIZAÇÃO DE VEÍCULOS, CAUTELARES DENTRE OUTRAS.', 2009, 2010, '[\"https://www.youtube.com/watch?v=xB4cPSCiObw\"]', '2026-04-01 02:00:01.433', '2025-08-05 22:20:24.602', 132, NULL, 1, 2009, 'A Olho Vivo Vistorias é uma empresa prestadora de serviços para o mercado automotivo. \nAtualmente está presente em mais de 100 munícipios por todo o Brasil, com todas as franquias qualificadas, bem localizadas e com amplas estruturas. \nVisando sempre a qualidade nos serviços e a real segurança dos clientes, fundamentais para o bom atendimento, as franquias Olho Vivo Vistorias atendem todos os requisitos técnicos e procedimentos exigidos pela legislação em vigor. Trabalhando principalmente como ECV (Empresas Credenciadas em Vistorias de Veículos), responsáveis pelas vistorias de transferência de propriedade e/ou regularização de veículos, estando agregadas ao seu mix de serviços, outras modalidades de vistorias automotivas, como a cautelar. \nO interessado em abrir uma unidade receberá total apoio da Franqueadora, como treinamentos específicos, campanhas de marketing direcionadas a cada público e região, entre outros.', NULL, 'SÃO PAULO', 1, NULL, 93, NULL, NULL, '2026-03-08 18:18:09.160', 'https://franquias.portaldofranchising.com.br/franquia-olho-vivo-vistorias-servicos-automotivos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '65000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
