INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza741y002weh0seqa42jnb', 'SAPATELLA', 'sapatella', NULL, 'Moda', 'Calçados', 'Comercio varejista de Calçados e Acessórios Femininos', 2019, 2023, NULL, '2026-04-01 02:00:01.611', '2025-08-05 22:20:24.646', 141, NULL, 1, 2005, 'Nascemos no Rio e temos mais de 10 anos de história. Somos femininas, conectadas, presentes e queremos sempre mais. \nPor isso, passamos por um reposicionamento de marca e mergulhamos em nossa essência. \nNossos produtos proporcionam uma experiência mais urbana e divertida. \nQueremos entregar o básico com bossa, uma moda acessível para o dia a dia e com muito alto astral. \nFalamos com mulheres que amam moda e prezam pelo conforto, são jovens de espírito e de muita personalidade. \nMuito mais do que um simples calçado, valorizamos a experiência.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2d930c2e-b324-485c-8d91-971fd10af729.png', 33, NULL, NULL, '2026-03-08 18:22:22.526', 'https://franquias.portaldofranchising.com.br/franquia-sapatella/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
