INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza742h0030eh0sb18gqs48', 'SLIM CENTER ESTÉTICA E EMAGRECIMENTO', 'slim-center-estetica-e-emagrecimento', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A rede de franquia de estética e emagrecimento mais completa do Brasil.', 2021, 2021, NULL, '2026-04-01 02:00:01.679', '2025-08-05 22:20:24.665', 145, NULL, 1, 2017, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4d4bab15-382b-4717-b2a4-16a1b937eb74.jpg', 13, NULL, NULL, '2026-03-08 18:24:07.536', 'https://franquias.portaldofranchising.com.br/franquia-slim-center-estetica-e-emagrecimento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza742q0031eh0skn6odynf', 'BAFF\'S SALGADERIA', 'baff-s-salgaderia', NULL, 'Alimentação', 'Bares e Restaurantes', 'Rede de Franquias de Cafés e Salgados', 2018, 2018, '[\"https://www.youtube.com/watch?v=x1RYFAuTtpQ\",\"https://www.youtube.com/watch?v=r07zyaJ8Rak\",\"https://www.youtube.com/watch?v=z8kp2R-Wg6w\",\"https://www.youtube.com/watch?v=28VEMh5zTr0\",\"https://www.youtube.com/watch?v=rz4f3xZcoI8\"]', '2026-04-01 02:00:01.700', '2025-08-05 22:20:24.674', 146, NULL, 1, 2006, 'Fundada em 2006 pelo empresário Nélson Camargo, a Baff\'s Salgaderia atingiu a marca de 100 lojas em 12 estados brasileiros. \nA partir deste ano (2023), depois de 17 anos de experiência no mercado, a Baff\'s iniciou o processo de expansão, ofertando 200 novas franquias até 2025', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5da4888c-0103-426b-af44-19fc01b8fda4.jpg', 103, NULL, NULL, '2026-03-08 18:24:30.478', 'https://franquias.portaldofranchising.com.br/franquia-baffs-salgaderia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza742x0032eh0s9iiwlpc6', 'TEREZA ZANCHI SHIATSU E BEM ESTAR', 'tereza-zanchi-shiatsu-e-bem-estar', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'TEREZA ZANCHI Shiatsu e Bem-estar oferece terapias de relaxamento e bem-estar através de um método próprio e exclusivo em shopping centers, pontos de rua e SPA. 12 unidades em operação (base: 2024)', 2005, 2016, NULL, '2026-04-01 02:00:01.715', '2025-08-05 22:20:24.681', 147, NULL, 1, 2003, 'TUDO O QUE VOCÊ PROCURAVA NUM EXCELENTE NEGÓCIO! SEGURANÇA: Investimento seguro. Negócio de sucesso testado e comprovado. Acesso a um mercado muito promissor e pouquíssimo explorado.  NOVIDADE: Conceito moderno e de alto valor agregado, com posicionamento diferenciado e liderança no mercado.  LOCALIZAÇÃO: Diferentes formatos e modelos de negócios viáveis e atraentes para localizações comerciais “Premium”: Operamos em Shopping Centers, Centros Comerciais e hotéis. KNOW-HOW: Metodologias e técnicas orientais inspiradas no “Shiatsu”, sistematizadas e adaptadas às necessidades do mercado brasileiro. \n  EXPERIÊNCIA: Mais de 30 anos de atuação bem sucedida no segmento, através do Método Tereza Zanchi. CUSTO-BENEFÍCIO: Ótima lucratividade, baixo custo operacional e rápido retorno de investimento.  EXPANSÃO: Em breve, a Tereza Zanchi Shiatsu e Bem-Estar estará nas principais regiões do país.   SUPORTE DA FRANQUEADORA: Serviço de apoio à seleção e avaliação de pontos comerciais e de potencial de mercado Projeto arquitetônico, decoração e montagem do estabelecimento (serviço prestado por terceiros) Supervisão durante as obras, a ser executada por equipe local Suporte para compra dos móveis, equipamentos e utensílios para o estabelecimento Transferência do direito de uso da marca, logotipo e outros sinais visuais característicos Exclusividade territorial em determinado bairro, cidade ou região Treinamento inicial do franqueado, de seu gerente operacional (multiplicador) e principais funcionários: na área administrativa, técnica e operacional Transferência do know-how comercial e operacional Central de Compras, Central de Treinamento e Central de Eventos Apoio comercial e operacional na inauguração da unidade Orientação quanto à promoção de lançamento Publicidade contínua de modo cooperado Contrato de 5 anos (bem superior ao payback estimado, condição favorável ao franqueado), e renovável automaticamente por iguais períodos anuais Know-how após expiração do contrato: Requer não concorrência direta com o segmento de atuação do franqueador no decorrer do período de vigência do contrato de franquia e por 5 anos contados a partir de sua expiração  Sistema de gestão informatizado Controles administrativos e financeiros: visitas dos consultores de campo, relatórios gerenciais e financeiros Assessoria contínua do franqueador e treinamento contínuo, em função de eventuais lançamentos de novos serviços ou produtos complementares, ou ainda novos procedimentos operacionais É permitido ao Franqueado gerenciar mais do que uma unidade, sendo incentivado ao franqueado que invista seus lucros na abertura de mais de uma unidade   NÃO É EXIGIDO DO CANDIDATO FRANQUEADO: Experiência anterior no ramo (embora seja desejável) Conhecimentos profissionais na área de massoterapia, porém isto deve ser exigido dos colaboradores que irão prestar serviços na unidade e serão treinados no Método Tereza Zanchi.   O QUE SÓ NÓS TEMOS: Empresa pioneira e rede de referência no segmento de massagens terapêuticas em Shopping Centers (desde 2003), Centros Comerciais, hoteis e SPAs, sem concorrentes diretos, sendo a maior rede do sul do Brasil; Método próprio e exclusivo criado por Tereza Zanchi – Método Tereza Zanchi© Know-how manualizado de sucesso testado e comprovado e não disponível por nenhuma outra fonte. Infraestrutura de apoio e suporte de gestão; Treinamento contínuo e pesquisa constante no lançamento de novos produtos e serviços em relaxamento e bem-estar; Simplicidade da operação e facilidade de replicação em diferentes praças; Diferenciais de atendimento e fidelização; Oásis de tranquilidade nos turbulentos centros urbanos; Bom ticket médio por cliente (público classes A/B); Excelente faturamento e rentabilidade, negócio duradouro; Consulte-nos para oportunidades no exterior; Atividade em alta em 2021;  Rede associada à ABF; Descubra e saiba mais sobre esta rara oportunidade que oferecemos para todo o Brasil na qualidade de pioneiras e líderes num ramo ainda pouco explorado do segmento de Saúde, Beleza e Bem Estar!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8986b32f-beaf-440f-ab52-0805e02b4ade.jpg', 12, NULL, NULL, '2026-03-08 18:25:01.726', 'https://franquias.portaldofranchising.com.br/franquia-centro-shiatsu-tereza-zanchi-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74360033eh0s2w8h793o', 'LE PETIT MACARONS', 'le-petit-macarons', NULL, 'Alimentação', 'Docerias, Padarias e Cafés', 'Boutique de Macarons', 2014, 2018, NULL, '2026-04-01 02:00:01.729', '2025-08-05 22:20:24.690', 148, NULL, 1, 2014, '', NULL, 'RIO GRANDE DO SUL', 1, NULL, 25, NULL, NULL, '2026-03-08 18:26:51.737', 'https://franquias.portaldofranchising.com.br/franquia-le-petit-macarons/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza743e0034eh0s8tvbttxw', 'EMPADA MIX', 'empada-mix', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'Modelo de negócio com operação simples e excelente margem de lucro. São diversas opções de salgadinhos, empadas, açai e muito mais! Tudo tão delicioso que podemos afirmar que #TODOMUNDOAMA', 2023, 2024, NULL, '2026-04-01 02:00:01.744', '2025-08-05 22:20:24.699', 149, NULL, 1, 2009, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/af68ef12-1ef1-4e15-bf8f-5709190bbc9c.png', 7, NULL, NULL, '2025-02-07 09:51:35.000', 'https://franquias.portaldofranchising.com.br/franquia-empada-mix/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza743m0035eh0sdulz3oji', 'ÁGUA DE CHEIRO', 'agua-de-cheiro', NULL, 'Saúde, Beleza e Bem Estar', 'COSMÉTICOS E PERFUMARIA', 'Água de Cheiro a primeira marca de franquias de beleza do Brasil.', 1976, 2017, NULL, '2026-04-01 02:00:01.762', '2025-08-05 22:20:24.706', 150, NULL, 1, 1976, 'A marca ÁGUA DE CHEIRO surgiu em 1976, com uma pequena loja de perfumaria na cidade de Belo Horizonte. O sucesso foi imediato e, em 1980, a empresa já contava uma rede de 45 lojas. Pioneira no mercado de franquias de beleza e perfumaria, iniciou o processo de franchising na década de 80, e já na década de 90, era líder de mercado no segmento de beleza. Hoje com mais de 40 anos no mercado, a ÁGUA DE CHEIRO é reconhecida pela qualidade de seus cosméticos e fragrâncias. Em 2013, a rede contava com 900 lojas, mas com uma direção que enfrentava problemas de gestão. Até o início de 2014 contava também com um fabricante de perfumes e algumas lojas próprias. Diante de acentuada dificuldade financeira, em agosto de 2014 a antiga direção protocolou na Justiça pedido de Recuperação Judicial. Em 2016, a Marca ÁGUA DE CHEIRO foi adquirida pela BEAUTY FRANCHISING, empresa que integra o grupo de empresas da HOLDING NARSANA. Em 2017, a empresa retomou o processo de expansão pelo sistema de franchising, hoje conta com cerca de 200 lojas em todo o Brasil. EXPERIÊNCIA E SOLIDEZ Atualmente a BEAUTY FRANCHISING é responsável pela gestão do negócio de Franquias da marca ÁGUA DE CHEIRO. A HOLDING NARSANA é um grupo sólido, composto por 17 empresas com de mais de 27 anos de experiência de varejo de produto, gestão, logística, desenvolvimento de produto e marketing no mercado de beleza nos segmentos de Luxo, Seletivo, Semi Prestigio, Massivo e Profissional. As atividades do grupo abrangem mais de 50 marcas nacionais e internacionais de perfumes, cosméticos, produtos de toucador em um portfólio de mais de 1.000 diferentes produtos, entre marcas próprias, licenciadas e representadas com exclusividade para todo o Brasil. No segmento de Franquias, o grupo é também o Master Franqueador da marca Argentina HAVANNA no Brasil desde 2005 e hoje conta com mais de 65 lojas em todo o país, sendo reconhecida pelos seus alfajores, doce de leite e seus exclusivos cafés. NOSSA MISSÃO VANTAGEM COMPETITIVA DA MARCA ÁGUA DE CHEIRO FORMAS DE ATUAÇÃO O Franqueado pode atuar no formato Loja Física, seja de rua ou shopping, ou ainda no formato quiosque com metragens que vão de 8 a 16 metros. LOJA CONCEITO Shopping Metro Itaquera, SP Investimento a partir de R$ 180 mil QUIOSQUE Em 4 formatos de 8 a 16 m2 Investimento a partir de R$ 80 mil A partir de R$ 80 mil reais, você já pode investir em uma unidade quiosque da ÁGUA DE CHEIRO. Ficou interessado? Entre em contato! Shirleine Diniz Executiva de Expansão', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/94f843a9-4aff-41dc-97cd-e64cf2fe4114.jpg', 135, NULL, NULL, '2025-02-04 12:29:25.000', 'https://franquias.portaldofranchising.com.br/franquia-agua-de-cheiro-cosmeticos-e-perfumaria/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6a0da4bf-e372-43c1-b79b-fd84538fc29b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3cf214ed-8f13-4314-a9e8-2b24d690c6d6.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2729456f-24f0-48be-9cf9-8e59f113d51f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/963b9a99-2b49-44e9-a465-8055cb7dcf46.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8fd3f25e-7400-4ad7-befd-6695b26cd860.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/dec75332-d68a-4f10-b3f0-a5e72f97a049.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza743s0036eh0sriph3ty3', 'FORTEC', 'fortec', NULL, 'Educação', 'Ensino e Formação Acadêmica', '“Educação de Nível Técnico, Educação Infantil, Ensino Fundamental e Médio, Cursos Técnicos a Nível Médio e Pós Médio, Ensino Superior e Pós Graduação, Cursos de qualificação ou requalificação”', 2023, 2023, NULL, '2026-04-01 02:00:01.777', '2025-08-05 22:20:24.712', 151, NULL, 1, 1983, 'História da Marca Escola e Faculdade FORTEC fundada em 1983, teve seu início a partir da implantação dos cursos técnicos em Eletrônica e Instrumentação, a primeira turma de alunos formou-se em 1987. Em 1989, na Av. Presidente Wilson, n° 754, em São Vicente, ao lado três amigos - tendo como um dos grandes incentivadores, o doutor Walter Iervolino - teve um começo humilde com 120 alunos, 12 professores e 2 funcionários administrativos e em seus primeiros anos de existência, a Escola Técnica Fortec passou a suprir a necessidade existente no Polo Petroquímico de Cubatão, oferecendo mão de obra especializada na área de Automação para o mercado de trabalho. Em 1987, foi implantado o curso Educação infantil e após o Ensino Fundamental. Em 1990, inaugurou-se a sua segunda unidade localizada à rua Cândido Rodrigues, n° 304, em São Vicente, com os cursos Educação Infantil, Ensino Fundamental e cursos Técnicos. Em 1993, a Fortec expandiu suas fronteiras, levando para a cidade de Praia Grande, sua terceira unidade localizada na Rua Indaiá, 119 - Jardim Guilhermina. Em 1998, inaugurou-se sua quarta unidade localizada em São Vicente, na Av. Presidente Wilson, n° 1013, em São Vicente. Além disso, aos poucos, a sociedade foi sendo integrada à Fortec, principalmente por meio de projetos sociais. Um dos primeiros projetos sociais foi a palestra sobre drogas, início de um trabalho de conscientização, depois vieram outros e até hoje a Fortec desenvolve diversos projetos sociais. Em 2001, a Fortec se expandiu para a cidade de Cubatão, inaugurando uma nova unidade, localizada na Av. Nações Unidas, 956, tendo surgido, concomitantemente, a Faculdade FORTEC na cidade de São Vicente a qual continuou crescendo ao longo destes anos com diversos cursos superiores, procurando atender as necessidades educacionais de nossa região. E hoje possui 03 (quatro) unidades educacionais na cidade de São Vicente no estado de São Paulo. Em suas unidades educacionais já se formaram mais de 16.000 jovens e adultos ao longo desses anos. Hoje ministramos cursos para os níveis: Educação Infantil, Ensino Fundamental, Ensino Médio, Ensino Médio/Técnico, Ensino Superior e Técnico a Distância. Hoje contamos com um projeto de expansão ousado para, através do sistema de franquias, ser uma grande rede com marca reconhecida nacionalmente.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cfb10680-621c-434d-8a3c-37cffc69857c.png', NULL, NULL, NULL, '2026-03-08 18:27:31.523', 'https://franquias.portaldofranchising.com.br/franquia-fortec-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '960000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
