INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza744f0039eh0s87uckl98', 'SUPERGEEKS', 'supergeeks', NULL, 'Educação', 'EDUCAÇÃO', 'A SuperGeeks é a primeira e melhor Escola de Programação, Robótica e Ciência da Computação para crianças e adolescentes do Brasil, bem como referência em todo país.', 2015, 2018, NULL, '2026-04-01 02:00:01.820', '2025-08-05 22:20:24.735', 154, NULL, 1, 2014, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8f4e10ef-0f59-49b0-a139-62fa2ef53c3a.png', 37, NULL, NULL, '2025-02-07 10:37:53.000', 'https://franquias.portaldofranchising.com.br/franquia-supergeeks/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza744l003aeh0ss8sa9kav', 'BELLIOTICA', 'belliotica', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'OTICA', 2010, 2018, NULL, '2026-04-01 02:00:01.836', '2025-08-05 22:20:24.741', 155, NULL, 1, 1984, '', NULL, 'SÃO PAULO', 1, NULL, 17, NULL, NULL, '2026-03-09 14:40:50.561', 'https://franquias.portaldofranchising.com.br/franquia-belliotica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza744r003beh0s051lxg05', 'NOHA SHOES', 'noha-shoes', NULL, 'Moda', 'CALÇADOS', 'A Noha nasce para criar possibilidades ao mercado de moda masculina. Ofertamos de tudo que um homem pode querer referente a sapatos: de sandália a bota. Mais que sapatos, criamos possibilidades.', 2018, 2022, NULL, '2026-04-01 02:00:01.852', '2025-08-05 22:20:24.747', 156, NULL, 1, 2016, 'A Noha tem a honra de nascer e viver numa época em que o homem começa a dar muito mais valor à maneira com que se apresenta ao mundo e temos muito orgulho de ser um vetor importante dessa transformação. Nascemos a partir de uma insatisfação com a moda masculina nacional, onde o segmento de calçados estava congelado há pelo menos 20 anos. As mesmas marcas ofereciam os mesmos modelos de sapatos com o mesmo design, nas mesmas cores, dentro de um mesmo ambiente de loja há mais de duas décadas. Um país do tamanho do Brasil não podia se contentar com esse cenário. Sonhamos abrir portas para as tendências internacionais com elegância e autenticidade. Sonhamos permitir que todos possam expressar-se através da moda. Sonhamos a Noha e o sonho virou realidade. Uma marca sólida. Somos uma marca jovem, mas extremamente sólida. Passamos pelo período mais difícil da história do varejo nacional com muita responsabilidade e organização. Temos como prioridade número um a rentabilidade dos nossos franqueados e por isso trabalhamos todos os dias. Atravessamos esses dois anos de pandemia sem deixar de crescer. Desde Março de 2020 são 9 lojas inauguradas e uma meta de mais 9 em 2022, fechando o ano com 30 operações no país.\"', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c3e2131e-fa24-41d6-b4fc-f03c72b6757c.jpg', 23, NULL, NULL, '2025-02-10 13:16:50.000', 'https://franquias.portaldofranchising.com.br/franquia-noha-shoes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza744x003ceh0sauz9mzow', 'FLASH COURIER', 'flash-courier', NULL, 'Serviços e Outros Negócios', 'Logística e Operações', 'Prestação de serviços de Courier', 1997, 2005, NULL, '2026-04-01 02:00:01.867', '2025-08-05 22:20:24.754', 157, NULL, 1, 1994, 'Fundada em 1993, a Flash Courier é referência em logística no Brasil e conta com mais de 2 mil colaboradores diretos e mais de 6,5 mil indiretos. \nAdministrada pelas holdings JHI Administração e Participações Ltda. e JHO Administração e Participações Ltda, a Flash é líder no setor bancário e sua carteira de clientes é composta por bancos brasileiros, fintechs, meios de pagamento, empresas de ingresso, gestoras de benefícios, planos de saúde, entre outros segmentos. \nPara se ter uma ideia da proporção da operação, sua malha de distribuição realiza mais de 10 milhões de entregas por mês em mais de 48 mil endereços visitados por dia em todo o país, o que resulta em uma média de 15 entregas por segundo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d76575da-65f2-42b7-b865-50623356818d.png', 308, NULL, NULL, '2026-03-08 18:30:06.928', 'https://franquias.portaldofranchising.com.br/franquia-flash-courier/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '21000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7453003deh0sjxwu2oot', 'AUTHENTIC FEET', 'authentic-feet', NULL, 'Moda', 'Calçados', 'Comércio de Roupas, Acessórios e Calçados Esportivos', 2004, 1989, NULL, '2026-04-01 02:00:01.883', '2025-08-05 22:20:24.759', 158, NULL, 1, 1995, 'Fundada em 1995, em São Paulo-SP, a Franquia Authentic Feet é a loja destino para quem quer malhar com muito estilo. \nConectada com as últimas tendências do seu segmento, a Authentic Feet oferece a melhor experiência de compra para quem tem lifestyle esportivo dentro ou fora da academia. \nCom um mix diferenciado e produtos exclusivos de grandes marcas como Nike, adidas, Reebok, Mizuno, Asics, Skechers, Puma, Under Armour e Converse, a loja se destaca ainda por um ambiente descolado e uma equipe de atendimento especializada em esporte e estilo. Atualmente, a rede está presente com mais de 80 unidades em São Paulo, Rio de Janeiro, Minas Gerais, Espírito Santo, Paraná, Rio Grande do Sul, Mato Grosso, Mato Grosso do Sul, Distrito Federal, Goiás, Bahia e Pernambuco e possui ainda a loja virtual.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/010a0fae-6817-4ce1-8851-f8781e88b2a9.jpg', 97, NULL, NULL, '2026-03-08 18:30:46.347', 'https://franquias.portaldofranchising.com.br/franquia-authentic-feet-tenis/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d9c62ec4-b32a-4439-8c41-2b62c138a577.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c3485f55-ec8e-4049-b7fa-79ea7e7a44c9.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
