INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza745i003geh0seebojm30', 'BELARI GELATO ARTESANAL', 'belari-gelato-artesanal', NULL, 'Alimentação', 'Docerias, Padarias e Cafés', 'Gelateria de entretenimento', 2023, 2023, NULL, '2026-04-01 02:00:01.945', '2025-08-05 22:20:24.774', 161, NULL, 1, 2019, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4d1519ee-2998-4c7c-8143-5c54646b4bc8.svg', 5, NULL, NULL, '2026-03-08 18:32:15.034', 'https://franquias.portaldofranchising.com.br/franquia-belari-gelato-artesanal/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza745n003heh0s5qwvpju6', 'SESTINI', 'sestini', NULL, 'Moda', 'Acessórios Pessoais', 'A Sestini é especialista no segmento de malas de viagem, mochilas, bolsas e acessórios de qualidade e com o melhor custo-benefício, para acompanhar nossos clientes em todas as etapas da vida.', 2013, 2012, '[\"https://www.youtube.com/watch?v=eEJ8OBzb4Eo\",\"https://www.youtube.com/watch?v=9dzFVjv0Xds\",\"https://www.youtube.com/watch?v=rgfGtD25V8I\",\"https://www.youtube.com/watch?v=cn-8gdTwZTY\"]', '2026-04-01 02:00:01.963', '2025-08-05 22:20:24.779', 162, NULL, 1, 1995, 'Fundada em 1994 por Alexandre Roberto Benedek, a Sestini nasceu de um sonho de seu fundador de empreender no país que recebeu seus pais. Criou o negócio Sestini com o propósito de oferecer malas, mochilas e acessórios de alta qualidade ao mercado brasileiro, aproveitando a abertura da economia na época. Ao longo dos anos, a marca se destacou pela capacidade de antecipar tendências e evoluir junto com o mercado. Em 2005, consolidou-se como líder na distribuição de mochilas escolares com grandes licenças, como Disney, Mattel e Marvel. A partir de 2013, a Sestini redefiniu sua estratégia para fortalecer a marca, investindo em lojas próprias e franqueadas e no e-commerce, e em pouco tempo de consolida nesse mercado, atingindo mais de 60 operações em território nacional no ano de 2019, sempre buscando crescer franqueados alinhados ao perfil da marca e com operações rentáveis e sustentáveis no longo prazo. Comemorando 30 anos em 2024, a Sestini se consolidou como uma referência nacional, mantendo seu compromisso com inovação, qualidade e excelência no atendimento aos seus consumidores. Hoje, a marca conta com uma ampla rede de franquias e distribuição nacional, sendo reconhecida pela confiabilidade e pelo cuidado com seus produtos. A franquia Sestini oferece uma oportunidade única para quem busca investir em um negócio consolidado e de alta demanda no mercado de malas, mochilas e acessórios. Com mais de 30 anos de tradição, a Sestini é reconhecida pela qualidade, inovação e confiança, sendo a única marca nacional do setor a expandir por meio de franquias monomarca. Ao se tornar franqueado Sestini, você contará com um modelo de negócio testado e aprovado, suporte completo em todas as etapas, desde a escolha do ponto comercial até a operação da loja. A rede de franquias oferece uma ampla linha de produtos, com destaque para malas de viagem, mochilas escolares e produtos licenciados, atendendo a diferentes públicos. A Sestini investe fortemente em marketing, inovação e desenvolvimento de novos produtos, o que permite uma alta rotatividade de estoque e uma excelente margem de lucro para seus franqueados. Com um plano de expansão audacioso e um mercado em constante crescimento, impulsionado pelo aumento nas viagens e a demanda por produtos de qualidade, a franquia Sestini se destaca como uma oportunidade segura e lucrativa. Além disso, o franqueado tem acesso a treinamentos contínuos e ferramentas de gestão que garantem o sucesso da operação.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7fa7c9f0-98b1-4b13-82a9-e76e5c1fcb27.jpg', 61, NULL, NULL, '2026-03-08 18:32:39.284', 'https://franquias.portaldofranchising.com.br/franquia-sestini/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '444000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza745r003ieh0smzhfjvey', 'GARAGEM BARBA CABELO E BEM ESTAR', 'garagem-barba-cabelo-e-bem-estar', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Estéticos e Bem-Estar', 'Salão voltado exclusivamente para o publico masculino. Com servicos de cabelo, barba, tratamentos faciais, corporais, massagens, podologia e depilação. Pacotes de serviços dia do noivo.', 2012, 2018, '[\"https://www.youtube.com/watch?v=2DtiL7opMnM\"]', '2026-04-01 02:00:01.983', '2025-08-05 22:20:24.784', 163, NULL, 1, 2001, 'A fim de resgatar o clima das antigas barbearias, agregando um bom atendimento e outros servicos de estetica e bem estar, o Garagem Barba Cabelo e Bem Estar, teve sua primeira unidade inaugurada em agosto de 2001 no bairro de Moema na cidade de Sao Paulo. Hoje ja sao 11 unidades distribuidas nos principais bairros e shoppings da cidade de Sao Paulo e em Campinas.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a860db28-ad1e-457c-972f-5252473d9e15.jpg', 10, NULL, NULL, '2026-03-08 18:33:55.468', 'https://franquias.portaldofranchising.com.br/franquia-garagem-barba-cabelo-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza745x003jeh0sohxhvs5f', 'SUSHILOKO', 'sushiloko', NULL, 'Alimentação', 'Bares e Restaurantes', 'Modelo de negócio inovador, um novo conceito para o consumo da culinária oriental. A missão da empresa é ofertar comida japonesa de qualidade em um ambiente divertido e sofisticado a um preço justo.', 2010, 2010, '[\"https://www.youtube.com/watch?v=-iLueXEZKug\"]', '2026-04-01 02:00:02.011', '2025-08-05 22:20:24.790', 164, NULL, 1, 2007, 'Em 2008, inicia-se em Brasília a trajetória Sushiloko, que trouxe consigo um conceito inovador para o mercado de comida japonesa. Buscamos um bom atendimento, prezamos pela qualidade em nossos pratos e contamos com ambientes descontraídos, mas sempre com um preço justo. Nosso cardápio conta com várias opções individuais ou para compartilhar. Com dezenas de unidades no DF, GO, MG e MT, o Sushiloko também possui serviço delivery com garantia de que nosso produto chegue fresquinho na sua casa.', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1ccceb23-6dc1-45c9-abf6-202a696b02b7.png', 38, NULL, NULL, '2026-03-08 18:34:30.796', 'https://franquias.portaldofranchising.com.br/franquia-sushiloko-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
