INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7468003leh0s9npb6n28', 'ITALIA NO BOX', 'italia-no-box', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fast Food de Comida Italiana', 2018, 2023, NULL, '2026-04-01 02:00:02.044', '2025-08-05 22:20:24.801', 166, NULL, 1, 2016, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0ea3bacd-a10f-4128-8029-d3172bf49ad9.jpg', 34, NULL, NULL, '2026-03-08 18:35:27.783', 'https://franquias.portaldofranchising.com.br/franquia-italia-no-box-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '90000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza746e003meh0slo0wngku', 'MUNDO VERDE', 'mundo-verde', NULL, 'Alimentação', 'Mercados e Distribuição', 'LOJAS DE PRODUTOS NATURAIS, SUPLEMENTO PARA ATLETAS E BEM ESTAR', 1993, 1989, NULL, '2026-04-01 02:00:02.057', '2025-08-05 22:20:24.806', 167, NULL, 1, 1987, 'Invista em um Futuro Saudável e Lucrativo com o Mundo Verde. Junte-se à maior rede de produtos naturais e bem-estar do Brasil. \nDescubra como se tornar um franqueado de sucesso de uma das maiores lojas especializadas em produtos naturais e orgânicos da América Latina!  Investimento Inicial: A partir de R$250.000. Prazo de Retorno: De 24 a 36 meses. Taxas e Royalties: 5% de royalties e 1% de fundo de marketing.      Conheça nossa história de sucesso:     Linha do Tempo   1987 - Fundação com a primeira loja em Petrópolis/RJ.  1993 - Início da rede de franquias e inauguração da primeira franquia.  1994 - Chegada ao Rio de Janeiro/RJ.  2007 - Atingimos 100 lojas.  2009 - Controle adquirido por um fundo de investimento.  2011 - Inauguração de mais de 30 lojas.  2012 - Início da venda de produtos com marca própria.  2014 - Controle pelo Grupo Sforza.  2018 - Aquisição do maior e-commerce de produtos saudáveis e suplementos do Brasil.  2019 - Lançamento do e-commerce Mundo Verde.  2022 -Transição do e-commerce para um marketplace da rede franqueada.  2024 - Reformulação e rebranding dos produtos de marca própria.   Desde o início o objetivo da marca Mundo Verde é levar mais saúde às mesas brasileiras sem deixar o sabor de lado.    Hoje somos:          Neste formato hoje, o Mundo Verde recebeu vários prêmios:         Depoimento dos nossos franqueados:           Seja um franqueado   Por que escolher o Mundo Verde?    Marca Reconhecida e Premiada:\nConfiança e reputação construídas ao longo de 37 anos.  Know-how Comprovado:\nConsiderada a maior curadoria de produtos ligados à saúde, treino e bem-estar da América Latina.  Mix de Produtos Homologados:\nDiversidade e qualidade garantidas.  Gestão Participativa:\nConselho de franqueados ativo. Presença Digital Forte:\nVenda em múltiplos canais, incluindo site, WhatsApp, aplicativos e lojas físicas. Top of Mind no Segmento:\nReconhecimento como líder de mercado.       Apoio e treinamento garantido   Serviço de Atendimento ao Franqueado:\nSuporte contínuo;   Treinamentos Iniciais e Periódicos:\nCapacitação constante;  Universidade Mundo Verde:\nCursos especializados;  Equipe de Consultores de Campo:\nAssistência prática e estratégica.       Suporte Contínuo em Marketing e Operações    Campanhas Mensais:\nAções de marketing consistentes;   Ações de marketing consistentes:\nVisibilidade e alcance ampliados;    Suporte em Ações Pontuais:\nPersonalização de estratégias locais.          Nosso diferencial           Como se tornar um franqueado Mundo Verde Passo a passo:       Tempo Médio do Processo: De 20 a 90 dias, dependendo da escolha do ponto comercial', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/20c42a8d-f478-42d5-982b-7836b113ded0.jpg', 166, NULL, NULL, '2026-03-08 18:35:52.369', 'https://franquias.portaldofranchising.com.br/franquia-mundo-verde-produtos-naturais/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a349bcb2-a2a8-49db-8cb5-050f1d4a68d0.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8b52a8c4-9a2e-48a5-aaf1-0ed5e295a6fe.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7749bfe4-f405-45e2-a56a-3c482b47538e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/674863a3-66fa-4e6b-befa-32b78bba4f43.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cd2a5ce0-76b2-4352-aab5-8f5167155159.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a8d98d72-a891-4cca-85a0-014c98228965.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5e04c124-4ad7-4e99-8d35-2ca0c743252d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e87f9495-16ee-403e-a656-0199fb419b35.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/13fc77ea-5747-4b51-be6b-7cfc548e0dda.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b64afc2a-89fe-4f54-8f6b-388d3049ee49.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cb595fb6-d269-4bde-827e-ad2d41a3b97a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5f2f67f9-59fc-4280-8170-0cef0187eafc.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c92b966c-556a-40da-b5ad-84b4f1a03ba4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2601b319-3808-4b58-8d86-112229f5dd66.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '335000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
