INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza746v003peh0s6go9i8bg', 'ROSAMANGO', 'rosamango', NULL, 'Moda', 'CALÇADOS', 'Loja de calçados. Boutique de calçados', 2022, 2023, NULL, '2026-04-01 02:00:02.096', '2025-08-05 22:20:24.823', 170, NULL, 1, 2005, '', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/78cc8830-d305-4c9b-878d-b55907ad2341.png', NULL, NULL, NULL, '2025-09-01 16:42:24.000', 'https://franquias.portaldofranchising.com.br/franquia-rosamango-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7471003qeh0s5csrv4ol', 'TIMES IDIOMAS', 'times-idiomas', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'ESCOLAS DE IDIOMAS e EDUCAÇÃO', 2014, 2019, '[\"https://www.youtube.com/watch?v=wZ3RwBzJ3RU\",\"https://www.youtube.com/watch?v=Q70fN9XsCYc\",\"https://www.youtube.com/watch?v=koFkXOU6VMQ\",\"https://www.youtube.com/watch?v=4SIvSrJhmW8\"]', '2026-04-01 02:00:02.107', '2025-08-05 22:20:24.829', 171, NULL, 1, 2014, 'Fundada em janeiro de 2014, por profissionais com amplo Know How no segmento, a Times optou pelo franchising em julho de 2015, com a venda da primeira escola na condição de franquia.\n  Somos associados pela ABF desde 2019, conquistamos o selo de excelência em 2023. A marca disponibiliza para o mercado 03 (três) modelos de Franquias, sendo o primeiro de Franquia Comercial, o segundo de Franquias de Escolas e depois de amplo sucesso, com a mudança de comportamento dos alunos por conta da pandemia, a Times se transforma numa EdTech, lançando com exclusividade o modelo de negócio Nexus, com alta lucratividade e baixo custo operacional.    Diferenciais   A qualidade do ensino e a experiência do aluno, sempre foram foco principal da franqueadora.\n  Esta satisfação, mais a disciplina operacional construída de forma inteligente, garantem números impressionantes na média da rede Times, como: 95% de retenção de alunos e inadimplência abaixo de 5%, impactando positivamente no resultado financeiro da operação.   No modelo TIMES NEXUS, a receita é compartilhada e a gestão operacional fica com a franqueadora. \nO Parceiro comercial ganha sobre: Matrículas Material Didático Mensalidades Além disso, não cobramos Royalties para este modelo, ou seja, com um custo operacional muito baixo. \nA lucratividade da operação ultrapassa os 25%, atingindo o ponto de equilíbrio quase que de imediato e o retorno do investimento em até 12 meses.   Contamos com outros modelos de negócio, que se ajustam a capacidade de investimento dos candidatos e da região de interesse. \nModelo Escola, retorno do investimento em 24 meses, franquia comercial em 6 meses.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ae48fca8-c89d-4687-8176-ddfaa46f25f0.png', 40, NULL, NULL, '2026-03-08 18:38:17.286', 'https://franquias.portaldofranchising.com.br/franquia-times-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '35000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza747a003reh0sxkt2rb67', 'YANG', 'yang', NULL, 'Moda', 'VESTUÁRIO', 'Industria de modeladores corporais, linha lingeries modeladoras funcionais, linha gestante e pos parto , linha pós operatória e linha masculina', 2009, 2021, '[\"https://www.youtube.com/watch?v=eg9MBknqJlc\",\"https://www.youtube.com/watch?v=QIkvqUWH9QQ\",\"https://www.youtube.com/watch?v=ZMApQEVoe_g\",\"https://www.youtube.com/watch?v=-fHFklbFPQo\"]', '2026-04-01 02:00:02.119', '2025-08-05 22:20:24.838', 172, NULL, 1, 2004, 'A franquia Yang nasceu do sonho de trazer elegância, conforto e funcionalidade para as mulheres modernas. Não era sobre se esconder, era sobre se amar e através deste sentimento o grande objetivo da marca se tornou a inovação constante do produto e a busca pela entrega de uma lingerie elegante, sensual e moderna, mas sem abrir mão da funcionalidade dos produtos. Hoje orientamos sobre a escolha da Lingerie correta para cada biotipo, defendemos que não existem padrões, somos diferentes e temos direitos iguais, portanto a Yang trabalha para todas, nos esforçamos ao máximo para a entrega de resultados, e assim obter a realização das nossas clientes. As mulheres que hoje são consumidoras Yang, sabem o real diferencial da nossa marca, não somos uma marca de Lingerie comum, somos a marca de lingerie que pode mudar a autoestima dela através dos benefícios que nossos produtos oferecem. A YANG é a principal franqueadora de lingeries funcionais no Brasil, liderando o mercado há mais de 20 anos. Nossa missão é fornecer soluções em moda íntima que combinem conforto, benefícios e elegância para mulheres de todas as idades e estilos. Hoje estamos em 8 estados com 22 franquias Suporte Abrangente Orientações Sobre Gestão & Pessoas Controle De Estoque Marketing Estratégico Treinamentos Imersivos Para Vendedores E Franqueados Operação Otimizada Com Equipe E Sistemas Integrados Design E Inovação Em Todas As Linhas Fabricação Própria De Todos Os Produtos Tecnologia De Ponta No Desenvolvimento Dos Nossos Produtos Loja Modelo De 45 A 60m2 Certificada Pela Anvisa', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8d6b9968-9322-477f-9f2a-900a2736c2d0.jpg', 19, NULL, NULL, '2025-02-14 00:00:17.000', 'https://franquias.portaldofranchising.com.br/franquia-yang/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza747f003seh0snnxmn8tm', 'BOLO DA MADRE', 'bolo-da-madre', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Bolos Caseiros', 2013, 2015, NULL, '2026-04-01 02:00:02.131', '2025-08-05 22:20:24.844', 173, NULL, 1, 2013, 'A Bolo da Madre é uma franquia de bolos caseiros fundada em 2013, na cidade de Jundiaí, interior de São Paulo, pelas empresárias Daniela Pelipas e Fernanda Castanheda. \nTudo começou quando Daniela procurou um bolo simples para festejar o aniversário do filho, Lucca, e se deparou apenas com opções confeitadas que não atendiam à simplicidade que buscava para a reunião do filho com outras crianças. O que, à primeira vista, parecia uma frustrante dificuldade logo se revelou uma brecha no mercado: a falta de receitas simples que evocassem memórias afetivas e motivassem a construção de lembranças doces e simples na presença da família e dos amigos. \nAo longo dos mais de 7 anos de história já foram desenvolvidas mais de 60 receitas de bolos e tortas e abertas 50 lojas franqueadas nos modelos tradicional, reduzido e quiosque.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/56bf4b83-0c9b-4586-9acc-1af094082121.jpg', 54, NULL, NULL, '2026-03-08 18:39:18.600', 'https://franquias.portaldofranchising.com.br/franquia-bolo-da-madre/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '93000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza747l003teh0setebvila', 'PEZINHO E CIA', 'pezinho-e-cia', NULL, 'Moda', 'Calçados', 'Rede de calçados e acessórios infantis.', 2010, 2012, NULL, '2026-04-01 02:00:02.145', '2025-08-05 22:20:24.849', 174, NULL, 1, 2000, 'Acreditamos na força do amor pela criança. Muito trabalho e dedicação levaram a Pezinho e Cia a ser presença marcante na vida e nos melhores momentos de milhares de famílias. Este sonho cresceu e se fortificou ano após ano pelo carinho e pela confiança dos nossos clientes, pela rigorosa busca de fornecedores de qualidade e pelo respeito e união entre todo quadro de funcionários. \nEm abril de 2011, após a formatação da marca “Pezinho e Cia”, constituiu-se a empresa Pezinho Franchising e Comercio Ltda, respaldada em 32 anos de experiência no mercado de varejo, adquirida com a empresa Boutique Futura Mamãe, que iniciou suas atividades em 1979, quando abriu a 1ª loja na Praça Tamandaré, em Goiânia, atuando no segmento de moda gestante e infantil, incluindo calçados e acessórios infantis. \nEm 1981 a loja foi transferida para o 1º shopping de Goiânia – Flamboyant Shopping Center e em 2000 alterou o nome fantasia para Pezinho & Cia tornando – se especializada em calçados e acessórios da linha infantil e infanto-juvenil.  Com o sucesso das lojas inauguradas na cidade de Goiânia em bairros nobres Marista e Bueno e nos principais shoppings da cidade surge um novo desafio na Pezinho Franchising e Comércio:  expandir sua atuação no mercado nacional. \nAssim, ao longo dos anos, no segmento infantil em calçados e acessórios a franquia Pezinho vem inaugurando lojas em todo Brasil sempre prezando pela qualidade de seus produtos e fornecedores oferecendo as melhores marcas nacionais e importadas. Faça parte dessa história! Venha ser nosso Franqueado!', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d9ac59cc-9c84-4420-825c-befe9993cfb2.jpg', 31, NULL, NULL, '2026-03-08 18:39:58.349', 'https://franquias.portaldofranchising.com.br/franquia-pezinho-e-cia-calcados-infantis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
