INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7481003weh0sv2abiv11', 'KX-SAFE', 'kx-safe', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Trabalhamos com dois modelos de negócios. 1 - comércio de EPI (Equipamento de Proteção Individual) e Sign (Comunicação Visual)', 2023, 2023, NULL, '2026-04-01 02:00:02.180', '2025-08-05 22:20:24.866', 177, NULL, 1, 2021, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/41cb5eb2-07bb-416c-aa1e-2c5019ceb00a.jpg', NULL, NULL, NULL, '2025-09-09 16:23:02.000', 'https://franquias.portaldofranchising.com.br/franquia-kx-safe/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7489003xeh0s2untsly8', 'AMERICANA SAÚDE', 'americana-saude', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Franquia de drogarias com mais de 400 lojas, suporte completo em gestão e vendas, foco em crescimento sustentável e aumento de rentabilidade para donos de farmácias.', 2007, 2012, '[\"https://www.youtube.com/watch?v=uGtm-s-yMmA\"]', '2026-04-01 02:00:02.201', '2025-08-05 22:20:24.874', 178, NULL, 1, 2007, 'A Drogaria Americana nasceu com o propósito de oferecer serviços e produtos farmacêuticos de qualidade a preços acessíveis, sempre com foco no bem-estar e na saúde de seus clientes. Desde a sua fundação, a marca cresceu e se consolidou como uma das maiores redes de drogarias do Brasil, integrando o Grupo AMR Saúde, que atualmente conta com mais de 400 unidades em operação e um faturamento anual superior a R$ 1,5 bilhão. O que começou como uma farmácia de bairro, dedicada ao atendimento próximo e personalizado, rapidamente ganhou a confiança do mercado, expandindo sua presença para várias regiões do país. Em 2010, após perceber a necessidade de profissionalizar e padronizar o modelo de negócios, a Drogaria Americana iniciou sua trajetória no mercado de franquias, tornando-se uma oportunidade valiosa para empreendedores que desejam crescer no setor farmacêutico. POR QUE SER UM FRANQUEADO DA DROGARIA AMERICANA? 1. Poder de negociação e condições exclusivas Ao fazer parte da Drogaria Americana, você ganha acesso a negociações diferenciadas com os maiores fornecedores do mercado. Isso garante melhores preços, maior variedade de produtos e condições comerciais exclusivas, aumentando a competitividade da sua loja. 2. Marketing estratégico e campanhas promocionais A rede oferece suporte completo em marketing, com campanhas sazonais, estratégias de fidelização e forte presença digital, ajudando sua drogaria a atrair e reter mais clientes. Além disso, promovemos ações de incentivo e campanhas promocionais que aumentam o fluxo de vendas. 3. Suporte e treinamento contínuo O sucesso dos nossos franqueados é a nossa prioridade. Por isso, oferecemos acompanhamento constante em gestão de loja, vendas, controle de estoque e treinamentos específicos para capacitar sua equipe. Assim, você estará sempre atualizado com as melhores práticas do mercado. 4. Tecnologia e inovação A Drogaria Americana investe constantemente em tecnologia para ajudar você a otimizar a gestão do negócio. Sistemas integrados facilitam o controle de vendas, relacionamento com clientes e acompanhamento de resultados, trazendo mais eficiência para o seu dia a dia. Faça parte da nossa rede de sucesso! Ao se tornar um franqueado da Drogaria Americana, você estará ingressando em uma rede consolidada, com uma trajetória de crescimento e inovação no setor farmacêutico. Se você já possui uma drogaria, pode converter a bandeira para a nossa marca e aproveitar todas as vantagens que oferecemos. Se ainda não tem experiência no segmento, também estamos prontos para te orientar em cada etapa do processo. Entre em contato e descubra como podemos transformar seu negócio!', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3dfbcab0-d1b0-40bc-b38b-fb5cde2fafad.png', 197, NULL, NULL, '2026-03-08 18:41:44.973', 'https://franquias.portaldofranchising.com.br/franquia-americana-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '260000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza748l003yeh0sdw3zrp4l', 'OUTER. SHOES', 'outer-shoes', NULL, 'Moda', 'Calçados', 'A OUTER. é uma marca conceito que desenvolve produtos femininos e masculinos exclusivos, a partir de elementos naturais com design e sofisticação.', 2010, 2024, NULL, '2026-04-01 02:00:02.217', '2025-08-05 22:20:24.885', 179, NULL, 1, 2004, 'Seja bem-vindo a um novo conceito de desenvolvimento de calçados: a Outer. Uma marca inovadora, que desde 2004 vem mantendo um ritmo contínuo de crescimento, oferecendo ao mercado produtos com design diferenciado, reconhecidos pela sofisticação e conforto e projetados por pessoas que respeitam as leis da natureza e estão sempre atentas à ela, buscando expressar tal característica através de designs inovadores. \nSempre movida pelo empreendedorismo, inovação e paixão, a Outer abriu sua primeira loja em 2005 no Shopping Cittá América no Rio de Janeiro, seguida pela abertura da loja do Shopping Leblon. Já nos anos seguintes, a Outer. deu inicio ao seu projeto de expansão abrindo mais cinco lojas nos principais pontos comerciais do Rio e de Niterói e uma no Shopping Recife, marcando o início da expansão para todo o país.  Nossa missão:\nA Outer. não se resume a produzir calçados sofisticados e cheios de personalidade. Nossa missão é ser a melhor marca conceito de calçados do Brasil, que permite a transformação do homem absorvido pelo ritmo cosmopolita em um homem mais integrado ao compasso da natureza, sem perder sua modernidade e sofisticação contemporânea.  Nossos valores:\nO que torna a Outer. uma empresa diferente das demais é forma como ela se relaciona com os clientes, colaboradores, concorrentes, fornecedores e, acima de tudo, como busca atingir seus objetivos de negócios. \nPara Outer., tratar os clientes com carinho, valorizar os colaboradores, respeitar os concorrentes, desenvolver relacionamentos sólidos com os fornecedores, respirar empreendedorismo e sempre buscar melhorar cada processo, são os passos para se alcançar seus objetivos.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e282bf2a-1f93-4618-a9de-540048f0b603.svg', 32, NULL, NULL, '2026-03-08 18:43:01.101', 'https://franquias.portaldofranchising.com.br/franquia-outer-shoes-calcados/', NULL, NULL, '[]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '515000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza748t003zeh0saeit1fl1', 'GOLDEN MIX ÓTICA', 'golden-mix-otica', NULL, 'Saúde, Beleza e Bem Estar', 'ÓTICAS', 'Comércio varejista de artigos de óptica.', 2017, 2022, NULL, '2026-04-01 02:00:02.228', '2025-08-05 22:20:24.893', 180, NULL, 1, 1999, 'Destaque no ramo óptico, a Golden Mix atua de maneira humanizada Muito além de um modelo de negócio, a Golden Mix é uma empresa com uma proposta validada no ramo óptico com mais de 23 anos de mercado. Como a Golden Mix surgiu? A primeira unidade da Golden Mix surgiu em 1999, na cidade de Suzano, na região do Alto Tietê. Com a capacidade de servir, de entregar um serviço humanizado e de qualidade, a primeira unidade foi um sucesso e a marca se expandiu para as principais cidades de São Paulo. Após a validação do trabalho de qualidade, de treinamentos específicos aos gestores e aos colaboradores, a Golden decidiu expandir a marca e se tornou uma franquia após 19 anos. Em 2018, a empresa inaugurou a primeira franquia no centro de São Paulo e hoje, já conta com 12 lojas franqueadas ao todo. A Golden atinge classes variadas e está localizada nos melhores pontos As unidades da Golden Mix estão espalhadas por toda São Paulo e em pontos estratégicos de cada uma das cidades. As lojas ficam localizadas nos centros comerciais, onde existe uma maior concentração de passantes. Os principais clientes da rede Golden Mix atualmente são: B-, C, D e E. Com um estoque variado que conta com produtos exclusivos e das principais marcas de grife do mundo, a rede Golden Mix promove a melhora da qualidade de vida das pessoas com preços acessíveis e boa margem de lucro aos franqueados. A rede Golden Mix entrega um fullservice de excelência, conta com laboratórios próprios, produtos de qualidade, atendimento premiado e humanizado. Os óculos são essenciais na vida das pessoas Os óculos já se tornaram essenciais na vida de muitas pessoas. Segundo a estimativa feita pela Organização Mundial da Saúde, até 2050, 50% da população mundial deverá usar óculos. A Golden Mix faz parte de um ramo de serviços essenciais, está ligado diretamente com a melhora da qualidade de vida das pessoas. 80% da comunicação das pessoas com o mundo, se dá pela visão. Então, o uso do óculos é muito essencial na vida das pessoas. Por isso, apesar da crise econômica que vários setores enfrentaram nos últimos anos de pandemia, o mercado óptico seguiu crescendo. Segundo a Associação Brasileira da Indústria Óptica (Abióptica), a estimativa de crescimento anual é de 20% para o setor nos próximos dez anos. Em 2021, o setor contou com um crescimento e expansão sobre o ano anterior e chegou a 9,7%. A Golden se preocupa com o investidor Com um modelo de negócio de sucesso, a Golden Mix criou o modelo de franquias e procura por investidores que desejam crescer junto à empresa, independente da experiência prévia no ramo. Para que o investidor não se sinta incapaz ou tenha que passar por uma difícil adaptação, a rede conta com treinamentos exclusivos aos franqueados e aos colaboradores das novas unidades. Os treinamentos são feitos remotamente e presencialmente, completando a experiência necessária para que o investidor se sinta seguro para gerir a própria loja. Suportes fornecidos aos investidores A Golden Mix auxilia o investidor em todos os processos, desde a escolha do ponto, até a estruturação da unidade. Oferece treinamentos individuais, de equipe e de gestão, além claro, de suportes de T.I, de marketing e muito mais! Dentre os treinamentos ao franqueado estão: O treinamento de lojas vai introduzir o franqueado na rotina da loja, entendendo a dinâmica e como funcionam os processos; O treinamento técnico, para otimizar o trabalho dele em meio aos processos e de como lidar com as situações do dia a dia na loja. Quer abrir um negócio estruturado, com um modelo de negócio seguro e validado? Escolha a Golden Mix e venha escrever mais um capítulo de sucesso conosco!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/500d47a1-9bc9-42ae-a219-98123c20fead.jpg', 60, NULL, NULL, '2025-02-13 13:02:49.000', 'https://franquias.portaldofranchising.com.br/franquia-golden-mix-otica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74920040eh0sfgcm1vi1', 'FÓRMULA ANIMAL', 'formula-animal', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Farmácia de Manipulação Veterinária', 2013, 2018, '[\"https://www.youtube.com/watch?v=TWSqP3Q2LHg\"]', '2026-04-01 02:00:02.239', '2025-08-05 22:20:24.903', 181, NULL, 1, 2010, 'Em setembro de 2009 surgiu a ideia de abrir uma farmácia de manipulação veterinária em Jaraguá do Sul, estado de Santa Catarina. A farmacêutica Renata D’Aquino Faria Piazera, que desde a infância tem uma relação de paixão pelos animais, decidiu que este seria o negócio de sua vida, trabalhar com esses seres sempre foi um de seus sonhos. Em parceria com seu sócio Marcelo Piazera, que desde o início a incentivou a abrir a farmácia, em janeiro de 2010 iniciou-se uma história de serviço e atendimento de qualidade destinado ao mercado veterinário. A Fórmula Animal Farmácia de Manipulação Veterinária representa um avanço no mercado \"pet\" no que diz respeito à administração de medicamentos e cosméticos de uso exclusivo em animais. Os fármacos que antes eram disponibilizados comercialmente na forma de comprimidos, na Fórmula Animal são manipulados na dose certa, em formatos variados como biscoitos, pastas, xaropes, com sabores agradáveis e acarretam uma economia considerável ao cliente. Criou-se assim uma nova fórmula de saúde ao animal, garantindo a adesão do “paciente”, e por sua vez do proprietário, ao gerar facilidade e conforto. Não só de medicamentos vive a Fórmula Animal. Após realizar cursos na área de estética e cosmetologia para \"pets\", a farmacêutica desenvolveu uma linha de higiene e embelezamento veterinária que vem sendo muito usada em estabelecimentos de banho e tosa assim como em uso doméstico. O atendimento a animais de grande porte também é um de seus diferenciais, sempre visando o bem estar animal e facilidade na hora da administração. Conta atualmente com um sistema inovador de embalagens para acondicionar os medicamentos e permitir melhor manuseio na hora de oferecer o medicamento a cavalos e potros. A Fórmula Animal também cumpre um papel de responsabilidade social importante, apoiando e contribuindo com entidades que protegem os animais, a adoção e o cuidado aos mesmos é um ato do bem e transforma de forma positiva a vida de todos que vivem na comunidade. Esta farmácia tem como objetivo oferecer produtos que sejam manipulados pelo rigoroso processo de qualidade, promovendo desta maneira uma relação de fidelização com o cliente ao adquirir produtos seguros e eficazes. O atendimento padrão da Fórmula Animal representa uma atenção diferenciada que leva em consideração valores como responsabilidade, atenção e conferência em todas as suas etapas. Para nós o cliente tem a preferência e o animal é Excelência!', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/99c63696-c7b8-47da-b8d9-8a5010be6100.png', 92, NULL, NULL, '2026-03-08 18:44:06.644', 'https://franquias.portaldofranchising.com.br/franquia-formula-animal/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza749c0041eh0svdnops8o', 'RAJAH ESFIHAS', 'rajah-esfihas', NULL, 'Alimentação', 'Bares e Restaurantes', 'Rajah Esfihas - Excelência em Franquia Missão: Elevar a gastronomia. Público: 20-47 anos, priorizando qualidade. . Localizado na Oliver\'s Pizza. Investimento eficiente, retorno ágil.', 2023, 2023, NULL, '2026-04-01 02:00:02.250', '2025-08-05 22:20:24.913', 182, NULL, 1, 2018, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/133886bc-4f8f-4d74-b987-55b75c3a45a2.png', NULL, NULL, NULL, '2026-03-08 18:45:26.189', 'https://franquias.portaldofranchising.com.br/franquia-rajah-esfihas/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza749i0042eh0spoofnfq5', 'AÇAI TREVO', 'acai-trevo', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Açaís, Gelatos e Cremes.', 2018, 2023, '[\"https://www.youtube.com/watch?v=-08GzPC_gUk\",\"https://www.youtube.com/watch?v=FgQztqxR1h8\",\"https://www.youtube.com/watch?v=q_iBlESZpFU\"]', '2026-04-01 02:00:02.260', '2025-08-05 22:20:24.918', 183, '43c1fff6-a024-4336-b5af-4cf21bc8c239', 1, 2014, 'Tudo começou com um sonho. Era o sonho da fundadora da Trevo, ter um negócio próprio. “Eu tinha experiência comercial, tinha uma poupança acumulada em um ano e, o que é principal: Eu tinha o desejo, a gana, a vontade.” Ao receber um insight durante um curso de autoconhecimento, tomou a decisão. Adquiriu know how se cercando de pessoas com notório conhecimento técnico, frequentou feiras do setor, desenvolveu e homologou fornecedores reconhecidos nacional e internacionalmente. Motivada pelo desenvolvimento de uma receita única, exclusiva e revolucionária que faria história ao mudar a percepção da experiência de consumo do Açaí. Assim começou a história da Trevo Açaí.', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/22d096fa-3988-4b91-8d73-a3d972143e63.png', 23, NULL, NULL, '2025-09-09 16:06:25.000', 'https://franquias.portaldofranchising.com.br/franquia-acai-trevo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
