INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza749s0044eh0snxfg1j9y', 'DÍDIO PIZZA', 'didio-pizza', NULL, 'Alimentação', 'Bares e Restaurantes', 'Dídio Pizza Modelo de negócio chave na mão - KNOW HOW de mais de 28 anos, pioneira no segmento, com operação 100% Delivery, com processos bem definidos não dependendo de mão de obra especializada.', 2006, 2010, '[\"https://www.youtube.com/watch?v=L6yVZAxYRK4\"]', '2026-04-01 02:00:02.287', '2025-08-05 22:20:24.928', 185, NULL, 1, 1994, 'Em 1993, Elídio Biazini inaugurou a primeira unidade, pensando em operar como uma rede de pizzarias, própria ou através de franquia. Logo veio a segunda unidade, ainda não formatada, porém franqueada. Dídio era a forma carinhosa como seu avô, imigrante italiano natural da cidade de Silea/Treviso, apelidava as pessoas que ele não sabia o nome. Tanto é que acabou virando o seu apelido também. A Didio Pizza surgiu com foco total no Delivery. Atualmente, a rede está presente nas principais regiões da cidade de São Paulo, Grande SP e Interior. Os Pilares de crescimento da marca estão alicerçados no investimento constante em tecnologia, na qualidade dos produtos e serviços e na entrega rápida (no máximo 30 minutos após o pedido). Ao longo de 29 anos, a Dídio Pizza investe em infraestrutura, processos e desenvolvimento de produtos, sendo pioneira em pizzas com massa integral, sem glúten e receitas de pizzas veganas. A marca Dídio é inovadora no seguimento Food e segue em plena expansão, mantendo a gestão familiar com a participação da segunda geração no negócio.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8fd274a9-6e56-4b2d-bb3c-201f374e1555.jpeg', 21, NULL, NULL, '2026-03-08 18:46:49.231', 'https://franquias.portaldofranchising.com.br/franquia-didio-pizza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza749y0045eh0s5vpo242u', 'TECFIT', 'tecfit', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Studios para condicionamento físico através da utilização de equipamentos de eletroestimulação muscular. \"Academia sem pesos\".', 2017, 2023, '[\"https://www.youtube.com/watch?v=6m6KOQthT_E\",\"https://www.youtube.com/watch?v=nWNPOFXJOZo\"]', '2026-04-01 02:00:02.301', '2025-08-05 22:20:24.934', 186, NULL, 1, 2017, 'Descubra a revolucionária franquia TECFIT - ACADEMIA SEM PESOS, fruto de uma parceria estratégica com a XBODY, líder mundial em eletroestimulação muscular e a única com aval da ANVISA e do FDA (semelhante à Anvisa no EUA) no Brasil. A tecnologia de eletroestimulação muscular nasceu na década de 1960 e inicialmente foi utilizada por fisioterapeutas e fisiologistas somente para o tratamento e recuperação de lesões musculares. Contudo, no início dos anos 2000 um novo rumo foi dado à utilização desta tecnologia. Em busca de resultados excepcionais e com o fim de reduzir a probabilidade de lesões, nadadores profissionais buscaram otimizar seu tempo fora das piscinas, reduzindo o seu tempo de musculação e aumentando o seu desempenho nos treinos de força com a tecnologia de eletroestimulação muscular. A partir de 2017 surge a TECFIT, pioneira no Brasil, tornou essa inovação acessível a todos. Treinos personalizados de 20 minutos ativam centenas de músculos pelo corpo inteiro e sem riscos de lesões. Sob a liderança de especialistas renomados e uma equipe de sucesso, cresceu mesmo na crise do COVID-19. Atualmente contamos com mais de 40 unidades em todo o país, é uma franquia promissora que tem como visão: \"Mudar a Vida das Pessoas\".', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f4338d78-3af8-4212-855c-71d3fe66ae40.png', 44, NULL, NULL, '2026-03-08 18:47:30.829', 'https://franquias.portaldofranchising.com.br/franquia-tecfit/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
