INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ah0049eh0scc647qza', 'HELP! LOJA DE CRÉDITO', 'help-loja-de-credito', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'A help! é uma rede de franquias de lojas de crédito de sucesso, focada em oferecer soluções multisserviços para aposentados, pensionistas do INSS e servidores públicos.', 2016, 2016, NULL, '2026-04-01 02:00:02.342', '2025-08-05 22:20:24.954', 190, NULL, 1, 2016, 'Com foco em produtos para Aposentados, Pensionistas do INSS e Servidores Públicos, help! é uma rede de lojas de crédito com forte presença nacional. São mais de 5 milhões de clientes atendidos todos os anos, com mais de R$ 700 milhões em créditos concedidos. \nMas não é apenas esse público que help! atende. Nossos franqueados oferecem um portfólio de produtos diversificado, com inúmeras soluções financeiras em um só lugar. É dinheiro na mão, sem burocracia e com as melhores condições do mercado. Opções para quem está sem dinheiro, para quem busca um cartão de crédito sem anuidade e com as melhores taxas de juros do mercado e também para quem precisa de crédito, mas está sem margem no consignado, além da antecipação do Saque FGTS. Franqueado help! ainda conta com todo o suporte, da abertura à implantação, ações de marketing nacionais e regionalizadas, tudo sem cobrança de taxa de propaganda.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ee6f1c3a-e957-4b06-b650-3537365b50ee.png', 914, NULL, NULL, '2026-03-08 18:49:13.374', 'https://franquias.portaldofranchising.com.br/franquia-help-loja-de-credito/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '137818.42', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
