INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74aw004ceh0syzraxwu9', 'ÓTICAS VÊNUS', 'oticas-venus', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Varejo de produtos de ótica (Óculos, armações, lentes e lentes de contato).', 2019, 2019, NULL, '2026-04-01 02:00:02.380', '2025-08-05 22:20:24.969', 193, NULL, 1, 1967, '', NULL, 'RIO GRANDE DO SUL', 1, NULL, 1, NULL, NULL, '2026-03-08 18:50:38.657', 'https://franquias.portaldofranchising.com.br/franquia-oticas-venus/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74b1004deh0sk9szk6db', 'CALIFORNIA COFFEE', 'california-coffee', NULL, 'Alimentação', 'Bares e Restaurantes', 'Coffee Shop', 2005, 2004, NULL, '2026-04-01 02:00:02.395', '2025-08-05 22:20:24.974', 194, NULL, 1, 2002, 'O California Coffee é uma empresa que busca viver novas experiências para que você possa viver as suas. O nosso conceito é fruto de uma visita feita ao Brasil em 1999, quando nos questionamos por que o maior exportador de café do mundo, que produz um café tão fino e de alta qualidade não tem a oportunidade de saborear o melhor que produz. A resposta era muito simples: quase toda a produção dos melhores e mais finos cafés é vendida para exportação. A partir de então os fundadores do California Coffee decidiram trazer a ideia do Specialty Coffee House para o Brasil. Hoje, oferecemos somente a melhor classe de café arábica, cultivado em grandes altitudes, tornando o crescimento mais lento e um sabor mais refinado. Temos nossa própria torrefação, onde torramos nosso café diariamente seguindo os mais restritos padrões europeus. Trabalhamos constantemente para aprimorar a qualidade e a consistência do nosso café para trazer o melhor de cada grão para você. Nossa missão: ser uma empresa inovadores, contemporânea com o objetivo de servir o melhor e mais moderno conceito em café do Brasil.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6e14ef87-c87e-4be3-a14e-e19993a166de.jpg', 41, NULL, NULL, '2026-03-08 18:50:58.212', 'https://franquias.portaldofranchising.com.br/franquia-california-coffee/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '250000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74b7004eeh0s0ub2itdq', 'SAÚDE CLÍNICA POPULAR', 'saude-clinica-popular', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Clínica Médica Popular', 2019, 2022, NULL, '2026-04-01 02:00:02.407', '2025-08-05 22:20:24.979', 195, NULL, 1, 2016, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1bc26841-d7c5-4d88-8f80-ceffab8a9197.png', 20, NULL, NULL, '2026-03-08 18:51:36.568', 'https://franquias.portaldofranchising.com.br/franquia-saude-clinica-popular/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '400000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74bb004feh0shhl6ot59', 'LOVE BRANDS', 'love-brands', NULL, 'Moda', 'Acessórios Pessoais', 'A Lovebrands reúne na mesma franquia as melhores soluções em presentes do mercado, com Imaginarium, Puket, Balonè e Chillibeans em um espaço feito para vivenciar a experiência de cada marca.', 2012, 2013, '[\"https://www.youtube.com/watch?v=ImoFo8zHOTc\"]', '2026-04-01 02:00:02.418', '2025-08-05 22:20:24.984', 196, NULL, 1, 2012, 'É a união da, PUKET, BALONÈ e IMAGINARIUM, que identificaram uma oportunidade de crescimento nas cidades pequenas e médias. Uma franquia Inovadora, posicionada para o mercado de Presentes. Franquia LOVE BRANDS!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0fd576dc-b95a-4cf8-8769-eaabccd6df13.jpg', 54, NULL, NULL, '2026-03-08 18:51:59.714', 'https://franquias.portaldofranchising.com.br/franquia-love-brands-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74bh004geh0sd8u6sblo', 'IP SCHOOL INGLÊS PARTICULAR', 'ip-school-ingles-particular', NULL, 'Educação', 'EDUCAÇÃO', 'Aulas de Inglês Particulares e Personalizadas à partir dos 6 anos. Foco no objetivo dos alunos. Metodologia própria, ensinamos o idioma mais presente no mundo de forma Natural, sem livros.', 2020, 2021, NULL, '2026-04-01 02:00:02.427', '2025-08-05 22:20:24.989', 197, NULL, 1, 2015, 'Com microfranquia homebased e sem material didático, IP School revoluciona o ensino de inglês! Rede dobra de tamanho na pandemia e se mostra pronta para oferecer suporte a franqueados de todo o Brasil Com apenas R$ 33 mil, o investidor pode se tornar franqueado da IPSchool – Inglês Particular, uma escola de ensino de inglês que dobrou de tamanho na pandemia e traz uma proposta bastante inovadora ao mercado:a de ensinar o idioma apenas em aulas particulares e sem a venda de material didático ao aluno.É isso mesmo: na IP School, o franqueado não se preocupa em cumprir com quotas de compras de livros, que oneram seu faturamento e também fazem com que o aluno tenha o aprendizado engessado. “Nossa metodologia é baseada nas necessidades e vivências do aluno, o que faz com que as aulas sejam personalizadas. Dessa forma, elas se tornam mais interessantes e focadas no que ele mais precisa, que é falar inglês, de uma vez por todas!”, diz Márcio Cafezeiro, sócio-franqueador e coordenador pedagógico da rede. Com o aluno ‘soltando a língua’, vem a fidelização e a indicação de mais alunos. “O microfranqueado pode formar uma rede de professores, que atendem virtualmente ou em empresas. Ele tem um raio de atuação e sua atividade é bastante comercial, buscando clientes e parcerias. Ele não precisa ser fluente no idioma e nem ministrar as aulas”, diz Rauel Araruna, sócio-franqueador responsável pela Expansão. A IP School tem 12 unidades, entre próprias e franqueadas, no Estado de São Paulo. Além da microfranquia, também possui escolas físicas – e quem deseja abrir uma delas investe a partir de R$ 149 mil. Nos dois últimos anos, a rede faturou R$ 2 milhões (por ano), mantendo-se estável mesmo na pandemia. “O ano de 2020 foi realmente mais difícil. Mas, implantamos com rapidez a modalidade virtual e os alunos adoraram. É até difícil nos lembrarmos de que praticamente não tínhamos aulas virtuais antes da pandemia e que, agora, essa é a modalidade predominante e preferida dos nossos alunos”, comenta Fábio Ferreira, o mais novo sócio da franqueadora, que cuida da gestão da rede.Os três sócios têm a meta de chegar a todo o Brasil. O franqueado recebe todo o treinamento comercial, de gestão da unidade franqueada (seja ela uma microfranquia ou franquia física) e os professores têm treinamentos constantes sobre a metodologia da marca, que foi criada e é constantemente aperfeiçoada por Márcio Cafezeiro. “Nós nos baseamos na programação neurolinguística para aprimorar o ensino e esse diferencial faz parte da transferência de know-how da franqueadora para a rede franqueada”, comenta o especialista. O suporte da IP School pode ser oferecido a franqueados de todo o Brasil, até mesmo de forma remota.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c5f8c5e6-9cdb-4db3-a24a-b6ace5279686.jpg', 14, NULL, NULL, '2025-03-07 15:55:50.000', 'https://franquias.portaldofranchising.com.br/franquia-ip-school-ingles-particular/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74bm004heh0sc38nl0og', 'NTW CONTABILIDADE E GESTÃO EMPRESARIAL', 'ntw-contabilidade-e-gestao-empresarial', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Especialista em Contabilidade Consultiva e Gestão Empresarial, a NTW é perfeita para quem quer empreender ou fazer a conversão de seu escritório, Seja parte da maior e mais premiada rede Contábil', 2010, 2011, '[\"https://www.youtube.com/watch?v=vQeUplMTmSE\",\"https://www.youtube.com/watch?v=m_au9NC9Qxw\"]', '2026-04-01 02:00:02.438', '2025-08-05 22:20:24.994', 198, NULL, 1, 1989, 'Em 2015, 2016, 2017, 2018, 2019, 2020, 2022, 2023 e 2024, a NTW Franquia Contábil foi chancelada com o Selo de Excelência em Franchising pela ABF (Associação Brasileira de Franchising), sendo a única franquia contábil a receber este Selo Internacional por 5 anos consecutivos. Em 2015, 2016, 2017, 2018, 2019, 2020, 2021, 2022, 2023 e 2024 a NTW Franquia Contábil conquistou o prêmio Melhores Franquias do Brasil pela revista Pequenas Empresas & Grandes Negócios.   Somos a maior e mais premiada rede de escritórios contábeis da América Latina   Com mais de 35 anos de atuação, a NTW é a maior e mais premiada rede de escritórios contábeis da América Latina. Possuindo mais de 270 unidades no Brasil, Portugal e Moçambique, a empresa também tem presença nos Emirados Árabes, além de já ter atendido mais de 22 mil clientes. Especialista em contabilidade consultiva e gestão empresarial, nossa experiência e presença internacional nos permitem oferecer soluções precisas e resultados consistentes.   Contamos com uma rede de parceiros estratégicos para enriquecer nossas soluções e garantir a excelência em cada serviço prestado. E com o objetivo de fazer negócios e estabelecer conexões empresariais lucrativas, temos o Conexão NTW, o Intercâmbio de Negócios da NTW em que disponibilizamos a oportunidade de contadores franqueados e seus clientes conhecerem o mundo.    NTW Prime   A NTW Prime é um clube de vantagem das unidades referências da NTW Franquia Contábil. Reconhecidos pelos próprios clientes pela excelência em serviços contábeis, os escritórios NTW Prime mantém um alto padrão na qualidade dos serviços e satisfação do cliente.   NTW Doctor   A NTW Doctor, a nossa franquia especializada para o setor da saúde, oferece soluções contábeis totalmente dedicadas para atender as necessidades de clínicas, consultórios médicos e profissionais da área. Com estratégias personalizadas para o público alvo, capacitamos contadores em um dos ramos que mais cresce no Brasil.    Se você é contador ou possui um sócio contador e deseja se especializar nesta área, a NTW Doctor é a oportunidade perfeita. Aqui, você encontrará treinamento por unidade para se especializar no setor da saúde, participando de um modelo colaborativo com excelentes oportunidades de negócios.   NTW Agro   A NTW Agro é a nossa franquia contábil especializada em atender o agronegócio, um setor em constante crescimento no Brasil. Com possibilidades de lucro e expansão, a NTW Agro oferece soluções contábeis altamente especializadas para produtores rurais, empresas do setor e demais profissionais da área, garantindo um atendimento excepcional às demandas exclusivas do agronegócio.   Contando com todo o suporte da maior e mais premiada rede de escritórios contábeis da América Latina, a NTW Agro é ideal para contadores ou sócios de contadores que desejam se especializar neste setor vital da economia brasileira. Com nosso treinamento e estratégias personalizadas, você pode se tornar uma referência em contabilidade para o agronegócio na sua cidade.     Conheça nossas Modalidades e Franquias Segmentadas   A NTW é uma rede de franquia para você, contador que desejar investir no seu primeiro escritório contábil ou para você que já possui o seu escritório e deseja fazer a conversão da sua marca. Nossos modelos de negócio são:    Start: Para cidades de até 30 mil habitantes, a Start é a opção perfeita para quem deseja ter o seu primeiro negócio contábil. Modalidade em que o franqueado irá implantar uma unidade home office ou em coworking, sendo toda a operação processada pela franqueada ou por fornecedor homologado, por ela indicado.    Light: Modalidade ideal é para você que já é empreendedor ou deseja empreender com baixo custo de investimento em cidades com até 30 mil habitantes, podendo investir do zero ou fazendo a conversão da sua marca. A unidade pode ser implantada em home office, coworking ou física.   Express: Modalidade desenvolvida para quem deseja empreender com baixo custo de investimento em cidades acima de 30 mil habitantes. A unidade pode ser implantada em home office ou coworking.    Select: Nossa modalidade Select é para você que já é empreendedor ou deseja empreender em uma cidade acima de 30 mil habitantes. Você pode implantar uma unidade física ou converter a sua marca com todas as vantagens que só a NTW tem.   NTW Doctor e NTW Agro: Nossas franquias especializadas no setor da saúde e do agronegócio é para você que deseja se tornar um contador especializado nos setores que mais crescem no país. Com o nosso apoio, uma variedade de serviços contábeis e um software especializado, garantimos um treinamento que irá te capacitar e destacar no mercado atual. A unidade pode ser implantada em formato físico, coworking ou home.   Na rede NTW, 98,6%* dos franqueados da NTW abririam esta franquia novamente e 99,1%* indicariam para amigos e familiares que buscam um novo negócio.   Márcio Torezzi: “Sou apaixonado pela rede NTW. Sou um entusiasta dessa empresa. Temos treinamento de vendas, liderança e convenções, além dos sistemas que nos ajudam no controle de processos e atividades. Eu sou suspeito de falar, já que tenho 4 unidades da NTW Contabilidade e 1 unidade da Tutoreanos Consultores de Negócios (Franquia do Grupo NTW). Tenho muita satisfação com minha escolha e, principalmente, o retorno financeiro desejado.” Márcio Torezzi – NTW Prime Pirassununga / NTW Prime São Carlos / NTW São Carlos Centro / NTW Prime Ribeirão Preto / Tutoreanos São Carlos   Alzieth Vilhena: “Montei meu escritório iniciando do zero e hoje tenho uma estrutura impecável! Posso afirmar que a expansão da unidade acontece com muita animação e cuidado. Conquistei clientes importantes na minha região e em vários estados do país com muito orgulho. Meu escritório não para de crescer!” Alzieth Vilhena – NTW Prime Belém Metropolitan Tower   Alexandre Castro: “Eu já estava estudando o mercado de franquias contábeis há muito tempo porque sentia a necessidade de expandir meu negócio. Também queria estruturar melhor os três pilares que movem meu escritório: pessoas, processos e ferramentas. E foi aí que eu encontrei a NTW! Fiquei encantado com o modelo de negócio e as melhorias contínuas, sempre pensando em como atender melhor seus clientes. Hoje, possuo 2 unidades NTW Contabilidade.”  Alexandre Castro – NTW Prime Teresópolis / NTW Juiz de Fora Santa Helena', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f1c48188-a68b-4cdc-b3f9-ca4903b93819.svg', 201, NULL, NULL, '2026-03-08 18:52:37.674', 'https://franquias.portaldofranchising.com.br/franquia-ntw-contabilidade-e-gestao-empresarial/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
