INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74c8004leh0selrt3u1h', 'REI DO GADO CASA DE CARNES', 'rei-do-gado-casa-de-carnes', NULL, 'Alimentação', 'EMPÓRIOS, MERCADOS E LOJAS DE CONVENIÊNCIA', 'Desde nossa fundação em 2019, o Rei do Gado redefine padrões de qualidade e atendimento. Nossa dedicação à excelência e inovação nos consolidou como líderes na região serrana do Rio.', 2023, 2024, NULL, '2026-04-01 02:00:02.476', '2025-08-05 22:20:25.016', 202, NULL, 1, 2019, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c7b0fdf9-5737-449a-b3ba-0b056937a053.png', NULL, NULL, NULL, '2025-09-17 17:05:09.000', 'https://franquias.portaldofranchising.com.br/franquia-rei-do-gado-casa-de-carnes-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74cd004meh0s2p9x4jbj', 'SHEKINÁ BURGER & AÇAÍ', 'shekina-burger-acai', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'Consiste em hamburguerias especializadas na comercialização de hambúrgueres artesanais, disponibilizando aos clientes um cardápio amplo e ainda uma ampla variedade em açaís.', 2021, 2022, NULL, '2026-04-01 02:00:02.486', '2025-08-05 22:20:25.021', 203, NULL, 1, 1990, 'A história da empresa Shekiná Burger & Açaí começou em 2017, quando o sócio proprietário, já inserido no ramo de restaurantes desde sua infância, quando chegou a uma cidade Chamada Guer na Suíça, onde conheceu a fabricação do queijo Camembert, o qual ficou impressionado pelo sabor e qualidade, foi então que partiu para o ramo de hamburguerias, para que pudesse criar seu primeiro lanche que seria com o queijo camembert, o qual fora criado no mesmo ano de 2017, denominado “cheese”. Inspirada no cenário histórico das cozinhas em que fora familiarizado desde pequeno e também pela cozinha europeia, trouxe para a região de Araçatuba e Birigui SP, uma releitura singular desses dois ícones gastronômicos. A vontade de inovar não parou por aí. Logo decidiu inovar na diversificação de lanches e na produção própria do hamburguer, molhos e temperos em suas lojas, e ainda realizou a junção da comercialização de açaí nas hamburguerias. Até agora, já percorremos um caminho de inovação e bom atendimento protagonizados por um delicioso e único sabor. É assim que conquistamos muitos clientes no interior de São Paulo e região, contando com lojas em shoppings e no centro da cidade. Esperamos espalhar por todo Brasil, para que todos possam experimentar esse sabor inigualável, não apenas na região da sede mas em todo Brasil.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d99bde4f-f1df-4af3-a03e-a7c98a478959.jpg', 6, NULL, NULL, '2025-03-06 18:00:28.000', 'https://franquias.portaldofranchising.com.br/franquia-shekina-burger-acai/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
