INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74co004oeh0sqt37c66d', 'NOCA MOVEIS', 'noca-moveis', NULL, 'Casa e Construção', 'MÓVEIS', 'Somos uma marca inovadora, pioneira na fabricação de móveis em Polyvinyl, um produto voltado para os novos tempos e que chega com um DNA de design, durabilidade e sustentabilidade.', 2022, 2022, NULL, '2026-04-01 02:00:02.506', '2025-08-05 22:20:25.032', 205, NULL, 1, 1990, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e44c0854-0de2-491c-9825-5295cd3e014f.jpg', 20, NULL, NULL, '2025-09-10 12:42:03.000', 'https://franquias.portaldofranchising.com.br/franquia-noca-moveis-casa-e-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74cu004peh0slkzkxq88', 'IE INTERCÂMBIO NO EXTERIOR', 'ie-intercambio-no-exterior', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Intercâmbio no Exterior, Especialista em Educação Internacional e Carreira, Cursos de idiomas, Ensino Médio e Superior. Oportunidades em diversos países para idade entre 10 a 60 anos.', 2005, 2010, '[\"https://www.youtube.com/watch?v=668Ip-gwcjs\",\"https://www.youtube.com/watch?v=E1ZpLB9oJPI\"]', '2026-04-01 02:00:02.516', '2025-08-05 22:20:25.039', 206, NULL, 1, 1998, 'Desde 1998, a IE Intercâmbio orienta estudantes e profissionais na realização de intercâmbios pelo mundo. Com franquias espalhadas de norte a sul do Brasil e também no exterior, a IE é uma das mais tradicionais e premiadas agências do segmento. Com um modelo de negócios simplificado, durante a nossa história aprendemos como oferecer diversos recursos de tecnologia, ferramentas de capacitação, além de encontros e ações que permitem uma gestão participativa do franqueado, tornando-os especialistas em educação internacional e donos do seu próprio negócio.  A IE se preocupa muito com a satisfação de seus colaboradores, monitoramos através de pesquisas internas e externas os indicadores de performance e satisfação de cada Franqueado. Como em qualquer negócio, o franqueado IE terá que trabalhar duro e superar muitos desafios para conquistar o sucesso. Por isso sabemos da importância de prestar um suporte profissional e sempre bem próximo ao franqueado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a4bfa364-2c98-492b-a02f-d524a347e037.png', 31, NULL, NULL, '2026-03-08 18:57:16.181', 'https://franquias.portaldofranchising.com.br/franquia-ie-intercambio-no-exterior-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '22000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74d1004qeh0sqclxyfh7', 'GRUPO CONECTA SEGUROS', 'grupo-conecta-seguros', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Franquia especializada na comercialização de todo tipo de seguros, venda de consórcios', 2018, 2024, NULL, '2026-04-01 02:00:02.526', '2025-08-05 22:20:25.045', 207, NULL, 1, 2010, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/27cf88e5-39e0-428d-9801-947d7cd99ca0.png', 4, NULL, NULL, '2025-10-16 10:47:23.000', 'https://franquias.portaldofranchising.com.br/franquia-grupo-conecta-seguros-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74d6004reh0seq294euy', 'CCAA', 'ccaa', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'ENSINO DE INGLÊS E ESPANHOL', 1969, 1989, '[\"https://www.youtube.com/watch?v=VkINBY6jc2U\"]', '2026-04-01 02:00:02.536', '2025-08-05 22:20:25.050', 208, NULL, 1, 1961, 'Desde 1961, nossa metodologia exclusiva e nosso material didático próprio transformam vidas com a proficiência dos idiomas Inglês / Espanhol. \nCom educação, as pessoas podem fazer mais escolhas sobre suas vidas. A capacitação, a valorização dos professores, o estímulo ao protagonismo dos alunos e a inserção tecnológica transformaram o CCAA numa escola de alto padrão de qualidade. Essa informação é corroborada por meio de depoimentos de alunos e ex-alunos, além dos resultados por eles obtidos, como uma das melhores colocações do Brasil no exame TOEFL ITP®, que está entre as principais certificações internacionais da língua inglesa. \nAlém das franquias espalhadas por todo o país e no exterior, o CCAA também está presente nas aulas de idiomas de escolas e colégios de todo o Brasil, que têm a oportunidade de oferecer aos seus alunos a excelência do método de ensino CCAA.  Nas franquias as aulas são híbridas, com turmas online ao vivo e presencial. \nDessa forma, os alunos têm flexibilidade e liberdade para decidir, a cada dia, onde querem aprender inglês e espanhol: em uma unidade ou em qualquer outro lugar.  E foi assim, a partir do sonho apaixonado do Sr. Waldyr Lima, que teve início a jornada desta marca. Uma marca em que a história das pessoas se mistura à história das suas vidas.\n    Mais do que motivos, temos motivações. Veja como apoiamos nossos franqueados:  Depoimentos de franqueados \n     Abrir uma franquia CCAA significa tornar-se parceiro de uma empresa forte, unir-se a uma marca consolidada e ter, desde o início do negócio, todo suporte, orientação e ferramentas necessárias para ter uma franquia e um empreendimento bem-sucedido.  Venha fazer parte dessa trajetória de sucesso!', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/61348937-d246-48c3-9af3-3b69460f05a2.jpg', 650, NULL, NULL, '2026-03-08 18:58:25.163', 'https://franquias.portaldofranchising.com.br/franquia-ccaa-escola-de-idiomas/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e6dc187f-8d44-4223-bfb3-e0c7f16f9f1d.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8ed8b779-1106-46f2-abcc-d3ce31a25a04.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/43cafcd7-5a1c-4374-afb6-56fe88f36b67.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '90000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
