INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74dn004ueh0s7ptzdww4', 'VIA MIA', 'via-mia', NULL, 'Moda', 'Acessórios Pessoais', 'A Via Mia é uma marca carioca, que tem por objetivo crescer encantando. Vendemos moda em acessórios, calçados e bolsas. Nossa franquia veio após longo estudo de 5 franquias pilotos, 100% de verdade.', 2009, 2015, '[\"https://www.youtube.com/watch?v=osR4cUtRCf0\"]', '2026-04-01 02:00:02.569', '2025-08-05 22:20:25.067', 211, NULL, 1, 1998, 'Alma colorida, sorriso no rosto. Nossa história nasceu em 1998, quando enxergamos a necessidade de criar bolsas, sapatos e acessórios que fizessem a diferença, unindo design, cor, qualidade, usabilidade e preço. Desde então a Via Mia conquistou muito espaço no coração das cariocas e cresce cada vez mais pelo Brasil, sempre atualizada nas necessidades e tendências dos dias atuais através de mix criativos e na forma de se comunicar. A Via Mia nasceu para fazer diferente! E esse desejo fez da Marca uma franqueadora com mais de 100 pontos e vendas espalhadas por todas as regiões do Brasil.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cca6ff26-a9ce-48eb-8de3-183e314e7007.jpg', 70, NULL, NULL, '2026-03-08 19:00:09.656', 'https://franquias.portaldofranchising.com.br/franquia-via-mia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
