INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74e7004yeh0s4djwbrcp', 'ROYAL TRUDEL', 'royal-trudel', NULL, 'Alimentação', 'Bares e Restaurantes', 'Modelo conhecido como \"fast casual\", podendo-se enquadrar como doceria ou cafeteria. A marca serve um doce típico de Praga - possuindo eventualmente variações salgadas e mix de cafés.', 2018, 2022, NULL, '2026-04-01 02:00:02.607', '2025-08-05 22:20:25.088', 215, NULL, 1, 2016, '', NULL, 'RIO GRANDE DO SUL', 1, NULL, 2, NULL, NULL, '2026-03-08 19:01:47.139', 'https://franquias.portaldofranchising.com.br/franquia-royal-trudel/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ec004zeh0s9tshub3t', 'CONTAINER SEGURANÇA', 'container-seguranca', NULL, 'Casa e Construção', 'Construção e Reforma', 'Locação de Containers, Módulos Habitáveis e Equipamentos para Obras. Sistema Inovador e Econômico e Banheiros Ecológicos.', 2012, 2020, '[\"https://www.youtube.com/watch?v=aHArQkQ-WeY\"]', '2026-04-01 02:00:02.617', '2025-08-05 22:20:25.093', 216, NULL, 1, 2009, 'Venha fazer parte da Maior Rede de Franquias de Locação de Containers do Brasil! Presente em mais 1000 cidades A Container Segurança revolucionou o segmento, criando uma solução de armazenamento móvel, simples, barata, segura e ágil que é utilizado por equipes em obras, em todo o Brasil, para acondicionar os materiais e ferramentas ou por qualquer pessoa que deseja guardar algo de valor em um cofre de aço (Container). Foi reconhecida como a melhor franquia pela “Pequenas Empresas & Grandes Negócios”, por sua qualidade e responsabilidade, sendo destaque do programa de TV da Rede Globo de Televisão, além da participação em diversas mídias, como “Exame”, “Uol”, “Estadão” e “O Globo”. Com unidades atendendo mais de 1.000 cidades do Brasil, é associada ABF (Associação Brasileira de Franchising) e destaque entre as franqueadoras de serviços em geral, tornando-se a maior franquia desse segmento há anos. Mais do que uma franquia, a Container Segurança busca constantemente a inovação para trazer mais praticidade e conforto para as obras, através de produtos ecologicamente corretos e investimentos em tecnologia.  Vantagens de ser um franqueado Marca consolidada Experiência no segmento de locação de CONTAINERS Fornecedores homologados Treinamento e suporte Marketing e publicidade Modelo de Negócio testado e aprovado Padronização e reconhecimento Maior poder de negociação Troca de conhecimento Índice de sucesso muito maior Auxílio de uma equipe experiente Apoio na gestão do negócio Apoio nos aspectos jurídicos Auxílio no planejamento financeiro Estamos com condições especiais para novas unidades. A hora é agora!', NULL, 'SÃO PAULO', 1, NULL, 35, NULL, NULL, '2026-03-08 19:02:10.481', 'https://franquias.portaldofranchising.com.br/franquia-container-seguranca/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1789c134-8193-43e0-a53d-9002e807c534.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74eh0050eh0sl86xih77', 'SHOPPING DA VISÃO', 'shopping-da-visao', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Comercio varejista de artigos ópticos', 2019, 2023, NULL, '2026-04-01 02:00:02.627', '2025-08-05 22:20:25.098', 217, NULL, 1, 2019, '', NULL, 'PERNAMBUCO', 1, NULL, NULL, NULL, NULL, '2026-03-08 19:03:05.258', 'https://franquias.portaldofranchising.com.br/franquia-shopping-da-visao-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '80000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74em0051eh0sw5cgtr1k', 'SENSE BIKE', 'sense-bike', NULL, 'Saúde, Beleza e Bem Estar', 'ESPORTE E RECREAÇÃO', 'A Rede S2 Bike Shop é a mais COMPLETA rede de comercialização de Bicicletas, Acessórios e Serviços do Brasil: São 26 operações em 36 meses de expansão, com unidades em 7 estados mais o DF.', 2020, 2023, NULL, '2026-04-01 02:00:02.636', '2025-08-05 22:20:25.103', 218, NULL, 1, 2019, 'Paixão é a palavra que nos define. Antes mesmo de sermos uma empresa com foco em lucros, nós somos apaixonados por bikes, pelo que fazemos e principalmente em causar boas sensações. Nascemos em 2009, inicialmente apenas como fábrica e comércio atacadista de bicicletas, como braço da LAGOA PARTICIPAÇÕES, com o objetivo de atender as demandas voltadas para a mobilidade urbana e, desde então nos tornamos referência no mercado pelos projetos elétricos pouco explorados por marcas nacionais. Em 2012 lançamos nossos três primeiros modelos: EASY, BREEZE e WIND, com a tecnologia de pedal assistido, bateria de lítio e 24v, que logo tomaram as ruas. Fomos tão inspiradores que em novembro de 2013, nossas bikes serviram de modelo para o Conselho Nacional de Trânsito (CONTRAN), regulamentar a utilização das bicicletas elétricas através da resolução 465. Experiência? Temos de sobra! Com mais de 40 anos de atuação no ramo das 2 rodas, possuímos estrutura própria que conta com os processos de: criação, importação, estoque, distribuição pós-venda e comercial. Em 2014 fomos além. Inauguramos nossa fábrica própria com grande apelo ecológico em gestão de resíduos, e com maquinários de ponta passamos a fabricar nossos quadros e criamos uma linha de montagem moderna para bikes elétricas e convencionais na cidade de Manaus/AM. Já em 2015 firmamos parceria com a Swift Carbon empresa Sul-Africana com grande know-how na confecção de quadros de carbono e passamos a vislumbrar uma linha de bikes de alta performance que poderia elevar a SENSE a outro patamar no segmento. 2(dois) anos mais tarde entendemos que teríamos que concentrar esforços e investimentos para chegarmos ao nosso objetivo de sermos a marca de bikes mais relevante no cenário nacional e para isso adquirimos nossa parceira Swift Carbon e instalamos uma nova fábrica em Portugal na cidade do Porto. Pós estudar a demanda do mercado, a necessidade da mobilidade urbana, o desejo dos consumidores entendemos que poderíamos com nossa dedicação e paixão fazer algo mais.  Nasce em 2019 o projeto S2 Bike Shop, um projeto sério e rentável com design inovador e portfólio 100% das marcas Sense Bike e Swift Carbon com complemento de acessórios das principais marcas do mercado. E atualmente? Atualmente somos 26 operações ativas em 7 estados mais o Distrito Federal e buscamos novos parceiros que assim como nós é apaixonado pelo ciclismo e empreendedorismo. PERFIL DO FRANQUEADO Apaixonado pelo ciclismo; Ter experiência comprovada de atuação no setor de varejo (mínimo 12 meses); Possuir capacidade de investimento com recursos próprios; Dedicar-se aos negócios da franquia, atuando conforme as regras estabelecidas; Ter aptidão e desejo de atuar em um modelo de negócio já formatado; Comprometimento com administração da operação; Dedicação de 8 a 12 horas diárias para a operação; Dinamismo, com espírito empreendedor; Proatividade, que reúna capacidade de análise e discernimento; Conhecimento do mercado local VANTAGENS E BENEFICIOS Ótimo custo x benefício para instalação; Isenção de royalties e taxa de publicidade nos dois primeiros anos de operação; Empresa com mais de 40 anos de experiência no mercado das 2 rodas; Fábrica própria com 10mil m2 dedicada à tecnologia para quadros em alumínio; Fabricação de quadros em carbono by Swift Carbon; Projetos Arquitetônicos para as lojas; Suporte em marketing, avaliação de varejo e treinamento especializado; Convenções anuais para lançamento do Model Year; Marketing nacional, com investimentos em revistas, influenciadores, eventos próprios com chancela CBC e equipes de níveis nacional e internacional SUPORTE QUE OFERECEMOS Estudo de viabilidade do negócio; Apoio na busca do ponto comercial; Acompanhamento pré e pós inauguração; Equipe capacitada para suporte focada em resultados; Projeto arquitetônico; Sistema de controle operacional PROCESSO DE IMPLANTAÇÃO Preenchimento de cadastro pré-qualificação enviado pelo departamento de franquias; Visita ao QG da empresa; Entrevista com departamento de franquias/expansão; Assinatura da circular de oferta de franquia (COF); Assinatura do contrato de franquia; Processo de seleção do ponto comercial; Aprovação do ponto comercial; Planejamento para inauguração (projetos, layout, obra e adaptações); Treinamento inicial do franqueado e equipe; Inauguração da loja; Acompanhamento pós-inaugural, através de consultoria de campo e apoio operacional periódico.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/85ab6d02-0afa-42d6-9b6d-4b779df7140a.png', 26, NULL, NULL, '2026-03-08 19:03:28.568', 'https://franquias.portaldofranchising.com.br/franquia-sense-bike/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74es0052eh0sh6fijelr', 'PATRONI PIZZA', 'patroni-pizza', NULL, 'Alimentação', 'Bares e Restaurantes', 'Pizzaria (Forno a Lenha) Trattoria (Carnes e Massas) Chopperia (Petiscos e Chopp)', 2003, 1989, '[\"https://www.youtube.com/watch?v=UrHLd3o7pnM\"]', '2026-04-01 02:00:02.645', '2025-08-05 22:20:25.108', 219, NULL, 1, 1984, 'Uma franquia diferente \nApós quase 20 anos de sucesso, a Patroni Pizza formatou seu próprio modelo de franquia e em 2003, abriu sua operação de franchising, atendendo a uma forte demanda do mercado. Para fazer um modelo de franquia que levasse a marca da Patroni vários detalhes foram analisados. O compromisso com o consumidor, por exemplo, deve se estender a todas as franquias, de forma que a qualidade dos produtos e a excelência do atendimento sejam similares ao das lojas próprias. Para suprir esta necessidade, nosso modelo inclui treinamento e apoio para franqueadores e suas equipes. Com estes e outros cuidados, em poucos anos nos tornamos referência em franquia no ramo de alimentação.  Bons negócios para todos \nNossa tradição no ramo de pizzarias unida a um projeto de franquia customizado faz toda a diferença para nossos franqueados. Enquanto o mercado registra um crescimento anual médio de 14% em faturamento, a Patroni Pizza tem um crescimento de 210%. Todas as etapas de negócio já foram e continuam sendo testadas e otimizadas pelo franqueador. Os franqueados não trabalham em um processo de tentativa e erro, pois contam com metodologia, filosofia de negócios, sistemas e apoio que dão segurança ao desenvolvimento de seus restaurantes. Outro ponto positivo para o sucesso é a percepção de qualidade e preço justo que os clientes têm em relação à Patroni Pizza. Em comparação com o mercado a Patroni Pizza tem o menor investimento médio de capital, o menor prazo médio de retorno, a menor cobrança de taxas e a maior rentabilidade média de investimento. Com certeza um bom negócio para quem está pensando em trabalhar no ramo da alimentação.  Os grandes diferenciais da franquia Patroni Pizza  Uso da Marca - a Patroni Pizza cede sua marca para ser explorada pelo franqueado em seu território, conforme nossas normas e padrões.  Apoio na seleção de pontos comerciais - considerando as características consideradas ideais para o local de uma unidade Patroni, orientamos o potencial franqueado na procura de pontos comerciais.  Financiamento bancário - podemos auxiliar cada franqueado na elaboração de projeto para encaminhamento e análise de financiamento bancário com condições especiais e competitivas, dependendo única e exclusivamente da aprovação do crédito, por parte do banco.  Montagem da loja - você pode escolher entre ter nossa assessoria junto aos profissionais de arquitetura que cuidarão do desenvolvimento do projeto e execução de obra.  Treinamento ao franqueado e à sua equipe - a unidade piloto Patroni Pizza serve de centro de treinamento do franqueado e sua equipe, trabalhando com todos os produtos, serviços e equipamentos que serão oferecidos na franquia.  Pesquisa e desenvolvimento de novos produtos, equipamentos e serviços - este é um trabalho permanente, que garante a qualidade da Patroni Pizza.  Apoio operacional no início de operação da franquia - disponibilizamos funcionários para acompanhar os primeiros dias de operação da nova franquia in loco.  Supervisão de campo constante e planejada - temos uma equipe de consultores de campo que garante o relacionamento aberto e contínuo entre franqueador e franqueados. Os consultores resolvem problemas e orientam profissionalmente o franqueado na busca do sucesso, além de promover treinamentos locais em cada franquia. \nAcompanhamento de desempenho - o termo é feed-back. Em função de relatórios periódicos dos franqueados, acompanhamos o desempenho de cada unidade.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f18c8bb7-df07-4a83-93e0-2a5d03b9aa83.jpg', 101, NULL, NULL, '2026-03-08 19:05:46.839', 'https://franquias.portaldofranchising.com.br/franquia-patroni-pizza-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ey0053eh0s2e10pior', 'BEM COSMÉTICOS', 'bem-cosmeticos', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Loja especializada de cosméticos multimarcas', 2023, 2024, NULL, '2026-04-01 02:00:02.655', '2025-08-05 22:20:25.114', 220, NULL, 1, 2023, '', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/105b5869-7ef6-4807-8805-e8efe899d168.png', 11, NULL, NULL, '2026-03-08 19:07:38.008', 'https://franquias.portaldofranchising.com.br/franquia-bem-cosmeticos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '330000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74f30054eh0s8sxppdj1', 'SETH', 'seth', NULL, 'Moda', 'ACESSÓRIOS PESSOAIS', 'A Seth é uma marca de joias reconhecida pelo design sofisticado e ousado. Uma joia feita com primor, rica em detalhes e alto padrão de acabamento. A Seth é Design e inovação com Bossa Brasileira!', 2024, 2024, NULL, '2026-04-01 02:00:02.664', '2025-08-05 22:20:25.119', 221, NULL, 1, 2012, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/75b12944-a7bf-4597-b540-9cc7d0e1cc51.png', 11, NULL, NULL, '2025-03-17 15:02:46.000', 'https://franquias.portaldofranchising.com.br/franquia-seth-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74f80055eh0syajjd8i3', 'SIRÈNE FISH & CHIPS', 'sirene-fish-chips', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Sirène é um lugar onde se alimenta o corpo e a alma com as melhores coisas da vida com o Melhor Fish & Chips & Fun. Uma franquia com fácil gestão, equipe enxuta e boas vibrações o ano todo.', 2018, 2020, '[\"https://www.youtube.com/watch?v=wwUrpOOCMk8\"]', '2026-04-01 02:00:02.673', '2025-08-05 22:20:25.124', 222, NULL, 1, 2016, 'O Sirène nasceu de um jeito meio louco. A ideia inicial era que o espaço, locado por Afonso Neto, um dos sócios, se tornasse uma livraria. Quando sua mãe, que seria sua sócia no negócio, desistiu da ideia, veio a inspiração de transformar o espaço – que fica na Trajano Reis, centro da boemia curitibana – em um bar. Mas não era para ser só mais um bar. Tinha que ser diferente. Especial. Afonso havia acabado de voltar de uma viagem à Austrália, onde conheceu o fish & chips, iguaria ainda pouco explorada por aqui. Apostar neste sabor diferenciado foi o primeiro acerto do Sirène. Afonso então uniu forças com dois amigos, Lucas Muller e Raphael Umbellino. A união não foi apenas financeira: eles literalmente colocaram “mãos à obra” para fazer o bar acontecer. Reformaram todo o imóvel, derrubaram paredes, pintaram, lixaram, restauraram... deixaram o ambiente do jeito estiloso e descolado que cativa todo mundo que passa por lá. Logo, outro amigo – Alexandre Lopes – entrou na onda, para ajudar na administração do bar. Em janeiro de 2016, era inaugurado o primeiro Sirène, e a mistura de culinária diferenciada, cerveja gelada e o carisma dos jovens sócios – que também atendiam no balcão – fez o bar cair no gosto do público. O Sirène começou a crescer, e logo não coube mais só na Trajano: outras filiais abriram pela capital paranaense. O sucesso fez clientes tornarem-se potenciais investidores, e “como faço para abrir uma filial do Sirène na minha cidade?” tornou-se a pergunta da vez. O início desta expansão foi planejado com cuidado, e logo um sólido modelo de franquias foi estruturado. Hoje o Sirène conta com 8 lojas em 4 estados (PR, SC, SP e MG). Formou-se uma grande família de pessoas que vibram na mesma frequência, curtem o melhor da vida e estão sempre atrás dos melhores rolês. Se identificou? Quer entrar pra essa família? Então chega mais e vamo pra cima!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b4efe2c1-52a5-4a9d-be11-590d7ec5f21f.png', 11, NULL, NULL, '2026-03-08 19:08:11.573', 'https://franquias.portaldofranchising.com.br/franquia-sirene-fish-chips/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '260000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74fd0056eh0suf3eosjv', 'PHENOM IDIOMAS', 'phenom-idiomas', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Franquia de escola de idiomas', 2021, 2022, '[\"https://www.youtube.com/watch?v=MoIVgmTBkm4\"]', '2026-04-01 02:00:02.683', '2025-08-05 22:20:25.130', 223, NULL, 1, 2020, 'A Phenom é uma escola de idiomas com uma metodologia única e avançada. \nAqui nossos franqueados possuem suporte vitalício desde o primeiro momento. \nCom a Phenom o investimento toma forma, gera lucros e obtém resultados surpreendentes. Mesmo em pouco tempo, a Phenom Idiomas já traz grandes resultados com unidades vendidas em todas as regiões do Brasil. Isso acontece também por conta da nossa metodologia única, onde acreditamos que assim como a sociedade, o idioma evolui de forma incessante. \nNossa metodologia acompanha essas mudanças e busca estar sempre atualizada.     Metodologia Phenomenal \nO método Phenom é fácil, possível e real. Fácil porque qualquer um consegue aprender. \nPossível pois é uma metodologia especificamente criada para nativos da língua portuguesa. \nÉ real porque ensina conteúdo do dia a dia, onde o aluno aprende e aplica todo o seu conhecimento na prática. Além disso, trazemos um diferencial de tudo o que há no mercado de idiomas. \nA Phenom conta com um módulo gamificado, onde o ambiente lúdico é trazido para dentro da sala de aula, tornando o aprendizado leve e eficaz.   \n  Franqueados Phenom Idiomas \nAqui acreditamos que uma verdadeira parceria ocorre quando ambos os lados trabalham juntos para o avanço de um negócio. \nPor isso, o investidor recebe consultoria completa durante toda a implantação, desde as primeiras escolhas, até treinamentos de gestão e confirmação da data de inauguração de sua escola. \nAlém do suporte vitalício a todo momento.  Além disso, a Phenom não cobra um centavo sequer de royalties. Ou seja, 100% do valor das mensalidades dos alunos ficam para o franqueado. \nNosso único vínculo se dá por meio do material didático.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/27ee68ec-de96-43eb-a5ed-f7fa0da99492.png', 35, NULL, NULL, '2026-03-08 19:09:17.113', 'https://franquias.portaldofranchising.com.br/franquia-phenom-idiomas/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0d552578-924a-4cc1-9250-8ea0b9dcb7c9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a8431cad-3480-4d9e-b3d6-e32aca207db0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e2dcd92c-b4f0-4df8-b3ef-14aed3fcb4f3.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74fl0057eh0s4nnoak0e', 'CI', 'ci', NULL, 'Hotelaria e Turismo', 'Agências de Turismo', 'TURISMO JOVEM E INTERCÂMBIO CULTURAL EDUCACIONAL', 1992, 1991, '[\"https://www.youtube.com/watch?v=9h8EgjvoeqE\",\"https://www.youtube.com/watch?v=h38rGeOLd5Q\",\"https://www.youtube.com/watch?v=a8J008qsRGY\",\"https://www.youtube.com/watch?v=rVDYlFNtbB0\"]', '2026-04-01 02:00:02.693', '2025-08-05 22:20:25.138', 224, NULL, 1, 1988, 'Fundada em 1988, a Franquia CI é a maior empresa de intercâmbio e turismo jovem do país. \nEm 1992 a empresa passou a trabalhar com o formato de franquia, sendo a primeira do segmento a atuar dessa forma. \nAo longo desses 28 anos, construiu uma forte presença com mais de 90 lojas espalhadas por todo o Brasil. \nAtualmente é a maior franqueadora do segmento e conta com várias filiações, prêmios e reconhecimento internacional. A CI Já foi premiada sete vezes com o Selo de Excelência em Franchising pela ABF, além de ser reconhecida como melhor operadora de cursos no Exterior pela Revista Viagem e Turismo. \nA empresa tem interesse em fortalecer a sua presença nacional, expandindo o número de unidades por todo o Brasil. \nPossuímos o modelo de loja  ideal para cada mercado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fede3f19-c1ac-40a5-bd6d-375c677e8772.jpg', 88, NULL, NULL, '2026-03-08 19:10:25.778', 'https://franquias.portaldofranchising.com.br/franquia-ci-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '18000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74fs0058eh0s4tloq3j8', 'ROVAL PET - MANIPULAÇÃO VETERINÁRIA', 'roval-pet-manipulacao-veterinaria', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Farmácia de Manipulação exclusivamente veterinária', 2013, 2015, '[\"https://www.youtube.com/watch?v=Fj0Mu-QrNfs\",\"https://www.youtube.com/watch?v=8Xkjncmwdh8\",\"https://www.youtube.com/watch?v=CXhRN8n7JkU\",\"https://www.youtube.com/watch?v=Xbic1gRxb_U\"]', '2026-04-01 02:00:02.702', '2025-08-05 22:20:25.145', 225, NULL, 1, 1988, 'A FARMÁCIA ROVAL DE MANIPULAÇÃO foi fundada em 1988, no Recife, com a proposta de “manipular medicamentos para todas as especialidades médicas” e com o firme propósito de criar o intercâmbio Médico-Farmacêutico, tão importantes para a melhoria da qualidade do tratamento dispensado ao cliente. Em 2010, optou-se por expandir o negócio, através da ROVAL FRANCHISING LTDA e da criação de um sistema único de franquia que refletisse a sua expertise no segmento, a credibilidade da sua marca e a sua bem-sucedida atuação, nos moldes da Lei 13966/19; e também se associou à ABF – Associação Brasileira de Franquias, de quem recebeu um selo de excelência após pesquisa junto aos seus franqueados, e atualmente conta com diversas unidades próprias e franqueadas. Ao longo de todos estes anos, A ROVAL PET - FARMÁCIA DE MANIPULAÇÃO VETERINÁRIA tem aprimorado a sua vocação de prestadora de serviços de saúde e tem participado ativamente da vida das comunidades onde atua, contribuindo com a melhoria da qualidade de vida nestas comunidades. A ROVAL PET - FARMÁCIA DE MANIPULAÇÃO VETERINÁRIA acredita que por trás da atividade mercantilista de vender o medicamento, está o serviço prestado ao cliente e, sobretudo, a missão de manipular medicamentos com segurança e precisão. Posturas como estas têm garantido à ROVAL PET - FARMÁCIA DE MANIPULAÇÃO VETERINÁRIA o respaldo de farmácia séria, comprometida com a saúde e o bem-estar das pessoas. NOSSO PROPÓSITO: Transformar a saúde e a vida das pessoas e dos animais. Diferenciais: Desenvolvemos formas farmacêuticas diferenciadas que auxiliam a adesão dos pets ao tratamento dos pacientes com necessidades especiais: biscoitos terapêuticos, pasta oral terapêutica , xarope saborizado, gel transdérmico, cápsulas, shampoo, queijinho, sachês, wipes, cremes, loções, solução otológica, flavorização. Excipientes exclusivamente veterinários (p.ex.: isentos de lactose) Rigoroso critério de qualidade, atendendo às normas exigidas pelo Ministério da Agricultura. Matérias-primas exclusivas selecionadas para cada necessidade. Palatabilizantes preferidos dos animais para cachorros, gatos, cavalos e animais silvestres. E mais: Auxílio na escolha e definição do ponto comercial; Projetos arquitetônicos/executivos; Treinamento ao franqueado e equipe; Suporte e acompanhamento durante implantação; Inauguração e operação do pdv; Equipe de mkt para suprir as demandas da rede; Consultoria de campo; Programa de gestão ao franqueados/gerentes manuais de gestão/identidade visual/operação/RH; Guia veterinário magistral; Compra coletiva; Linha de produtos Roval PET exclusiva Análise, acompanhamento e suporte da operação da franquia sob um sistema em que utiliza boas práticas da governança corporativa Apoio em eventos e parcerias', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b95ed30f-d2f9-469a-8a2a-71de7bd94f66.jpg', 4, NULL, NULL, '2026-03-08 19:11:09.229', 'https://franquias.portaldofranchising.com.br/franquia-roval-pet/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74g10059eh0sbzne3t2o', 'MOLDURA MINUTO', 'moldura-minuto', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Somos a única e maior rede de franquia de emolduramento de luxo do país e líder no segmento, além de galeria com foco na valorização da arte, temos mais de 25 anos de história', 2000, 1990, '[\"https://www.youtube.com/watch?v=Oq9Igu7oJ4E\",\"https://www.youtube.com/watch?v=MrlHbxjns6k\",\"https://www.youtube.com/watch?v=qRRMf00jSQM\",\"https://www.youtube.com/watch?v=ftdq1aYVgxY\"]', '2026-04-01 02:00:02.712', '2025-08-05 22:20:25.153', 226, NULL, 1, 1999, 'Venha fazer parte da maior franquia de emolduramento do país. Um mercado milionário está esperando por você! A moldura minuto é uma marca líder de mercado com uma das maiores margens de lucro no segmento de franquias do brasil. com mais de 2 décadas de experiência, somos a maior rede de franquias no segmento de emolduramento e decoração com quadros alto padrão e um negócio milionário para você lucrar! \nSão mais de 30 mil quadros vendidos por mês, além da marca ter 94% de índice de satisfação dos franqueados, segundo a abf, possuímos 8 selos de excelência em franchising e somos a única rede com emolduramento personalizado e galeria de artes e fotografias. \nNós oferecemos alta lucratividade, segurança, solidez, baixo custo operacional, e uma marca que já possui seu nome consolidado no mercado nacional e internacional, com mais de 60 lojas no brasil e mais 3 no exterior: paraguai, uruguai e bolívia. \nNosso propósito é fazer parte da vida e contar a história de nossos clientes através do emolduramento de fotografias, imagens, artes e mais variados objetos. \nEstamos focados em transmitir segurança através da nossa assessoria humanizada e especializada com foco em ajudar o cliente a decorar seu ambiente de forma personalizada, com eficiência e comodidade para atender às suas expectativas através da excelência no serviço de emolduramento. \n  HISTÓRIA DA MOLDURA MINUTO A Moldura Minuto deu o pontapé para se tornar referência no segmento de emolduramento em 1999, quando fundou sua primeira unidade no Shopping Butantã, em São Paulo, no entanto, a proposta de montar uma rede que oferecesse o serviço de emolduramento rápido veio muito antes.  Antonio Viegas, CEO da Moldura Minuto atuava como odontologista em Portugal quando ao reformar seu consultório optou pela decoração com quadros e se espantou com a espera estimada para que os mesmos ficassem prontos. Inspirado nisso, ao voltar para o Brasil, apostou no seu próprio negócio, inaugurando a primeira sede da Moldura Minuto.  Com o propósito de emolduramento rápido em até uma hora, nasceu a Franquia Moldura Minuto, que hoje conta com mais de 60 unidades espalhadas pelo Brasil e América Latina.  Hoje, a Moldura Minuto está posicionada no segmento de decoração com quadros e oferece aos clientes mais do que apenas quadros emoldurados. \nNós queremos estar inseridos nos momentos mais marcantes da vida de nossos clientes, fazer parte da sua vida e contar a sua história.  E é por isso, que a Moldura Minuto conta com uma equipe treinada e especializada em decoração com quadros, com atendimento humanizado, alta qualidade e perfeição nos detalhes e acabamentos.  E tudo isso só é possível graças a nossa tecnologia de ponta, know-how focado nos ideias da marca e experiência de mais de 20 anos no mercado, que garante um modelo de negócio voltado para o sucesso.   Sobre o Mercado \nA Moldura Minuto é uma franquia com uma das maiores margens de lucro do mercado no segmento, que já fatura mais de R$ 1,5 bilhões ao ano com a venda de mais de 30 mil quadros ao mês, além da venda para todo o mercado corporativo, como arquitetos, decoradores e fotógrafos.  Um mercado que é altamente lucrativo e com baixíssima concorrência, baixo custo operacional e alta conversão de vendas no PDV.    Quem são os clientes Moldura Minuto   Gostam de decoração;  Gostam de viajar e trazer recordações das viagens;  Adoram coleções e querem expor na decoração;  Adoram fotos em família;  São fotógrafos por hobby;  São fotógrafos profissionais;  Possuem recordações de família e desejam expor como verdadeiras obras de arte;  São apaixonadas por esportes e querem expor medalhas;  São apaixonados por futebol e possuem objetos assinados pelos seus ídolos;  São arquitetos;  São designers de interiores;  Possuem consultórios médicos ou odontológicos; Possuem escritórios comerciais, hotéis e pousadas;   Conheça as vantagens de ser um franqueado Moldura Minuto\n  O modelo de negócios Moldura Minuto é estruturado para ser compatível com centros urbanos e pequenas cidades que tenham mais de 90 mil habitantes.  Somos reconhecidos por nossos franqueados com 94% de índice de satisfação e temos 8 selos de excelência em franchising pela ABF.  Somos uma franquia com:  BAIXO CUSTO FIXO\n\tLoja compacta gerando o lucro que você merece, com equipe enxuta e eficaz.\n\t  BAIXO CUSTO OPERACIONAL\n\tSem estoque para o seu dinheiro não ficar parado, sem perda de produto com vencimento ou item fora de linha.\n\t  FÁCIL DE OPERAR\n\tCom foco 100% na venda.\n\t  ALTA LUCRATIVIDADE\n\tUma das maiores margens de lucro entre todo o mercado de franquias no brasil!   Possuímos 4 modelos de negócios:\n  Loja de Shopping A Loja de Shopping concentra versatilidade e dinamismo em um ambiente compacto e arrojado. \nEstrategicamente projetada para atender a latente demanda do público dos centros de compras.     Loja Home Um espaço aconchegante desenhado para acomodar quadros, decoração e celebrar o bom gosto de forma a consagrar e aguçar a percepção sensorial dos consumidores e artistas.     \n  Moldura Minuto Smart É nosso principal modelo com foco em expansão atualmente, ideal para você que deseja investir pouco, mas com a garantia de ter um retorno de alta margem de lucro.          Contêiner Moldura Minuto Para você que deseja mobilidade, baixo risco de operacional e lucro.             Vamos trabalhar com você os 5 pilares do sucesso: Praça:\nVocê terá acesso a um profundo estudo de geomarketing para validar o potencial da sua praça. Ponto:\nVamos te ajudar na escolha do melhor ponto comercial com o estudo de geolocalização. Franqueado:\nVocê terá uma formação completa, para se tornar um excelente gestor da sua operação e da sua equipe.  Equipe:\nSua equipe terá acesso ao programa Moldura Minuto Loja de Excelência, para entregar mais resultados, se mantendo motivados e engajados.  Marca:\nVocê fará parte de uma marca forte, com mais de duas décadas de experiência, reconhecida internacionalmente e que dita tendências.  \n  Suportes Moldura Minuto:  Pré-abertura \nA Moldura Minuto garante a todos os seus franqueados o suporte pré-abertura, que conta com um plano de negócios estruturado para oferecer toda a assistência necessária:   Desenvolvimento de plano de negócio customizado ao mercado alvo Suporte no estudo da viabilidade do ponto comercial Desenvolvimento e acompanhamento do cronograma de implantação Auxílio na negociação dos valores de contrato de locação Desenvolvimento de projeto arquitetônico e de marcenaria Desenvolvimento das ações de Marketing inaugural Transferência de “Know-How” e tecnologia através de treinamento teórico e prático para franqueados e toda a equipe Acompanhamento presencial do início das novas operações Auxílio na busca por perfis de colaboradores Realização da primeira compra de produtos e insumos, além do maquinário, visando o melhor desempenho do franqueado na abertura de sua loja Estudo e desenvolvimento do primeiro enxoval de quadros na loja, conforme coleção vigente   Pós-abertura \nPós-abertura, a Moldura Minuto também conta com um planejamento para colaborar com a gestão de seus franqueados oferecendo toda a ajuda necessária para sua operação: Suporte full-time de operações, gestão, financeiro e marketing nos diversos canais de comunicação Desenvolvimento das metas mensais Feedback periódico do desempenho da loja com análise dos índices operacionais Treinamentos mensais online e/ou apresentações. Auxílio na contratação de colaboradores Convenção anual de franqueados Gestão participativa de marketing juntamente com o Conselho de franqueados SAF – Serviço de atendimento ao franqueado Desenvolvimento constante de novos produtos Busca constante de novos fornecedores com os melhores produtos e preços exclusivos para rede Software de gestão online Campanhas de marketing periódicas Suporte na aquisição de produtos, através do clube de compras\n\t  Produtos e serviços oferecidos:  Emolduramento customizado;  Composições personalizadas de quadros;  Consultoria em projetos de decoração com quadros;  Impressão digital em papel fotográfico e canvas;  Quadros prontos;  Artes e fotografias do acervo Moldura Minuto;  Espelhos;  MM Instala;  MM Imprime;', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/370c14a1-49bf-4ed9-92eb-0adf8e9560cb.png', 53, NULL, NULL, '2026-03-08 19:12:46.764', 'https://franquias.portaldofranchising.com.br/franquia-moldura-minuto-decoracao-e-presentes/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/01f1150f-65f8-40d5-83d4-fe851e0fe785.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/46d460a1-950e-4533-b90c-17fc315acd50.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1de4c94e-144c-4346-bc39-97d8d29be532.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0979743b-e065-46e1-8d6a-91b6e529d43f.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '140000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74gd005aeh0s8ruwwex6', 'FARMÁCIAS SÃO RAFAEL', 'farmacias-sao-rafael', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Franquia no segmento de Farmácias e Drogarias com atuação nacional', 2016, 2016, '[\"https://www.youtube.com/watch?v=0TmG-FZqZDM\"]', '2026-04-01 02:00:02.723', '2025-08-05 22:20:25.165', 227, NULL, 1, 1997, 'A Farmácia São Rafael iniciou as suas atividades em março de 1997 na cidade de Chapecó em Santa Catarina. Uma trajetória empreendedora, com muitos desafios e aprendizados. Em 2017, a São Rafael completou 20 anos da sua trajetória, chegando ao total de 11 lojas próprias e duas unidades franqueadas. Em 2020, com um total de 33 lojas em operação a São Rafael já é uma franquia consolidada, um sucesso em resultados e com a expansão a pleno vapor nas regiões Sul e Sudeste do Brasil. Dispomos de experiência e know-how suficientes para estender esse modelo aos parceiros que desejam obter o mesmo êxito que conseguimos. Confira abaixo algumas vantagens de se investir em uma Franquia Farmácias São Rafael: Marca reconhecida e qualidade percebida pelos consumidores; Análise do ponto e estudo de viabilidade de implantação; Disponibilizamos o projeto de interiores comercial e layout de fachada; Suporte em todo o processo de implantação; Treinamento ao Franqueado e equipe para trabalhar nos padrões da marca; Manuais da franquia; Estudo de mercado e sugestão do mix ideal para dar início as atividades e precificação a ser aplicada; Negociações estratégicas com fornecedores; Produtos exclusivos com qualidade e rentabilidade diferenciada; Acesso a uma estratégia de marketing mais agressiva e efetiva; Suporte especializado na gestão; Acompanhamento full time dos indicadores de desempenho da franquia; Tabloide de ofertas com produtos selecionados estrategicamente para garantir os resultados; Ferramentas que irão reduzir a inadimplência a zero; Convênio Corporativo com gestão totalmente on-line, facilidade e agilidade no processo; Comunicação direta com a Franqueadora para facilitar as orientações e a troca de informações; Consultoria de campo especializada, com suporte efetivo focado em resultado, proporcionando crescimento e permanência no mercado farmacêutico. \nA união de um mercado muito promissor a uma marca que fundamenta o seu modelo de negócio na excelência do atendimento, layout e mix de produtos diferenciados para proporcionar sempre a melhor experiência aos seus clientes, pode ser a sua receita de sucesso também.   Invista em uma Franquia Farmácias São Rafael!', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c3f2e65b-0c56-4f68-b096-b943de36bec5.svg', 60, NULL, NULL, '2026-03-08 19:17:16.822', 'https://franquias.portaldofranchising.com.br/franquia-farmacias-sao-rafael-farmacias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '233000.01', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74gi005beh0ske0ttyeu', 'DROGARIA MEDFACIL', 'drogaria-medfacil', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Comercio de produtos farmacêuticos, cosmético e perfumaria. Mix completo de produtos para reabilitação.', 2018, 2022, NULL, '2026-04-01 02:00:02.733', '2025-08-05 22:20:25.171', 228, NULL, 1, 1992, '', NULL, 'GOIÁS', 1, NULL, 7, NULL, NULL, '2026-03-08 19:18:31.590', 'https://franquias.portaldofranchising.com.br/franquia-drogaria-medfacil/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74go005ceh0sbnmkge3c', 'ORAL SIN IMPLANTES', 'oral-sin-implantes', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'CLÍNICAS ODONTOLÓGICAS COM ATENDIMENTO ESPECIALIZADO EM IMPLANTES DENTÁRIOS.', 2010, 2017, '[\"https://www.youtube.com/watch?v=DmQgJB0upDc\"]', '2026-04-01 02:00:02.743', '2025-08-05 22:20:25.177', 229, NULL, 1, 2004, 'A Oral Sin foi fundada em 2004 na cidade de Arapongas – PR com o objetivo de levar tratamento odontológico de qualidade com um preço justo. Resultado de um trabalho de excelência, em 2008, a clínica inaugurou sua primeira afiliada na cidade de Londrina – PR e, desde então, não parou mais de crescer, levando saúde bucal para todo o Brasil. Em 2014 a Oral Sin foi considerada a rede Nº 1 de implantes no país pelos principais fornecedores de insumos de implantes do Brasil. Atualmente, a rede conta com centenas de unidades em todos os estados do Brasil e mais de 1500 colaboradores, que transformam a saúde dos pacientes.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cc7a4384-4fd2-4123-b16c-450493b12a02.png', 390, NULL, NULL, '2026-03-08 19:18:55.181', 'https://franquias.portaldofranchising.com.br/franquia-oral-sin-implantes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '830000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74gu005deh0sg5hlj5f5', 'LASER&CO', 'laser-co', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'Serviços estéticos a laser. Somos mais que depilação, trabalhamos com vários lasers que fazem vários serviços, desde rejuvenescimento, clareamento, remoção de manchas e tatuagens etc...', 2023, 2023, NULL, '2026-04-01 02:00:02.754', '2025-08-05 22:20:25.182', 230, NULL, 1, 2022, 'A LASER&CO é a primeira rede de serviços estéticos a laser do Brasil. Não somos “mais uma” rede de depilação, realizamos diversos outros serviços a laser como rejuvenescimento facial, tratamentos de manchas e melasma, remoção de tatuagens e micropigmentação, clareamento de virilha e axila a laser, além de tratamentos com Ultrassom, que produzem uma lipo sem cortes, redução de papada, lifting facial, redução de até 20% de gordura corporal e estimula o aumento de colágeno. Enquanto uma empresa “normal” de depilação pode depilar uma virilha, nós podemos depilar, clarear e rejuvenescer a região íntima. Isso sem falar que podemos realizar diversos outros tratamentos em outras regiões, potencializando muito mais os atendimentos em cada cliente. Além do mais, enquanto falamos que uma depilação é “definitiva”, temos tratamentos que são RECORRENTES, como o Rejuvenescimento Facial a laser (afinal, envelhecemos todos os dias), ou seja, temos potencial para ter clientes para sempre! Nossos serviços estavam restritos apenas a Médicos e clínicas de alto padrão, que cobram caro e atendem um público “A”, que corresponde a 1% do público consumidor. Nós somos a resposta para todo o público B/C, que corresponde a cerca de 90% do público consumidor e que nunca teve acesso a este tipo de serviço, com equipamentos de ponta e preços acessíveis, democratizando este tipo de serviço. Também temos ampla vantagem em relação a clínicas de Harmonização, pois não temos estoque, não dependemos de fornecedores nem de mão de obra qualificada (afinal, nossa máquina é a artista principal). Nosso serviço possui um valor agregado por sessão muito melhor que depilação ou harmonização, além de uma barreira de entrada muito mais alta (equipamento) sendo um mercado inovador criado pela LASER&CO e, por isso, com baixa concorrência, ao contrário dos mercados de depilação e harmonização. Vantagens da franquia Laser&Co: Diversos serviços a Laser executados pelo mesmo equipamento. Equipamento exclusivo, financiado e pago pela operação. Baixo custo de investimento e alta taxa de retorno (rápido payback). Baixa concorrência e alta barreira de entrada. Facilidade de gestão: sem estoque, poucos funcionários, alto ticket médio.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/32da0dec-8cf1-4997-ac16-f2ceaab08537.png', 36, NULL, NULL, '2025-09-03 14:52:00.000', 'https://franquias.portaldofranchising.com.br/franquia-laserco/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
