INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74hi005ieh0s5010lebj', 'WERNER COIFFEUR', 'werner-coiffeur', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Instituto de Beleza', 1997, 1999, NULL, '2026-04-01 02:00:02.811', '2025-08-05 22:20:25.207', 235, NULL, 1, 1986, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/19125a9c-29ee-40a1-81e4-ee17c4979422.jpg', 52, NULL, NULL, '2026-03-08 19:21:22.543', 'https://franquias.portaldofranchising.com.br/franquia-werner-coiffeur-beleza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '140000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74hn005jeh0sdu3sg32u', 'OTICAS IPANEMA', 'oticas-ipanema', NULL, 'Saúde, Beleza e Bem-Estar', 'ÓTICAS', 'Comércio varejista de óculos, lentes oftálmicas e acessórios.', 2009, 2012, '[\"https://www.youtube.com/watch?v=ukgJsPPfW7A\"]', '2026-04-01 02:00:02.832', '2025-08-05 22:20:25.211', 236, NULL, 1, 1981, 'A ÓTICAS IPANEMA se pauta pela prática de preços competitivos, aliados à alta qualidade técnica e de atendimento, instalações e serviços; fatores esses imprescindíveis para o sucesso de qualquer atividade comercial. A ÓTICAS IPANEMA cresceu sua participação no mercado através de um trabalho bem estruturado, alicerçado por princípios de qualidade. A empresa é administrada de forma dinâmica ao longo de seus 40 (quarenta) anos de existência, fortemente conhecida em sua área de atuação, por contar com um alto poder de penetração no mercado e dispor de uma altíssima qualidade em seus produtos e serviços. Este histórico vem ao encontro do perfil dos sócios e responsáveis pela marca e pelo sistema de operação de unidades ÓTICAS IPANEMA, que buscam exatamente envolvimento, responsabilidade e profissionalismo no que executam e nas parcerias que desenvolvem. Em janeiro de 1981, sob a liderança dos irmãos Silvio e Sinval Ferreira, foi aberta a primeira unidade ÓTICAS IPANEMA, na cidade de Indaiatuba, Estado de São Paulo. Com  ousadia e espírito empreendedor, em pouco tempo, tornaram-se uma referência nacional no segmento óptico. Atualmente, a rede conta com 57 unidades.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fa4134d2-58df-4279-a4d9-39e9af64a165.jpg', 33, NULL, NULL, '2026-03-08 19:21:47.022', 'https://franquias.portaldofranchising.com.br/franquia-oticas-ipanema/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
