INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74i8005meh0sfittvkt6', 'CASTELO DOS SONHOS', 'castelo-dos-sonhos', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e Recreação', 'Buffet de festas infantis.', 2021, 2023, NULL, '2026-04-01 02:00:02.923', '2025-08-05 22:20:25.232', 239, NULL, 1, 2021, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/14f659d5-18b9-4087-a875-aa26ff96cde9.png', 4, NULL, NULL, '2026-03-08 19:23:23.442', 'https://franquias.portaldofranchising.com.br/franquia-castelo-dos-sonhos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74id005neh0sq34yniun', 'VOX2YOU ESCOLAS DE ORATÓRIA', 'vox2you-escolas-de-oratoria', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Maior rede de escolas de oratória e comunicação da America Latina, com presença em todas as regiões do país e mais de 90 mil alunos já transformados através de metodologia inovadora.', 2016, 2024, '[\"https://www.youtube.com/watch?v=D7Wl7_bhxIo\",\"https://www.youtube.com/watch?v=Kb8cyrFupsQ\",\"https://www.youtube.com/watch?v=pI75MDc7Ufc\",\"https://www.youtube.com/watch?v=gisbvSwR44o\"]', '2026-04-01 02:00:02.937', '2025-08-05 22:20:25.238', 240, NULL, 1, 2015, 'Franquia Vox2you: Uma Oportunidade de Sucesso no Mercado de Comunicação e Oratória. A Vox2you é a maior rede de escolas de comunicação e oratória da América Latina, destacando-se como uma referência no desenvolvimento de habilidades essenciais para o sucesso pessoal e profissional. Com uma abordagem inovadora e metodologia comprovada, a Vox2you transforma a vida de milhares de alunos, ajudando-os a superar desafios na comunicação e alcançar seus objetivos. O Que é a Vox2you? Fundada com o objetivo de democratizar o acesso ao ensino de oratória, a Vox2you rapidamente se consolidou como uma das principais redes de ensino do Brasil. A escola oferece cursos de comunicação que vão desde a oratória tradicional até técnicas avançadas de persuasão e expressão corporal. Com um time de profissionais altamente qualificados e uma metodologia exclusiva, a Vox2you ajuda seus alunos a desenvolverem confiança, clareza e eficácia na comunicação. Por Que Investir na Franquia Vox2you? Investir em uma franquia Vox2you é uma excelente oportunidade para quem deseja entrar em um mercado em plena expansão. Aqui estão alguns dos principais motivos para considerar a Vox2you como sua próxima empreitada empresarial:', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8fba761d-157f-4874-a1a9-61ba1fe585ee.png', 134, NULL, NULL, '2026-03-08 19:23:51.386', 'https://franquias.portaldofranchising.com.br/franquia-vox2you-escolas-de-oratoria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ik005oeh0sa279wn4n', 'TWICE', 'twice', NULL, 'Educação', 'EDUCAÇÃO', 'Twice é uma franquia que oferece um sistema de ensino bilíngue de fácil implementação nas escolas parceiras, com um modelo de negócio simples, prático e com rápido retorno sobre o investimento.', 2020, 2021, NULL, '2026-04-01 02:00:02.949', '2025-08-05 22:20:25.244', 241, NULL, 1, 2010, 'TWICE é a franquia de bilinguismo integrado e eficaz para escolas Há 12 anos no mercado, a história do sistema TWICE de Educação Bilíngue nasce da percepção de uma lacuna nos conteúdos bilíngues oferecidos nos país. Se observou que os programas de inglês e o Currículo Nacional não se falavam: os livros eram importados e dissociados da nossa realidade. Acabavam o ano em branco, enquanto os professores tinham de recorrer à internet para improvisar as aulas. Nascia assim uma proposta de integração entre esses dois mundos, que foi fundamental para a consolidação e desenvolvimento do bilinguismo no Brasil. No TWICE os benefícios do bilinguismo estão sob o olhar de intensas pesquisas desde a década de 1960. “Estudos científicos comprovam que os bilíngues desenvolvem mais e melhor as funções executivas do cérebro, responsáveis por memória, atenção, foco, planejamento, resolução de problemas e multitarefa. Os diferenciais do TWICE estão em diversos aspectos: na estrutura e composição das aulas e, principalmente, no material didático.  Conteúdo diferenciado e alinhado à BNCC O material procura ativar outras áreas do conhecimento e não apenas a área da linguagem oral e escrita. Há também um compromisso muito grande com o desenvolvimento da expressão criativa nos projetos, além do fato de que o aluno entra em contato com a língua através do aprendizado de outras disciplinas. Em tempos onde tanto se fala das diretrizes da Base Nacional Comum Curricular, é fundamental saber que o TWICE é totalmente alinhado à BNCC, com a vantagem de tornar o que antes era considerado maçante em uma ferramenta de exploração do mundo, leve, eficaz e concreta. O material do TWICE contempla todo o conteúdo do currículo nacional, isto é, tudo o que uma criança deve aprender na terceira série no Brasil é revisto em inglês. Daí vem o nome TWICE, que em inglês significa ‘duas vezes’. O TWICE também pode ser seu Ampliar as possibilidades de aplicação desse formato de ensino bilíngue em escolas de todo o país foi a inspiração para a criação do modelo de franquia do sistema de ensino. Como franqueado, você terá autonomia para integrar o sistema de ensino bilíngue do TWICE nas escolas existentes em sua região de atuação. Você administra o negócio e ainda conta com todo nosso know how e experiência para ser um grande franqueado de sucesso. Como vantagens de ser franqueado estão alguns pontos que podem ser considerados diferenciais na hora de empreender nessa vertente. Selecionamos alguns: O TWICE é um sistema de ensino que se integra nas escolas que desejam se tornar bilíngues ou desejam oferecer um projeto pedagógico bilíngue na grade curricular; \n\t  É uma proposta com investimento inicial baixo e que é totalmente home based, ou seja, não depende de um ponto comercial; \n\t  Oferece metodologia de ensino exclusiva, o TWICE Educação Bilíngue, que apresenta elevada aprovação dos diretores de escolas parceiras, além de todo o suporte para formação de professores – e um sólido sistema de suporte total ao franqueado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4c4fb41e-11d3-479e-9a13-121b29144af5.jpg', 1, NULL, NULL, '2026-03-08 19:24:39.633', 'https://franquias.portaldofranchising.com.br/franquia-twice/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0c580c41-5db8-42cb-9b49-a68d54ee3f6a.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ip005peh0s4lt4lgu0', 'RECCO LINGERIE', 'recco-lingerie', NULL, 'Moda', 'Vestuários', 'Comércio Varejista de moda moda íntima e loungewear', 2019, 2019, '[\"https://www.youtube.com/watch?v=-yaQ40gsURI\",\"https://www.youtube.com/watch?v=SvucjjM9dyw\",\"https://www.youtube.com/watch?v=LkDyH4OuhHw\"]', '2026-04-01 02:00:02.962', '2025-08-05 22:20:25.249', 242, NULL, 1, 1979, 'Em 1979 nascia a Recco Lingerie. Foi o início de um verdadeiro relacionamento de amor com a mulher brasileira. Os anos passaram e o nosso relacionamento com o universo feminino se tornou cada dia mais íntimo. Hoje produzimos moda íntima e casual para cada momento da vida da mulher com qualidade e excelência.    A qualidade total é primordial e a Recco possui certificação ISO 9001, obtido através da gestão eficiente de processos e investimentos constantes em qualidade de produtos. A marca tem se destacado no varejo e conquistado o espaço em cada lugar onde possui uma loja.    São vários os fatores que fortalecem nossa confiança de que a franquia Recco faz todo sentido. Os principais são: Uma marca madura com alto nível de reconhecimento no Brasil; Uma indústria sólida com total eficiência e tecnologia em seus processos; O segmento de moda íntima vem ganhando destaque e se sobressaindo frente a outras categorias do vestuário; Temos o mix de produto mais completo e consistente do mercado; Temos uma rede de lojas próprias que a mais de 20 anos funcionam como laboratório de produto e operação de varejo; E, acima de tudo, temos uma cultura de gestão muito forte voltada ao desenvolvimento de pessoas e respeito ao ser humano.  Nosso franqueado sabe que sempre pode contar com todo o time de retaguarda da marca!', NULL, 'PARANÁ', 1, NULL, 26, NULL, NULL, '2026-03-08 19:26:02.516', 'https://franquias.portaldofranchising.com.br/franquia-recco-lingerie/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '390000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74iu005qeh0sqe8nn4md', 'Consulting Now', 'consulting-now', NULL, '', '', '', 2014, 2018, '[\"https://www.youtube.com/watch?v=r--hNHWyOD8\",\"https://www.youtube.com/watch?v=wcfj9sgY518\",\"https://www.youtube.com/watch?v=MyQiua0crzE\",\"https://www.youtube.com/watch?v=9k5edfYxNWo\"]', '2026-04-01 02:00:02.973', '2025-08-05 22:20:25.255', 243, NULL, 1, 1994, 'Com mais de 30 anos de experiência e presente em todas as regiões, a Consulting Now consolidou-se como a referência em consultoria para pequenas e médias empresas, no Brasil.', NULL, 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0c54df74-80fb-4232-8249-b6bf4198c04e.png', 96, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/95877ba4-0776-4304-9dc1-c13d664ac4bc.jpg', '2025-10-09 00:01:03.000', 'https://franquias.portaldofranchising.com.br/franquia-consulting-now/', NULL, 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/93f9a30a-21f7-4dd7-ba11-bfde8000a452.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/824886a9-23cc-4e99-bef3-5ea110efee24.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/14b15245-f85d-4d13-bdbb-d52f7a0a8fb0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4b4fdaa2-4f9d-4f05-99b1-78434e48540b.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '32000', NULL, NULL, NULL, '22000', NULL, '15', '0', NULL, '10000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74iz005reh0szrifinkb', 'ÓTICAS FERRI', 'oticas-ferri', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Rede de óticas inserida no varejo, com marca própria de lentes e armações, além de laboratório próprio com tecnologia FREEFORM, o que garante markup acima da média para o segmento.', 2015, 2021, '[\"https://www.youtube.com/watch?v=Mn5xK5c1THQ\",\"https://www.youtube.com/watch?v=w9G4aTznhuI\",\"https://www.youtube.com/watch?v=XBk4SdYcM2M\"]', '2026-04-01 02:00:02.984', '2025-08-05 22:20:25.259', 244, NULL, 1, 1999, 'Toda nossa história começou com a fundação da ÓTICAS FERRI no ano de 1999, no bairro Estreito, na cidade de Florianópolis/SC, quando atuávamos apenas como distribuidora de produtos óticos. Após 5 (cinco) anos no mercado, os sócios, Eglo Ferri e Milena Ferri, observando diversas necessidades no segmento varejista, a empresa estendeu as atividades no setor ótico, ramo promissor até os dias atuais, sendo que sempre buscaram o atendimento de excelência, vendendo produtos de qualidade a preço justo. Os irmãos cresceram em uma família empreendedora e aprenderam com os pais o gosto pelo empreendedorismo. Eglo construiu sua carreira corporativa em uma empresa multinacional do setor ótico. Trabalhando neste grande player, aprendeu as questões técnicas e adquiriu a visão do setor, o que mais tarde o auxiliou a consolidar a ÓTICAS FERRI. Estudou e se formou em técnico em Ótica, cumprindo assim os requisitos necessários para a abertura de seu negócio. Em 2004, fundou a primeira loja na cidade de Biguaçu/SC. Mais tarde, Milena passou a incorporar a sociedade, auxiliando no crescimento da rede.  A partir de 10 (dez) anos de atuação específica no comércio de venda, já contendo 05 (cinco) unidades próprias na ocasião, em julho de 2016 iniciamos nossa trajetória no franchising, contando com uma equipe de especialistas e com muita experiência adquiridas em outras grandes redes, botamos em prática nosso sonho de termos uma rede completa, que gera resultados e proporciona expansão aos franqueados. A FRANQUIA ÓTICAS FERRI consolidou-se no mercado conquistando a confiança dos seus clientes e trazendo toda a experiência destes anos de trabalho para oferecer a máxima qualidade para a saúde dos olhos. A preocupação em fornecer as melhores opções a seus clientes, o ÓTICAS FERRI trabalha com os últimos lançamentos em termos de lentes e armação para óculos, buscando melhorar a saúde visual e ocular, proporcionando conforto para seus clientes, além de contarmos com uma equipe altamente capacitada para desenvolver a rede e os franqueados. A expansão está aberta em 04 (quatro) estados, SP, SC, RS e PR, com produtos e distribuição próprios, o que favorece o negócio aumentando mark-up do franqueado. Além disso, temos atualmente um plano específico e com muitos benefícios para favorecer o franqueado expandir organicamente, ou seja, com duas ou mais unidades. Saiba como preenchendo o formulário e conheça mais sobre nossa marca e trajetória.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/de44488b-67a2-4bbe-a91d-af1d5a8f4fea.jpeg', 36, NULL, NULL, '2026-03-08 19:26:57.564', 'https://franquias.portaldofranchising.com.br/franquia-oticas-ferri/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74j3005seh0sv8m6w3uq', 'LEMAX HAMBURGUERIA', 'lemax-hamburgueria', NULL, 'Alimentação', 'Bares e Restaurantes', 'Hamburgueria', 2019, 2019, '[\"https://www.youtube.com/watch?v=Zbsv87citZU\",\"https://www.youtube.com/watch?v=6BcS6X5HLeM\",\"https://www.youtube.com/watch?v=07U-EJThvos\"]', '2026-04-01 02:00:02.994', '2025-08-05 22:20:25.264', 245, NULL, 1, 2014, 'Em 2013 os sócios atuais do LeMax possuem 4 lojas franqueadas de outra marca. Neste momento eles decidem criar uma marca própria e convidam o Chef Hugo Grillo para se juntar à sociedade. Assim nasce o projeto LeMax . \nNo ano seguinte inauguramos, no Centro do Rio de Janeiro, o LeMax café e sanduíches, vendendo além de sanduíches, almoço e café.  No ano de 2015 o LeMax mostrou seu verdadeiro DNA, vender hambúrguer, desta forma, os sócios decidem fazer uma remodelação da marca, passando a se chamar Lemax Hamburgueria.  \nEm 2016 o Lemax se torna sucesso no Centro do Rio, com a loja lotada todos os dias, a partir daí, pensando no crescimento, em 2017 inauguramos a segunda loja em Botafogo, com sucesso ainda maior, bombando de dia e de noite.  Após a consolidação do sucesso da marca LeMax, em 2019, estruturamos o negócio para franquear e a partir do ano de 2020 abrimos as 3 primeiras lojas franqueadas com grande sucesso. \nCom a pandemia, freamos a expansão e investimos no crescimento do delivery.  \nApós se tornar um sucesso no delivery, tendo aumentado em 20 vezes o seu faturamento neste canal, em 2021 voltamos a aceitar novos franqueados e terminamos o ano com 6 unidades. O Lemax dobra o tamanho em 2022 e termina o ano com 13 unidades, batendo o recorde de faturamento todos os meses.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/995973e3-7ec5-40b9-bc4d-f926131bb11b.jpg', 12, NULL, NULL, '2026-03-08 19:28:23.970', 'https://franquias.portaldofranchising.com.br/franquia-lemax-hamburgueria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74j8005teh0si9ampotd', 'PHITOFARMA', 'phitofarma', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Farmácia de Manipulação, especialista em fórmulas sob medida, dispensação de fórmulas em blisters', 2012, 2011, '[\"https://www.youtube.com/watch?v=se4be2dw91w\",\"https://www.youtube.com/watch?v=Xpb7cqyqKDQ\"]', '2026-04-01 02:00:03.005', '2025-08-05 22:20:25.269', 246, NULL, 1, 1970, 'A história da franquia Phitofarma remonta ao início do século XX, quando a manipulação de fórmulas personalizadas e a fitoterapia começaram a ganhar destaque como alternativas à medicina tradicional. Desde então, a Phitofarma tem desempenhado um papel fundamental na história da farmácia no Brasil, sendo uma das pioneiras e líderes no setor de medicamentos manipulados. Com 53 anos de atuação, a empresa estabeleceu padrões de qualidade e inovação que moldaram o cenário farmacêutico do país. Há 11 anos, a Phitofarma expandiu sua influência ao oferecer franquias, solidificando ainda mais sua posição icônica na história da farmácia no Brasil. A Phitofarma também desempenhou um papel importante na promoção da fitoterapia como uma abordagem legítima e eficaz para a saúde, enquanto continuava a oferecer serviços de manipulação de fórmulas personalizadas.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cf10ef7e-56f6-4f41-b98f-174e6ca96807.jpg', 23, NULL, NULL, '2026-03-08 19:29:24.257', 'https://franquias.portaldofranchising.com.br/franquia-phitofarma/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
