INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ko0063eh0svlgm7pcx', 'PELO ZERO DEPILAÇÃO', 'pelo-zero-depilacao', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Depilação Expressa feminina e masculina, designer de sobrancelhas e depilação oriental e Depilação Definitiva', 2002, 2008, '[\"https://www.youtube.com/watch?v=1681nLBCQfc\",\"https://www.youtube.com/watch?v=CGMuox4_6hE\",\"https://www.youtube.com/watch?v=rUoEtHABlCo\"]', '2026-04-01 02:00:03.111', '2025-08-05 22:20:25.320', 256, NULL, 1, 1998, 'Pelo Zero Depilação – uma história marcada por desafios e conquistas Perseguindo a excelência, dificuldades e desafios foram atrativos para que a Pelo Zero Depilação alcançasse o sucesso.  O que teve início em uma discreta loja no bairro de Vila Isabel, no Rio de Janeiro, destaca-se hoje por um continuado trabalho, que se distingue não só pela qualidade do produto e dos serviços prestados, como também pela reafirmação diária de princípios e valores éticos e sociais. Hoje a Pelo Zero Depilação é o sonho realizado de muitos empreendedores.  Com mais de 20 anos de experiência no segmento de depilação expressa, a rede – com mais de 30 Unidades - conta com mais de 400 mil clientes atendidos e mais de 17 milhões de serviços realizados. Isso se traduz em prestar um excelente serviço, direcionado à satisfação dos clientes, tendo como principal objetivo cuidar da beleza, aliando um atendimento ágil a serviços de qualidade.  Sistema de Franquia Pelo Zero Depilação  Primando por uma atuação consistente e de qualidade, que conferiu à marca a conquista do Selo de Excelência em Franchising da ABF por 8 anos consecutivos, o sistema de franquia Pelo Zero Depilação consiste em parceria formada com o franqueado visando o fortalecimento da marca, o que traz como resultado uma operação comercial com um continuado potencial de desenvolvimento.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/425f51a6-1d24-488c-aba3-633351238f79.jpg', 34, NULL, NULL, '2026-03-08 19:33:56.383', 'https://franquias.portaldofranchising.com.br/franquia-pelo-zero-depilacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
