INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74kx0065eh0sg4spfkpz', 'PET 10 PETSHOP', 'pet-10-petshop', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'A franquia Pet 10 é um ótimo investimento para quem prioriza segurança e confiabilidade. Atuante em um mercado de alto crescimento, você conta com total suporte e acompanhamento para deslanchar.', 2022, 2023, NULL, '2026-04-01 02:00:03.133', '2025-08-05 22:20:25.330', 258, NULL, 1, 2009, '', NULL, 'SÃO PAULO', 1, NULL, 23, NULL, NULL, '2025-09-12 15:26:24.000', 'https://franquias.portaldofranchising.com.br/franquia-pet-10-petshop/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '200000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74l20066eh0ssah1mroz', 'BELGO CERCAS', 'belgo-cercas', NULL, 'Casa e Construção', 'Construção e Reforma', 'Venda e instalação de materiais para Cercas Urbanas', 2017, 2018, NULL, '2026-04-01 02:00:03.144', '2025-08-05 22:20:25.335', 259, NULL, 1, 1921, 'A Belgo Bekaert Arames é uma parceria entre a Arcelor Mittal – líder mundial na produção de aço – e a Bekaert – líder mundial em tecnologia de transformação e revestimento de arame de aço. Unindo a força desses acionistas, que juntos somam mais de 200 anos de atuação, a Belgo Bekaert Arames é pioneira e líder no mercado brasileiro de arames. \nLíder na América do Sul em produção de arames, a Belgo Bekaert é uma associação da ArcelorMittal (líder mundial na produção de aço) e Bekaert (líder mundial em tecnologia de transformação e revestimento de arames). E nessa marca mundial e de presença consolidada, você pode confiar.  Por que investir na franquia Belgo Cercas? \nForça da marca Belgo Bekaert Líder de mercado; Empresa global; Pioneira no segmento de Cercas Urbanas no Brasil.  Qualidade Sistemas de cercamento com estética, funcionalidade, segurança e durabilidade; Tecnologia de ponta; Pesquisa e desenvolvimento constantes para aprimorar a linha de produtos.  Mercado Crescente Cercas urbanas modulares são tendência no mundo todo; Padrão de construção em quase todos os países da Europa; Alto crescimento no Brasil: os sistemas de cercamento Belgo Bekaert já estão em mais de 300 mil empreendimentos.  Suporte Acesso a um know-how para planejar um negócio sólido, com resultados competitivos; Apoio total na escolha do ponto, manuais de gestão e treinamentos regulares.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/84e21747-a5eb-4211-8511-7d7cb3985b5d.png', 24, NULL, NULL, '2026-03-08 19:35:22.556', 'https://franquias.portaldofranchising.com.br/franquia-belgo-cercas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74l70067eh0s8brzhwf1', 'MATEO BABY', 'mateo-baby', NULL, 'Moda', 'VESTUÁRIO', 'Brechó infantil de produtos seminovos adquiridos através de avaliação individual (curadoria) e novos de fábrica, das melhores marcas, oferencendo opção completa do universo infantil, de 0 a 8 anos.', 2021, 2024, NULL, '2026-04-01 02:00:03.155', '2025-08-05 22:20:25.339', 260, NULL, 1, 2018, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/aeeed8b3-e03c-495b-befe-886fbd5dd3e9.png', 15, NULL, NULL, '2025-09-04 19:01:01.000', 'https://franquias.portaldofranchising.com.br/franquia-mateo-baby-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74lb0068eh0scp6wc6fr', 'EMPRESTA BEM MELHOR', 'empresta-bem-melhor', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Franquia de Serviços Financeiros. Representante dos maiores bancos do país, com linhas de crédito destinadas para pessoa física, sendo o crédito consignado e o saque fgts os principais produtos.', 2013, 2017, NULL, '2026-04-01 02:00:03.167', '2025-08-05 22:20:25.344', 261, NULL, 1, 1995, 'A EMPRESTA atua há 25 anos na área de serviços financeiros, estando presente em 8 Estados + DF, com 49 lojas no Brasil. Possuímos uma carteira com mais de 100.000 clientes e 1 BI de produção! Temos parceria com os principais bancos do segmento e atuamos com os serviços: crédito consignado, crédito pessoal, consórcio, seguro, cartão de crédito consignado e crédito com garantia de imóvel e veículo. Nosso objetivo é servir ao cliente com excelência, superando suas expectativas e construindo uma relação de fidelidade e confiança. Planejamento, orientação e suporte: • Construção do Plano de Negócios • Suporte na Escolha do Ponto Comercial • Entrega do Projeto Arquitetônico • Apoio na Montagem e Inauguração da Franquia • Auxílio na contratação do time e desenvolvimento do time • Treinamentos de produto e gestão • Acompanhamento permanente para crescimento e maior lucratividade • Suporte Operacional • Suporte Comercial • Suporte Estratégico • Sistema próprio de Vendas e Gestão • Assessoria permanente de Marketing e campanhas de vendas', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/961b5d7f-9d1e-409a-a388-5be4386425b1.svg', 75, NULL, NULL, '2025-09-09 17:27:20.000', 'https://franquias.portaldofranchising.com.br/franquia-empresta-bem-melhor-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
