INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74lm006aeh0s3lvt8m3s', 'GRUPO 21 TEC', 'grupo-21-tec', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'O Grupo 21 Tec é uma franquia inovadora que oferece soluções em energia solar, produtos financeiros e banco digital, com suporte completo para franqueados e alto potencial de lucratividade.', 2024, 2024, NULL, '2026-04-01 02:00:03.198', '2025-08-05 22:20:25.354', 263, NULL, 1, 2023, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d89de379-1a62-4686-b5c6-818eaba19ad7.png', 10, NULL, NULL, '2025-09-01 12:24:30.000', 'https://franquias.portaldofranchising.com.br/franquia-grupo-21-tec-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ls006beh0shtf90d88', 'CHOCOLATES BRASIL CACAU', 'chocolates-brasil-cacau', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'BOMBONIÉRE E CAFETERIA - CHOCOLATERIA.', 2009, 2009, '[\"https://www.youtube.com/watch?v=F53MyjLudx8\",\"https://www.youtube.com/watch?v=Sxd3Ab48AsY\"]', '2026-04-01 02:00:03.213', '2025-08-05 22:20:25.360', 264, NULL, 1, 2009, 'Ser a marca de chocolates De Todo Brasileiro vai além de criar sabores que conquistam os mais diversos gostos. \nÉ também entender a essência descomplicada e feliz do nosso povo, e ser cúmplice da graça, da liberdade e do jeito de ser do brasileiro. \nJá são mais de 15 anos de mercado e mais de 420 lojas espalhadas pelo país. Somos 100% digitais e atuamos nos principais canais de venda online. \nApaixonados pelo chocolate, inspirados pelo brasileiro: assim é a Brasil Cacau. \nÉ De Todo Brasileiro.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/59d16c87-9d87-41c3-b1fa-32293223e36e.png', 472, NULL, NULL, '2026-03-08 19:37:02.118', 'https://franquias.portaldofranchising.com.br/franquia-chocolates-brasil-cacau/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '180000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74lw006ceh0sq3pxl77n', 'SOLUMEDI', 'solumedi', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Franquias de agendamentos clínicos médicos, odontológicos e de exames laboratoriais e imagens', 2016, 2020, '[\"https://www.youtube.com/watch?v=drOyo4XxBOY\"]', '2026-04-01 02:00:03.236', '2025-08-05 22:20:25.364', 265, NULL, 1, 2016, 'A Solumedi surgiu em 2016, a partir da ideia de conectar clinicas particulares com pessoas que buscam atendimento médico de qualidade por um preço justo. Não realizamos nenhum tipo de cobrança recorrente e o usuário efetua somente o pagamento do agendamento. O que faz com que a Solumedi tenha o melhor CUSTO X BENEFÍCIO no ramo da saúde.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/696bed6e-89b6-4a20-8546-f085d6cf2e8c.jpg', 85, NULL, NULL, '2026-03-08 19:37:35.090', 'https://franquias.portaldofranchising.com.br/franquia-solumedi/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74m1006deh0sh8or99qh', 'ODONTOCLINIC', 'odontoclinic', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Rede de Clínicas Odontológicas', 2002, 2002, '[\"https://www.youtube.com/watch?v=pguBWynFmfU\",\"https://www.youtube.com/watch?v=HktTvnmjvTE\",\"https://www.youtube.com/watch?v=hifS9M8hEfc\"]', '2026-04-01 02:00:03.251', '2025-08-05 22:20:25.369', 266, NULL, 1, 1997, 'Não nos tornamos a melhor por acaso! Fundada em 1997 e credenciada à ABF (Associação Brasileira do Franchising) em 2002, se tornou a primeira franquia no segmento odontológico. A Odontoclinic conta com uma sólida e estruturada rede de 260 clínicas, as quais adotam um modelo multidisciplinar, sendo preparadas para atender todas as especialidades da Odontologia, entre elas ortodontia, implantodontia, periodontia, entre outras. Conveniência, qualidade e constante inovação no atendimento fazem parte de nosso dia-a-dia.  Somos a única companhia do setor com uma administração institucional, sustentada por uma equipe altamente qualificada de gestores. O modelo de negócio foi criado para permitir que empreendedores e dentistas tenham sucesso com a odontologia.  Está em nosso DNA transformar a experiência de ir ao dentista, utilizando as mais modernas e sofisticadas tecnologias disponíveis e tornar nossos franqueados empresários de sucesso, apoiando-os de forma efetiva na implementação e operação de suas clínicas. PRÊMIOS:  Umas da melhores franquias do país, chancelada com o selo de Excelência em Franchising pela ABF por vários anos   Grande vencedora na categoria saúde-clínicas do Prêmio Reclame AQUI - Edições de 2019, 2020 e 2021  Eleita uma das melhores franquias do Brasil pela Revista PEGN - Franquia 5 estrelas  Prêmio ABF+RDI Design na categoria produto. Reconhecimento que chancela a inovação, tecnologia e a qualidade.  Referência em atendimento com o selo RA1000, o nível mais alto de reconhecimento do site Reclame AQUI.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/15dccb2b-1156-4f73-9fd5-c6d1822f0856.jpg', 150, NULL, NULL, '2026-03-08 19:38:09.745', 'https://franquias.portaldofranchising.com.br/franquia-odontoclinic-odontologica/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/67a96159-cdbd-48b7-93da-d89a912e2750.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1dc3b262-8a21-4e99-bc1e-cee754f5d038.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b0faf507-3f1f-400a-ac74-d4e04250f89b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3ca6a781-eec0-4c0f-9335-f8b33df14a83.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/91c5ee45-19a1-431b-a561-3c8626853289.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e82d800e-385f-48e9-a653-184229b01c6e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0e1a828f-ace4-4ec8-a56e-3af906d15da9.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '370000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74m7006eeh0s83ycv281', 'JANELA BAR', 'janela-bar', NULL, 'Alimentação', 'Bares e Restaurantes', 'Gastronomia e coquetelaria de rua, essa é nossa especialidade! O Janela nasceu em Curitiba e hoje conquista todo o Brasil através da sua expansão em formato de franquias.', 2021, 2022, '[\"https://www.youtube.com/watch?v=u8Jl1tiEIF0\",\"https://www.youtube.com/watch?v=n6qY-TPX7A8\",\"https://www.youtube.com/watch?v=0-CR5q0fQAM\"]', '2026-04-01 02:00:03.276', '2025-08-05 22:20:25.375', 267, NULL, 1, 2017, 'O Janela Bar nasceu em 2017, na cidade de Curitiba - PR, com o objetivo de tornar a coquetelaria um produto acessível. Um ano depois da nossa inauguração fomos indicados como melhor coquetel da cidade, o que nos deu ainda mais certeza que: SOMOS O MELHOR DRINK DO ROLÊ! Anos depois, em 2021, decidimos que era o momento de expandir e, de lá pra cá, já são mais de 30 bares inaugurados, mais de 50 confirmados, espalhados por 8 estados do Brasil. O Janela reúne o melhor dos dois mundos: gastronomia e entretenimento. 90% dos nossos drinks são autorais da casa, trazendo ainda mais exclusividade para a experiência que proporcionamos. Além disso, nosso cardápio de burgers conquistam qualquer paladar, com burgers altos, smash burgers, de frango e também opções veganas e vegetarianas. Nosso diferencial é claro: entregar um produto custo benefício gigantesco, desde os burgers até as bebidas, tudo isso em um ambiente super descontraído e acolhedor. Em 2023, vendemos mais de 370 mil drinks, 295 mil litros de chope e mais de 340 mil burgers. Em 2024 fizemos parcerias com grandes marcas como Red Bull, Jagermeister, Tinder e diversas outras, o que nos aproximou ainda mais do nosso público e levou a marca para todo o Brasil. Se você busca uma franquia lucrativa e que está constantemente inovando, o Janela é sua opção!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/10b8058a-97b2-4928-8822-25993fda40b7.png', 31, NULL, NULL, '2026-03-08 19:39:10.612', 'https://franquias.portaldofranchising.com.br/franquia-janela-bar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74mb006feh0sy0dii6x0', 'Maxsorriso', 'maxsorriso', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', '', 2021, 2021, '[\"https://www.youtube.com/watch?v=m6MhEqdMF-w\",\"https://www.youtube.com/watch?v=OPmkpPr3YZ0\",\"https://www.youtube.com/watch?v=fL8kdzKLTBk\",\"https://www.youtube.com/watch?v=E5brJFA7Uhw\",\"https://www.youtube.com/watch?v=NV42ZEeKb8g\"]', '2026-04-01 02:00:03.292', '2025-08-05 22:20:25.380', 268, NULL, 1, 2012, 'A Maxsorriso nasceu com um propósito claro: levar atendimento odontológico de qualidade e transformar a vida das pessoas, inclusive a de dentistas e investidores que desejam empreender com segurança.', NULL, 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cf33bb05-c813-49ad-befc-a910e7e9f9fe.png', 24, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/48aabb65-e52b-4b52-b14f-444d8d521895.jpg', '2026-03-08 19:40:02.260', 'https://franquias.portaldofranchising.com.br/franquia-maxsorriso/', NULL, 'Receita Mensal', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4ece3b63-d090-417a-96ae-68ba7c9cdb66.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6891212f-2ffb-4722-8c6b-5b185e908558.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4cc69ca0-0820-4c14-9ef4-1aefed778881.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/11c9abb6-5db2-4091-9ca9-b865b98fe832.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/82a36fa3-aef3-49bb-b186-f2348c5b9e42.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e94d6794-25d6-4faa-a59d-bcbed0e92065.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8a819f8e-247c-46e2-97ca-67be2be729f5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/49a817d7-4ad5-46ae-a117-d210c43834cf.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d12ba2d3-1fde-4a4c-8c73-d11742e0fffc.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '390000', NULL, NULL, NULL, '30000', NULL, '6', NULL, '280000', '80000', 80);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74mg006geh0shpegbb35', 'SODIÊ DOCES', 'sodie-doces', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Confecção e Revenda de Bolos', 2006, 2009, NULL, '2026-04-01 02:00:03.339', '2025-08-05 22:20:25.384', 269, NULL, 1, 1999, 'Junte uma mulher simples, trabalhadora, determinada, justa, perseverante e dedicada com uma grande vontade de vencer. Misture tudo e coloque em uma assadeira untada de amor e paixão pelo que faz antes de levar ao forno. A Sodiê Doces foi criada pela empresária de sucesso Cleusa Maria da Silva, idealizadora e fundadora da Rede. A Sodiê Doces é uma rede especializada em bolos artesanais, com mais de 13 anos de existência e mais de 80 lojas. Surgiu no interior do estado de São Paulo, cidade de Salto, e avança por todo o Brasil, já presente em cinco estados. Composta de um mix de mais de 75 receitas elaboradas a base de pão de ló, matéria prima de primeiríssima qualidade e frutas frescas, capaz de conquistar todos os paladares, com preço acessível. Temos também as versões ZERO AÇÚCAR.   Diferenciais Utilizando matéria prima de qualidade, o diferencial esta na valorização do preparo artesanal com criação em 20 minutos a escolha do cliente. São mais de 80 tipos de bolos, com o melhor chocolate e as mais frescas frutas alem dos bolos na versão zero açúcar e ainda utilizamos a colher de pau em seu preparo. Com valor acessível para todos os públicos. Assim são as delicias dos Bolos da Sodiê Doces, que adoçam cada vez mais nosso dia a dia, unindo a família e amigos nos melhores momentos de nossas vidas. O segredo está na dedicação especial que são preparados cada pedaço com o mais suculento e singular sabor.  Conhecendo um pouco da Sodiê Doces. Talvez, quando uma mulher simples, mas com o dom da excelência em confeitaria, essa especiaria tão apreciada por nós brasileiros, começou a trabalhar na confecção de bolos nas horas vagas, para ajudar no orçamento doméstico, não tivesse conhecimento de onde chegariam suas habilidades, tão pouco o tamanho do sucesso que seus BOLOS fariam. A SODIÊ DOCES, fundada em 27 de julho de 1999, por Cleusa Maria da Silva, trouxe ao mercado um novo conceito em BOLO, ou seja, a criadora da arte reuniu matérias-primas de qualidade, associou aos métodos, técnicas e processos, para preparar e apresentá-los de maneira que constituíssem um prazer para o paladar além de agradar aos olhos e ainda, ter aroma apetecível. Hoje, no estado de São Paulo, tornou-se praticamente impossível falar em BOLOS e não associá-los aos confeccionados pelas SODIÊ DOCES. Quem tem a oportunidade de apenas apreciá-los com os olhos, fica extasiado diante de tanta beleza que aguça o paladar. Mas o grande pecado consiste em prová-los, pois, basta colocá-los na boca e solvê-los com o paladar, para se apaixonar e nunca mais esquecer tamanha gostosura. É baseado no incontido sucesso dos BOLOS, associado à vida moderna, onde a maioria das mulheres trabalham fora, mas sempre preocupadas em manter a qualidade e beleza em suas mesas, que a SODIÊ DOCES quer avançar com sua MARCA, levando à todas a oportunidade de saborear suas especiarias, além de gozar de uma enorme praticidade, aliada ao que há de mais importante: PREÇO e QUALIDADE. Bom apetite! De o primeiro passo para fazer parte da família SODIÊ DOCES É com enorme satisfação que apresentamos a você o sistema de franquias Sensações Doces. A SODIÊ DOCES superou todos os desafios de mercado nos últimos anos, expandindo suas atividades e se tornou uma das maiores franquias de bolos do estado de São Paulo. São 9 anos de qualidade e profissionalismo que se tornaram sinônimo de rentabilidade e crescimento constante. Ser franqueado SODIÊ DOCES significa ter às mãos uma marca singular, seja por conta de sua especialidade no ramo de bolos, seja por conta de suas lojas altamente aconchegantes e requintadas. Conheça um pouco mais sobre a nossa estrutura. Perfil do franqueado Para iniciarmos a abertura de uma Franquia SODIÊ DOCES precisamos conhecer o perfil de quem irá gerir o negócio, uma vez que o envolvimento do franqueado na operação é fundamental para o sucesso de qualquer franquia. Buscamos parceiros com habilidade e vivência comercial; experiência no varejo; visão empresarial; espírito empreendedor e liderança na condução de pessoas e negócios. É necessário possuir recursos compatíveis para investimento em curto prazo, considerando eventuais aportes necessários ao empreendimento, durante o período de maturação do mesmo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/22cf2940-aa6a-44d0-a0bd-b1290eee5a40.png', 391, NULL, NULL, '2026-03-08 19:45:09.741', 'https://franquias.portaldofranchising.com.br/franquia-sodie-doces/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '310000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ml006heh0saumnahcz', 'COXINHA NO POTE', 'coxinha-no-pote', NULL, 'Alimentação', 'Bares e Restaurantes', 'Coxinha no Pote é uma rede de franquia especializada em mini coxinhas, onde destaca a crocância irresistível do produto, e possui 4 modelos de negócio: Quiosque, loja de Rua , Container e Totem.', 2018, 2019, '[\"https://www.youtube.com/watch?v=JtRWjb2ierU\"]', '2026-04-01 02:00:03.362', '2025-08-05 22:20:25.389', 270, NULL, 1, 2014, 'No ano de 2014, momento em que o Brasil passava por uma enorme grande crise econômica, iniciamos um projeto desafiador, criar um fast-food de mini coxinhas dando prioridade e diversificação de produtos baratos e com qualidade superior aos concorrentes. Estudamos, planejamos, organizamos e finalmente, abrimos as portas de nossa primeira unidade no mesmo ano. \nDevido ao grande sucesso, a segunda Coxinha no Pote surgiu seis meses depois.  Em 2018 iniciamos nosso processo de franquia, adotamos uma nova identidade visual, nova marca, site, embalagens mais modernas e expandimos o negócio em mais 15 lugares. Possuímos três modelos de negócios, reformulados para atender aos diferentes perfis de empreendedores. Nossa expectativa é chegar a 50 unidades até o final de 2023.', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c877cb75-e21b-49dd-89ea-afe4e98c4b57.jpg', 20, NULL, NULL, '2026-03-08 19:47:26.060', 'https://franquias.portaldofranchising.com.br/franquia-coxinha-no-pote/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '75000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74mp006ieh0s62q4pqb8', 'Puro Açaí', 'puro-acai', NULL, 'Alimentação', 'Saudáveis', '', 2014, 2022, '[\"https://www.youtube.com/watch?v=gEMphQAI_vI\"]', '2026-04-01 02:00:03.379', '2025-08-05 22:20:25.394', 271, NULL, 1, 2011, 'A Puro.Açaí nasceu em 2011, a partir de um carrinho de açaí e do espírito empreendedor de seu fundador.', NULL, 'Ceará', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/aac35f68-2319-4b0f-8a7b-75c277010aa4.jpg', 63, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a0facab1-62b8-4b0a-ad59-826a8ac9e322.jpg', '2026-03-09 14:55:24.637', 'https://franquias.portaldofranchising.com.br/franquia-puro-acai/', 'Fat. Total', 'Fat. Total', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7f8274eb-f3ae-43cd-85d0-d74d0942c71e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a51346fd-7ef2-4872-95e4-a51cffae63c9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/05aa3ffa-c9c7-4882-bc3e-a5e2a6368b12.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/65e76c48-5b13-4ecc-8b57-b6518909d749.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/62f9387d-281e-4d0c-8867-a48749bbd686.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f015dec8-327f-4a2a-9eea-3b81e8bf4260.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/426206de-a98c-4383-b43d-63908a71ab10.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5749564c-1754-4d88-8875-fbf4c93035b2.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d9e97146-77e0-4a10-89f1-813707a5fe56.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '110000', NULL, NULL, NULL, '60000', NULL, '4', '2', NULL, '50000', 50);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74mu006jeh0svmoy13d0', 'SIMPLE ORGANIC', 'simple-organic', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Cosméticos naturais e orgânicos, livres de crueldade animal e pautados na sustentabilidade da biodiversidade.', 2017, 2019, '[\"https://www.youtube.com/watch?v=TS2cn6wRUX0\"]', '2026-04-01 02:00:03.390', '2025-08-05 22:20:25.399', 272, NULL, 1, 2016, 'Fundada em 2016 pela publicitária Patricia Lima, a marca foi lançada oficialmente na maior semana de moda do Brasil: São Paulo Fashion Week. Ao levar o conceito de cosméticos orgânicos e veganos para a passarela, se tornou a marca orgânica mais conhecida do Brasil. \nA marca foi concebida a partir do desejo da fundadora em criar uma marca sustentável, com impacto social positivo. \nA ideia surgiu após a maternidade da Patrícia, que decidiu buscar um novo caminho para sua vida, pensando no futuro das próximas gerações, inspirada em sua filha (com seis anos atualmente).  A Maior Franquia de Cosméticos Orgânicos, Veganos e Sustentáveis Temos a missão de democratizar a beleza natural, com produtos livre de ingredientes sintéticos, pesticidas e nocivos à pele, que prezam pela saúde por meio do respeito à natureza, às pessoas e aos animais. \nAcreditamos que a beleza vem junto com a saúde e, desta forma, levamos esse propósito para todo o Brasil. \nA marca nasceu digital, porém a demanda do mercado por uma rede de franquias que atendesse o consumidor com a experiência da marca, fez com que abríssemos a possibilidade de franquias e rapidamente abrimos inúmeras lojas que levam os nossos valores de sustentabilidade para todo território nacional.  Somos reconhecidos como case de sucesso dentro do segmento, tanto na comunicação / marketing, como produtos e também nas estratégias comerciais. \nSomos pioneiros no formato franquia de cosméticos orgânicos, veganos e sem gênero. Aliás, inovação é um dos pilares da marca, junto com a sustentabilidade. \nCom o maior mix de produtos orgânicos, veganos, os lançamentos são mensais e com a criação da maior variedade de cores de bases liquidas orgânicas, corretivos compactos e tantos outros produtos que ainda não existiam no mercado de beleza natural, conquistamos o reconhecimento como referência de produtos com alta performance. O resultado entregue para o nosso consumidor é reconhecido nacionalmente e internacionalmente, só no primeiro semestre de 2019 foram três produtos premiados e o Blending Facial já foi eleito como melhor hidratante facial orgânico dos EUA, em 2017. \nNossas franquias representam o conceito contemporâneo da marca e são inclusivas, com objetivo de receber da melhor maneira cada consumidor presente nas lojas', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a38016d1-604f-4bc9-86be-3885eec0246a.jpg', 15, NULL, NULL, '2026-03-08 19:52:00.203', 'https://franquias.portaldofranchising.com.br/franquia-simple-organic/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '110000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74n0006keh0s5pw2zw8a', 'DOUTORES DA WEB', 'doutores-da-web', NULL, 'Comunicação, Informática e Eletrônicos', 'COMUNICAÇÃO', 'Marketing de posicionamento da internet.', 2016, 2018, NULL, '2026-04-01 02:00:03.405', '2025-08-05 22:20:25.404', 273, NULL, 1, 2016, '', NULL, 'SÃO PAULO', 1, NULL, 17, NULL, NULL, '2025-09-09 08:32:11.000', 'https://franquias.portaldofranchising.com.br/franquia-doutores-da-web/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74n4006leh0s1lxslgu3', 'VILESOFT', 'vilesoft', NULL, 'Comunicação, Informática e Eletrônicos', 'Comunicação e Mídia', 'Softwares de gestão empresarial ERP / RH', 2005, 2007, '[\"https://www.youtube.com/watch?v=2i-Qk4JcK6A\",\"https://www.youtube.com/watch?v=LIFifmoRTcs\",\"https://www.youtube.com/watch?v=Mhp8TyvMmUQ\"]', '2026-04-01 02:00:03.421', '2025-08-05 22:20:25.409', 274, NULL, 1, 1986, 'A Vilesoft tem experiência de  mais três décadas com softwares de gestão empresarial. \nTrabalha com o modelo de franquias desde 2005, é filiada a ABF – Associação Brasileira de Franchising deste 2007 e foi a primeira franquia de software de gestão, no Brasil.   \nRecentemente a Vilesoft, optou em modernizar todo seu processo de franquias, incluindo outras modalidades que permite estar mais perto do cliente, utilizar novos conceitos de gestão e principalmente, permitir que profissionais de consultoria, contabilidade e outras especializações do ecossistema empresarial, também tenham a oportunidade de se tornarem um franqueado de sucesso Vilesoft. \nDurante toda nossa trajetória, a Vilesoft tem sido premiada seguidamente pela pela mídia e o mercado especializado, entre as melhores redes de franquias em vários quesitos, e principalmente na avaliação do franqueado. \nA Vilesoft  tem clientes  em várias cidades do Brasil, além de consultores e parceiros comerciais nos principais centros comerciais e empresariais do país. Possui uma fábrica de software certificada pela SOFTEX/Ministério da Ciência e Tecnologia em mps.BR nível \'G\' em Minas Gerais, produz e fornece softwares de gestão empresarial ERP, para empresas privadas de portes e segmentos diferentes, como o setor de Transportes – TMS, Avicultura, Indústria, Telemarketing de Arrecadação,  Recursos Humanos, Controladoria e serviços. \nEm 2021 iniciou seu processo de internacionalização, com sua primeira Master Franquia nos Estados Unidos da América.  Com objetivo de fortalecer sua marca e oferecer seus produtos e o seu modelo de franquias, também, na América do Norte. \nA Vilesoft tem em seu portfólio muita experiência no que faz, uma equipe afinada com seus clientes e principalmente sabe aliar com muita precisão, a tecnologia à gestão empresarial para realmente tornar efetivos os resultados que toda organização necessita. \nVILESOFT, são mais de três décadas de América, entregando resultados. Se você é sério, gosta de desafios, trabalhar em equipe, compartilhar talentos; fale conosco e venha fazer parte do nosso time de águias.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2525a1c7-9175-460e-92df-7d252eea0425.jpg', 4, NULL, NULL, '2026-03-08 19:53:41.537', 'https://franquias.portaldofranchising.com.br/franquia-vilesoft/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74n9006meh0s5upypg3w', 'PAREDES BETEL', 'paredes-betel', NULL, 'Casa e Construção', 'CONSTRUÇÃO', 'A marca está há mais de 50 anos no mercado, decidiu expandir o seu método facilitador para todo o território brasileiro, realizando sonhos de todos os clientes, em todo Brasil.', 2022, 2024, '[\"https://www.youtube.com/watch?v=ttcEX8IgZHs\",\"https://www.youtube.com/watch?v=1KLrWJTD5g0\",\"https://www.youtube.com/watch?v=fg-Ana-9c70\",\"https://www.youtube.com/watch?v=L3QR6uuxGAM\"]', '2026-04-01 02:00:03.440', '2025-08-05 22:20:25.414', 275, NULL, 1, 1997, 'A história emocionante da Paredes Betel se entrelaça com os últimos 54 anos de inovação e paixão na construção civil. Desde 1969, quando o visionário Walter Pedro da Silva fundou a empresa em Goianésia, nossa jornada começou com tijolos de cerâmica, uma base sólida para sonhos que se elevam aos céus. Somos parte do Grupo Betel, uma família de nove empresas dedicadas, incluindo três indústrias de cerâmica vermelha, quatro distribuidoras de Aço e EPS, uma loja de materiais para construção e uma fábrica de produtos de EPS. A evolução da cerâmica para o EPS simboliza não apenas uma mudança de material, mas uma transição que marca o nosso compromisso com a inovação e o futuro da construção. A Paredes Betel, nascida como uma indústria de produtos de EPS em 2003, tinha inicialmente a missão de atender à região de Brasília e ao centro-oeste. No entanto, à medida que nosso compromisso com a qualidade e a visão sustentável ganharam destaque, a popularidade de nossos produtos transcendeu fronteiras. Hoje, com especialistas em todos os estados e principais cidades do país, estamos orgulhosos de ver nossas criações transformando e aprimorando a paisagem arquitetônica nacional. Cada produto que oferecemos conta uma história de dedicação, qualidade e inovação. Estamos moldando o amanhã da construção civil, e cada tijolo, cada peça de EPS, é um testemunho do nosso comprometimento em construir não apenas estruturas, mas legados que resistem ao teste do tempo.', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9879d444-5ac2-40b4-a672-358dd775c4f7.png', 16, NULL, NULL, '2025-04-02 17:19:42.000', 'https://franquias.portaldofranchising.com.br/franquia-paredes-betel/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ne006neh0sgim1y1ip', 'TOUAREG CORRETORA DE SEGUROS', 'touareg-corretora-de-seguros', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Os corretores de seguros têm como função a distribuição e venda de seguros, tendo em vista que são intermediários independentes que negociam contratos de seguro para clientes que procuram proteção.', 2016, 2017, NULL, '2026-04-01 02:00:03.454', '2025-08-05 22:20:25.418', 276, NULL, 1, 2011, '', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/386feea9-97d8-4d43-a5f5-7c4d7495d529.png', 200, NULL, NULL, '2026-03-08 19:55:02.436', 'https://franquias.portaldofranchising.com.br/franquia-touareg-corretora-de-seguros/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '25000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74nj006oeh0s1xg9bzo7', 'PIASEG SEGUROS', 'piaseg-seguros', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Somos uma franqueadora de corretoras de seguros.', 2021, 2021, '[\"https://www.youtube.com/watch?v=DjWjKeCuYMM\"]', '2026-04-01 02:00:03.468', '2025-08-05 22:20:25.423', 277, NULL, 1, 2020, 'Nossa História começa lá em 1979, quando Wilson Piacentine (mais conhecido como Piá) foi contratado por uma grande seguradora, e por lá ficou por 15 anos, e o desejo de empreender foi ficando cada vez maior, quando em 1991 juntamente com outro funcionário da seguradora resolveu iniciar sua própria empresa, como os recursos eram limitados, a Sra Maria do Carmo, esposa, abraçou a ideia junto com ele dando início do negócio.  Em 2001 houve a cisão da sociedade, mas o Piá e a Sra Maria do Carmo continuaram firme com seu propósito de empreendedorismo, nascendo a Piaseg Seguros, o nome Surgiu da ideia de aproveitar o nome Piá que já era muito conhecido na cidade, somado com a palavra seguros, Pia + seg , nascendo a Piaseg. \nLá se vão 30 anos contemplando toda essa jornada, de sucesso e muitos desafios, que surgiram na vontade de empreender. Em 2020 demos mais um passo importante para o crescimento do negócio, nasceu a Piaseg Seguros Franchising, com o propósito de replicar o modelo de sucesso que executamos durante esses 30 anos de história, nosso propósito é trazer facilidade, ensinamos nossos franqueados os caminhos para ter uma empresa de sucesso, com processos fácil e proporcionando alta rentabilidade. A Piaseg Franchising é uma empresa inovadora, que acompanha bem de perto seus franqueados dando todo o suporte necessário para o impulsionamento da sua franquia. \nNossos franqueados poderão comercializar as apólices das melhores seguradoras do mercado Brasileiro em qualquer parte do território nacional.  A Piaseg proporcionará ao seu franqueado liberdade financeira e geográfica, ser dono do seu próprio negócio, com autonomia de trabalho, não precisando passar por toda essa jornada que seus fundadores passaram, trazemos nosso propósito muito a sério, que é gerar facilidade e alta rentabilidade aos nossos franqueados.', NULL, 'MATO GROSSO DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4f2f5937-cbbb-45b0-9f1f-5cfde945baba.jpeg', 7, NULL, NULL, '2026-03-08 19:55:28.910', 'https://franquias.portaldofranchising.com.br/franquia-ps-piaseg-seguros/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74no006peh0sb5aprwy9', 'TOP ENGLISH', 'top-english', NULL, 'Educação', 'Idiomas', 'Escola itinerante de inglês com foco na conversação.', 2011, 2016, NULL, '2026-04-01 02:00:03.479', '2025-08-05 22:20:25.428', 278, NULL, 1, 1997, 'A Top English está no mercado há 20 anos, ou seja, desde 1996. A princípio operamos unicamente com nossa sede própria até 2011, quando então iniciamos nossa expansão pelo sistema de franquias. Hoje contamos com 39 franquias espalhadas pelo Brasil, e além de 2 unidades internacionais, sendo uma na Flórida, EUA e outra no Japão. Nosso modelo de negócio permite que muitas pessoas que têm potencial, mas não possuem muito capital para empreendedor o façam, pois o investimento para abrir uma Top English é muito mais baixo se comparado às outras franquias tradicionais de idiomas. Nossa metodologia atende todas as idades a partir dos 3 anos de idade. Com metodologia que ensina conversação desde a primeira aula, nosso material didático é super moderno, contando, inclusive, com todos os livros no formato digital para tablet. Todos os professores só dão aulas com tablets e os alunos também podem fazer o download da versão digital da metodologia, caso possuam um tablet.', NULL, 'ALAGOAS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/dd245165-57bb-495a-9953-7b8882144597.jpg', 57, NULL, NULL, '2026-03-08 19:56:35.452', 'https://franquias.portaldofranchising.com.br/franquia-top-english-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '35000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74nt006qeh0s8itu5b4z', 'THE JOY SCHOOL', 'the-joy-school', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escola de Educação Verdadeiramente Bilingue com metodologia e material didático próprios, presente no mercado há 10 anos.', 2019, 2019, NULL, '2026-04-01 02:00:03.490', '2025-08-05 22:20:25.433', 279, NULL, 1, 2008, 'Fundada em 2008 como a primeira escola bilíngue na região de Jundiaí -São Paulo, com metodologia e material pedagógico próprio, os fundadores da THE JOY SCHOOL buscaram nas teorias de Piaget e Vygotsky, bem como nos estudos de pesquisadores do bilinguismo como Macnamara, Harms e Blanc, Patoon Tabors e Ofelia Garcia,  as bases para o desenvolvimento de seu trabalho. Desde então, vem crescendo e comprovando a eficiência de sua metodologia desenvolvida e única, levando em conta o conteúdo obrigatório definido pelo MEC- Ministério de Educação e Cultura a agora também se enqadrando nas normas da BNCC. JOY – Aprender com Alegria – as crianças  vivenciam a Língua Inglesa em um ambiente lúdico alinhado às novas tendências da educação mundial, sempre trabalhando com a cultura brasileira e norte-americana nas aulas de Artes, Matematica, Ciências e Ed. Do Movimento,  respeitando a infância como momento único na vida do ser humano.  Escola Bilingue: Duas Línguas e Duas Culturas – Os valores das duas linguas são trabalhados e respeitados para não haver bilinguismo de subtração.   ALGUMAS VANTAGENS Bilinguismo alinhado com a Edução do Seculo XXI Capacidade de seexpressar em 2 idiomas de forma maleável e a facilidade de aquisição de uma terceira língua no futuro ja comprovados cientificamente Criar diferencial competitivo em relação a escolas da região aproveitando o espaço físico da própria escola', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2fb2be43-ff7f-442f-bdf3-0d900cdf9b20.jpg', 10, NULL, NULL, '2026-03-08 19:57:16.482', 'https://franquias.portaldofranchising.com.br/franquia-the-joy-school/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/55869de9-3e99-4839-bdda-f7466a297ad5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5a0bff6a-45be-42bb-995a-68ad0acc4f77.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4ee65276-bfb1-407a-821a-72be9b46d045.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '800000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ny006reh0sa1vf4tf2', 'DSOP', 'dsop', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Referência em Educação Financeira no Brasil e no mundo, oferecemos produtos e serviços para pessoas, empresas e instituições de ensino interessadas em ampliar seus conhecimentos Educação Financeira.', 2012, 2019, NULL, '2026-04-01 02:00:03.502', '2025-08-05 22:20:25.438', 280, NULL, 1, 2008, 'Há mais de 10 anos transformando vidas e realizando sonhos A DSOP Educação Financeira é uma organização dedicada à disseminação da educação financeira no Brasil e no mundo, por meio da aplicação da Metodologia DSOP, criada pelo PhD. em Educação Financeira, educador e terapeuta financeiro, Reinaldo Domingos. Para atingir essa missão, a DSOP oferece uma série de produtos e serviços para pessoas, empresas e instituições de ensino, interessadas em ampliar e consolidar seus conhecimentos sobre Educação Financeira. Criada em 2008, a DSOP se firma dia após dia, como principal promotora de conhecimento sobre o tema no Brasil, destacando-se pelo amplo alcance de seus programas, os quais beneficiam cada indivíduo em todo o seu ciclo de vida: infância à idade adulta. Atualmente, a DSOP dispõe de uma rede formada por mais de mil educadores financeiros em todo o Brasil, além da representatividade nos Estados Unidos, África, Ásia, América do Sul e Central, que compartilham da missão de disseminar a educação financeira, romper com o ciclo de pessoas com desequilíbrio financeiro e construir novas gerações e famílias sustentáveis financeiramente. Missão: Disseminar a Educação Financeira no Brasil e no mundo, por meio da Metodologia DSOP, ensinando as pessoas a conquistarem autonomia financeira para a realização de seus sonhos. Visão: Ser referência em Educação Financeira no Brasil e no mundo por meio da Metodologia DSOP. Valores: Família, Diversidade, Sustentabilidade, Empreendedorismo, Autonomia e Cidadania. Política de Qualidade: Fornecer produtos e serviços especializados em Educação Financeira. Sendo franqueado DSOP, os seus lucros e sonhos estão em primeiro lugar. Conhecendo a Metodologia DSOP A Metodologia DSOP é formada por quatro pilares: Diagnosticar, Sonhar, Orçar e Poupar. São passos muito simples de aplicar e que promovem uma verdadeira transformação na vida das pessoas e famílias. Com este conhecimento, você terá as ferramentas necessárias para conquistar uma vida equilibrada e sustentável financeiramente. DIAGNOSTICAR Diagnosticar tem como objetivo identificar a sua movimentação financeira de ganhos, necessidades, sonhos, prestações/dívidas, reserva estratégica e gastos num período\ndeterminado. Por meio dele, você vai conhecer o caminho que seu dinheiro percorre, descobrindo o seu verdadeiro EU FINANCEIRO. Seu papel é o de buscar pela economia necessária que possibilite a realização dos seus propósitos. SONHAR No segundo pilar da Metodologia DSOP, Sonhar, você tem contato com o agente motivador que te mostra o caminho e o verdadeiro sentido da vida: O SONHO. Com ele, você se sente empoderado para realizar. ORÇAR O Orçamento é um instrumento que te faz enxergar o ontem, o hoje e o amanhã. Com ele, você pode corrigir hábitos já praticados, desenvolver um novo jeito de fazer e alinhar as expectativas futuras. Pode-se priorizar, por meio dele, os propósitos, os sonhos e as necessidades. POUPAR Poupar é o ato de empreender os recursos, financeiros ou não, provenientes do ganho e do gasto. Sua essência visa proteger, por meio de reservas financeiras, o destino dos recursos do hoje, do amanhã e do depois. Conceito de Educação Financeira “Educação Financeira é uma ciência humana que busca a autonomia financeira, fundamentada por uma metodologia baseada no comportamento, com o objetivo de construir um modelo mental que promova a sustentabilidade, crie hábitos saudáveis e proporcione o equilíbrio entre o SER, o FAZER, o TER e o MANTER, com escolhas conscientes para a realização de sonhos e necessidades”. PhD Reinaldo Domingos Como você pode fazer sucesso? Torne-se um Franqueado DSOP, você fará parte de um time de empreendedores que acredita que a Educação Financeira muda o mundo. São três modalidades de negócios (educador financeiro, terapeuta financeiro e educador educacional) capazes de transformar a vida de milhares de pessoas, ajudando-as a lidarem melhor com o dinheiro e mostrando os melhores caminhos para a realização de sonhos. Os ganhos como franqueado vão além dos produtos da modalidade da franquia adquirida, pois através do Ecossistema DSOP tem ganhos com indicação dos produtos das outras modalidades, o que permite aumentar a recorrência dos ganhos como franqueado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7b58f428-8124-4087-8350-b401f9a8f343.svg', 62, NULL, NULL, '2026-03-09 14:59:18.478', 'https://franquias.portaldofranchising.com.br/franquia-dsop/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '20820', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74o4006seh0skyuizqqh', 'CLIGE', 'clige', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Rede de Clinicas Odontológicas com atendimento humanizado em todos os seguimentos da odontologia, inclusive estética e beleza. Visite-nos: https://clinicasclige.com.br/sejafranqueado/', 2022, 2024, '[\"https://www.youtube.com/watch?v=umD6po8qpRQ\"]', '2026-04-01 02:00:03.512', '2025-08-05 22:20:25.444', 281, NULL, 1, 2006, 'Fundada em 2006 na cidade de Salvador (BA) pelo recém-formado e empreendedor Doutor Geraldo Menezes. Em 2010 migrou para Senhor do Bonfim, interior da Bahia e, com seu método de atendimento, em 5 anos tornou-se referência em odontologia na microrregião, recebendo e tratando pacientes das cidades circunvizinhas. 2015 já era referência em seu segmento na Região. O sonho de replicar seu trabalho e modelo de negócio para todo o Brasil crescia a cada dia, com sólidos motivos para acreditar que esse era o caminho certo. Clínicas Clige, hoje, é considerada referência em tratamento odontológico. Seu modo de ouvir e falar a língua dos seus clientes, com consultórios simples, mas confortáveis e sem se descuidar das atualizações científicas, materiais, equipamentos e técnicas de primeira qualidade, é o diferencial nos mercados onde atua. A marca tem por objetivo oferecer excelência no atendimento, desde o primeiro contato, com equipamentos modernos e profissionais altamente qualificados e treinados pelo modo Clige de atender.     Com foco na qualidade do atendimento e disponibilidade de todos os serviços odontológicos num só lugar, gera plena satisfação dos seus pacientes com serviços garantidos e preços justos.   Nossa MISSÃO – transformar vidas.\nPrestar serviços de alta qualidade ao maior número de pessoas, ajudando-as a recuperar a saúde bucal, sua autoestima e o seu melhor sorriso. Vamos transformar a vida de milhares de pessoas: nossos clientes, nossos colaboradores e todas as suas famílias. Nossa VISÃO – ser referência em odontologia de alto nível no País. Duplicar nossas unidades, com qualidade e segurança, para entregar e devolver o sorriso a todas as pessoas que nos procurar. Nossos VALORES – praticar odontologia de qualidade com responsabilidade. Compromisso, ética e respeito ao ser humano, sempre com dedicação e harmonia entre nossos colaboradores e pacientes. Transformar sorrisos e conquistar clientes para a vida inteira, não por dinheiro e sim pela confiança em nossa marca.', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/71fcccae-e3f7-468c-933b-0dc52b1dad56.jpg', 3, NULL, NULL, '2026-03-08 20:00:25.938', 'https://franquias.portaldofranchising.com.br/franquia-clige/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/12415502-f7d8-4f2a-afb9-b01b6f41d764.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/475e7856-cbbf-4217-a18c-56417834817d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/63a77d13-f6ed-4ac3-ba5c-dc5d6f7b9b80.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74o9006teh0swf3fls5p', 'EMBRACON', 'embracon', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Venda de cota de consórcio e outros serviços financeiros', 2022, 2022, NULL, '2026-04-01 02:00:03.524', '2025-08-05 22:20:25.449', 282, NULL, 1, 1988, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e28679ef-3ccb-4ea4-9e94-e56c88f84408.png', 129, NULL, NULL, '2025-11-25 09:43:01.000', 'https://franquias.portaldofranchising.com.br/franquia-embracon/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '140000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74od006ueh0suxlia10b', 'MR. CAT', 'mr-cat', NULL, 'Moda', 'Calçados', 'Loja de calçados, moda e acessórios masculinos e femininos.', 1987, 2009, '[\"https://www.youtube.com/watch?v=UfmVueoCrMU\"]', '2026-04-01 02:00:03.537', '2025-08-05 22:20:25.454', 283, NULL, 1, 1981, 'A MR. CAT é uma das maiores referências do Brasil no segmento de calçados e acessórios masculinos e femininos. Com mais de 40 anos de história, a marca carioca possui presença nacional consolidada, com mais de 100 lojas em todo o país, forte atuação digital e uma produção anual próxima a um milhão de produtos, entre calçados e acessórios. Suas coleções são desenvolvidas a partir de pesquisas de tendências, incorporando tecnologia, materiais de alta qualidade e design contemporâneo, sempre com foco em conforto, estilo e autenticidade. Na linha masculina, destacam-se os sapatos sociais leves e modernos, além dos tênis em knit, que proporcionam maior conforto. Já a linha feminina prioriza o bem-estar aliado à elegância e praticidade para o dia a dia. Desde a inauguração de sua primeira franquia, em 1987, a MR. CAT mantém um projeto de expansão contínuo e sustentável. Atualmente, atua com estratégia de multicanalidade, integrando os canais físico e digital com excelência operacional e foco total na experiência do cliente.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/09f8ecc0-8634-41f4-bfd4-739b3c83e98a.svg', 99, NULL, NULL, '2026-03-08 20:01:54.367', 'https://franquias.portaldofranchising.com.br/franquia-mr-cat/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '298000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74oi006veh0s9kgoj9ys', 'NEMA', 'nema', NULL, 'Alimentação', 'PADARIAS', 'Panificação de fermentação natural em modelo de negócio minimalista', 2022, 2022, '[\"https://www.youtube.com/watch?v=HVVm64vuEuI\",\"https://www.youtube.com/watch?v=m4Wkg8TA6NU\",\"https://www.youtube.com/watch?v=YxIKDVg2VFk\"]', '2026-04-01 02:00:03.562', '2025-08-05 22:20:25.458', 284, NULL, 1, 2019, 'Somos uma rede de padaria artesanal e fazemos o melhor pão do mundo: o sourdough; além de muitos outros produtos de alta qualidade e de fermentação natural. Nosso principal objetivo é levar comida de qualidade para o maior número de pessoas pelo Brasil. A essência da marca é encantar o cliente com qualidade e praticidade, trazer o artesanal afetivo para o dia a dia das pessoas. Entregando aos nossos clientes uma experiência encantadora, com produtos frescos e de alta qualidade pelo melhor preço possível. Para manter este compromisso, somos extremamente focados em melhoria e otimização de processos, qualidade e usamos muita tecnologia para nos ajudar nessa missão.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/03824326-9782-4be4-bedd-3bd97ca9ccec.jpg', 7, NULL, NULL, '2025-09-12 10:48:11.000', 'https://franquias.portaldofranchising.com.br/franquia-nema/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74on006weh0safe0c5ua', 'MEGAMATTE', 'megamatte', NULL, 'Alimentação', 'Bares e Restaurantes', 'Mate orgânico, pão de queijo, salgados integrais, tradicionais. açaí orgânico, guaraná natural, sucos naturais, cafeteria', 2005, 2006, NULL, '2026-04-01 02:00:03.577', '2025-08-05 22:20:25.463', 285, NULL, 1, 1994, 'A Megamatte surgiu com uma proposta diferente e inovadora: superar as expectativas dos nossos clientes com uma alimentação saudável e saborosa, de qualidade diferenciada e preço justo, atuando com responsabilidade social e ambiental por meio de uma gestão baseada em processos sustentáveis e criação de valor para colaboradores, franqueados e fornecedores. Desde a sua chegada ao mercado, a marca possui um modo de produção exclusivo para o mate. A bebida é preparada como se fosse um chá, de forma artesanal, em cada loja. Feita com erva-mate orgânica, o mate possui uma fórmula livre de conservantes, xaropes e outras químicas. Deste modo, todos os seus benefícios são mantidos, levando aos clientes um produto completamente natural. Com um projeto empreendedor e ambicioso, a franquia Megamatte abriu sua primeira unidade na cidade do Rio de Janeiro, em 1994. Desde então, muitas mudanças ocorreram, desde o cardápio até a marca, sempre atendendo às demandas do público crescente da Megamatte, que hoje possui mais de 150 lojas em 6 estados do Brasil.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7576c962-9d78-4b79-8c0f-0fb6e1f7781c.svg', 105, NULL, NULL, '2026-03-08 20:03:18.712', 'https://franquias.portaldofranchising.com.br/franquia-megamatte-bebidas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '112000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74os006xeh0shhhez70r', 'DOCTOR FEET', 'doctor-feet', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Prestação de serviços de podologia e venda de produtos médicos, ortopédicos, esporte e fisioterapia.', 2000, 1993, '[\"https://www.youtube.com/watch?v=cMjOMoSNSrU\",\"https://www.youtube.com/watch?v=sA8ACc6sjZw\",\"https://www.youtube.com/watch?v=p4-UCWGBnEI\"]', '2026-04-01 02:00:03.588', '2025-08-05 22:20:25.468', 286, NULL, 1, 1998, 'A Doctor Feet é a maior rede especializada na prestação de serviços de podologia, voltados aos cuidados e à saúde dos pés. Além dos tratamentos, também oferece serviços de estética e bem-estar e cada loja possui um catálogo com uma grande variedade de produtos e acessórios médicos e ortopédicos das marcas mais conceituadas do mercado. Histórico Em 1998 a Doctor Feet inaugurou sua primeira loja no Shopping Aricanduva, Zona Leste de São Paulo. Foi o início da construção da maior Rede de podologia do país, hoje presente em 14 estados e com mais de 80 lojas. Essa trajetória de sucesso partiu da necessidade de um serviço que oferecesse padrões técnicos de qualidade, segurança e atendimento especializado para a demanda de um público cada vez mais consciente da necessidade de cuidar da saúde dos pés. Visão Ser a melhor e mais ampla rede de cuidados e saúde para os pés, oferecendo ainda serviços complementares de conveniência, e os melhores produtos médicos, ortopédicos e para o bem estar. Missão Excelência na prestação de serviços de cuidados e saúde para os pés dos nossos clientes, serviços complementares de conveniência, suportada por um processo de aperfeiçoamento contínuado de nossos profissionais, disponibilizando também os melhores produtos médicos, ortopédicos e para o bem estar do mercado. Valores Ética, credibilidade e confiança: atuar com base nos mais elevados princípios éticos, dentro dos limites técnicos estabelecidos para a área de Podologia, atendendo 100% das determinações das autoridades de Saúde. Excelência no atendimento: busca contínua em melhorar o atendimento aos nossos clientes. Segurança dos clientes e profissionais: esterilização de vanguarda dos instrumentos e equipamentos utilizados.\nRespeito: aos colaboradores e parceiros de negócios', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4a34216b-3d02-48de-bcbc-d18dadfc273b.jpg', 53, NULL, NULL, '2026-03-08 20:04:05.390', 'https://franquias.portaldofranchising.com.br/franquia-doctor-feet-beleza-e-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '299000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74oy006yeh0sjhkea60k', 'BOLOS DO CERRADO', 'bolos-do-cerrado', NULL, 'Alimentação', 'Mercados e Distribuição', 'Especializada em bolos caseiros e artesanais, feitos com ingredientes selecionados e receitas que resgatam o verdadeiro sabor da tradição, oferecemos produtos derivados com nossa marca própria.', 2013, 2018, '[\"https://www.youtube.com/watch?v=nkHGq2ksXCA\"]', '2026-04-01 02:00:03.598', '2025-08-05 22:20:25.474', 287, NULL, 1, 2012, 'Em 2012, dois amigos, Gustavo Martins e Ademar Cabral Júnior se uniram para inaugurar a primeira loja da Bolos do Cerrado em Goiânia, no estado de Goiás. Um negócio que nasceu da verdadeira vontade de empreender, levando para casa dos nossos clientes, sabores e encantos para os mais variados paladares. Após um ano de muito trabalho e dedicação, iniciou-se em 2013 o processo de franqueamento, que até então não era o objetivo dos empreendedores. A decisão de se tornar uma franquia foi fomentada pelos próprios clientes e amigos, que queriam investir num modelo de negócio de sucesso e com a qualidade que oferecíamos. A cozinha tradicional caseira simples, porém delicada e saborosa e que sempre foi o forte da Bolos do Cerrado, conquistou corações por todo Brasil. Estar na mesa dos brasileiros é um privilégio! Cada família, cada cliente, cada amigo é para a Bolos do Cerrado uma conquista. Por isso nos dedicamos para que cada mordida seja uma degustação que remete a uma viagem nostálgica a memórias felizes com pessoas queridas em momentos inesquecíveis. A Bolos do Cerrado conta hoje com mais de 45 franquias em 13 estados brasileiros, e o projeto de expansão contempla todo o território nacional, sendo assim, seja bem-vindo! Existe muito espaço para você na nossa família. O nosso cardápio contempla mais de 60 sabores de bolos para satisfazer o gosto de seus clientes, tendo como o principal ingrediente a qualidade, a dedicação e o amor pelo que faz. Somos mais que uma franquia de bolos, somos uma família que busca sempre o melhor, para servir a sua!', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8fe51ead-03c0-4dfd-9112-7b6e7035431e.png', 42, NULL, NULL, '2026-03-08 20:05:15.593', 'https://franquias.portaldofranchising.com.br/franquia-bolos-do-cerrado/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '180000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74p3006zeh0s4xehze2l', 'REDEORTO', 'redeorto', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Clínicas Odontológicas', 2006, 2008, '[\"https://www.youtube.com/watch?v=PTMovAoKR6Y\"]', '2026-04-01 02:00:03.609', '2025-08-05 22:20:25.480', 288, NULL, 1, 1999, 'Por que investir em uma franquia odontológica é o modelo de negócio com garantia de sucesso? Ao abrir seu consultório, todo dentista certamente almeja ter um grande número de pacientes e crescer de modo financeiramente sustentável, garantindo assim, seu sucesso e seu futuro no mercado de trabalho. Entretanto, esta não é a trajetória traçada pela maioria dos profissionais. País com o maior número de dentistas no mundo, o Brasil tem um ambiente bastante hostil e concorrido para os dentistas, tornando nada fácil competir com clínicas já estabelecidas e bem estruturadas. O que fazer, então, diante destes desafios enfrentados? A resposta pode ser investir em um modelo bem sucedido de franquia odontológica e contar com o suporte de uma marca consolidada, que irá oferecer ferramentas de gestão e empreendedorismo, além de vantagens competitivas frente à concorrência, auxiliando em uma jornada de sucesso no universo profissional. A trajetória do dentista Rubens Vergani pode ser usada como exemplo. Em 2001, ele decidiu unir seu talento na área e somar esforços com as habilidades em administração de seus sócios Renato Vergani e Afrânio Wehbe. Os três iniciavam ali as primeiras ações para viabilizar uma clínica que oferecesse tratamento de qualidade com alta lucratividade. Diante da experiência bem sucedida, o passo seguinte foi transformar o projeto em um modelo de negócio replicável. Cinco anos depois, em 2006, surgia a REDEORTO, uma das maiores redes de franquia de clinicas odontológicas do Brasil, referência em tratamento odontológico de qualidade e atenção ao cliente. Hoje, a REDEORTO ultrapassa uma centena de unidades em funcionamento em 17 estados brasileiros e no Distrito Federal, e a meta é crescer 30% até o final de 2020. Uma das estratégias utilizada para ser alcançar essa meta é a conversão de clínicas particulares em unidades franqueadas. Esta expectativa é pauta principalmente na estratégia de converter clínicas particulares em uma franquia odontológica da REDEORTO. “Uma das vantagens de se investir no mercado de franquias é contar com todo o suporte da franqueadora para planejar ações de crescimento, ter auxílio na contratação de equipes, estabelecimento de indicadores e acompanhamento da jornada empreendedora. Ao converter uma clínica particular em uma franquia odontológica, é possível aumentar o domínio sobre uma série de questões do plano gerencial que são fundamentais para um crescimento sólido do negócio”, explica o CEO da REDEORTO, Rubens Vergani. Outra vantagem para quem decide converter uma clínica em uma franquia odontológica é aumentar a captação de pacientes. Por se tratar de uma marca já reconhecida no mercado, o franqueado conta com a força das campanhas de marketing, tanto online como off-line. Converter uma clínica em uma franquia odontológica, naturalmente, reduz os riscos de empreender por conta própria em um ambiente saturado e bastante concorrido. Atualmente, as franquias odontológicas fazem parte dos segmentos que mais crescem no franchising. No primeiro trimestre de 2019, o setor de beleza, saúde e bem-estar, do qual fazem parte as clínicas odontológicas, registrou uma taxa de crescimento de 9,2%.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cd0b3626-f93b-43f2-b4d6-a15bc0e329f2.svg', 63, NULL, NULL, '2026-03-08 20:06:21.613', 'https://franquias.portaldofranchising.com.br/franquia-redeorto-odontologia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74p90070eh0sgmwdsclr', 'CARACOL CHOCOLATES', 'caracol-chocolates', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'No segmento de chocolate artesanal ,com mais de 40 anos de história, a Caracol Chocolates é uma marca forte no Sul do País e também no coração de cada turista que visita a cidade de Gramado no RS.', 2019, 2020, '[\"https://www.youtube.com/watch?v=3LKclCI08AU\",\"https://www.youtube.com/watch?v=ATTpDKMywR4\"]', '2026-04-01 02:00:03.619', '2025-08-05 22:20:25.485', 289, NULL, 1, 1982, 'Prestes a completar 40 anos, a Caracol é uma empresa moderna e inovadora, especializada em elaborar e produzir chocolates artesanais de excelência. Uma história de amor pelo chocolate e, acima de tudo, de obstinação por oferecer os melhores produtos aos consumidores. Em 2019 a Caracol Chocolates foi adquirida pela Florestal Alimentos S/A, uma das maiores e mais importantes fabricantes de candies do país. É também a maior fabricante de pirulitos planos da América Latina e uma das maiores do mundo atualmente. O Brasil é o 6º país em volume de vendas de chocolate no varejo no mundo. Sete em cada dez brasileiros consomem chocolate. Isso se reflete no mercado de chocolate gourmet, por exemplo, que vem crescendo até três vezes mais que o mercado de chocolate tradicional, com consumo de 2,2 kg de chocolate por pessoa ao ano. O consumo era de 1,65 kg há três anos atrás. A Caracol acredita em parcerias sólidas e duradouras. Assim, a identificação de investidores com perfil adequado ao negócio, é muito importante para o sucesso do franqueado e naturalmente da marca Caracol na região onde se apresenta. Queremos levar às pessoas toda a qualidade, sabor e encantamento dos chocolates Caracol. Por isto, entendemos como imprescindível associar a marca a investidores que tenham total identificação com a dinâmica que o negócio exige. Associado a isto, a Caracol entrega toda a sua expertise e suporte para o êxito da operação.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ed59743e-cbcc-4c9d-87ca-33225faf9495.svg', 25, NULL, NULL, '2025-08-18 12:38:31.000', 'https://franquias.portaldofranchising.com.br/franquia-caracol-chocolates/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74pe0071eh0sbrfufo28', 'GRAND CRU', 'grand-cru', NULL, 'Alimentação', 'Mercados e Distribuição', 'Presente no Brasil há mais de 21 anos, a Grand Cru é a maior rede de lojas de vinhos da América Latina, com mais de 130 lojas (próprias e franquias) em todo Brasil.', 2004, 2018, NULL, '2026-04-01 02:00:03.630', '2025-08-05 22:20:25.490', 290, NULL, 1, 1998, 'A GRAND CRU nasceu do sonho de difundir a cultura do vinho e vem trabalhando incessantemente em busca dos melhores rótulos. Fundada em Buenos Aires no ano 1998, chegou ao Brasil em 2002. Passados mais de 16 anos de nossa história, crescemos e nos tornamos a maior rede de lojas de vinho de importação exclusiva do Brasil, consolidada como detentora do melhor portfólio do mercado! Somada a essa seleção incrível, uma intensa transformação de nossa empresa- em todos os aspectos. Desde a chegada do Fundo Acqua Capital , em 2015, a GRAND CRU, vem apresentando um crescimento muito significativo nos últimos anos. Com estrutura e equipes sólidas, nosso modelo de negócio nos permite atuar nos B2B E B2C como referência em ambos os segmentos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d8de0525-42ff-404a-bca3-66d779e6b6b9.jpg', 126, NULL, NULL, '2026-03-08 20:08:17.024', 'https://franquias.portaldofranchising.com.br/franquia-grand-cru/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '390000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74pk0072eh0sfcjgc3tj', 'REGUS', 'regus', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Locação de espaços de trabalho flexíveis (escritórios, coworking e salas de reunião) inteiramente equipados e prontos para uso.', 2015, 2019, '[\"https://www.youtube.com/watch?v=fhuibHDcZ8E\"]', '2026-04-01 02:00:03.641', '2025-08-05 22:20:25.496', 291, NULL, 1, 1989, 'Torne-se um franqueado da IWG e aproveite a crescente demanda por espaços de trabalho flexíveis. A demanda por trabalho híbrido continua a crescer em um ritmo sem precedentes, com 88% das empresas adotando modelos de trabalho flexíveis.* Estamos em busca de parceiros de franquia individuais, multiunidades e regionais que tenham uma visão de crescimento e excelência operacional. Como a maior provedora de espaços de trabalho flexíveis do mundo, com mais de 4.000 locais em mais de 120 países, a IWG oferece mais de 30 anos de experiência para ajudá-lo a maximizar seus retornos e construir um negócio lucrativo. Fale conosco hoje mesmo e torne-se um parceiro de franquia do líder global em espaços de trabalho flexíveis. *Fonte: Microsoft, New Future of Work Report   Vantagens Usufruir de uma forte atração comercial global. Qualquer unidade do Brasil ou do mundo pode gerar demanda para uma nova franquia. E quanto ao suporte, a consultoria fornecida por nossos especialistas responsáveis pela operação, indicará qual o formato mais adequado, além de auxiliar em todas as etapas da implantação e operação da franquia. Avaliamos a viabilidade do negócio na região, o que consequentemente traz uma melhor chance de atender os clientes de forma satisfatória.  Não precisa de experiência prévia Para a abertura das franquias, basta ter experiência em gestão de negócios, um imóvel (próprio ou alugado) e que cumpra com os requisitos de abertura da marca.   Sobre o International Workplace Group O International Workplace Group é líder global em soluções para o trabalho híbrido. Criamos valor pessoal, financeiro e estratégico para empresas de todos os portes. Desde algumas das companhias e organizações mais conhecidas do planeta, até microempreendedores e a próxima geração de líderes do setor. Todos podem aproveitar o poder da plataforma de trabalho híbrido do International Workplace Group para aumentar sua produtividade, eficiência, agilidade e proximidade com o mercado. A cobertura de rede do IWG inclui aproximadamente 4.000 locais em mais de 120 países, enquanto 83% das empresas da Fortune 500 fazem parte da nossa crescente base de clientes. No Brasil, por meio das marcas Regus, Spaces e HQ Coworking, o IWG colabora para que milhares de pessoas e seus negócios possam trabalhar de forma mais produtiva. Fazemos isso ao fornecer espaços de trabalho híbrido profissionais, inspiradores e colaborativos, além de serviços digitais disponíveis por meio do aplicativo do International Workplace Group.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/450f149c-22ec-4be6-89e7-cf15d72f06c8.jpg', NULL, NULL, NULL, '2026-03-08 20:08:59.181', 'https://franquias.portaldofranchising.com.br/franquia-regus/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '1900000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
