INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74s5007leh0scihzqfwu', 'ACG HOME CARE', 'acg-home-care', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Atenção Domiciliar à Saúde no segmento de Home Care, com atendimentos de enfermeiros, equipe de técnicos de enfermagem, cuidadores de pessoas, medico geral, fisioterapia, fonoaudiologia e nutrição.', 2021, 2022, '[\"https://www.youtube.com/watch?v=EbRi8bshjuI\"]', '2026-04-01 02:00:03.874', '2025-08-05 22:20:25.590', 310, NULL, 1, 2000, 'A FRANQUIA MAIS BARATA DO BRASIL NO SEGMENTO DE HOME CARE Faça parte de um negócio que só cresce na área da saúde. E não pense você que estamos falando isso para vender um produto, mas os dados falam por si. “O número de brasileiros com mais de 60 anos superou os 30 milhões em 2017, segundo a Pesquisa Nacional por Amostra de Domicílios Contínua (Pnad) divulgada nesta quinta-feira pelo IBGE, e a tendência é que o envelhecimento da população acelere de forma a, em 2031, o número de idosos superar o de crianças e adolescentes de 0 a 14 anos no Brasil” Somos uma das mais antigas empresas de Atenção Domiciliar do Brasil, desde 2000 no mercado do Rio Grande do Sul. Oferecemos à você mais que uma bandeira, mas uma consultoria constante para te fazer crescer, além de uma estrutura de logística para a entrega de materiais médicos hospitalares, medicamentos e dietas enterais. Se você possui os 3 pontos abaixo, fale conosco: 1) Espírito empreendedor\n2) Ama cuidar de pessoas\n3) Vontade de vencer', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/871f6a55-86bd-4c08-9d5a-448cf7bb75fc.jpg', 6, NULL, NULL, '2026-03-08 20:21:23.180', 'https://franquias.portaldofranchising.com.br/franquia-acg-home-care/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
