INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74u4007xeh0s9uwhi6hs', 'NOOMA', 'nooma', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO COMPLETO', 'Restaurante que não necessita de exaustão, podendo ser instalado em locais pequenos, se apropriando do fluxo de shoppings e aeroportos.', 2019, 2021, NULL, '2026-04-01 02:00:04.010', '2025-08-05 22:20:25.661', 322, NULL, 1, 2018, 'O Sistema de Franquia NOOMA é um sistema multimarca de produtos de chocolate e restaurante com chocolate bar, pelo qual a Franqueadora disponibilizará ao Franqueado, por contrato, o seu know-how com relação aos aspectos operacionais, financeiros, administrativos, técnicos e comerciais necessários à operação de uma loja NOOMA. A NOOMA oferece uma variada linha de produtos de chocolate “Bean To Bar” premiados, assim como suas linhas próprias. Numa loja que ostente a marca NOOMA, o público poderá desfrutar de lanches, refeições leves e sobremesas, com produtos sortidos que atendem o cliente desde o café da manhã até a ceia noturna. As lojas possuem um conceito colaborativo e aberto a todos os públicos, tendo o papel informativo e o dever de levar o que há de melhor ao consumidor, com o objetivo de revolucionar a cultura de chocolate no Brasil. Além do produto, sempre focado em seu cliente, a NOOMA mantém uma preocupação constante com sua apresentação visual, com lojas claras, atuais e que permitem uma exposição atrativa e objetiva de seus produtos. O trabalho com a equipe de vendas complementa o encantamento de seus clientes, com um atendimento que inclui o envolvimento de todo o pessoal com o conceito NOOMA. A equipe trabalha feliz e os clientes percebem este envolvimento, tanto na responsabilidade de suas funções, quanto na felicidade de participarem da equipe NOOMA.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0ae7c171-7e69-457f-a74b-b5975f5fcc59.jpg', 2, NULL, NULL, '2025-09-12 10:53:14.000', 'https://franquias.portaldofranchising.com.br/franquia-nooma/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74u9007yeh0s5a1kd6a5', 'PENTAGONAL SEGUROS', 'pentagonal-seguros', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'FRANQUIA DE CORRETORA DE SEGUROS INSERIDA NA ÁREA DE SERVIÇOS, ONDE O FRANQUEADO NEGOCIA DIVERSOS TIPOS DE SEGUROS, CONSÓRCIOS E FINANCIAMENTOS DE SEGURADORAS DE ALTO NÍVEL NO MERCADO', 2013, 2015, NULL, '2026-04-01 02:00:04.025', '2025-08-05 22:20:25.666', 323, NULL, 1, 2003, '', NULL, 'RIO DE JANEIRO', 1, NULL, 25, NULL, NULL, '2025-09-09 12:14:44.000', 'https://franquias.portaldofranchising.com.br/franquia-pentagonal-seguros-negocios-e-servicos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ue007zeh0svnjm7q3s', 'GELA BOCA SORVETES', 'gela-boca-sorvetes', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Uma rede de sorveterias que é sucesso em todas as regiões onde atua. Investimento sob medida para quem valoriza a inovação, o relacionamento com o cliente e a mais alta qualidade em produtos.', 2010, 2018, '[\"https://www.youtube.com/watch?v=NYfei0E7xNM\",\"https://www.youtube.com/watch?v=h1EP7wdjGys\"]', '2026-04-01 02:00:04.036', '2025-08-05 22:20:25.670', 324, NULL, 1, 2000, 'A Gela Boca surgiu no ano 2000 em Maringá, no norte do Paraná, em um pequeno espaço de  120 m² que funcionava como fábrica e loja, atendendo diretamente ao consumidor final. Depois de ganhar a preferência em seu bairro, conquistou notoriedade por toda cidade, que reconhecia nos produtos Gela Boca a qualidade, originalidade e o preço justo. Logo a demanda e produção aumentaram, assim como o investimento em inovação e matéria-prima de excelência. Depois da abertura das primeiras filiais, alinhadas com um sistema de gestão que funcionava com alto padrão de excelência,  veio um novo projeto de expansão que consistia na formatação do sistema de franquias. em 2010 nasceram as primeiras lojas franqueadas da Gela Boca e em 2011 a rede conquistou mais 16 novas franquias. Duas décadas se passaram e hoje a Gela Boca conta com uma fábrica que ocupa 8.000m² e mais de  70 lojas franqueadas espalhadas pelos estados do Paraná, Santa Catarina e São Paulo. O crescimento é constante e as projeções são animadoras. Com inovação no DNA e simplicidade nos processos, a Gela Boca está  diariamente em busca de novos conhecimentos para se modernizar, elevar ainda mais a qualidade e variedade dos produtos e gerar novas experiências ao consumidor. Tudo isso para atender com cuidado as principais necessidades dos clientes e franqueados que ajudam a construir essa deliciosa história de sucesso.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6942e8d7-b4bb-4f15-9588-4ed2f0d8383a.png', 146, NULL, NULL, '2026-03-08 20:26:31.464', 'https://franquias.portaldofranchising.com.br/franquia-gela-boca-sorvetes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '350000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ui0080eh0sf68yyqqz', 'TT BURGER', 'tt-burger', NULL, 'Alimentação', 'Bares e Restaurantes', 'CNAE 56.11-2-01 - Restaurantes e similares', 2021, 2022, '[\"https://www.youtube.com/watch?v=e0mU4e0neaM\",\"https://www.youtube.com/watch?v=UHU3NJtp1xw\",\"https://www.youtube.com/watch?v=V9WvgA0YziA\",\"https://www.youtube.com/watch?v=L-s_sBxD19w\"]', '2026-04-01 02:00:04.048', '2025-08-05 22:20:25.675', 325, NULL, 1, 2013, 'Desde 2013, o T.T. Burger vem mudando o jogo da gastronomia brasileira. Com cardápio assinado pelo chef Thomas Troisgros, premiado com estrela Michelin e eleito Melhor Chef do Ano (Prêmio Rio Show de Gastronomia 2025), nasceu com um propósito claro: criar o primeiro burger 100% brasileiro. Nada de copiar fórmula gringa. Aqui, a gente mistura, inventa e transforma. Do pão ao molho, do nome às combinações, cada detalhe é um tributo à nossa cultura e à criatividade brasileira. O que começou como uma hamburgueria com alma carioca se tornou o Grupo T.T., um ecossistema que já movimenta mais de 18 toneladas de carne por mês, reúne 300 pessoas entre lojas próprias e franquias e está presente em diversas cidades do país. Depois de recalcular a rota durante a pandemia, os sócios Thomas Troisgros e André Meisler aceleraram a expansão apostando em inovação, eficiência e sabor autêntico. O resultado? R$ 60 milhões faturados em 2024, crescimento de 40% em relação ao ano anterior, e uma ambição ousada pela frente: 200 franquias e R$ 1 bilhão em faturamento nos próximos cinco anos. Hoje, o Grupo T.T. reúne quatro marcas: T.T. Burger, Três Gordos, Marola e Tom Ticken, e segue com o mesmo propósito que inspirou o início de tudo: mostrar que o Brasil tem sabor, história e identidade o suficiente pra liderar o futuro da gastronomia. Mais do que um hambúrguer, o T.T. é um movimento de sabor, brasilidade e ousadia.? E você pode fazer parte dele.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/59f6e725-e9c5-4f99-b3ec-c69acd1d2e3d.png', 18, NULL, NULL, '2026-03-08 20:27:23.642', 'https://franquias.portaldofranchising.com.br/franquia-tt-burger/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '780000', NULL, NULL, NULL, '160000', NULL, '7', '2', '780000', '100000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74un0081eh0sydkbwnqz', 'ODONTO-VIDA', 'odonto-vida', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Franquia de clínicas odontológicas', 1993, 2016, NULL, '2026-04-01 02:00:04.061', '2025-08-05 22:20:25.679', 326, NULL, 1, 1993, '', NULL, 'RIO DE JANEIRO', 1, NULL, NULL, NULL, NULL, '2026-03-08 20:28:20.570', 'https://franquias.portaldofranchising.com.br/franquia-odonto-vida-odontologia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ur0082eh0sjuez3hs3', 'INTIMISSIMI', 'intimissimi', NULL, 'Moda', 'Vestuários', 'Peças simples e elegantes de particular estilo italiano. Moda Íntima: feminina / masculina. Roupas Básicas: feminina / masculina.', 1996, 2015, '[\"https://www.youtube.com/watch?v=3ZcpFTVNzL0\",\"https://www.youtube.com/watch?v=2owOxMXMlIM\",\"https://www.youtube.com/watch?v=McAzCieo22A\"]', '2026-04-01 02:00:04.073', '2025-08-05 22:20:25.683', 327, NULL, 1, 1996, 'Essa história começou em Verona e tomou o mundo todo. É a história do grupo Calzedonia, grupo forte e muito difundido em rede de franquias com mais de 3.800 lojas em 40 países no mundo todo. \nPodemos encontrá-la no coração das maiores cidades do mundo: Milão, Roma, Paris, Londres, Berlim, Moscou, Barcelona, Viena,Praga, Istambul, Dubai, Lisboa, Atenas, Hong Kong, São Paulo. Lançada em 1996, a INTIMISSIMI conquistou homens e mulheres no mercado de peças íntimas, graças as suas peças elegantes e simples de particular estilo italiano. \nCom uma sensação de romantismo e sensualidade você pode inspirar sua imaginação e aproveitar ao máximo seu charme natural e beleza. A Franquia INTIMISSIMI conta hoje com mais de 1.315 lojas em mais de 32 países, incluindo a Itália.', NULL, 'SÃO PAULO', 1, NULL, 72, NULL, NULL, '2026-03-08 20:28:44.845', 'https://franquias.portaldofranchising.com.br/franquia-intimissimi-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '480000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
