INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74vb0086eh0sc0hx85o9', 'FACEPRIME', 'faceprime', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Estética facial avançada manuais e com alta tecnologia', 2019, 2021, NULL, '2026-04-01 02:00:04.121', '2025-08-05 22:20:25.703', 331, NULL, 1, 2019, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a17ef056-036f-425e-b8df-a8ff5328e363.png', 8, NULL, NULL, '2026-03-08 20:30:30.936', 'https://franquias.portaldofranchising.com.br/franquia-faceprime/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '350000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74vg0087eh0soy4ntcx5', 'ACHEI NO PÃO', 'achei-no-pao', NULL, 'Comunicação, Informática e Eletrônicos', 'Comunicação e Mídia', 'A Achei no Pão é uma franquia de publicidade em sacos de pão, com mídia de grande impacto a baixo custo e conceito sustentável. Invista em uma franquia de sucesso com retornos financeiros atraentes.', 2014, 2019, '[\"https://www.youtube.com/watch?v=BpNMYYrOJuo\",\"https://www.youtube.com/watch?v=5YmCHE_aa6g\"]', '2026-04-01 02:00:04.133', '2025-08-05 22:20:25.708', 332, NULL, 1, 2013, 'A franquia Achei no Pão foi criada em São José do Rio Preto pelo casal de empresários Junior Talhaferro e Glaucia Sato. \nEspecializada em publicidade em sacos de pão por meio de microfranquias, a empresa se destaca por sua estratégia de mídia de grande abrangência, com um conceito sustentável e eficiente. \nCom um baixo custo de operação, as embalagens de papel são uma ferramenta de marketing diferenciada e presente no cotidiano dos brasileiros. A Achei no Pão oferece oportunidades únicas de crescimento e desenvolvimento de negócios para nossos franqueados. \nCom sua estratégia de mídia inovadora, a franquia se destaca no mercado publicitário e é uma opção acessível e democrática para quem deseja empreender. \nAlém disso, a franqueadora oferece suporte completo, treinamento e transferência de know-how para garantir o sucesso da unidade. Os franqueados também têm acesso à Universidade de treinamentos em todas as áreas da franquia e ao aplicativo Achei no Pão Ofertas, que une a mídia offline com a mídia online, potencializando os resultados dos anunciantes. \nCom a Achei no Pão, você pode investir em uma franquia de sucesso com retornos financeiros atraentes e uma proposta sustentável e inovadora.', NULL, 'SÃO PAULO', 1, NULL, 54, NULL, NULL, '2026-03-08 20:30:57.431', 'https://franquias.portaldofranchising.com.br/franquia-achei-no-pao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '5700', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74vl0088eh0sc7qrd2od', 'LINK MONITORAMENTO', 'link-monitoramento', NULL, 'Serviços Automotivos', 'SERVIÇOS AUTOMOTIVOS', 'Rastreamento de veículos, Telemetria, logistica, gestao de frotas, bens e objetos, auxiliando clientes a aumentar lucratividade e reduzir seus custos.', 2009, 2010, NULL, '2026-04-01 02:00:04.145', '2025-08-05 22:20:25.713', 333, NULL, 1, 2009, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4bdd8420-519b-400a-9f7e-e5868e74435a.png', 34, NULL, NULL, '2025-11-05 08:39:47.000', 'https://franquias.portaldofranchising.com.br/franquia-link-monitoramento-servicos-automotivos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '334500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74vq0089eh0sbpr2gvq2', 'INSTITUTO BRASILEIRO DE LÍNGUAS', 'instituto-brasileiro-de-linguas', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escola de Idiomas (Inglês, Espanhol, Francês, Italiano, Alemão e Japonês)', 2006, 2009, '[\"https://www.youtube.com/watch?v=T0zSQYimevo\",\"https://www.youtube.com/watch?v=Os7I683CKgs\",\"https://www.youtube.com/watch?v=mFCyd42GpxQ\",\"https://www.youtube.com/watch?v=Z-YzZnVjpDc\"]', '2026-04-01 02:00:04.156', '2025-08-05 22:20:25.718', 334, NULL, 1, 1992, 'O Instituto Brasileiro de Línguas (IBL) é uma franquia especializada no ensino de idiomas, com uma trajetória de sucesso e inovação desde sua fundação em 1992. Utilizando uma metodologia própria, baseada em técnicas neurolinguísticas, o IBL se destaca por oferecer um processo de ensino dinâmico e moderno, focando na comunicação efetiva. Desde 2006, adotou o sistema de franchising, ampliando sua presença e consolidando sua marca. A franquia oferece um amplo portfólio de idiomas, incluindo inglês, espanhol, alemão, francês, italiano e japonês, atendendo a diferentes faixas etárias e necessidades. Com sólida experiência dos fundadores e um modelo de negócio estruturado, o IBL representa um investimento seguro e rentável. Presente em várias regiões do país e na Europa, nosso sistema de franquia é bem estruturado para proporcionar aos franqueados um excelente atendimento e assessoramento. Esta formatação garante à rede um alicerce sólido quanto à implantação, administração e gestão das unidades oferecendo suporte completo aos franqueados, com treinamentos, assistência jurídica, em marketing e gestão. Os cursos do IBL integram a tecnologia ao aprendizado, permitindo aos alunos estudar também online, trazendo flexibilidade e modernidade ao processo educativo com o portal \"Sem Legenda\" atendendo às demandas modernas de educação online e ampliando seu alcance. Além de oferecer aos nossos alunos Certificação Internacional. O Instituto Brasileiro de Línguas (IBL) se diferencia no mercado por sua capacidade de atender a uma ampla gama de públicos, desde crianças até adultos, abrangendo diversas classes sociais. Essa versatilidade permite que a franquia alcance um vasto espectro de alunos, adaptando-se às necessidades e objetivos específicos de cada faixa etária e grupo social. Esse enfoque inclusivo e abrangente é um forte atrativo para franqueados, pois amplia o potencial de mercado e reforça o compromisso do IBL com a educação acessível e de qualidade para todos. O IBL é mais do que uma franquia, é a oportunidade de investir em um negócio seguro e rentável, com suporte completo jurídico, marketing e gestão. Transforme seu sonho de empreender no setor educacional em realidade com o Instituto Brasileiro de Línguas (IBL)! Seja líder no mercado educacional com uma marca consagrada. Descubra como fazer parte desta rede vitoriosa de ensino de idiomas. Acesse agora e dê o primeiro passo para um futuro brilhante com o Instituto Brasileiro de Línguas!', NULL, 'ALAGOAS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c76ed584-4431-466f-912e-d6c3d8fef035.jpg', 16, NULL, NULL, '2026-03-08 20:32:10.473', 'https://franquias.portaldofranchising.com.br/franquia-instituto-brasileiro-de-linguas-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '50000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74vw008aeh0shs2162hx', 'PUSCO', 'pusco', NULL, 'Moda', 'Vestuários', 'Moda feminina Premium.', 2017, 2020, '[\"https://www.youtube.com/watch?v=NQNAiUMk70w\"]', '2026-04-01 02:00:04.167', '2025-08-05 22:20:25.724', 335, NULL, 1, 1989, 'É com grande satisfação que apresentamos a você o sistema de franquias da PUSCO. Ser um franqueado desta marca significa ter em suas mãos um produto Brasileiro, tradicional, inovador e de alta qualidade. A PUSCO implantou o sistema de franquias após um criterioso estudo de mercado e avaliação de viabilidade que propicia ao futuro franqueado uma leitura do investimento que irá fazer e de seu retorno. Criada em 1996, por Rita e Persio, a Marca com mais de 20 anos de tradição, desenvolve desde então produtos para mulheres modernas, que gostam de estar atualizadas com as últimas tendências da moda, e que prezam pelo conforto, qualidade e preço justo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7bebf200-dcb6-4d19-aece-0d49b6a2866e.jpg', 18, NULL, NULL, '2026-03-08 20:33:27.884', 'https://franquias.portaldofranchising.com.br/franquia-pusco-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '520000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
