INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74wa008deh0s8k28m61p', 'BIG BOCA', 'big-boca', NULL, 'Alimentação', 'Bares e Restaurantes', 'PIZZARIA', 2019, 2024, NULL, '2026-04-01 02:00:04.202', '2025-08-05 22:20:25.738', 338, NULL, 1, 2019, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d5d0fe37-425b-47b2-aab7-6542dc2b0a70.svg', NULL, NULL, NULL, '2026-03-08 20:34:35.358', 'https://franquias.portaldofranchising.com.br/franquia-big-boca-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '210000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74we008eeh0sxyrz4eve', 'SPEDINI TRATTORIA EXPRESSA', 'spedini-trattoria-expressa', NULL, 'Alimentação', 'Bares e Restaurantes', 'A Spedini é um negócio no ramo de alimentação que agrega agilidade, variedade facilidade na operação e baixos custos, com a mesma qualidade de uma autentica Trattoria Italiana.', 1994, 1994, '[\"https://www.youtube.com/watch?v=Uq_q3JTs4Xs\"]', '2026-04-01 02:00:04.214', '2025-08-05 22:20:25.743', 339, NULL, 1, 1994, 'Quando a Spedini foi idealizada, o foco foi desenvolver um negócio no ramo de alimentação que agregasse agilidade, variedade, facilidade na operação e baixos custos; importantes características do Fast Food, mas com a mesma qualidade de uma autêntica Trattoria Italiana.\n  Há mais de 25 anos no mercado, a Spedini Trattoria Expressa leva ao consumidor o melhor da culinária Italiana. Nossas receitas são elaboradas com os melhores ingredientes e com o mesmo carinho da comida da “nonna”. Nossos molhos são produzidos diariamente na própria unidade, proporcionando o frescor de nossos pratos e fazendo da sua refeição um momento único, pois adicionados às massas de grano duro ou massas artesanais alcançam a combinação perfeita. \nA empresa detentora da marca e negócio Spedini é formada por profissionais com larga experiência que em 1996, buscando novas oportunidades de negócios, decidiram investir na área de alimentação. \nCom sede própria instalada em Curitiba desde 2002, a Spedini vem investindo constantemente no desenvolvimento e qualificação de seus colaboradores para cada vez melhor atender seus franqueados e stakeholders. \nInserida em um mercado competitivo, a Spedini mantém uma equipe técnica para prestar ampla assessoria aos franqueados, dentro do mais elevado grau de profissionalismo e alinhada com as melhores práticas do mercado.   Diferenciais da Marca:   O cardápio tem um mix diferenciado, com produtos de alta qualidade e preparados na própria loja, mantendo o frescor dos alimentos; Apoio na negociação para aquisição do ponto comercial; Acompanhamento da obra para montagem da unidade; Treinamento do franqueado para gestão do negócio; Apoio na contratação de colaboradores para início da operação; Treinamento pré-operacional dos colaboradores; Manuais e receituários de execução e atendimento; Visitas técnicas realizadas por profissionais com grande conhecimento em padronização de rede e gestão de negócios.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e7383553-ba4d-4066-a361-1c716d7c8e02.jpg', 15, NULL, NULL, '2026-03-08 20:34:58.566', 'https://franquias.portaldofranchising.com.br/franquia-spedini-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74wj008feh0sxyls4e64', 'FICHIPS FOOD', 'fichips-food', NULL, 'Alimentação', 'Bares e Restaurantes', 'Primeira Franquia de culinária Inglesa no Brasil.', 2018, 2020, '[\"https://www.youtube.com/watch?v=MOuh3Zs40ns\",\"https://www.youtube.com/watch?v=IDUdxymQL0k\",\"https://www.youtube.com/watch?v=ibtTdR59wt4\",\"https://www.youtube.com/watch?v=ZfFu1awUkI8\"]', '2026-04-01 02:00:04.228', '2025-08-05 22:20:25.747', 340, NULL, 1, 2013, 'A Fichips nasceu em 2013 quando eu estava desempregado e olhei uma foto minha em Londres e me deu um insight de trazer a iguaria inglesa o “Fish and Chips” para o Brasil, naquela mesma noite, comecei a desenhar o Plano de negócios da Fichips, quando estava prestes a finalizar com os olhos ardendo de sono percebi que já tinha clareado o dia, passei toda a noite desenvolvendo. Procurei diversos locais para comer o “fish and chips” porém só encontrado em PUBS no qual teria que pagar para entrar. Além de trazer essa iguaria o modelo de negócio seria em um foodtruck que na época era uma novidade no Brasil, pois o “boom” dos foodtrucks só viria 2 anos depois em 2015. Iniciei a operação em um mini foodtruck em Dezembro de 2013 na região da Berrini em SP, com um manequim vestido o uniforme de um soldado inglês segurando o cardápio, cujo nome é “Aquiles” (O Nome Aquiles foi dado devido a um ano antes eu ter rompido o tendão de aquiles da perna esquerda e tive algumas complicações na cirurgia no qual fiquei 6 meses sem andar) por isso o nome “Aquiles”, hoje continua presente em todas as nossas unidades espalhadas em todo o território Nacional, segurando o cardápio e trouxemos nele uma versão de auto-atendimento também a nossos franqueados. Em 2014 a Fichips foi considerada entre as 11 empresas que mais inovaram no ramo de alimentação no Brasil, pela revista Pequenas Empresas & Grandes Negócios.\n \n Participamos dos maiores eventos, Lollapalooza, Maximum Festival, Olimpiadas Tocha Olimpica (Olimpiadas no Brasil, Evento da Premier League (Campeonato Ingles de futebol) taça no Brasil, entre outros. Fizemos parceria com a maior industria de batatas do País (Bem Brasil). Em 2018 seguindo o plano de negócios, montamos nossa primeira unidade física, uma Loja shopping no coração de SP, travessa da Av.Paulista, no mesmo ano contratamos um engenheiro de alimentos para iniciar nosso delivery, pois delivery de fritura era um enorme desafio e essa era nossa preocupação entregar um excelente produto via delivery também, deu muito certo, caixinha estratégica juntamente com pacote que dizia THANK YOU com o nome do cliente, pois para nós clientes não são apenas números. E deu muito certo, nossa unidade com apenas 20m2 bombou tanto PDV quanto Delivery que o espaço passou a ficar pequeno para a operação de tanta demanda, pois desta unidade em 2019 iniciamos as vendas das franquias. No mesmo ano 2019 participei do programa Shark Tank no qual João Apolinário e José Carlos Semenzato tiveram interesse na Fichips, posteriormente decidi não seguir com os tubarões pois já estavamos com 23 contratos e unidades nos principais Shoppings no final do ano de 2019. Em 2020 venho a pandemia e criamos um modelo de negócio mais enxuto com parceria com a Industria Germânia, (quiosques Fichips e Germânia), com um maquinario e frita sozinho os alimentos sem fumaça e sem cheiro, fritadeira com sistema de exaustão próprio, crescemos 300% na pandemia, inauguramos quiosques em Shoppings e em redes de mercados Atacadistas. Inclusive temos um showroom do quiosque na fábrica da Germânia em Vinhedo\\SP. Contamos com 60 contratos de franquia no Brasil e 1 em Portugal Contamos com 5 modelos de negócio: LOJA SHOPPING, LOJA RUA\\PUB, LOJA CONTAINER, LOJA QUIOSQUE e MODELO DELIVERY (todas as operações\\modelo possuem Delivery)', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7995e518-688e-44f5-97d8-4fe6e61743e4.jpg', 26, NULL, NULL, '2026-03-08 20:36:05.302', 'https://franquias.portaldofranchising.com.br/franquia-fichips-food/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '109000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
