INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74x7008keh0s1j9l3bnq', 'MICROVENDING', 'microvending', NULL, 'Alimentação', 'Mercados e Distribuição', 'Vending Machines pequenas', 2023, 2023, NULL, '2026-04-01 02:00:04.283', '2025-08-05 22:20:25.772', 345, NULL, 1, 2023, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d2ad20b3-0d6b-4f01-a749-287f07166646.png', 1, NULL, NULL, '2026-03-08 20:45:43.641', 'https://franquias.portaldofranchising.com.br/franquia-microvending/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '27500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74xd008leh0s03laauz6', 'ÓTICAS MERCADÓTICA', 'oticas-mercadotica', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Comércio de produtos ópticos: lentes, armações e óculos solares. Com 30 anos de experiência no setor.', 2012, 2013, '[\"https://www.youtube.com/watch?v=81v8NDREB4Q\"]', '2026-04-01 02:00:04.297', '2025-08-05 22:20:25.777', 346, NULL, 1, 1991, 'A Franquia Mercadótica é um modelo de negócio muito interessante para novos empreendedores, pois permite o uso de uma marca já consolidada, testada e padronizada, diminuindo os riscos e problemas de administração que podem surgir decorrentes de um novo negócio. \nEm poucas palavras: O sucesso será compartilhado pelo franqueado e pelo franqueador.\n  TEMOS TODA A EXPERIÊNCIA QUE VOCÊ PRECISA \nTenha a perspectiva de sucesso de um negócio já experimentado, com marca consagrada no mercado que mais cresce no Brasil. \nCom acesso ao planejamento e pesquisas, orientações e aperfeiçoamentos sob a responsabilidade do franqueador, você estará pronto para abrir a sua loja.\n  +40 lojas, +30 cidades presentes, +8 estados, +150 colaboradores \nBenefícios: 1 - 30 anos de experiência em óptica:  \nIsso mesmo! A Mercadótica existe desde 1991 e já tem toda a experiência do setor óptico bem consolidada. \nConhecemos todas as informações, estratégias, procedimentos e produtos desse setor. \nSem contar que, nesses 30 anos já conquistamos a confiança de milhares de clientes que atestaram a qualidade de nossos produtos, atendimento e marca. \n  2 - Franquia desde 2012: \nA Mercadótica se iniciou no Franchising em 2012, seguindo todo o processo de formatação exigido pela legislação brasileira. \nTemos todo o conhecimento no setor de Franchising que é necessário para guiar você no processo de se converter em um Franqueado. \nAlém  disso, somos parte da ABF (Associação Brasileira de Franchising) e já conquistamos a confiança de nossos Franqueados graças ao sucesso que tiveram com a Mercadótica. \nTodos os nossos Franqueados possuem mais de uma loja.\n  3 - Acesso aos diretores e fundadores da marca:  \nApesar da Franquia Mercadótica contar com uma equipe especializada para a implantação de Franquias, a marca se destaca por ser uma empresa integrada e na qual os diretores participam de forma ativa em todos os processos, incluindo a implantação e supervisão de Franquias. \n  4 - Treinamento e capacitação de equipes de forma constante:  \nDurante a implantação de Franquia acontece o treinamento do Franqueado e de sua equipe de vendas. \nO treinamento aborda todos os assuntos relacionados com o setor óptico, técnicas de vendas, marketing e boas práticas do varejo. \nAlém disso, duas vezes por ano, acontece o Fórum de Franqueados Mercadótica, onde todos os colaboradores da rede participam de forma gratuita e são atualizados sobre diversos assuntos relacionados com o setor óptico. \n  5 -   Laboratório próprio:  \nA Mercadótica possui um laboratório próprio de montagem e surfaçagem. \nDesta forma, não dependemos integralmente de terceiros e mantemos o tempo de entrega ao cliente final dentro de altos padrões de satisfação. \nA maioria de nossas entregas acontecem antes do tempo previsto. Ainda, permite que o controle de qualidade seja feito de forma mais rigorosa e os produtos sejam entregues sem defeitos.\n  6 - Parcerias com laboratório e fornecedores:  \nAlém do laboratório próprio, a Mercadótica também tem parceria com os maiores fornecedores do mercado óptico como a Essilor, Zeiss, Hoya, Ray-Ban, Vogue, Hugo Boss, Colcci, Mormaii. Desta forma, temos acesso a uma diversidade de armações e lentes oftálmicas da mais alta gama do mercado e com condições diferenciadas para os nossos Franqueados. \n  7 - Suporte:  \nA Franquia Mercadótica possui uma equipe altamente capacitada de Suporte ao Franqueado que fica disponível para auxiliar Franqueados e Colaboradores durante as operações diárias. \nAssim como mediar o contato entre lojas e fornecedores, a fim de agilizar procedimentos dentro da rede.', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3762d772-81b7-423c-9394-7e4796862b8b.jpg', 35, NULL, NULL, '2026-03-08 20:46:10.865', 'https://franquias.portaldofranchising.com.br/franquia-oticas-mercadotica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
