INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74xq008neh0swtcjpe6u', 'DORTPREV', 'dortprev', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Medicina Ocupacional, Check-Up Médico e Segurança no Trabalho', 2012, 2020, NULL, '2026-04-01 02:00:04.319', '2025-08-05 22:20:25.790', 348, NULL, 1, 2002, 'O caminho certo para um grande negocio! \nA DortPrev Medicinal Ocupacional e Segurança no Trabalho é exatamente o que você procura para um investimento em franquia. Atuando num segmento que vem se expandindo pela necessidade e obrigatoriedade do mercado. Podendo ainda ser trabalhada com várias alternativas e flexibilização de negócios e serviços. \nSendo ainda mais atrativa por pertencer a um segmento de baixa concorrência. E ainda ser de fácil implantação. \nAlém disso, outros fatores contribuem atrair o empreendedor para a rede de franquias DORTPREV; \n- Serviços especializados prestados por profissionais capacitados e especialmente treinados para atender as necessidades dos clientes;- Padronização das unidades nos projetos arquitetônicos e de comunicação visual, interna e externa de nossa rede; \n- Possibilidade de realizar todos os exames necessários a medicina ocupacional em qualquer uma de nossas unidades; \n- Atenção dedicada à manutenção da qualidade do atendimento prestado pela rede, através de monitoramento ON LINE, via internet dos serviços realizados em nossas unidades; \n- Sistema próprio desenvolvido, totalmente digital que permite a entrega dos resultados pela internet; e parceria estratégica com o maior Laboratório de Exames Clínicos e Laboratoriais do país (Sergio Franco). \nPor todos estas características a Franquia DortPrev é garantia de sucesso. \nA DortPrev, hoje pertencente ao DORTGROUP, começou sua história de sucesso a mais de uma década. Tendo sua primeira criada na Cidade de Duque de Caxias, Rio de Janeiro. \nHoje a DortPrev é referência em todo país no segmento em que atua. Sendo sinônimo de eficiência e competência na área de Medicinal Ocupacional e Segurança no Trabalho. \nAtualmente contamos com 3 unidades de negócio e mais 2 em implantação. São mais de 100 funcionários. \nA DortBusiness, tem a missão de levar ao franquiado DortPrev toda sua experiência em anos de atuação no mercado. Sendo responsável por todo o apoio na aquisição, abertura e operação da sua franquia DortPrev.  \nFale com a DortBusiness \n                                   Faça parte dessa história de sucesso. \n                                                        Juntos vamos ultrapassar suas expectativas.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/472d474e-7c0c-409d-8963-6c000f01f84b.jpg', 7, NULL, NULL, '2026-03-08 20:48:11.453', 'https://franquias.portaldofranchising.com.br/franquia-dortprev/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74y1008peh0s1z8h1jvw', 'LAUNDROMAT', 'laundromat', NULL, 'Limpeza e Conservação', 'Lavanderia', 'Lavanderia Self-Service 100 % automática.', 1987, 2010, '[\"https://www.youtube.com/watch?v=lpo2uyKvUkA\"]', '2026-04-01 02:00:04.330', '2025-08-05 22:20:25.801', 350, NULL, 1, 1987, 'A marca mais inovadora do segmento de Lavanderias. A inovação faz parte do nosso DNA. Fomos os pioneiros do segmento de lavanderias self service na América Latina. Os primeiros a viabilizar lojas-contêineres, ampliando assim as possibilidades de pontos comerciais e proporcionando economia no custo de ocupação. Estamos inovando mais uma vez, com as lojas 100% automatizadas. Um modelo ainda mais simples de gestão, com o melhor modelo do mercado, pois possibilita a ampliação e flexibilidade na configuração da unidade, conforme os objetivos do franqueado. Além da inovação, somos também a marca mais consolidada do setor, com mais de 200 unidades em todo o território nacional e uma experiência e conhecimento do mercado de lavanderias acumulados nos últimos 40 anos.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9f101e76-b0f4-48ce-8c53-a2dfe9b0d1f8.png', 318, NULL, NULL, '2026-03-08 20:49:39.987', 'https://franquias.portaldofranchising.com.br/franquia-laundromat-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '85000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74y6008qeh0s6teb6tnj', 'UNITED INSTITUTE', 'united-institute', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Franquia de escola de inglês para adultos, com muito mais tecnologia e diferenciais como horários de aula flexíveis, material online interativo e equipe comercial para captação de alunos.', 2008, 2012, NULL, '2026-04-01 02:00:04.340', '2025-08-05 22:20:25.807', 351, NULL, 1, 2008, 'Você está em busca em um bom negócio e vê no modelo de franquia uma oportunidade de não começar do zero? Nossa rede de franquias de escola de idiomas United Idiomas tem 10 anos de mercado e os sócios-fundadores já possuem mais de 27 anos de experiência no segmento de idiomas e estão à frente da operação, comprometidos com a rede e seus franqueados. A United Idiomas conta com 26 unidades espalhadas pelo Brasil, sendo 25 franquias e uma unidade própria e está em plena expansão. Possuímos um modelo de negócio consolidado, testado e aprovado por mais de 70 mil alunos que já estudaram na rede. Também temos a chancela da Associação Brasileira de Franquias, a ABF, dando ainda mais credibilidade à marca. É muito fácil ingressar no mercado de idiomas quando falamos de uma rede forte, que é pioneira em tecnologia, e está à frente neste quesito dos principais players do mercado. A United Idiomas se antecipa às tendências tecnológicas, oferecendo recursos interativos, desde aplicativos para os alunos agendarem as aulas pela internet, até visualizar a evolução do curso e ter acesso aos módulos online de acompanhamento das aulas presenciais. E o resultado para seu investimento é rápido! Mas claro, depende da sua dedicação como franqueado. O melhor é que temos uma equipe de suporte pronta para te ajudar desde a escolha do ponto ideal, implantação da sua unidade e acompanhamento no dia a dia buscando sempre os melhores resultados.  Temos uma equipe comercial que faz a captação de alunos para sua unidade! \nVocê também pensou que além do negócio mudar sua via, pode mudar a vida de outras pessoas? Ter uma franquia com propósito é fundamental! Oferecemos cursos para adultos que querem se desenvolver profissionalmente e que para crescer na carreira precisam do idioma. Nossos alunos também querem aproveitar novas oportunidades culturais, viagens, conteúdos em inglês para desenvolvimento de teses de especialização, por exemplo, ou acompanhar as principais inovações e tendências mundiais, e muitos conteúdos em diversas áreas profissionais são disponibilizados apenas em inglês. E nós participamos da vida dos alunos através deste crescimento por meio do idioma, oferecendo um método de aprendizagem rápido e dinâmico, perfeito para o dia a dia do público adulto que precisa falar fluentemente, em menos tempo que os métodos tradicionais.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c6eb065e-92cd-4f6d-835d-394755b3b7b8.jpg', 20, NULL, NULL, '2026-03-08 20:50:18.015', 'https://franquias.portaldofranchising.com.br/franquia-united-institute-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '45000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
