INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ym008teh0s68mnc7if', 'CAFÉ DU CENTRE', 'cafe-du-centre', NULL, 'Alimentação', 'Bares e Restaurantes', 'Cafeteria e doceria', 2015, 2018, '[\"https://www.youtube.com/watch?v=BxWnhghjvs0\",\"https://www.youtube.com/watch?v=5jhqgO3CIpg\",\"https://www.youtube.com/watch?v=qgp_N8uCfN4\",\"https://www.youtube.com/watch?v=VnZ216uOPmk\"]', '2026-04-01 02:00:04.360', '2025-08-05 22:20:25.823', 354, NULL, 1, 2014, 'Somos duas irmãs, Paula Fotógrafa e Administradora e Bruna, Psicóloga. Nossa história começa assim: Costumávamos nos finais de tarde nos sentar em alguma cafeteria para conversar sobre o nosso dia. Com isso aprendemos a tomar e apreciar um bom café!  \nComo não se apaixonar por essa bebida tão grave, quente e peculiar?  \nAssim nossos encontros casuais passaram -se a tornar um hábito diário. Por nossa cidade apresentar um déficit de um bom lugar para tal, tínhamos que nos deslocar para cidades vizinhas. \nEra final de mais uma temporada de verão, e disponibilizávamos de um pequeno espaço comercial, e porque não uma cafeteria? As dúvidas eram muitas. A vontade de empreender e à uma possível perda das nossas ocupações profissionais. \nDevido as nossas profissões não teríamos disponibilidade para se dedicar integralmente a ao novo negócio, e o desafio de trazer uma proposta diferenciada para uma cidade de pouco mais de 50.000 habitantes. \nNossa proposta era o diferente, o clássico, a excelência e um novo conceito de cafeteria no Brasil.  \nHoje o Café du Centre é referência de qualidade, luxo e sofisticação, trata-se de um ambiente único, com características próprias, receitas exclusivas, arte na apresentação dos produtos com padrão Europeu. Com lojas no Brasil e no exterior. \nNossos Clientes desfrutam de uma decoração inspirada na charmosa Paris {França} e também uma trilha sonora francesa. \nHoje conseguimos manter nossas profissões e a cafeteria, estamos realizadas, encantadas, pois essa bebida tão especial: o café, tornou-se arte e protagonista do nosso pequeno e aconchegante espaço.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c8015bf5-bd02-4dbf-bac0-a6b2575fa1ef.jpg', 13, NULL, NULL, '2026-03-08 20:52:12.842', 'https://franquias.portaldofranchising.com.br/franquia-cafe-du-centre/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74yr008ueh0shq07ndrw', 'LEVE', 'leve', NULL, 'Moda', 'VESTUÁRIO', 'Comércio de confecções, calçados, cama, mesa, banho e decorações.', 2005, 2020, NULL, '2026-04-01 02:00:04.370', '2025-08-05 22:20:25.827', 355, NULL, 1, 2005, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e03bd4fe-f75c-46e4-a89b-4156ac600fc9.png', 31, NULL, NULL, '2025-11-05 08:33:12.000', 'https://franquias.portaldofranchising.com.br/franquia-leve-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '200000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74yx008veh0s9wvwhrs3', 'EMIVE FRANCHISING', 'emive-franchising', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Empresa especializada em segurança eletrônica, com certificação comprovada nos mais altos padrões de excelência internacional, ISO 9001 e selo ABESE.', 2020, 2020, NULL, '2026-04-01 02:00:04.380', '2025-08-05 22:20:25.833', 356, NULL, 1, 2019, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b420d2c4-7fa0-4ab8-8d0a-982e267f3855.png', 945, NULL, NULL, '2026-02-11 19:46:50.000', 'https://franquias.portaldofranchising.com.br/franquia-emive-franchising/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '25000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74z2008weh0ssqx45rgp', 'FERROVIA', 'ferrovia', NULL, 'Moda', 'Acessórios Pessoais', 'ÓCULOS SOLAR', 2005, 2009, NULL, '2026-04-01 02:00:04.391', '2025-08-05 22:20:25.838', 357, NULL, 1, 1987, '', NULL, 'CEARÁ', 1, NULL, NULL, NULL, NULL, '2026-03-08 20:53:50.455', 'https://franquias.portaldofranchising.com.br/franquia-ferrovia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74z7008xeh0stweem321', 'FIRST CLASS', 'first-class', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Cama, Mesa, Banho e Sonhos.', 2008, 2010, NULL, '2026-04-01 02:00:04.402', '2025-08-05 22:20:25.843', 358, NULL, 1, 2000, 'A First Class já é a 2ª maior empresa de cama mesa e banho do país. \nA First Class nasceu da união e vocação empresarial de seus dois sócios, André Pivetti e Orlando Pedro.\nAmbos com história de vidas bem distintas, mas que resultou em uma parceria de sucesso. \nCom 14 anos no mercado CAMEBA - cama, mesa e banho, a carioca First Class® possui hoje um market share de 155* operações disseminadas pelo Brasil, presente em 20 estados e 62 cidades e uma internacionalização da marca, em Luanda-Angola. \nA parceria resultou em novas lojas, mas o sucesso de fato só se concretizou depois de alguns anos de muito trabalho e adaptações as exigências do mercado. As oscilações econômicas do país e as dificuldades de dar uniformidade à rede e de contrabalançar os custos foram o maior desafio. Várias mudanças foram feitas para impulsionar os negócios até formar um grupo financeiramente equilibrado e comercialmente lucrativo. \nCom isso, a sociedade que até então comportava a mesma supra mencionada, em 2014, com a saída do sócio Orlando Ferreira, integra-se a sociedade junto ao André Pivetti, a figura atual do seu novo sócio, Sérgio Lombardi, cuja experiência têxtil é de aproximadamente 20 anos administrando a fábrica da Bouton, com sede em Brusque – SC, licenciada e exclusiva da marca Buettner do segmento cama, banho e importados e vem a somar e muito nessa nova empreitada.   Antes somente com um olhar fabril, agora alinha essa estratégia comercial com os pontos de venda, formando uma parceria estratégica de sucesso. \nQualidade, inovação, democratização, preço e atendimento são os nossos diferenciais e certamente o que garante a posição de destaque entre as melhores do segmento. \nAlém de produtos das principais indústrias de marcas nacionais, cada vez mais a First Class investe na fabricação própria e na importação de produtos exclusivos. \nConsiderando perspectivas de expansão para 2014  O sucesso da marca tem sido reconhecido em diversas pesquisas de varejo com renome nacional:  Em 2010 associou-se a ABF – Associação Brasileira de Franchising; \nEm 2012 e 2013 foi reconhecida por adotar as melhores práticas de gestão no varejo de franquia. \nEm 2012 e 2013 foi eleita, pelo voto do consumidor, a melhor loja de Cama Mesa e banho do Brasil.  Em 2012 e 2013 Participou pelo 3° ano da pesquisa feita pela PEGN – Pequenas Empresas e Grandes Negócios, obtendo destaque de maior nota de satisfação de franqueado comparado a diversas marcas de renome no varejo nacional.  Em 2013 e 2014 Participou pelo 4° ano da pesquisa feita pela  PEGN – Pequenas Empresas e Grandes Negócios, sendo elegida a 1ª no ranking Casa, Decoração e Presente e mais uma vez foi destaque de maior nota de satisfação de franqueado comparado a diversas marcas de renome no varejo nacional.  Missão\nEncantar o cliente, fazendo por ele mais do que ele espera. Democratizar o consumo, trazendo sempre os melhores produtos pelos menores preços. Permitir a todas as classes o acesso aos seus sonhos de qualidade dos produtos de cama, mesa e banho.  Visão\nTornar-se a melhor e maior empresa de cama, mesa e banho, sendo reconhecida por vender produtos de qualidade pelos menores preços do Brasil.  Público Alvo\nClasse: A, B e C\nDemocratização de consumo. Permitindo a todas as classes o acesso a produtos de qualidade e preço.\n90% Feminino / 10% Masculino     “Sonhos...\nTransformam vidas. Criam mundos. Acredite nos seus sonhos.\nAlimente-se deles. Sonhos criaram nossa história.\nTransformaram nossa vida. “Com fé e força sonhos se realizam.”\nFirst Class.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7512f6ea-a93d-4a33-8325-3120c192b5d6.svg', 230, NULL, NULL, '2026-03-08 20:54:13.455', 'https://franquias.portaldofranchising.com.br/franquia-first-class-artigos-para-o-lar/', NULL, NULL, '[]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '280000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74zc008yeh0s2jzjrisy', 'MR CHEFF GASTRONOMIA', 'mr-cheff-gastronomia', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fast Food, com excelência em pratos executivos e porções', 2018, 2020, '[\"https://www.youtube.com/watch?v=JIu1_i9oe5c\"]', '2026-04-01 02:00:04.413', '2025-08-05 22:20:25.849', 359, NULL, 1, 2011, 'O MR. CHEFF GASTRONOMIA é uma marca com cardápio variado que oferece as mais diversas opções de pratos executivos, massas e porções que são produzidas uma a uma diariamente, com cuidado e dedicação em suas receitas. Nascemos devido a falta que o fundador sentiu à época de ter no mercado opções de pratos que ofereciam qualidade e quantidade por um custo acessível que atendesse a todos. \nDesse modo, o objetivo da empresa sempre foi prestar um excelente serviço que oferecesse uma memorável experiência gastronômica a todas as classes sociais, prezando acima de tudo a satisfação de seus consumidores e diante do cenário promissor da empresa, em 2017 iniciamos o plano de expansão da marca e hoje marcamos presença em 3 estados (São Paulo, Paraná e Santa Catariana).', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/aff3a319-ff6e-426b-bcf1-478a541b89e3.jpg', 19, NULL, NULL, '2026-03-08 20:55:55.253', 'https://franquias.portaldofranchising.com.br/franquia-mr-cheff-gastronomia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74zi008zeh0sbcat5uj9', 'SAT SOLAR', 'sat-solar', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'VENDA, INSTALACAO, MANUTENCAO DE SISTEMAS SOLARES FOTOVOLTAICOS E CARREGADORES VEICULARES PARA EMPRESA , RESIDENCIAS E AGRONEGOCIOS', 2022, 2023, NULL, '2026-04-01 02:00:04.424', '2025-08-05 22:20:25.854', 360, NULL, 1, 1998, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e6cd9d5c-1165-443b-b2d4-21c51fcdc0aa.png', 1, NULL, NULL, '2025-09-29 09:17:36.000', 'https://franquias.portaldofranchising.com.br/franquia-sat-solar-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74zo0090eh0s7jsu98ga', 'BRCONDOS', 'brcondos', NULL, 'Casa e Construção', 'Serviços e Imobiliárias', 'Administração de condomínios, cobrança extrajudicial, segurança eletrônica, automação predial, seguros.', 2013, 2019, '[\"https://www.youtube.com/watch?v=SLArrkUFobE\"]', '2026-04-01 02:00:04.436', '2025-08-05 22:20:25.860', 361, NULL, 1, 2013, 'A BRCondos Franchising é uma empresa brasileira especializada na administração de condomínios, oferecendo soluções inovadoras e tecnológicas para a gestão condominial. Fundada em 2013, a empresa tem como missão tornar a vida em condomínios mais transparente, segura e eficiente, posicionando-se sempre à frente do seu tempo com qualidade e tecnologia. Histórico e Expansão Desde sua fundação, a BRCondos tem se destacado no mercado condominial brasileiro. Com sede em Joinville, Santa Catarina, a empresa expandiu sua atuação para mais de 150 cidades no Brasil, consolidando-se como a maior rede de administradoras de condomínios do país. Modelo de Negócio A BRCondos opera por meio de um modelo de franquias, permitindo que empreendedores locais se tornem franqueados e ofereçam os serviços da marca em suas regiões. Esse modelo de negócio é sustentado por inovação, integrando central, franqueados, síndicos e condôminos, com foco em gerar resultados enquanto a operação é realizada pela central. Serviços Oferecidos A BRCondos oferece uma ampla gama de serviços para a administração de condomínios, incluindo: Administração Financeira: Gestão de contas a pagar e a receber, prestação de contas transparente com lançamentos diários e acesso a todos os boletos e comprovantes. Central de Relacionamento: Atendimento aos condôminos via telefone ou web, resolução de questões fiscais e tributárias, e disponibilização de informações de forma transparente através do BRCondosOnline. Serviços de Cobrança: Gestão profissional e eficaz na redução da inadimplência condominial, incluindo conta individual automatizada, previsão fixa para mais segurança orçamentária e setor exclusivo para negociação extrajudicial de inadimplentes. BRCondos Online: Sistema e aplicativo que integra o condomínio, facilitando a comunicação entre condôminos, síndico e administradora, com funcionalidades como abertura de chamados, registro de ocorrências, enquetes, comunicados e acesso a documentos e contratos. Calendário de Eventos & Reservas: Controle eficiente das reservas de áreas comuns via sistema, com visualização de calendário, estipulação de valores para aluguel e bloqueio de acesso para condôminos inadimplentes. BRCondos Automação: Soluções para identificação de pessoas por reconhecimento facial, biometria, chaveiros de proximidade ou QR-Code, acessos de veículos registrados por adesivos veiculares ou controles remotos, segurança no recebimento de visitantes e prestadores de serviço, e monitoramento completo do condomínio através de gestão em tempo real das informações do controle de acesso. Departamento Pessoal: Serviço especializado de Recursos Humanos para contratação, controle e relatórios, admissão e registro, processamento de ponto, processamento de folha, gestão de benefícios, recolhimento de impostos e encargos sociais, controle e emissão de férias, rescisão e outros, gerenciando o quadro de funcionários da unidade e dos condomínios da rede de forma profissional.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3b83c8e3-a336-4400-83fc-7a9f157e24dc.png', 85, NULL, NULL, '2026-03-08 20:56:46.451', 'https://franquias.portaldofranchising.com.br/franquia-brcondos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74zt0091eh0sl9oxxub2', 'BR MULTAS SOLUÇÕES EM TRÂNSITO', 'br-multas-solucoes-em-transito', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Prestação de serviços, relativos a Recurso de Infrações de Trânsito e de Processos em Carteira Nacional de Habilitação (CNH), onde a franqueadora fica com toda burocracia junto aos órgãos de trânsito.', 2021, 2022, NULL, '2026-04-01 02:00:04.446', '2025-08-05 22:20:25.866', 362, NULL, 1, 2018, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/af7b221f-b8ec-4a96-a1cb-33506d6af2b6.png', 16, NULL, NULL, '2025-11-04 06:55:21.000', 'https://franquias.portaldofranchising.com.br/franquia-br-multas-solucoes-em-transito/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '52000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74zz0092eh0swi0rvfrk', 'AÇAÍ BEAT', 'acai-beat', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Especializado em creme de açai com acompanhamentos', 2011, 2013, '[\"https://www.youtube.com/watch?v=tu-8doxItVM\",\"https://www.youtube.com/watch?v=oZAipflOG4M\",\"https://www.youtube.com/watch?v=BWfhmUYpRUg\"]', '2026-04-01 02:00:04.457', '2025-08-05 22:20:25.871', 363, NULL, 1, 2011, 'A Marca O mercado de açaí vem crescendo no Brasil e no mundo, e a rede de Franquia Açaí Beat acompanha esta tendência graças à qualidade de seus produtos, somada a um projeto arquitetônico prático e inovador de suas unidades e a uma comunicação interativa com o seu público. Uma marca diferenciada, antenada ao seu público, que foge da mesmice e cai no gosto das pessoas. Traz o que é bom, saudável, gostoso e o melhor “do seu jeito”. Esse é o Açaí Beat, a franquia mais gostosa de açaí do mundo! A História Após morar alguns anos na Europa, trabalhar nos melhores restaurantes da Espanha e se pós-graduar em Gestão de Alimentos y Bebidas pela Escuela de Hosteleria y Turismo de Valencia, o empresário Júnior Marques volta ao Brasil com a mente aberta e disposto a encontrar nos alimentos um ramo próspero e lucrativo. Quando conheceu o açaí, um creme muito encontrado já em todas as cidades brasileiras mas pouco explorado de forma profissional viu uma oportunidade e após muitas pesquisas criou a marca Açaí Beat. A empresa teve início de suas atividades em julho do ano de 2009 com uma loja na cidade de Viçosa - MG e um ano depois a aquisição da fábrica de creme de açaí (2010) foi o pontapé inicial para a formatação da franquia. Em 2011 com um pequeno quiosque na cidade de Ipatinga - MG deu-se a abertura de sua segunda unidade e a partir de então não parou mais de crescer. Ao final de 2013, com apenas 2 anos de existência, a rede Açaí Beat tinha 18 unidades abertas em 5 estados diferentes. Atualmente a rede engloba 01 fábrica, 02 unidades próprias e 37 franqueadas, está presente em 31 cidades em 09 estados brasileiros, incluindo a região nordeste e centro-oeste. Em 2016, a meta é finalizar o ano com 70 unidades em operação. O produto Com a formação em gastronomia, a experiência internacional adquirida junto a Ferran Adri (um dos chefs mais prestigiados do mundo) e a exigência do paladar, Júnior liderou o processo de desenvolvimento de um creme de açaí de sabor incomparável, leve e que mantém as propriedades naturais da fruta cultivada no Pará. Ele explica que o creme do Açaí Beat pode ser consumido puro ou com adicionais da melhor qualidade, já que a rede busca sempre as melhores marcas e fornecedores para esses opcionais. “Com essa mistura de produtos de sucesso, o cliente sempre sairá satisfeito!” - Júnior Marques Recentemente foi lançado os smoothies Açaí Beat. São três opções de smoothies, que consistem em açaí batido com frutas e sucos, aumentando assim a gama de produtos da rede.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/24f35963-7a11-4099-bb8c-5b10e3525a5a.jpg', 31, NULL, NULL, '2025-09-09 09:51:06.000', 'https://franquias.portaldofranchising.com.br/franquia-acai-beat-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75040093eh0s2c86q2gn', 'RISE MARTIAL ARTS CLUB', 'rise-martial-arts-club', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Escola de artes marciais para todas as idades. Fundada em fev/2018 a RISE CLUB possui + 3.000 alunos e seis unidades, têm como propósito cuidar da saúde física, emocional e social de nossos alunos', 2023, 2023, '[\"https://www.youtube.com/watch?v=yBFgx-SAC1I\",\"https://www.youtube.com/watch?v=dpD0WfHywnI\",\"https://www.youtube.com/watch?v=K1cYmNKi4NE\",\"https://www.youtube.com/watch?v=zxjDpPtDnvQ\"]', '2026-04-01 02:00:04.467', '2025-08-05 22:20:25.877', 364, NULL, 1, 2018, 'A Rise Club foi fundada em fevereiro 2018 por dois amigos que se conheceram no tatame e depois de duas décadas tendo a arte marcial como uma comunidade perceberam que mesmo atuando em outras áreas profissionais ao longo de suas vidas, sempre estiveram o tatame como um lugar de pertencimento. Quando se formaram faixas pretas observando o crescimento do público que procuravam arte marcial como qualidade de vida, vendo as academia com pouca estrutura e dificuldade de gestão, enxergaram uma oportunidade de trazer um novo conceito de artes marciais para todas as idades de 3 a 80 anos e NÃO com foco em competição. Hugo Veras com +30 anos engenharia com a PSA é responsável pelo estudo de viabilidade estrutural, implantação e manutenção das unidades. Carlos Ferraz foi sócio por + 8 anos de um grupo educacional que montou +50 escolas no Brasil sendo responsável pela gestão, expansão e trouxe o conceito de governança para Rise. Fechando o conselho temos hoje Tomaz Alcoforado responsável pelo corpo jurídico e advisor com a SRAB Advogados. Além disso, a Rise conta hoje com escritório da V4 Company na sua estrutura de growth marketing Atualmente com 4 unidades próprias, sendo 1 já com modelo franquias + 2.000 alunos ativos a Rise iniciou seu processo expansão iniciando processo seletivo para franquias. Primeiro semestre 2025 será inaugurada a 5 unidade, também no modelo franquia. Com taxa de lucratividade até 40% , breakeven 6 meses e payback entre 24 a 36 meses a Rise se apresenta como uma excelente oportunidade negócio, oferecendo um mercado promissor saúde, negócio sólido e escalável com carteira de recebíveis e uma holding que faz toda gestão e estrutura da unidade', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e1627fdf-bb0a-478e-9eb0-0cb6684bcd46.png', 6, NULL, NULL, '2026-03-08 20:58:40.910', 'https://franquias.portaldofranchising.com.br/franquia-rise-martial-arts-club/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza750a0094eh0snd2g8tv7', 'VERSOLABS', 'versolabs', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Franquia de Posto de Coleta laboratorial para análises clínicas.', 2022, 2023, NULL, '2026-04-01 02:00:04.477', '2025-08-05 22:20:25.883', 365, NULL, 1, 2022, 'Somos uma franquia de coleta laboratorial, fazemos todos os tipos de exames de análises clínicas, com apoio e logística para todo o Brasil.  \nNossa missão é ser a melhor opção para quem não tem plano de saúde e necessite de serviços com qualidade, rapidez e valores acessíveis.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2509ff4a-93f7-4a29-b2b3-d69dc1ef12b2.jpg', 3, NULL, NULL, '2026-03-08 20:59:36.521', 'https://franquias.portaldofranchising.com.br/franquia-versolabs/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza750g0095eh0s9hl4kv2l', 'ROSA MAKE', 'rosa-make', NULL, 'Saúde, Beleza e Bem Estar', 'COSMÉTICOS E PERFUMARIA', 'Loja especializada em maquiagem.', 2022, 2022, '[\"https://www.youtube.com/watch?v=rpsK2tLtPsY\",\"https://www.youtube.com/watch?v=knNXb_eyRqQ\"]', '2026-04-01 02:00:04.489', '2025-08-05 22:20:25.888', 366, NULL, 1, 2019, 'Franquia multimarcas de maquiagem acessíveis, mais de 50 marcas. Alta lucratividade, baixo investimento, modelos validados, mix de produtos com mais de 50 marcas nacionais e internacional e o setor da beleza e cosméticos é um dos que mais crescem no Brasil! Focando em crescer, expandir e fortalecer a marca e principalmente aumentar a rentabilidade para os franqueados, os Royalties são fixos de 1 salário mínimo mensal e sem taxa de marketing. PORQUE ESCOLHER A ROSA MAKE? Royalties fixo de 1 salário mínimo; Sem taxa de marketing; Franquia associada a ABF; Produtos exclusivos da marca; Alta rentabilidade; Modelo de negócio validado; Parceria Rosa Make com Santander: Financiamento de até 50% do investimento total e carência de 7 meses (direto com banco); 3 Modelos de negócios; + de 50 marcas nacionais e internacionais; A Rosa Make conta com 3 opções de operações, Quiosque, Loja de Rua (Slim e Luxo) e Loja em Shopping (Slim e Luxo). A Rosa Make tem no seu diferencial o atendimento, qualidade e a variedade do seu mix de produtos de diversas marcas tais como, Mari Maria, Bruna Tavares, Boca Rosa, Ruby Rose, Melu, Dalla, Vizella, Ruby Kisses, Playboy, Dapop, Fran, Max Love, Jasmyne, Dermachem, Griffty, Fenzza, Vivai, Adversa, Miss Lary, Miamake, Pink21, Lua&Neve e muito mais e AGORA TAMBÉM PRODUTOS EXCLUSIVOS DA MARCA ROSA MAKE! Venha crescer com a gente! Saiba mais!', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/301287e2-7b76-4f6c-ad16-a916d29aac44.jpg', 25, NULL, NULL, '2025-09-24 14:21:28.000', 'https://franquias.portaldofranchising.com.br/franquia-rosa-make/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
