INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza750v0098eh0sg5648k42', 'IMAGINARIUM', 'imaginarium', NULL, 'Casa e Construção', 'Móveis e Decoração', 'ARTIGOS PARA PRESENTES E DECORAÇÃO', 1990, 1993, '[\"https://www.youtube.com/watch?v=O6Vf5uWtbXY\",\"https://www.youtube.com/watch?v=ckXCETxHZSc\",\"https://www.youtube.com/watch?v=hGiA6A4Y5iA\",\"https://www.youtube.com/watch?v=0Aemu7--Ffg\",\"https://www.youtube.com/watch?v=Na1CB__ZlbQ\"]', '2026-04-01 02:00:04.523', '2025-08-05 22:20:25.903', 369, NULL, 1, 1987, 'Transformar todo dia pra melhor: essa é a missão da Imaginarium, empresa brasileira criada em 1991.   Tudo começou na década de oitenta, quando uma arquiteta e um médico decidiram que passariam mais tempo com as duas filhas pequenas, acompanhando de perto seu crescimento: a qualidade de vida da família era prioridade. O casal começou a trabalhar em casa, produzindo artesanalmente enfeites de Natal, que eram vendidos na vizinhança. A demanda foi tão grande que a produção teve que se profissionalizar e, em pouco tempo, os produtos já estavam sendo comercializados em grandes lojas de departamento. Sempre em busca de bem-estar e qualidade de vida, a família se mudou para Florianópolis em 1991, quando nasceu a marca Imaginarium. No início, os produtos tinham muita madeira, itens de cozinha, com temáticas voltadas para o aconchego, sugerindo experiências para serem compartilhadas em família, entre amigos ou para a simples celebração da existência. Inovação é a palavra-chave dos produtos da marca, que busca sempre surpreender seus clientes com criações exclusivas e muito bom humor, e que é referência em presentes criativos e inovadores no mercado. Atualmente, a rede conta com 220 lojas exclusivas, mais de 600 pontos de lojas licenciadas, e-commerce, marketplace, um escritório na cidade de São Paulo e um escritório internacional.  A marca faz parte do GrupoUni.Co, detentor das marcas Imaginarium, Puket, Mind e Love Brands.   UMA DAS MAIORES MARCAS DE PRESENTES E DECORAÇÃO DO BRASIL Hoje, a franquia Imaginarium é reconhecida no mercado brasileiro como uma das maiores marcas de presentes criativos e inovadores, além de ser reconhecida nacional e internacionalmente por antecipar conceitos e tendências em eletrônicos, utilitários e presentes. As características fundamentais dessa trajetória são a inovação e o desejo de transformar as rotinas dos seus clientes: por ano, estima-se que a marca lance mais de 400 novos itens. A franquia Imaginarium é uma das poucas marcas franqueadoras detentora de 20 Selos de “Excelência em Franchising”.  O selo é concedido pela ABF (Associação Brasileira de Franchising), mediante uma rigorosa pesquisa realizada com os franqueados da rede. Além disso, a marca franqueadora também possui 11 Prêmios de Franquia 5 Estrelas PEGN (Pequenas Empresas, grandes Negócios) e 3 Prêmios Lojista Alshop.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c045f5b1-adab-4d6f-8ca2-2b1527cf207a.jpg', 75, NULL, NULL, '2026-03-08 21:01:06.495', 'https://franquias.portaldofranchising.com.br/franquia-imaginarium-decoracao-e-presentes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '95000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
