INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza751u009feh0sz7ccblem', 'ANA TERRA SEGUROS', 'ana-terra-seguros', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Corretora de Seguros', 2016, 2017, NULL, '2026-04-01 02:00:04.594', '2025-08-05 22:20:25.938', 376, NULL, 1, 1994, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6ddba78c-9d4d-48d2-bed9-82532438ec21.png', 50, NULL, NULL, '2025-09-09 13:02:18.000', 'https://franquias.portaldofranchising.com.br/franquia-ana-terra-seguros-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza751z009geh0sskmdn8q5', 'ON BYTE', 'on-byte', NULL, 'Educação', 'EDUCAÇÃO', 'Cursos profissionalizantes, idiomas e informática. Atendemos todos os públicos dos 7 anos a melhor idade.', 2009, 2009, '[\"https://www.youtube.com/watch?v=hXomlc5_0xk\",\"https://www.youtube.com/watch?v=yS8KWUTRISE\",\"https://www.youtube.com/watch?v=ofiZHE_3mGk\",\"https://www.youtube.com/watch?v=zg6i4Ag5EO0\"]', '2026-04-01 02:00:04.604', '2025-08-05 22:20:25.943', 377, NULL, 1, 2002, 'Quem somos. A ON BYTE® é uma rede de franquias que se ativa no segmento de educação e treinamento. Por meio do moderno método de ensino interativo audiovisual por ela desenvolvido, oferece cursos profissionalizantes e de informática. Seu modelo de ensino foca no aprendizado e preparação do aluno para o mercado de trabalho. São utilizados programas de computador (software de ensino interativo On Byte) e apostilas de apoio, os quais contêm exemplos práticos e reais, condizentes com o dia a dia das empresas. As apostilas adotam o sistema passo a passo, de modo a facilitar a absorção do conteúdo. Assim, ao final do curso o estudante sai preparado para ingressar no mercado de trabalho. Os cursos ON BYTE® são um grande diferencial na busca por emprego. A empresa conta hoje com os melhores cursos do mercado, os quais estão em constante aprimoramento e evolução. Anualmente são investidas grandes somas no desenvolvimento de novos cursos, os quais acompanham o progresso dos programas de computador e as necessidades do mercado. Também possui plataforma para ensino de inglês com aulas individualizadas, seguindo o mesmo método (software de ensino e apoio de apostilas). Por meio do sistema de ensino ON BYTE® o aluno aprende de verdade, como se estivesse de fato em um ambiente de trabalho. Não são utilizadas apenas simulações; depois destas, o aluno pratica os exemplos das apostilas no computador. É a união da praticidade do ensino interativo com apostilas de alta qualidade e excelente conteúdo, que satisfaz às exigências do mercado. Por outro lado, a ON BYTE® é uma franqueadora que oferece magníficas oportunidades para empresários e pessoas com perfil empreendedor. Adquirindo uma franquia On Byte, será disponibilizado ao franqueado todo o know how desse empreendimento de sucesso, com suporte contínuo desde os procedimentos que precedem a inauguração até a captação constante de alunos e sua manutenção. Enfim, é fornecido todo o auxílio necessário para a montagem da nova empresa que, por fazer parte de uma rede, sai na frente e começa a caminhar bem desde a inauguração. Além disso, será também concedida a autorização para a utilização da marca registrada ON BYTE®, sólida e notoriamente reconhecida pelos consumidores como fornecedora de cursos de excelência. Venha fazer parte da rede de franquias de treinamento e educação mais promissora do país. Missão. A ON BYTE® tem como objetivo criar cursos voltados ao mercado de trabalho, buscando sempre novas tecnologias e produtos para que seus franqueados estejam à frente dos concorrentes. Ao mesmo tempo, busca qualificar e preparar as pessoas para atuarem de maneira competitiva no mercado globalizado e exigente, tudo por meio de um sistema de ensino inovador. Visão. Ser conhecida pela qualidade de seus produtos e serviços, tornando-se a melhor rede de cursos profissionalizantes livres do país. Valores. Ética, seriedade, comprometimento e qualidade. Imagem da empresa no mercado de atuação. - É reconhecida como a empresa que melhor atende e prospecta seus clientes; - Possui uma das maiores grades de cursos; - Alta qualidade dos produtos e serviços; - Apostilas de excelência, aliadas ao conteúdo que o mercado demanda. Um pouco da história. Em 1992 foi fundada a Prodata Informática, na cidade de Taquaritinga/SP, empresa que atuava no ramo de cursos de informática e venda de computadores. Ao longo dos anos ela conseguiu nome forte e respeito na cidade, onde sempre foi a escola com o maior número de alunos. Em agosto de 2002 iniciou-se o desenvolvimento de um sistema de ensino interativo audiovisual, que inicialmente seria utilizado apenas na própria empresa. Com a rápida evolução deste, em julho de 2004 ele começou a ser licenciado para outras escolas de informática, com valores bem mais acessíveis do que os então existentes. A empresa registrou no INPI a marca ON BYTE® e com o tempo adquiriu know-how e muita experiência. Em meados de 2009, devido ao grande sucesso do método, possuía mais de 350 unidades licenciadas em todo o Brasil; o método conseguiu respeito e credibilidade, tendo consolidado-se como um dos melhores sistemas de ensino do país. A partir daí, foram iniciados os procedimentos para que a ON BYTE® se tornasse uma franquia. Hoje, ela consolidou-se como uma das mais respeitadas marcas do segmento de educação e treinamento, com uma infinidade de unidades franqueadas. Mantém-se em exponencial expansão.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ba7b7ad7-3abe-4c44-8d14-8dfc20432064.jpg', 26, NULL, NULL, '2025-04-09 10:51:10.000', 'https://franquias.portaldofranchising.com.br/franquia-on-byte-educacao-e-treinamento/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a8086a18-9249-44a9-8007-38f63f153dc4.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
