INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza752k009ieh0se55w00fz', 'PARMÊ', 'parme', NULL, 'Alimentação', 'Bares e Restaurantes', 'Especializada em Pizzas e Massas de qualidade, servindo grelhados e complementos. Foco no Rio de Janeiro.', 2007, 2007, '[\"https://www.youtube.com/watch?v=39g4q-DtW38\",\"https://www.youtube.com/watch?v=0QU6hO9OS08\"]', '2026-04-01 02:00:04.623', '2025-08-05 22:20:25.964', 379, NULL, 1, 1972, 'Há mais de 40 anos a Parmê mostra compromisso com a qualidade e excelência de seus produtos e serviços. A rede de restaurantes, pizzarias e lanchonetes leva tradição, confiança e sabor aos cariocas e se mantém como referência em pizzas e massas na cidade do Rio de Janeiro. Atualmente são mais de 60 operações entre restaurantes, lojas express em shopping centers, unidades de delivery e lanchonetes. Por trás de toda essa entrega ao cliente, está uma fábrica de 5 mil m², onde são produzidas receitas exclusivas de forma artesanal.', NULL, 'RIO DE JANEIRO', 1, NULL, 39, NULL, NULL, '2026-03-08 21:05:10.007', 'https://franquias.portaldofranchising.com.br/franquia-parme-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '740000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
