INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza752y009leh0szsg21d1s', 'STUDIO VELOCITY', 'studio-velocity', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Estúdios de de ciclismo indoor, estúdios de funcional', 2018, 2022, '[\"https://www.youtube.com/watch?v=GizQM_aBZq0\",\"https://www.youtube.com/watch?v=XEjNQqk3pfU\"]', '2026-04-01 02:00:04.651', '2025-08-05 22:20:25.978', 382, NULL, 1, 2013, 'PRIMEIRA E MAIOR REDE DE BIKE INDOOR DA AMERICA LATINA  Fundada em 2013 por um grupo de investidores nacionais e internacionais, a rede surgiu com o intuito de revolucionar o mercado de fitness no Brasil, inovando em metodologia, tecnologia (primeira rede a oferecer resultados individuais online e ao vivo, pagamento por aula e agendamento online) e principalmente, em uma experiência para transformar a atividade física em algo divertido, prazeroso e viciante. \nO Studio Velocity foi inaugurado no final de 2013 e hoje existem 30 unidades operando na América Latina, sendo 27 no Brasil e 3 unidades no Mexico, e mais 23 unidades em implantação, totalizando 53 unidades na América Latina. \nSão mais de 260mil clientes na base, e espera-se mais de 1,5 milhão de visitas em 2022. 2013 - Fundação\n2014 - Inauguração primeiro estúdio\n2016 - 5 estúdios próprios em São Paulo e Campinas, e Inauguração da 1ª unidade México\n2017 - Inauguração da Unidade Própria Leblon e início do projeto Franquias Brasil\n2018 - Abertura da 1ª franquia, em Maringá-PR\n2019 - 21 unidades operando, sendo 18 no Brasil e 3 unidades no México\n2020 - 24 unidades operando + 6 em implantação\n2021 - 30 unidades operando+ 23 em implantação\n2022 - 53 unidades total + 6 regiões reservadas', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0139f3b7-7d8f-4c38-b7e4-fb8220508536.jpg', 47, NULL, NULL, '2026-03-08 21:06:29.841', 'https://franquias.portaldofranchising.com.br/franquia-studio-velocity/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/75ceccdb-cc03-4772-80a6-fa0769d1655a.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '760000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7532009meh0ss3j5vwkg', 'GLESS', 'gless', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A GLESS é especialista em alongamento em fibra e gel com seu método exclusivo de cutigulagem. Através de um projeto arquitetônico moderno e foco em qualidade total, se tornou uma marca reconhecida.', 2022, 2024, NULL, '2026-04-01 02:00:04.660', '2025-08-05 22:20:25.983', 383, NULL, 1, 2018, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0d64dd07-185c-4ffe-b6fc-e8931461980d.png', 8, NULL, NULL, '2026-03-08 21:07:24.547', 'https://franquias.portaldofranchising.com.br/franquia-gless-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '294000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
