INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza753z009teh0s9o1yt4bm', 'OUTLET LINGERIE', 'outlet-lingerie', NULL, 'Moda', 'Vestuários', 'Outlet de Lingerie reúne as melhores marcas com o melhor preço em um só lugar.', 2011, 2011, '[\"https://www.youtube.com/watch?v=yykAI_3IfW4\"]', '2026-04-01 02:00:04.724', '2025-08-05 22:20:26.016', 390, NULL, 1, 2008, 'A empresa começou em 2008, através de uma ideia visionária do diretor da marca,  depois de fazer carreira como executivo em indústrias de lingerie e perceber que muitas peças boas  e com qualidades não tinham mais saídas, por causa de rotatividade de coleções e entrada de peças novas, essas  peças eram simplesmente descartadas. Foi então que nasceu a Outlet Lingerie, líder nesse modelo de negócio, inicialmente com lojas próprias em São Paulo  e iniciando a expansão, através de franchising, em 2011. Hoje a rede tem unidades distribuídas em todo o país e o negócio é considerado uma ação inédita no segmento de lingeries multimarcas pela Associação Brasileira de Franchising (ABF), e inclusive possui o selo de excelência da ABF de 2014, 2015, 2016, 2017 e 2018 na qual a rede é filiada.  A Outlet Lingerie é reconhecida nacionalmente por oferecer até 70% de desconto em relação aos valores originais em peças de grifes, sem defeitos. Também como diferenciais do negócio, a rede é considerada a  maior  compradora de lingerie das  grandes marcas do mercado nacional e trabalha com um estoque total superior a 500 mil peças de 20 marcas femininas e masculinas, que são renovadas mensalmente.  Assim as lojas recebem novidades toda semana.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8a76e095-1b77-44b1-8ed1-1f31fc153bc0.jpg', 93, NULL, NULL, '2026-03-08 21:09:51.931', 'https://franquias.portaldofranchising.com.br/franquia-outlet-lingerie-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '275000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7544009ueh0szv6j3c5b', 'AMIGÃO CALÇADOS', 'amigao-calcados', NULL, 'Moda', 'Calçados', 'Comércio varejista de calçados, artigos esportivos e artigos de viagem.', 2014, 2024, NULL, '2026-04-01 02:00:04.733', '2025-08-05 22:20:26.020', 391, NULL, 1, 1982, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/de3c82a0-8599-4d1c-b7f9-79925cff794d.jpeg', 33, NULL, NULL, '2026-03-08 21:10:40.897', 'https://franquias.portaldofranchising.com.br/franquia-amigao-calcados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '600000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7549009veh0siyhi5jrg', 'AMISTE CAFÉ', 'amiste-cafe', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Empresa de Locação e Venda de Máquinas de Café, Vending Machine, Cafés e Insumos', 2013, 2014, '[\"https://www.youtube.com/watch?v=ozc-efRhJ74\"]', '2026-04-01 02:00:04.743', '2025-08-05 22:20:26.025', 392, NULL, 1, 2001, 'Café sem abrir cafeteria. Conheça modelo de negócio de máquinas de café B2B e fature em média R$250.000 por mês A Amiste Café é uma empresa que oferece soluções completas em café para clientes corporativos, e isso abre diversas oportunidades de negócios para nossos franqueados. Ao se juntar à nossa rede, você terá acesso a uma gama de serviços e produtos que incluem: Locação e Venda de Máquinas de Café: Torne-se um especialista em máquinas de café e atenda às necessidades de empresas de todos os tamanhos, fornecendo soluções de café sob medida. Vendas de Insumos de Alta Qualidade: Trabalhe com insumos premium, como cafés especiais, gourmet e superiores, cappuccinos, chocolates, chás, xaropes e outros. Assistência Técnica Autorizada: Lidere o mercado oferecendo assistência técnica para as principais marcas de máquinas de café, garantindo a satisfação de seus clientes. Treinamentos, Cursos e Workshops: Ofereça treinamentos personalizados para quem deseja aprimorar a experiência de seus clientes. Nossa empresa atende com excelência uma variedade de setores e portes, incluindo indústrias, hotéis, hospitais, laboratórios, clínicas, escritórios, cafeterias, restaurantes e muito mais. A Amiste Café é sinônimo de qualidade e excelência no mundo do café, e você pode fazer parte dessa história de sucesso. Margem de lucro de 25% Payback de 24 meses Negócio de café que não é cafeteria Receita recorrente e escalável Baixa concorrência B2B. Atenda todo tipo de empresa como indústrias, escritórios, clínicas, cafeterias, hotéis, restaurantes e muitos outros.   A primeira franquia de Office Coffee Service do Brasil \nNossa primeira unidade surgiu em 2001, na cidade de Londrina-PR, sendo umas das primeiras do Brasil no ramo de Office Coffee Service (OCS), fornecendo serviços de locação e manutenção de máquinas de café para empresas. \nLogo nossa empresa passou a oferecer além de máquinas, produtos como cafés especiais de alto padrão, cappuccinos, chocolates e outros insumos para elaboração de bebidas, expandindo o comércio para atender bares, restaurantes e cafeterias. \nApós 10 anos de crescimento, nos tornamos líder no segmento em Londrina-PR e Maringá-PR e, em 2012, convertemos o nosso negócio para rede de franquias levando nosso padrão de qualidade para outras cidades e estados. \nAtualmente estamos presente em 12 cidades do Brasil. \nHoje oferecemos soluções completas em cafés para todo tipo e tamanho de empresa. \nSomos autorizados e homologados dos principais fabricantes de máquinas de café, temos nossas próprias marcas de cafés, chocolates e cappuccinos e somos distribuidores oficiais dos principais fabricantes de insumos para preparação de bebidas quentes e geladas.   Porque investir na Amiste Café: Know-how de mais de 20 anos. \nAções de marketing e vendas. Contamos com um time dedicado para trazer leads para as equipes comerciais dos nossos franqueados e acelerar o crescimento. \nTreinamento contínuo. A franqueadora capacita a equipe dos franqueados periodicamente. \nReceita recorrente. Nossa principal fonte de receita vem de contratos de locação e fornecimento de insumos, o que garante previsibilidade na receita conforme a carteira de clientes vai sendo construída. \nBaixa concorrência. Nesse mercado existem poucos operadores. Somos a única franquia de OCS do Brasil. \nInvestimento modular. A maior parte do investimento conforme o franqueado vai conquistando seus clientes.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/02c44eec-167e-4e61-a26b-a3d6e4b58321.jpg', 20, NULL, NULL, '2026-03-08 21:11:05.091', 'https://franquias.portaldofranchising.com.br/franquia-amiste-cafe-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza755i009weh0sdocef710', 'PRIME SAÚDE', 'prime-saude', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Comercialização de Sistemas/Planos de Saude (Individual, Familiar/Empresarial)', 2003, 2011, NULL, '2026-04-01 02:00:04.752', '2025-08-05 22:20:26.070', 393, NULL, 1, 1992, '', NULL, 'SÃO PAULO', 1, NULL, NULL, NULL, NULL, '2026-03-08 21:12:50.352', 'https://franquias.portaldofranchising.com.br/franquia-prime-saude-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza755o009xeh0s6hiqrq13', 'SUPER OTICA SÃO JOSÉ', 'super-otica-sao-jose', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Ótica voltada para a Saúde dos Olhos', 2010, 2010, '[\"https://www.youtube.com/watch?v=pcb9wFk1f9g\",\"https://www.youtube.com/watch?v=tiWzEu7CUec\",\"https://www.youtube.com/watch?v=TfIzEPUQiyE\",\"https://www.youtube.com/watch?v=e8ILD9MGW8A\"]', '2026-04-01 02:00:04.762', '2025-08-05 22:20:26.076', 394, NULL, 1, 1969, 'VOCÊ QUE DESEJA SER UM EMPREENDEDOR / FRANQUEADO TER SEU PRÓPRIO NEGÓCIO 1- Conheça características importantes para o comportamento empreendedor / franqueado 2- Confira a seguir algumas características básicas de um empreendedor de sucesso.  Iniciativa e coragem Empreender consiste basicamente em colocar ideias em prática. \nUm empreendedor sabe que uma boa ideia é aquela que pode ser executada. \nPara isso, traça um plano de ação. Ele sabe o que quer fazer e como fazer. O empreendedor é alguém que aceita correr riscos. \nPara implementar suas ideias, ousa de maneira consciente, seja para colocar um novo produto no mercado ou com o objetivo de expandir seu negócio. Também é alguém que planeja e realiza seus projetos, mudando de estratégia caso seja necessário.  Visão estratégica  Liderança  Perceber quais as demandas do mercado, entender o perfil do cliente, saber qual o posicionamento da empresa, avaliar vantagens e riscos. Essas são algumas características que compõem a visão estratégica dos bons empreendedores. Eles são capazes de compreender como as diversas instâncias da organização estão articuladas, estabelecendo planos de ação tanto para o ambiente interno como para o externo. Faz parte da visão estratégica a capacidade de aproveitar oportunidades e de inovar, e essas ações são fundamentais para manutenção e crescimento de uma empresa.  Liderança  Visão estratégica  Capacitação  Por compreender todos os processos de funcionamento da organização, o empreendedor é alguém que sabe liderar. Distribui tarefas e funções para os funcionários mais aptos a desempenhá-las. Ao aplicar táticas de liderança, a equipe torna-se autogerenciável, passa a conhecer a ordem organizacional, identifica-se com os valores da empresa e age em prol da conquista dos objetivos. A gestão de talentos é também uma ação essencial para o gerenciamento produtivo, inclusive com melhoria na lucratividade. Ao saber quais as aptidões de um funcionário, o líder pode remanejá-lo para outra função que possa exercer com mais destreza.  Capacitação  Liderança  As discussões mais recentes têm abandonado a antiga visão do empreendedorismo como uma característica inata. Os teóricos da administração e da gestão de empresas têm defendido a capacidade empreendedora como um aperfeiçoamento de competências. Por isso, investir na capacitação e no aprendizado tem sido uma característica bastante incentivada em quem deseja empreender ou ampliar seu negócio. E isso não se restringe apenas ao gestor, mas à equipe de funcionários, seja com a capacitação da equipe de vendas ou a organização de um curso para implementar novas rotinas produtivas na empresa.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/328065a5-bd12-4ad3-9ea6-f4aca2ca191f.jpg', 45, NULL, NULL, '2026-03-08 21:13:14.197', 'https://franquias.portaldofranchising.com.br/franquia-super-otica-sao-jose-oculos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '271000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
