INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza756e00a2eh0sidaalwbs', 'ESPAÇO DAS EMPADAS', 'espaco-das-empadas', NULL, 'Alimentação', 'Bares e Restaurantes', 'Modelo de negócio é de alimentação rápida, focadas em empadas de diversos sabores salgadas e doces. Voltado para shoppings center ou locais de grande fluxos de pessoas.', 2022, 2023, NULL, '2026-04-01 02:00:04.808', '2025-08-05 22:20:26.102', 399, NULL, 1, 2021, '', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f330da04-75bb-4850-ade9-49c5fac86575.png', 11, NULL, NULL, '2026-03-08 21:16:18.728', 'https://franquias.portaldofranchising.com.br/franquia-espaco-das-empadas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '125000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza756j00a3eh0snfpiyj83', 'ARRANJOS EXPRESS', 'arranjos-express', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'A marca diversifica os serviços e acompanha as tendências do mercado da moda, consolidando-se como referência em alinhavar a personalidade única dos clientes por meio de ajustes e customizações.', 2003, 2012, '[\"https://www.youtube.com/watch?v=ZA3gbpVc7nY\",\"https://www.youtube.com/watch?v=TuMIK43nzLU\",\"https://www.youtube.com/watch?v=mgFtcEQaGgk\",\"https://www.youtube.com/watch?v=0m8DHFTpg4Q\"]', '2026-04-01 02:00:04.818', '2025-08-05 22:20:26.107', 400, NULL, 1, 2003, 'A Arranjos Express foi fundada em 2003, originalmente em Portugal. Chegou ao Brasil em 2012 e em sua trajetória, consolidou-se estando hoje com mais de 120 lojas e com potencial crescimento em toda a América. \nMais que uma rede de costura, a Arranjos Express atua com excelência e com um conceito criativo, criamos junto ao mercado um novo hábito de consumo, onde o cliente pode consertar, transformar, adequar e reaproveitar suas peças. \nPara a praticidade do público e a rentabilidade dos franqueados, a Arranjos Express busca sempre ser uma aliada e parceira das lojas locais. \nE para equivaler ao ambiente instalado, contamos com lojas modernas, práticas, maquinários inovadores, profissionais bem treinados e serviços com qualidade além de um operacional bastante simplificado e sem estoque.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/635fe1d4-005f-42b0-9990-ba745e3aed8e.jpg', 134, NULL, NULL, '2026-03-08 21:16:38.693', 'https://franquias.portaldofranchising.com.br/franquia-arranjos-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '160000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza756p00a4eh0swukou9qt', 'OJO', 'ojo', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Somos uma ótica conceito especializada em Ray Ban principal marca de óculos do mundo.', 2015, 2019, NULL, '2026-04-01 02:00:04.827', '2025-08-05 22:20:26.113', 401, NULL, 1, 2012, 'A OJO nasceu com o desejo de revolucionar aquilo que você conhece como ótica. Tudo é uma questão de escolhas e praticidade. Por isso reunimos o que existe de melhor em um mesmo lugar: os melhores laboratórios e lentes, os últimos lançamentos das marcas mais consagradas do mundo, um atendimento personalizado (sem ser chato), a maior variedade de tamanhos, formatos e modelos – tudo, tudinho mesmo, num ambiente mais descontraído e contemporâneo. \nOs modelos ficam a sua disposição para experimentar, os equipamentos tiram qualquer dúvida e o capuccino está sempre quentinho esperando você. Tudo foi pensado para fazer você se sentir bem, e sair ainda mais satisfeito e seguro com aquilo que escolheu. E se você não gostar, não tem problema: a gente troca. \nNão somos uma loja, somos uma tendência. Somos a evolução daquilo que você conhece como ótica. Somos a OJO by Mr. Ray.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6f77c2bf-81ba-4a64-80ae-6d68d9ef3d2a.jpg', 9, NULL, NULL, '2026-03-08 21:17:19.429', 'https://franquias.portaldofranchising.com.br/franquia-ojo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
