INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza758600aaeh0s50q9rnlo', 'RESTAURA JEANS', 'restaura-jeans', NULL, 'Limpeza e Conservação', 'Reparos', 'Lavanderia de alta Tecnologia, Serviços para Costura, Customização e Tingimento Profissional, Restauração de Roupas e Assessórios em Couro e Venda de Produtos. Uma Franquia completa.', 1994, 2001, '[\"https://www.youtube.com/watch?v=KUS21-NFzu0\",\"https://www.youtube.com/watch?v=3_GQd1WyBMg\"]', '2026-04-01 02:00:04.888', '2025-08-05 22:20:26.166', 407, NULL, 1, 1991, 'A rede já passou de 170 unidades em todo o Brasil com um faturamento superior a 100 milhões de reais no último ano, sendo líder no segmento de limpeza e conservação de roupas e acessórios. \nHoje a Restaura Jeans é a marca mais valorizada e reconhecida pela qualidade dos serviços e credibilidade da rede. \nCom mais de 500.000 mil consumidores ativos no Brasil temos um índice de satisfação dos nossos serviços acima de 94% com base em quem já utilizou. \nA mais de 31 anos no mercado de franchising a Restaura Jeans oferece a nossos franqueados 5 fontes de renda em um único negócio. \nLavanderia completa, tingimento profissional, costura e customização, renovação de couro e venda de mais de 100 produtos inovadores. \n  \n  Com serviços que vão muito além do jeans, e um modelo de negócio enxuto, a Restaura Jeans traz segurança e solidez para seu investimento.    Na Restaura Jeans temos um Suporte 360, ou seja, um suporte completo. \nComo franqueado você contará com uma equipe especialista nas mais diversas áreas de negócio para dar segurança em todas as fases, da implantação à operação da sua franquia.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ad97bb0c-0b0a-47ad-b468-da18eff4d75c.jpg', 134, NULL, NULL, '2026-03-08 21:25:07.012', 'https://franquias.portaldofranchising.com.br/franquia-restaura-jeans-conservacao-e-lavanderia/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b7f3e9e2-c3ad-457a-b690-b1b7e0ae6899.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ee1fd3f2-e9bc-4357-ba18-c47dfa809c57.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/511a0113-ccd8-4a43-9d9b-aaf352b2519a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ee043129-31ed-4486-afb8-53c6662ac0d9.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza758e00abeh0sx9po3x9x', 'INSTITUTO ANA HICKMANN', 'instituto-ana-hickmann', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'A Escola Profissionalizante Ana Hickmann é referência em cursos de beleza, tecnologia e inglês, unindo ensino de alta qualidade, inovação pedagógica e a transformação de vidas por meio da educação.', 2018, 2019, '[\"https://www.youtube.com/watch?v=Mds2GbOBFho\"]', '2026-04-01 02:00:04.898', '2025-08-05 22:20:26.175', 408, NULL, 1, 2018, 'Escola Profissionalizante Ana Hickmann: transformando vidas através da educação e da beleza! A Escola Profissionalizante Ana Hickmann é uma rede de ensino inovadora que atua nas áreas de beleza, tecnologia e inglês, com uma proposta pedagógica moderna e acessível. Nosso compromisso é oferecer capacitação profissional de alta qualidade, permitindo que nossos alunos adquiram uma profissão e gerem renda para suas famílias, independentemente de gênero, idade, classe social ou formação acadêmica. Um modelo de negócio completo: 3 em 1 Além de oferecer cursos profissionalizantes, nossas unidades contam com um Salão Profissional, onde os alunos aplicam seus conhecimentos na prática, proporcionando uma experiência real e, ao mesmo tempo, gerando uma nova fonte de receita para os franqueados. Escola Profissionalizante na área da tecnologia – Mais de 50 cursos com uma plataforma interativa. Escola Profissionalizante na área da beleza – Formação em diversas profissões do setor. Salão Profissional – Um dos poucos modelos de escola no Brasil que forma e emprega profissionais no mesmo local. Suporte de excelência para os Franqueados A franqueadora disponibiliza um Centro de Excelência em Treinamentos, garantindo suporte completo aos franqueados e suas equipes por meio de duas plataformas estratégicas: Universidade Corporativa Presencial Infraestrutura de alto nível para treinamentos e palestras, com um auditório moderno e climatizado para 150 pessoas, equipado com: Poltronas confortáveis Flipchart e laser point Microfone e sonorização profissional Projetor HD Wide e Wi-Fi Salas de reuniões equipadas Espaço exclusivo para franqueados Área para coffee break/almoço Estacionamento próprio e localização privilegiada Universidade Corporativa EAD Uma plataforma online completa, com materiais estratégicos para a operação da franquia, incluindo: Manuais de franquia Peças personalizáveis para ações comerciais Campanhas de marketing Vídeos de treinamentos Fotos e documentos essenciais Comunicação visual e muito mais! Liderança e Credibilidade A Escola Profissionalizante Ana Hickmann é liderada por grandes nomes do mercado: Sidney Kalaes – Presidente do Grupo Kalaes, uma holding multissetorial de franquias. Administrador de empresas, com mais de 30 anos de experiência no setor, sendo líder, master e fundador de diversas franqueadoras de sucesso. Ana Hickmann – Apresentadora e empresária de renome, trazendo credibilidade, exposição e diferenciais estratégicos ao negócio. Seu engajamento na educação profissional tem impactado a vida de milhares de alunos, capacitando-os para o mercado de trabalho. Seja parte dessa transformação! Invista em um modelo de negócio inovador, sólido e altamente rentável.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e0e24b08-a50e-4ada-9a22-bd04e0bbe8d7.jpg', 48, NULL, NULL, '2026-03-08 21:25:51.802', 'https://franquias.portaldofranchising.com.br/franquia-instituto-ana-hickmann/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '197000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza758l00aceh0sz5zfxzut', 'LE BISCUIT', 'le-biscuit', NULL, 'Casa e Construção', 'ARTIGOS PARA O LAR', 'A Le biscuit é um varejo que oferece soluções com sortimento completo para seus clientes em todos os eventos promocionais do ano, além das campanhas exclusivas.', 2018, 2018, NULL, '2026-04-01 02:00:04.908', '2025-08-05 22:20:26.181', 409, NULL, 1, 1968, 'A Le biscuit foi criada em 1968, em Feira de Santana, sendo a primeira rede de variedades da Bahia. A partir de 2012, com o apoio do fundo de investimento Vinci Partners, a rede investiu na expansão e iniciou o ano de 2018, quando comemorou 50 anos de existência com mais de 100 lojas próprias em operação e presente em 14 estados brasileiros nas regiões Norte, Nordeste, Sudeste e Centro Oeste. Atualmente a companhia passa a contar com 144 estabelecimentos comerciais, sendo 137 lojas próprias e 07 franquias. A Le Biscuit foi reconhecida diversas vezes ao longo dos seus 50 anos de existência em decorrência do seu compromisso em servir os seus clientes. O último reconhecimento aconteceu no ano de 2018, quando a marca foi novamente vencedora do troféu TOP OF MIND na categoria de Produtos para o Lar. A Le biscuit comercializa mais de 20 mil itens, divididos em diversas categorias: Utilidades domésticas, brinquedos, papelaria, eletroportáteis, bomboniere, festa, Cama, mesa e banho, Higiene, beleza e moda, lazer, armarinho e artesanato, decoração, bebê e telefonia. Para o modelo de franquia foi elaborado um mix otimizado de produtos, mais adequado ao formato destas lojas. Este sortimento oferece soluções completas para os clientes em todos os eventos promocionais do ano, além das campanhas exclusivas. A Le Biscuit tem como missão encantar os clientes através de uma experiência de compra diferenciada, em um ambiente agradável, com maior variedade de produtos, qualidade, inovação e economia, gerando alegria para todos e crescimento para o nosso time. Atualmente são mais de 2.400 colaboradores divididos em nossa matriz que fica na cidade de Salvador/BA, em nosso centro de distribuição que fica na cidade de Camaçari/BA, e em nossa rede de lojas próprias. Em 2018 consolidamos o projeto Le franchise, em consonância com a crescente evolução do sistema de franquias no Brasil, com o objetivo de criar uma rede padronizada, de forma profissional e organizada, transferindo o know-how a seus Franqueados. Iniciamos o ano de 2020 com 04 franquias em operação (Irecê, Ipirá, Santo Amaro e Cruz das Almas) todas no estado da Bahia. No segundo semestre levamos a nossa franquia para outros estados da região NE. A primeira unidade a inaugurar nesse ano foi na cidade de Serra Talhada em seguida em Carpina e breve em Santa Cruz do Capibaribe, ambas no estado de Pernambuco.', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fe2b2d99-b66f-478b-b374-899ba2f468a4.png', 140, NULL, NULL, '2025-04-15 17:03:31.000', 'https://franquias.portaldofranchising.com.br/franquia-le-biscuit/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
