INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759100afeh0sn3b1pabt', 'GIGATRON', 'gigatron', NULL, 'Comunicação, Informática e Eletrônicos', 'INFORMÁTICA', 'Softwares de gestão, SaaS, PDV, força de venda, Business Intelligence, ERP, soluções ágeis para empresas.', 2011, 2012, NULL, '2026-04-01 02:00:04.937', '2025-08-05 22:20:26.197', 412, NULL, 1, 1999, 'Somos uma empresa de tecnologia que se baseia nas necessidades de nossos clientes e franqueados, seguindo a tendência em demandas de produtos em tecnologia. A Gigatron Tecnologia iniciou suas atividades no desenvolvimento de sistemas de gerenciamento no mês de Maio do ano de 1998, na cidade de Birigui, interior de São Paulo, tendo como patrono, o Sr. Marcelo Salomão Guimarães. À época, a empresa tinha como escopo o desenvolvimento de sistemas comerciais para atender as exigências fiscais que encontravam-se em grande transformação. Em detrimento da carência de mercado ou pelo alto custo de seus concorrentes, muitas indústrias calçadistas da cidade de Birigui começaram a solicitar sistemas à Gigatron. Somente a partir do ano de 2002 que a Gigatron se consolidou no mercado. Após a construção de seu prédio próprio e contando com equipe estruturada, a empresa passou a traçar sua forma. Apenas a partir de 2012 que a empresa decidiu entrar no mercado do franchising, sendo inclusive referência por três anos seguidos no ramo de tecnologia e serviços. Modalidades de Negócio Especializada em softwares e prestação de serviços para empresas, a rede de franquias apresenta cinco modalidades de negócios. Formato de trabalho Nossa rede trabalha de forma descentralizada, permitindo um modelo de negócio diferenciado. Guarda Chuva = Foco no produto Franqueador = Foco no negócio Master Franquia = Foco na expansão Franquia ou Micro = Foco no cliente Núcleo = Foco em atendimento', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ded09603-30b5-47b8-824a-dc3353a49af7.jpg', 49, NULL, NULL, '2025-09-09 09:18:22.000', 'https://franquias.portaldofranchising.com.br/franquia-gigatron-comunicacao-informatica-e-eletronicos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759600ageh0srm9905a8', 'SIDE WALK', 'side-walk', NULL, 'Moda', 'Calçados', 'Calçados, vestuário e acessórios para o público masculino e feminino.', 2013, 2014, NULL, '2026-04-01 02:00:04.946', '2025-08-05 22:20:26.202', 413, NULL, 1, 1982, 'Três amigos, muita coisa em comum e uma vontade. Foi com esse espírito que, em 1982, Luis Gelpi, Eduardo Rizk e Tinho Azambuja resolveram fundar a Sidewalk, uma marca que cresceu com o DNA repleto de originalidade e irreverência. O homem e a mulher Side vivem uma rotina urbana e moderna, mas não perdem a chance de sair da cidade para dias mais tranquilos em contato com a natureza. Para isso, além de peças perfeitas para o dia a dia, o conforto éindispensável para a marca.   \nMuitas vezes inspirados por experiências de suas viagens ao exterior e decididos a mesclar inovação a um jeito autêntico de se fazer moda, Luis, Eduardo e Tinho abriram a primeira loja da marca na Rua Melo Alves, nos Jardins, em São Paulo. Em pouco tempo, os calçados da Side, que vinham embalados em saquinhos flanelados, foram sucesso absoluto entre os clientes. Logo depois, a cartela de cores das pólos e das meias, os Topsiders, os sapatos de bolinha, entre muitos outros, já estavam nas wish list de gente cheia de estilo no país inteiro. \nAtualmente, são 26 lojas em todo o Brasil, sendo 13 em São Paulo. Após completar 30 anos, a Sidewalk continua imprimindo seu estilo criativo e descontraído ao mercado de moda brasileiro.', NULL, 'SÃO PAULO', 1, NULL, 6, NULL, NULL, '2026-03-08 21:28:13.240', 'https://franquias.portaldofranchising.com.br/franquia-side-walk-acessorios-pessoais-e-calcados/', NULL, NULL, '[]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '420000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759c00aheh0spjoeoxaz', 'INVEST4U', 'invest4u', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'A Invest4U entrega direção financeira com base cristã, ajudando famílias a proteger o presente e construir um plano claro para multiplicar seu patrimônio com propósito e paz.', 2023, 2024, NULL, '2026-04-01 02:00:04.956', '2025-08-05 22:20:26.208', 414, NULL, 1, 2018, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fa7ed04a-8645-4c1c-a7e7-59f56c5705da.png', 8, NULL, NULL, '2026-03-08 21:29:00.699', 'https://franquias.portaldofranchising.com.br/franquia-invest4u-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '33000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759h00aieh0s4beq7ruy', 'POPDENTS', 'popdents', NULL, 'Saúde, Beleza e Bem Estar', 'ODONTOLOGIA', 'Área da saúde', 2017, 2018, '[\"https://www.youtube.com/watch?v=JnQytcdzkME\",\"https://www.youtube.com/watch?v=GPCuYPdmuv4\",\"https://www.youtube.com/watch?v=hxvk2v2n3bY\"]', '2026-04-01 02:00:04.966', '2025-08-05 22:20:26.213', 415, NULL, 1, 2000, 'O propósito do negócio é impactar positivamente a vida das pessoas, fornecendo atenção e cuidado àqueles que mais necessitam, além de capacitar o dentista a se tornar um empreendedor. As operações da POPdents são focadas em alto giro e demanda, com desempenho detalhado. Priorizamos a experiência individual de cada paciente e cada atendimento de forma personalizada. O caminho para o sucesso está em um ciclo diário de atendimento imediato, construção de relacionamento com nossa base de clientes, estímulo ao fluxo de indicações e encorajamento à recompra de novos tratamentos. Nosso CEO e fundador - Marcelo Buriti Ainda na faculdade de odontologia, tinha certeza que não pensava como seus colegas e enxergava o dia a dia da profissão de forma diferente. Já sentia que seu trabalho não se resumiria aos atendimentos no consultório. O que mais lhe chamava atenção durante este período (além das necessidades e dores dos pacientes) era a certeza da capacidade que tinha de transformar a vida dessas pessoas. Depois de formado, decidiu que esse era seu objetivo, e assim começou o projeto. Apostou tudo que tinha nesse sonho e montou seu primeiro consultório. Depois do sucesso do empreendimento, abriu o segundo, o terceiro e assim 26 anos depois, ao alcançar a marca de 80 operações de varejo e tornar o atendimento odontológico de qualidade mais acessível a todos, passou a se concentrar em governança, padrões e processos, inteligência corporativa, maximizar a margem de lucro das operações, simplificando o modelo de gestão e melhorando o posicionamento das marcas. Como empreendedor e empresário que é, decidiu abrir sua primeira marca, a POPdents, para o mercado de franquias, dando a oportunidade de empreendedores e investidores entrarem nos segmentos de beleza, bem estar e saúde, de forma segura e assertiva.', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7e6be0df-cb00-4879-87bd-8ea816cde146.svg', 41, NULL, NULL, '2025-10-13 09:04:17.000', 'https://franquias.portaldofranchising.com.br/franquia-popdents/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759m00ajeh0sg8ilflzd', 'ÓTICAS BRASIL', 'oticas-brasil', NULL, 'Saúde, Beleza e Bem Estar', 'ÓTICAS', 'Comércio varejista de óculos, lentes oftálmicas e acessórios.', 2018, 2021, '[\"https://www.youtube.com/watch?v=un7m6FDTTCc\"]', '2026-04-01 02:00:04.977', '2025-08-05 22:20:26.219', 416, NULL, 1, 1964, 'ÓTICAS BRASIL: UMA FRANQUIA COM PROPÓSITO Com mais de 58 anos de história, a Óticas Brasil tem como propósito proporcionar às pessoas uma visão perfeita e personalizada para ampliar a visão de si e do mundo Fundada há 58 anos por Jerônimo Motta, um dos pioneiros no segmento óptico em Goiás, a tradicional Óticas Brasil, nasceu do amor pela visão, onde Sr. Jerônimo não media esforços para fazer as pessoas enxergarem melhor. Jerônimo era um autodidata criativo, amante da literatura e músico nas horas vagas. Foi um visionário no mercado de lentes ópticas e inaugurou a Óticas Brasil pelo amor ao ofício. Além de criar diversos equipamentos para a produção de lentes no seu laboratório, ainda publicou o livro “Elementos de Óptica Para Balconistas” e fundou a ASCOEG – Associação do Comércio de Óptica do Estado de Goiás, que, posteriormente se transformou no SINDIÓPTICA – GO, contribuindo para o desenvolvimento do setor. Hoje, Óticas Brasil se consolidou como uma marca de confiança junto ao mercado, transmitindo o conhecimento e a experiência acumulados como atributos determinantes do binômio atendimento/fidelidade. Tal experiência estende-se também nas melhores negociações com fornecedores, incluindo mix de produtos completo (Óculos solares, Armações, Tratamentos antirreflexos, lentes ópticas e acessórios), as melhores Grifes e marcas revendidas do mercado e também marcas próprias, que estão em franco crescimento, garantindo alta rentabilidade e preços ainda mais competitivos. Dentro de todas as Lojas Óticas Brasil, o cliente tem a experiência única de Consultoria Óptica especializada, que inclui a modernização de todo processo de atendimento e confecção dos óculos através do que há de mais moderno em termos de solução digital óptica. Com o aparelho i. Terminal go, os parâmetros de medição ocular são capturados digitalmente, resultando em personalização avançada das lentes. São medidas oculares perfeitas, obtendo parâmetros individuais com tecnologia de alta precisão. O processo digital evita possíveis erros de ajuste da medição manual, que podem resultar em perda de até 40% do desempenho das lentes. Essa e outras ações traduzem o investimento e compromisso da Óticas Brasil em oferecer ao cliente atendimento de qualidade e soluções visuais completas e tecnológicas. O Grupo Óticas Brasil conta também com Laboratório Ótico Próprio, a Unilentes. Com mais de 15 anos de mercado e capacidade produtiva de mais de 1600 serviços-dia, a Unilentes é atualmente um dos maiores e mais bem estruturados Laboratórios Óticos da região centro-oeste do país, e, um dos únicos do Brasil que recebeu a certificação internacional ZEISS (Empresa Alemã líder mundial na fabricação de lentes). Para receber esta homologação, foram realizados altos investimentos em maquinário e tecnologia, adequação de todos os processos produtivos e garantia dos mais exigentes protocolos de qualidade, o que garante ao cliente final lentes de alta performance. Para a Óticas Brasil, a qualidade do serviço, inovação e excelência no atendimento são os requisitos mais considerados nos seus programas de desenvolvimento. Provas disso são as premiações e certificados recebidos ao longo dos anos. Os últimos foram o Prêmio TOP OF MIND Goiânia – A marca de Óticas Mais lembrada pelos Goianos (PopList Goiânia 2021) e também o certificado de excelência em NPS (Net Promoter Score), metodologia internacional que certifica grandes multinacionais e nos pontua como uma das poucas empresas onde mais de 90% dos clientes avaliam nosso atendimento como bom ou ótimo. André Silva, Gestor de Atendimento e Qualidade Óticas Brasil, trabalha no negócio há mais de 40 anos e afirma com confiança: “Mesmo após 58 anos da fundação, a Óticas Brasil segue o legado do Sr Jerônimo, trabalhando na mesma metodologia humanizada, mantendo uma relação próxima com o cliente e com total garantia de adaptação. Caso não haja satisfação, os óculos são trocados e se por acaso não houver solução o dinheiro é devolvido. Com metodologia disruptiva no mercado, a empresa traz soluções óticas por meio de sua inovação, tecnologia e humanização. Seu pioneirismo agrega valor e qualidade no produto. Hoje a Óticas Brasil conta com um modelo de franquia com payback em 20 meses e investimento inicial de R$238.000,00. Além de números expressivos de lucratividade, o franqueado recebe também total acompanhamento, incluindo suporte para Implantação do Negócio, suporte à Negociação de Produtos e Equipamentos, programas de Captação Inicial e Continuada, Treinamento Técnico em Óptica para Franqueado e Equipe, apoio às Ações de Marketing Local, software de Gestão, Consultoria de Campo e Negócio e Programas de Excelência.', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7d4d1e65-f5ca-4708-9d89-641dfe3e6d13.jpg', 40, NULL, NULL, '2025-04-16 17:13:04.000', 'https://franquias.portaldofranchising.com.br/franquia-oticas-brasil/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/55c59078-a445-464e-9067-f901de072f74.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759s00akeh0sbkfvd745', 'ALGAR TELECOM', 'algar-telecom', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Telecomunicações e T.I.', 2018, 2018, '[\"https://www.youtube.com/watch?v=cTJ2yGEv3pg\",\"https://www.youtube.com/watch?v=0v5VFCNIwbs\"]', '2026-04-01 02:00:04.988', '2025-08-05 22:20:26.224', 417, NULL, 1, 1954, 'Lançada em dezembro de 2017, Algar Telecom Franquias é uma grande inovação no mercado de Telecom. Pra começar, é uma operação de ponta a ponta pioneira no Brasil. \nO franqueado fica à frente de decisões estratégicas, que passam por atendimento, expansão de rede, cobrança, recrutamento, treinamento e muitos outros assuntos. \nCom suporte total da Algar Telecom, ele se sente o verdadeiro dono da operação de telecom na sua região. \nA marca fica ainda mais próxima das necessidades e demandas de seus clientes. Há melhora sensível na qualidade dos serviços e no atendimento. Por essa e outras iniciativas, a Algar Telecom foi reconhecida como empresa mais inovadora do setor de Telecomunicações, segundo o prêmio Valor Econômico de 2019. Não por acaso, se tornou a primeira operadora de telecom franqueadora do Brasil filiada à ABF, a Associação Brasileira de Franchising.  Atualmente, Algar Telecom Franquias conta com 60 franquias em operação, que absorveram a operação em 16 estados do país e no Distrito Federal com atendimento a mais de 1,4 milhão de clientes.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9db11467-e740-4b85-8a95-5ee38b326b6c.png', 105, NULL, NULL, '2026-03-08 21:29:43.602', 'https://franquias.portaldofranchising.com.br/franquia-algar-telecom/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '2000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759x00aleh0suxh5qp2y', 'MEUS CÍLIOS', 'meus-cilios', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A rede Studios Meus Cílios® é focada em um dos segmentos que mais crescem na área da beleza feminina, que é o embelezamento do olhar. O negócio que iniciou em 2017, agora conta com franquias.', 2021, 2022, '[\"https://www.youtube.com/watch?v=ryh8aqaZIGE\"]', '2026-04-01 02:00:05.000', '2025-08-05 22:20:26.230', 418, NULL, 1, 2017, 'Franquia da área da beleza feminina com foco em extensão de cílios que teve início em 2017 na cidade de Gramado. A primeira franquia da rede Meus Cílios entrou no ar em julho de 2021, e conta com um mix de serviços completo, inclui: alongamento de cílios, alongamento de unhas em fibra de vidro, bronzeamento por vaporização, micro pigmentação labial, sobrancelhas, outros. Uma empresa feita por mulheres, para mulheres. A franqueadora do Meus Cílios dá apoio completo ao franqueado em todas as fases, desde a escolha do ponto comercial, até o método de recrutamento para garantir uma equipe alinhada aos propósitos do negócio. Tão importante quando a implementação é o suporte dado durante a condução do negócio, com encontros contínuos e treinamentos de gestão e atualização. Uma empresa dinâmica, e que está crescendo de forma orgânica e sustentável.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/26d5271a-1474-4442-838e-7eaba13c1160.jpg', 36, NULL, NULL, '2026-03-08 21:30:31.482', 'https://franquias.portaldofranchising.com.br/franquia-meus-cilios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
