INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75aj00apeh0sag1rjq9p', 'AGRONERI', 'agroneri', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Soluções em Sistemas de Irrigação para os segmentos do Agronegócio e Urbanismo.', 2023, 2023, NULL, '2026-04-01 02:00:05.057', '2025-08-05 22:20:26.252', 422, NULL, 1, 2013, '', NULL, 'MATO GROSSO DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2a55affe-e3f7-4750-92df-fb5d6068224b.png', 10, NULL, NULL, '2025-08-15 17:43:29.000', 'https://franquias.portaldofranchising.com.br/franquia-agroneri/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ao00aqeh0s4ht7u29v', 'LUG\'S', 'lug-s', NULL, 'Alimentação', 'Bares e Restaurantes', 'O carro chefe da marca: frango no balde e batata belga no cone. Os clientes também encontram opções de pratos executivos gourmet e premium, chopp artesanal produzido pela marca, bebidas e sobremesa.', 2014, 2014, '[\"https://www.youtube.com/watch?v=fTt-Zu6tMb4\"]', '2026-04-01 02:00:05.071', '2025-08-05 22:20:26.257', 423, NULL, 1, 2009, 'Única no segmento. O que já é sucesso na Europa há décadas, esta fazendo o maior sucesso no Brasil. \nAs Batatas Belgas da Lug\'s, produzidas com batatas Premium importadas da Bélgica, são crocantes por fora e macias por dentro, servida no Cone com molhos exclusivos ficam especiais. \nO clima frio e o método de cultivo fazem das Batatas Belgas da Lug\'s únicas em sabor e textura. Venha experimentar este negocio altamente lucrativo e seja mais um louco por batatas!!!  Benefícios da Franquia LUG\'S \n- Conceito inovador, diferente de tudo que existe no ramo de Fast Food;\n- Produto Único e exclusivo no Mercado;\n- Operação padronizada e manualizada;\n- Uma das maiores rentabilidades do segmento;\n- Baixo custo de implantação tendo em vista a rentabilidade.  Sistema Lug\'s \nA LUG´S concebeu um Sistema de Franchising bastante simples e objetivo, onde o Franqueado é tratado como um verdadeiro parceiro. \nA principal preocupação da Franqueadora é oferecer aos Franqueados qualidade nos produtos e condições de lucratividade cada vez mais atraentes, repassando conhecimentos estratégicos, métodos de implantação e operação de unidades.  Assessoria oferecida \n- Fornecimento de toda matéria prima necessária;\n- Assessoria e apoio na escolha localização do ponto comercial adequações e layouts de obras a serem executadas no imóvel escolhido para a unidade;\n- Suporte na seleção e treinamento de colaboradores, divulgadores e demais funcionários;\n- Treinamento e reciclagem para o pessoal operacional e conceitual para os profissionais recém contratados, na sede da franqueadora ou em locais designadas por ela, visando minimizar os custos do franqueado.\n- Layout interno e externo, e identidade visual do imóvel escolhido e/ou aprovado pela LUG´S FRANCHISING.\n- Auditoria Preventiva e Instrutiva;\n- Marketing de inauguração, manuais da franquia, perspectivas de gastos antecipados e previsíveis, Pós-inauguração;\n- Desenvolvimento de novos produtos', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/aefa911e-87cf-4bc4-801c-afe5183fd145.jpg', 3, NULL, NULL, '2026-03-08 21:32:35.026', 'https://franquias.portaldofranchising.com.br/franquia-lugs-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75au00areh0s0jx3klqc', 'LOS CREPES', 'los-crepes', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO COMPLETO', 'Restaurante especialista em Crepes. Servimos mais de 90 sabores de crepe, saladas com crepes, shakes, sucos naturais e açaí. Também temos o formato fast food.', 2023, 2023, NULL, '2026-04-01 02:00:05.083', '2025-08-05 22:20:26.262', 424, NULL, 1, 2020, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/40bc30ab-9925-423d-a423-098b609c9dca.jpeg', NULL, NULL, NULL, '2025-04-17 16:24:11.000', 'https://franquias.portaldofranchising.com.br/franquia-los-crepes-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75az00aseh0sq3yzdszb', 'IGA', 'iga', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Com mais de 160 escolas e presente em 5 países, o IGA hoje é a Maior Rede de Escolas de Gastronomia das Américas. Única 3 vezes a conquistar o Selo de Excelência em Franquias - 2018/2019/2020.', 2003, 2010, '[\"https://www.youtube.com/watch?v=qVeX8YTA_bw\",\"https://www.youtube.com/watch?v=rhFMI17VjhA\"]', '2026-04-01 02:00:05.095', '2025-08-05 22:20:26.267', 425, NULL, 1, 2001, 'Fundado em 2001, na Argentina, o IGA – Instituto Gastronômico das Américas e´ uma Rede de Escolas de Gastronomia, capacitando cursos de gastronomia e alta cozinha, além de confeitaria profissional e avançada. \nPrecursora no ensino profissionalizante de gastronomia, assim que ingressou no mercado, a empresa se posicionou entre as melhores no segmento, conquistando sua força e presença através de sua metodologia exclusiva. \nSua entrada em países da América do Sul, sendo eles, Argentina, Paraguai, Uruguai, Bolívia e Brasil fortaleceu e potencializou o ensino gastronômico. \nTeve sua consolidação no mercado com uma chancela Internacional com mais de 500.000 alunos certificados nestes mais de 20 anos de existência. \nSendo uma rede sustentável, de grande expansão internacional e excelência no Sistema de Franquias, alcançamos mais de 160 unidades sendo atualmente a maior rede de escolas de gastronomia da América Latina.  \nCom investimento seguro e sólido, o IGA e´ uma rede com multifranqueados, tendo hoje pouco mais de 70 franqueados/investidores em toda a rede.  \nTendo no cenário atual, franqueados com mais de 20 anos de participação, inicia-se na rede o processo de transição para a segunda geração das unidades. \nQuanto ao segmento, representado por um mercado altamente competitivo, o IGA, esta´ pronto para o desafio de inovar constantemente e melhorar a qualidade e o prestígio dos seus cursos. \nNo Brasil, desde 2008, hoje conta com mais de 85 unidades em 20 Estados da Federação. \nA rede possui mais de 30 mil alunos ativos em todo Brasil, e com potencial para dobrar este número nos próximos 3 anos. \nCom um crescimento sustentável e efetivo, o planejamento de expansão esta´ em sua quarta fase no Brasil, e, esta´ apontando para Europa, África e Asia nos próximos 10 anos. \nEstes são dados que o IGA apresenta, para que você^ investidor/franqueado tenha seu capital aplicado em um modelo de negócios que perpetua a mais de 20 anos!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3dc42a76-7848-46ba-9644-71d3277a3f80.jpg', 76, NULL, NULL, '2026-03-08 21:33:51.761', 'https://franquias.portaldofranchising.com.br/franquia-iga/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75b500ateh0s38698rh9', 'FEITO A GRÃO®', 'feito-a-grao', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Cafeteria de Cafés Especiais, Doceria, Lanches e Bistrô', 2013, 2024, NULL, '2026-04-01 02:00:05.108', '2025-08-05 22:20:26.274', 426, NULL, 1, 2006, '', NULL, 'SERGIPE', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ea397ed4-d65b-4e25-a19f-1d287c41ed8c.png', 5, NULL, NULL, '2025-08-29 11:08:24.000', 'https://franquias.portaldofranchising.com.br/franquia-feito-a-graor-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75bb00aueh0sokc3aeae', 'POSTNET', 'postnet', NULL, 'Comunicação, Informática e Eletrônicos', 'Serviços Gráficos e Impressão', 'Cópias, Impressões, Remessas nacionais e internacionais, Internet, Gráfica rápida.', 2004, 1992, NULL, '2026-04-01 02:00:05.118', '2025-08-05 22:20:26.280', 427, NULL, 1, 1980, 'A PostNet é um centro de conveniência de Office Services, que atende pequenas e médias empresas, profissionais liberais, estudantes e pessoas físicas em geral. Fundada em 1980, nos Estados Unidos, a PostNet iniciou sua expansão internacional em 1993 e atingiu mais de 1000 lojas em operação no mundo, distribuídas em 10 países, todas no modelo de franquia. A PostNet chegou ao Brasil em 2003 e operou apenas com a loja Piloto nos padrões do mercado nacional até 2006, quando deu início à expansão de franquias. Atualmente a PostNet Brasil conta com mais de 40 unidades em operação e uma unidade Piloto para treinamento de novos franqueados. A franquia PostNet está presente no Brasil em 19 cidades, distribuídas por 9 estados. O principal objetivo da PostNet é a qualidade no atendimento, oferecendo diversos serviços em um único local.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1b98c214-df79-4225-9b6c-c0e1c96c455d.jpg', 55, NULL, NULL, '2026-03-08 21:35:17.390', 'https://franquias.portaldofranchising.com.br/franquia-postnet-grafica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75bh00aveh0s85ggvsjz', 'HAPPY&CO.®️', 'happy-co', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'A Happy é uma experiência única e definitiva no ensino do inglês. Nosso curso é fast mas não é food. O sucesso da nossa metodologia é ensinar os alunos de forma consistente, divertida e feliz.', 2021, 2021, NULL, '2026-04-01 02:00:05.130', '2025-08-05 22:20:26.285', 428, NULL, 1, 2020, 'Somos uma Academia de Inglês. Ensinamos o idioma mais falado no mundo em apenas 15 meses (60 semanas), através de uma metodologia diferenciada e focada no sentimento de nossos alunos, por meio de avaliações de satisfação sistemáticas e acompanhamento pedagógico eficiente, ágil e, acima de tudo, personalizado. A Happy&Co® possui um corpo diretivo com vasta experiência em escolas de inglês. Porém, todo o desenvolvimento da empresa foi baseado em \"Marketing de Diferenciação\". Isto nos torna únicos no mercado. A Happy&Co® surge em meio à ausência do sentimento de bem-estar e pertencer, na falta do reconhecimento e na luta por um propósito. Desde a fundação da JG ENSINO DE IDIOMAS LTDA EPP (2007) este sentimento foi abalado e petrificado, até que tudo mudou na presença do propósito de Deus em levar aos alunos o compromisso pela satisfação, pois este sentimento \"trocado\" de um filho por uma empresa, fez com que a HAPPY nascesse 14 anos após, madura, robusta e com o espírito de fazer um sentimento mais forte aflorar em seus alunos: FELICIDADE! Assim nasceu na leitura nua e crua de \"FELIZ E CIA\" nosso desejo em sermos não apenas uma empresa ou marca, mas um estilo de vida. Como citada antes, nossa metodologia de ensino é focada no entretenimento, imersão e muita doação do \"eu\".    Viver este sentimento merece uma celebração. Aliás, ensinar/aprender inglês nunca mais será da mesma maneira.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c4dc6adf-1a48-41bc-8c24-ae583ca2c796.jpg', 3, NULL, NULL, '2026-03-08 21:35:57.556', 'https://franquias.portaldofranchising.com.br/franquia-happy-co/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75bn00aweh0sm9rybwph', 'SUBURBANOS', 'suburbanos', NULL, 'Alimentação', 'Bares e Restaurantes', 'Delivery e balcão. A suburbanos nasceu com o propósito de trazer uma pizza de qualidade e preço justo para seus clientes, junto com uma identidade visual alegre, inovadora e fora do padrão.', 2020, 2022, '[\"https://www.youtube.com/watch?v=37pTzBPPAoU\",\"https://www.youtube.com/watch?v=IrkhT-6xAA0\"]', '2026-04-01 02:00:05.141', '2025-08-05 22:20:26.291', 429, NULL, 1, 2018, 'A Suburbanos surgiu a partir da ideia de 2 primos que nasceram no subúrbio da Zona Oeste e queriam empreender, um deles tinha uma pizzaria, enquanto o outro empreendia com outros negócios, então em um bate papo descontraído pensaram em unir seus conhecimentos. \nCarregando as origens de onde nasceram para montar um negócio que remetesse as cores, o carinho e o gosto do lugar onde nasceram. \nEntão surgiu a marca Suburbanos no dia 5 de novembro de 2019 com uma pegada jovem e um nome ousado.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7e6dd582-bf57-4aac-bb59-64735c34ffc5.png', 40, NULL, NULL, '2026-03-08 21:36:53.052', 'https://franquias.portaldofranchising.com.br/franquia-suburbanos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '280000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
