INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75dc00b7eh0smiz59nu3', 'EMPÓRIO MINEIRO CHEIRIN BÃO', 'emporio-mineiro-cheirin-bao', NULL, 'Alimentação', 'Mercados e Distribuição', 'Empório de produtos tipicamente Mineiros e Cafeteria com cafés especiais do Sul de Minas!', 2016, 2018, '[\"https://www.youtube.com/watch?v=5ADd5sH3Bac\",\"https://www.youtube.com/watch?v=95aw762gVJg\",\"https://www.youtube.com/watch?v=QzQLTO5iAnQ\"]', '2026-04-01 02:00:05.247', '2025-08-05 22:20:26.352', 440, NULL, 1, 2013, 'Empreenda com a maior rede de cafeterias do Brasil! Com mais de 800 franquias espalhadas em todo o Brasil, nos tornamos a maior rede de cafeterias no mercado nacional! Muito mais do que cafeteria de cafés especiais nos tornamos especialistas em proporcionar momentos únicos e criar boas memórias através de sensações e aromas que remetem as melhores lembranças da nossa vida. Nos conectamos com nossos clientes através do famoso “jeitin mineiro”, o cheirin de café passado na hora, o bolo quentinho que lembra a casa da vó e delícias mineiras recheadas de tradição, originalidade e muito afeto! Cheirin Bão recebe três dos prêmios mais importantes do franchising em evento promovido pela ABF em 2022! No maior evento do Franchising brasileiro, promovido pela Associação Brasileira de Franchising (ABF), fomos reconhecidos com três prêmios: Selo de Excelência em Franchising 2022 Prêmio Destaque Franchising ABF na categoria Franqueado por Inovação Prêmio Destaque Franchising ABF na categoria Sustentabilidade É motivo de muito orgulho e comemoração ter tido o reconhecimento do órgão que auxilia o mercado de franquias a crescer e se desenvolver. Com a Cheirin Bão você encontra um negócio validado, marca consolidada, a segurança e rentabilidade que você precisa! Fature até R$104 Mil por mês com a sua Cheirin Bão Graças a um modelo de negócio sólido com estratégias validadas, com a sua Cheirin Bão você pode obter até R$104 Mil de faturamento por mês! Esses são resultados potenciais para o nosso modelo de negócio, que podem variar de acordo com a gestão do franqueado. Na Cheirin Bão você tem a segurança e rentabilidade que você precisa!', NULL, 'MINAS GERAIS', 1, NULL, 588, NULL, NULL, '2026-03-08 21:46:37.822', 'https://franquias.portaldofranchising.com.br/franquia-emporio-mineiro-cheirin-bao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '332900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
