INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75dn00b9eh0sjcbyu097', 'ENCONTRE SUA VIAGEM', 'encontre-sua-viagem', NULL, 'Hotelaria e Turismo', 'Agências de Turismo', 'Suporte e consultoria no ramo turístico, através de reservas nacionais e internacionais de pacotes que abrangem hotéis, companhias áreas, rodoviárias e marítimas, proporcionando conforto e segurança.', 2017, 2022, NULL, '2026-04-01 02:00:05.268', '2025-08-05 22:20:26.363', 442, NULL, 1, 2017, 'A Encontre Sua Viagem é uma franquia de turismo consolidada no mercado, e que faz parte do grupo Encontre Sua Franquia. \nA marca conta hoje com mais de 1.500 empresas parceiras do setor, oferecendo ainda mais variedade para os serviços entregues aos clientes. \nHoje, a Encontre Sua Viagem oferece dois modelos de negócio aos seus futuros candidatos. Um modelo de loja física e outro Home Office, e em ambos o franqueado atua como um verdadeiro agente de viagem. \nCom isso, os clientes da Encontre Sua Viagem podem encontrar várias opções em um só lugar. \nVenha para a Encontre Sua Viagem e seja um Franqueado de sucesso! \nENTRE EM CONTATO COM A ENCONTRE SUA VIAGEM', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cf584148-6d72-47d9-b406-9759633d24f0.jpg', 210, NULL, NULL, '2026-03-08 21:48:06.048', 'https://franquias.portaldofranchising.com.br/franquia-encontre-sua-viagem/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '13000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
