INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75e800bdeh0s12xc3rb6', 'MY ROBOT SCHOOL', 'my-robot-school', NULL, 'Educação', 'EDUCAÇÃO', 'Escola de robótica e programação criada para atender crianças, jovens e adultos que desejam entender e dominar as tecnologias da Era Digital.', 2015, 2020, NULL, '2026-04-01 02:00:05.300', '2025-08-05 22:20:26.384', 446, NULL, 1, 2008, '', NULL, 'SÃO PAULO', 1, NULL, 31, NULL, NULL, '2025-12-03 14:17:59.000', 'https://franquias.portaldofranchising.com.br/franquia-my-robot-school/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '94800', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ed00beeh0szib7jf6e', 'UZA', 'uza', NULL, 'Moda', 'Calçados', 'CALÇADOS E ACESSÓRIOS DE MODA FEMININA', 2016, 2021, '[\"https://www.youtube.com/watch?v=Pp264Af2Oyk\"]', '2026-04-01 02:00:05.314', '2025-08-05 22:20:26.390', 447, NULL, 1, 2001, 'Em 2001 a UZA emergia com o propósito de trazer ao mercado, calçados femininos que estivessem em sintonia com o lifestyle da mulher contemporânea por meio de um design sofisticado e singular. Inicialmente instalada em um pequeno pátio fabril atendendo ao mercado de multimarcas, a organização desenvolveu sua trajetória construindo uma identidade autoral em consonância com as necessidades do mercado. Sete anos mais tarde, alinhada à crescente demanda por seus produtos, a marca passou a ocupar novas instalações e projetar ampliações focadas em novos mercados, onde em dezembro de 2013 estendeu-se ao varejo online. Em 2016, um novo marco para expansão da marca é delineado através da inauguração da sua flagship store no Shopping Cidade Jardim, em São Paulo, iniciando assim o projeto de sistema de franquias. Atualmente, além da sua contínua e crescente atuação por meio das franquias implementadas pelo país, atende também a demanda de mais de 800 lojas multimarcas distribuídas no Brasil e no exterior e, empreende de maneira ascendente no varejo online. Todas as lojas da rede trazem a identidade da marca apresentada por meio das instalações que compreendem um projeto arquitetônico que expõe os produtos de forma a gerar o desejo de experimentação e compra. O sapato é um ícone apaixonante e difusor de poder para as mulheres, por isso, esse cenário representa a figura de um closet, feito com materiais que refletem autoridade e atualidade.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/eb4986c1-251d-4842-a8b0-bffa86de42e0.jpg', 49, NULL, NULL, '2026-03-08 21:53:28.732', 'https://franquias.portaldofranchising.com.br/franquia-uza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '490000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ei00bfeh0sjkwoeiim', 'TEMPLUM FRANCHISING', 'templum-franchising', NULL, 'Serviços e Outros Negócios', 'CONSULTORIAS', 'Consultoria digital especializada em gestão e certificação de pequenas e médias empresas.', 2022, 2022, NULL, '2026-04-01 02:00:05.326', '2025-08-05 22:20:26.395', 448, NULL, 1, 1994, '', NULL, 'SÃO PAULO', 1, NULL, 1, NULL, NULL, '2025-08-27 10:20:30.000', 'https://franquias.portaldofranchising.com.br/franquia-templum-franchising-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75eo00bgeh0st4kfye0i', 'MELTEN CO', 'melten-co', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'A MELTEN CO. é uma nova proposta de atendimento que busca revolucionar o modelo de gestão de sorveterias, inovando no método de consumo e de gama de produtos.', 2021, 2021, NULL, '2026-04-01 02:00:05.336', '2025-08-05 22:20:26.400', 449, NULL, 1, 2020, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ae4cda3f-3adf-429d-9769-f020f231ee5c.jpg', 19, NULL, NULL, '2025-09-08 17:53:59.000', 'https://franquias.portaldofranchising.com.br/franquia-melten-co/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75et00bheh0s01qypqai', 'MERCADINHO DO SEO JUCA SEU MELHOR VIZINHO', 'mercadinho-do-seo-juca-seu-melhor-vizinho', NULL, 'Alimentação', 'Mercados e Distribuição', 'O Mercadinho do Seo Juca é um minimercado dentro do seu condomínio que funciona 24hs, de maneira autônoma, com itens essenciais para seu dia a dia, e aquelas delícias que bate a vontade de comer.', 2022, 2023, NULL, '2026-04-01 02:00:05.345', '2025-08-05 22:20:26.405', 450, NULL, 1, 2020, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d80370d4-ec66-4e00-ad1f-f6b1ca25822b.png', 22, NULL, NULL, '2026-03-09 15:15:37.817', 'https://franquias.portaldofranchising.com.br/franquia-mercadinho-do-seo-juca-seu-melhor-vizinho-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '25000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ez00bieh0s5c8ak181', 'CASA PILÃO', 'casa-pilao', NULL, 'Alimentação', 'Bares e Restaurantes', 'Coffee Shops. Rede de cafeterias da marca líder no mercado de cafés no Brasil, a Casa Pilão foca em qualidade com cafés espressos e coados, além de cappuccinos, bebidas geladas, doces e salgados.', 2013, 2013, '[\"https://www.youtube.com/watch?v=Q7CK9h2ml6g\"]', '2026-04-01 02:00:05.355', '2025-08-05 22:20:26.411', 451, NULL, 1, 2010, 'A Casa Pilão é uma marca tradicional e líder de mercado. \nCom um conceito de brasilidade, ambiente aconchegante e atrativo, a Casa Pilão possui um mix variado de produtos de qualidade, produzido por fornecedores homologados. Líder em vendas, seu objetivo é deixar os clientes à vontade dentro do espaço e, para isso, a Casa Pilão oferece diversas opções de café espresso, cappuccinos e bebidas frias e aquecimento quente à base de café, além dos seus processos de cafés coados na hora. Na cafeteria, além do café em si, que pode ser servido de diversas formas atrativas, também há comercialização de outros alimentos como salgados, biscoitos ou doces. Permitindo uma experiência deliciosa como acompanhamento e agregam no faturamento da unidade.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/eb864fdc-97ac-490e-9fe4-6a747e73b488.jpg', 15, NULL, NULL, '2026-03-09 15:16:00.102', 'https://franquias.portaldofranchising.com.br/franquia-casa-pilao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '240000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75f500bjeh0sbzza6ig5', 'ANIMALIAFARMA', 'animaliafarma', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Farmácia de Manipulação Veterinária', 2016, 2017, NULL, '2026-04-01 02:00:05.365', '2025-08-05 22:20:26.417', 452, NULL, 1, 2011, 'A Animalia Farma é uma farmácia de manipulação veterinária, pioneira em seu segmento na cidade de Araraquara e região. Conta com um corpo profissional altamente especializado, as proprietárias são farmacêuticas que possuem pós-graduação na área de Fármacos e Medicamentos (Mestrado e Doutorado na Faculdade de Ciências Farmacêuticas – Unesp e Pós Doutorado na Universidade Estadual Paulista - USP) e ampla experiência no setores de pesquisa e desenvolvimento de produtos na indústria veterinária. \nNosso projeto de expansão começou com o aperfeiçoamento dos nossos serviços nos primeiros três anos, não só na forma de gerenciar e aprimorar nosso negócio, mas no desenvolvimento de formas farmacêuticas e fórmulas exclusivas de diversos formatos e sabores a fim de facilitar a administração aos pets e a adesão dos mesmos ao tratamento. \nAs formulações de nossa pasta oral e biscoitos são únicas, o que nos torna diferenciados das demais empresas do ramo. Investimos constantemente em pesquisa, tecnologia e conhecimento nosso e de nossos colaboradores, realizando melhorias contínuas em processos e produtos. Nossa sede foi inaugurada em Araraquara em 2011. Em 2014 inauguramos uma filial em Ribeirão Preto , depois vieram as unidades nas cidades de Piracicaba em 2017, em 2018 São Carlos e Campinas, e em 2019 São Paulo e Bebedouro', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fbb21240-2462-4e12-a07c-4bef1faec2e4.jpg', 15, NULL, NULL, '2026-03-08 21:55:54.729', 'https://franquias.portaldofranchising.com.br/franquia-animaliafarma/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75fa00bkeh0sn816tk2l', 'MORDIDELA', 'mordidela', NULL, 'Alimentação', 'Bares e Restaurantes', 'A Mordidela é uma conceituada rede de franquia no segmento alimentício com conceito baseado em pequenas porções e grande mix de produtos, pensados para atender os consumidores de todas as classes.', 2015, 2015, NULL, '2026-04-01 02:00:05.374', '2025-08-05 22:20:26.422', 453, NULL, 1, 2013, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/dfa15c93-13d0-4956-86ff-c789e1c633f6.png', 62, NULL, NULL, '2026-03-08 21:56:46.675', 'https://franquias.portaldofranchising.com.br/franquia-mordidela-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ff00bleh0s53gzjy6k', 'VOLL PILATES STUDIO', 'voll-pilates-studio', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Disponibilizamos um modelo inovador de franquias de estúdios de Pilates.', 2019, 2021, NULL, '2026-04-01 02:00:05.384', '2025-08-05 22:20:26.428', 454, NULL, 1, 2009, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/097f3372-444a-4d0e-85e8-a8bc0bacaa87.png', 102, NULL, NULL, '2026-03-08 21:57:10.691', 'https://franquias.portaldofranchising.com.br/franquia-voll-pilates-studio/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '91790', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75fl00bmeh0sm597hc5f', 'BELLA GULA', 'bella-gula', NULL, 'Alimentação', 'Bares e Restaurantes', 'Tortaria e Café', 1999, 1993, NULL, '2026-04-01 02:00:05.393', '2025-08-05 22:20:26.433', 455, NULL, 1, 1993, 'A Bella Gula é uma rede de franquias gaúcha de Tortaria e Café, com forte atuação no mercado local desde 1993 e foi concebida pelo então jovem casal Bernardo e Daniella Thomaz unindo a paixão e o super talento dela em criar delícias fantásticas com a grande expertise administrativa dele. \nEles escolheram Porto Alegre para iniciar este sonho e a data de aniversário dele, 21 de maio, para ser o primeiro dia, de sua primeira loja. \nDepois desta, vieram muitas outras num processo formatado de franquias. Atualmente a Bella Gula está rompendo os limites geográficos do Brasil e levando suas delícias para os Estados Unidos, dando início a sua internacionalização. O sonho cresceu! Todo o mix da marca tem como característica fundamental ser natural e não utilizar aditivos químicos e conservantes em sua formulação. \nEm sua fábrica própria, apesar de serem produzidas toneladas de produtos, a Bella Gula faz questão de manter a artesanalidade no processo de produção das tortas e doces que são feitos à mão, com muito amor, cuidado e carinho por confeiteiras que estão na empresa desde o seu início, garantindo assim o sabor incrível e qualidade impecável em todos os produtos. A Bella Gula proporciona uma experiência única e se consolidou no mercado com mais de 30 lojas espalhadas no Rio Grande do Sul, Paraná e São Paulo. \nAlém de ser uma das franquias de alimentação mais premiadas do Sul do Brasil, com 10 selos de Excelência em Franchising da ABF. \nAlém deste, está há 15 anos consecutivos entre as 10 melhores franquias do país, nomeadas pela Revista Pequenas Empresas, Grandes Negócios. O faturamento médio anual de uma franquia é de R$1.200.000,00, com uma lucratividade entre 10 e 20%, payback de 24 a 36 meses e investimento médio entre R$350.000,00 e R$450.000,00 (incluindo a taxa de franquia).', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6d59207b-2156-4927-a753-de286951abc5.png', 26, NULL, NULL, '2026-03-09 17:20:13.748', 'https://franquias.portaldofranchising.com.br/franquia-bella-gula-docerias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '350000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75fq00bneh0s7uqftb6q', 'FARMÁCIA ROVAL', 'farmacia-roval', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Farmácia de Manipulação', 2009, 2009, '[\"https://www.youtube.com/watch?v=-YRsv4CxjmA\",\"https://www.youtube.com/watch?v=VJf2R9mSwsE\",\"https://www.youtube.com/watch?v=MBbwNGmCckQ\",\"https://www.youtube.com/watch?v=yEr6JCZ9zqw\"]', '2026-04-01 02:00:05.402', '2025-08-05 22:20:26.438', 456, NULL, 1, 1988, 'A FARMÁCIA ROVAL DE MANIPULAÇÃO foi fundada em 1988, no Recife, com a proposta de “manipular medicamentos para todas as especialidades médicas” e com o firme propósito de criar o intercâmbio Médico-Farmacêutico, tão importantes para a melhoria da qualidade do tratamento dispensado ao cliente. Em 2010, optou-se por expandir o negócio, através da ROVAL FRANCHISING LTDA e da criação de um sistema único de franquia que refletisse a sua expertise no segmento, a credibilidade da sua marca e a sua bem-sucedida atuação, nos moldes da Lei 13966/19; e também se associou à ABF – Associação Brasileira de Franquias, de quem recebeu um selo de excelência após pesquisa junto aos seus franqueados, e atualmente conta com 80 unidades pelo Brasil. A FARMÁCIA ROVAL DE MANIPULAÇÃO é uma empresa inovadora que tem como diferencial oferecer alternativas farmacêuticas que viabilizem a manipulação de medicamentos personalizados e adaptados às necessidades especiais de pacientes e prescritores. A empresa oferece tratamento adequado, com eficácia e segurança, garantindo a manutenção da saúde e qualidade de vida. NOSSO PROPÓSITO: Transformar a saúde e a vida das pessoas e dos animais.', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/231a3b7c-3eea-460f-b796-395f5f4b1393.png', 62, NULL, NULL, '2026-03-08 21:58:43.963', 'https://franquias.portaldofranchising.com.br/franquia-farmacia-roval-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '430000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75fv00boeh0smfg2vwu3', 'ÓTICAS VIDERE', 'oticas-videre', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Invista em nossa franquia de sucesso: modelo comprovado, suporte total com grande potencial de crescimento. Junte-se às Óticas Videre.', 2020, 2022, NULL, '2026-04-01 02:00:05.413', '2025-08-05 22:20:26.443', 457, NULL, 1, 2018, '', NULL, 'SÃO PAULO', 1, NULL, 19, NULL, NULL, '2026-03-08 21:59:29.017', 'https://franquias.portaldofranchising.com.br/franquia-oticas-videre/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75g000bpeh0sb593s8s5', 'SMART FIT', 'smart-fit', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Academia de Ginástica', 2011, 2014, NULL, '2026-04-01 02:00:05.422', '2025-08-05 22:20:26.449', 458, NULL, 1, 2005, 'Franquia Smart Fit a maior rede de academias da América Latina Na franquia Smart Fit você tem todo suporte que precisa para ser um franqueado de sucesso      Projeto Arquitetônico A franqueadora oferece tecnologia para escolha do ponto comercial e projeto arquitetônico para as novas unidades franqueadas, respeitando as especificidades locais e atendendo ao design consolidado da marca.   Marketing Acesso a um plano de Marketing que engloba todo o país, reforçando a presença da marca. Ferramentas de captação, gestão e relacionamento com clientes. Marca Top of Mind e líder de categoria.   Gestão Acesso a uma equipe de consultoria dedicada às novas unidades, ao longo dos 12 meses iniciais. Após esse período o suporte continua através de um regional para continuarmos garantindo apoio regular e suporte na organização do dia a dia da operação.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/bebf81a3-a6d4-4290-b2ac-b5f75e004fc3.jpg', 986, NULL, NULL, '2026-03-08 21:59:52.221', 'https://franquias.portaldofranchising.com.br/franquia-smart-fit-valor/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/343ca0e3-f7f8-4c4e-a2c4-bc8d34fa7320.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '3530000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75g800bqeh0s5xxsawc2', 'SOLARY VILLE', 'solary-ville', NULL, 'Saúde, Beleza e Bem Estar', 'SERVIÇOS MÉDICOS', 'O Solary Ville Residencial Senior traz um conceito premium em cuidados com os idosos,desenvolvemos casas de repouso com alto padrão em cada detalhe.', 2022, 2022, NULL, '2026-04-01 02:00:05.432', '2025-08-05 22:20:26.456', 459, NULL, 1, 2016, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3f207de4-d9f8-45d7-bb5a-fda62aad6ace.jpg', NULL, NULL, NULL, '2025-08-18 12:58:58.000', 'https://franquias.portaldofranchising.com.br/franquia-solary-ville-hotelaria-e-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ge00breh0sfzkupl7k', 'START ANGLO BILINGUAL SCHOOL', 'start-anglo-bilingual-school', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Franquia de escolas bilíngues', 2023, 2024, '[\"https://www.youtube.com/watch?v=-3-XtI3IP9U\",\"https://www.youtube.com/watch?v=XkR6o2EDdkk\"]', '2026-04-01 02:00:05.441', '2025-08-05 22:20:26.463', 460, NULL, 1, 1960, 'A Start Anglo Bilingual School é uma das franquias de Educação Básica mais inovadoras do país. A rede é a única que oferece excelência em bilinguismo e em alta performance acadêmica na mesma proporção, como uma resposta aos desejos e necessidades de famílias e alunos do século XXI. Com menos de um ano de operação, a Start Anglo já conta com duas flagships [São José do Rio Preto e Vila Mariana (SP), uma parceria com Liceu Pasteur, a partir de 2025]; uma unidade pronta em Alphaville (SP), inaugurada em janeiro; além de 12 contratos assinados para 2025 e 2026. A rede nasceu fundamentada em décadas de experiência de renomados especialistas que se dedicaram em estudos e análises da realidade das escolas privadas do Brasil. O modelo de negócio Start Anglo foi elaborado com o respaldo de uma reconhecida consultoria de franchising da América Latina, a Cherto. O plano de negócios das escolas se fundamenta em análises aprofundadas do mercado, criando um formato de franquia eficiente e saudável, com resultados reais para os investidores. Dentre as variáveis de sucesso da Start Anglo estão a oportunidade de adesão ao modelo de escola premium, a metodologia exclusiva pautada na excelência, as jornadas de formação e certificação dos educadores, as ferramentas pioneiras de gestão escolar, a cultura de análise de dados, relatórios e aprendizado constante. Tudo isso permite que a Start Anglo se posicione no topo das melhores franquias de escolas bilíngues do Brasil, com projeções favoráveis de rentabilidade e potencial de crescimento financeiro.', NULL, 'SÃO PAULO', 1, NULL, 2, NULL, NULL, '2026-03-08 22:00:35.523', 'https://franquias.portaldofranchising.com.br/franquia-start-anglo-bilingual-school/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '2550000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
