INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75h500bueh0s6jjr9w02', 'ESCOLA FLAMENGO', 'escola-flamengo', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'A maior Rede de Escolas de Futebol do Brasil. A Escola Flamengo apresenta metodologia exclusiva da Base do C.R Flamengo e diversas vantagens. Venha empreender com a maior marca do futebol brasileiro.', 2000, 2019, NULL, '2026-04-01 02:00:05.468', '2025-08-05 22:20:26.489', 463, NULL, 1, 1994, '', NULL, 'RIO DE JANEIRO', 1, NULL, 175, NULL, NULL, '2026-03-09 15:18:03.747', 'https://franquias.portaldofranchising.com.br/franquia-escola-flamengo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '29000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75hd00bveh0s6ikpr0p4', 'MAG PAPELARIA', 'mag-papelaria', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Franquia de papelaria e presentes voltado para produtos que estimulam a organização e produtividade, desde a escola até o mercado de trabalho.', 2018, 2019, '[\"https://www.youtube.com/watch?v=CO79VUNAnOE\",\"https://www.youtube.com/watch?v=z8hwqjTwMdA\"]', '2026-04-01 02:00:05.480', '2025-08-05 22:20:26.497', 464, NULL, 1, 2018, 'Somos uma marca que estimula a organização e consequentemente a produtividade de jovens e adultos, desde a escola até o mercado de trabalho, e que usam o papel em paralelo ao digital para otimizar as multitarefas do dia a dia. \nO projeto da Magnólia surgiu lá no início de 2018, quando 4 casais de amigos se juntaram e tiraram do papel o sonho de abrir um quiosque de papelaria focado em organização, planejamento e produtividade.', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/070c3365-f7d4-417d-bcb5-914728127e9f.jpg', 60, NULL, NULL, '2026-03-08 22:02:33.011', 'https://franquias.portaldofranchising.com.br/franquia-mag-papelaria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '134900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75hj00bweh0stf0tyo33', 'SOBRANCELHAS DESIGN', 'sobrancelhas-design', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Unidades especializadas em Tratamentos para Sobrancelhas, Cílios e Maquiagem de alto padrão', 2012, 2013, NULL, '2026-04-01 02:00:05.491', '2025-08-05 22:20:26.504', 465, NULL, 1, 2012, 'Marca forte e referência para o mercado, o Grupo Sobrancelhas Design despertou o mundo para a importância das sobrancelhas dentro do nicho de beleza e bem-estar. Consolidado como líder absoluto do segmento com mais de 400 lojas distribuídas pelo Brasil, Estados Unidos e América Central, é a primeira rede de lojas dedicada exclusivamente ao design de sobrancelhas no mundo e realiza, em média, mais de 3 milhões de atendimentos por ano. A Sobrancelhas Design possui a mais renomada técnica do mercado, que considera diversos aspectos como: formato do rosto, linhas de expressão, quantidade, tipo e cor dos fios, além, é claro, da simetria facial e identidade, bem como o gosto pessoal da cliente. Analisando todos esses pontos é possível encontrar o formato ideal de sobrancelha para cada rosto, realçando a beleza natural e proporcionando uma expressão mais bonita. As unidades da SD contam com instalações inteligentes que proporcionam conforto e bem-estar às clientes que as frequentam, além do Kit Individual de Atendimento SD com o nosso incrível gel tonalizante, especialmente desenvolvido por Indústria própria. Nossas profissionais são capacitadas e treinadas pelo próprio Grupo, que conta com dois Centros de Treinamentos e formação onde as profissionais contratadas aprendem a nossa técnica exclusiva e os franqueados são orientados sobre a gestão do negócio. Profissionais com vasta experiência em franchising auxiliam diariamente toda a rede de franqueados. O atendimento ao franqueado é prestado de forma local, em sua própria região, através de gerentes operacionais que acompanham integralmente cada novo franqueado. Os masters franqueados orientam o franqueado durante todo o processo de implantação e operação da nova unidade. Além do design, a franquia Sobrancelhas Design oferece também depilação facial com linhas orgânicas e antibacterianas, exclusivas da marca. A técnica utilizada é a egípcia, que permite uma depilação melhor com menos irritações e desconfortos. E também o SD Relax, um serviço de massagens relaxantes nos pés.  De tanto vivenciar o universo feminino e todas as suas nuances e necessidades, o Grupo Sobrancelhas Design desenvolveu também uma linha de maquiagem e acessórios para make. Já consolidada como referência no cuidado com as sobrancelhas, a SD MAKE•UP expandiu a sua linha de produtos exclusivos para olhos, boca e rosto, mantendo o mesmo padrão de qualidade e alta tecnologia, já reconhecidos, com ajuda dos principais profissionais e especialistas do segmento, como o conceituado hair stylist e maquiador Duda Molinos. A linha de maquiagem já possui mais de 30 produtos de altíssimo padrão. Dentre os principais produtos da SD MAKE•UP, vale o destaque para a Linha de Tratamento para Transformação das Sobrancelhas, que recupera as sobrancelhas falhadas, regenerando os folículos capilares e estimulando o crescimento de novos fios.', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/20ab060a-8bf9-45ad-afb0-a8ea42fd7095.jpg', 125, NULL, NULL, '2026-03-08 22:03:09.019', 'https://franquias.portaldofranchising.com.br/franquia-sobrancelhas-design-estetica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '160000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75hq00bxeh0sziyitlpv', 'EVINO', 'evino', NULL, 'Alimentação', 'Mercados e Distribuição', 'Criada em 2013, a Evino é o maior e-commerce de vinhos da América Latina e possui mais de 1 milhão de clientes. Sua essência é entregar ao consumidor um mundo de descobertas e novas experiências.', 2022, 2023, NULL, '2026-04-01 02:00:05.501', '2025-08-05 22:20:26.510', 466, NULL, 1, 2013, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d6572811-82e7-4afb-ad21-1f158730d585.png', 10, NULL, NULL, '2026-03-08 22:04:29.552', 'https://franquias.portaldofranchising.com.br/franquia-evino-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '355000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75hw00byeh0so2pwlqa4', 'OLIVER\'S PIZZA', 'oliver-s-pizza', NULL, 'Alimentação', 'Bares e Restaurantes', 'Somos uma pizzaria que oferece o modelo delivery, a lá Carte e rodízio', 2023, 2023, NULL, '2026-04-01 02:00:05.511', '2025-08-05 22:20:26.516', 467, NULL, 1, 2017, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7bbdcffc-df70-429d-8c16-ba3ff15d8116.png', NULL, NULL, NULL, '2026-03-08 22:04:53.071', 'https://franquias.portaldofranchising.com.br/franquia-olivers-pizza/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75i200bzeh0spexsxbdy', 'YOGOBERRY', 'yogoberry', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Comercio de Frozen Yogurt', 2008, 2020, NULL, '2026-04-01 02:00:05.522', '2025-08-05 22:20:26.522', 468, NULL, 1, 2007, 'A YOGOBERRY nasceu da paixão de três amigos fascinados por Frozen Yogurt que conheciam o produto, até então só encontrado fora do Brasil e assim sonhavam em encontrar a receita perfeita: um iogurte delicioso e saudável, sem gordura, livre de conservantes e de alta qualidade em um só produto. A Yogoberry é a escolha certa! Com um produto delicioso e SUPER saudável, margem líquida de aproximadamente 20%, suporte abrangente ao franqueado e operação fácil, ser um franqueado Yogoberry é a chave para o sucesso empreendedor. Produto delicioso e saudável Margem líquida de aproximadamente 20% Suporte abrangente ao franqueado Modelo de negócio testado e aprovado Operação fácil Marca consolidada e reconhecida Baixo custo de estoque Receita exclusiva e sabor incomparável Flexibilidade de investimento Oportunidade de fazer parte de uma rede líder', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c3544ea5-dd54-4aae-b35b-a3117b0e6651.jpg', 34, NULL, NULL, '2025-08-08 12:02:03.000', 'https://franquias.portaldofranchising.com.br/franquia-yogoberry/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75i800c0eh0snyco85dy', 'FUEL THE EYEWEAR COMPANY', 'fuel-the-eyewear-company', NULL, 'Moda', 'Acessórios Pessoais', 'Comércio varejista de óculos de sol, armações e acessórios.', 2016, 2017, '[\"https://www.youtube.com/watch?v=aQxH0fJZhIU\"]', '2026-04-01 02:00:05.533', '2025-08-05 22:20:26.528', 469, NULL, 1, 2013, 'A Fuel Eyewear, criada em 2013 no RJ, se destaca no mercado óptico por sua visão transformadora e empoderadora, aliando tecnologia, design inovador e preços acessíveis.  Um óculos para cada look. Uma comunidade de apaixonados por estilo. Get ready. Be great. Fuel your look!', NULL, 'RIO DE JANEIRO', 1, NULL, 70, NULL, NULL, '2026-03-08 22:05:25.182', 'https://franquias.portaldofranchising.com.br/franquia-fuel-the-eyewear-company/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9d697cb3-d14a-43ad-abde-447d174e105d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/05d404ab-8470-4599-b831-33b034aa7fe0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d7ab3c3a-1e5a-42fb-b296-4282b1268c42.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75id00c1eh0slg72erb7', 'BOI BRABO O SHOPPING DA CARNE', 'boi-brabo-o-shopping-da-carne', NULL, 'Alimentação', 'Mercados e Distribuição', 'O Shopping da Carne é a evolução do açougue. Trabalhamos com produtos para churrasco e linha dia a dia. Nossas carnes são100% embaladas e temos também os setores de empório, acessórios e bebidas.', 2020, 2023, NULL, '2026-04-01 02:00:05.543', '2025-08-05 22:20:26.534', 470, NULL, 1, 2017, '', NULL, 'SÃO PAULO', 1, NULL, 40, NULL, NULL, '2026-03-08 22:05:53.497', 'https://franquias.portaldofranchising.com.br/franquia-boi-brabo-o-shopping-da-carne-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '430000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ij00c2eh0sw88h0cxi', 'LAVO', 'lavo', NULL, 'Limpeza e Conservação', 'Lavanderia', 'Lavanderia de autoatendimento', 2019, 2020, '[\"https://www.youtube.com/watch?v=cxCxisc4c88\",\"https://www.youtube.com/watch?v=WRxdV4brFsc\"]', '2026-04-01 02:00:05.554', '2025-08-05 22:20:26.539', 471, NULL, 1, 2019, 'Em 2018 depois de ter experimentado o autosserviço em uma viagem aos EUA, pude notar que essa solução vem de encontro ao mercado brasileiro, em especial para cidades que tem altos índices de umidade e a dificuldade de secar roupas, aliado ao fato de que o consumidor não deseja mais investir grandes valores em máquinas de lavar e secar onde o espaço para acomoda-las nos apartamentos está cada vez menor. No mesmo ano, o empresário – que antes da Lavô trabalhou 25 anos na área comercial – começou a pesquisar sobre esse modelo de negócio e resolveu abrir uma unidade de testes em Balneário Camboriú. “Apesar de morar em São Paulo, eu sabia que a concorrência na cidade era muito maior”, explica. “O fato de Balneário Camboriú ser uma cidade litorânea, onde as pessoas sujam muito as roupas, também influenciou na escolha”. Formado em Marketing pela Faculdade Anhanguera, com pós-graduação em Gestão de Projetos (Senac) e especialização em Energia Solar (Unicamp), Donaton criou a Lavô como um modelo de negócio com baixo investimento, retorno rápido e que dispensa contratação de funcionários. O projeto foi um grande sucesso e inspirou a abertura da primeira unidade em outubro de 2019. Nas unidades da marca, o tempo total de utilização do serviço é de aproximadamente uma hora entre lavagem e secagem. Em um ciclo completo, o usuário pode lavar até 10 quilos de roupas (25 peças, em média). O modelo de negócios permite a adoção de um horário de funcionamento flexível – as lojas podem operar 24 horas por dia, sete dias por semana. O público que consome o serviço é variado, incluindo desde jovens solteiros e donas de casa e aposentados. Em julho, a Lavô passou a ser uma das marcas aceleradas pela 300 Franchising, empreendimento liderado pelos irmãos empresários Leandro e Leonardo Castelo, fundadores da Ecoville, a maior rede de produtos de limpeza do país. Com o suporte da 300 Franchising no processo de expansão, a Lavô projeta encerrar o ano com 35 unidades e um faturamento de R$ 700 mil. Para 2021, a projeção é de um total de 120 lojas, com faturamento de R$ 2 milhões. Segundo Donaton, a crise gerada pela pandemia não teve impacto significativo nos negócios da marca. “Com a crise, mudamos alguns planos de inaugurações de unidades, mas esse momento nos fez sair do lugar comum e encontrar outras formas de expandir o negócio. Foi assim que começamos o projeto de expansão e conhecemos a 300 Franchising”, conta o empresário. “Em agosto, a 300 Franchising começou a operar a venda de franquias.”', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c011be04-bd73-4451-b304-209868e0c9b7.jpg', 663, NULL, NULL, '2026-03-08 22:06:13.920', 'https://franquias.portaldofranchising.com.br/franquia-lavo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '211000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75io00c3eh0s60jc3stb', 'SLEEP HOUSE', 'sleep-house', NULL, 'Casa e Construção', 'Móveis e Decoração', 'A Sleep House Colchões é a maior rede multimarcas da América Latina. Atuando desde o ano 2000 conta atualmente com mais de 100 lojas com presença em São Paulo e regiões Sul, Centro Oeste e Nordeste.', 2016, 2021, NULL, '2026-04-01 02:00:05.565', '2025-08-05 22:20:26.544', 472, NULL, 1, 2000, 'A rede de lojas Sleep House Colchões foi fundada no ano 2000 e é hoje a Maior Rede Multimarcas Internacionais de Colchões da America Latina, fazendo parte do Grupo espanhol Pikolin, líder de descanso na Europa e presente em mais de 25 países, contanto com 10 fábricas de colchões e mais de 500 lojas espalhadas pelo mundo. \nNosso franqueado conta com o suporte de quem já atua no mercado há mais de 20 anos tendo fornecido volume superior a 1,5 milhões de colchões para mais de 1 milhão de consumidores. \nAlém de fazer parte de uma marca consolidada, nossos franqueados se beneficiam de outros diferenciais: não tem investimento em estoque, operação de baixa complexidade, alta rentabilidade, zero investimento em logística e produtos exclusivos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/400ad3e9-468f-4f5b-a5c1-55a04f922f96.jpg', 119, NULL, NULL, '2026-03-08 22:07:34.139', 'https://franquias.portaldofranchising.com.br/franquia-sleep-house/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '60000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
