INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75j400c6eh0sl2d2cerh', 'SPÉ O SPA DO PÉ', 'spe-o-spa-do-pe', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Tratamento dos Pés, Venda de Produtos Para o Conforto dos Pés', 1993, 2007, NULL, '2026-04-01 02:00:05.596', '2025-08-05 22:20:26.561', 475, NULL, 1, 1990, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/18c2bae7-9a11-42b5-9dee-10871dbce5fe.png', 17, NULL, NULL, '2026-03-08 22:08:50.127', 'https://franquias.portaldofranchising.com.br/franquia-spe-o-spa-do-pe-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ja00c7eh0soivxjwsi', 'HSH - HOME SUSHI HOME', 'hsh-home-sushi-home', NULL, 'Alimentação', 'Bares e Restaurantes', 'Empresa especializada em delivery de comida japonesa.', 2018, 2019, '[\"https://www.youtube.com/watch?v=T1N81kq_-HA\",\"https://www.youtube.com/watch?v=04WQBH6r9Lc\",\"https://www.youtube.com/watch?v=mE7Bg10trZo\",\"https://www.youtube.com/watch?v=cnTTAySrD_M\"]', '2026-04-01 02:00:05.606', '2025-08-05 22:20:26.567', 476, NULL, 1, 2016, 'A Rede de Franquias HSH, com origem em João Pessoa, é uma empresa que nasceu através da marca HOME SUSHI HOME em 2016, com o objetivo de proporcionar aos clientes a experiência de saborear um sushi de qualidade no conforto de suas casas. Desde o início, a Franquia HSH se destacou por oferecer um cardápio diversificado de sushi, combinando ingredientes frescos e técnicas tradicionais da culinária japonesa. Com um modelo de negócio enxuto e focado no mercado de delivery, a empresa expandiu sua presença para outras regiões do país e hoje atua em 25 cidades (de Norte a Sul). Ao longo dos anos, a Franquia HSH ampliou seu leque de produtos/marcas dentro da mesma estrutura (Poke, Comida asiática quente e Pizza), consolidando uma base fiel de clientes e se tornando referência nacional no segmento de delivery. Agora, busca expandir para outras cidades através de um modelo de Franquia em que o Franqueado opera até 4 marcas com um investimento inicial atrativo (abaixo da média de mercado), custo operacional baixo e diluído e uma equipe multidisciplinar. Isso tudo através de uma logística operacional simples, onde os pedidos de todas as marcas são centralizados em único computador.', NULL, 'PARAÍBA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/32e0841d-13d3-4b18-8f6b-444550768563.jpg', 20, NULL, NULL, '2026-03-08 22:09:14.857', 'https://franquias.portaldofranchising.com.br/franquia-hsh-home-sushi-home/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75jf00c8eh0sl9l6ppz0', 'ISP SAÚDE', 'isp-saude', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Comércio/Distribuição de Equipamentos e Produtos Médicos, Ortopédicos, Eletroterapia, Ginástica, Fitness e Outros Produtos para Saúde, Beleza e Bem-Estar.', 2014, 2015, NULL, '2026-04-01 02:00:05.616', '2025-08-05 22:20:26.572', 477, NULL, 1, 1996, '', NULL, 'PARANÁ', 1, NULL, 20, NULL, NULL, '2026-03-08 22:10:00.314', 'https://franquias.portaldofranchising.com.br/franquia-isp-saude-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75jl00c9eh0spihn5ry3', 'ENJOY', 'enjoy', NULL, 'Educação', 'EDUCAÇÃO', 'Única Rede de Escolas de Inglês Profissionalizante com metodologia própria e realidade aumentada, unindo o inglês, tecnologia e 4 áreas de formação profissionalizante para jovens de 11 a 18 anos.', 2015, 2017, NULL, '2026-04-01 02:00:05.625', '2025-08-05 22:20:26.577', 478, NULL, 1, 2007, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3a6dac3e-f093-4d3f-86e5-32dbb334fefc.svg', 77, NULL, NULL, '2025-05-07 11:10:15.000', 'https://franquias.portaldofranchising.com.br/franquia-enjoy/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75jr00caeh0synkz74uh', 'PEIXINHO FELIZ', 'peixinho-feliz', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escola de Educação Infantil para crianças a partir de 4 meses de idade. Metodologia exclusiva e inovadora. Investimentos flexíveis. Suporte permanente. Garantia de resultados.', 2011, 2022, '[\"https://www.youtube.com/watch?v=NxmSSGVphxk\"]', '2026-04-01 02:00:05.634', '2025-08-05 22:20:26.583', 479, NULL, 1, 2002, 'A Escola de Educação Infantil Peixinho Feliz nasceu do desejo da sua idealizadora, Damir Forner, de promover mudanças na prática pedagógica da educação infantil e contribuir para a sua melhoria. A finalidade primordial da escola é oferecer às crianças amor e segurança e aos pais a tranquilidade necessária para desempenhar suas atividades profissionais, sabendo que seus filhos estão recebendo cuidados, educação e acompanhamento personalizado do seu aprendizado e desenvolvimento. A Franquia Peixinho Feliz nasceu em 2004, após intensos e consistentes estudos desenvolvidos na área da Pedagogia, Psicopedagogia, da Linguística e da Neurociência. A metodologia Peixinho Feliz é decorrência de estudos teóricos e práticos realizadas no Brasil e no Exterior, principalmente nos Estados Unidos. Desde os seus primeiros passos, a Peixinho Feliz tem obtido um grande sucesso no planejamento, execução e formatação da Franquia com sistemas didáticos, pedagógicos, operacionais, administrativos e financeiros, testados e em permanente evolução. A Franquia Peixinho Feliz é ideal para empresários, empreendedores e novos investidores, que não precisam ser da área da educação, e que buscam uma opção de negócio seguro e rentável em um dos segmentos que mais cresce no Brasil. Tudo com o respaldo de uma marca que é referência em Educação Infantil de qualidade.', NULL, 'SANTA CATARINA', 1, NULL, 8, NULL, NULL, '2026-03-08 22:10:38.092', 'https://franquias.portaldofranchising.com.br/franquia-peixinho-feliz/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '340000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
