INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75kk00cdeh0soij7icvz', 'ULTRA', 'ultra', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Academia de ginástica com posicionamento \"High Value Low Price\"(HVLP), que oferece um serviço de alto valor percebido por um preço de entrada acessível.', 2020, 2021, NULL, '2026-04-01 02:00:05.661', '2025-08-05 22:20:26.613', 482, NULL, 1, 2020, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/630b7d12-fafe-4ede-bc05-06d96e25eac3.png', 75, NULL, NULL, '2026-03-09 15:19:08.348', 'https://franquias.portaldofranchising.com.br/franquia-ultra/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1400000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75kw00ceeh0sjpyo37z6', 'INSTITUTO GOURMET FORMAÇÃO PROFISSIONAL', 'instituto-gourmet-formacao-profissional', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'O Instituto Gourmet é a maior rede nacional de franquia em cursos profissionalizantes em gastronomia criado para quem deseja ingressar no mercado gastronômico, empreender e obter formação profissional', 2016, 2017, '[\"https://www.youtube.com/watch?v=5xqFvnRuon4\",\"https://www.youtube.com/watch?v=1jV4RsbMyf0\",\"https://www.youtube.com/watch?v=rDqNqP3kdQY\",\"https://www.youtube.com/watch?v=4wuPjmtt9Ms\"]', '2026-04-01 02:00:05.670', '2025-08-05 22:20:26.624', 483, NULL, 1, 2014, 'Instituto Gourmet - A Revolução do Empreendedorismo Gastronômico no Brasil Em 2014, na cidade de Serra, Espírito Santo, nasceu um sonho: transformar vidas através da gastronomia. Assim surgiu o Instituto Gourmet Brasil, uma marca que ensina técnicas gastronômicas de forma prática, presencial, empodera pessoas a mudarem suas histórias e trilharem um caminho de sucesso dentro desse segmento. Fundado com a visão de democratizar o acesso ao conhecimento gastronômico de alta qualidade, o Instituto Gourmet rapidamente ganhou destaque. Seu impacto foi tão significativo que, apenas dois anos depois da inauguração e início da operação no Espírito Santo, a marca expandiu para o estado do Rio de Janeiro, iniciando sua operação em Duque de Caxias. O sucesso foi instantâneo. As salas de aula lotadas e as histórias de transformação pessoal e profissional tornaram-se a marca registrada da operação. Em 2016, impulsionado pelo impacto gerado e pela alta demanda, o Instituto Gourmet deu um passo ousado: adotou o modelo de franquias. Sob a liderança visionária do CEO Glaucio Paiva Athayde, o crescimento foi meteórico. Hoje, com mais de 110 escolas espalhadas por todo o Brasil, a marca é referência no segmento de educação gastronômica, formando empreendedores, entusiastas e profissionais do setor. Ao longo de sua trajetória, mais de 100 mil alunos já passaram pelo Instituto Gourmet. Muitos deles buscam aprimorar técnicas, conquistar uma nova profissão, aprender por hobby e saem com suas vidas transformadas. Relatos de empreendedorismo bem-sucedido, superação, e reconhecimento profissional estão no DNA da marca em todas as regiões do país. “Hoje, nosso franqueado tem o poder de transformação social no território que está inserido, levando aos alunos através da gastronomia e do empreendedorismo, uma mudança de vida”, reforça Glaucio Athayde, CEO. O Instituto Gourmet não é apenas uma escola de gastronomia, é um movimento. Um movimento que conecta propósito, técnica e empreendedorismo. Liderado por um time que acredita na força do conhecimento, a marca continua a inspirar milhares de brasileiros a saírem da zona de conforto e construírem um futuro mais saboroso e promissor. E a história continua. O próximo capítulo? Ser escrito pelas mãos daqueles que ousam sonhar. Uma marca com essência e propósito. Afinal, no Instituto Gourmet, cozinhar é transformar vidas.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ae657528-1005-47f5-8c6a-d3d350ea8b1e.jpg', 102, NULL, NULL, '2026-03-08 22:12:31.491', 'https://franquias.portaldofranchising.com.br/franquia-instituto-gourmet-formacao-profissional/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '294000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
