INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75li00cheh0swh07ag5b', 'WCHIC', 'wchic', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Franquia especializada em Locação de banheiros móveis de luxo, com alta tecnologia, equipamentos e estruturas de uso temporário para Eventos.', 2014, 2014, NULL, '2026-04-01 02:00:05.698', '2025-08-05 22:20:26.646', 486, NULL, 1, 2014, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6b092492-a4d0-4b97-b50e-3e4808e6f201.png', 3, NULL, NULL, '2025-09-09 12:11:36.000', 'https://franquias.portaldofranchising.com.br/franquia-wchic-negocios-e-servicos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75lq00cieh0spbeuiz1m', 'OPT ÓCULOS', 'opt-oculos', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Comércio varejista de armações de óculos, lentes de grau e acessórios para óculos', 2018, 2019, '[\"https://www.youtube.com/watch?v=E5oW5qTEP9M\"]', '2026-04-01 02:00:05.706', '2025-08-05 22:20:26.655', 487, NULL, 1, 2018, 'Fundada em 2018, a Opt Óculos nasceu do desejo do seu fundador que, após 20 anos de experiência no segmento óptico, acreditava que a compra dos óculos poderia ser uma experiência mais agradável e descomplicada. \nPara criar essa experiência, a rede investe em tecnologia e pessoas, oferecendo vários canais de contato integrados, sem abrir mão do atendimento humanizado. \nAtuando inicialmente no interior de São Paulo, a partir de 2019 a rede iniciou o processo de expansão através do modelo de franquias com a missão de levar o conceito Opt Óculos a um número cada vez maior de brasileiros. \nAtualmente, a rede possui 34 lojas nos estados de São Paulo, Paraná, Santa Catarina e Rio Grande do Sul, e a perspectiva é de chegar a 300 lojas em até 2 anos através de 3 formatos de loja diferentes: Standard: Lojas de rua com até 40m². Full: Lojas de rua com aproximadamente 70m². Shopping: Lojas com aproximadamente 50m². Ser franqueado Opt Óculos traz uma série de vantagens como: Modelo de negócio Omnichannel com crescimento sustentável e e-commerce compartilhado com os franqueados.\n\t  Ótimo relacionamento e negociação com os principais fornecedores do segmento.\n\t  Constante investimento em tecnologia para oferecer as melhores ferramentas de gestão e vendas aos franqueados.\n\t  Plataforma EAD para capacitação e treinamento de toda equipe técnica e vendas.\n\t  Alto investimento em publicidade local e regional em mídias online e offline.\n\t  Laboratório próprio com equipamentos digitais de última geração.\n\t  Ações sociais para promover impactos positivos junto às vizinhanças das franquias. A Opt Óculos oferece suporte completo aos seus franqueados, permitindo que estes se concentrem exclusivamente na área comercial, enquanto toda a gestão da loja é feita pela Central de Gestão Opt.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7c0b1be2-cf29-4e9d-9fc5-fd56549ba40f.svg', 42, NULL, NULL, '2026-03-08 22:14:50.249', 'https://franquias.portaldofranchising.com.br/franquia-opt-oculos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '195000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ly00cjeh0skxa6j0vk', 'MEX BURRITOS (MARCA MISTA)', 'mex-burritos-marca-mista', NULL, 'Alimentação', 'Bares e Restaurantes', 'Loja de shopping, loja de rua, casual dinner e Dark kitchen', 2020, 2024, NULL, '2026-04-01 02:00:05.715', '2025-08-05 22:20:26.662', 488, NULL, 1, 2020, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/18376e5d-c22f-4a8c-a68c-a8efbf3366e0.svg', 34, NULL, NULL, '2026-03-08 22:15:50.869', 'https://franquias.portaldofranchising.com.br/franquia-mex-burritos-marca-mista-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75m500ckeh0svd17zooa', 'VICOFLORA', 'vicoflora', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Farmacia de manipulação de formulas, cosméticos e produtos naturais. Linha completa suplementos alimentares para atletas e geriatria.', 1994, 2013, NULL, '2026-04-01 02:00:05.725', '2025-08-05 22:20:26.669', 489, NULL, 1, 1986, 'Com 27 anos de experiência no mercado magistral, a qualidade de nossos produtos e serviços tem sido a receita do sucesso de nossa franquia. \nCom credibilidade no mercado, inovamos na criação do Centro Técnico e Científico, onde a realização de pesquisas e desenvolvimento de novos produtos são prioridades. Criamos uma farmácia de manipulação moderna, onde o principal objetivo é a excelência da qualidade.\n  \nTransferimos aos nossos franqueados, todo o know-how necessário para administração do negocio, desde a gestão administrativa, área técnica, atendimento até o marketing médico e técnico. Nossos treinamentos são realizados de forma contínua, em sintonia com o mercado e a legislação em vigor.    Manipulamos todas as substâncias permitidas no Brasil, em todas as especialidades, com todos os prescritores autorizados.  \nNosso suporte oferece a segurança para os que estão entrando no segmento, já que nossa equipe é responsável pela aprovação de projetos sanitários, licenças e documentação junto à ANVISA.    \nSomos referência no segmento, não somente pela qualidade de nossos produtos, mas também, pela qualidade de nosso suporte técnico, avaliado pela Revista Pequenas Empresas & Grandes negócios, como a melhor da categoria. Por tudo isso, somos a Franquia de farmácia de manipulação mais premiada em 2013 e 2014.   VANTAGENS DO NEGÓCIO: TRANSFERÊNCIA DO KNOW-HOW \n• Gestão do Negócio\n• Projeto Arquitetônico e Documentação Sanitária\n• Manipulação de todas as substâncias permitidas no Brasil\n• Franqueadora certificada pela ISO 9000.\n• Equipe formada por profissionais habilitados, com experiência no mercado magistral. \nNossa equipe de suporte técnico oferece segurança aos franqueados, pois acompanham o mercado e a legislação sanitária. \nNossos treinamentos e reciclagem profissional são contínuos, tanto aos franqueados, quanto aos seus funcionários.   Ser um franqueado Vicoflora é ter uma receita de sucesso!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/94cebf20-70df-4008-a4b3-e6ba5994a188.jpg', 9, NULL, NULL, '2026-03-08 22:16:14.312', 'https://franquias.portaldofranchising.com.br/franquia-vicoflora-farmacias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ma00cleh0sprm4j3m1', 'SAMSONITE', 'samsonite', NULL, 'Moda', 'Acessórios Pessoais', 'A franquia House of Samsonite apresentará aos consumidores três das marcas mais consagradas da multinacional americana: Samsonite, marca líder no mercado global, assim como American Tourister e Xtrem.', 2018, 2018, NULL, '2026-04-01 02:00:05.734', '2025-08-05 22:20:26.675', 490, NULL, 1, 1910, '', NULL, 'SÃO PAULO', 1, NULL, 59, NULL, NULL, '2026-03-09 15:20:36.318', 'https://franquias.portaldofranchising.com.br/franquia-samsonite-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '560000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75mg00cmeh0sxsezm55b', 'SKYLER', 'skyler', NULL, 'Moda', 'VESTUÁRIO', 'Marca de moda masculina \"Lifewear\": \"vestindo a vida\". Para qualquer ocasião e momento da vida! Conta com 5 linhas de produto com foco na versatilidade e satisfação do cliente.', 2005, 2021, NULL, '2026-04-01 02:00:05.743', '2025-08-05 22:20:26.680', 491, NULL, 1, 1997, '', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/33478699-fd4e-474d-b62b-bd957ebb4c7a.svg', 63, NULL, NULL, '2025-11-03 16:24:56.000', 'https://franquias.portaldofranchising.com.br/franquia-skyler/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ml00cneh0spklrfro8', 'NOW NUTRIÇÃO ESPORTIVA', 'now-nutricao-esportiva', NULL, 'Saúde, Beleza e Bem Estar', 'ESPORTE E RECREAÇÃO', 'Maior rede de suplementos alimentar e artigos para uma vida saudável, focada em atletas profissionais e amadores.', 2014, 2014, '[\"https://www.youtube.com/watch?v=DsqsrEa0uRs\"]', '2026-04-01 02:00:05.752', '2025-08-05 22:20:26.685', 492, NULL, 1, 2004, 'A Now! é uma marca consolidada no segmento de suplementação e nutrição esportiva, que atua há mais de 10 anos no mercado e seu nome é sinônimo de qualidade, atendimento de alto padrão para seus clientes e preços atrativos para o público. A loja trabalha somente com produtos Linha A certificados pela ANVISA, garantindo, assim, que o consumidor sempre tenha em mãos as melhores marcas que o mercado tem a oferecer. Os colaboradores das lojas são pessoas treinadas e adeptas, também, para realizar uma consultoria de suplementação para qualquer um. FRANQUIAS Com muito esforço, dedicação e comprometimento diário, hoje contam com diversas lojas próprias e muitas franquias, num total de mais de 70 lojas, localizadas nos melhores Shoppings de São Paulo e região. Com mais de 300 mil vendas realizadas no ano de 2023 e faturamento anual de 55 milhões de reais. A projeção para 2024 é de 75 milhões de reais.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/86330ad9-3f08-4023-8fe1-de5f1b599e14.jpg', 55, NULL, NULL, '2025-05-08 00:00:15.000', 'https://franquias.portaldofranchising.com.br/franquia-now-nutricao-esportiva-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
