INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75n100cqeh0sq7iy7ovr', 'RHOPEN CONSULTORIA', 'rhopen-consultoria', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Consultoria de Recursos Humanos com soluções de carreira e negócios para todos os subsistemas de Gestão de Pessoas.', 2019, 2020, NULL, '2026-04-01 02:00:05.780', '2025-08-05 22:20:26.702', 495, NULL, 1, 2011, '', NULL, 'ESPÍRITO SANTO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/831a974e-64b9-43bb-9c26-bbd57f80bc1b.png', 9, NULL, NULL, '2026-03-08 22:18:42.208', 'https://franquias.portaldofranchising.com.br/franquia-rhopen-consultoria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75n800creh0sx7rjs0bu', 'ECOPOWER ENERGIA SOLAR', 'ecopower-energia-solar', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Soluções em Energia Energia Solar, Energia Fotovoltaica, Integradora De Energia, Sustentabilidade, Energia Renovável.', 2019, 2021, '[\"https://www.youtube.com/watch?v=A0sUnxDDq-c\",\"https://www.youtube.com/watch?v=So7R4KiO8E0\",\"https://www.youtube.com/watch?v=S_qj_dQoxTI\",\"https://www.youtube.com/watch?v=DdqlDT5Hq0M\"]', '2026-04-01 02:00:05.790', '2025-08-05 22:20:26.708', 496, NULL, 1, 2013, 'A EcoPower é a líder brasileira em integração de energia solar nos sistemas fotovoltaicos. Desde nossa fundação em 2013, em Barretos, SP, pelos visionários Anderson e Náchila Oliveira, crescemos de forma impressionante. Com 38 mil projetos homologados pela ANEEL e mais de 350 franquias em todo o Brasil, nossa equipe de mais de 500 colaboradores se dedica a oferecer soluções energéticas de alta qualidade. Nossa operação presente nas 27 unidades federativas do Brasil. Orgulhamo-nos de ser uma das poucas empresas do setor com frota própria, percorrendo centenas de milhares de quilômetros mensais para atender nossos clientes com rapidez e eficiência. Nossa trajetória é marcada por dois pilares fundamentais: Eco, que reflete nosso compromisso com a sustentabilidade, e Power, que demonstra nossa expertise em energia. Nossas soluções personalizadas e integradas atendem às diversas necessidades dos clientes, garantindo qualidade e inovação. Somos Eco, Somos Power, Somos a energia que move o futuro.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3409df0a-478f-4590-b07d-8ccf339e0617.png', 340, NULL, NULL, '2026-03-08 22:19:09.275', 'https://franquias.portaldofranchising.com.br/franquia-ecopower-energia-solar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '17500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ni00cseh0s6jr7mq5k', 'KOPENHAGEN', 'kopenhagen', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'BOMBONIÉRE E CAFETERIA - CHOCOLATERIA.', 1992, 1991, '[\"https://www.youtube.com/watch?v=dcGAaEfnS-k\",\"https://www.youtube.com/watch?v=aWd0rsFoPFs\"]', '2026-04-01 02:00:05.799', '2025-08-05 22:20:26.718', 497, NULL, 1, 1928, 'São mais de 95 anos de história e experiência consolidada como franqueadora, superando 570 pontos de venda em 27 estados do Brasil nos modelos de lojas e quiosques. \nQuem conhece a Kopenhagen garante sabores irresistíveis que transcendem gerações e acompanham a vida de muitas pessoas. Somos 100% digitais, atuamos nos principais canais de venda online e possuímos uma base de CRM forte e estruturada com mais de 3MM de clientes.  Ser parte do time Kopenhagen é pertencer a uma marca protagonista e desbravadora, que é reconhecida e celebrada pelos clientes e pelo mercado de atuação.\n     Venha fazer parte dessa história de sucesso!', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e0c71948-2509-4739-97b2-2231123fee5e.png', 780, NULL, NULL, '2026-03-08 22:19:53.946', 'https://franquias.portaldofranchising.com.br/franquia-kopenhagen-bebidas-cafe-doces-e-salgados/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/67f53e36-b5be-437c-871c-a138a8e9618d.png\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '280000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75nn00cteh0s2f48f2ah', 'R-CRIO CÉLULAS-TRONCO', 'r-crio-celulas-tronco', NULL, 'Saúde, Beleza e Bem Estar', 'SERVIÇOS MÉDICOS', 'Produtos e serviços técnicos especializados de coleta de células-tronco mesenquimais provenientes do dente decíduo (dente de leite), terceiro molar (dente do siso), periósteo do palato, tecido adiposo', 2020, 2022, '[\"https://www.youtube.com/watch?v=ccTxKr8HZos\",\"https://www.youtube.com/watch?v=Mez4Pk9ec7I\"]', '2026-04-01 02:00:05.809', '2025-08-05 22:20:26.724', 498, NULL, 1, 2014, 'A R-Crio Células-tronco nasceu com o propósito de garantir para a população brasileira mais qualidade de vida associada à já conquistada longevidade. Desde 2014, ano de início das operações comerciais, a empresa busca promover soluções para a população ter acesso à medicina regenerativa, uma nova forma de medicina que busca regenerar células para tratar doenças comuns do envelhecimento. Nessa época, o laboratório iniciou suas coletas por meio da polpa dentária de dentes de leite e dentes do siso, o que fez se tornar conhecida de dentistas do Brasil inteiro. Em 2020 passou a coletar células-tronco de adultos e idosos por meio do Céu da Boca (periósteo do palato) e também do tecido adiposo. Esse último com profissionais médicos como coletores. O processo de coleta da R-Crio é prático e intuitivo para os profissionais coletores e também para as famílias. A coleta da R-Crio pouco incide na rotina da clínica ou do consultório, mas permite trazer uma nova forma de faturamento e fidelização por meio do serviço inovador e único oferecido. Durante esses anos, a R-Crio desenvolveu mais de 50 artigos científicos, 12 patentes com depósitos nacionais e internacionais, 8 livros dedicados a inovação em Medicina e Odontologia Regenerativas, projetos de pesquisa, participação em bancas de especialização, mestrado e doutorado com entidades de renome e referência, além de possuir hoje, em sua sede em Campinas/SP, um laboratório de pesquisa e desenvolvimento de biomateriais para serem associados às células armazenadas para oferecer uma solução completa para a saúde dos clientes. Hoje, a empresa conta também com iniciativas internacionais, possuindo uma cadeira técnico-científica na Universidade de Laval, em Quebéc, no Canadá, e um escritório dentro do Laboratório de Ciências da Vida, localizado na área do Kennedy Space Center, local de treinamento da NASA, na Flórida. Por conta de tanta atuação em pesquisa científica comprometida com entrega de soluções para a saúde, a R-Crio se tornou referência em criopreservação e processamento de células-tronco no Brasil, oferecendo diferentes vantagens e diferenciais para seus clientes, como: Qualidade técnica: cultivar células em meio de cultura de soro humano, garantindo mais estabilidade genética, e realizar treinamento com todo profissional coletor, exigindo também o envio de alvará sanitário vigente anualmente; Transparência: notificar o cliente sobre os estágios do processo laboratorial em tempo real, e emitir um Certificado de Criopreservação impresso em papel moeda ao cliente no final do processo; Informação: enviar frequentemente notificações aos clientes atualizações da área da medicina regenerativa, bem como realizar consultorias com médicos no caso de solicitação do produto para uso. Razões para se tornar um Franqueado R-Crio Células-tronco O serviço da R-Crio se torna cada vez mais contemporâneo, uma vez que os desafios da medicina se tornam maiores com o aumento da expectativa de vida e, consequentemente, das doenças crônicas-degenerativas, as quais não possuem cura e muitas consistem no envelhecimento - ou mal funcionamento - das células do organismo por conta do avanço da idade. A R-Crio está levando à investidores do Brasil todo a possibilidade de oferecer essa forma de prevenção e acesso à saúde por meio de uma rede franqueada suportada por diferentes iniciativas com foco no sucesso da operação do franqueado, sendo elas: Fidelização de pacientes e inovação: franqueados poderão levar para suas regiões um serviço garantido por exclusividade territorial, se destacando ainda mais em um mercado denso de profissionais de saúde e clínicas especializadas. Rapidez no retorno do investimento: a franquia R-Crio pode ser alocada dentro de uma clínica já estabelecida, significando mais agilidade para início das operações. Assistência de marketing, vendas, recursos humanos e processos: todo know-how do laboratório é repassado ao franqueado, bem como realizadas assistências continuadas, treinamentos e consultoria de seleção de ponto comercial; Portal de Relacionamento com Franqueado: intranet para gestão de vendas, notificações, recebimento de materiais de marketing digital e gestão de pós-vendas de serviços de clientes. TIPOLOGIAS DE UNIDADES FRANQUEADAS O Sistema de Franquia R-Crio Células-tronco prevê a utilização de espaços físicos em 3 modelos operacionais: • TIPO 1 Clínicas ou consultórios médicos ou odontológicos, localizadas em estruturas de Shopping Centers, Centros ou Galerias Médicas e Odontológicas, Avenidas, Regiões Metropolitanas de Capitais de Estados e Municípios polo acima de 100.000 mil habitantes, com metragem mínima a partir de 20m². • TIPO 2 Clínicas ou consultórios médicos ou odontológicos que operam no modelo de negócio Franquia Empresarial (franchising), localizadas em estruturas de Shopping Centers, Centros ou Galerias Médicas e Odontológicas, Avenidas, Regiões Metropolitanas de Capitais de Estados e Municípios-polo acima de 100.000 mil habitantes, com metragem mínima a partir de 20m². • TIPO 3 Estruturas médicas e odontológicas que realizam atividades comercial e operacional de saúde em escala de rede hospitalar ou laboratorial privada, localizadas em Parques Tecnológicos, Shopping Centers, Centros ou Galerias Médicas e Odontológicas, Avenidas, Regiões Metropolitanas de Capitais de Estados e Municípios polo acima de 100.000 mil habitantes, com metragem mínima a partir de 40m²', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/03a5fcfb-dab8-4211-bc1a-1a74a2b217c0.jpg', 5, NULL, NULL, '2025-09-09 16:06:11.000', 'https://franquias.portaldofranchising.com.br/franquia-r-crio-celulas-tronco/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75nt00cueh0s1x5856em', 'TOTAL CLEAN', 'total-clean', NULL, 'Limpeza e Conservação', 'Serviços de Limpeza', 'Limpeza e impermeabilização de estofados.', 2017, 2022, '[\"https://www.youtube.com/watch?v=EQUljpIY1V8\",\"https://www.youtube.com/watch?v=QilFO_K60qo\",\"https://www.youtube.com/watch?v=-OK2Sil_qds\"]', '2026-04-01 02:00:05.819', '2025-08-05 22:20:26.729', 499, NULL, 1, 2016, 'Especialista em limpeza e impermeabilização de estofados e tapetes, a Total Clean está em constante inovação e oferece sempre um alto padrão de qualidade na prestação de serviço, além de ser referência nacional no segmento. \nMais de 100 mil clientes já foram atendidos por nossas unidades, por meio de nosso exclusivo sistema de prestação de serviço, utilizando sempre produtos de altíssima qualidade, proporcionando um resultado e experiência única para nossos clientes.  Invista em uma marca consolidada no mercado nacional de franquias, que já recebeu diversos prêmios ao longo dos anos.   \nÉ a segurança e solidez que seu investimento precisa, venha fazer parte da Total Clean! A Total Clean tem orgulho em ter 53% dos franqueados são multifranqueados (franqueados que possuem mais de uma unidade da marca). Índice esse que reflete muito o sucesso no modelo de negócio. Além disso, para o sucesso do negócio é importante também ter: energia, presença, dedicação, senso de dono e muito empenho.', NULL, 'ESPÍRITO SANTO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fb47a88c-fe91-4aca-9d98-7f2d9a7c1c5e.jpg', 229, NULL, NULL, '2026-03-08 22:20:36.728', 'https://franquias.portaldofranchising.com.br/franquia-total-clean/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/97fa906b-e88c-4645-8ea2-10cffe16fe58.jpeg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cb787555-ffd2-42bb-9e9e-8a4efe534155.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '39900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
