INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75o600cweh0sa8o1un4m', 'MEI MEI CULINÁRIA ASIÁTICA', 'mei-mei-culinaria-asiatica', NULL, 'Alimentação', 'Bares e Restaurantes', 'Mei Mei Culinária Asiática oferece o melhor do fast food em shoppings, com pratos rápidos e saborosos, ideais para quem busca uma experiência culinária asiática prática e com qualidade.', 2008, 2023, NULL, '2026-04-01 02:00:05.838', '2025-08-05 22:20:26.742', 501, NULL, 1, 1991, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1047328b-486f-46c7-a7f0-7b328bd8729c.png', 38, NULL, NULL, '2026-03-08 22:21:39.908', 'https://franquias.portaldofranchising.com.br/franquia-mei-mei-culinaria-asiatica-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ob00cxeh0sbl1qsa9f', 'GRUPO ACOLHER & CUIDAR', 'grupo-acolher-cuidar', NULL, 'Saúde, Beleza e Bem Estar', 'SERVIÇOS MÉDICOS', 'Atuamos no paciente com necessidades de atenção de pequena a alta complexidade, com ênfase na recuperação e qualidade de vida em âmbito domiciliar, hospitalar e em viagens.', 2021, 2022, '[\"https://www.youtube.com/watch?v=rX6q8xTQaqY\"]', '2026-04-01 02:00:05.847', '2025-08-05 22:20:26.748', 502, NULL, 1, 2016, 'O Grupo Acolher e Cuidar Franchising nasceu em 2016 em Brasília-DF, com foco na realização da prestação de serviços domiciliares em saúde através do atendimento de cuidador de idosos. A rede atua no ramo de home care em atendimento de pacientes com necessidades de cuidados de baixa, média e alta complexidade, com destaque para os serviços na área de reabilitação e qualidade de vida, prezando acima de tudo pelo conforto e segurança. O franqueado precisa de um ponto físico para operar e são disponibilizados três modelos de franquias: unidade fit, premium e home care, com investimento a partir de R$ 67 mil e prazo de retorno previsto em 16 meses. Nos diferenciamos das demais franquias através da operação validada, conte com quem já chegou lá e conhece o caminho do sucesso, uma estrutura simplificada com o sistema de locação de aparelhos tendo um investimento mínimo em estrutura. Além disso, dispomos de um modelo padronizado, pronto para começar a faturar, oferecemos manuais operacionais de apoio para a implantação e gestão da sua unidade. Contamos com um suporte técnico, nossa equipe especializada irá auxiliá-lo no dia a dia de sua unidade e possuímos um sistema personalizado, um software desenvolvido especialmente para a Franquia Grupo Acolher & Cuidar.', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/527430e4-36b0-4380-b3bd-a6f0f2ebc024.svg', 14, NULL, NULL, '2025-09-01 12:17:11.000', 'https://franquias.portaldofranchising.com.br/franquia-grupo-acolher-cuidar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75og00cyeh0sckfota04', 'RONALDO ACADEMY', 'ronaldo-academy', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Com uma metodologia própria, a Ronaldo Academy nasceu com a missão de espalhar por todo o mundo o estilo de jogo Fenomenal que fez do Ronaldo um dos jogadores mais importantes da história do futebol.', 2015, 2016, NULL, '2026-04-01 02:00:05.856', '2025-08-05 22:20:26.753', 503, NULL, 1, 2015, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c57860f2-54c2-4bb9-8dea-0ecf77889943.jpg', 39, NULL, NULL, '2026-03-08 22:22:04.769', 'https://franquias.portaldofranchising.com.br/franquia-ronaldo-academy/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ol00czeh0s0lnym3fx', 'CHIQUINHO', 'chiquinho', NULL, 'Alimentação', 'Docerias, Padarias e Cafés', 'Com uma receita exclusiva e mais de 100 produtos em seu cardápio a Chiquinho Sorvetes se consolidou como a maior rede de sorveterias do Brasil.', 2010, 2025, NULL, '2026-04-01 02:00:05.866', '2025-08-05 22:20:26.758', 504, NULL, 1, 1980, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b0110953-1621-43fc-bc73-cc405b5559b1.png', NULL, NULL, NULL, '2026-03-08 22:22:30.464', 'https://franquias.portaldofranchising.com.br/franquia-chiquinho-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ou00d0eh0s9okaw4hc', 'L`ENTRECÔTE DE PARIS', 'l-entrecote-de-paris', NULL, 'Alimentação', 'Bares e Restaurantes', 'Restaurante de prato único, leva a uma experiência sensorial em uma autêntica brasserie parisiense. Prato principal é o famoso entrecôte, servido com molho secreto e batatas fritas à vontade.', 2012, 2012, NULL, '2026-04-01 02:00:05.875', '2025-08-05 22:20:26.766', 505, NULL, 1, 2008, 'O clássico agora nas casas dos brasileiros \nAlto valor agregado, alta rentabilidade e agora com modelo enxuto com novas áreas de expansão. O L’Entrecôte de Paris é uma rede de restaurantes com prato único, com uma marca líder e reconhecida há mais de 10 anos no mercado. \nO suculento entrecôte fatiado recoberto pelo molho secreto é oferecido pelo conceituado restaurante L’Entrecôte de Paris por todo o país desde 2009, agora traz a mesma sofisticação e qualidade para a casa dos seus clientes através do Delivery.  A receita: Foram necessários dez anos de pesquisas para recriar o molho servido na capital francesa. \nDesde novembro de 2009, quando o L’Entrecôte de Paris abriu as portas, a clientela pode saborear o contrafilé banhado na consistente combinação de 21 ingredientes, que leva 36 horas para ficar pronta. \nPara garantir um padrão de excelência em todas as franquias, os restaurantes seguem rigorosamente o mesmo padrão da unidade fundada em 2009 e, claro, o famoso molho secreto, que é enviado para todas as unidades diretamente da fábrica. E estratégias de comunicação, comercialização e de gestão de relacionamento com o cliente também são transferidas da matriz para as franquias.  Novo modelo: Após mais de 10 anos de sucesso no mercado, com unidades espalhadas pelas principais capitais do país, e contabilizando mais de 500 mil pratos servidos, o L’Entrecôte de Paris iniciou em 2020 o modelo de negócio exclusivo para o delivery. Franquia de Delivery: A rede está em expansão para todo o Brasil com um modelo de franquia dark-kitchen, ou seja, 100% focada para o delivery. Com a franquia delivery L’Entrecôte de Paris você tem baixo investimento inicial, facilidade no dia a dia da operação e uma maior margem de lucro. \nDiferenciais de ter uma franquia L’Entrecôte de Paris Delivery: \n* Não requer fachada nem estrutura de salão;\n* Economia com operacional de atendimento;\n* Aluguéis mais baratos do que em pontos como ruas de comércio e shoppings.\n* Parceria exclusiva com o aplicativo iFood \n* Nossos franqueados têm acesso a taxas diferenciadas, significativamente menores;\n* Temos posicionamento destacado no app.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/11a33e60-2d54-48b9-b7e1-ddb740bc76bd.jpg', 28, NULL, NULL, '2026-03-08 22:22:57.119', 'https://franquias.portaldofranchising.com.br/franquia-lentrecote-de-paris-restaurantes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '700000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75oz00d1eh0suhunzbj5', 'BORDA E LENHA', 'borda-e-lenha', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO COMPLETO', 'Pizzaria Delivery', 2022, 2023, NULL, '2026-04-01 02:00:05.885', '2025-08-05 22:20:26.772', 506, NULL, 1, 2015, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/dbda0520-519f-4c8d-a8b1-5a7884a3fb9b.jpg', 24, NULL, NULL, '2025-08-15 15:11:42.000', 'https://franquias.portaldofranchising.com.br/franquia-borda-e-lenha/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75p500d2eh0scn8yjenp', 'HAVANNA', 'havanna', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'CAFETERIA ARGENTINA', 1998, 2015, NULL, '2026-04-01 02:00:05.894', '2025-08-05 22:20:26.777', 507, NULL, 1, 1939, 'COMO SURGIU A HAVANNA! \nA história da Havanna começou a ser escrita em 1939, quando o entusiasmo de dois jovens amigos e empreendedores falou mais alto, se expandiu e transformou-se em um dos maiores ícones da Argentina! Os Alfajores Santa Monica, como eram comercializados no inicio de sua história, eram produzidos em uma pequena fábrica em Buenos Aires, tendo como um de seus principais clientes uma bomboniere de Mar Del Plata. \nA partir de uma relação comercial muito boa, nasceu uma grande amizade que fortaleceu a oportunidade de expansão da empresa, desafiando os dois amigos. \nLogo, a marca Havanna se tornou sinônimo de Alfajor e símbolo de prazer, já que naquela época os argentinos e turistas passavam as férias no balneário e compravam os doces para presentear amigos e familiares. Possuem a mesma receita desde 1947, que foi aprimorada pelas mãos do pasteleiro Toribio Gonzáles; Hoje na Argentina são 202 lojas, sendo 59 próprias e 141 franqueadas. \nNo exterior são 92 pontos de venda, além dos pontos de distribuição em todo o mundo. \nA Chegada da Havanna no Brasil foi em 2006. O sucesso foi instantâneo e não demorou muito para que outras lojas e quiosques fossem inaugurados pelo país. A partir de 2014, com a adoção do sistema de franquia, a expansão nacional foi acelerada. \nA marca trabalha com dois modelos de negócio: Café Quiosque e Cafeteria. Hoje são mais de 50 pontos de venda espalhados por 18 estados brasileiros. \n  MISSÃO, VISÃO E VALORES!\n  Quem não gosta de ter uma experiência de consumo única? Fundamentada em conforto, acessibilidade, inovação e sabores que sejam ligados e fiéis aos valores, a verdade da marca Havanna são os seus principais pilares: Alfajor, Doce de Leite, Argentina. O modelo de negócios Havanna é baseado em excelência, ética, melhoria contínua, superação de resultados, comprometimento, valorização humana, experiência de qualidade, inovação, respeito aos valores e à verdade\nda marca e seus produtos, estabelecendo relações de transparência, integridade e respeito com fornecedores, colaboradores, clientes!   LOCALIZAÇÃO HAVANNA\n  São indicadas para shoppings, prédios comerciais, universidades, galerias, terminais rodoviários, aeroportos, enfim, locais que tenham um grande fluxo de pessoas.\n    MODELOS DE NEGÓCIO HAVANNA\n    Café Quiosque   \n  Metragem: 18M² de área operacional + área de mesas. Mix de Produtos: linha Havanna, produtos sazonais e produtos cafeterias.\n(sanduíches; tortas; cafés; drinks, salgados e crepe). Investimento: A partir de R$350.000,00 Taxa de franquia: R$65.000,00 (já inclusa no investimento) Lucratividade: 12% á 15% Capital de Giro: 3x o estoque inicial. Royalties: 5%* Taxa de Marketing: 2%* *Sobre o faturamento mensal bruto.     Cafeteria   \nMetragem: A Partir de 35M² de área operacional + área de mesas. Mix de Produtos: linha Havanna, produtos sazonais e produtos cafeterias. \n(sanduíches; tortas; cafés; drinks, salgados e crepe). Investimento: A partir de R$520.000,00 Taxa de franquia: R$65.000,00 (já inclusa no investimento) Lucratividade: 15% á 18% Capital de Giro: 3x o estoque inicial. Royalties: 5%* Taxa de Marketing: 2%* *Sobre o faturamento mensal bruto.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f349ff64-d993-4a09-8074-9c20f413ffe1.jpg', 134, NULL, NULL, '2026-03-08 22:24:14.414', 'https://franquias.portaldofranchising.com.br/franquia-havanna/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/781fb1cd-a969-4cd0-8a9a-19f933d3e27a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6d61dd54-cbdb-4c2d-95c2-28acfb37386c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0d201900-920e-4c2d-a707-e0bcb50f64ab.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/875978f6-6462-40dd-8881-3b71b01cb4e6.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '331000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75pa00d3eh0s2kb70atq', 'OFICIAL MED', 'oficial-med', NULL, 'Saúde, Beleza e Bem Estar', 'FARMÁCIAS', 'Rede de farmácias de manipulação e suplementação personalizada', 2024, 2025, NULL, '2026-04-01 02:00:05.906', '2025-08-05 22:20:26.783', 508, NULL, 1, 2022, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/66fc1af0-0719-418c-8aa6-68ba566c76be.png', 3, NULL, NULL, '2025-05-09 14:21:18.000', 'https://franquias.portaldofranchising.com.br/franquia-oficial-med-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75pf00d4eh0sqwwvnnvj', 'LOCARX FRANCHISING', 'locarx-franchising', NULL, 'Serviços Automotivos', 'Locação de veículos', 'Locação de Veiculos', 2009, 2022, NULL, '2026-04-01 02:00:05.916', '2025-08-05 22:20:26.787', 509, NULL, 1, 2009, 'A LOCARX surgiu em 2009, quando cinco diferentes empresas de aluguel de veículos automotivos ex-franqueadas de uma das maiores redes de locadora do país a época, se uniram para partilhar conhecimento do mercado de locação de veículos e utilizar a marca, de maneira nacional, criando uma rede com uma frota de aproximadamente 500 veículos. Em 2010 a LOCARX estabeleceu a cidade de Salvador como sua sede, oportunidade em que a empreendedora Livia Villar passou a ser a sua administradora e principal executiva. Com o crescimento exponencial do mercado de franquias, no início de 2020, a LOCARX vislumbrou nesse forte segmento uma forma de expandir suas operações. \nNesse sentido, e contando com a expertise de Luiz Villar, presente na LOCARX desde o início do projeto, foram iniciados os estudos mercadológicos para o lançamento da franquia LOCARX no final do ano de 2021. Em novembro de 2021 a LOCARX assina um acordo operacional com a 300 Franchising, maior aceleradora de franquias do Brasil.   Missão:   Proporcionar mobilidade e liberdade aos nossos clientes com excelência e eficiência no atendimento.   Visão:   Ser uma empresa lucrativa, eficiente e respeitada no mercado de locação de veículos, oferecendo serviços com qualidade e acessibilidade aos clientes, fornecedores e funcionários.   Valores:  Respeito a relações humanas; Comprometimento com a satisfação do cliente; Busca constante pela excelência, ética e transparência; Valorização do trabalho em equipe; Respeito ao meio ambiente.\n\t  Sistema de Franquia: A franquia LOCARX é um método de se fazer negócios em que a FRANQUEADORA concede ao(à) FRANQUEADO(A), durante a vigência do Contrato, o direito de instalar e operar uma Unidade Franqueada em determinada Área de Atuação, mediante a utilização de know-how próprio, para o desenvolvimento e operacionalização do negócio de locação de veículos automotivos, aplicação das técnicas e metodologia operacional, administrativa e mercadológica desenvolvida pela FRANQUEADORA. A franquia LOCARX oferece à sua rede diversas ferramentas que automatiza as rotinas operacionais, contribuindo para um melhor gerenciamento do negócio, por meio da padronização de informações e visualização de modo seguro, do desempenho e da lucratividade da unidade. O franchising proporciona a expansão de um conceito comprovado na operação da Unidade Franqueada, publicidade ampla e de alto impacto, marcas registradas reconhecidas, assistência técnica e gerencial contínua.   Por que fazer parte da rede de franquias LOCARX e quais as vantagens? Ao fazer parte da rede de franquias LOCARX o(a) FRANQUEADO(A) passa a integrar uma rede nacional de atendimento, podendo contar com as seguintes vantagens: Utilização de software de gestão. Central de atendimento ao cliente 24 horas. Geração de negócios – a rede trabalhando para a rede. Terceirização da frota – Know How e tradição. 9/78 Força de vendas. Descontos e condições competitivas junto às montadoras de veículos. Central de reservas. Site LOCARX. Treinamento – relação contínua. Sites nacionais de reservas online Site internacional de reserva online para as Unidades Franqueadas Aeroporto. Ferramentas digitais e sistemas auxiliares, os quais são indispensáveis para a operação da franquia LOCARX, cujo uso, e o respectivo custo, a ser pago pelo(a) FRANQUEADO(A), está definido no Manual de Operações.   Perfil do Franqueado LocarX Para ser um(a) Franqueado(a)da LOCARX, o(a) CANDIDATO(A) deve se enquadrar no perfil que, em linhas gerais, tenhas as seguintes características: Empreendedor, organizado, comprometido, honesto e com noção em administração geral. Preferivelmente com experiência no ramo de automóveis, mas se não tiver, que possua interesse em aprender as nuances de um negócio que envolve além da venda de serviços a comercialização dos veículos. Possuir disponibilidade financeira; Disponibilidade de tempo; É imprescindível que o mesmo tenha residência ou grande conhecimento da praça onde deseje instalar a unidade. Identificação com a marca e a política da mesma, cumprindo as especificações de identidade visual e metodologia de trabalho desenvolvidas pela Franqueadora.', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4e01c0ec-5f41-4fbc-bdc1-98b510954459.jpg', 26, NULL, NULL, '2026-03-08 22:25:59.551', 'https://franquias.portaldofranchising.com.br/franquia-locarx-franchising/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '120000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75pk00d5eh0sbvoakj4o', 'SEAZONE', 'seazone', NULL, 'Hotelaria e Turismo', 'Hospedagem', 'A Seazone é uma empresa de locação de imóveis por temporada. Nossa rede franqueada é formada por anfitriões (franqueados) que são responsáveis pela operação local com os nossos hóspedes.', 2020, 2024, NULL, '2026-04-01 02:00:05.927', '2025-08-05 22:20:26.792', 510, NULL, 1, 2019, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6264289a-13b8-49bf-b89d-5531dc7bc6e5.png', 74, NULL, NULL, '2026-03-08 22:27:57.126', 'https://franquias.portaldofranchising.com.br/franquia-seazone-hotelaria-e-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75pp00d6eh0sr0szoyd3', 'AMPLIZ', 'ampliz', NULL, 'Comunicação, Informática e Eletrônicos', 'Serviços Gráficos e Impressão', 'A Ampliz é uma tecnológica franquia de gráfica online que oferece a micro e pequenas empresas fácil acesso a impressos personalizados de alta qualidade, em baixo e alto volume com baixo custo.', 2024, 2024, NULL, '2026-04-01 02:00:05.936', '2025-08-05 22:20:26.797', 511, NULL, 1, 2023, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7a4e828c-884f-491b-b8e3-2678dbd55988.png', NULL, NULL, NULL, '2026-03-08 22:28:24.425', 'https://franquias.portaldofranchising.com.br/franquia-ampliz-comunicacao-informatica-e-eletronicos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '11000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75pv00d7eh0szsfv0vx6', 'JANI KING', 'jani-king', NULL, 'Limpeza e Conservação', 'Serviços de Limpeza', 'SERVIÇOS DE LIMPEZA, CONSERVAÇÃO e FACILITIES com foco condomínios comerciais e residenciais, bancos, estádios, indústrias, colégios e universidades, hoteis e grandes eventos', 1970, 1991, NULL, '2026-04-01 02:00:05.946', '2025-08-05 22:20:26.803', 512, NULL, 1, 1969, 'Maior franquia de limpeza comercial do mundo, a Franquia Jani-King, há quase meio século, ajuda empreendedores a se tornarem empresários de sucesso, através da oferta dos melhores serviços de limpeza profissional para os mais exigentes setores corporativos. Nós compartilhamos o seu sonho, mostramos o caminho, acompanhamos cada passo e vibramos com o seu sucesso. Mais de nove mil franqueados em onze países de três continentes avalizam a eficiência do nosso modelo de negócio. Centenas de milhares de clientes satisfeitos assinam o padrão de qualidade dos nossos serviços de limpeza. Com sede nos Estados Unidos, na cidade de Addison no estado do Texas, a Jani-King chegou ao Brasil há vinte e cinco anos e conta com escritórios corporativos no Rio de Janeiro e em São Paulo, que oferecem suporte permanente aos seus franqueados e clientes. Aqui, conquistamos o respeito do mercado, formamos empresários de sucesso, crescemos e acumulamos belas histórias de determinação, conquistas e realizações pessoais e profissionais. Oferecemos vinte planos de franquia, todos eles com contratos iniciais garantidos, o que siginifica faturamento desde o primeiro dia da operação. Quer ir ainda mais longe? Torne-se um master franqueado Jani-King. O máster franqueado atua como um franqueador regional com a licença de captar franqueados em sua área, com todas as responsabilidades de prestar suporte aos mesmos. Temos oportunidades nas seguintes cidades e regioes: Belo Horizonte (MG), Brasília (DF), Belém (PA), Campinas (SP), Curitiba (PR), Florianópolis (SC), Fortaleza (CE), Goiânia (GO), Jacareí (SP), Jundiaí (SP), Manaus (AM), Natal (RN), Porto Alegre (RS), Recife (PE), Ribeirão Preto (SP), Rio de Janeiro (município do Rio de Janeiro, Baixada Fluminense, Região dos Lagos, Região Serrana e Região Sul Fluminense), Salvador (BA), São Carlos (SP), São José dos Campos (SP), São Luis (MA), Taubaté (SP), Vila Velha (ES) e Vitória (ES). Seja qual for sua ambição profissional, temos o modelo mais adequado para a realização do seu sonho de vida. Nós somos a Jani-King do Brasil. Temos orgulho da nossa marca, construída pela eficiência do nosso modelo de negócio e empenho dos nossos franqueados. Convidamos você a fazer parte dessa jornada.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a261244a-8ee1-46b2-b57c-fcda01d278d5.jpg', 2, NULL, NULL, '2026-03-08 22:28:47.067', 'https://franquias.portaldofranchising.com.br/franquia-jani-king-limpeza/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4fa9be10-1c47-4a2d-841c-2c10b7b157a1.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '30000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75q000d8eh0st7jpzmxw', 'UC ULTRA CURSOS FORMAÇÃO PROFISSIONAL', 'uc-ultra-cursos-formacao-profissional', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Uma Edtech que veio democratizar o acesso a toda população das classes socias C, D e E a cursos de extrema qualidade, além de proporcionar aos empreendedores/franqueados uma mudança de vida.', 2023, 2023, NULL, '2026-04-01 02:00:05.955', '2025-08-05 22:20:26.809', 513, NULL, 1, 2016, '', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2f44002c-0824-463c-bec7-b472f6c7d9ec.png', 7, NULL, NULL, '2026-03-08 22:29:59.352', 'https://franquias.portaldofranchising.com.br/franquia-uc-ultra-cursos-formacao-profissional/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75q600d9eh0sgm1kxldw', 'SUPORTE SMART', 'suporte-smart', NULL, 'Comunicação, Informática e Eletrônicos', 'ELETRÔNICOS', 'Reparos p/ Celulares, Venda de Acessórios, Venda de Celulares novos e semi-novos, Games e Informática!', 2017, 2022, NULL, '2026-04-01 02:00:05.965', '2025-08-05 22:20:26.814', 514, NULL, 1, 2010, 'Mais do que um Centro Técnico Especializado, somos uma rede de franquias de sucesso. A Suporte Smart é uma marca do grupo iService Soluções, empresa com mais de 40 colaboradores e apoio de grandes marcas. Zelamos pelo conforto e confiança de nossos franqueados, dando suporte e atendimento técnico do começo até após a abertura da sua loja. Nosso diferencial é o forte investimento em publicidade e propaganda, tendo como principais meios de vinculação mídia impressa (cartões, banners, flyers), mídia online (facebook, instagram, google, email marketing). Nós oferecemos todo suporte, expertise e segurança para a abertura do seu próprio negócio.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fc54545d-fc45-4672-8c55-ba5999e767de.jpg', 100, NULL, NULL, '2025-09-09 13:53:28.000', 'https://franquias.portaldofranchising.com.br/franquia-suporte-smart/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75qb00daeh0shoe00osk', 'RHS PREMIUM LIMPEZA PROFISSIONAL', 'rhs-premium-limpeza-profissional', NULL, 'Limpeza e Conservação', 'Serviços de Limpeza', 'Somos uma franquia especializada em limpeza de ambientes comerciais (pessoas jurídicas) realizando a gestão completa do serviço e utilizando o que existe de mais moderno em equipamentos e técnicas.', 2020, 2021, NULL, '2026-04-01 02:00:05.974', '2025-08-05 22:20:26.819', 515, NULL, 1, 2016, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/50145242-672c-474e-98f2-77e89edfcf00.jpeg', 4, NULL, NULL, '2026-03-08 22:30:40.553', 'https://franquias.portaldofranchising.com.br/franquia-rhs-premium-limpeza-profissional/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75qh00dbeh0s9j4f91ni', 'O\'STORE', 'o-store', NULL, 'Moda', 'Calçados', 'Comercialização de calçados, confecções e acessórios sneakers multimarcas', 2018, 2021, NULL, '2026-04-01 02:00:05.983', '2025-08-05 22:20:26.825', 516, NULL, 1, 2018, 'A O’STORE SNEAKERS instalou sua primeira loja, em março de 2018, em uma das principais avenidas da cidade de São Paulo: a Avenida Paulista; local onde encontrou e consolidou toda a personalidade de sua marca.  A O’STORE SNEAKERS analisou seu mercado de atuação durante 03 (três) anos, de modo a sempre trazer um conceito único dentro de seu segmento: a loja na Avenida Paulista surgiu como um marco dentro da empresa Franqueadora, tendo em vista sua estratégica localização no coração de São Paulo, e a grande força cultural que permeia a região.  Assim, a loja proporciona aos clientes a experiência de sentir toda a sinergia que envolve o segmento, através de diversas ações, envolvendo cultura, dança, arte e música.  Os princípios e valores éticos já se consolidam na O’STORE SNEAKERS desde sua criação, de modo a sempre se fortalecer no segmento mediante essa essência.\n \nCom foco direcionado à comercialização de poucas e selecionadas marcas e fornecedores, a O’STORE SNEAKERS desenvolveu sua identidade, criando assim diferenciais competitivos dentro do mercado, no ramo de comercialização de calçados Sneakers, roupas e acessórios.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a79a9f5b-095b-4169-938e-167bbd355801.jpg', 10, NULL, NULL, '2026-03-08 22:31:08.923', 'https://franquias.portaldofranchising.com.br/franquia-o-store/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '400000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75qn00dceh0sexbtoqru', 'FIOLASER SPA', 'fiolaser-spa', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'Centro de depilação à laser, estética corporal e facial.', 2016, 2019, '[\"https://www.youtube.com/watch?v=7SfLpRZSbpU\",\"https://www.youtube.com/watch?v=-UeL8RpDJ68\",\"https://www.youtube.com/watch?v=o4W3TlKf91s\"]', '2026-04-01 02:00:05.993', '2025-08-05 22:20:26.831', 517, NULL, 1, 2008, 'Quando quatro empreendedoras baianas decidiram virar sócias e apostar no ainda incipiente mercado de estética e depilação a laser, talvez não imaginassem que estivessem à frente de um dos negócios mais bem-sucedidos do Norte e Nordeste. Hoje, 11 anos após o início da empreitada e iniciado um processo de expansão, a Fiolaser já conta com 15 unidades em operação. Vanessa Duarte, Perla Lemos, Juliana Albuquerque e Tarsila Carvalho são as responsáveis por comandar a empresa líder em tratamentos de ponta para estrias, celulites, rejuvenescimento da pele e eliminação de gordura e pelos, mas é importante frisar que a Fiolaser não se resume a procedimentos estéticos. Com foco na saúde, beleza e bem-estar, o caminho natural do crescimento levou à criação de um novo braço: a Fiolaser CLINIC, que, como o nome sugere, realiza procedimentos médicos e de dermatologia avançada. Os motivos do sucesso são muitos, mas, entre eles destacam-se os contínuos investimentos em tecnologia e a preocupação com a qualidade do atendimento. Além de oferecer os equipamentos de laser e estética mais modernos do mercado, a empresa foca grande parte de seus esforços em capacitação, a fim de oferecer a melhor experiência em atendimento aos seus mais de 200 mil clientes. Recentemente, por exemplo, foi criado o Fiolaser+, uma plataforma digital de treinamento integrada, exclusiva para os colaboradores da rede. A gestão atenciosa e dedicada das sócias fez prosperar também o modelo de franchising. Com um plano de expansão iniciado em 2017, a Fiolaser possui lojas distribuídas atualmente por Salvador, Lauro de Freitas, Alagoinhas, Santo Antônio de Jesus, Aracaju, Feira de Santana, Brasília e Recife, além das recém-inauguradas em Maceió, Itabuna, Vitória da Conquista e Barreiras. Para outros empreendedores, a Fiolaser passa a servir não apenas de inspiração, mas também como uma das melhores opções na hora de considerar a abertura de uma franquia de sucesso e com grande potencial de crescimento, principalmente após sua entrada na ABF (Associação Brasileira de Franchising), processo conduzido de perto por Dax Aniceto, sócio responsável pela gestão da franqueadora Fiolaser. Enquanto a empresa continua a fazer bonito, todo mundo sai ganhando: colaboradores, franqueados e, principalmente, os clientes. Do social ao ambiental, uma empresa engajada Em junho de 2018, com o intuito de gerar uma rede de afetos para ajudar ao próximo, foi criado o Instituto Fiolaser, um projeto social voltado ao auxílio de pessoas em situação de vulnerabilidade. Com uma equipe com cerca de 100 pessoas, entre colaboradores e voluntários, o Instituto tem um calendário anual e organiza ações de arrecadação de itens para serem doados a instituições como asilos, creches e orfanatos. Tão importante quanto o compromisso com o próximo é o compromisso em se tornar cada dia mais sustentável. O Fiolaser + Sustentável é um selo que tem acompanhado diversas ações e decisões da empresa no esforço de que clientes e colaboradores adotem posturas ecologicamente corretas no trabalho e em casa.', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/034fad73-f822-4497-accc-30e5e7ee85bc.jpg', 35, NULL, NULL, '2025-08-29 11:24:31.000', 'https://franquias.portaldofranchising.com.br/franquia-fiolaser-spa/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2230ceb5-63e3-4c2c-8428-4e9601dbce71.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0a8bd18e-cee3-46b6-a771-62cd719074d7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/916be471-f8c3-4b5a-9c7a-cbd8e814060b.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
