INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75r600dfeh0sg18w7orn', 'LA PANATA', 'la-panata', NULL, 'Alimentação', 'Bares e Restaurantes', 'Tudo feito à mão e assadas em forno de pedra em alta temperatura, deixando a massa leve, gostosa e queimadinha. De um jeito único, como você nunca viu. Nascemos para ser mais que uma experiência!', 2021, 2023, NULL, '2026-04-01 02:00:06.022', '2025-08-05 22:20:26.850', 520, NULL, 1, 2017, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e0d2cfa8-f15f-44bd-b83c-6e852c158aa7.png', 11, NULL, NULL, '2026-03-08 22:32:31.285', 'https://franquias.portaldofranchising.com.br/franquia-la-panata-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75rb00dgeh0s8jgr1o4o', 'DINIZ LASER', 'diniz-laser', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'Clínica especializada em tratamentos estéticos a laser. A Diniz Laser conta com uma equipe de especialistas da área da saúde, com atendimento personalizado e focado na necessidade de cada cliente.', 2019, 2023, '[\"https://www.youtube.com/watch?v=cOHVrcf2Jqs\",\"https://www.youtube.com/watch?v=ivn2F-v6P6U\"]', '2026-04-01 02:00:06.030', '2025-08-05 22:20:26.855', 521, NULL, 1, 2019, 'Com mais de 15 anos de experiência na área, em 2019, a empresária Ali Diniz trouxe aos clientes uma nova proposta de clínica especializada em tratamentos estéticos a laser. A Diniz Laser passa a ser a PRIMEIRA ESTÉTICA A LASER DO BRASIL. A Diniz Laser é uma franqueadora de clínicas especializadas em tratamentos estéticos a laser. A marca possui um portfólio completo envolvendo diversos tratamentos faciais e corporais a laser, todos eles de alta tecnologia e contando com os melhores equipamentos do mundo. A expansão está em ritmo acelerado e nossa projeção é de 50 franquias para os próximos meses, sendo que 90% dos nossos franqueados são MULTIFRANQUEADOS, possuindo mais de uma unidade. O grande diferencial é o baixo investimento e alta rentabilidade, que se caracteriza pela operação enxuta e ausência de estoque de produtos para gerenciar. O plano de negócio tem payback (retorno do investimento) entre 8 e 18 meses, lucro líquido médio de 40% e faturamento anual estimado em 1,5 milhão de reais. Invista na Diniz Laser e seja dono de uma franquia da PRIMEIRA ESTÉTICA A LASER DO BRASIL.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/48c41b7e-e60a-45a1-be29-2dfe41484ca4.svg', 10, NULL, NULL, '2025-09-17 10:17:22.000', 'https://franquias.portaldofranchising.com.br/franquia-diniz-laser/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
