INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75rm00dieh0srq1iufow', 'SUCOS S/A', 'sucos-s-a', NULL, 'Alimentação', 'Bares e Restaurantes', 'A FRANQUEADORA possui como atividade empresarial especializada para o segmento de Alimentação Saudável, com variedade de sucos, vitaminas, frapês, lanches naturais e açaí.', 2019, 2021, NULL, '2026-04-01 02:00:06.049', '2025-08-05 22:20:26.866', 523, NULL, 1, 2009, 'Fundada em 2009, em Araçatuba (SP), a Sucos S/A é uma franquia de alimentação saudável e que oferece em seu cardápio uma variedade de sucos, saladas, açaís, sanduíches naturais e tapiocas. \nA rede conta com modelos de negócios no formato loja, container e quiosque. \nAtualmente, possui mais de 10 unidades com forte presença no interior de São Paulo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/65ff9df9-1c35-4e96-8df2-6e96615fae69.jpg', 9, NULL, NULL, '2026-03-08 22:33:27.452', 'https://franquias.portaldofranchising.com.br/franquia-sucos-sa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75rr00djeh0se3plulze', 'COLCCI', 'colcci', NULL, 'Moda', 'Vestuários', 'Desde 86 carregando a essência jeanswear no seu DNA, a Colcci é uma das mais renomadas marcas de moda brasileira. Disruptiva e vanguardista, a marca é reconhecida por sua inovação, estilo e qualidade.', 1986, 2013, NULL, '2026-04-01 02:00:06.058', '2025-08-05 22:20:26.871', 524, NULL, 1, 1986, 'FRANQUIA COLCCI – A MAIOR MARCA DE JEANSWEAR DO BRASIL \nA Colcci é considerada a maior marca de jeanswear nacional, presente em 130 lojas e mais de 2000 multimarcas, além de contar com a presença de distribuidores em todos os continentes.  \nA marca carrega em seu DNA a essência do denim, se conectando com o público jovem e urbano, atingindo o público A e B da faixa etária dos 18 a 35 anos. \nSinônimo de moda, a Colcci traz sempre o melhor produto para nossos clientes. Reforçada através da poderosa imagem da uber model Gisele Bundchen e de grandes eventos como o SPFW. O mix amplo e diversificado que conta com itens de confecção, sapatos e acessórios , tanto para o público feminino como para o público masculino, impacta diversos estilos.  \n  Vantagens em ser um franqueado COLCCI:\n \n- Principal marca de jeanswear nacional\n \n- Experiência de 30 anos de mercado\n \n- Projeto arquitetônico padronizado\n \n- Análise e consultoria para a definição do ponto comercial\n \n- Moderno software de gestão\n \n- Acompanhamento próximo do Consultor de Franquias\n \n- Treinamentos de vendas e produtos, para a capacitação de equipe\n \n- Acesso ao Guia Visual da marca e Visual Merchandising\n \n- Apoio à materiais de marketing e ações de varejo\n \n- Amplo material estratégico para fomentar as vendas\n \n- Condições comerciais mais favoráveis\n \n- Suporte nos pedidos de compra\n \n- Variado mix de produtos com mais de 1800 itens por coleção\n \n- Trabalhar com uma marca de reconhecimento internacional\n \n- Suporte do Grupo AMC Têxtil:  proprietária da marca, o maior gestor de marcas da América Latina', NULL, 'SANTA CATARINA', 1, NULL, 155, NULL, NULL, '2026-03-08 22:33:59.075', 'https://franquias.portaldofranchising.com.br/franquia-colcci-vestuario/', NULL, NULL, '[]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '490000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75rv00dkeh0sy38jvfm5', 'MITTY COLLEZIONE', 'mitty-collezione', NULL, 'Moda', 'VESTUÁRIO', 'Nosso Principal negocio hoje e a fabricação e comercialização de cintos e carteiras de couro, e estamos espandindo para vestuarios em Geral', 2024, 2024, NULL, '2026-04-01 02:00:06.068', '2025-08-05 22:20:26.876', 525, NULL, 1, 1974, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e8a33a3a-0738-4f1e-8721-9dd31c6bb701.svg', 1, NULL, NULL, '2025-09-09 15:14:09.000', 'https://franquias.portaldofranchising.com.br/franquia-mitty-collezione-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75s000dleh0scgzg8spo', 'RODMAK', 'rodmak', NULL, 'Casa e Construção', 'Construção e Reforma', 'Locação de equipamentos e ferramentas para a construção civil, reformas, jardinagem e limpeza.', 2024, 2024, NULL, '2026-04-01 02:00:06.077', '2025-08-05 22:20:26.881', 526, NULL, 1, 2023, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2a7b4bdc-173f-4148-bbea-f576785a80e6.png', 4, NULL, NULL, '2026-03-08 22:35:20.089', 'https://franquias.portaldofranchising.com.br/franquia-rodmak/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '396600', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75s500dmeh0sgb6p6zcn', 'LEZ A LEZ', 'lez-a-lez', NULL, 'Moda', 'Vestuários', 'Loja de vestuário feminino. Somos moda, somos praia dentro da cidade, uma marca urbana com os pés na areia & cultura Urban Beach. Acreditamos que o equilíbrio entre a leveza da praia e a modernidade', 2008, 2016, '[\"https://www.youtube.com/watch?v=Kpcsh03Uy7Y\",\"https://www.youtube.com/watch?v=SgSS85szLF4\",\"https://www.youtube.com/watch?v=_yeifX8fDX8\"]', '2026-04-01 02:00:06.086', '2025-08-05 22:20:26.885', 527, NULL, 1, 1981, 'A Lez a Lez nasceu em 2006 e pertence a Lunelli, umas das principais indústrias têxteis do Brasil que faz moda com significado há mais de 40 anos. Atualmente, com 16 fábricas e 165.000m² de área construída, a Lunelli tem um parque fabril com tecnologia de ponta, conta com mais de 4.800 colaboradores e produz 26 milhões de peças por ano. Dentre as premiações e conquistas que a Lez a Lez recebeu, destacamos os 4 últimos selos de Excelência em Franchising da ABF, os 3 selos de Franquia Internacional da ABF e também a pontuação que nos classificou como a Melhor Marca de Moda Feminina do Brasil, pelo Pequenas Empresas e Grandes Negócios. A Lez a Lez está presente em todos estados brasileiros, em mais de 2 mil pontos de vendas e contamos com 37 lojas no Brasil e também no exterior. Nossas lojas conceito estão localizadas na Oscar Freire e na praia de Jurerê Internacional. Somos moda, somos praia dentro da cidade, uma marca urbana com os pés na areia & cultura Urban Beach. Acreditamos que o equilíbrio entre a leveza da praia e a modernidade da cidade faz o sol da gente brilhar bem mais bonito.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cbec695f-f5ef-4f64-9d30-5f65288482bd.jpg', 43, NULL, NULL, '2026-03-08 22:35:43.774', 'https://franquias.portaldofranchising.com.br/franquia-lez-a-lez/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
