INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75tp00dueh0sj01cndf9', 'SHOPMASP', 'shopmasp', NULL, 'Moda', 'Calçados', 'Franquia de Varejo Esportivo, focada nas maiores marcas mundiais, levando o que há de melhor no ramo de calçados, confecções, acessórios para nossas lojas, tornando-as referência na região onde atuam', 2014, 2020, '[\"https://www.youtube.com/watch?v=2onl-ZleHYA\"]', '2026-04-01 02:00:06.163', '2025-08-05 22:20:26.940', 535, NULL, 1, 1979, 'A maior franquia de artigos esportivos da região Sul A Shopmasp, uma das 10 maiores redes de lojas de artigos esportivos do sul do Brasil, é sinônimo de inovação e qualidade no setor. Atualmente, a rede conta com quase 50 lojas físicas estrategicamente localizadas no sul do país. História da Shopmasp Fundada em 1979 pelos pais do atual proprietário Marcelo Luis Vieira. A ideia de criar a loja surgiu do pai de Marcelo, um professor de educação física apaixonado por esportes. Ele decidiu transformar sua paixão em um negócio. A primeira loja foi batizada de Marcelo Sports, em homenagem ao ?lho. Em 1993, Marcelo Luis Vieira assumiu a gestão do negócio, trazendo uma visão estratégica e transformadora. Ele reposicionou a marca para atender ao segmento de estilo casual e elevou o padrão de qualidade da loja. O crescimento contínuo da loja culminou na decisão de expandir o negócio por meio de franquias. Esse marco trouxe também uma nova identidade: o nome foi alterado de Marcelo Sports para Shopmasp. Hoje, a Shopmasp é reconhecida por sua inovação, qualidade e liderança no setor esportivo, focada em comercializar produtos das principais marcas esportivas do mercado, como Nike, Adidas, Asics e Mizuno.', NULL, 'SANTA CATARINA', 1, NULL, 22, NULL, NULL, '2026-03-08 22:38:30.388', 'https://franquias.portaldofranchising.com.br/franquia-shopmasp/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '209400', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
