INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75v800e0eh0sxoi02wbw', 'HARO SUSHI', 'haro-sushi', NULL, 'Alimentação', 'Bares e Restaurantes', 'Somos uma rede de restaurantes delivery com foco na culinária japonesa e chinesa.', 2019, 2022, '[\"https://www.youtube.com/watch?v=fH1bsh1wfTY\"]', '2026-04-01 02:00:06.220', '2025-08-05 22:20:26.997', 541, NULL, 1, 2017, 'Imagine uma jornada culinária que começou em 2017 e desde então tem transformado o mercado do delivery no Brasil. ? Bem-vindo ao Grupo Harô, onde a inovação e a paixão pela gastronomia se unem para criar uma experiência única. Somos mais do que uma simples franquia, somos a personificação do sucesso em seis segmentos diferentes? Sempre buscando estar a frente, construímos uma verdadeira miscelânea de sabores, oferecendo não apenas comida, mas uma experiência gastronômica de tirar o fôlego. Nosso segredo? Uma cozinha otimizada, estrategicamente projetada para reduzir os custos operacionais dos nossos parceiros e garantir que cada prato seja uma obra de arte ? Ao unir forças conosco, você não apenas ingressa em uma franquia, mas sim em uma rede de empreendedores apaixonados, prontos para conquistar o paladar de milhares de clientes em todo o Brasil. Junte-se a nós e embarque nessa jornada rumo ao sucesso, onde cada entrega é mais do que um simples embalagem, é uma promessa de excelência e satisfação.? Venha fazer parte do Grupo Harô e descubra como podemos transformar seus sonhos em uma realidade altamente lucrativa. O futuro está à mesa e você está convidado a saboreá-lo conosco.', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1ac86937-6235-4465-af32-e97de9f77f60.png', 40, NULL, NULL, '2026-03-08 22:46:27.056', 'https://franquias.portaldofranchising.com.br/franquia-haro-sushi/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '135000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ve00e1eh0s23p0ilsb', 'B.LEM PADARIA PORTUGUESA', 'b-lem-padaria-portuguesa', NULL, 'Alimentação', 'PADARIAS', 'Padaria e doceria com foco em produtos portugueses', 2017, 2018, '[\"https://www.youtube.com/watch?v=Pwf5P1XFbvg\"]', '2026-04-01 02:00:06.229', '2025-08-05 22:20:27.002', 542, NULL, 1, 2014, 'A B.LEM foi fundada em 2015 e em cinco anos expandiu para 8 estados brasileiros e hoje é a maior franquia de padarias do Brasil. A tradição portuguesa e a forma de produzir os produtos são os diferenciais que tornam a B.LEM uma empresa única, com forte personalidade nas suas receitas e muita inovação na forma de entregar a experiência para seus clientes. Durante 2020 novas lojas foram inauguradas em diversas regiões do país, entre lojas de rua e shoppings, provando que a franquia tem grande solidez e experiência para apoiar os franqueados com resiliência e know how.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7b83eeae-0c22-4791-b2f2-2ee3a9d2e619.jpg', 35, NULL, NULL, '2026-02-09 14:52:28.000', 'https://franquias.portaldofranchising.com.br/franquia-blem-bakery/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '250000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
