INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75xa00efeh0snlqto3uh', 'MR. BLACK CAFÉ GOURMET', 'mr-black-cafe-gourmet', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'O Mr. Black é uma rede de cafeterias focada na qualidade dos seus produtos e na excelência no atendimento ao cliente.', 2012, 2012, '[\"https://www.youtube.com/watch?v=NqnhPN8EzKM\",\"https://www.youtube.com/watch?v=Kw-WpNTwlcA\",\"https://www.youtube.com/watch?v=cw0SdaMwl6s\"]', '2026-04-01 02:00:06.375', '2025-08-05 22:20:27.070', 556, NULL, 1, 2006, 'Fundada em 2006 na cidade de Belo Horizonte, o Mr. Black Café rapidamente se consolidou no mercado de cafeterias através de três pilares essenciais: alta qualidade dos produtos, preço justo e atendimento diferenciado. Buscando sempre a excelência, o Mr. Black Café se tornou sinônimo de qualidade e estamos sempre em busca das melhores práticas de gestão, desenvolvimento da marca e aperfeiçoamento da experiência do cliente. Acreditamos que a melhor forma de atrair e manter clientes satisfeitos é sempre trabalhar de forma justa e sincera. Nos posicionamos como uma cafeteria de cafés especiais, ou seja, os cafés que utilizamos são cafés que foram cultivados observando as melhores práticas, gerando grãos de alta qualidade, tal que, através de teste de prova, são classificados por especialistas com notas entre 84 e 86 pontos. Estes cafés tem características sensoriais diferenciadas, promovendo aos nossos clientes uma experiência diferenciada. Em 2012, após 6 anos de muito trabalho e grande sucesso na capital mineira, os nossos gestores, através de um plano estratégico de longo prazo, disponibilizaram a marca para expansão através do sistema de franquias. Associada a ABF (Associação Brasileira de Franchising), o Mr. Black Café conta com 25 unidades franqueadas em 7 estados brasileiros. Desde o ano de 2016, decidimos por fabricar os nossos próprios produtos da linha de salgados e doces. Essa estratégia nos proporcionou um grande ganho de qualidade, exclusividade, controle de custos e consequente diferencial competitivo frente aos nossos concorrentes. Como uma franquia Mineira e de Belo Horizonte, que recebeu o título de Cidade Criativa da Gastronomia pela UNESCO no ano de 2019, buscamos sempre a excelência na qualidade dos nossos produtos, a melhoria continua na experiência do nosso cliente e a adequação do modelo de negócio às tendências internacionais de arquitetura, tecnologia no preparo dos alimentos e inovações nas nossas estratégias de marketing. Modelos de Franquia Express Ideal para locais de grande fluxo como supermercados, faculdades, call centers, estações de metrô, hospitais e store in store. » Espaço: 6m² a 9m² » Taxa de Franquia: R$30.000,00 » Capital para Instalação: entre R$90.000,00 e R$110.000,00 » Capital de Giro: R$10.000,00 » Investimento total: entre R$130.000,00 e R$150.000,00 » Faturamento médio estimado: R$30.000,00 » Lucro estimado: 15% do faturamento » Royalties fixo: R$1.100,00 (reajustável anualmente pelo IGPM) » Taxa de publicidade fixa: R$200,00 (reajustável anualmente de acordo com plano de marketing) Quiosque Modelo que pode ser instalado em: shopping center, prédios comerciais, supermercados, hospitais, faculdades e estações. » Espaço para shopping: 15 m² mais área para mesas e cadeiras » Taxa de franquia: R$ 40 mil » Maquinário e mobiliário: em torno de R$ 80 mil » Obra civil: entre R$ 50 mil e R$ 80 mil » Utensílios: em torno de R$ 15 mil » Capital de giro: R$ 15 mil » Investimento total estimado: entre R$ 200 mil e R$ 230 mil » Royalty: 5% do faturamento bruto » Taxa de publicidade: rateio (não cobramos % fixo) Loja de Shopping ou Rua Ideal para shoppings ou pontos de rua com grande fluxo de pessoas. » Espaço para shopping: 20 m² e 45 m² » Espaço para rua: 60 m² e 100 m² » Taxa de franquia: R$ 40 mil » Maquinário e mobiliário: em torno de R$ 80 mil » Obra civil: entre R$ 90 mil e R$ 130 mil » Utensílios: em torno de R$ 15 mil » Capital de giro: R$ 15 mil » Investimento total estimado: entre R$ 240 mil e R$ 280 mil » Royalty: 5% do faturamento bruto » Taxa de publicidade: rateio (não cobramos % fixo)', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7eea81bb-5ce5-4033-91ea-867efbdd32f8.jpg', 23, NULL, NULL, '2025-09-11 17:20:01.000', 'https://franquias.portaldofranchising.com.br/franquia-mr-black-cafe-gourmet/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75xf00egeh0sf98n7obo', 'PRIORIDADE 10', 'prioridade-10', NULL, 'Moda', 'Vestuários', 'Loja de departamento, especializado em vestuário e utilidades. Loja de presentes com preço popular.', 2021, 2022, '[\"https://www.youtube.com/watch?v=yGRVCSwrKP4\",\"https://www.youtube.com/watch?v=mx2Ut-ozSs0\",\"https://www.youtube.com/watch?v=Mx0N6VrqiIA\"]', '2026-04-01 02:00:06.384', '2025-08-05 22:20:27.075', 557, NULL, 1, 2014, 'Tudo por até R$ 20. Essa é a proposta da Prioridade 10, uma loja de departamentos criada em Cunha Porã (SC), uma cidade com pouco mais de 11 mil habitantes, em 2014. A parceria com fornecedores estratégicos foi a chave para conseguir produtos de qualidade por um preço baixo, tornando o negócio um verdadeiro sucesso, que em pouco tempo começou a expandir para cidades vizinhas. Com a preocupação de manter a qualidade e o padrão dos itens vendidos, resolveram buscar informações sobre o sistema de franquias e migraram para o modelo em 2022. Hoje a Prioridade 10 conta com mais de 2 mil fornecedores homologados e 10 mil itens cadastrados no Portal de Compras exclusivo da rede. Além disso, é possível contar com o software ERP para gestão de estoque, equipe de marketing dedicada e mais de 09 anos de experiência no setor. Atualmente somos a maior rede de loja de departamento de preço popular do Brasil, com unidades em Santa Catarina, Paraná, Rio Grande do Sul e Distrito Federal.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5f0c18ae-125c-4e82-9873-9ba8d9274acd.jpg', 45, NULL, NULL, '2026-03-08 22:52:06.921', 'https://franquias.portaldofranchising.com.br/franquia-prioridade-10/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75xk00eheh0spb4oa036', 'SPIN\'N SOUL', 'spin-n-soul', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'ACADEMIA DE SPINNING', 2015, 2018, '[\"https://www.youtube.com/watch?v=qbDeb6Houng\",\"https://www.youtube.com/watch?v=PdTctXhX_kY\",\"https://www.youtube.com/watch?v=8kLHbwuntM0\",\"https://www.youtube.com/watch?v=Wt-F1O7JvTA\"]', '2026-04-01 02:00:06.393', '2025-08-05 22:20:27.081', 558, NULL, 1, 2014, 'Fundada em 2014 por Daniel Nasser, João Bordon e Fábio Tutundjian, a Spin’n Soul trouxe ao Brasil o primeiro estúdio de Spinning dentro do conceito de Full Body & Mind Workout, que inclui exercícios intensos que trabalham todo o corpo aliados ao componente mental de coaching inspiracional. “Um cardio santuário para cuidar do corpo e da alma”', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/97a417ef-1e58-4afc-bc68-94f113742444.jpg', 4, NULL, NULL, '2026-03-09 15:30:33.852', 'https://franquias.portaldofranchising.com.br/franquia-spinn-soul/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75xq00eieh0snf9nyzvm', 'DR. SHAPE', 'dr-shape', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Maior Rede de Franquias Especializada em Suplementos Alimentares e Artigos Esportivos da América Latina. E única do segmento com clínica de emagrecimento e estética corporal.', 2013, 2014, '[\"https://www.youtube.com/watch?v=DTkP8KApGpU\",\"https://www.youtube.com/watch?v=Kz9ArOQokW0\",\"https://www.youtube.com/watch?v=CYugfvwU8p8\",\"https://www.youtube.com/watch?v=06S3tqznWls\"]', '2026-04-01 02:00:06.402', '2025-08-05 22:20:27.086', 559, NULL, 1, 2002, 'A Dr. Shape atua há 19 anos no mercado e é a Maior Rede de Franquias Especializada em Suplementos Alimentares e Artigos Esportivos da América Latina. E a única do segmento com clínica de emagrecimento e estética corporal. \nMUITO MAIS QUE UMA LOJA DE SUPLEMENTOS \nA Dr. Shape oferece um mix atrativo de produtos e serviços que vão desde artigos esportivos, vestuário fitness, produtos naturais e a granel, até atendimento nutricional e clínica de emagrecimento e estética corporal. Tudo em um só lugar. E além de trabalhar com suplementos mundialmente conhecidos, a Dr. Shape possui uma linha própria que oferece custo-benefício e qualidade imbatíveis ao consumidor, e rentabilidade sem igual ao franqueado.  O mercado - Estima-se que 54% dos brasileiros consomem algum tipo de suplemento em sua rotina;\n- 66% dos brasileiros acham que cuidar da beleza não é um luxo, mas uma necessidade;\n- O Brasil é o 2º colocado no ranking mundial em número de academias;\n- Estima-se que o Brasil fatura em torno de R$ 2,5 bilhões ao ano em suplementos e R$ 34 bilhões no setor de saúde, beleza e bem-estar; \nMotivos para ser você ser um franqueado Dr. Shape: 1º A Dr. Shape é uma marca forte e consagrada, atuando há 19 anos no mercado; 2º Consultoria profissional no dia a dia da franquia e treinamentos exclusivos, através da Universidade Corporativa; 3º Vantagens comerciais e excelentes condições de compra, através da Central de Compras Cooperada Dr. Shape; 4º Mix completo de produtos próprios, nacionais e importados que atendem a todas as pessoas e classes sociais; 5º Mercado em franco crescimento; 6º Maior capilaridade ao franqueado, podendo explorar a loja física, loja online, delivery planejado, pontos de venda avançados e serviços especializados; 7º Agência de publicidade com atendimento exclusivo e assessoria de imprensa.  Em nossa rede você contará com total suporte para ter uma franquia de sucesso!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/303d0a27-e779-49bc-a9d9-3bca96d018a3.jpg', 50, NULL, NULL, '2026-03-08 22:53:21.352', 'https://franquias.portaldofranchising.com.br/franquia-dr-shape-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75xv00ejeh0sqg0jjra1', 'RIOLAX', 'riolax', NULL, 'Casa e Construção', 'Construção e Reforma', 'COMÉRCIO DE SPA\'S, OFURÔS E BANHEIRAS', 2010, 2011, NULL, '2026-04-01 02:00:06.411', '2025-08-05 22:20:27.092', 560, NULL, 1, 2010, 'A riolax é resultado da iniciativa de um grupo de empreendedores com o extenso know-how na área industrial, que, após  acompanhar as tendências do mercado de construção e decoração, trouxe soluções para atender ao segmento de hidromassagens, spas e ofurôs.  A Industria Riolax é a responsável pela fabricação de produtos com a mais alta tecnologia, a partir das melhores matérias primas. Sua principal característica é a inovação. Ano a ano a fabrica surpreende com novos modelos de banheiras, ousando e de muito bom gosto. O resultado e a satisfação garantida dos profissionais da construção e do consumidor final.   As franquias Riolax tem por objetivo a venda especializada de hidromassagens, spas e ofurôs, para um publico que contempla desde pequenos empreendimentos ate grandes investimentos imobiliários, tais como condomínios, residências e redes hoteleiras.  A ideia é proporcionar conforto, bem estar e segurança para quem usa, e uma excelente fonte de lucros, rentabilidade e credibilidade para quem comercializa os produtos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7fed6af2-1592-4e63-b477-be78c973b1dc.jpg', 24, NULL, NULL, '2026-03-08 22:54:20.573', 'https://franquias.portaldofranchising.com.br/franquia-riolax-imobiliarias/', NULL, NULL, '[\"http://www.tribecca.com.br/centraldeservicos/img//%7B9E0B7899-6C73-4DB9-BAA7-AD7FD9425F8F%7D_riolax_01.png\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '200000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75y200ekeh0se3onw5qh', 'DEDAL OFICINA DE COSTURA', 'dedal-oficina-de-costura', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Prestação de serviço em conserto de roupas', 2023, 2023, NULL, '2026-04-01 02:00:06.420', '2025-08-05 22:20:27.099', 561, NULL, 1, 1992, 'Em 1991 Neide de Lourdes Pelissari Figueiredo, até então gerente em uma loja de shopping, fica grávida da segunda filha e resolve abrir um ateliê de costura no Shopping Goiabeiras em Cuiabá, o ponto tinha 20m². No mês seguinte após a abertura, resolve ampliar a loja, pois já não conseguia atender a demanda que surgiu. Em 1997 abre a segunda loja no Shopping Três Américas, também em Cuiabá. Em 2006 abre a terceira loja no Shopping Pantanal, também em Cuiabá. Em 2015 abre a quarta loja no Várzea Grande Shopping, na cidade de Várzea Grande Mato Grosso. Abre ainda a quinta loja no Shopping Estação, em pouco tempo teve que mudar de ponto devido ao sucesso do negócio. Em 2020 enfrenta, com muita persistência e determinação, os desafios causados pela covid-19. Fecha as 5 lojas com mais de 50 funcionárias durante 4 meses. Quando a abertura foi permitida, foca a operação na fabricação de máscaras e supera a crise com muita criatividade. Em 2021 se recupera dos efeitos causados pelo covid-19, voltando a normalidade. O mercado de reformas ficou bastante aquecido no pós-pandemia melhorando os resultados das lojas. Essa melhora ampliou o interesse de investidores pela operação da DEDAL OFICINA DE COSTURA. Missão: Proporcionar conforto e bem-estar para nossos clientes através do ajuste perfeito de suas roupas. Valores: - Respeito - Cooperação - Excelência no serviço - Parceria - Comprometimento - Sustentabilidade - Transparência', NULL, 'MATO GROSSO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/28c78009-7612-4bba-8adb-822ae90684bf.jpg', 6, NULL, NULL, '2025-05-23 13:54:32.000', 'https://franquias.portaldofranchising.com.br/franquia-dedal-oficina-de-costura/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75yb00eleh0so979k5ii', 'DANKI MODA', 'danki-moda', NULL, 'Moda', 'CALÇADOS', 'EMPRESA VOLTADA PARA O SEGMENTO PRÉ ADOLESCENTE NO SETOR DE CALÇADOS, VESTUÁRIO E ACESSÓRIOS.', 2017, 2018, NULL, '2026-04-01 02:00:06.430', '2025-08-05 22:20:27.108', 562, NULL, 1, 2011, '', NULL, 'SÃO PAULO', 1, NULL, 16, NULL, NULL, '2025-08-21 12:28:42.000', 'https://franquias.portaldofranchising.com.br/franquia-danki-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75yj00emeh0sej6hzz2l', 'MEU DEVER DE CASA', 'meu-dever-de-casa', NULL, 'Educação', 'EDUCAÇÃO', 'A Escola de Apoio Meu Dever de Casa oferece dois tipos de serviços: apoio ao processo de alfabetização e curso para o aprimoramento cognitivo através do Método Estudo Eficaz, ambos exclusivos.', 2017, 2018, '[\"https://www.youtube.com/watch?v=o7Gkc52Bz00\"]', '2026-04-01 02:00:06.439', '2025-08-05 22:20:27.116', 563, NULL, 1, 2013, 'Você deseja tornar este mundo um lugar melhor? Só tem um caminho: a educação! E não é esse modelo educacional que vemos… Apesar de muitas escolas oferecerem modelos excelentes, acabam não conseguindo personalizar as demandas das crianças por serem obrigadas a seguir parâmetros legais. Por esse motivo, a busca por apoio escolar é muito grande. Hoje, os pais estão cada vez mais ocupados e, ao mesmo tempo, preocupados com o futuro dos seus filhos, porém com dificuldade para acompanhar a vida escolar. Fica difícil manter o foco, a motivação e a organização, então, a ajuda profissional se torna a alternativa mais viável. Com uma das franquias na área mais rentável do momento, você pode ter bom retorno financeiro e, ainda, transformar a educação desenvolvendo competências e habilidades essenciais às crianças. Ser franqueado do Meu Dever de Casa é uma oportunidade imperdível. Método Estudo Eficaz A Escola de Apoio Meu Dever de Casa é a detentora exclusiva do Método Estudo Eficaz, elaborado pelo economista e educador Paulo Henrique Menezes com base em seus estudos em neuroeducação. A proposta do Método é otimizar o processo de aprendizagem gerando autonomia, concentração e foco. Dividido em três pilares: ambientação, procedimentos e técnicas, o Método Estudo Eficaz promove melhorias incríveis e muito rápidas em cada um dos estudantes. Tudo feito no tempo de cada estudante! Quanto vou investir para abrir uma Franquia? Os custos variam dependendo do modelo escolhido e do local em que a unidade será aberta, pois materiais e mão de obra de serviços oscilam bastante de região para região – o que nos impede de fornecer um valor preciso. - Royalties Os franqueados poderão escolher entre as alternativas de cada modelo. - Fundo de Marketing A empresa não cobra fundo de marketing e oferece apoio na elaboração de materiais. - Materiais de Apoio Além desses valores, o único compromisso do franqueado com a franqueadora é o de comprar o material de apoio e todos os demais itens que a escola desenvolve para vender aos estudantes. Conheça os modelos de Franquias Modelo de Apoio Escolar I Modelo indicado para quem ama educação e sonha em trabalhar com crianças entre 04 e 08 anos e que estejam matriculadas da Pré Escola até o 3º ano do Fundamental 1. O foco é trabalhar o apoio ao processo de alfabetização. Os materiais são lindos, lúdicos, com propostas variadas e exercícios exclusivos. As turmas podem ser montadas com diferentes faixas etárias, pois o atendimento é individualizado. Modelo de Apoio Escolar II Modelo desenvolvido para quem deseja ter uma escola de apoio com atendimento a crianças entre 04 e 10 anos e que estejam matriculadas da Pré Escola até o 5º Ano do Fundamental 1. Além do apoio ao processo de alfabetização com a utilização de todo o material exclusivo, este modelo permite que crianças do 4º e 5º anos do Fundamental 1 possam frequentar a unidade e ter acesso ao Método Estudo Eficaz. As turmas também podem ser mistas, o importante é que os grupos sejam de etapas similares. Modelo de Apoio Escolar III Se a sua preferência é trabalhar com crianças/adolescentes entre 11 e 17 anos que estejam matriculadas entre o 6º ano do Fundamental 2 até o 3º ano do Ensino Médio, este é o modelo recomendado. Totalmente focado no processo de ensinar a estudar sozinho com motivação, independência, foco e prazer, adota o Método Estudo Eficaz em todos os seus materiais. Os horários a serem montados poderão ser mistos, sem preocupação com faixa etária ou nível. Modelo de Apoio Escolar Completo Modelo para quem deseja montar uma Escola de Apoio Meu Dever de Casa Completa, uma escola que atende crianças e adolescentes que estejam matriculadas desde a Pré Escola até o 3º ano do Ensino Médio. Esse modelo oferece todos os serviços - apoio ao processo de alfabetização, aprimoramento cognitivo e reforço escolar. *Para saber mais sobre os valores financeiros entre em contato com nosso time preenchendo o formulário.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e95a7d21-2563-4428-9d6e-c7b2c9552b71.svg', 34, NULL, NULL, '2025-09-10 15:01:39.000', 'https://franquias.portaldofranchising.com.br/franquia-meu-dever-de-casa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ys00eneh0s7s057tvt', 'ALL NET NUCLEO DE FORMAÇAO PROFISSIONAL', 'all-net-nucleo-de-formacao-profissional', NULL, 'Educação', 'EDUCAÇÃO', 'Cursos de Informatica, Idiomas e Profissionalizantes', 1996, 2010, NULL, '2026-04-01 02:00:06.448', '2025-08-05 22:20:27.124', 564, NULL, 1, 1996, 'A primeira unidade All Net foi inaugurada em 1996 na cidade de São Caetano do Sul. Como consequência de seu compromisso com a qualidade de ensino, em poucos meses foi inaugurada a primeira franquia do Grupo, no Grande ABC. Em 2000 abrimos a primeira unidade All Net Idiomas, em Interlagos na cidade de São Paulo, sendo pioneira no sistema audiovisual e cinema. Nossa posição atual no mercado é privilegiada com mais de vinte anos de atuação e mais de 1 milhão de alunos formados. Um número significativo no segmento. Com uma postura inovadora, obtivemos um dos maiores índices de crescimento ao longo dos anos. Nossa missão é formar não apenas profissionais para o mercado de trabalho, mas cidadãos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0485c3dc-9aa9-4fc3-8a18-803726ee4ed7.png', 37, NULL, NULL, '2025-08-13 13:35:34.000', 'https://franquias.portaldofranchising.com.br/franquia-all-net-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75z000eoeh0srtctbbvx', 'VALHALLA', 'valhalla', NULL, 'Alimentação', 'Bares e Restaurantes', 'Hamburgueria e Cervejaria', 2024, 2024, NULL, '2026-04-01 02:00:06.457', '2025-08-05 22:20:27.132', 565, NULL, 1, 2016, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b72af1c1-dd21-4bbb-aac3-f9b12b579299.png', NULL, NULL, NULL, '2026-03-08 22:55:44.946', 'https://franquias.portaldofranchising.com.br/franquia-valhalla/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '410000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75z800epeh0swydynftz', 'POSÉ', 'pose', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Estéticos e Bem-Estar', 'Posê é uma rede de franquias de beleza e estética, com vários modelos de negócio que permite você expandir rapidamente, não se limitando à um serviço especifico. Projeto modular e métodos exclusivos.', 2009, 2011, '[\"https://www.youtube.com/watch?v=wC7zEQYqEs8\",\"https://www.youtube.com/watch?v=bTyM0bhXf6Q\",\"https://www.youtube.com/watch?v=G9BhzE5pPrM\",\"https://www.youtube.com/watch?v=1C2q6JhOqnA\"]', '2026-04-01 02:00:06.466', '2025-08-05 22:20:27.140', 566, NULL, 1, 2009, 'Liderada por sua fundadora, Karla Gomes, a Posê nasceu em 2009 e em pouco menos de uma década passou a estar presente em todas as regiões do Brasil, se consolidando como uma das maiores redes de depilação e sobrancelhas sem hora marcada, laser, beleza e estética, acompanhando tendências mundiais com atualizações constantes, adesão às novas tecnologias, conquistando prêmios por sua qualidade e excelência, atendendo às demandas dos mais exigentes clientes com segurança e respeito.', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1798837d-a42c-4061-9d8a-0d62081e3e03.jpg', 33, NULL, NULL, '2026-03-08 22:56:17.243', 'https://franquias.portaldofranchising.com.br/franquia-pose/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '280000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
