INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761000f1eh0szkz47jy2', 'HIGH TORQUE CAR SERVICE', 'high-torque-car-service', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Oficina de manutenção e reparação automotiva.', 2016, 2020, '[\"https://www.youtube.com/watch?v=UDcvUsNLnko\",\"https://www.youtube.com/watch?v=Q-AhpzyX_H0\",\"https://www.youtube.com/watch?v=azs492xmsfI\",\"https://www.youtube.com/watch?v=IkSsak8N91M\"]', '2026-04-01 02:00:06.573', '2025-08-05 22:20:27.204', 578, NULL, 1, 2016, 'Você possivelmente conheceu a High Torque pelos nossos vídeos no Youtube. Mas, sabe como isso começou? Sabe como uma pequena oficina se transformou em uma franquia de sucesso? Para entender a nossa história é preciso voltar ao ano de 2005, quando o fundador da empresa, Alexandre Dias Generoso (ADG), que trabalhava como taxista durante o dia e em uma oficina na parte da noite, decidiu abrir o próprio negócio. No dia 15 de setembro de 2005 nasce a High Torque, fundada com base em uma sólida experiência no mercado de manutenção automotiva. ADG sempre foi um entusiasta do mundo automotivo, buscando se aperfeiçoar cada vez mais na área e decidiu, então, compartilhar o que sabia em um programa chamado PDO - Por Dentro da Oficina, transmitido pelo canal High Torque no Youtube, alcançando milhares de seguidores. Desenvolvemos o modelo de franquia High Torque Car Service para que você tenha negócio rentável, de gestão descomplicada e prazerosa, que preste serviços confiáveis e de qualidade com preços competitivos. Atuamos em um nicho de serviços automotivos de alto padrão, sendo capazes de atender às demandas de multimarcas em um modelo de negócio honesto e acessível. A High Torque Car Service chegou chegando, com forte presença e diferencial competitivo. Assim, além da excelência em seus processos, a rede preza por oferecer serviços com qualidade aos clientes. Missão Promover o crescimento da marca e a realização pessoal de todos os envolvidos através dos serviços automotivos. Promover mais que manutenção, uma nova experiência em serviços automotivos. Visão Ser a marca de referência nacional em manutenção automotiva de alta qualidade a um preço justo. Valores Confiança Honestidade Qualidade Valorização e respeito aos clientes e colaboradores; Comportamento ético Zelo pela imagem da empresa e honra à marca. Se fossemos resumir a essência do nosso negócio em uma frase, poderíamos dizer que: A High Torque busca promover a satisfação de franqueados, colaboradores e clientes na prestação de serviços automotivos. Somos mais do que uma oficina mecânica, mais que uma marca de sucesso, somos pessoas que buscam se realizar profissionalmente ao atender com qualidade e honestidade nossos clientes.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c36a1822-f987-4027-b62d-4b29fd7cde80.jpg', 10, NULL, NULL, '2026-03-08 23:00:53.498', 'https://franquias.portaldofranchising.com.br/franquia-high-torque-car-service/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '472000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761500f2eh0smb18gexl', '60 Minutos Lavanderia Self-service', '60-minutos-lavanderia-self-service', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', '', 2018, 2021, NULL, '2026-04-01 02:00:06.582', '2025-08-05 22:20:27.209', 579, NULL, 1, 2015, 'As lavanderias self-service, presentes globalmente há mais de 70 anos, estão profundamente conectadas à cultura DIY (Do It Yourself), que promove a eficiência e a minimização do uso de recursos.', NULL, 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/de43840d-7511-46aa-bb7d-e5fefce4c159.jpg', 680, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7548c187-8332-436b-af0a-6f8fe5ece242.jpg', '2026-03-08 23:02:02.052', 'https://franquias.portaldofranchising.com.br/franquia-60-minutos-lavanderia-self-service/', 'Fat. Bruto', 'Fat. Bruto', NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '90000', NULL, NULL, NULL, '10000', NULL, '5', '5', '80000', NULL, 18);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761a00f3eh0su5kdobfo', 'KASCÃO', 'kascao', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Industria e comercio do segmento de sorvetes', 2022, 2024, NULL, '2026-04-01 02:00:06.592', '2025-08-05 22:20:27.214', 580, NULL, 1, 1980, 'A Franquia da Kascão Express surgiu mediante a um sonho antigo da empresa em poder atuar de forma direta com a venda B2C, e poder proporcionar uma experiência única aos nossos clientes e fãs da marca, através da venda de toda a nossa linha de picolés, linha de potes, linha Açaí e principalmente através de nosso serviço que contempla a venda de sorvete de massa com 20 sabores e venda de Açaí com mais de 6 sabores, ambos boleados e servidos em copos de diversos tamanhos, com os complementos a escolha de nossos clientes. Investindo em nossa marca você poderá diversificar seus investimentos com a garantia de retorno esperado entre 18 e 24 meses, com um diferencial muito expressivo através de nossa área de serviço, onde encontrará nossas tendas de sorvete de massa e Açaí.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7b884edc-ce12-471d-854e-bf682dae496e.svg', 86, NULL, NULL, '2026-03-08 23:10:14.601', 'https://franquias.portaldofranchising.com.br/franquia-kascao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '200000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
