INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761p00f6eh0sjtvwvhmu', 'CADE', 'cade', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Trabalhos para dar mais qualidade de vida para os nossos pacientes com dor.', 2024, 2024, NULL, '2026-04-01 02:00:06.619', '2025-08-05 22:20:27.229', 583, NULL, 1, 2019, 'O Centro Avançado da Dor e Especialidades surge a partir de um momento de muita dedicação para com a minha família. \nO meu avô paterno, que enfrentava então fortes dores crônicas, me levou a um estudo e especialização profundo na busca por aliviar e proporcionar qualidade de vida em um momento tão delicado para todos nós. \n \nE a partir dessa busca, identifiquei uma importante lacuna no mercado de cuidados com a saúde, e somado a isso, uma grande determinação e vontade de implantar em cada ponto deste País um centro especializado com atendimentos multidisciplinares com foco em melhora e alívio de dores crônicas. \nNeste momento divido o meu objetivo e apresento uma excelente oportunidade de negócio a cada um de vocês: levar o mesmo conforto que proporcionei a minha família para os lares de todos que precisem do mesmo acolhimento e atuação. \nSeja Bem-vindo a CADE, sua Rede Avançada de tratamento de Dor e Especialidades. \nDr. Lúcio Gusmão Rocha', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/73e09713-5f01-4588-b641-a15816f547a7.png', 2, NULL, NULL, '2026-03-08 23:11:43.304', 'https://franquias.portaldofranchising.com.br/franquia-cade/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761t00f7eh0s0mc2me1d', 'ADONAI RH', 'adonai-rh', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Temos como especialidades, Recrutamento e Seleção de Profissionais de nível operacional, tático e estratégico, Administração de Estágios e no Desenvolvimento Profissional e Empresarial.', 2021, 2022, NULL, '2026-04-01 02:00:06.629', '2025-08-05 22:20:27.234', 584, NULL, 1, 2014, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/16ea04c0-29d8-4eae-9229-90c467f27697.png', 24, NULL, NULL, '2026-03-08 23:12:28.298', 'https://franquias.portaldofranchising.com.br/franquia-adonai-rh/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '14000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761y00f8eh0snto3x79b', 'PARIS SAINT-GERMAIN ACADEMY', 'paris-saint-germain-academy', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Escola de Futebol Premium no Brasil; Líder em Faturamento Nacional no Segmento; Marca Consolidada Mundialmente; Metodologia de Treino do Paris Saint-Germain; Rede em Expansão.', 2005, 2022, NULL, '2026-04-01 02:00:06.638', '2025-08-05 22:20:27.238', 585, NULL, 1, 2005, 'A história da empresa começou com 3 franceses fundadores que se encontraram jogando futebol no Rio de Janeiro em 2010 quando surgiu o projeto de abrir um complexo de futebol inovador baseado no modelo europeu de Fut5 e de campeonatos corporativos. \nO mesmo abriu em 2013 no bairro de Botafogo no coração da Zona Sul carioca depois de mais de 1 ano de obra. \nDurante o processo e com a observação do mercado se destacou a oportunidade de abrir uma escola oficial do clube Paris Saint-Germain. Assim foi feito e em janeiro 2014 foi inaugurada a 1a unidade PSG Academy fora da França. \nLogo percebemos o potencial do negócio e começamos a concentrar nossos esforços no desenvolvimento da operação de escolas de futebol. \nEm um primeiro tempo foi em próprio e apenas no RJ e a partir de 2017 assinamos a master franquia nacional da PSG Academy e começamos a desenvolver Brasil afora tanto com unidades próprias como em franquias. 8 anos depois contamos com 36 unidades - com 7 próprias entre SP, BH e RJ; e 29 franquias de Manaus a Porto Alegre.  \nNelas treinam 9.000 alunos semanalmente com a camisa e dentro da metodologia PARIS SAINT-GERMAIN graças aos mais de 300 treinadores capacitados e constantemente treinados e atualizados.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cfc848b6-dd0a-4367-956d-2512fec21f66.jpg', 42, NULL, NULL, '2026-03-08 23:12:57.091', 'https://franquias.portaldofranchising.com.br/franquia-paris-saint-germain-academy/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza762300f9eh0slic1p3hk', 'SANTO SANTO SANTO', 'santo-santo-santo', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Loja de Presentes Católicos - Acessórios femininos, masculinos e infantil. Itens de decoração para o lar. Imagens. Todos os produtos católicos. Presentes com Fé', 2022, 2025, NULL, '2026-04-01 02:00:06.648', '2025-08-05 22:20:27.243', 586, NULL, 1, 2016, '', NULL, 'SÃO PAULO', 1, NULL, 15, NULL, NULL, '2025-09-18 09:54:23.000', 'https://franquias.portaldofranchising.com.br/franquia-santo-santo-santo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '311000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza762800faeh0sdwr9rj36', 'ALERGOSHOP', 'alergoshop', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Alergoshop, desde 1993 desenvolvendo produtos de forma criteriosa para o seu bem-estar e prevenção das alergias. (cosméticos, saneantes, produtos anti-ácaros, semi-jóias, repelentes etc.)', 2012, 2011, NULL, '2026-04-01 02:00:06.659', '2025-08-05 22:20:27.248', 587, NULL, 1, 1993, 'Desde 1993 a Alergoshop trabalha focada no bem-estar das pessoas. \n  E esta história já começou com um propósito, em um tempo quando ainda não haviam muitas alternativas para alérgicos no Brasil, a Alergoshop chegou e mudou esse cenário.   De lá pra cá investimos muitos em pesquisa e desenvolvimento, ampliamos nossa distribuição com canais físicos e digitais, principalmente com a nossa rede de franquias.    Conquistamos reconhecimento e recomendações dos melhores profissionais da saúde e inúmeros clientes pelo cuidado dos nossos produtos para toda a família, inclusive os pets.   Somos referência em produtos hipoalergênicos de alta qualidade e eficiência, sendo grande parte com selo Cruelty Free e Vegano.   Os números do cenário global confirmam o quanto a nossa presença se faz revelante. Só para se ter uma ideia, segundo a organização mundial da saúde, atualmente:\n  30% da população mundial é alérgica, podendo chegar a 50% até 2040. O Brasil está entre os países que mais consomem cosméticos no mundo. 21,8% das dermatites de contato são desencadeadas por maquiagens e cosméticos. 80% das alergias respiratórias são causadas por fungos e ácaros presentes na poeira doméstica. Passamos 3/4 da vida em ambientes fechados.   Invista em uma franquia da empresa pioneira no Brasil, especializada em produtos para alérgicos e para quem não quer ter alergias ou outros prejuízos à saúde.    Faça parte desse movimento,   Seja um franqueado ALERGOSHOP!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5ec5ad36-e33e-4dc6-91e9-622eecd17322.jpg', 10, NULL, NULL, '2026-03-08 23:14:04.594', 'https://franquias.portaldofranchising.com.br/franquia-alergoshop-beleza-e-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '190000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza762e00fbeh0s8zl7nudj', 'PROHOUSE', 'prohouse', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Loja de colchões', 2010, 2023, '[\"https://www.youtube.com/watch?v=aX3LJDweJeY\",\"https://www.youtube.com/watch?v=vvP-Ay7BEzw\",\"https://www.youtube.com/watch?v=K72CpGZLCFE\",\"https://www.youtube.com/watch?v=jzfa0qkpQk0\"]', '2026-04-01 02:00:06.668', '2025-08-05 22:20:27.254', 588, NULL, 1, 1979, 'A franquia Prohouse Colchões é a rede de lojas do grupo MGA Moveleira com nome e reputação constituídos há mais de 45 anos. Líder de mercado na fabricação de Camas Box e Colchões de grandes redes varejistas, contamos atualmente com mais de 60 lojas Prohouse distribuídas nos estados de São Paulo, Rio de Janeiro e Minas Gerais. A expertise da MGA na fabricação e montagem de colchões e o conhecimento de mercado da Prohouse, se evidenciam nos produtos inovadores e no atendimento personalizado para todas as necessidades e gostos. Foi com base nestes princípios que se criou o modelo de loja de fábrica Prohouse, que reúne em um só espaço, ampla variedade de produtos e complementos para o dormitório em um ambiente agradável, aconchegante e confortável. Produtos exclusivos e inovadores: A gama de diferenciais só é encontrada em um modelo de negócio como o da PROHOUSE Colchões. A expertise da rede PROHOUSE advém da MGA Moveleira na fabricação e montagem de colchões e camas box desde 1979. Marketplace Franqueado: Os produtos vendidos no site Prohouse dentro da região do franqueado são direcionados 100% para o franqueado. Ter uma loja de fábrica possibilita acesso rápido as melhores tecnologias em conforto e relaxamento que o mercado pode oferecer. Estilo moderno de loja especializada de colchões, as lojas PROHOUSE criam um ambiente que traduz aconchego e conforto, além de produtos que facilitam e agregam valor a experiência de compra.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/360c7f9f-fcff-48b0-aa96-537700812a79.jpg', 64, NULL, NULL, '2026-03-08 23:15:01.338', 'https://franquias.portaldofranchising.com.br/franquia-prohouse/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
