INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza763500ffeh0so1g8s6wf', 'CASA PRADO', 'casa-prado', NULL, 'Moda', 'Vestuários', 'Moda masculina', 2018, 2021, NULL, '2026-04-01 02:00:06.707', '2025-08-05 22:20:27.282', 592, NULL, 1, 1955, 'A Casa Prado foi fundada em 11 de Fevereiro 1955 e desde o seu início, traz como principal característica do negócio, seu DNA futurista e contemporâneo ( à frente do seu tempo ). \nNa época, o seu fundador: Sr. José Rodrigues do Prado segmentou o mercado da região, criando uma loja exclusiva de artigos para cavalheiros. \nUma atitude arrojada e inovadora para a época, pois a grande maioria das lojas vendia vários produtos femininos, infantis e masculinos no mesmo espaço físico. \nDurante toda a sua trajetória, a Casa Pardo sempre prezou pelo atendimento de qualidade e exclusivo aos homens de bom gosto, característica marcante e reconhecida por nossos clientes que garantem a perenidade do nosso negócio em nossos 66 anos de existência. \nDesenvolvemos nossa marca própria em 2010 e hoje se tornou o principal produto das nossas lojas, graças à qualidade apresentada de nossos artigos. \nTemos um trabalho forte e consistente de gestão de produtos, conectado com as principais tendências de moda masculina e uma parceria próspera que mantemos com nossos parceiros comerciais em todo Brasil que nos permitem um ganho de eficiência na logística de entrega de nossas mercadorias em nossas unidades próprias e franqueadas e um portfólio que atende as principais exigências de um público seleto e de alto poder econômico. \nA franquia nasceu de um sonho de levar o conceito da Casa Prado para todo Brasil, com a certeza de que possuímos a vocação e interesse genuíno para realizar uma gestão da rede de franqueados de forma próxima, eficaz, com total parceria entre as partes e ancorada na tradição da nossa marca. \nFato este que já acontece com nossos franqueados de SINOP-MT e SORRISO-MT. \nApostamos muito nesse conceito de uma marca que se relaciona com os clientes ao longo de mais de seis décadas, colhemos frutos dessas relações até hoje, fato que tornou a marca sólida, garantindo produtos de alta qualidade e com forte gestão profissional.', NULL, 'MATO GROSSO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5094cf8f-53a2-4022-aee6-c9de739b61e0.jpg', 12, NULL, NULL, '2026-03-08 23:16:54.401', 'https://franquias.portaldofranchising.com.br/franquia-casa-prado/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
