INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza765300fseh0st32pljo0', 'ONCOCLÍNICAS', 'oncoclinicas', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Pioneira no país em gestão de serviços oncológicos, a Oncoclínicas&Co foi fundada em 2010 e hoje é um dos maiores centros de oncologia, hematologia e radioterapia da América Latina.', 2024, 2025, NULL, '2026-04-01 02:00:06.825', '2025-08-05 22:20:27.352', 605, NULL, 1, 2010, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5f0f15da-4c07-487f-9c0c-71ea0aa5a090.png', 4, NULL, NULL, '2026-03-08 23:21:28.931', 'https://franquias.portaldofranchising.com.br/franquia-oncoclinicas-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '600000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza765900fteh0sbn08kxic', 'SUCÃO', 'sucao', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Sucão está inserido no segmento de \"healthy fast food\", proporcionando, de forma única, alimentação saudável e saborosa de maneira rápida e acessível.', 2014, 2016, '[\"https://www.youtube.com/watch?v=MEIyAC0AWLk\"]', '2026-04-01 02:00:06.834', '2025-08-05 22:20:27.357', 606, NULL, 1, 1975, 'Reconhecimento – A mais premiada do País 5x Selo de excelência em franchising; 2019 – 2020 – 2021 – 2022 – 2023 4x Nota máxima (5 estrelas) no Guia de Franquias da PEGN; 2020 – 2021 – 2022 – 2023 Prêmio Retail Design Institute 2022: 1º Lugar médios formatos e 2° Lugar pequenos formatos; Prêmio ABF + Retail Design Institute : 1º lugar na categoria “Embalagens” e 2° lugar na categoria “Projetos de Quiosque”; 7x eleito o melhor “Suco da Cidade” pela revista Veja;  Fast and Healthy Food De olho na expansão de centros comerciais de pequeno, médio e grande porte e nas oportunidades identificadas no mercado de alimentação saudável, o Sucão desenvolveu um projeto sólido e sustentável com um completo e exclusivo portfólio de produtos, baixo custo operacional e margens de contribuição acima da média do mercado de alimentação, inaugurando um novo segmento neste ramo: alimentação saudável e saborosa, com preços competitivos e rapidez na entrega dos produtos: este é o conceito “Fast and Healthy Food”. Para conhecer mais sobre a nossa história, acesse nosso site: www.sucao.com.br Tudo próprio: marketing, indústria e logística Isso é essencial para o dinamismo que o mercado exige: Pesquisa de mercado e desenvolvimento de produtos sempre, alinhados a comunicação de marca; Cozinha central com profissionais especializados, com altíssimo rigor de qualidade e segurança alimentar, sempre atentos às tendências e diretamente ligados ao time de marketing; Logística própria para que tudo isso chegue até a ponta com qualidade, padrão e sob responsabilidade da rede, sem intermediários e elevação de custo para nossos parceiros.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2199d877-74f5-44a9-92ce-702375dd038d.png', 62, NULL, NULL, '2026-03-08 23:21:56.187', 'https://franquias.portaldofranchising.com.br/franquia-sucao-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '295000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
