INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza765o00fweh0s2lik28vb', 'TOLI', 'toli', NULL, 'Moda', 'VESTUÁRIO', 'COMÉRCIO VAREJISTA DE CONFECÇÃO FEMININA', 2003, 2024, NULL, '2026-04-01 02:00:06.863', '2025-08-05 22:20:27.373', 609, NULL, 1, 1992, '', NULL, 'RIO GRANDE DO NORTE', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/435be8e9-7ca5-4802-a4ab-dd350bcf7e9b.png', 27, NULL, NULL, '2025-09-18 16:32:24.000', 'https://franquias.portaldofranchising.com.br/franquia-toli-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza765t00fxeh0s8ag44rs2', 'ZÉ COXINHA', 'ze-coxinha', NULL, 'Alimentação', 'Bares e Restaurantes', 'Lanches rápidos e casuais, rápida implementação, espaços reduzidos, atendimento rápido com salgados fritos e assados, preços acessíveis e baixo custo de implantação.', 2011, 2022, '[\"https://www.youtube.com/watch?v=dsovxnrlNbI\",\"https://www.youtube.com/watch?v=jS5ekEbAmm4\",\"https://www.youtube.com/watch?v=X8xWxmsUaO8\",\"https://www.youtube.com/watch?v=5CjRQM6Q8a0\"]', '2026-04-01 02:00:06.872', '2025-08-05 22:20:27.377', 610, NULL, 1, 2011, 'Fundado em 2011 no município de Vila Velha, Espírito Santo, o Zé Coxinha é a marca pioneira em venda de salgados na caixa. Seu grande diferencial é ter produtos de ALTA QUALIDADE, PREÇO ACESSÍVEL E MUITO SABOROSOS! Em 2019, o Grupo Vó Alimentos, empresa especializada na produção e comercialização de salgados fritos, assados e pães de queijo juntou-se à NAZCA Co, especialista em estruturação empresarial, inteligência, desenvolvimento e gestão de negócios. Após o feito, a franquia Zé Coxinha entrou para a família com intuito de evoluir e proporcionar uma experiência ainda melhor. Em conjunto, nossa missão e propósito é levar muito sabor de forma acolhedora para você se sentir em casa, por meio de nossa rede de distribuição e lojas franqueadas. Hoje contamos com mais de 40 lojas nos estados do ES, MG e RJ. A proposta para os próximos anos é consolidarmos todas as unidades existentes e avançar com novas inaugurações, tendo como objetivo alcançar 400 lojas. O Zé Coxinha possui uma área de 3.000m² localizada em Serra/ES, onde são fabricados todos os salgados chegando a 100mil coxinhas por dia. Com investimento de 2milhões em melhorias na nossa planta fabril, o Zé Coxinha faz a entrega em todas as lojas, com carros e caminhões refrigerados e equipados para o transporte adequado de produtos congelados. O investimento inicial de R$90mil inclui todos os equipamentos, taxa de franquia, reforma e obras, contratação de mão de obra, sistema, estoque inicial, capital de giro e abertura da empresa. As vantagens em ser um franqueado Zé Coxinha: fábrica própria, baixo investimento, baixo custo operacional, implementação ágil, operação simples, mix de produtos, suporte antes e depois da inauguração. Invista em um negócio prático, gestão simples, ótimos resultados e baixo custo de investimento. Você pode lucrar até 1 milhão por ano com uma opção rápida e simples para você começar a funcionar em 30 dias.', NULL, 'ESPÍRITO SANTO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e8941b33-9176-4df5-9e4a-e6547da35e87.png', 24, NULL, NULL, '2026-03-08 23:23:53.026', 'https://franquias.portaldofranchising.com.br/franquia-ze-coxinha/', NULL, NULL, NULL, 1, 5, 10, 2, 'MAINTAIN', 0, 0, NULL, '140000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza765y00fyeh0sych2qd3a', 'NAÇÃO VERDE', 'nacao-verde', NULL, 'Alimentação', 'EMPÓRIOS, MERCADOS E LOJAS DE CONVENIÊNCIA', 'Primeira franquia de produtos naturais do Brasil com 3 linhas de produtos e 3 canais de venda: varejo, venda direta em atacado, e e-commerce em um mesmo local e integrado com tecnologia própria.', 2012, 2018, '[\"https://www.youtube.com/watch?v=A9Nw24d_M8g\",\"https://www.youtube.com/watch?v=pqwGzMrBFf8\"]', '2026-04-01 02:00:06.881', '2025-08-05 22:20:27.382', 611, NULL, 1, 2010, 'A franquia Nação Verde é para você que busca muito mais do que lucratividade, é para você que busca um propósito! Com a franquia Nação Verde você vai impactar a vida de milhares de pessoas na sua região, vai levar mais saúde, mais alegria, vai se tornar referência local para quem busca uma vida melhor. Nunca empreendeu? Nós temos uma equipe de profissionais altamente capacitados para te acompanhar nessa sua jornada empreendedora e te ajudar a conquistar os seus sonhos. Motivos para investir no mercado de alimentação saudável: Venda de alimento saudável bate R$ 100 bilhões em 2020, em meio à pandemia. Foi a maior cifra para essa categoria de alimentos desde 2006 (Euromonitor). No final de 2020 foi feito um estudo pela Euromonitor para avaliar como estava a alimentação do brasileiro na pandemia e descobriu que 78% delas começaram a ficar mais atentas à alimentação e à saúde, e que 53% estavam buscando informação sobre a função dos alimentos. Outra pesquisa feita pela Federação das Indústrias do Estado de São Paulo (Fiesp) com três mil pessoas maiores de 16 anos, em 12 regiões metropolitanas do Brasil, aponta que 80% dos brasileiros buscam por uma alimentação saudável. São mais de 300 produtos próprios que chegam até todas as franquias através de uma central própria de distribuição. - 3 Linhas exclusivas de fabricação própria - Equipe dedicada a criação de novos produtos Hoje somos mais de 100 franqueados! Perfil do franqueado NAÇÃO VERDE Conheça abaixo o perfil que a franquia Nação Verde busca para selecionar franqueados: - Paixão por pessoas e pela atividade de participar de um negócio em rede; - Bom relacionamento interpessoal; - Capacidade de relacionar pessoas para comunicação do negócio; - Capacidade de criação, uso e expansão de network; - Senso de valorização do sucesso da marca e sua importância; - Foco comercial; - Identidade com o propósito da marca, - Disponibilidade e dedicação. Processo de seleção da franquia NAÇÃO VERDE Conheça abaixo quais são as etapas do processo de seleção da franquia Nação Verde: Primeiro contato para verificação de disponibilidade de licença Avaliação de perfil Análise de documentos (COF/CONTRATO) Esclarecimento de dúvidas Contrato e Pagamento Primeira mentoria – Boas vindas e ponto comercial Aprovação de ponto Projeto Implantação Incubadora – treinamento presencial para lojas físicas Inauguração Já consegue se imaginar sendo dono de sua loja Nação Verde? Envie seus dados e receba informações exclusivas sobre como abrir sua própria Franquia Nação Verde.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/71e2b0cc-a332-42cb-bd1c-1c33fce457a6.svg', 99, NULL, NULL, '2025-05-29 00:00:26.000', 'https://franquias.portaldofranchising.com.br/franquia-nacao-verde/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5200091e-6b7f-4bbf-91d4-f161fa51e464.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8ff21873-0b37-45a7-ae83-8b8d2472781b.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza766300fzeh0swt8uh5u7', 'CREPEFY', 'crepefy', NULL, 'Alimentação', 'Bares e Restaurantes', 'Somos a primeira creperia 3 em 1 semiautomática do Brasil, se expandindo através do sistema de franquias.', 2023, 2023, '[\"https://www.youtube.com/watch?v=Ky1yy5TBx7w\",\"https://www.youtube.com/watch?v=wcFjmwH7yFk\",\"https://www.youtube.com/watch?v=yMsSi5ll4kA\"]', '2026-04-01 02:00:06.890', '2025-08-05 22:20:27.387', 612, NULL, 1, 2022, 'SEJA FRANQUEADO  DA ÚNICA CREPERIA SEMIAUTOMÁTICA 3 EM 1  DO BRASIL. Faturamento possível de 500mil/ano, com retorno líquido de 18% a 25% \nInvestimentos a partir de R$49.900,00   Vantagens crepefy Crepe especial como você nunca viu para assustar seus clientes, através da sua store to go smart, delivery Ifood, Rappi e App Próprio + eventos e festas de forma muito inteligente e lucrativa.  Store To Go Smart Uma loja charmosa, objetiva e muito moderna para seus clientes, trazendo o novo conceito. \nO modelo To Go consiste na ideia de que a pessoa compre o seu produto para consumir ao ar livre. \nEssa proposta inovadora e visionária vai totalmente ao encontro com a modernidade e com o novo padrão de comportamento do século 21 – otimizando o tempo e evitando as aglomerações.    Delivery Delivery Ifood, Rappi e App Próprio. Atenda a demanda mais latente dos ultimos tempos.    Eventos Corporativos e Festas Atenda os principais eventos da sua cidade, com um produto rápido, fácil e com uma experiência incrível para os convidados.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e4611045-174b-4543-a591-22607a3954b0.png', 65, NULL, NULL, '2026-03-08 23:25:08.444', 'https://franquias.portaldofranchising.com.br/franquia-crepefy/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '94900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza766800g0eh0sc87ms763', 'FIUZA DAY CARE', 'fiuza-day-care', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Fiuza Day Care é um centro de convivência para idosos que estimula a autonomia e o envelhecimento ativo por meio de atividades sociais, físicas e cognitivas em ambiente acolhedor e dinâmico.', 2025, 2025, NULL, '2026-04-01 02:00:06.900', '2025-08-05 22:20:27.392', 613, NULL, 1, 2014, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/81f7fa7c-014b-490a-a0d1-c425bab52b6b.png', 4, NULL, NULL, '2026-03-08 23:25:50.783', 'https://franquias.portaldofranchising.com.br/franquia-fiuza-day-care-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '420000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza766e00g1eh0ssnzin0xz', 'PLENA VISÃO VISTORIA VEICULAR', 'plena-visao-vistoria-veicular', NULL, 'Serviços Automotivos', 'SERVIÇOS AUTOMOTIVOS', 'Prestação de serviços de vistoria veicular.', 2009, 2015, NULL, '2026-04-01 02:00:06.909', '2025-08-05 22:20:27.398', 614, NULL, 1, 2009, '', NULL, 'SÃO PAULO', 1, NULL, 73, NULL, NULL, '2025-09-16 10:58:22.000', 'https://franquias.portaldofranchising.com.br/franquia-plena-visao-vistoria-veicular-servicos-automotivos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza766l00g2eh0sy794qzws', 'PERSONAL CLEAN PROFESSIONAL', 'personal-clean-professional', NULL, 'Limpeza e Conservação', 'Serviços de Limpeza', 'Modelo de franquia que especializa o franqueado em produtos e processos inovadores para limpeza e desinfecção em ambientes que requeiram cuidados especiais como alimentação, saude, lazer e industrias.', 2015, 2019, '[\"https://www.youtube.com/watch?v=p8gqHFK8ILo\",\"https://www.youtube.com/watch?v=TwrW7ftO9jQ\",\"https://www.youtube.com/watch?v=wvXCsbF0HRQ\"]', '2026-04-01 02:00:06.918', '2025-08-05 22:20:27.406', 615, NULL, 1, 2015, 'PERSONAL CL’EAN especialistas em soluções sustentáveis para higienização. Nossa história decorre da soma de esforços de empreendedores visionários que através de um grupo de empresas sustentáveis que em homologação recíproca atua no mercado de higienização profissional com êxito e crescimento continuo possibilitando que empreendedores integrem neste grupo e difundam a marca em todo território nacional. Iniciamos em 1986 com a exploração do comercio de produtos para limpeza institucional, basicamente nas regiões próximas à sede na cidade de Itatiba, estado de São Paulo. Em 1993, atuando com sucesso em grande parte do estado e sul do estado de Minas Gerais, através de planta moderna e totalmente estruturada passamos a fabricar especialidades voltadas a higienização profissional, com isso conquistando cada vez mais o mercado local e o de outros estados. Uma empresa só é respeitada e se solidifica se agir com idoneidade, responsabilidade, respeito, parceria e profundo conhecimento no que faz, o que lhe assegura operações sadias e confiável contabilmente.  Esses atributos gerados pelos valores do grupo, política, visão e empreendedorismo, ampliaram a atuação e industrialização dando início em 1999 as operações como franqueadores, expandindo assim a marca nos estados do Rio Grande do Sul, Santa Catarina, Espírito Santo, Bahia, Maranhão e São Paulo através de Franquias O sistema foi reconhecido no ranking do Guia de Franquia da revista Pequenas Empresas Grandes Negócios, publicado pela Editora Globo, por dois anos consecutivos em satisfação do franqueado, crescimento, melhor marca para se investir e excelência em desempenho. Por esses motivos destacamo-nos dentre inúmeras empresas no ramo industrial, em especial o de higienização profissional, por não nos limitarmos a um segmento apenas, desenvolvemos a química usual, tradicional àquela que preserva e mantém a vida, inovando e agregando diversos segmentos do mercado. Vantagens em optar pela franquia PERSONAL CL’EAN O mercado de higienização cresce de forma constante e regular e o Brasil é o quarto maior mercado do mundo em produtos de limpeza. Limpeza e sanitização são requisitos de saúde. Há carência de produtos e soluções mais rentáveis e inovadoras. Exclusividade na área de atuação Mercado seguro Baixo custo operacional Treinamento completo Franquia direto da indústria Independência financeira Pagamento facilitado Preços competitivos Retorno rápido do investimento Acompanhamento e capacitação permanentes  Alta tecnologia e inovações de produtos Excelente margem de lucratividade Área planejada para o crescimento da franquia', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a9f094ea-379c-4488-97a5-b51390b589a0.jpg', 13, NULL, NULL, '2026-03-08 23:26:34.154', 'https://franquias.portaldofranchising.com.br/franquia-personal-clean-professional/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '83000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza766r00g3eh0syqio83e4', 'SOLAR21', 'solar21', NULL, 'Serviços e Outros Negócios', 'SERVIÇOS ADMINISTRATIVOS', 'Especialista em soluções de energia com tecnologia própria, atuação nacional e modelo inovador. E foco em relacionamento de longo prazo.', 2023, 2023, '[\"https://www.youtube.com/watch?v=7LESp15AwYc\",\"https://www.youtube.com/watch?v=7h-gAbf7jYY\"]', '2026-04-01 02:00:06.927', '2025-08-05 22:20:27.411', 616, NULL, 1, 2017, 'História de sucesso: Temos uma história sólida de mais de 6 anos. Crescemos 7x em 2022 em número de clientes, chegando a mais de 800 projetos em 200 cidades brasileiras, com uma geração de mais de 3mil cadastros mensais em nossa plataforma. Captamos mais de R$ 20 milhões nos últimos dois anos, o que nos permitiu crescer rápido, construir uma marca forte e desenvolver tecnologia de ponta. Time fundador experiente: dois dos nossos fundadores, o Vinicius Ferraz (CEO) e o Rafael Magossi (CTO), são engenheiros eletricistas e formados pela Universidade de São Paulo (USP), com experiência em grandes projetos de Engenharia e Tecnologia. Foco no cliente: Nós somos uma empresa “foco no cliente”, visão estratégica fundamental hoje em dia para que uma empresa tenha sucesso, gerando: mais venda, mais credibilidade, maior satisfação e fidelização do cliente. De acordo com uma pesquisa da consultoria Deloitte, as organizações que aplicam essa estratégia registram 60% a mais de lucro do que as que não têm o cliente em foco. Gigantes como a Amazon e a Apple são excelentes exemplos de marcas que adotaram essa proposta, ressaltando a importância dessa estratégia. A Franquia Solar21 é diferente de todas do mercado e vamos te explicar em 3 motivos: Máquina de vendas: Garantimos uma alta geração de leads para que o franqueado possa vender mais e aumentar a sua receita. Temos uma grande relevância no digital e o franqueado se beneficia de forma direta. Tecnologia e Plataformas: temos tecnologia de alto nível de ponta a ponta, como a Plataforma cliente que permite a contratação rápida e segura, o nosso App próprio de monitoramento, para que o cliente acompanhe a sua usina solar em tempo real e a Plataforma franqueado, permitindo que você possa gerir a sua carteira de clientes o tempo inteiro, te dando agilidade para crescer de forma acelerada. Consultoria dedicada ao Franqueado: temos um time operacional experiente que será responsável pela sua Franquia em diversas frentes: engenharia, comercial, marketing, atendimento ao cliente, planejamento estratégico etc, tudo para que você tenha o melhor planejamento e consiga executá-lo da melhor forma possível, levando a sua franquia ao sucesso.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c4d8a5ba-5644-452c-8df1-1aac3aeab908.png', 25, NULL, NULL, '2025-09-09 15:39:16.000', 'https://franquias.portaldofranchising.com.br/franquia-solar21/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
