INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza767200g5eh0s20xbaw6u', 'VINHO 24H', 'vinho-24h', NULL, 'Alimentação', 'Mercados e Distribuição', 'A Vinho24h é uma franquia de adegas autônomas instaladas em condomínios, oferecendo vinhos de qualidade a preço fixo, com autoatendimento 24h e sem necessidade de funcionários.', 2024, 2025, NULL, '2026-04-01 02:00:06.945', '2025-08-05 22:20:27.422', 618, NULL, 1, 2024, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1ae49e86-d87b-4ca2-b605-beab62ad63ca.png', 1, NULL, NULL, '2026-03-08 23:28:21.409', 'https://franquias.portaldofranchising.com.br/franquia-vinho-24h/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza767700g6eh0s4b4d993k', 'SAL E BRASA GRILL', 'sal-e-brasa-grill', NULL, 'Alimentação', 'Bares e Restaurantes', 'Restaurantes de Fast Food localizado em Lojas de Shoppings ou de Supermercados.', 2015, 2016, '[\"https://www.youtube.com/watch?v=DvuU7kxzqU4\"]', '2026-04-01 02:00:06.954', '2025-08-05 22:20:27.427', 619, NULL, 1, 2010, 'O Grupo Sal e Brasa iniciou suas atividades no interior de São Paulo, em 1993, com a inauguração da sua primeira churrascaria. Em 2010, foi dada a largada do processo de expansão da marca no modelo Fast Food, quando nasceu a Sal e Brasa Grill Express. Em 2015, iniciamos o nosso modelo de franquias, que em apenas 3 anos despontou como umas das redes de grelhados que mais cresceram no Nordeste. Hoje já são mais de 50 lojas espalhadas pelo Brasil.', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c5e0a271-5c52-410f-845b-f6346f3da399.jpg', 42, NULL, NULL, '2026-03-08 23:28:46.198', 'https://franquias.portaldofranchising.com.br/franquia-sal-e-brasa-grill-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '430000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
