INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza768100gbeh0s0jwfpxt2', 'PORTO DO SABOR', 'porto-do-sabor', NULL, 'Alimentação', 'Bares e Restaurantes', 'Rede de alimentação saudável especializada no preparo de açaí, sucos, sanduíche natural, crepes, omeletes, refeições e saladas.', 2014, 2016, NULL, '2026-04-01 02:00:07.009', '2025-08-05 22:20:27.457', 624, NULL, 1, 1997, 'Há 22 anos a família Wolfram abria a primeira unidade da marca Porto do Sabor no Shopping Novo Leblon, na Barra da Tijuca. Ainda com o conceito de Delicatessen, aquela loja seria a fonte de renda para uma mãe, uma avó e seus três netos. Os consumidores locais traziam a demanda por produtos diferentes dos que eram comercializados e foi assim que o “melhor açaí do Rio” surgiu, além de outros produtos que compõem o mix atual. Com receitas passadas de geração para geração que conquistou não somente o paladar dos clientes, mas despertou o desejo de empreender, desde 2014 o Porto do Sabor se tornou uma Rede de Franquias para poder cumprir sua missão.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/37aaa848-25ac-447c-86fe-8f505f4ea47d.jpg', 38, NULL, NULL, '2026-03-08 23:30:43.080', 'https://franquias.portaldofranchising.com.br/franquia-porto-do-sabor/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza768900gceh0sn78o3xbr', 'POYOS', 'poyos', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'Franquia de alimentação – fast casual especializado em frango frito crocante, unindo qualidade e agilidade no atendimento via delivery, take away e consumo express.', 2023, 2025, NULL, '2026-04-01 02:00:07.020', '2025-08-05 22:20:27.465', 625, NULL, 1, 2019, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/66487495-f423-4c22-b296-7fd228b749cf.png', 8, NULL, NULL, '2025-09-16 11:14:23.000', 'https://franquias.portaldofranchising.com.br/franquia-poyos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
