INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza768u00gfeh0s0defu5nw', 'HENRIMAR', 'henrimar', NULL, 'Casa e Construção', 'Construção e Reforma', 'Venda de Piscinas de Fibra, Equipamentos e Acessórios de Lazer', 2017, 2019, '[\"https://www.youtube.com/watch?v=MtkfsJDvnLs\",\"https://www.youtube.com/watch?v=KWKIBIkSTcg\",\"https://www.youtube.com/watch?v=I-4YEN7xr5c\"]', '2026-04-01 02:00:07.047', '2025-08-05 22:20:27.486', 628, NULL, 1, 1988, 'Com 35 anos de experiência, a Henrimar é uma empresa líder no setor de piscinas que oferece uma oportunidade única para você se tornar um franqueado de destaque. Nossa trajetória de sucesso é impulsionada por um compromisso inabalável com a satisfação do cliente, que se reflete em nossas três indicações ao prestigioso prêmio Reclame Aqui. Além disso, somos a única empresa no segmento de piscinas com a certificação ISO 9001, garantindo a qualidade excepcional de nossos produtos. Com 16 modelos e mais de 70 tamanhos de piscinas em nosso portfólio, oferecemos uma variedade de opções incomparável no mercado. Estamos particularmente interessados em expandir nossa presença em diversas cidades estratégicas, incluindo: MINAS GERAIS: Passos, Boa Esperança, Alfenas, Lavras, Poços de Caldas, Pouso Alegre, Patos de Minas, Uberlândia, Uberaba, Araguari, Catalão, Pará de Minas, Araxá. PARANÁ: Londrina, Maringá, Campo Mourão. SÃO PAULO: Presidente Prudente, Marília, Bauru, Rio Claro, Leme, São João da Boa Vista, Guarulhos, Taubaté, Litoral Norte e Litoral Sul. RIO DE JANEIRO: Volta Redonda, Nova Iguaçu, Itaboraí, Cabo Frio, Macaé, Búzios, Itaperuna, Campos dos Goytacazes. GOIÁS: Itumbiara, Anápolis, Goiânia, Aparecida de Goiânia, Rio Verde, Jataí, Quirinópolis. ESPIRITO SANTO: Guarapari, Vila Velha, Linhares. DISTRITO FEDERAL: Brasília e cidades satélites. Junte-se a nós e faça parte do nosso sucesso em sua região!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/79a073bf-e946-45ff-b042-f1cf5b73ee62.jpg', 61, NULL, NULL, '2026-03-08 23:32:05.377', 'https://franquias.portaldofranchising.com.br/franquia-henrimar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
