INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza769500gheh0ssb9x5x73', 'RENT A BOX', 'rent-a-box', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Locação de espaços/boxes - Guarda Móveis, Guarda tudo.', 2012, 2025, NULL, '2026-04-01 02:00:07.065', '2025-08-05 22:20:27.497', 630, NULL, 1, 2006, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/de667717-94fd-4be3-8b41-6956cd906702.png', 5, NULL, NULL, '2026-02-10 13:37:47.000', 'https://franquias.portaldofranchising.com.br/franquia-rent-a-box-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '610000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza769a00gieh0swusci90i', 'CLUBE MORENA ROSA', 'clube-morena-rosa', NULL, 'Moda', 'Vestuários', 'A Clube Morena Rosa é o modelo de franquia do Grupo Morena Rosa, com 30 anos de mercado. Reúne o melhor da moda num único espaço com as grifes Iódice, Lebôh, Maria Valentina, Morena Rosa, e Zinco.', 2014, 2018, '[\"https://www.youtube.com/watch?v=xiU7fPPGt7U\"]', '2026-04-01 02:00:07.075', '2025-08-05 22:20:27.503', 631, NULL, 1, 1993, 'Com o objetivo de ser um ponto de encontro entre os diferentes estilos da mulher brasileira, a Clube Morena Rosa se destaca pelo atendimento multicanais, uma equipe dedicada à inovação e pela experiência presente em cada detalhe, que trazem significado e vão muito além do consumo. Entre as marcas, a Morena Rosa evidencia o protagonismo feminino e aposta em criações que aliam design, conforto e sensualidade. O lado sofisticado e prático da mulher contemporânea aparece na Maria Valentina que traduz versatilidade em peças essenciais para a rotina cosmopolita. A Zinco traz o estilo jovem e descontraído de quem sabe aproveitar o melhor da vida. A Lebôh, por sua vez, se destaca pelo design urbano, que revela a personalidade única de cada consumidora. Já a Iódice apresenta uma moda exclusiva e atemporal, que veste uma mulher confiante e autêntica. Fundador da rede de franquias, o Grupo Morena Rosa, holding paranaense, consolidada, com 30 anos de história no mercado da moda, conta com mais de 1500 colaboradores e um parque fabril de 24.000 m2 em Cianorte-PR. Além da capacidade produtiva, a empresa é parceira do meio ambiente com soluções para o descarte adequado de resíduos e atua com programas de bem-estar junto aos colaboradores através do Instituto Morena Rosa. Criada em 2014, a ClubeMR conta com uma flagship na Oscar Freire, que ocupa 654m2 no famoso endereço paulistano. Com fachadas padronizadas e um rótulo exclusivo de espumante, a franquia surpreende clientes em todo o Brasil. Comprometida com o propósito de oferecer uma moda única, versátil e apaixonante, tem a meta de alcançar 100 franquias até 2024.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/faf6880d-d2eb-428f-9ec5-518f59e5bc63.png', 38, NULL, NULL, '2026-03-08 23:33:41.414', 'https://franquias.portaldofranchising.com.br/franquia-morena-rosa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '450000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza769f00gjeh0sdxt8zot7', 'DUDALINA', 'dudalina', NULL, 'Moda', 'VESTUÁRIO', '● A DUDALINA, marca da Veste S.A. Estilo, empresa do setor de vestuário e acessórios de alto padrão no Brasil, apresenta seu novo conceito de loja, pensado após um rebranding que marca o novo momento.', 2010, 2024, NULL, '2026-04-01 02:00:07.085', '2025-08-05 22:20:27.508', 632, NULL, 1, 1957, '', NULL, 'SÃO PAULO', 1, NULL, 3, NULL, NULL, '2025-08-22 18:20:09.000', 'https://franquias.portaldofranchising.com.br/franquia-dudalina-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '200000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
