INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ah00gqeh0ska45scub', 'B LASER DEPILAÇÃO A LASER E ESTÉTICA', 'b-laser-depilacao-a-laser-e-estetica', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'A B\'Laser é uma clínica especializada em depilação a laser e estética, reconhecida pela excelência em tratamentos personalizados, tecnologia de ponta e atendimento qualificado para garantir resultados', 2020, 2024, NULL, '2026-04-01 02:00:07.153', '2025-08-05 22:20:27.545', 639, NULL, 1, 2013, '', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f0fa5b5b-8c29-403a-ba88-301444f7a6b4.png', 12, NULL, NULL, '2025-06-05 17:02:35.000', 'https://franquias.portaldofranchising.com.br/franquia-b-laser-depilacao-a-laser-e-estetica-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76an00greh0sgvivktl8', 'AÇAÍ NO KILO', 'acai-no-kilo', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Empresa do segmento de gelados, com lojas de Açaí no sistema Self-Service. Estrutura completa de suporte ao Franqueado em todas as fases do negócio. Operação inovadora e agrada todo tipo de público.', 2018, 2020, '[\"https://www.youtube.com/watch?v=v2pYI5U1QZ8\"]', '2026-04-01 02:00:07.162', '2025-08-05 22:20:27.552', 640, NULL, 1, 2017, 'Com a primeira loja inaugurada em 7 de outubro de 2017, em Euclides da Cunha, Bahia, a marca Açaí NoKilo se tornou a franquia de açaí com maior crescimento no estado. \nA rede que nasceu do sonho da empresária Elisângela Lavina Siqueira, em proporcionar uma experiência de consumo personalizada e acessível, é formada por uma equipe com mais de 10 anos de expertise no ramo de gelados comestíveis. \nCom a crescente demanda no consumo de açaí no país e a percepção da empresária sobre a praticidade do sistema self service, um modelo de negócio foi criado com o objetivo de inovar o formato já existente no mercado. Diferenciado não apenas pela qualidade dos seus produtos mas, pela variedade e preços competitivos, associados a um ambiente bonito, agradável, o formato oferece praticidade aos consumidores. Nas lojas, cada mobiliário e produto é posicionado estrategicamente, para garantir uma experiência de consumo agradável e exclusiva. \nA rede que já conta mais de 45 lojas em toda a Bahia, além de unidades em processo de instalação em outros estados, é a própria fabricante dos açaís e cremes comercializados, garantindo melhores margens, autonomia e ainda, o lançamento de novos sabores durante todo ano. Outro diferencial da franquia Açaí NoKilo está no sistema logístico da rede que é próprio, garantindo a entrega no tempo e quantidade ideais para o bom funcionamento do negócio. \nCom a comercialização de produtos exclusivos, o Açaí NoKilo tem como objetivo oferecer ao mercado de franchising um negócio de baixo investimento e ótima lucratividade, formando uma rede de parceiros com capacidade para crescer, conquistando o setor com produtos e atendimento de qualidade.  \nO Açaí NoKilo conta com cinco formatos de operação, que possibilitam aos diversos perfis de investidores a realização do sonho de empreender:  \n- Quiosque NoKilo;\n- Loja Container;\n- Mini Loja NoKilo;\n- Loja padrão, e;\n- Loja Premium. \nDiferentes entre si, os formatos de operação são alicerçados no mesmo propósito: NUTRIR A VIDA COM EMOÇÕES POSITIVAS.  \nProporcionando bons momentos às famílias e consumidores de açaí, hoje o Açaí NoKilo é sinônimo de praticidade, entretenimento, sucesso de expansão e lucratividade. Faça parte dessa família que não para de crescer!', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d1e9df60-6c47-47ea-8c8e-e99beecea6d2.jpg', 57, NULL, NULL, '2026-03-08 23:36:59.787', 'https://franquias.portaldofranchising.com.br/franquia-acai-no-kilo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '160000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76aw00gseh0ssru6oe6c', 'Amo Vacinas', 'amo-vacinas', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', '', 2021, 2021, '[\"https://www.youtube.com/watch?v=oP_5UVBhsYM\",\"https://www.youtube.com/watch?v=TFzakE-ENZo\"]', '2026-04-01 02:00:07.171', '2025-08-05 22:20:27.560', 641, NULL, 1, 2016, 'A Amo Vacinas nasceu do sonho e da visão empreendedora das irmãs Juliana e Thaís Farias, que uniram suas experiências no setor da saúde e no marketing digital para transformar a forma como o Brasil vivencia a vacinação. Inspiradas por uma experiência familiar significativa — quando seu pai, médico respeitado, adquiriu uma geladeira tecnológica para o armazenamento de vacinas — elas enxergaram a oportunidade de criar um modelo de negócio inovador, capaz de unir humanização, eficiência e tecnologia.', NULL, 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a2fc012c-d418-45ef-88d9-aa9e9ecb2e0b.png', 48, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fa74768b-c625-4bcc-864a-aefc9a485b1d.jpg', '2026-03-09 15:40:41.855', 'https://franquias.portaldofranchising.com.br/franquia-amo-vacinas/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0db8c626-d34c-469f-9e58-7b3ac64de52c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d3dfd2be-2727-4b73-9068-30b800bcc472.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d68bbc97-fdca-4097-b1c6-19bdc296a2e7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4a4a4e5d-357a-4ee0-b592-7321a865415d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b8e29474-666e-40d3-9752-bdaffd6d8fe5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/33fc7f86-820b-4d4d-b580-01ceb6d593bf.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '350000', NULL, NULL, NULL, '60000', NULL, '5', '2', '250000', '40000', 40);
