INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76bb00gueh0s5654meq9', 'BRED CAPAS', 'bred-capas', NULL, 'Comunicação, Informática e Eletrônicos', 'ELETRÔNICOS', 'Venda de acessórios para celular, eletrônicos e assistência técnica especializada.', 2017, 2019, NULL, '2026-04-01 02:00:07.190', '2025-08-05 22:20:27.575', 643, NULL, 1, 2017, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8d4c75f0-7d3b-4862-be3c-c62a160b1ad6.png', 55, NULL, NULL, '2025-08-18 09:23:04.000', 'https://franquias.portaldofranchising.com.br/franquia-bred-capas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76bi00gveh0snrmncibd', 'REDEVERDE JARDINS E ECONEGOCIOS', 'redeverde-jardins-e-econegocios', NULL, 'Casa e Construção', 'MANUTENÇÃO', 'Jardinagem e paisagismo, jardins, manejo ambiental, rec. de área degradada, mitigação ambiental, neutralização de carbono, horta urbana, parede e telhado verde, transplante de arvores, arborização,', 2017, 2017, NULL, '2026-04-01 02:00:07.199', '2025-08-05 22:20:27.583', 644, NULL, 1, 2001, '', NULL, 'SANTA CATARINA', 1, NULL, 2, NULL, NULL, '2025-09-09 13:48:37.000', 'https://franquias.portaldofranchising.com.br/franquia-redeverde-jardins-e-econegocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76bq00gweh0scjk3aymo', 'MAIS NATURAL', 'mais-natural', NULL, 'Alimentação', 'Mercados e Distribuição', 'Invista em saúde e qualidade de vida! O seu próximo negócio é Mais Natural, franquia com 10 anos de experiência e mais de 40 lojas por todo país! Vem ser Mais Natural você também!', 2012, 2021, '[\"https://www.youtube.com/watch?v=M606eCgudBU\",\"https://www.youtube.com/watch?v=LDAv0R74Q2A\"]', '2026-04-01 02:00:07.209', '2025-08-05 22:20:27.590', 645, NULL, 1, 2008, 'A necessidade da população em procurar alimentos saudáveis e a preocupação com a qualidade de vida faz do investimento em produtos naturais um negócio certo e lucrativo. Pensando em cada um desses detalhes é que nasceu a Mais Natural, a primeira franquia gaúcha de lojas de produtos naturais. A proprietária Sandra Marasca Martini, na condição de farmacêutica e de produtora rural, percebeu a necessidade de agregar valor à produção de grãos, desde seu cultivo, processamento até o seu consumo. Por isso, o diferencial da Mais Natural é levar produtos direto do campo até a mesa do consumidor. Cada grão é cultivado e processado com acompanhamento especial em lavouras cultivadas pela própria empresa, o que garante procedência e qualidade nos produtos. Oferece também produtos provenientes da agricultura orgânica, cultivados sem agrotóxicos ou fertilizantes químicos. A franquia que foi fundada em 2012, completa 10 anos em 2022, e está presente em diversos Estados do Brasil não para de crescer, pelo profissionalismo e experiência em sua administração, impulsionada pela crescente demanda por alimentos naturais diferenciados e de valor nutricional melhorado. TENHA SUA FRANQUIA MAIS NATURAL! E agora você pode realizar seu sonho de empreender em um dos setores (alimentação saudável) que mais cresce no Brasil e no mundo. A Mais Natural proporciona a você a oportunidade de trabalhar para você e não para os outros. Na Mais Natural, você tem a oportunidade de trabalhar e administrar o seu próprio negócio: a sua Franquia Mais Natural. E não é só isso, você vai gerir uma loja para ter SUA INDEPENDÊNCIA FINANCEIRA com um GRANDE PROPÓSITO: melhorar a vida e a saúde das pessoas na sua cidade ou região. INVISTA COM TOTAL SEGURANÇA! Empreender é um sonho da maioria das pessoas, mas muitos fracassam, porque não tem o conhecimento específico do ramo em que vão atuar e o tempo que levam para aprender acaba consumindo todo o capital existente. NA MAIS NATURAL VOCÊ NÃO VAI ESTAR SOZINHO, nós temos uma super equipe para ajudar você em todos os momentos. Conte conosco para: Apoiar você a encontrar o melhor ponto comercial e criar sua estrutura de gestão; Ter um software com tudo que você precisa para administrar sua empresa; Ter os melhores fornecedores do mercado e uma LINHA EXCLUSIVA com marca própria; Melhorar sua rentabilidade com nossa INDÚSTRIA E DISTRIBUIDORA próprias; Treinar os seus colaboradores com um sistema de EAD que fará sua loja vender mais e ter clientes encantados; Melhorar sua capacidade de gestão com palestras, mentorias e encontros mensais; Ter uma LOJA ONLINE e poder vender tanto presencial quanto pela internet; Ajudar a “bombar” suas redes sociais com treinamentos na área do marketing digital.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/855d84b5-6079-4024-be1d-6e9872716182.jpg', 37, NULL, NULL, '2026-03-08 23:43:26.301', 'https://franquias.portaldofranchising.com.br/franquia-mais-natural/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
