INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76co00h2eh0su3jc1jeb', 'CALZOON MINI CALZONES', 'calzoon-mini-calzones', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fast Food de Calzones, Massas, Sucos e Açaí', 2012, 2011, NULL, '2026-04-01 02:00:07.263', '2025-08-05 22:20:27.624', 651, NULL, 1, 1999, 'Maior rede de calzones do Brasil! Com modelo fast food de alimento saudável, a Calzoon, desde 1999, marcou presença e conquistou o público de 26 estados do País. A rede de franquias é especializada em calzones e sucos e é considerada uma marca rápida, prática e eficiente no atendimento de um público diversificado.  A rede de franquias tem layout moderno, diferenciado e dispõe de 3 modelos de negócio: express, loja e shopping. Oferecer um produto que atende vários públicos, sem manipulação de alimentos ou desperdícios, são alguns dos pontos vantajosos da franquia de sucesso.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4cf50830-032d-400a-8954-f896084ee617.jpg', 35, NULL, NULL, '2026-03-08 23:46:19.713', 'https://franquias.portaldofranchising.com.br/franquia-calzoon-mini-calzones/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ct00h3eh0sd531godt', 'SUPER PIZZA PAN', 'super-pizza-pan', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Ramo de pizzaria com massa pan. Atendimento delivery e restaurante.', 2009, 2022, NULL, '2026-04-01 02:00:07.273', '2025-08-05 22:20:27.630', 652, NULL, 1, 2005, 'HISTÓRIA A Super Pizza Pan, empresa 100% brasileira, iniciou suas atividades em julho de 2005, mais precisamente na Avenida Salgado Filho, na Cidade de Guarulhos, Estado de São Paulo. Oferecendo um ambiente agradável e produtos de excelente qualidade e sabor, o público da região foi rapidamente conquistado. Como resultado de um “delicioso” trabalho, mas feito com muita dedicação, seriedade e, principalmente, respeito aos seus clientes, funcionários e fornecedores, não demorou muito para a inauguração da segunda loja, também localizada na Cidade de Guarulhos, já sob o sistema de franquia. MISSÃO Levar alegria por meio de nossas pizzas aos lares de nossos clientes. VISÃO Ser reconhecida pela excelência na qualidade, sendo a pizza mais desejada dos brasileiros. VALORES Respeito Credibilidade Qualidade Inovação', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/69a1c0ad-8c44-47b6-9cd1-0c17bde13c62.jpg', 20, NULL, NULL, '2026-03-08 23:46:52.264', 'https://franquias.portaldofranchising.com.br/franquia-super-pizza-pan/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76cz00h4eh0sqtq8gbkb', 'SORVETES ROCHINHA', 'sorvetes-rochinha', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'A Sorvetes Rochinha é uma marca renomada no mercado de sorvetes, especialmente conhecida por seu público AB e por sua história de mais de 40 anos.', 2016, 2017, '[\"https://www.youtube.com/watch?v=P_9g9_w5bBQ\",\"https://www.youtube.com/watch?v=yzfAcUDg1WI\"]', '2026-04-01 02:00:07.282', '2025-08-05 22:20:27.635', 653, NULL, 1, 1980, 'Com mais de 40 anos de história, os Sorvetes Rochinha ficaram famosos nas areias das mais belas praias do litoral de São Paulo, graças a sua qualidade e sabor natural derivado das frutas frescas utilizadas na produção. Continuamos trazendo a missão de entregar a todos os estilos de consumidores, sorvetes de alta qualidade e que remetam a momentos inesquecíveis. Somado ao orgulho de nossas origens e o comprometimento com a sustentabilidade. Sendo franqueado da Rochinha, você sempre ganha: Acesso a um modelo de negócio comprovado e de sucesso. Reconhecimento de uma marca forte e consolidada. Estratégias de marketing eficazes e materiais promocionais. Ampla rede de franqueados para compartilhar experiências. Suporte contínuo e treinamento especializado. Produtos de alta qualidade e grande aceitação no mercado. Orientação sobre gestão e melhores práticas operacionais. Potencial de crescimento e retorno financeiro atrativo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2a2ab4ef-4ae4-43b6-9ab4-6b33bdb805df.png', 23, NULL, NULL, '2025-11-05 16:20:42.000', 'https://franquias.portaldofranchising.com.br/franquia-sorvetes-rochinha/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '423000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76d600h5eh0smfav145f', 'AMERICAN COOKIES', 'american-cookies', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Mix de produtos com mais de 25 sabores de cookies com receita exclusiva e ingredientes premiums, mais de 10 milk-shake’s especiais, sodas italianas e variedade de cafés.', 2020, 2021, '[\"https://www.youtube.com/watch?v=uoTdBGzCuNQ\",\"https://www.youtube.com/watch?v=PlKSc7Z0sdc\",\"https://www.youtube.com/watch?v=FOKtljk8T7g\"]', '2026-04-01 02:00:07.291', '2025-08-05 22:20:27.642', 654, NULL, 1, 2015, 'Com um modelo de operação enxuto e altamente lucrativo, rapidamente se tornou a maior franquia de cookies do Brasil, conquistando consumidores em todo o país com sua receita exclusiva e experiência marcante de consumo. Inserida em um dos segmentos que mais crescem no food service — o mercado de sobremesas e indulgência —, a marca se destaca pelo forte apelo visual dos produtos, operação simplificada, baixo custo fixo e alta rentabilidade. Com suporte completo ao franqueado, presença em shoppings estratégicos e uma marca que gera desejo e fidelização, a American Cookies é a escolha certa para quem busca empreender com segurança, escalabilidade e reconhecimento nacional.', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/08a16006-a8b2-492f-b84d-c52d28272fc8.jpg', 60, NULL, NULL, '2026-01-11 00:00:08.000', 'https://franquias.portaldofranchising.com.br/franquia-american-cookies/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '210000', NULL, NULL, NULL, '70000', '0', '5', '2', '180000', '10000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76db00h6eh0slj0i4viu', 'ARABIA EXPRESS', 'arabia-express', NULL, 'Alimentação', 'Bares e Restaurantes', 'A GAMA YK FRANQUIAS LTDA. possui como diretriz oferecer ao consumidor ARABIA EXPRESS uma alimentação saudável e nutritiva, baseada no conceito de culinária árabe, no formato fast-food.', 2016, 2017, NULL, '2026-04-01 02:00:07.301', '2025-08-05 22:20:27.647', 655, NULL, 1, 2016, 'Em 1987, à família de Fernanda Pulgaci , abriram uma pequena “rotisserie” na cidade de São Paulo, na Rua Haddock Lobo (Jardins), com apenas 4 mesas onde ofereciam os pratos da autêntica culinária árabe.  As receitas de família, pesquisadas durante anos para igualar o paladar da culinária do Líbano, foram aprovadas por um público crescente e fiel.  O sucesso convenceu à família a procurar um local maior, com 120 lugares, que foi inaugurado em 1992, na mesma Rua Haddock Lobo,  ao lado da “rotisserie”. É o ARÁBIA, onde a alta qualidade de seus produtos, aliada a um atendimento primoroso, faz dele um dos melhores restaurantes árabes de alto nível em São Paulo.  Com o passar do tempo, a pedido dos clientes que queriam saborear a comida árabe em casa, em festas pessoais ou de empresas, foi lançado o ARÁBIA BUFFET, que é hoje um dos mais requisitados da cidade de São Paulo. Para atender essa demanda crescente, foi inaugurada em 1996, na Vila Olímpia, a COZINHA INDUSTRIAL ARÁBIA. Lá eram produzidos os salgados (esfihas e quibes) para venda em supermercados e empórios de alto nível, com a mesma reconhecida qualidade.  Em 2002 foi a vez do ARÁBIA EXPRESS, no Shopping Iguatemi, uma loja compacta com uma versão reduzida de cardápio, para aqueles clientes que procuram a praticidade do serviço de uma praça de alimentação, sem abrir mão da qualidade.  Em 2012 foi inaugurada a segunda loja ARÁBIA EXPRESS, no Shopping Iguatemi JK, confirmando uma receita de sucesso que demonstra um dos maiores faturamentos (lojas de pequeno porte) da área de alimentação.  Há ainda o serviço ARÁBIA DELIVERY, com mais de 4.000 entregas por mês, com elevado ticket médio por entrega.  Em 2016 foi concluída a implantação de uma nova Cozinha Central, que permitirá forte ampliação produtiva para fazer frente ao significativo aumento de demanda provocado pelas outras operações do grupo, principalmente as vendas diretas para supermercados e lojas de varejo de alto nível, que crescem acima da capacidade de produção. Este é um modelo de negócio que está demonstrando resultados cada vez mais expressivos, contribuindo efetivamente para o sucesso da operação do Grupo como um todo. A qualidade ARÁBIA já foi diversas vezes reconhecida pela imprensa especializada:  \n• Por 7 anos, foi eleito o melhor restaurante árabe no prêmio “O melhor da Cidade – Comer & Beber”, da Veja São Paulo; \n• Foi eleito o melhor restaurante árabe pela edição especial da Revista da Folha; \n• Foi eleito o melhor restaurante árabe de São Paulo em todas as premiações da revista GULA; \n• Recebeu por 7 anos consecutivos o Prêmio de Excelência de Carta de Vinhos pela revista Prazeres da Mesa.  Isso demonstra que, desde a sua fundação, o ARABIA passou por todas as fases e mudanças de mercado, sempre buscando a evolução sustentada. \n \nQuase 30 anos depois da abertura da pequena “rotisserie”, à família continua contribuindo com a operação do ARÁBIA com a mesma dedicação e carinho, garantindo a qualidade e autenticidade de seus pratos e produtos.  Pelos conceitos acima apresentados e por sua maneira cuidadosa de estruturar a operação como uma parceria entre as pessoas chave de operações e investidores, procurando incentivar e compartilhar atitudes positivas sobre qualidade, ética e, sobretudo, a importância do desenvolvimento coerente e satisfação empresarial de todos os envolvidos, o ARÁBIA acredita ter uma sólida e bem fundamentada base de crescimento e consolidação para a marca no mercado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b0ece0f6-c618-42f1-b6df-9b9ed58ea11f.jpg', 3, NULL, NULL, '2026-03-08 23:48:35.176', 'https://franquias.portaldofranchising.com.br/franquia-arabia-express-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '640000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76di00h7eh0sjver87we', 'TOUTI', 'touti', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A Touti traz para o mercado produtos na área de beleza de alto desempenho e ótima relação custo-benefício. Nossa expansão se baseia no modelo de microfranquias de baixo investimento e alto desempenho.', 2019, 2019, NULL, '2026-04-01 02:00:07.313', '2025-08-05 22:20:27.654', 656, NULL, 1, 2014, 'A Touti nasceu em 2014 em Pernambuco, e se inspira na beleza de Paris para criar sua linha de perfumes, capilar e corporal com alto poder de fixação e ótima relação custo-benefício. \nA marca é cruelty free e está em franca expansão com mais de 500 unidades no Brasil, tendo seu número dobrado mesmo durante a pandemia, figurando entre as microfranquias que mais cresceram. Há três modelos de negócio: quiosque smart, quiosque full e loja com investimento inicial a partir de R$ 12 mil e prazo de retorno estimado entre 5 a 24 meses.   Modelo de franquia   Em 2019 a Touti entrou para o mercado de franchising com três formatos de negócios:   Quiosque Smart: modelo de apenas 1m2 ideal para ser instalado em supermercados, galerias, shoppings, estações de metrô, entre outros locais de fluxo intenso de pessoas. \n\tEsse modelo solicita investimento inicial de R$ 12 mil.\n\t  Quiosque Full: modelo de franquia voltado para ser instalado em shopping, com dois tipos de tamanhos 6m2 ou 3m2. Formato solicita investimento inicial a partir de R$ 80 mil.\n\t  Loja: Esse modelo foi criado em 2021 com o intuito de gerar representatividade nos centros comerciais do Brasil e para os shoppings que não aceitam a entrada do quiosque Full. \n\tO tamanho da loja varia entre 15m2 e 35m2. O investimento é a partir de R$ 85 mil.\n\t  POR QUE INVESTIR NO MERCADO DE PERFUMARIA?\n  - O Brasil é o segundo maior consumidor de perfumaria do mundo ficando atrás somente da Itália. - O setor de perfumaria e cosméticos fatura por ano a incrível marca de mais de R$ 120 Bilhões - As vendas de cosméticos crescem aproximadamente 13% ao ano. Um estudo feito pelo IBGE revelou que o brasileiro gasta mais com beleza do que com comida.   CONHEÇA NOSSAS VANTAGENS PARA O SUCESSO DO SEU NEGÓCIO:\n  - Assessoria na escolha do ponto - Treinamento e suporte em gestão e operação do negócio - Desenvolvimento e lançamento de novos produtos - Apoio na manipulação e inauguração da unidade - Supervisão de processos comerciais', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1a6f3592-be2c-4d5f-b803-26ec558cc133.png', 927, NULL, NULL, '2026-03-08 23:50:22.797', 'https://franquias.portaldofranchising.com.br/franquia-touti/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '12000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76do00h8eh0sx9fdkf8o', 'NUMBER ONE CHICKEN', 'number-one-chicken', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Tastefy é uma marca 100% brasileira, cuja especialidade é o delivery, somos detentores das marcas N1 Chicken, Brasileirinho Delivery, O que Comer, Fernando? e Zé Coxinha. (Dark kitchen)', 2018, 2019, NULL, '2026-04-01 02:00:07.323', '2025-08-05 22:20:27.660', 657, NULL, 1, 2017, 'Quer saber como é ser um franqueado do N1 Chicken? Então vou te mandar um dos comentários que recebemos dos mais de 200 franqueados do N1:   Talvez até pense que para ser franqueado do N1 Chicken você não pode ser advogado, administrador, engenheiro, servidor público, contador, representante, biólogo, bancário, dentista, médico, enfermeiro ou ter qualquer outra formação. Então preciso te contar um segredo: essas são apenas algumas das profissões dos mais de 200 franqueados do N1 Chicken. A prioridade do N1 Chicken é dar suporte e meios para que os franqueados tenham o delivery mais famoso de suas cidades, atuando em um modelo de negócio enxuto e inovador, através do modelo Dark Kitchen (100% delivery), seguindo uma premissa básica: o franqueado tem que ganhar dinheiro! Com cerca de 200 unidades no Brasil e 4 em Portugal, o N1 tem uma operação simplificada, com baixo custo de investimento e mensal, além de necessitar de apenas 3 pessoas na unidade.', NULL, 'ESPÍRITO SANTO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a7d72d22-7e89-47ae-bd43-1a846ea32ea8.png', 203, NULL, NULL, '2026-03-08 23:51:47.747', 'https://franquias.portaldofranchising.com.br/franquia-number-one-chicken/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '299000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ds00h9eh0sgqil1jjo', 'HOSTNET', 'hostnet', NULL, 'Comunicação, Informática e Eletrônicos', 'Comunicação e Mídia', 'A Hostnet é uma empresa pioneira no mercado de hospedagem de sites e registro de domínio no Brasil. Desenvolve em conjunto com sua rede de Franqueados soluções para promover negócios na Internet.', 2017, 2018, NULL, '2026-04-01 02:00:07.333', '2025-08-05 22:20:27.665', 658, NULL, 1, 2001, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d1494d61-0ca7-43e1-b727-c55fca362cd7.jpg', 23, NULL, NULL, '2026-03-09 15:50:12.113', 'https://franquias.portaldofranchising.com.br/franquia-hostnet/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76dx00haeh0sqzh3qvnj', 'SOLÁRIO PISCINA', 'solario-piscina', NULL, 'Casa e Construção', 'Construção e Reforma', 'Empresa do ramo de piscinas de fibra.', 2010, 2020, '[\"https://www.youtube.com/watch?v=imhMwDNuMTo\",\"https://www.youtube.com/watch?v=l4qBEq-o8X8\"]', '2026-04-01 02:00:07.343', '2025-08-05 22:20:27.670', 659, NULL, 1, 1990, 'A Solário Piscinas é o resultado da iniciativa de empreendedores que, desde 1990, conquistaram um extenso “Know-how” e experiência na área de piscinas. Após análise das tendências do mercado, trouxeram soluções para atender a forte demanda no segmento de lazer, oferecendo uma gama de opções em piscinas de fibra instaladas, spas, conjuntos filtrantes, aquecedores solares, produtos químicos e acessórios em geral. A Solário desenvolveu com base em sua experiência no varejo uma linha de piscinas exclusivas e inovadoras, as quais são fabricadas respeitando os mais altos padrões de qualidade. Atualmente, ocupa lugar de destaque e liderança no cenário nacional, por seus diferenciais de qualidade na fabricação e pós venda de seus produtos. Com sua loja matriz localizada na cidade de São José do Rio Preto – SP, a rede expandiu-se vertiginosamente, tendo em vista a demanda expressiva pelas piscinas em toda região.  Hoje, com 3 parques industriais no Brasil e mais de 45 lojas, a Solário está em plena expansão, aumentando o número de seus franqueados de forma exponencial em todo território brasileiro', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fda0e047-8830-4f9e-a929-9689cde4b743.jpg', 44, NULL, NULL, '2026-03-08 23:52:54.255', 'https://franquias.portaldofranchising.com.br/franquia-solario-piscina/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76e200hbeh0szimgnbib', 'MR SHAKE SORVETES', 'mr-shake-sorvetes', NULL, 'Alimentação', 'Docerias, Padarias e Cafés', 'O MR SHAKE SORVETES se destaca pela inovação em sorvetes, milkshakes e açaís. . Nossos produtos são preparados com polpa de frutas selecionadas e chocolates italiano', 2022, 2023, NULL, '2026-04-01 02:00:07.352', '2025-08-05 22:20:27.674', 660, NULL, 1, 2010, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4942e710-63e6-460e-92d1-1f65ce7d2d61.png', 147, NULL, NULL, '2026-03-08 23:53:37.564', 'https://franquias.portaldofranchising.com.br/franquia-mr-shake-sorvetes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '285000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76e600hceh0siyvuhn9k', 'COMFORT', 'comfort', NULL, 'Moda', 'CALÇADOS', 'Loja de Calçados e acessórios femininos', 2021, 2025, NULL, '2026-04-01 02:00:07.362', '2025-08-05 22:20:27.678', 661, NULL, 1, 2011, '', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b9495dca-7fad-4f32-a67c-69d968c5f848.png', 16, NULL, NULL, '2025-08-21 10:30:15.000', 'https://franquias.portaldofranchising.com.br/franquia-comfort/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ea00hdeh0sg98ioelp', 'PETLOVE', 'petlove', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'A Petlove é a maior plataforma pet do Brasil. Nossas franquias unem tecnologia, experiência e amor pelos pets, oferecendo tudo em um só lugar: loja, banho e tosa, saúde e conveniência.', 2023, 2024, NULL, '2026-04-01 02:00:07.372', '2025-08-05 22:20:27.682', 662, NULL, 1, 1999, '', NULL, 'SÃO PAULO', 1, NULL, 10, NULL, NULL, '2025-11-04 08:09:09.000', 'https://franquias.portaldofranchising.com.br/franquia-petlove-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1460000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76eg00heeh0szxtw6291', 'MORANA', 'morana', NULL, 'Moda', 'Acessórios Pessoais', 'Acessórios (bijuterias, bolsas, lenços e afins)', 2002, 2001, '[\"https://www.youtube.com/watch?v=5pqgWFKAOdY\",\"https://www.youtube.com/watch?v=-ixxJkCr9kY\"]', '2026-04-01 02:00:07.383', '2025-08-05 22:20:27.689', 663, NULL, 1, 2001, 'A Franquia Morana é uma das maiores redes de acessórios femininos do Brasil com presença em todas as capitais brasileiras, além dos Estados Unidos. Criada pelo Grupo Ornatus, empresa com mais de 30 anos de experiência em varejo e especialista em gestão de franquias, a Morana está no mercado há 16 anos e soma cerca de 300 operações. Qualidade no design, acessórios que se destacam pela qualidade e versatilidade em coleções exclusivas e renovadas constantemente. Essas são as características que fazem da Morana uma marca que cresce exponencialmente e se torna cada vez mais desejada por consumidoras seletivas e exigentes, que estão antenadas com a moda, mas não abrem mão da beleza clássica e do acabamento impecável. As campanhas transitam entre temas atuais a debates que valorizam e respeitam as mulheres, tendo à frente o peso de celebridades ou embaixadoras que compartilham dos mesmos valores da marca. As ações de marketing são criadas de maneira estratégica com foco na comunicação 360º que atua em todos os pontos de contato da marca com o cliente. Assim, é possível estar presente nos canais onde o consumidor Morana está. Hoje, o sucesso das grandes cidades está pronto para ser lucrativo em todo o restante do País. Para isso ocorrer em municípios com população entre 70 mil e 200 mil habitantes, a marca criou a Morana Light. Pequenas mudanças no formato do projeto arquitetônico e, principalmente, no estoque da loja, permitem que o investidor tenha uma franquia de acessórios femininos em cidades menores, mas de grande poder aquisitivo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d1e85d66-d6e2-48f2-92fb-e42be063f8ea.png', 310, NULL, NULL, '2026-03-08 23:54:38.409', 'https://franquias.portaldofranchising.com.br/franquia-morana-bijuterias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '163000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76em00hfeh0sdn5q7ksi', 'LOUCOS POR COXINHA', 'loucos-por-coxinha', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Loucos por Coxinha é uma rede de franquia consolidada e sustentável. Modelo testado e aprovado por 95% dos franqueados. São mais de 100 Unidades nos melhores shopping e regiões do Brasil.', 2014, 2016, '[\"https://www.youtube.com/watch?v=6nSAU9XlL4o\"]', '2026-04-01 02:00:07.393', '2025-08-05 22:20:27.694', 664, NULL, 1, 2014, 'Loucos por Coxinha: Nossa História e Expansão A Loucos por Coxinha nasceu em 2014, na cidade de Natal, Rio Grande do Norte, da visão empreendedora de Pablo Farias e Vitor Azevedo. Amigos de infância unidos pelo sonho de transformar a paixão nacional – a coxinha – em uma experiência de consumo e um negócio de sucesso no mercado de franchising. Crescimento Estruturado e Inovação em Formatos Em 2015, consolidamos o nosso modelo de quiosque em shopping centers, que rapidamente se estabeleceu como um formato testado e altamente aprovado tanto pelos clientes quanto pelos nossos franqueados. Hoje, a Loucos por Coxinha oferece formatos de franquia adaptáveis a diferentes mercados e pontos comerciais, incluindo: Quiosque Container Pocket (Formato compacto) Liderança Ampla Atualmente, somos uma franquia com estrutura verticalizada, contando com produção e logística própria. Temos, também, uma base sólida com mais de 100 operações ativas. Além do modelo de franquias, fortalecemos nossa presença no mercado de varejo com a marca Loucos por Coxinha Varejo, que atende a mais de 6 mil pontos de venda em supermercados.  Nossa atuação abrange 13 estados das regiões Norte, Nordeste, Sul e Sudeste do Brasil, demonstrando a capilaridade e o sucesso da nossa marca. Visão de Futuro e Expansão Para os Próximos Anos O plano de expansão para 2026 foca na consolidação regional por meio da interiorização nos estados onde já estamos presentes. Adicionalmente, buscaremos ampliar o alcance da marca para novas regiões estratégicas, incluindo a entrada nos estados de Tocantins e Piauí.', NULL, 'RIO GRANDE DO NORTE', 1, NULL, 102, NULL, NULL, '2026-03-08 23:55:32.783', 'https://franquias.portaldofranchising.com.br/franquia-loucos-por-coxinha/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '117759.57', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76eq00hgeh0s4tqp95p0', 'FOLKS FRANQUEADORA', 'folks-franqueadora', NULL, 'Alimentação', 'Bares e Restaurantes', 'AgroBar é um bar temático sertanejo para todos os dias e todos os públicos. Uma marca da FOLKS FRANQUIAS que já possui outros modelos de sucesso, como o Folks Pub.', 2019, 2022, NULL, '2026-04-01 02:00:07.404', '2025-08-05 22:20:27.698', 665, NULL, 1, 2014, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5bd14916-f5ad-4c4f-ab6a-153a85c96825.jpg', 13, NULL, NULL, '2026-03-08 23:56:25.762', 'https://franquias.portaldofranchising.com.br/franquia-folks-franqueadora/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '349000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ev00hheh0s5yys0xy7', 'GET IT', 'get-it', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'A Get it é uma empresa jovem e inovadora que nasceu com o objetivo de quebrar barreiras e conectar as pessoas com o mundo. Uma metodologia forte, uma empresa humanizada, com foco nos resultados.', 2016, 2019, NULL, '2026-04-01 02:00:07.415', '2025-08-05 22:20:27.703', 666, NULL, 1, 2007, 'A única franqueadora de idiomas com o trabalho de Governança Corporativa.\n\nTodos os nossos franqueados recebem um suporte conferido pelo CEO da Get it, Thiago Sanches, que faz um acompanhamento detalhado e realiza um trabalho de consultoria mensal. \nEle participa diretamente de todos os processos com os novos integrantes da rede, deixando o lado humano sobressair ao que poderia ser uma simples negociação. Isso já demonstra o quanto a Get it está posicionada na contramão dos grandes “players” do mercado. \nNossa proposta é trazer facilidades e diferenciações no investimento inicial, além de fazer um planejamento de execução compatível com a realidade dos franqueados, dando-lhes total autonomia nas decisões das escolas. A forma como a Get it trabalha está relacionada com a experiência real do mundo moderno, respeitando as opiniões, absorvendo ideias dos franqueados, os impulsionando, dando força e voz aos mesmos, que contam com a possibilidade de trocar informações relevantes e experiências. Um lugar onde todos são ouvidos e atendidos durante o processo completo de desenvolvimento empresarial. Uma marca projetada para promover experiências. Uma empresa jovem, inovadora, eficaz, que está adaptada ao universo digital, visa a evolução e executa práticas conscientes da velocidade com que as coisas acontecem. A Get it nasceu com o principal objetivo de quebrar barreiras e conectar as pessoas com o mundo. Por isso não oferece somente cursos de idiomas, mas possibilita conquistas, experiências sem limite de fronteiras e a realização de sonhos. Atualmente, estamos presentes em diversos estados do território nacional, e é com muito otimismo e fidelidade aos nossos valores que projetamos nossa expansão para os próximos anos. \nNossa prioridade é sempre manter uma metodologia forte, ser uma empresa humanizada, e oferecer um ensino de qualidade, possibilitando resultados rápidos e duráveis. A Get it confia na concretização dos objetivos maiores, e busca contribuir de forma direta com o sucesso de nossos alunos, parceiros e franqueados. Faça parte dessa família!', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0c09dc16-03de-4e26-b5f2-0e3f2ad3c642.jpg', 14, NULL, NULL, '2026-03-08 23:56:49.027', 'https://franquias.portaldofranchising.com.br/franquia-get-it/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76f100hieh0szb889o2s', 'DUGAS PIZZA DELIVERY', 'dugas-pizza-delivery', NULL, 'Alimentação', 'Bares e Restaurantes', 'Modelo de Pizzaria Delivery formatado para alto volume de vendas com processos bem delineados visando a entrega de pizzas de alta qualidade para público A, B e C+.', 2021, 2023, '[\"https://www.youtube.com/watch?v=BPFp3tSbZAE\",\"https://www.youtube.com/watch?v=As1YDPOAEw0\",\"https://www.youtube.com/watch?v=Q2LFIgvixEk\",\"https://www.youtube.com/watch?v=c4KmH8PNado\"]', '2026-04-01 02:00:07.425', '2025-08-05 22:20:27.709', 667, NULL, 1, 2016, 'Após conquistar o mercado regional e se tornar referência de pizzas de qualidade na região sul de Santa Catarina, a Dugas Pizza Delivery, juntamente com dois empresários locais com ampla experiência em Franquias e apaixonados pela pizza da Dugas, iniciaram a formatação da empresa para a expansão através do franchising - e o resultado não poderia ser diferente: em 01 ano de expansão a Rede já conta com 16 unidades espalhadas pelo Brasil, com presença em todos os Estados do Sul e Sudeste e mais de 85 mil pizzas entregues. Sabendo que o Brasil é o segundo maior consumidor de pizzas do Mundo, atrás apenas dos Estados Unidos, bem como do exponencial crescimento e consolidação do delivery nos últimos anos, a Dugas aposta na qualidade de seus produtos, elaborados somente com ingredientes de máxima qualidade, para navegar nesse verdadeiro oceano azul de oportunidades em um mercado concorrido, porém, onde a maior parte da concorrência briga por preço. Um dos grandes diferenciais, além da altíssima qualidade da pizza, é o valor de investimento abaixo do mercado, pois a Dugas Pizza Delivery não necessita de pizzaiolo nem de mão de obra especializada. Todos os processos são padronizados e o Franqueado recebe todo o suporte necessário, o treinamento inicial é realizado pela franqueadora presencialmente na unidade Franqueada, e após esse treinamento a equipe ja se encontra apta a produzir e fornecer a pizza de qualidade com o selo da Dugas Pizza Delivery. “Essa combinação resulta em um processo ágil e muito rápido na entrega para fidelizar cada vez mais os clientes”, explica Marcus Mendes, Diretor de Expansão da marca.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/df64ebf9-c80a-45e6-8a36-de24048332fa.jpg', 13, NULL, NULL, '2026-03-08 23:57:57.480', 'https://franquias.portaldofranchising.com.br/franquia-dugas-pizza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76f600hjeh0s6o2sskd0', 'AÇOUGUE DO FRANGO', 'acougue-do-frango', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Açougue especializado em frangos resfriados e a granel.', 2023, 2023, NULL, '2026-04-01 02:00:07.435', '2025-08-05 22:20:27.714', 668, NULL, 1, 2018, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/af2bac7e-9935-4a0e-9fbb-a0e73f9010b7.png', 2, NULL, NULL, '2025-06-10 14:38:31.000', 'https://franquias.portaldofranchising.com.br/franquia-acougue-do-frango/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76fb00hkeh0su3eabbcj', 'AÇAÍ CONCEPT', 'acai-concept', NULL, 'Alimentação', 'Bares e Restaurantes', 'Franquia de Açaí, com foco em produzir, distribuir e vender a melhor qualidade de açaí existente, proporcionando uma incrível experiência de sabor aos nossos clientes.', 2014, 2016, NULL, '2026-04-01 02:00:07.444', '2025-08-05 22:20:27.719', 669, NULL, 1, 2014, 'Somos uma empresa jovem,  dinâmica e arrojada fundada em 2014.   Com foco total em trazer ao mercado um produto saudável, de altíssima qualidade e adaptado ao estilo de vida moderno.    A empresa foi criada depois de sentir no mercado a carência de produtos de fast-food saudável para o consumidor exigente   Produzimos e distribuímos o melhor açaí existente no mercado e fazemos isso em lojas únicas, confortáveis  com layout moderno e apelativo num formato prático e higiênico.    Temos no momento mais de 120 unidades já inauguradas, espalhadas por todo o Brasil.   Iniciamos 2016  o nosso processo de internacionalização abrindo unidades em Portugal e USA já este ano.   Temos como missão ser reconhecidos como líderes e exemplo em nosso segmento e proporcionar uma incrível experiência de sabor aos nossos clientes. Fazendo isso com o compromisso de incorporar ingredientes naturais e saudáveis. Assegurando sempre as boa práticas e o respeito pelo planeta e ambiente. \nFaça parte desta família #viciadosemaçai', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/278cf56b-4bcb-44b5-8d89-2c93b970d10e.jpg', 378, NULL, NULL, '2026-03-08 23:59:06.254', 'https://franquias.portaldofranchising.com.br/franquia-acai-concept/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '90000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76fg00hleh0sv5sx8tz5', 'HABIB´S', 'habib-s', NULL, 'Alimentação', 'Bares e Restaurantes', 'FAST-FOOD DE COMIDA ÁRABE', 1991, 1991, NULL, '2026-04-01 02:00:07.454', '2025-08-05 22:20:27.724', 670, NULL, 1, 1988, 'O Habib’s, maior rede de fast food genuinamente brasileira, foi fundado em 1988 na capital paulista com a missão de democratizar o acesso aos restaurantes de refeições rápidas, aliando um cardápio variado a uma política de preços extremamente acessíveis. \nO resultado foi a expansão da marca e a consolidação do negócio como um dos maiores e mais respeitados do país.Atualmente, o Grupo, que conta com mais de 17 mil colaboradores, está presente em 18 estados e é conhecido por seu produto carro-chefe: as deliciosas Bib’sfihas, que fazem parte da história dos mais de 200 milhões de clientes que passam pelos restaurantes da rede durante o ano. \nAlém disso, o Grupo é detentor das marcas Ragazzo e a rede de churrascarias Tendall Grill.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/bc44d560-c956-4e3c-aa96-02f855b55c83.jpg', 254, NULL, NULL, '2026-03-08 23:59:46.507', 'https://franquias.portaldofranchising.com.br/franquia-habibs-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1230000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76fk00hmeh0snquo731z', 'RAGAZZO', 'ragazzo', NULL, 'Alimentação', 'Bares e Restaurantes', 'Comida Italiana', 2005, 2006, '[\"https://www.youtube.com/watch?v=3-gcEjlGotc\"]', '2026-04-01 02:00:07.464', '2025-08-05 22:20:27.729', 671, NULL, 1, 1991, 'O Ragazzo foi fundado em 1991, na capital paulista, com o objetivo de democratizar o acesso a refeições saborosas e preparadas de maneira rápida. Há mais de 30 anos, a rede une a política de preços acessíveis a um cardápio variado, com seu produto ícone, a coxinha. Ela ficou tão popular que foi eleita pelo jornal Folha de S. Paulo como a melhor coxinha da capital paulista. Em junho de 2022, o Ragazzo lançou 6 modelos de franquias Express testados e aprovados em mais de 200 lojas próprias: Bike, Quiosque Interno, Quiosque Externo, Vitrine e Lojas Com ou Sem Salão. Hoje, a marca está presente em 5 estados do Brasil, com um total de mais de 250 unidades no país, entre restaurantes e modelos Express. A rede conta com centrais de produção e distribuição próprias.', NULL, 'SÃO PAULO', 1, NULL, 185, NULL, NULL, '2026-03-09 00:00:26.897', 'https://franquias.portaldofranchising.com.br/franquia-ragazzo-valor/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '320000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
