INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76gh00hseh0s23kv75oa', 'STANNIS FRANCHISE LTDA', 'stannis-franchise-ltda', NULL, 'Alimentação', 'Bares e Restaurantes', 'Sistema pre pago, onde o cliente adiciona credito em seu aplicativo e libera a torneira de chope para encher seu copo', 2024, 2024, NULL, '2026-04-01 02:00:07.522', '2025-08-05 22:20:27.761', 677, NULL, 1, 2011, '', NULL, 'SANTA CATARINA', 1, NULL, NULL, NULL, NULL, '2026-03-09 00:03:15.241', 'https://franquias.portaldofranchising.com.br/franquia-stannis-franchise-ltda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '136000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76gm00hteh0swuzt1t0l', 'AMBEV - CHOPP BRAHMA EXPRESS', 'ambev-chopp-brahma-express', NULL, 'Alimentação', 'DISTRIBUIÇÃO E PRODUÇÃO', 'Delivery de chopp para eventos, com foco no atendimento apenas de Pessoa Física.', 2005, 2008, NULL, '2026-04-01 02:00:07.532', '2025-08-05 22:20:27.766', 678, NULL, 1, 1999, 'CHOPP BRAHMA EXPRESS O Chopp Brahma Express, no mercado desde 2005, inovou e se transformou num modelo mais convergente às tendências e comportamentos dos nossos consumidores. A proposta de valor da Franqueadora é ser a principal solução de consumo de chopp em casa, garantindo uma experiência ainda mais completa e sinérgica entre todos os nossos canais, em especial as lojas físicas. Em seus dois tamanhos e formatos distintos de unidades físicas, Light Store e Compact, o CBE têm a definição pelo tamanho ideal para cada tipo de cidade, território de atendimento, sendo baseado em diretrizes geográficas, quantidade habitantes e potencial de consumo, além de levar em consideração raios de deslocamento logístico. O formato ideal apontado, visa o encaixe assertivo considerando fatores de investimento, rentabilidade e payback, mantendo os pilares de entrega do CBE: as principais soluções de consumo e experiência de chopp em casa, somado com a disponibilidade de todo portfólio Ambev, seja via visitação nas lojas físicas, ou pelos nossos demais canais (online/digitais ou offline), proporcionando uma verdadeira experiência “Omnichannel”. Chopp Brahma Express é uma franquia oficial Ambev! Qual é o momento do mercado e segmento? A Ambev é líder no segmento em que atua. Nossas franquias têm relevante peso no mercado de chopp nacional e cada vez mais é percebida como uma solução completa na experiência de todos os demais líquidos do nosso portfólio. Entretanto, diante do enorme potencial de crescimento do setor e surgimento de novos entrantes nesse mercado, nosso dever é inovar e evoluir para mantermos a solidez dos nossos parceiros e expandirmos constantemente o business como um todo. Quais os produtos e serviços disponíveis? O CBE é uma franquia de sortimento e uma solução completa desde grandes eventos a pequenos encontros. Todo o portfólio Ambev está disponível para compra e consumo nas nossas lojas físicas, via delivery, ou através do nosso e-commerce oficial (a disponibilidade de sku’s pode variar de acordo com cada região). Qual o território de atuação e as principais rotinas operacionais? Estamos presentes em aproximadamente 60% do território do Brasil e em plena expansão. Com isso, a Franqueadora determina o raio de atuação da sua unidade baseado de um estudo de potencial e de deslocamento logístico e aponta quais os bairros ou até mesmo cidades que sua loja poderá atender. O CBE tem como foco o atendimento ao consumidor final, festas e eventos particulares e, por regra, não está autorizado a atender pontos de vendas e estabelecimentos comerciais, salvo em exceções concedidas pela própria Ambev. As vendas são realizadas nas 207* lojas físicas CBE, no 0800 888 1021, através da plataforma e-commerce no site choppbrahmaexpress.com.br e de app’s de entrega (parceiros), como o Zé Delivery. O projeto e design da loja, em seus dois diferentes modelos, foi desenvolvido a fim de criar um ambiente baseado em curadoria, experiência, relacionamento e especialmente excelência operacional. (*Jan/2024). O CEP de onde cada compra se origina, seja através do e-commerce, seja através do telefone oficial são direcionados à sua unidade respeitando o território de atendimento e polígono concedido e/ou presente em seu contrato de franquia. Vale ressaltar que não há interseção de raios, ou seja, o cliente sempre será direcionado à unidade do território que ele se encontra. O contrato de franquia tem vigência de 5 anos e o tempo médio entre a formalização e a inauguração da unidade física varia entre 60 e 90 dias, de acordo com o modelo. A rentabilidade média mensal varia entre 10% e 13%. O payback médio é entre 40 e 48 meses. Sendo o ponto de equilíbrio de venda do chopp de 8000 litros/mês. Sobre o Franqueado: A Franqueadora possui um criterioso processo de seleção e uma das características essenciais é que o franqueado esteja à frente do negócio com dedicação exclusiva, preferencialmente, e com disponibilidade para gerir sua franquia inclusive aos finais de semana e feriados. A Ambev garante o treinamento inicial, transferência de know-how e consultoria de campo para a condução do negócio. Porém, é de extrema importância que o candidato se identifique com o produto e com a oportunidade. Sociedades são permitidas, mas sempre deverá existir a figura do sócio operador, aquele que terá a interface diária com a Franqueadora sobre novas campanhas, além de questões administrativas, financeiras, legais, técnicas e operacionais. O franqueado deverá ter as seguintes características: Ter ciência de que está se propondo a ter um negócio próprio e com riscos inerentes à implantação de quaisquer atividades empresariais; Compreender premissas, estimativas de investimento e payback, inteirar-se do conteúdo, deveres e obrigações presentes na COF – Circular de Oferta de Franquia; Espírito empreendedor, dinâmico e com forte desejo de ser bem-sucedido; Dedicar-se ao perfeito andamento da operação e performance financeira; Zelar por produtos e equipamentos concedidos sob regime de comodato pela Ambev; Respeitar as iniciativas, programas e utilização de serviços e assets de fornecedores e parceiros homologados pela Franqueadora; Gostar de trabalhar em Rede, atendendo a diretrizes do contrato de franquia. Quais as características de cada modelo e seus investimentos? A Ambev auxilia na escolha do ponto comercial, premissas de locação (contrato mínimo de locação de cinco anos) e projeto arquitetônico. A adequação civil, aquisição e instalação do enxoval geral adquirido junto a fornecedores homologados: mobiliários, câmara fria, utensílios e uniformes, cilindros e ferramentaria são responsabilidade do franqueado e já previstos no investimento inicial. Quais são os gastos após a compra da franquia? Todo o investimento citado anteriormente é para a implantação física da loja. Porém, o franqueado terá alguns outros custos corriqueiros e operacionais. Royalties (10%) e Fundo de Propaganda (4%) incidem sobre a compra de produtos Ambev. Marketing local: a Franqueadora realiza ações de propaganda em seus canais oficiais, mas cabe ao franqueado impulsionar as vendas localmente com as mídias que melhor se adequam à região. Mensalidade sistema de gestão homologado (Linx): o valor da mensalidade para administração do sistema é de responsabilidade do franqueado. Renovação de contrato: caso seja de interesse do franqueado e da Franqueadora, após o período de 5 anos de contrato, é feita a renovação. Nesse momento, será cobrado o valor de 75% do valor da taxa de franquia (TIF) vigente do ano de renovação. Manutenção: cabe ao franqueado manter a loja e os equipamentos em perfeito funcionamento. Para isso, devem manter uma manutenção periódica por meio de serviços especializados. Reforma: de tempos em tempos, será necessária a reforma e adequação ao padrão mais atual da franquia.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/06c045a2-bf61-446d-9395-bdfd5a80a1a0.jpg', 205, NULL, NULL, '2025-08-07 11:09:22.000', 'https://franquias.portaldofranchising.com.br/franquia-ambev-chopp-brahma-express-conveniencia/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/761591a6-187a-44cc-9209-85a10c467186.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a3fbae9b-5c20-4bd2-8471-9c4ac7b7e524.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ff302b1b-e907-4fae-b750-616bcf03c700.png\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76gt00hueh0sllaqonzg', 'CEC', 'cec', NULL, 'Educação', 'EDUCAÇÃO', 'Colégio', 2024, 2025, NULL, '2026-04-01 02:00:07.543', '2025-08-05 22:20:27.773', 679, NULL, 1, 2021, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/767b1426-25c3-481d-aaab-dca15531d2e7.png', 1, NULL, NULL, '2025-10-13 14:55:24.000', 'https://franquias.portaldofranchising.com.br/franquia-cec-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76gy00hveh0sua89rboz', 'MINI KALZONE', 'mini-kalzone', NULL, 'Alimentação', 'Bares e Restaurantes', 'Primeira e maior rede de mini calzones com a concepção fast-food no mundo, a Mini Kalzone reúne produtos de alta qualidade com resultados comprovados nas mais de 145 lojas de sucesso pelo Brasil.', 2001, 2002, '[\"https://www.youtube.com/watch?v=N5FrBsQQGD8\",\"https://www.youtube.com/watch?v=KjetihEybls\",\"https://www.youtube.com/watch?v=2wxCmCEo68k\"]', '2026-04-01 02:00:07.552', '2025-08-05 22:20:27.778', 680, NULL, 1, 1993, 'A Mini Kalzone foi fundada em setembro de 1993 com a abertura de sua primeira loja na rua Anita Garibaldi, onde funciona até hoje, no Centro de Florianópolis/SC. \nA grande sacada do fundador e atual sócio da empresa, João Batista Cardoso, foi transformar um prato típico italiano, que lembra uma pizza dobrada ao meio, recheada e assada (o calzone), em uma porção individual prática, bem recheada e com preço acessível. \nAssim, nasceu a primeira rede de calzones com a concepção de fast-food no mundo. \nLogo em 1994, para aumentar a capacidade produtiva e atender a demanda crescente, João Batista Cardoso associou-se a Murilo de Souza Naspolini e Luciano José Fadel, iniciando o processo de multiplicação deste bem sucedido modelo de negócio. \nA partir de 2001, foi criada a MK Marketing e Franchising Ltda, com o objetivo de replicar em todo o Brasil o sucesso já consagrado em Florianópolis, expandindo como formato de franquia. \nAssim, a Mini Kalzone se consolidou como uma empresa verticalizada e completa, atuando na indústria alimentícia (indústrias), no transporte das mercadorias com logística própria, no comércio varejista (lojas) e na prestação de serviços de Marketing e Franchising (expansão) \nDessa forma, além de excelentes produtos, a Mini Kalzone oferece também um ótimo modelo de negócio para investidores, uma franquia verdadeira, com resultados comprovados e reconhecimento no mercado. \nCom uma marca forte, produtos de alta qualidade e proporcionando experiências de sabores únicos, a Mini Kalzone cresceu de forma orgânica e sustentável, chegando em 2018 ao marco de 100 lojas, entregando qualidade e amor em cada produto. \nHoje a rede está presente em quase todo o Brasil, do Sul ao Nordeste, com mais de 125 lojas ativas em 12 estados + Distrito Federal e 55 cidades. \nSeguindo um contínuo processo de expansão sustentável e responsável, a Mini Kalzone é altamente comprometida com o sucesso de seus franqueados e com a qualidade dos produtos servidos para cada cliente em todas as lojas..', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b717df60-a155-481d-81ed-03282d67d832.jpg', 152, NULL, NULL, '2026-03-09 00:03:58.733', 'https://franquias.portaldofranchising.com.br/franquia-mini-kalzone/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76h400hweh0se0dk40pz', 'POKE NIHOA', 'poke-nihoa', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'Restaurante Fast Casual de alimentação saudável, especializado em comida havaiana. O modelo de atendimento é no balcão ou por totens, nos quais o cliente monta o prato ou faz escolha de itens prontos.', 2023, 2024, NULL, '2026-04-01 02:00:07.562', '2025-08-05 22:20:27.784', 681, NULL, 1, 2018, '', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/492496df-7b2c-4425-97c0-97b37686e9bc.png', 4, NULL, NULL, '2025-09-16 11:24:14.000', 'https://franquias.portaldofranchising.com.br/franquia-poke-nihoa-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76h900hxeh0sqp6c8uh7', 'ECODECOR', 'ecodecor', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Venda de revestimentos para paredes internas e externas já aplicados, (m²), por profissionais especializados, treinados pela franquia. Agregamos valor ao trabalho com a venda de produtos e serviços.', 2014, 2021, NULL, '2026-04-01 02:00:07.573', '2025-08-05 22:20:27.790', 682, NULL, 1, 2011, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7732c480-bd74-4bba-a878-8227008abf18.jpeg', 109, NULL, NULL, '2025-10-27 15:37:50.000', 'https://franquias.portaldofranchising.com.br/franquia-ecodecor/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76hf00hyeh0skgy5lalf', 'VINHO & PONTO', 'vinho-ponto', NULL, 'Alimentação', 'Mercados e Distribuição', 'Loja especializada em vinhos, trabalha c/ marcas exclusivas nacionais e importadas das melhores regiões, além da operação da loja o franqueado também atua como distribuidor, venha ser nosso sócio .', 2014, 2015, '[\"https://www.youtube.com/watch?v=LkWnTcv0940\"]', '2026-04-01 02:00:07.583', '2025-08-05 22:20:27.795', 683, NULL, 1, 2010, 'Como na maioria das vezes grandes ideias surgem da necessidade de seus idealizadores, e no caso da franquia Vinho & Ponto Franchising não foi diferente. Em nossa família desde sempre cultivamos o hábito de consumir e conhecer vinhos, tendo o mesmo como parte de nossa alimentação e dos melhores momentos de nosso dia a dia. Projeto diferenciado e único para este produto, dedicado a atender bairros de grandes cidades e ou cidades de pequeno porte, de maneira a aproximar-se do novo consumidor e superar expectativas dos velhos amantes do vinho, apresentando o vinho como produto acessí­vel a todos, a fim de criar a referência de vinhos no mercado brasileiro e aproveitar todo o potencial deste mercado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/05c21e7b-4e26-49f2-95a5-8de260fe5e39.jpg', 8, NULL, NULL, '2026-03-09 00:05:36.372', 'https://franquias.portaldofranchising.com.br/franquia-vinho-e-ponto-bebidas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '296000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
