INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76j100i8eh0s8seizbr1', 'HINODE', 'hinode', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Comercialização de cosméticos', 2012, 2015, NULL, '2026-04-01 02:00:07.691', '2025-08-05 22:20:27.853', 693, NULL, 1, 1988, 'O Grupo Hinode possui duas marcas consolidadas no mercado com cerca de 600 produtos, dentre eles perfumaria, bem-estar, higiene pessoal, maquiagem e cosméticos.   TEMOS FRANQUIAS EM TODO BRASIL As franquias Hinode, hoje conhecidas como Hinode Center, foram criadas com o objetivo de facilitar a logística e a distribuição de produtos para os consultores da empresa. Com estruturas modernas que contam com sala para treinamento e reunião, as franquias da Hinode são uma verdadeira “mão na roda” para os consultores, os quais podem retirar seus produtos na hora, garantindo que seus clientes sejam atendidos com agilidade. Muito mais que um local para experimentar e adquirir produtos, o Hinode Center e´ uma extensão da nossa marca para todo o Brasil.  Além de ser um ponto de retirada de produtos, as franquias Hinode servem como ponto de apoio para o consultor, o qual pode fazer reuniões e agendar apresentação do plano de negócios. Muitas franquias também oferecem treinamento sobre produtos e sobre os 10 passos para o sucesso. O Hinode Center é o lugar ideal para levar os prospectos que estão em fase de acompanhamento, para que eles possam conhecer a estrutura da empresa. Atualmente, a empresa conta com mais de 440 franquias, espalhadas pelos quatro cantos do Brasil.    PASSADA DE GERAÇÃO A GERAÇÃO Com muito trabalho e determinação, Sr Francisco e Dona Adelaide Rodrigues fundaram a Hinode em 1988 com uma missão: oferecer às pessoas a oportunidade para mudarem de vida. Hoje, seu filho Sandro Rodrigues é o presidente do Grupo Hinode e vencedor do troféu empresário do ano, conquistando uma gestão de sucesso junto aos seus irmãos Alessandro Rodrigues, Crisciane Rodrigues e Leandro Rodrigues e toda a equipe.   NOSSA MISSÃO OFERECER ÀS PESSOAS A OPORTUNIDADE PARA MUDAREM DE VIDA Acreditamos que temos um papel maior na sociedade - ser um agente transformador na vida de milhões de pessoas, proporcionando uma oportunidade única de mudar de vida. Enxergamos em cada pessoa um empreendedor em potencial e, por isso, oferecemos todas as ferramentas para que possam se desenvolver profissionalmente. Para que consigam atingir suas metas pessoais, realizar seus sonhos e construir um novo futuro para sua família. É essa crença que nos move e nossa verdadeira razão de existir.   SEM ESFORÇO NÃO HÁ RESULTADO Não tem milagre. Com honestidade, fé e muito trabalho, construímos uma trajetória de superação e atingimos um crescimento exponencial.   VERDADEIROS LÍDERES INSPIRAM O CRESCIMENTO A liderança faz parte do nosso DNA. Acreditamos que são os líderes que movimentam o mundo, por isso, decidimos desenvolvê-los. Buscamos revelar talentos, motivar e inspirar não só os nossos parceiros, mas a sociedade.   MAIS QUE UM TIME, UMA FAMÍLIA Acolhemos a todos de braços abertos, criamos relações verdadeiras, compartilhamos ideais e objetivos, comemoramos lado a lado o nosso sucesso. Porque ninguém conquista nada sozinho. Juntos, somos mais fortes.   ISSO É SÓ O COMEÇO. TEMOS O MUNDO PELA FRENTE Compartilhamos o desejo por algo mais, a vontade de ir além. Temos o espírito empreendedor, a inquietude e o entusiasmo de quem ainda tem muito a conquistar. Para nós, tudo isso é apenas o começo.   FRANQUIA HINODE  Adotamos o modelo de franchising em 2012.  Nelas, nosso consultores, tem um local para adquirir seus produtos, fazer seus treinamento e reuniões.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c936a8ba-1b8e-467b-9b10-d4ccdf7a49f7.png', 253, NULL, NULL, '2026-03-09 00:09:14.125', 'https://franquias.portaldofranchising.com.br/franquia-hinode-cosmeticos-e-perfumaria/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6972bca9-e146-4c85-82dd-8139f6690728.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e2f201cd-8d09-4851-8f23-fb76d79c3667.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
