INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ji00ibeh0smjfplq2j', 'BEM SAFE', 'bem-safe', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Corretora e Administradora de Seguros e Créditos', 2019, 2019, NULL, '2026-04-01 02:00:07.720', '2025-08-05 22:20:27.870', 696, NULL, 1, 2018, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/277fcddc-f87e-435e-bb9c-d46eb9fd9a7a.png', 678, NULL, NULL, '2025-12-18 11:14:50.000', 'https://franquias.portaldofranchising.com.br/franquia-bem-safe/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '12900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76jn00iceh0srt20otm2', 'PELLO MENOS DEPILAÇÃO', 'pello-menos-depilacao', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Depilação a Cera, Linha e Laser', 2007, 2009, '[\"https://www.youtube.com/watch?v=6WwUfofmf_Y\",\"https://www.youtube.com/watch?v=oO5rONRr2mQ\",\"https://www.youtube.com/watch?v=jKtm3ssQ124\"]', '2026-04-01 02:00:07.729', '2025-08-05 22:20:27.875', 697, NULL, 1, 1996, 'Pode ser mãe, esposa, filha, irmã. Pode ser empresária, executiva. Não importa o cargo que ocupa ou o estado civil; o que vale mesmo é que todas, embora tão diferentes, têm três características em comum: o passo acelerado, a vida corrida e uma agenda atribulada. Foi pensando nelas e, principalmente, por ser uma delas, que a Regina Jordão, visualizou e estruturou um negócio de sucesso num nicho de mercado pouco explorado até então. \nO Pello Menos, hoje uma rede de franquias com 46 unidades, nasceu no ano de 1996 em Copacabana e se tornou pioneiro na idealização de um instituto de depilação, exclusivamente feminino. \nO que as mulheres querem quando pensam em depilação? Uma pele lisinha e macia é certamente a resposta correta, mas um procedimento seguro e sem sofrimento também são requisitos muito importantes. Para obter esses resultados a depilação à cera é a mais indicado e engana-se quem pensa que esse método é sinônimo de dor. O segredo para esse momento se tornar apenas mais um ritual de beleza tranquilo é, justamente, o material utilizado. \nOs benefícios da utilização da cera são muitos. Ela deixa a pele mais lisa, ajuda a retirar células mortas, retira os pelos pela raiz, além de fazê-los crescerem mais finos. Foi pensando em todos esses benefícios proporcionados pelo método que a fundadora e CEO da rede Pello Menos, Regina Jordão, criou uma cera com fórmula exclusiva e que causa menos dor na depilação. \nCom uma fórmula à base de mel e especiarias naturais, a cera tem uma textura elástica que garante maior aproveitamento e aderência ao pelo, o que resulta em uma depilação mais prática e, o melhor, menos dolorosa. \nMantida em uma temperatura ideal e agradável para a pele, a cera pode ser utilizada em todas as áreas do corpo e por mulheres de todas as idades, incluindo as adolescentes. O método à cera é o mais indicado para todas as mulheres, explica Regina Jordão. Isso porque não há destruição dos tecidos celulares do organismo, como outros métodos fazem. Afinal, cuidar da pele é prezar pela saúde e não devemos maltratá-la. \nEm 1997 foi inaugurado o Centro de Orientação Profissional (COP), localizado em Copacabana, no Rio. O Cop é considerado a Universidade do Pello. O objetivo é oferecer conhecimento teórico e prático para suas profissionais, possibilitando-as a exercerem o trabalho da melhor forma possível. \nEntendemos que a depilação feminina possui muitas dificuldades. Por isso, nossas profissionais recebem um treinamento técnico intenso e constantes avaliações para realizarem uma depilação sem hora marcada, rápida, com menos dor e mais conforto para todas as nossas clientes em qualquer uma de nossas unidades. \nToda nova colaboradora tem um período de quatro meses de formação, sendo 360 horas de aulas teóricas e 600 horas de aulas práticas. O treinamento oferecido capacita a profissional para o atendimento, através de conhecimento teórico da histologia da pele e o treinamento prático em grande escala para total capacitação da profissional, o que garante que nossas clientes serão atendidas por equipe altamente qualificada. \nAlém disso, o Pello Menos trabalha com a famosa cera exclusiva, única no Brasil: “A depilação faz parte da rotina das mulheres e não precisa ser um momento de sofrimento. Por isso criamos uma cera exclusiva, registrada pelo Ministério da Saúde e aprovada dermatologicamente, para proporcionar praticidade, liberdade e segurança”, ressalta Regina.', NULL, 'RIO DE JANEIRO', 1, NULL, 35, NULL, NULL, '2026-03-09 00:12:06.237', 'https://franquias.portaldofranchising.com.br/franquia-pello-menos-depilacao-estetica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '355000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76jt00ideh0s0vsc4542', 'LETS POKE', 'lets-poke', NULL, 'Alimentação', 'Bares e Restaurantes', 'Missão: Servir para nossos clientes um poke fresco, saudável e delicioso, com ótimo astral e receptividade. Temos como sócio Filipe Toledo, bicampeão mundial de Surfe. Negócio validado,único, vencedor', 2023, 2023, '[\"https://www.youtube.com/watch?v=SN8XJmgMbpI\"]', '2026-04-01 02:00:07.739', '2025-08-05 22:20:27.881', 698, NULL, 1, 2017, 'O Let\'s Poke nasceu em 2017 e de lá pra cá estruturamos o negócio para crescermos com qualidade, processos e lucratividade para nossa rede de franqueados. Atualmente temos 5 lojas próprias e 4 franquias que são a base do nosso conhecimento. O Let\'s Poke une um produto incrível que é tendência no mundo inteiro, alimentação saudável que não para de crescer, muita força vendas e know-how de delivery, ambientes de lojas aconchegantes, sócios gestores com vasta experiência e uma marca com posicionamento único no mundo do surf junto com nosso sócio, bicampeão mundial de surfe, Filipe Toledo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4dbec28c-f6a4-4c79-bdae-795adfc54242.png', 2, NULL, NULL, '2026-03-09 00:13:45.027', 'https://franquias.portaldofranchising.com.br/franquia-lets-poke/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76jz00ieeh0svol43x1e', 'PARMEGGIO GRELHADOS', 'parmeggio-grelhados', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fast Food', 2007, 2007, NULL, '2026-04-01 02:00:07.749', '2025-08-05 22:20:27.887', 699, NULL, 1, 2003, 'O PARMEGGIO Uma trajetória recheada de sabor e sucesso. \"Desde o princípio atendemos cerca sete mil clientes ao mês.\" Sergio Olmos A história do Parmeggio começou em 2003 na cidade de Campinas (SP), quando os empresários Marcelo Rocha e Sergio Olmos uniram sua vasta experiência no ramo de restaurantes fast food para criar uma nova marca, inspirada em uma receita italiana deliciosa, a Parmeggiana. “Pensamos nesse nome justamente por causa do prato que é uma de nossas especialidades: o tradicionalíssimo bife à parmeggiana, acompanhado de arroz com fritas ou fettuccine, feito de acordo com a tradicional receita italiana,” afirma Sérgio Olmos Com o tempo, o Parmeggio ganhou destaque pelo sabor irresistível de seus pratos e seu cardápio foi ampliado para incluir massas, saladas e tábuas de porções, perfeitas para happy hours e jantares. \nTamanha aceitação levou a empresa a inaugurar a rede Parmeggio Franquias em 2007, abrindo novas lojas em diferentes cidades e expandindo seu modelo de excelência em todo o país. A padronização dos processos e ingredientes garante uma experiência única de sabor em todas as unidades. O Parmeggio também se especializou em grelhados e se tornou famoso pelo seu contrafilé especial, que é um dos pratos mais pedidos em todas as mais de 60 lojas espalhadas pelo Brasil.” Marcelo Rocha O segredo do sucesso do Parmeggio é a simplicidade: ingredientes cuidadosamente selecionados, atendimento rápido e eficiente, um menu diversificado e muita paixão pelo trabalho realizado.  Por que investir no Parmeggio? Empresa 100% brasileira. Produtos de alta qualidade. Cardápio variado e atrativo ao público. Boa aceitação no mercado. Boa lucratividade. Qual é o perfil dos franqueados Parmeggio? Boas habilidades de liderança. Espírito empreendedor. Boa comunicação para gerenciar equipes e delegar tarefas. Disposição para trabalhar aos finais de semana e após o expediente. Conhecimentos em matemática financeira, contabilidade e administração. Ensino médio ou curso técnico concluído.  Como o Parmeggio ajuda a sua franquia a crescer? Suporte na busca do local ideal para instalação da franquia. Definição de identidade visual e layout da loja. Assistência permanente ao franqueado. Treinamento das equipes. Fornecimento de manuais e software de gerenciamento da unidade. Supervisões periódicas do negócio. E mais: parcerias com o Bradesco Franquias, o Santander Franquias e a Caixa Franquias que garantem o financiamento de até 50% do investimento* por meio de linhas de crédito! *Sujeito à análise de crédito e aprovação.  Quer um investimento seguro e rentável? Escolha a rede Parmeggio! Fundação: 2007 Unidade modelo: 1 Unidades franqueadas: 60 Metragem da loja: 30 a 50 m² Taxa de propaganda: 1% do faturamento bruto Taxa de royalties: 4% a 6% do faturamento bruto Taxa de franquia: R$ 35 mil a R$ 40 mil Faturamento médio mensal: R$ 150 mil Investimento inicial: R$ 390 mil a R$ 530 mil Tempo médio de retorno do investimento: a partir de 24 meses Prazo de contrato: 5 anos', NULL, 'SÃO PAULO', 1, NULL, 54, NULL, NULL, '2026-03-09 00:14:21.733', 'https://franquias.portaldofranchising.com.br/franquia-parmeggio-grelhados-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '330000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76k500ifeh0s4bw02rnn', 'KINSOL ENERGIAS RENOVÁVEIS', 'kinsol-energias-renovaveis', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Energias Renováveis, Mobilidade Elétrica e Mercado Livre de Energia', 2021, 2022, '[\"https://www.youtube.com/watch?v=ubGloRDwAeM\",\"https://www.youtube.com/watch?v=_cMRN1AQRd0\"]', '2026-04-01 02:00:07.758', '2025-08-05 22:20:27.893', 700, NULL, 1, 2013, 'A Kinsol tem a missão de levar ao cliente a satisfação de gerar a sua própria energia de forma limpa, com liberdade de escolha, para fazer parte de um mundo mais sustentável. Visão Nosso objetivo é ser referência como empresa fornecedora de energias solar. Buscamos atender às necessidades e expectativas dos nossos clientes realizando projetos com competência, e eficiência, gerando economia e sustentabilidade. Valores Pensamos muito além de simples valores. Visamos o respeito ao meio ambiente e a sociedade, gerando economia e proporcionando um futuro mais justo e sustentável para as famílias brasileiras. A empresa é integradora oficial e parceira da WEG. Por isso, oferece por meio da energia solar, soluções inteligentes, garantindo assim maior competitividade, economia, sustentabilidade e desenvolvimento para o país. O empenho e acúmulo de experiências exitosas no mercado de franquias, promoveu a Kinsol Energia a uma das maiores empresas do Brasil no segmento de energia solar que atualmente possui um enorme número de franquias em todas as regiões do país.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/df3d04f4-fef5-4328-8546-10163ea78c69.jpg', 344, NULL, NULL, '2025-06-12 16:26:07.000', 'https://franquias.portaldofranchising.com.br/franquia-kinsol-energias-renovaveis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76kd00igeh0sq5xcw2bj', 'ENGENHEIRO DO ÓCULOS LTDA', 'engenheiro-do-oculos-ltda', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Somos uma ótica especializada em consertos de óculos, nossa missão é dar acesso à saúde visual de qualidade, tornando o uso dos óculos acessíveis a todas as classes sociais.', 2024, 2024, NULL, '2026-04-01 02:00:07.769', '2025-08-05 22:20:27.901', 701, NULL, 1, 2021, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d80bb0e3-e6e3-443a-9d4c-1211e403ce5e.png', 4, NULL, NULL, '2026-03-09 00:16:05.085', 'https://franquias.portaldofranchising.com.br/franquia-engenheiro-do-oculos-ltda-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76kj00iheh0s6s694k2y', 'CONTA4U', 'conta4u', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'A nossa proposta é facilitar os processos contábeis para que sua empresa receba tudo com agilidade, qualidade e transparência. Agência de Contabilidade Digital.', 2020, 2020, NULL, '2026-04-01 02:00:07.779', '2025-08-05 22:20:27.907', 702, NULL, 1, 2019, 'A Conta 4U é a solução para quem busca praticidade, agilidade e simplificação para a gestão e contabilidade do negócio. \nO cliente tem à sua disposição o que há de melhor para a empresa, escritório, clínica, comércio e os microempreendedores. Diretamente do celular, tablete ou computador, ele fará, através de um painel simples e fácil de usar, todas as atividades que precisa nestes processos. É MUITO SIMPLES, FÁCIL E RESOLVE!', NULL, 'ESPÍRITO SANTO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b7eb5edc-72b8-43b9-892a-1da79f36b368.jpg', 14, NULL, NULL, '2026-03-09 00:16:31.858', 'https://franquias.portaldofranchising.com.br/franquia-conta4u/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76kp00iieh0sqpn05frc', 'NEW SHOES LAVANDERIA ESPECIALIZADA EM TÊNIS', 'new-shoes-lavanderia-especializada-em-tenis', NULL, 'Limpeza e Conservação', 'LAVANDERIAS', 'A Franquia New Shoes é pioneira no segmento de lavanderia especializada em tênis. Com layout inovador, a loja requer um espaço mínimo de 60m². Oferece serviços de pintura e pequenos reparos.', 2024, 2024, NULL, '2026-04-01 02:00:07.788', '2025-08-05 22:20:27.913', 703, NULL, 1, 2023, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/350ca7d3-c83d-436e-aa28-1dbb9d35eb47.png', 36, NULL, NULL, '2026-02-05 17:41:34.000', 'https://franquias.portaldofranchising.com.br/franquia-new-shoes-lavanderia-especializada-em-tenis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '244900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ku00ijeh0svcyhwjfs', 'KARSTEN S.A.', 'karsten-s-a', NULL, 'Casa e Construção', 'ARTIGOS PARA O LAR', 'Empresa da fabricação de cama, mesa e banho', 2025, 2025, NULL, '2026-04-01 02:00:07.797', '2025-08-05 22:20:27.919', 704, NULL, 1, 1882, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e8745b80-efa7-4470-8c7d-a9d7fd966b57.png', NULL, NULL, NULL, '2025-10-14 11:28:17.000', 'https://franquias.portaldofranchising.com.br/franquia-karsten-sa-casa-e-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76l000ikeh0sj26z3txr', 'EURO COLCHÕES', 'euro-colchoes', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Comércio de colchões, boxes, cabeceiras, poltronas e acessórios.', 2008, 2017, '[\"https://www.youtube.com/watch?v=4XBl0DKTwaE\",\"https://www.youtube.com/watch?v=W94UfIC3jBc\",\"https://www.youtube.com/watch?v=A2dahC9pb5M\"]', '2026-04-01 02:00:07.806', '2025-08-05 22:20:27.924', 705, NULL, 1, 2005, 'A Euro Colchões nasceu para entregar uma experiência única no mercado de colchões. Nós somos apaixonados pelo o que fazemos. E usamos nossa expertise e inovação tecnológica para cuidar dos nossos clientes. Nossa primeira loja foi inaugurada em 2005. Desde o início, nosso objetivo é oferecer produtos da mais alta qualidade, bem como um atendimento especializado e cuidadoso. \nAlcançar a excelência está em nosso DNA. \nTemos como foco principal o desenvolvimento de novas tecnologias para colchões, em 2011 inauguramos a nossa fábrica na cidade de Três Rio. Firmamos parceria de desenvolvimento, transferência de tecnologia, possuindo exclusividade de fabricação e comercialização dos colchões KINGSDOWN® no Brasil. Além disso, em parceria com a Unifi, maior fabricante de fios reciclados do mundo, desenvolvemos a linha EcoMind. \nNossa marca desperta interesse, devido a diferenciais como: baixo investimento, rentabilidade rápida, marcas exclusivas, fábrica própria e ausência de estoque. Essas são algumas das vantagens que um franqueado da Euro tem, além da certeza de comercializar produtos de alta qualidade. \nDisponibilizamos suporte ao franqueado, através de sistema de informática TOTVS, manuais operacionais, programa de treinamento e capacitação, consultoria de campo, marketing e publicidade. No ano de 2020, recebemos o prêmio Excelência em Franchising da ABF. \nA Euro Colchões se posiciona como uma marca de prestígio. Um local onde o cliente é atendido de forma diferenciada. Nos preocupamos em oferecer uma grande experiência de compra e nossos vendedores são altamente capacitados para ajudar o cliente a escolher o produto ideal.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/352041ca-c510-4eaf-946c-a1019d8ac27e.png', 72, NULL, NULL, '2026-03-09 00:17:48.591', 'https://franquias.portaldofranchising.com.br/franquia-euro-colchoes-artigos-para-o-lar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '278000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76l500ileh0s6l8r3yoe', 'VIASOFT', 'viasoft', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Soluções/Softwares de gestão empresarial', 1995, 2023, NULL, '2026-04-01 02:00:07.815', '2025-08-05 22:20:27.930', 706, NULL, 1, 1990, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9d194aa3-52ff-4c98-9e56-f9c3331aef84.png', 12, NULL, NULL, '2026-02-23 17:16:14.000', 'https://franquias.portaldofranchising.com.br/franquia-viasoft/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '36900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76lb00imeh0sa0l4v3nx', 'CASA DO CONSTRUTOR', 'casa-do-construtor', NULL, 'Casa e Construção', 'Construção e Reforma', 'Aluguel de equipamentos para construção civil, pintura, jardinagem e limpeza.', 1998, 1998, '[\"https://www.youtube.com/watch?v=jVA9BBF9znA\"]', '2026-04-01 02:00:07.824', '2025-08-05 22:20:27.935', 707, NULL, 1, 1993, 'Nossa história agrega, de fato, muitos desses valores. \nEscrita com ética, com responsabilidade social, contaminada pela paixão ao trabalho, devotada à sustentabilidade, à inovação, às melhores práticas de gestão, manifestada na excelência do atendimento ao cliente, no respeito humano. \nHistória que, desde sua origem, inspirou-se na amizade entre dois universitários, os engenheiros civis Altino Cristofoletti Junior e Expedito Eloel Arena. Partiu deles a iniciativa de materializar esse projeto. No início, em 1993, uma modesta loja de materiais de construção fundada em Rio Claro, região de Campinas, no interior paulista. \nDepois, nos três anos seguintes, desenvolveu-se o roteiro para a criação da primeira franquia brasileira especializada na locação de máquinas e equipamentos de pequeno porte para a construção civil. \nA Unidade Piloto da Rede surgiu em 1998, já com o registro da marca CASA DO CONSTRUTOR no INPI – Instituto Nacional de Propriedade Industrial. Naquele mesmo ano era inaugurada a primeira loja da franquia, em Americana. Consolidada, hoje, em todas as regiões do Brasil, num contínuo movimento de expansão pelo território nacional, é uma das marcas mais laureadas dos últimos anos. \nMelhor Franquia em 2010, pela Revista Pequenas Empresas & Grandes Negócios e também a Melhor do Brasil em 2012, prêmio da Associação Brasileira de Franchising (ABF), a qual a empresa é associada desde sua fundação. Em 2011, a CASA DO CONSTRUTOR tornava-se Empreendedor do Ano, pela Consultoria Ernst & Young, passando ainda a figurar como Empreendedor Endeavor. \nTodas as premiações – e são inúmeras – além de selos de certificação consecutivos obtidos têm o respaldo dos mais conceituados institutos. Com a responsabilidade de ser referência no mercado, a Rede se permite ter ao seu lado parceiros que também advogam os mesmos princípios. \nÉ este o perfil dos nossos franqueados, dos nossos fornecedores, todos consagrados em seus segmentos, dos nossos colaboradores, dos nossos amigos e clientes. \nNegócios são negócios, mas aqui as amizades nunca ficam à parte. O sucesso de um é o sucesso do coletivo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5ac6e109-453d-461e-9814-675adae77d97.png', 808, NULL, NULL, '2026-03-09 00:18:53.464', 'https://franquias.portaldofranchising.com.br/franquia-casa-do-construtor-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '529000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76lg00ineh0syzxq6z7c', 'ORTHODENT CLÍNICA ODONTOLÓGICA E SAÚDE INTEGRADA', 'orthodent-clinica-odontologica-e-saude-integrada', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Clinica Odontológica de Alta performance', 2020, 2021, NULL, '2026-04-01 02:00:07.833', '2025-08-05 22:20:27.940', 708, NULL, 1, 2014, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/96cbdfbc-2886-4854-9042-f56e0905e059.jpeg', 5, NULL, NULL, '2026-03-09 00:20:00.290', 'https://franquias.portaldofranchising.com.br/franquia-orthodent-clinica-odontologica-e-saude-integrada/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
