INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76lp00ipeh0sdf62lcsh', 'ITAL\'IN HOUSE MACARRÃO GOURMET', 'ital-in-house-macarrao-gourmet', NULL, 'Alimentação', 'Bares e Restaurantes', 'Restaurante de inspiração italiana, com foco para delivery e retirada - Receitas exclusivas de massas, risotos e nhoques gourmet.', 2021, 2023, NULL, '2026-04-01 02:00:07.853', '2025-08-05 22:20:27.950', 710, NULL, 1, 2020, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1ae514ee-df1f-4551-84d6-dd0241cb4378.jpg', 171, NULL, NULL, '2026-03-09 00:20:53.008', 'https://franquias.portaldofranchising.com.br/franquia-italin-house-macarrao-gourmet-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76lv00iqeh0sqk0ns8y0', 'DOUTOR RESOLVE', 'doutor-resolve', NULL, 'Casa e Construção', 'CONSTRUÇÃO', 'Doutor Resolve oferece serviços que atende tanto residências com pequenos reparos, reformas, projetos, construções e paisagismo, quanto empresas com soluções corporativas.', 2010, 2018, '[\"https://www.youtube.com/watch?v=euj4R9GYqDk\"]', '2026-04-01 02:00:07.863', '2025-08-05 22:20:27.956', 711, NULL, 1, 2010, 'Fundada em agosto de 2010, a Doutor Resolve nasceu com o objetivo de profissionalizar o setor de serviços da construção civil. Em um cenário de alta demanda e carente por profissionais qualificados e compromissados, rapidamente a Doutor Resolve conquistou milhares de clientes por todo o Brasil atendendo-os de maneira inovadora e altamente eficiente. Hoje a Doutor oferece serviços que atende tanto residências com pequenos reparos, reformas, projetos, construções e paisagismo, quanto empresas com soluções corporativas. A marca passou a fazer parte do portfólio de franquias da EFFE Franchising em Julho de 2016. A EFFE Franchising é uma Holding de Franquias, de São José do Rio Preto, interior de São Paulo. Além das marcas Doutor Resolve a EFFE também possui a marca Dona Resolve, focada em limpeza e facilidades para o lar e soluções para empresas. No ano de 2020 a Doutor Resolve alcança 5 Estrelas no anuário da revista da Pequenas Empresas e Grandes Negocios e neste mesmo ano conquista seu primeiro Sele de Excelência em Franchising, comprovando a qualidade da marca e eficiência do suporte ao franqueado. Nos anos seguintes a marca conquista o Selo de Excelência em Franchising, somando três conquistas consecutivas, consolidando sua presença de destaque no franchising brasileiro.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c5f26840-16e2-4683-8ccf-b3d9a3f24413.png', 25, NULL, NULL, '2025-08-22 18:40:20.000', 'https://franquias.portaldofranchising.com.br/franquia-doutor-resolve/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76m000ireh0su3q4dwks', 'NO COFFEE', 'no-coffee', NULL, 'Alimentação', 'Bares e Restaurantes', 'A REDE DE CAFÉS E SMOOTHIES MAIS INOVADORA DO BRASIL!', 2025, 2025, NULL, '2026-04-01 02:00:07.874', '2025-08-05 22:20:27.960', 712, NULL, 1, 2023, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/aceb33a6-73a7-4283-987a-df50a5f531fc.png', NULL, NULL, NULL, '2026-03-09 00:21:19.344', 'https://franquias.portaldofranchising.com.br/franquia-no-coffee-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76m500iseh0s4ghnhbtc', 'DETROIT STEAKHOUSE', 'detroit-steakhouse', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO COMPLETO', 'Steakhouse', 2014, 2021, '[\"https://www.youtube.com/watch?v=ghVb6lU3g_g\",\"https://www.youtube.com/watch?v=Fh-Q_Gax974\",\"https://www.youtube.com/watch?v=vVvHdQ1awjo\"]', '2026-04-01 02:00:07.884', '2025-08-05 22:20:27.965', 713, NULL, 1, 2011, 'O Detroit Steakhouse foi fundado em 2011 pelo Grupo Great Time, uma empresa com experiência em alimentação desde 2002. Em 2014 se tornou franquia e hoje já conta com cerca de 50 franquias comercializadas em todo o Brasil. Neste processo de venda e implementação de franquias é responsável pelo desenvolvimento de todos os fornecedores de equipamentos, alimentos e bebidas, implementação de toda a logística de suprimentos, posicionamento de marca e modelo de negócio. Uma marca estabelecida, com suporte abrangente, atendendo uma diversidade de público, levando boa gastronomia e acima de tudo experiência ao cliente.', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f007a672-cf29-45e3-8b2e-b36dc3bba465.png', 21, NULL, NULL, '2025-06-13 14:31:37.000', 'https://franquias.portaldofranchising.com.br/franquia-detroit-steakhouse/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ma00iteh0sbbeb2lb4', 'LA VINICOLA', 'la-vinicola', NULL, 'Alimentação', 'Bares e Restaurantes', 'Wine bar inovador com finger foods, carta de vinhos acessível e experiências sensoriais, voltado a iniciantes e apreciadores em ambientes informais e acolhedores.', 2016, 2025, NULL, '2026-04-01 02:00:07.894', '2025-08-05 22:20:27.971', 714, NULL, 1, 2013, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/594d48cb-3ea1-4afe-87c3-ff651d0e9c2d.png', 9, NULL, NULL, '2026-03-09 00:21:46.235', 'https://franquias.portaldofranchising.com.br/franquia-la-vinicola-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76mg00iueh0s9mdkuf98', 'TEMAKERIA JAPESCA', 'temakeria-japesca', NULL, 'Alimentação', 'Bares e Restaurantes', 'Culinária Japonesa', 2015, 2024, NULL, '2026-04-01 02:00:07.904', '2025-08-05 22:20:27.976', 715, NULL, 1, 2009, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6761fd7c-16c6-4f69-8491-25b0d450b054.png', 1, NULL, NULL, '2026-03-09 00:22:07.457', 'https://franquias.portaldofranchising.com.br/franquia-temakeria-japesca-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ml00iveh0si9wr90ns', 'CHURRAS EXPRESS', 'churras-express', NULL, 'Alimentação', 'Mercados e Distribuição', 'LOJA OU QUIOSQUE DE VENDA DE ESPETOS ASSADOS OU IN NATURA, COM UM MIX VARIADO DE PRODUTOS COMPLEMENTARES', 2018, 2021, '[\"https://www.youtube.com/watch?v=QpHr31r3pfA\",\"https://www.youtube.com/watch?v=l13E9tMA2wA\"]', '2026-04-01 02:00:07.914', '2025-08-05 22:20:27.981', 716, NULL, 1, 2018, 'CHURRAS EXPRESS – desde 2019 A ideia do Churras Express, surgiu após 18 meses de experiência em nossa outra franquia, no mesmo mercado mas com outro produto.  \nDetectamos na época quais eram os desejos e necessidades do público, quais os diferenciais deveriam ser criados e o que definitivamente atenderia essa necessidade independente de clima, local, fluxo entre outros quesitos.  \nO desafio seria criar algo que o brasileiro consome diariamente, de uma forma rápida, higiênica, com qualidade e baixo custo, surgindo assim o Churras Express Brasil.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/82ca99c4-ea04-4702-a860-949b784ffaf0.jpg', 57, NULL, NULL, '2026-03-09 00:22:33.407', 'https://franquias.portaldofranchising.com.br/franquia-churras-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '164000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76mq00iweh0sgq6wmz97', 'PEGGÔ MARKET', 'peggo-market', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Mercados autônomos para condominios e empresas', 2022, 2023, '[\"https://www.youtube.com/watch?v=dXom-1_NzBM\",\"https://www.youtube.com/watch?v=D-d_5VDYxP0\"]', '2026-04-01 02:00:07.924', '2025-08-05 22:20:27.986', 717, NULL, 1, 2021, 'Empresa formada por Empreendedores, que identificaram as oportunidades de mercado em meio à alta demanda proporcionada pelo advento da pandemia. \nDecidiram focar seus esforços em desenvolver um modelo de negócios que unisse tecnologia e praticidade para o ramo de minimercados, trazendo comodidade e praticidade aos clientes. Com muito estudo e pesquisas de mercado, quisemos ser ágeis na aplicação do modelo estudado, e já nos primeiros meses de operação o negócio foi replicado em novas unidades próprias. \nEm cada uma das unidades pudemos comprovar a viabilidade do modelo de negócios, nos deixando seguros de que poderíamos entrar para o sistema de franchising, permitindo a formação de uma rede de sucesso. Com isso, em 2022 o Peggô Market desenvolveu o modelo com o maior mix de produtos do seguimento, a única empresa a fazer abastecimentos diários, hoje está presente em varios estados Brasil, dentro dos principais condomínios. Mas não é só isso! Com toda a estrutura e suporte que nossa equipe fornece somos a única empresa que em toda nossa trajetória mantemos uma taxa de churn em 0%, isso temos 100% de satisfação em todos os condominios atendidos. O que você está esperando se juntar ao segmento que mais cresce no Brasil? Torne-se um franqueado do Peggô Market!', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ec901d74-2950-4d93-86d1-cd3107b6b265.png', 33, NULL, NULL, '2026-03-09 00:23:11.744', 'https://franquias.portaldofranchising.com.br/franquia-peggo-market/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '50000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
