INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ng00j1eh0se5j3gtaq', 'FAST DRYWALL', 'fast-drywall', NULL, 'Casa e Construção', 'CONSTRUÇÃO', 'Especialistas em Drywall, Acústica e Steel Frame. Fast Sistemas Construtivos abrange venda de produtos de alta qualidade e treinamento constante da equipe de vendas e projetos do franqueado.', 2021, 2022, NULL, '2026-04-01 02:00:07.973', '2025-08-05 22:20:28.012', 722, NULL, 1, 2021, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4190e795-4f8c-411a-8173-03f8cac9467d.png', 41, NULL, NULL, '2025-12-09 13:07:33.000', 'https://franquias.portaldofranchising.com.br/franquia-fast-drywall/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '222000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76nm00j2eh0s9j6uco1d', 'MARY HELP', 'mary-help', NULL, 'Limpeza e Conservação', 'Serviços de Limpeza', 'Agenciamento de diaristas, seleção de mensalistas, terceirização de mão de obra.', 2011, 2011, '[\"https://www.youtube.com/watch?v=4P6ObWojPps\"]', '2026-04-01 02:00:07.983', '2025-08-05 22:20:28.018', 723, NULL, 1, 2011, 'Como começou \nA Mary Help é uma franquia que foi concebida em abril de 2011, idealizada por José Roberto Campanelli e sua mulher. \nA motivação nasceu da constatação da dificuldade de se conseguir contratar uma profissional diarista para trabalhar em sua residência, Iogo após retornarem de uma viagem de férias. Então viu da dificuldade uma grande oportunidade de negócio. A franquia iniciou suas atividades com uma unidade própria em 2011 no município de São José do Rio Preto, já tendo sido concedida com a estratégia de se tornar, em pouco tempo, uma franquia nacional. \nA concepção do negócio foi baseada na constatação da forte demanda atual no Brasil por serviços prestados em domicílios em todas as áreas, notadamente para os serviços ligados à  organização, conservação e limpeza diária das residências e pequenas empresas (escritórios, clínicas, salões, lojas comerciais, etc).  Mary Help Pioneira no Brasil no seu modelo de negócio \nA Mary Help inovou em 2011 ao agenciar uma equipe de diaristas preparadas em sua escola de capacitação para realização de serviços de limpeza, faxina, lavar e passar roupas. Foi, portanto, uma proposta de negócio inédita no Brasil, operando na forma de uma rede de empresas pelo sistema de franchising. O conceito inicial foi estendido e hoje a Mary Help atua desde o agenciamento de diaristas para diversas funções, recrutamento e seleção de profissionais mensalistas (empregadas domésticas, babás, cuidadores de idosos, etc) e terceirização de mão de obras em residências e empresas.  Mão de obra altamente qualificada \nA mão de obra selecionada e treinada para realização de serviços representa um diferencial competitivo da Mary Help sobre as demais profissionais existentes no mercado. Isto é, há muito tempo ansiado pelas donas de casa que enfrentam a cada dia, com maior frequência, a escassez no número de empregadas domésticas mensalistas e sofrem com o despreparo das diaristas. A praticidade na contratação e a confiança percebida e valorizada pelos clientes é a chave para o sucesso da franquia.  Mais 5 bons motivos para você fazer parte da Mary Help \n1 - Vasta gama de serviços. Nossos principais serviços são: faxineira, lavadeira, passadeira, cozinheira, copeira, churrasqueiro, garçom, babá, cuidador de idosos, processos seletivos, terceirização de mão de obra, personal organizer, jardineiro, piscineiro, sanitização de ambientes, limpeza e higienização de estofados e tapetes. \n2 - Somos a rede do setor mais informatizada no momento. \n3 - Conquistamos pelo terceiro ano consecutivo o selo da ABF (Associação Brasileira de Franchising) de excelência em Franchising. \n4 - Em constante crescimento. Já somos mais de 160 franquias pelo Brasil. \n5 - O modelo de negócio Mary Help possui índice de satisfação entre 9 e 10 dos nossos clientes. \nEntre em contato e saiba como para fazer parte do time de franqueados Mary Help. Bem-vindo (a)! \nMais informações: www.maryhelp.com.br', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/69a6e24c-b736-4ec3-ac82-c0c56ad44bd5.jpg', 177, NULL, NULL, '2026-03-09 00:26:05.845', 'https://franquias.portaldofranchising.com.br/franquia-mary-help/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '40000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ns00j3eh0skf5dcnd7', 'S4F', 's4f', NULL, 'Serviços Automotivos', 'Locação de veículos', 'Locação de Carro por Assinatura para clientes pessoa física e Terceirização de Frota para empresas.', 2022, 2023, '[\"https://www.youtube.com/watch?v=ofTI5qnmDoo\"]', '2026-04-01 02:00:07.993', '2025-08-05 22:20:28.024', 724, NULL, 1, 2019, 'Com o olhar atento para as inovações e às mudanças do comportamento do consumidor, principalmente em relação à posse e uso, a Solution 4Fleet, uma empresa do grupo Santander, lança no mercado a marca S4F – SEU CARRO POR ASSINATURA, unindo seus produtos, soluções e conhecimento de toda a sua experiência para entregar um atendimento mais ágil, fácil e com foco no consumidor. Com a S4F, o consumidor fica somente com a parte boa de ter um carro, pois privilegiamos o atendimento humanizado, focado em atender problemas reais com pessoas de verdade, sem sustos ou surpresas no final do mês. Seja qual for o seu propósito de vida, é importante levar consigo parceiros verdadeiros, comprometidos com suas metas, pois tão importante quanto o que te leva a caminhar, é o que você leva do percurso. Para a S4F, tão importante quanto a chegada, é o caminho que você supera até chegar lá porque sabemos e acreditamos que é a maneira como nos relacionamos que nos motiva a ir sempre em frente. Conte com a S4F para seguir novos caminhos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6892bce1-ec8e-465a-9264-8d1437771f82.png', 24, NULL, NULL, '2026-03-09 00:27:35.059', 'https://franquias.portaldofranchising.com.br/franquia-s4f/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '573464.21', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
