INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76oj00j8eh0sbaltvnlw', 'DOUTOR SOFÁ', 'doutor-sofa', NULL, 'Limpeza e Conservação', 'Serviços de Limpeza', 'Limpeza e proteção de estofados.', 2015, 2020, '[\"https://www.youtube.com/watch?v=MFaa8Pc-tRE\",\"https://www.youtube.com/watch?v=VPNzlcjvhkE\"]', '2026-04-01 02:00:08.046', '2025-08-05 22:20:28.051', 729, NULL, 1, 2014, 'Com presença em mais de 1600 cidades em três continentes, a Doutor Sofá é a maior rede de franquias de limpeza especializada de estofados do Mundo! A franquia, com sede em Joinville-SC, é a única empresa do segmento à receber os dois maiores reconhecimentos do franchising nacional, o Selo de Excelência em Franchising (ABF) e o Prêmio 5 Estrelas da revista Pequenas Empresas Grandes Negócios, sendo uma das franquias com maior satisfação de franqueados de todo Brasil! Atualmente a Marca está presente em 25 estados brasileiros, com mais de 1 milhão de clientes atendidos! Com sistema próprio de gestão, a Doutor Sofá se destaca pela qualidade de seus serviços e pelo amplo suporte oferecido ao franqueado, que engloba todos os aspectos da gestão da franquia, desde a precificação dos serviços até o pós-venda ao cliente, passando pelo marketing para prospecção de clientes, que é um grande diferencial da marca. Além disso, os franqueados desfrutam de produtos exclusivos com marca própria, suporte completo na operação, forte presença de Marketing Digital para prospecção de seus clientes, e muito mais! A franquia também é pioneira em oferecer uma plataforma de streaming própria aos seus franqueados, o SOFÁFLIX, possibilitando ao franqueado se capacitar com centenas de treinamentos em vídeo para aprimoramento das operações. Com baixo investimento inicial e baixo custo operacional (por não exigir ponto comercial), a Doutor Sofá se destaca como uma franquia com rápido retorno do investimento, em média de 06 a 12 meses!', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ae5117a7-f329-4e07-83a4-ee5d04055b09.png', 164, NULL, NULL, '2026-03-09 00:29:26.683', 'https://franquias.portaldofranchising.com.br/franquia-doutor-sofa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '35000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76oo00j9eh0s5si6eq80', 'MINDS ENGLISH SCHOOL', 'minds-english-school', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Ensino de Inglês com duração de apenas 18 meses. Além do intensivo, com duração de um mês, no período de férias', 2008, 2009, '[\"https://www.youtube.com/watch?v=C-0o_Ct8ctk\"]', '2026-04-01 02:00:08.056', '2025-08-05 22:20:28.056', 730, NULL, 1, 2007, 'Em 2007, a marca Minds English School que remete a mente/inteligência é criada. \nLeiza Oliveira e Augusto Jimenez inauguram a sua primeira unidade e com o lado humano, em cada etapa do aprendizado, atinge a marca de 1.000 alunos em menos de um ano. \nPor isso, em 2008, os sócios enxergam que podem expandir a escola no sistema de franchising levando tecnologia em sinergia  com o processo de aprendizado de cada estudante. \nImplantaram as primeira lousas touch-screen, incluíram o conteúdo dos livros no tablet e uso dos board games (Jogos de tabuleiro) dentro e fora das salas de aula. \nTudo para tornar a fluência do inglês mais orgânico. \nA união entre a inovação e \"o olho no olho\" de cada estudante gerou uma expansão consciente e contínua em todo o país. \nCom o curso regular flex, em que o aluno fica fluente no idioma em 18 meses e pode agendar as suas aulas, a marca atingiu mais de 50 unidades em 2016. \nEm 2017, a rede coloca em prática o curso misto (50% online e 50% presencial) otimizando o tempo do estudante e possibilitando a inauguração de novas escolas em uma metragem mais compacta  e em municípios menores. \nIndo além dos grandes centros. Com essa nova ação saltamos para mais de 70 escolas.  \nDe Junho a Dezembro de 2019, mais três escolas foram inauguradas e o uso de gameficação fortaleceu. \nA Minds Idiomas é a única rede de inglês com expansão consciente de até 10 unidades por ano. \nEm que há o estudo para as novas franquias  a fim de  alcançar o público correto para esse novo franqueado(a), gerar lucro e entregar realmente o aprendizado do inglês para os seus estudantes.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/80e75855-ab8f-48ae-805b-28c314654f23.jpg', 52, NULL, NULL, '2026-03-09 00:30:20.862', 'https://franquias.portaldofranchising.com.br/franquia-minds-english-school-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
