INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76q600jgeh0sglhy5e00', 'TRADICIONAL BOLOS & TORTAS', 'tradicional-bolos-tortas', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Confeitaria especializada em produção diária de bolos caseiros, sobremesas, pudins e bolos confeitados para festa e tortas salgadas.', 2012, 2015, NULL, '2026-04-01 02:00:08.117', '2025-08-05 22:20:28.110', 737, NULL, 1, 2011, 'A TRADICIONAL BOLOS E TORTAS surgiu no ano de 2011 como uma das pioneiras na Capital do Estado de São Paulo. \nSua trajetória vem seguido sempre do fator inovador de produtos aliado à alta qualidade dos insumos, o que vem trazendo destaque em outras regiões do País também, tanto em cidades de interior como capitais, na qual o negócio se torta muito bem quisto pela sociedade por onde se instala, com um prestígio inigualável ao ponto de empresas de grande porte buscarem se aliar à TRADICIONAL BOLOS E TORTAS com parcerias igualmente vencedoras.  Venha também fazer parte deste negócio que não é comum de se encontrar e muito prazeroso para trazer resultados.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/dc12b84e-cf9d-44de-a863-73dae876046b.png', 38, NULL, NULL, '2026-03-09 00:33:49.142', 'https://franquias.portaldofranchising.com.br/franquia-tradicional-bolos-e-tortas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '240000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76qg00jheh0s90odr9jh', 'JAN-PRO', 'jan-pro', NULL, 'Limpeza e Conservação', 'SERVIÇOS DE LIMPEZA', 'Franquia de serviços de limpeza e manutenção de imóveis.', 1991, 2012, '[\"https://www.youtube.com/watch?v=dIUZDGuI2g4\",\"https://www.youtube.com/watch?v=USvAp1d2BoY\",\"https://www.youtube.com/watch?v=RIHv0p-nc6U\",\"https://www.youtube.com/watch?v=7IBHX1EJnlQ\"]', '2026-04-01 02:00:08.127', '2025-08-05 22:20:28.121', 738, NULL, 1, 1991, 'A franquia JAN-PRO foi criada em 1991, nos Estados Unidos. Hoje, atua em 15 países do mundo, com mais de 9.000 franqueados atendendo mais de 60.000 clientes. No Brasil desde 2011, atualmente tem 14 Franquias Regionais, que atuam como escritório de suporte e vendas de franquias nas cidades de São Paulo, Rio de Janeiro, Niterói, Vitória, Salvador, Recife, Belém, Manaus, Porto Velho, Belo Horizonte, Triângulo Mineiro, Campinas, Florianópolis e Porto Alegre. Que atendem a mais de 300 Franqueados locais, que por sua vez atendem a mais de 1.000 clientes de manutenção mensal. Sua equipe de gestão é composta por profissionais com mais de 25 anos de experiência no mercado de franquia e de limpeza, tendo participado da diretoria da ABF nos anos 90, bem como da fundação de outras entidades do segmento com ABRALIMP (Associação Brasileira de Limpeza), ABRAFAC (Associação Brasileira de Facilities), da Fundação Lidio Nobuo que foi a primeira escola profissionalizante de faxineiros do Brasil. O Jeito JAN-PRO A JAN-PRO é a maior franquia de limpeza comercial do mundo, e está classificada como a décima maior franquia americana. Presente no Brasil desde 2011 hoje é uma das cinquenta maiores franquias brasileiras. E já recebeu diversos prêmios que comprovam sua formatação, como os de excelência da ABF, de Melhor Microfranquia e Melhor Franquia de Limpeza da PEGN, nos últimos dois anos foi considerada uma das 25 melhores franquias brasileiras pela consultoria da Bittencourt, além de estar em primeiro lugar entre as franquias Top10 do segmento de limpeza. Este sucesso todo ocorre pelo contínuo aperfeiçoamento do modelo de franquia chamado de “Duas Camadas” ou de Franquias Regionais. As franquias de limpeza são consideradas no mundo todo como as precursoras do modelo de franquia de baixo investimento, que com sucesso em todos os países que é implantado acaba fomentando quase todos os outros modelos de franquia. A JAN-PRO conseguiu unir o modelo de baixo investimento com o de alto investimento, promovendo a oportunidade de todos os tipos de investidores virem a ser seu franqueado. Assim, um investidor com experiência empresarial e capital disponível poderá comprar um território para implementar a franquia JAN-PRO. Desenvolvendo todo o marketing necessário para atrair novos clientes de serviços de limpeza, e ao mesmo tempo montando uma central de serviços para dar suporte aos futuros Franqueados Locais que passarão a aderir à franquia nesta região. Estes Franqueados Locais irão comprar do Franqueado Regional o direito de operar a franquia de limpeza JAN-PRO e receberão como segurança para seu sucesso um cliente realmente garantido até quatro meses depois de treinado, num valor proporcional ao investimento inicial feito de acordo a um dos 19 planos de franquia que existem disponíveis no Brasil, o que lhe dará um retorno em menos de 18 meses. Franquia Locais Os franqueados Locais foram divididos em 3 categorias de acordo o grau de envolvimento com a operação dos serviços prestados. Microfranqueadores: os que vão executar os serviços por conta própria, que vão por a mão na massa. Eles fazem o menor investimento que existe hoje no mercado brasileiro de franquia. Franqueados Gerenciais: os que vão executar os serviços junto a uma equipe de até 10 auxiliares de serviços gerais. Realizam um investimento maior que o anterior, mas ainda assim menor que a média das franquias brasileiras. Franqueados Empresariais: a última categoria foi criada para atender àquela pessoa que irá coordenar duas ou mais equipes de limpeza em clientes diferentes, transformando-se no que hoje em dia se chama Multifranqueados. O investimento é equivalente à média do mercado brasileiro. Estes quatro formatos de franquia possibilitam que qualquer pessoa possa vir a ser franqueado da JAN-PRO, gerando uma flexibilidade enorme que gera também crescimento para a rede. Desta forma, o Franqueado Regional fica focado na obtenção de novos contratos de limpeza (gerando demanda) e os Franqueados Locais ficam focados na prestação dos serviços de limpeza (atendendo a demanda). Existem dezenas de casos de franqueados que iniciaram com contratos garantidos entre R$ 3.500,0 e R$ 9.000,00 e que depois de três anos faturam mais de R$ 100.000,00 mensais. Valores de investimento das franquias Master Franquia Taxa Inicial: R$ 240.000,00 Montagem Escritório: R$ 40.000,00 Capital de Giro: R$ 120.000,00 Faturamento Médio: R$ 1 milhão Microfranquia Taxa Inicial: R$ 20.500 (podendo ser financiada em até 36 meses) Montagem Escritório: 0 (porque é Home-Based) Capital de Giro: R$ 2.500,00 Faturamento Garantido inicial: R$ 36.000,00 Faturamento Médio: R$ 120.000,00 Franquia Gerencial Taxa Inicial: R$ 49.950,00 (podendo ser financiada em até 36 meses) Montagem Escritório: 0 (porque é Home-Based) Capital de Giro: R$ 5.500,00 Faturamento Garantido Inicial: R$ 144.000,00 Faturamento Médio: R$ 250.000,00 Franquia Empresarial Taxa Inicial: R$ 92.000,00 (podendo ser financiada em até 36 meses) Montagem Escritório: 0 (porque é Home-Based) Capital de Giro: R$ 12.500,00 Faturamento Garantido Inicial: R$ 360.000 Faturamento Médio: R$ 1.000.000,00 Agora o mais importante é saber que você pode começar no primeiro modelo e com o tempo ir avançando para os outros. Já temos casos, até no Brasil, de franqueados que começaram como Microfranqueados e que hoje são Franqueados Regionais.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/878fbea6-4cd4-4f03-9bd1-fa97584de2dd.png', 175, NULL, NULL, '2025-09-03 09:21:08.000', 'https://franquias.portaldofranchising.com.br/franquia-jan-pro/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76qv00jjeh0s7j27g898', 'ACADEMIA DE INGLÊS WASHINGTON', 'academia-de-ingles-washington', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escolas de Ensino Especializadas em Inglês.', 2015, 2016, '[\"https://www.youtube.com/watch?v=s3dqz7rPX9o\"]', '2026-04-01 02:00:08.137', '2025-08-05 22:20:28.135', 740, '88b24c4c-9be7-41a4-a01c-02f7e7ac9801', 1, 2008, 'A Academia de Inglês Washington nasce em 1963 quando o professor Luis Octávio da Costa chega ao Brasil vindo da Índia. \nO sonho de disseminar educação e cultura para alunos em todo o país tornou-se realidade com a fundação da primeira Academia de Inglês Washington na cidade de Arapongas-PR. \nA rede foi conquistando seu espaço, priorizando relações duradouras e pautadas no respeito com seus parceiros. \nHoje conta com unidades espalhadas por todo o Brasil que utilizam sua metodologia, os materiais didáticos e os processos de gestão. \nA rede segue em plena expansão, focada em oferecer um modelo de negócio que combina qualidade de ensino com especialização na língua inglesa, custos enxutos e alta rentabilidade. Em 2008, Siddhartha Octavio da Costa, filho do fundador, iniciou a expansão da marca através do modelo de licenciamento, onde a metodologia e material didático eram ofertados fundamentalmente para professores que tinham o sonho de empreender. \nEm 2015, a expansão passa a acontecer através do sistema defranchising, oferecendo aos seus parceiros um suporte completo para a gestão das unidades da rede. Além da metodologia de ensino e materiais didáticos exclusivos, o franqueado conta com um amparo que incluisoftware de gestão especializado, treinamentos presenciais e EAD. \nTambém são oferecidas ações comerciais e campanhas de marketing exclusivas, totalmente direcionadas para a comunidade onde a escola está inserida. Ao mesmo tempo em que valoriza e preza pela tradição de 55 anos dando novas oportunidades para as pessoas através do ensino da língua inglesa, a Academia de Inglês Washington sabe que é necessário renovar-se constantemente para acompanhar as tendências do mercado. \nÉ por isto que o material didático conta com tecnologias de realidade aumentada e virtual para proporcionar aos seus alunos a melhor experiência possível de aprendizado, além da plataforma interativa Washington Web, que permite complementar o que é visto na sala de aula através da tela do celular. \nTradição e modernidade andando juntas é uma prioridade da instituição.   As franquias da Academia de Inglês Washington representam uma opção com baixo investimento, rápido retorno e lucratividade líquida de 40%, sem restrições geográficas de mercado. \nO modelo se adapta a cidades de pequeno, médio e grande porte, tornando-se uma ótima opção não apenas para professores, mas também para qualquer empreendedor que procura uma boa opção de investimento. \nEm sua primeira participação no ranking Guia de Franquias da revista Pequenas Empresas Grandes Negócios obteve o 8° lugar no segmento Ensino de Idiomas, ficando a frente de grandes nomes deste mercado. Entre em contato com nossa equipe de expansão para iniciarmos uma parceria de sucesso!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/59a7aeb0-c37f-4822-a603-424114ac613f.png', 53, NULL, NULL, '2026-03-09 00:40:14.409', 'https://franquias.portaldofranchising.com.br/franquia-academia-de-ingles-washington-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76r400jkeh0sa6garcbu', 'TUTORES', 'tutores', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Transforme vidas através da educação: reforço escolar, aulas particulares, tutorias, apoio escolar, preparação para Enem e vestibulares.', 2008, 2008, '[\"https://www.youtube.com/watch?v=pMSU2m4T9zI\",\"https://www.youtube.com/watch?v=f4Ec2kd-A5c\",\"https://www.youtube.com/watch?v=YmwHDFGKa1Y\"]', '2026-04-01 02:00:08.146', '2025-08-05 22:20:28.144', 741, NULL, 1, 2007, 'Serviços oferecidos Acompanhamento escolar Reforço Escolar Acompanhamento da lição de casa Preparação para avaliações escolares Acompanhamento do dever de casa  Aula particular Preparação para prestar vestibulares Preparação para as provas do Enem Cursos para Acelerar a Aprendizagem Programa de Estimulação Cognitiva Quem são nossos clientes Alunos da Educação infantil Alunos do Ensino fundamental: 1º ao 9º ano Alunos do Ensino médio: 1º ao 3º ano Método Mais que um método, a Tutores é uma filosofia de educação que proporciona benefícios reais para os alunos. Nossa abordagem pedagógica enfatiza ensinar a aprender, fortalecendo o potencial de aprendizado de cada aluno e os incentivando à independência nos estudos.  Modalidades de Franquia Na Tutores, você pode escolher a modalidades de negócio que melhor se encaixa na sua realidade: Home Based: a operação da franquia é realizada no conforto de seu lar, sem necessidade de locação de um ponto comercial. Os alunos são atendidos pelos tutores em suas residências e em clubes, condomínios, escolas etc. Ponto Comercial: com uma unidade física, você terá a possibilidade de atuar não só nas residências dos alunos, mas também em seu ponto comercial, o que pode permite atender maior número de alunos e, consequentemente, obter maiores rendimentos. Os alunos podem ser atendidos nas seguintes modalidades: VIP: aulas individuais Flex: aulas em grupos  Os Fundadores Nossa experiência de 16 anos de franquia é respaldada pela visão empreendedora dos sócios-fundadores da Tutores.  Artur Hipólito é fundador da rede Home Angels, a maior franquia de cuidadores de pessoas da América Latina, pioneira no ramo, com mais de 170 unidades e 110.000 clientes atendidos no país. Sua expertise como gestor garante suporte sólido e eficaz para os franqueados da Tutores. Léa Bueno criou e desenvolveu sistemas educacionais de ensino de idiomas e produziu material didático para o Ensino Fundamental e Cursos Profissionalizantes. Suas pesquisas e visitas às principais empresas do setor de franquias de tutoria nos Estados Unidos a posicionam como uma fonte de conhecimento valioso, trazendo as melhores práticas internacionais para a rede.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f8ecd181-466d-476b-945c-5ccdcbab2665.svg', 20, NULL, NULL, '2026-03-09 00:41:42.151', 'https://franquias.portaldofranchising.com.br/franquia-tutores-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76r900jleh0scd129chz', 'HYPERLOCAL', 'hyperlocal', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Franquia de tecnologia, com produtos de alto valor agregado para todo o varejo local. Pense grande: Aja local, seja Hyperlocal.', 2018, 2019, '[\"https://www.youtube.com/watch?v=s31gRb-l6wk\",\"https://www.youtube.com/watch?v=d1rmF1KbLRo\",\"https://www.youtube.com/watch?v=yVM-noW8EzU\"]', '2026-04-01 02:00:08.157', '2025-08-05 22:20:28.150', 742, NULL, 1, 2013, 'A franquia Hyperlocal nasceu em 2018 quando ainda era Avec e os seus franqueados comercializavam apenas essa solução focada em beleza e bem estar. Em 2021, a partir de investimentos de fundos internacionais, a Avec adquiriu outros produtos, possibilitando aos franqueados aumentar seu leque de soluções para o comércio local. Assim nos tornamos Hyperlocal Franquias. Nosso franqueado pode atuar em todo o ecossistema de estabelecimentos locais, o que possibilita e facilita a geração de networking, gerando valor para todo esse ecossistema. Nossos principais diferenciais: Software de gestão com alto valor agregado e preço acessível; possibilidade de investimento baixo custo, receita recorrente, franquia home based e tecnologia de gestão totalmente integrada com meio de pagamento.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/32d7ccd2-acc7-4a5b-8a77-9d86e66d85d0.jpg', 32, NULL, NULL, '2025-09-01 16:43:18.000', 'https://franquias.portaldofranchising.com.br/franquia-hyperlocal/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76re00jmeh0sj660rb66', 'SPACE W', 'space-w', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Consultoria estratégica para empresas nas áreas de redução de custos, aumento de receitas, organização, compliance, escalabilidade e empreendedorismo.', 2020, 2022, '[\"https://www.youtube.com/watch?v=iNiFDb2YZK8\",\"https://www.youtube.com/watch?v=g66C1AZ9H_w\"]', '2026-04-01 02:00:08.167', '2025-08-05 22:20:28.155', 743, NULL, 1, 2020, 'A empresa teve origem no projeto pessoal de Juliana Tescaro, CEO da Space W, que vinha de uma carreira “estabilizada”, mas a vontade de criar novas frentes e compartilhar sua trajetória com outras mulheres e famílias estava maior.  Além de o momento ser propício para o desenvolvimento da Space W, começou a ganhar destaque no mercado, conquistando autoridade, recebendo premiações nas áreas de motivação e estímulo ao empreendedorismo feminino com impacto de renda nas famílias e sociedade, serviços corporativos e empresas em geral.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/651a9bbd-3590-4407-8b8a-1e2cde548682.jpg', 11, NULL, NULL, '2026-03-09 00:43:08.691', 'https://franquias.portaldofranchising.com.br/franquia-space-w/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '66688', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
