INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ru00jpeh0sy9fd7au3', 'REDE AUTORIZA SOLUÇÕES FINANCEIRAS', 'rede-autoriza-solucoes-financeiras', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Correspondente bancário, atuando com a intermediação de produtos financeiros voltados principalmente ao crédito para pessoa física.', 2019, 2020, NULL, '2026-04-01 02:00:08.197', '2025-08-05 22:20:28.170', 746, NULL, 1, 2015, 'A franquia nasceu em 2019 e faz de parte um grupo empresarial que está no mercado de crédito desde em 2007. O sócio majoritário do grupo vislumbrou a possibilidade de criar a Rede Autoriza para que pudéssemos disseminar nossos conhecimentos a empreendedores de diversas partes do país, ajudando-os a crescer em um mercado sólido e promissor. Com a inauguração da primeira loja em Agosto de 2019, hoje somos 11 franquias e estamos em franca expansão mesmo com os desafios do momento. Com o suporte de quem está há 14 anos no mercado de crédito para pessoa física, a Rede Autoriza Soluções Financeiras é o projeto certo pra quem deseja lucrar e expandir no mercado de créditos e financiamentos.', NULL, 'ESPÍRITO SANTO', 1, NULL, 11, NULL, NULL, '2026-03-09 00:44:06.276', 'https://franquias.portaldofranchising.com.br/franquia-rede-autoriza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '14490', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
