INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76sj00jueh0sprkyrnyr', 'DROGARIAS MAX', 'drogarias-max', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Farmácias e Drogarias', 1989, 2000, '[\"https://www.youtube.com/watch?v=ianBqNcQkkM\"]', '2026-04-01 02:00:08.245', '2025-08-05 22:20:28.196', 751, NULL, 1, 1983, 'Fundada em 1980, a rede Drogarias Max é a primeira franquia de farmácias do Brasil associada à Associação Brasileira de Franchising (ABF). Atualmente, são 128 lojas franqueadas em todo o Estado do Rio de Janeiro, que juntas faturam, em média, R$ 29 milhões por mês.  \nA Drogarias Max atua no mercado varejista farmacêutico como franquia de conversão para empresários independentes que buscam apoio para uma gestão estruturada e uma estratégia comercial eficaz de rentabilidade. \nHá duas formas de adesão: Selo Max e Bandeira Max.  \nPrincipais serviços oferecidos aos franqueados:  \n- Condições comerciais negociadas pela franqueadora;\n- Material de marketing;\n- Central de compras com aplicativo próprio;\n- Negociação centralizada de taxas de cartão de crédito e débito;\n- Indicadores de gestão e performance da drogaria;\n- 30mil clientes ativos pelo Convênio Empresas com desconto em folha;\n- Simulador para definição de metas;\n- Apoio nas políticas de precificação;\n- Acesso a linhas de crédito;\n- Assessoria jurídica;\n- Captação de pedidos para a loja por meio do Número Único;\n- Manual de operação de loja. A rede Drogarias Max é a única franquia do setor no Estado do Rio de Janeiro a fazer parte do ranking das dez marcas de farmácia mais lembradas pelos cariocas em 2020, de acordo com ranking do jornal O Globo. Desde 2014, conquista consecutivamente o Prêmio Excelência em Franchising, concedido pela ABF.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7a400c3a-16a9-4535-af9d-a6b213182cad.svg', 138, NULL, NULL, '2026-03-09 00:45:48.619', 'https://franquias.portaldofranchising.com.br/franquia-drogarias-max/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76sp00jveh0sgl4hvwy9', 'GELAB ANÁLISES CLÍNICAS (GRUPO EXAME LABORATÓRIOS DE ANALISES CLÍNICAS)', 'gelab-analises-clinicas-grupo-exame-laboratorios-de-analises-clinicas', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Franquia Laboratorial, para quem quer ter seu Laboratório de Análises Clínicas, modelo mais enxuto ao mais robusto de analises.', 2021, 2025, NULL, '2026-04-01 02:00:08.255', '2025-08-05 22:20:28.201', 752, NULL, 1, 1986, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/58be7e7a-d700-4f48-b48b-8478f0326f03.png', 10, NULL, NULL, '2026-03-09 00:46:43.564', 'https://franquias.portaldofranchising.com.br/franquia-gelab-analises-clinicas-grupo-exame-laboratorios-de-analises-clinicas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76su00jweh0s21ek4wnw', 'MORMAII FITNESS', 'mormaii-fitness', NULL, 'Saúde, Beleza e Bem Estar', 'ESPORTE E RECREAÇÃO', 'Franquia Studio Mormaii, com metodologia própria e exclusiva de treinamento físico.', 2015, 1990, '[\"https://www.youtube.com/watch?v=gPz1i6bxKFg\",\"https://www.youtube.com/watch?v=6Y66LjFJXFQ\",\"https://www.youtube.com/watch?v=JF2_mkfP12I\"]', '2026-04-01 02:00:08.266', '2025-08-05 22:20:28.206', 753, NULL, 1, 2013, 'A Mormaii é uma empresa originalmente brasileira e democrática que, acaba de completar 40 anos de história, tem como principal premissa proporcionar qualidade de vida às pessoas. Com raízes no mundo do surf e pioneirismo na fabricação das reconhecidas roupas de neoprene, hoje a marca transcende esse universo e se insere nas mais diversas categorias esportivas. Não seria por acaso que a Mormaii é considerada a maior e mais querida marca de esportes livres do Brasil, entregando aos seus consumidores e fãs mais de 5 mil itens que tangibilizam a promessa da marca. Seguindo por esse caminho e ampliando ainda a sua participação no mercado, a empresa desenvolveu o projeto Mormaii Fitness em 2012. O objetivo: melhorar o desempenho esportivo e a capacidade física das pessoas e proporcionar a melhor experiência, sejam elas atletas profissionais ou iniciantes, que estão à procura de opções diferenciadas e dinâmicas de exercícios físicos. Para isso, lançou uma metodologia exclusiva de treinamento, o Método Integrado Mormaii Fitness, que consiste em quatro pilares reunindo os movimentos do pilates, treinamento funcional e cardio, associados ao Five Konzept, uma técnica alemã trazida exclusivamente pela Mormaii para o Brasil. Através de nosso treinamento físico, ajudamos na melhora da performance de atletas, não atletas e de todos que desejam alcançar seus objetivos com mais saúde. Já são mais de 40 franquias espalhadas pelo Brasil. Invista agora em um negócio com propósito. Queremos levar para sua vida o estilo de vida que transpiramos dentro do Studio Mormaii.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3c76e7dd-720f-4d3f-ba3b-e5b562d81212.jpg', 52, NULL, NULL, '2025-08-07 11:33:56.000', 'https://franquias.portaldofranchising.com.br/franquia-mormaii-fitness/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76sz00jxeh0sntcxy2mw', 'Nanica', 'nanica', NULL, 'Alimentação', 'Doces', 'Comercio varejista', 2021, 2021, '[\"https://www.youtube.com/watch?v=tZIzmZJCx7g\"]', '2026-04-01 02:00:08.277', '2025-08-05 22:20:28.212', 754, NULL, 1, 2021, 'A rede de doceria Nanica foi criada por Leonardo Macedo e Tito Barcellos, amigos que se conheceram no tempo da faculdade de gastronomia, ainda em Curitiba, com um investimento de R$ 15 mil.', NULL, 'São Paulo', 1, NULL, 38, NULL, NULL, '2026-03-09 00:47:11.935', 'https://franquias.portaldofranchising.com.br/franquia-nanica/', 'Fat. Bruto', 'Fat. Bruto', NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '349000', NULL, NULL, NULL, '70000', NULL, '7', '2', '239000', '40000', 50);
