INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76uo00k9eh0st3bg4m0v', 'TFLOW', 'tflow', NULL, 'Moda', 'VESTUÁRIO', 'A marca TFlow, foi desenvolvida para o público masculino e feminino, modernos e sofisticados e tem em seus fundadores a tradição do empreendedorismo com ampla visão de negócios e paixão pela arte.', 2017, 2018, NULL, '2026-04-01 02:00:08.402', '2025-08-05 22:20:28.273', 766, NULL, 1, 2013, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/85f257c3-1b3a-4e0f-ae83-759c085e7f12.png', 43, NULL, NULL, '2025-06-18 15:19:36.000', 'https://franquias.portaldofranchising.com.br/franquia-tflow/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76uu00kaeh0sxitt260i', 'AMÁVIA COSMÉTICOS', 'amavia-cosmeticos', NULL, 'Saúde, Beleza e Bem Estar', 'COSMÉTICOS E PERFUMARIA', 'Franquia de Cosméticos especialmente Capilar comprometida em oferecer produtos de alta qualidade.', 2017, 2018, '[\"https://www.youtube.com/watch?v=-G5pur0OoMg\",\"https://www.youtube.com/watch?v=PRB_gjoOXWk\",\"https://www.youtube.com/watch?v=CPN3dP9eUEw\"]', '2026-04-01 02:00:08.412', '2025-08-05 22:20:28.278', 767, NULL, 1, 2011, 'Amávia foi fundada em 2011, com o objetivo de provocar uma revolução na área de estética capilar, com inovações e soluções para o mercado de cosméticos. Como novo conceito de marca, a empresa está sustentada pelos pilares do Amor e Viabilidade, sempre em busca da satisfação do cliente. Recebemos o Prêmio de Melhor Produto Capilar da América Latina, em 2019 com o produto Névoa Micelar Vegan Coconut e em 2021 com a linha Keraplex. O prêmio de Atualidade Cosmética celebra a inovação e o talento de profissionais e empresas que movimentam o mercado de beleza na América Latina. É reconhecidamente, o \"Oscar\" do mercado de beleza no Brasil. A expansão com franquias iniciou há cinco anos, e hoje a franqueadora soma mais de 80 operações, dentre quiosques e lojas, estrategicamente posicionados em 13 estados e Distrito Federal. Na contramão do mercado brasileiro, nossa empresa ampliou os resultados de faturamento durante a pandemia, e para 2024 projetamos um crescimento de 80% em nossa rede de franquias. Embora o número pareça audacioso, a sustentabilidade de um negócio de 12 anos, já se mostrou viável.', NULL, 'BAHIA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ae7a2a00-f7e4-43cb-b8a6-3e074f963f75.jpg', 59, NULL, NULL, '2025-07-01 13:12:45.000', 'https://franquias.portaldofranchising.com.br/franquia-amavia-cosmeticos-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76uz00kbeh0sawzmcac9', 'STUDIO GAMES', 'studio-games', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e Recreação', 'A maior rede de Studios de Entretenimento e Educação Gamer do Brasil.', 2021, 2022, NULL, '2026-04-01 02:00:08.422', '2025-08-05 22:20:28.283', 768, NULL, 1, 2017, '', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/130c337d-ecd7-4596-8b98-84d2d26fe87b.png', 7, NULL, NULL, '2026-03-09 17:52:27.185', 'https://franquias.portaldofranchising.com.br/franquia-studio-games/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76v400kceh0s85xma3m4', 'CLUBE DE PERMUTA', 'clube-de-permuta', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'O Clube de Permuta é uma plataforma de relacionamento que gera negócios através de Permuta. Fazemos intermediação de negócios através dos créditos concedidos aos associados para transações em Permuta.', 2015, 2019, NULL, '2026-04-01 02:00:08.432', '2025-08-05 22:20:28.289', 769, NULL, 1, 2012, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0a9b332b-bc9b-4a13-a90e-9a5aefb782ef.png', 21, NULL, NULL, '2025-11-19 16:37:57.000', 'https://franquias.portaldofranchising.com.br/franquia-clube-de-permuta/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76v900kdeh0se1h2v16n', 'THE STEAK FACTORY', 'the-steak-factory', NULL, 'Alimentação', 'Bares e Restaurantes', 'O The Steak Factory é uma marca de estilo Rústico, com Carnes e Burgers que vão proporcionar uma experiência única e com sabor verdadeiro de grelhado em fogo alto!', 2016, 2025, NULL, '2026-04-01 02:00:08.443', '2025-08-05 22:20:28.294', 770, NULL, 1, 2016, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ca4b701f-8936-42ab-9500-4eb3ff6d717f.png', 13, NULL, NULL, '2026-03-09 01:12:23.499', 'https://franquias.portaldofranchising.com.br/franquia-the-steak-factory/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '960000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vf00keeh0sywfh1fy6', 'PRA COMER', 'pra-comer', NULL, 'Alimentação', 'Mercados e Distribuição', 'Lanchonete, Cafeteria, Suplementação,', 2023, 2023, '[\"https://www.youtube.com/watch?v=N-GjLN66cDk\"]', '2026-04-01 02:00:08.453', '2025-08-05 22:20:28.299', 771, NULL, 1, 2016, 'Fundada em 2016, a Pra Comer nasceu a partir da vontade de ter mais tempo de qualidade com os filhos, desejo de maior autonomia para cuidar de projetos pessoais e da necessidade de uma renda maior.  À época era funcionário público do Governo de Minas Gerais, gastava muito tempo em deslocamento de casa/trabalho/casa e não me sobrava tempo nem disposição. \nComo funcionário público estadual não via possibilidade de aumentar renda, tão pouco de crescimento pessoal/profissional. \nEstava estagnado em um patamar financeiro que não me permitia projetar uma vida melhor para mim e meus filhos. Era preciso tomar o risco e empreender! Inicialmente montei o primeiro BOX da Pra Comer e toquei a empresa e meu trabalho no Governo do Estado paralelamente. \nApós 10 meses de operação da lanchonete, já ganhava o dobro do que ganhava como funcionário público! Então pedi exoneração do cargo público. O Box Pra Comer é uma lanchonete completa! Ocupa apenas 3m2, ideal para locais como hospitais, clínicas, shoppings, galerias, prédios comerciais, rodoviárias, aeroportos, etc. A Pra comer é uma ótima opção para empreender e prosperar em família. Aconteceu comigo, experiência própria!  Charleston Souza\nIdealizador da Franquia Pra Comer', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/533c4f64-725d-422a-9d07-92991d273b03.jpg', 1, NULL, NULL, '2026-03-09 01:12:48.149', 'https://franquias.portaldofranchising.com.br/franquia-pra-comer/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '74970', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vk00kfeh0sor09uijm', 'MUNIZ AUTOCENTER', 'muniz-autocenter', NULL, 'Serviços Automotivos', 'Locação de veículos', 'Auto Center, especialistas em serviços automotivo, corretivos e preventivos, troca de pneus, cambagem, alinhamento e balanceamento, sistema de ar cond., manutenção de freios, suspensão, troca de oleo.', 2016, 2020, '[\"https://www.youtube.com/watch?v=Gji_FzmfTZQ\",\"https://www.youtube.com/watch?v=qxxODQCN3YU\"]', '2026-04-01 02:00:08.464', '2025-08-05 22:20:28.304', 772, NULL, 1, 2009, 'Muito Prazer; somos a Rede Muniz Auto Center   Tudo começou com Maedson Muniz, um jovem que veio de uma família muito humilde e diversas vezes passou por muitas dificuldades, até mesmo privações extremas, porém Maedson sempre foi um jovem cheio de esperança e com um sonho a ser conquistado, ele começou a investir no seu futuro com apenas 11 anos de idade, para ajudar nas despesas em casa começou a trabalhar na oficina do seu tio, foi nesta fase que ele descobriu o sonho de ter seu próprio negócio, uma oficina, inspirado no seu pai que também era mecânico. \nInvestindo neste sonho, com 18 anos de idade, Muniz percebeu que precisava de uma renda extra, foi ai que ele começou a fazer bicos como office boy a noite e lavando carros aos sábados e domingos, ele mal descansava, mas seu desejo por crescer o impulsionava e dava forças para não desistir. \nAos 23 anos, foi quando ele decidiu que era a hora de começar o seu empreendimento! Fez um empréstimo de 6 mil reais e abriu a primeira Muniz Auto Center, o sonho, finalmente, havia começado. No começo era muito difícil, pois, Muniz não tinha ajuda, então era ele quem cuidava de tudo e todos os detalhes da tão sonhada empresa. \nMaedson Muniz sempre teve seu próprio objetivo e sempre soube o porque era tão importante alcançar seus sonhos e pela primeira vez em sua vida este sonho estava em prática, finalmente ele podia ajudar outras famílias a não sofrerem o que ele sofreu, podia dar uma chance a todos aqueles que quisessem crescer e alcançar seus próprios sonhos! \nSeu negócio foi crescendo cada vez mais, contratando funcionários, conquistando mais clientes e, após 5 anos da primeira loja localizada em Paranavaí, foi inaugurada em Maringá – PR, a segunda unidade da Muniz Auto Center, em pouco tempo, foi inaugurada a terceira loja, desta forma, sendo comprovado que o negócio, era sem dúvidas, um excelente empreendimento! \nCerto dia, conversando com um grande amigo que também tinha o sonho de ter seu próprio negócio e trazer estabilidade e conforto a sua família, Muniz pensando em formas de ajudar teve um estalo em sua mente, por que não transformar a Muniz Auto Center em uma franquia? Dessa forma, ajudaria não somente seu amigo, mas muitas outras pessoas, que assim como ele, sonhavam alto! Seu amigo aceitou comprar a primeira franquia na hora! Então em apenas 30 dias, tudo estava pronto e assim, foi inaugurada em Londrina a primeira franquia! \nCom um grande crescimento, atualmente, Muniz Auto Center conta com 30 franquias, em apenas 4 anos após a venda da primeira, um negócio comprovado e sólido no mercado. Muniz realizou seu sonho e o sonho de 30 famílias que, assim como ele, almejavam uma mudança de vida! \nE você quer mudar a sua vida? Temos a oportunidade certa para você que é apaixonado por carros, deseja uma mudança de vida e finalmente conquistar a tão sonhada liberdade financeira adquirindo o seu próprio negócio! Com nossa ajuda na gestão do seu novo empreendimento, sem dúvidas você vai longe, não perca esta grande oportunidade.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0927d125-0ce1-4edf-94d9-3c81314718b8.jpg', 59, NULL, NULL, '2026-03-09 01:13:35.226', 'https://franquias.portaldofranchising.com.br/franquia-muniz-autocenter/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vp00kgeh0s9en99u0r', 'SEU VIDAL', 'seu-vidal', NULL, 'Alimentação', 'Bares e Restaurantes', 'A franquia de sanduicheria Seu Vidal apresenta um modelo de negócio sólido e lucrativo, que tem atraído empreendedores em busca de oportunidades no ramo da alimentação.', 2022, 2023, NULL, '2026-04-01 02:00:08.474', '2025-08-05 22:20:28.310', 773, NULL, 1, 2016, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ab65bfe2-c04e-4379-8d24-6349398bcd15.png', 38, NULL, NULL, '2026-03-09 01:14:55.769', 'https://franquias.portaldofranchising.com.br/franquia-seu-vidal-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '380000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vu00kheh0ssqxku4tt', 'ARAMIS', 'aramis', NULL, 'Moda', 'Vestuários', 'Vestuário masculino, calçados e acessórios', 2003, 2019, '[\"https://www.youtube.com/watch?v=Ub-289B0IEE\",\"https://www.youtube.com/watch?v=Q5YX3z-lqV8\",\"https://www.youtube.com/watch?v=mEAylUih7wQ\",\"https://www.youtube.com/watch?v=DUiZrNkboTM\"]', '2026-04-01 02:00:08.484', '2025-08-05 22:20:28.314', 774, NULL, 1, 1994, 'A Aramis atua no mercado de moda masculina há mais de 25 anos, com excelência em qualidade, alinhada ao que há de novo em menswear pelo mundo. Inovamos constantemente, e nos mantemos conectados às tendências e demandas da moda masculina contemporânea. \nA Aramis foi criada em 1995 por Henri Stad, empresário francês com 45 anos de experiência no setor têxtil. \nA proposta da grife sempre se baseou em uma moda masculina moderna e sofisticada, com poder de inovação e tino comercial. \nFoi a primeira a trazer para o mercado brasileiro a camisaria de fio egípcio. Inspirado nas aventuras de “Os Três Mosqueteiros\", Henri batizou a marca em homenagem ao seu personagem preferido do romance histórico de Alexandre Dumas. \nA primeira loja foi inaugurada no Shopping Iguatemi, em São Paulo, em um dos mais concorridos espaços de moda do país. \nCom o tempo, aprimorou o estilo de suas peças, unindo conceito de moda, conforto, qualidade e evoluiu dividindo-se em quatro linhas: Menswear, Jeanswear, Night e Social, que juntas atendem o homem em todas as ocasiões. Atualmente, conta com uma equipe de estilo que acompanha as tendências mundiais e realiza pesquisas internacionais constantes sobre consumo.  \nCom um mix de produtos de qualidade indiscutível, é referência no lifestyle masculino, com alfaiataria de corte e caimento impecáveis em peças que vão do clássico ao moderno.  Expansão da marca Em fevereiro de 2014, o filho de Henri Stad, Richard Stad, assume a presidência, se tornando CEO, aos 29 anos de idade, após dez anos trabalhando na marca. \nDepois de um crescimento focado entre 2015 e 2016, a Aramis partiu para seu projeto de expansão, liderado por Richard, abrindo mais de 40 lojas, entre próprias e franquias, por todo o território nacional. \n“Com a abertura de novas lojas, o objetivo é oferecer ao cliente uma experiência de compra única. \nPara isso, implementamos um novo projeto de lojas - que segmenta a coleção em linhas para cada ocasião e valoriza ainda mais o produto. \nAlém do investimento no ponto de venda, também iniciamos um plano de marketing agressivo que atua com diferentes pontos de contato com o nosso consumidor.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/429e1a62-93aa-4ce5-9a5a-8081950d0f25.svg', 138, NULL, NULL, '2026-03-09 01:15:16.148', 'https://franquias.portaldofranchising.com.br/franquia-aramis-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1050000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vz00kieh0seqq9w8oh', 'ESPETINHOS MIMI', 'espetinhos-mimi', NULL, 'Alimentação', 'Bares e Restaurantes', 'Comércio de Espetinhos Assados, Congelados, Desenvolvimento e Comercialização de Outros Produtos e Organização de Festas e Eventos.', 1988, 1992, NULL, '2026-04-01 02:00:08.494', '2025-08-05 22:20:28.320', 775, NULL, 1, 1967, 'Mais de 50 anos de história \nCom DNA industrial, no começo de sua trajetória, a Espetinhos Mimi reinventou o jeito de fazer churrasco para facilitar a logística dos eventos – seja uma pequena festa familiar ou a confraternização de uma empresa para centenas de funcionários. Com o passar do tempo, além de fabricar os espetinhos e fornecê-los para eventos, a Espetinhos Mimi passou a produzir também para o segmento de marca própria, e hoje é responsável pelos espetinhos de grandes redes varejistas. Depois, em 1988, veio a presença no varejo, com lojas próprias e franqueadas. Hoje, a Espetinhos Mimi tem mais de 20 pontos de venda.  A fábrica, uma planta industrial de 1200 metros quadrados, está localizada em Indaiatuba/SP. O mais novo passo da marca, além dos novos modelos de franquia, e a construção de seu e-commerce. A nova loja virtual conta com uma plataforma robusta desenvolvida pela Vtex (R$ 500 mil de investimento), que está por trás de mais de 2,5 mil sites de comércio eletrônico, e inclui a rede de franquias na operação. Além da parceria inédita com o iFood para alavancar as vendas de suas lojas próprias e franqueadas.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/03dc8337-0f0c-491d-a6aa-80fcf467c745.jpg', 22, NULL, NULL, '2026-03-09 01:16:18.063', 'https://franquias.portaldofranchising.com.br/franquia-espetinhos-mimi/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '185000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
