INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76wr00kneh0s1ye9pw4n', 'INSTITUTO TRATA - JOELHO E QUADRIL', 'instituto-trata-joelho-e-quadril', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'CLÍNICAS DE FISIOTERAPIA', 2016, 2018, NULL, '2026-04-01 02:00:08.543', '2025-08-05 22:20:28.347', 780, NULL, 1, 2016, '', NULL, 'SÃO PAULO', 1, NULL, 60, NULL, NULL, '2026-03-09 01:18:14.456', 'https://franquias.portaldofranchising.com.br/franquia-instituto-trata-joelho-e-quadril/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ww00koeh0sjgc3epry', 'EX-TOURO', 'ex-touro', NULL, 'Alimentação', 'Bares e Restaurantes', 'Hamburgueria no modelo Delivery', 2020, 2021, '[\"https://www.youtube.com/watch?v=dGstIo4K3JU\",\"https://www.youtube.com/watch?v=RrS0c7hKdM0\"]', '2026-04-01 02:00:08.553', '2025-08-05 22:20:28.352', 781, NULL, 1, 2015, 'O negócio começou por acaso. Quando abriu as portas em 2015, na pequena loja no Cadeg, Yasser Regis tinha como ideia ser apenas um açougue de carnes nobres. Por pressão dos amigos (que adoravam seus hambúrgueres) começou a criar seus blends com cortes de angus e wagyu. A brincadeira se tornou sonho, o sonho se tornou realidade e a Ex-Touro foi premiada dois anos depois pelo prêmio da Veja Rio COMER & BEBER. O sucesso e a vontade de levar essa maravilha gastronômica para um maior número de pessoas fez a hamburgueria premium investir na sua expansão e se tornar uma franquia.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/12b9c5cd-d386-4604-beda-e4aca5d8f13c.png', 42, NULL, NULL, '2026-03-09 01:18:40.734', 'https://franquias.portaldofranchising.com.br/franquia-ex-touro/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '420000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76x100kpeh0s1qmj7aq1', 'WISEHOME', 'wisehome', NULL, 'Casa e Construção', 'Construção e Reforma', 'Solução inovadora para Automação Residencial sem quebra-quebra com tecnologia campeã dos desafios brasileiro e internacional de internet das coisas.', 2021, 2023, '[\"https://www.youtube.com/watch?v=fL2eYAEYdWI\"]', '2026-04-01 02:00:08.563', '2025-08-05 22:20:28.357', 782, NULL, 1, 2017, 'A WISEHOME É AUTORIDADE NO ASSUNTO A WiseHome foi criada com atenção aos detalhes, usando o que há de melhor na indústria mundial de hardware e software. Nossa patente requerida permite a automação residencial ou empresarial com facilidade de instalação, seja numa construção nova ou antiga, a instalação é feita de maneira prática e rápida. A nossa marca é referência no mercado devido à qualidade dos serviços prestados, tanto pelo atendimento pessoal quanto por equipamentos exclusivos que possuem excelente desempenho. É uma solução campeã do Desafio Brasileiro e Mundial de Internet das Coisas, nossa experiência agrega valor e reconhecimento. Possibilita uma instalação limpa e rápida, sem precisar de infraestrutura prévia. Além de ser a mais segura do mercado, com criptografia BLOCKCHAIN.  Seu cliente conseguirá controlar a iluminação, cascata da piscina, aparelhos de ar condicionado, TVs, persianas e  eletrodomésticos de onde estiver, com a velocidade de um clique e a segurança que só a WiseHome entrega!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e7d47150-c3ba-45ff-92ef-920e0c17a0cb.png', 47, NULL, NULL, '2026-03-09 01:19:16.711', 'https://franquias.portaldofranchising.com.br/franquia-wisehome/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
