INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76xg00kseh0s7ngqvhcd', 'MYBOX MARCENARIA MODERNA', 'mybox-marcenaria-moderna', NULL, 'Casa e Construção', 'MÓVEIS', 'Modelo 5 em 1 de negócio, com melhor custo beneficio do mercado. Loja de móveis planejados.', 2020, 2023, NULL, '2026-04-01 02:00:08.595', '2025-08-05 22:20:28.373', 785, NULL, 1, 2017, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6cc23e4e-8c35-4b58-90b2-b4480c0f4402.jpg', 52, NULL, NULL, '2025-07-04 16:20:54.000', 'https://franquias.portaldofranchising.com.br/franquia-mybox-marcenaria-moderna-casa-e-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76xl00kteh0sdnd2erso', 'DIA%', 'dia', NULL, 'Alimentação', 'Mercados e Distribuição', 'Supermercado Varejista', 1989, 2011, NULL, '2026-04-01 02:00:08.606', '2025-08-05 22:20:28.378', 786, NULL, 1, 1979, 'Cada dia mais perto  Somos a loja do bairro, aquela que proporciona uma experiência de compra fácil, rápida e completa, perto de casa e com produtos fresquinhos a um preço acessível. Chegamos ao Brasil em 2001, como parte do Grupo Dia, um dos maiores varejistas alimentares do mundo, atualmente com lojas na Espanha, onde nasceu em 1979, e na Argentina. Hoje, não fazemos mais parte do Grupo Dia, mas seguimos no Brasil, oferecendo qualidade e preço justo em 244 unidades próprias e franqueadas, distribuídas pelo estado de São Paulo. Juntos, somos mais de 2.300 colaboradoras e colaboradores. Contamos ainda com a Marca Própria Melhor a Cada Dia, que contempla desde alimentos, itens congelados e bebidas até produtos de limpeza, higiene e beleza – sendo a linha própria mais consumida no país, segundo a Nielsen IBOPE.', NULL, 'SÃO PAULO', 1, NULL, 240, NULL, NULL, '2026-03-09 01:20:42.489', 'https://franquias.portaldofranchising.com.br/franquia-dia-servicos-e-conveniencia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1515000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76xq00kueh0sb0jshabf', 'MANIA DE CHURRASCO! PRIME STEAK & BURGER', 'mania-de-churrasco-prime-steak-burger', NULL, 'Alimentação', 'Bares e Restaurantes', 'Steakhouse - (Churrasco, Lanches, Acompanhamentos, Saladas, Bebidas)', 2013, 2013, '[\"https://www.youtube.com/watch?v=DQEbdkbCzNk\",\"https://www.youtube.com/watch?v=e6Uz2xXp_Dg\",\"https://www.youtube.com/watch?v=M4BnTZ4IEd4\"]', '2026-04-01 02:00:08.616', '2025-08-05 22:20:28.383', 787, NULL, 1, 2001, 'Em agosto de 2001 nasce a Mania de Churrasco! Buffet Express com o autêntico churrasco gaúcho no shopping Ibirapuera. Em 2012, depois de muito aprendizado, persistência, diversos estudos e pesquisas, os fundadores do Mania de Churrasco! – começaram a pensar em um novo modelo de negócio, que pudesse ser replicado de maneira consistente e, então, nasceu o Mania de Churrasco ! PRIME STEAK HOUSE, cujo objetivo é oferecer, também em praça de alimentação, os melhores cortes de carnes nobres, normalmente encontrados apenas em churrascarias de luxo, restaurantes e butiques de carnes. \nO novo modelo de negócio foi concebido dentro do modelo de franquias. Isso, porque era crescente o número de pessoas interessadas em investir em um negócio semelhante ao Mania de Churrasco!, mas que envolvesse investimento um pouco mais baixo do que as unidades no modelo Buffet. Com investimento na casa a partir de R$ 2.5 milhão, o conceito – que une praticidade e qualidade – logo se revelou um sucesso. Durante este período, o número de candidatos a franqueados só cresce e a rede já contabiliza mais 90 unidades em operação nas regiões Sudeste, Sul, Centro – Oeste e também no Distrito Federal,  com um time com muita gente boa e que faz a marca crescer de forma saudável;', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4faa2b0c-e4e7-46c6-849e-735ba29fbd85.png', 106, NULL, NULL, '2026-03-09 01:21:22.854', 'https://franquias.portaldofranchising.com.br/franquia-mania-de-churrasco-prime-steak-burger-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76xv00kveh0s4e72i9mn', 'SCADA', 'scada', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'Cafeteria com foco no bem estar, muitos cafés especiais e um cardápio diversificado com produtos premium, pois acreditamos que toda pausa precisa ser especial.', 2007, 2022, '[\"https://www.youtube.com/watch?v=FhviVdzeTQs\",\"https://www.youtube.com/watch?v=3LvJMjEUzz0\",\"https://www.youtube.com/watch?v=LTQTNUBKtVg\",\"https://www.youtube.com/watch?v=SIsFAaWCA5o\"]', '2026-04-01 02:00:08.626', '2025-08-05 22:20:28.388', 788, NULL, 1, 2004, 'Acreditamos que toda pausa merece um café especial. A marca nasceu com esse espírito e seu nome foi inspirado nas características sensoriais dos melhores cafés: Sabor, Corpo, Acidez, Doçura e Aroma.. Somos uma marca contemporânea que acompanha as grandes tendências mundiais, sempre com foco no bem-estar dos nossos clientes, entregando o máximo de qualidade nos nossos produtos e serviços. A primeira unidade foi instalada em 2004 na cidade de Presidente Prudente, Estado de São Paulo, no modelo de quiosque. Em pouco tempo, a marca SCADA CAFÉ tornou-se referência na cidade e região. O principal diferencial da rede SCADA CAFÉ é a sua preocupação em oferecer um serviço e um café de excelência. O café comercializado na rede SCADA CAFÉ é produzido com grãos 100% arábica, cuidadosamente selecionados e torrados de forma artesanal, garantindo um toque pessoal à bebida. Cultivado na Serra da Mantiqueira, nas montanhas de Carmo de Minas, nossos cafés reúnem características raras, que fazem dele um produto altamente diferenciado e premiado como um dos melhores do mundo. O desejo de continuar crescendo, ganhando o mercado e novos consumidores, foi o fator preponderante para a marca entrar no sistema de franquia. Hoje a marca está presente nas principais capitais do Brasil, atendendo mais de 100 mil consumidores por mês. Temos três formatos de negócios, um cardápio democrático e inclusivo para atender os clientes a qualquer horário do dia e tornar o modelo de negócio mais atraente e lucrativo aos franqueados. VANTAGENS AOS FRANQUEADOS: Suporte inicial para escolha do ponto; Treinamento inicial e contínuo; Produtos para qualquer hora do dia; Consumidores de todas as idades; Fornecedores homologados há mais de 15 anos; Acompanhamento de resultados online; Ótima rentabilidade; Campanhas de markenting anual; Desenvolvimento de novos produtos; Consultoria de campo.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1205ab1a-128f-4229-8fc7-33736fd2ab2f.jpg', 7, NULL, NULL, '2025-09-12 14:13:31.000', 'https://franquias.portaldofranchising.com.br/franquia-scada/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76y000kweh0s440c4ju2', 'UNIORTO', 'uniorto', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'CLÍNICAS DE ODONTOLOGIA', 2024, 2025, NULL, '2026-04-01 02:00:08.636', '2025-08-05 22:20:28.393', 789, NULL, 1, 1996, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b2e5a8b7-04a4-4267-8aaa-3e8aabf591b4.png', 1, NULL, NULL, '2026-03-09 01:22:19.737', 'https://franquias.portaldofranchising.com.br/franquia-uniorto/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76y500kxeh0sorzeg6by', 'SONHO DOS PÉS', 'sonho-dos-pes', NULL, 'Moda', 'Calçados', 'Comércio Varejista de Calçados e Acessórios femininos.', 2004, 2018, '[\"https://www.youtube.com/watch?v=c8VzgshIo1I\",\"https://www.youtube.com/watch?v=cINuRWwKelM\",\"https://www.youtube.com/watch?v=G7EfbhjVBfw\"]', '2026-04-01 02:00:08.646', '2025-08-05 22:20:28.398', 790, NULL, 1, 1978, 'Você sabe qual segredo da Sonho dos Pés para os negócios? Nosso sonho começou em 1978, com a abertura de uma loja de bolsas e acessórios no Rio de Janeiro. \nMovidos pelo imenso desejo de conectar nossas clientes às principais tendências de moda, através do melhor custo-benefício, consolidamos a marca no mercado varejista como uma das mais presentes no dia a dia da mulher brasileira. Há 35 anos no mercado de calçados e acessórios e há mais de 20 anos franqueando, chegamos a mais de 200 lojas distribuídas pelos principais estados do Brasil, conseguindo atender a todos os estilos, por meio de um leque altamente variado de opções. \nSempre atentos aos detalhes que envolvem acabamento e durabilidade, oferecemos produtos que reúnem qualidade única, design e conforto: tudo isso aliado a uma experiência de compra encantadora! \nQueremos conquistar as mulheres da vida real e incentivá-las a serem o seu melhor, em qualquer momento ou humor. \nEntregando sempre brasilidade, proximidade e moda acessível. Faz parte dos nossos valores acreditar na arte dos encontros sinceros e genuínos e sabemos que juntos somos mais fortes, afinal amamos gente! A Sonho dos Pés cresceu sabendo que fazer junto faz toda a diferença, faz parte da nossa missão propiciar um ambiente de negócios seguro e rentável, por isso trabalhamos para oferecer aos nossos franqueados a melhor margem do mercado, um payback de até 36 meses e um lucro mensal de 10% a 15%. Sabemos da importância de um negócio sólido e de confiança, e temos total expertise nesse assunto, por 3 anos chancelados pela ABF com o selo de excelência em franchising. \nSomos uma marca com mais 3 milhões de pares de calçados vendidos no ano, com uma família de 49 franqueados. Venha fazer parte da família Sonho dos Pés!\n  A nossa marca está há 35 anos no mercado. Nós temos em nosso DNA: - Margem de 3,0;\n- Auxilio na escolha do ponto;\n- Lojas com uma ótima estrutura;\n- Suporte integral ao franqueado;\n- Marketing 360;\n- Preço acessível;\n- Qualidade e coleções que encantam;\n- Conforto e variedade; \n- Cartão Private Label exclusivo da loja.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a12b8729-5d9d-46ed-ab66-b2f929845618.jpg', 199, NULL, NULL, '2026-03-09 01:22:46.447', 'https://franquias.portaldofranchising.com.br/franquia-sonho-dos-pes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '330000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ya00kyeh0sext5nzcr', 'MAR NA MÃO', 'mar-na-mao', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'O restaurante atuará exclusivamente nos formatos delivery e take away, oferecendo refeições de alta qualidade, com foco em praticidade, sabor e excelente custo-benefício.', 2025, 2025, NULL, '2026-04-01 02:00:08.656', '2025-08-05 22:20:28.403', 791, NULL, 1, 2024, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0f7ff8c2-af46-4e16-985e-1605bcc91d06.png', 5, NULL, NULL, '2025-07-07 10:13:07.000', 'https://franquias.portaldofranchising.com.br/franquia-mar-na-mao-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76yg00kzeh0scua25o73', 'SOU COLUNA CLINICA ESPECIALIZADA', 'sou-coluna-clinica-especializada', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Somos uma clínica especializada no tratamento da coluna vertebral.', 2024, 2024, NULL, '2026-04-01 02:00:08.668', '2025-08-05 22:20:28.408', 792, NULL, 1, 2024, '', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2d4b288c-0b22-4d71-b708-922560e4af44.png', NULL, NULL, NULL, '2026-03-09 01:23:57.362', 'https://franquias.portaldofranchising.com.br/franquia-sou-coluna-clinica-especializada-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '205000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76yl00l0eh0snylm0wvq', 'PURE PILATES', 'pure-pilates', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Studio de Pilates', 2015, 2020, '[\"https://www.youtube.com/watch?v=oeQNU-sejPc\",\"https://www.youtube.com/watch?v=BSvpP0Hi3lQ\",\"https://www.youtube.com/watch?v=InFx8RTlbpM\",\"https://www.youtube.com/watch?v=XTdyHdR5iNE\"]', '2026-04-01 02:00:08.678', '2025-08-05 22:20:28.413', 793, NULL, 1, 2009, 'Nós da Pure Pilates nascemos com o intuito de oferecer para a comunidade o melhor em qualidade de vida. Desde 2009, atuamos em busca deste objetivo e somos uma empresa jovem e moderna, onde o atendimento diferenciado nos torna referência nacional no método Pilates. Sempre pensando em estar alinhados com o que há de novo no mercado, não nos acomodamos e investimos muito tempo e dedicação em pesquisa, treinamento e inovação. Nossos franqueados passam por um longo treinamento de capacitação para garantir que um excelente desempenho tanto nos negócios quanto na entrega de serviços aos seus alunos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3f7f2625-d838-48c3-afc5-3eda29a75efc.jpg', 275, NULL, NULL, '2026-03-09 01:24:23.829', 'https://franquias.portaldofranchising.com.br/franquia-pure-pilates/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '135000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76yq00l1eh0sirevxmbs', 'BRITISH AND AMERICAN', 'british-and-american', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Ensino do idioma inglês focado em uma metodologia rápida com ênfase na conversação. Gama de produtos que atendem todas as faixas etárias.', 2015, 2017, '[\"https://www.youtube.com/watch?v=M1seCK8zBhA\",\"https://www.youtube.com/watch?v=yvDcIYAeD2M\",\"https://www.youtube.com/watch?v=akjsrP0DgmI\"]', '2026-04-01 02:00:08.688', '2025-08-05 22:20:28.418', 794, NULL, 1, 1996, 'Com o respaldo do know-how adquirido ao longo de mais de 22 anos de experiência no mercado de ensino do idioma inglês, a franquia British and American tem um imenso orgulho em poder aproximar pessoas de seus sonhos. O segredo do nosso sucesso está na alegria do nosso aluno em frequentar aulas, e a nossa maior satisfação é perceber sua rápida evolução no nível de aprendizagem e aquisição da língua, dia após dia.\n  Por que escolher a BRITISH AND AMERICAN? • Software de gestão desenvolvido exclusivamente para a Rede, suprindo todas as necessidades e com constantes upgrades (atualizações); • Material didático próprio, moderno e registrado na Biblioteca Nacional; • Total suporte aos três departamentos: Comercial, Pedagógico e Administrativo; • Baixos custos fixos; • Desenvolvimento Profissional e Pessoal; • Gestão flexível do seu horário.\n  CURSOS OFERECIDOS Atualmente, a Rede BRITISH AND AMERICAN oferece aos franqueados 3 tipos de produtos distintos, mas conectados entre si.\n  CURSO TEENS Voltado ao mundo adolescente, o curso Teens absorve alunos a partir dos 09 anos de idade. O curso Teens tem duração de 04 anos e contempla 8 books, utilizando uma abordagem que fala a língua dos nossos alunos, os teachers promovem uma maior proximidade e interatividade em sala de aula. Tendo à disposição salas de aula com kits multimídia e com possibilidade de reforço semanal gratuito, o curso Teens torna-se um excelente investimento no futuro de nossos jovens.   CURSO ADULTS Curso dirigido a adultos e jovens a partir dos 15 anos de idade. O curso tem duração de 12 meses (3 books), com ênfase total na conversação, aulas ministradas 100% em inglês e horários semi-flexíveis, assim, o aluno marca sua aula conforme sua disponibilidade de tempo, podendo assistir até 05 aulas semanais. As turmas reduzidas (limite máximo de 05 alunos por turma), tornam o ensino muito mais personalizado. E tem mais, as matrículas ficam abertas o ano todo, com início imediato.   CURSO HYPER Seguindo a premissa de 12 meses de duração, e com um único book, o Curso Hyper é destinado a pessoas que já dominam o idioma inglês, mas que buscam proficiência. O curso potencializa todas as habilidades dos alunos, que ao final do curso, terão a oportunidade de fazer O teste de proficiência TOIEC, gratuitamente. A British and American é centro aplicador homologado deste teste.\n  CURSO START: Agora, pessoas que tiveram pouco contato com a língua inglesa, terão seu, \"Start\" na busca da fluência. The Start Book é divertido, atual e, acima de tudo, inclusivo. Ele foi criado com base em feedback direto tanto dos alunos como dos professores. Ele tem a duração 3 meses totalizando 12 aulas. No aprendizado da língua inglesa, confiança na sua capacidade é fundamental e o Start Book promove exatamente isso aos alunos, ao mesmo tempo que os prepara para o curso de 12 meses.   APOIO AO FRANQUEADO • Orientação para localização e aprovação do ponto comercial; • Fornecimento do Manual do Franqueado, explicitando o know-how de instalação, operação e gestão da British and American; • Orientação e manual do projeto arquitetônico e comunicação visual; • Indicação de fornecedores e prestadores de serviços homologados.    SERVIÇOS CONTÍNUOS • Capacitação contínua para o FRANQUEADO OPERADOR e sua equipe de trabalho; • Orientação nas ações de captação de alunos, coordenação dos planos de comunicação, bem como a criação e arte-final das peças de comunicação para veiculação pelos FRANQUEADOS no mercado; • Supervisão periódica do padrão de qualidade dos serviços prestados; • Desenvolvimento e busca constante de melhorias do Sistema de Franquia British and American, objetivando o crescimento e sucesso das unidades FRANQUEADAS; • Realização de encontros periódicos, para exposição de ideias, críticas, sugestões, bem como realização de workshops, convenções, seminários, palestras e treinamentos; Programa BFF. Ações de relacionamento com clientes internos e alunos.   Mais informações Contato: expansao@britishandamerican.com.br', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/02c21c2d-ca28-489a-b415-903d3bc7023e.jpg', 14, NULL, NULL, '2026-03-09 01:24:56.321', 'https://franquias.portaldofranchising.com.br/franquia-british-and-american-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '80000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76yw00l2eh0sfrryqnwe', 'BALANCEADO', 'balanceado', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Balanceado é uma rede de alimentação saudável ancorada na megatendência mundial da saudabilidade e sustentabilidade, oferece uma alimentação muito colorida e nutricionalmente correta.', 2013, 2018, NULL, '2026-04-01 02:00:08.698', '2025-08-05 22:20:28.425', 795, NULL, 1, 2013, 'O Balanceado é uma rede de franquias gaúcha com foco em alimentação saudável, equilibrada e não radical, o que se traduz no seu nome e faz parte da megatendência mundial de saudabilidade. Seu mix de produtos é muito colorido, cheio de texturas e muito sabor,  o que proporciona combinações incrivelmente equilibradas e deliciosas. Apesar de seu carro chefe serem saladas personalizadas montadas pelo clientes, a marca possui pratos quentes, sanduiches, wraps, sucos, sobremesas e bebidas geladas saudáveis. \nTodo o cardápio é concebido por uma equipe de nutricionistas, engenheiro de alimentos e chefes especializados. \nPara aqueles que buscam por uma alimentação natural e saudável, as receitas contam com insumos frescos e de muita qualidade. A marca surgiu em 2010 de um projeto de vida do empresário carioca, Bernardo Thomaz, que sempre idealizou ter um negócio de alimentação saudável e sustentável que fizesse bem as pessoas e ao planeta e que pudesse crescer mundo afora. \nUsando sua experiência de mais de 20 anos como franqueador de alimentação de outro segmento, ele conseguiu concretizar seu projeto com muito sucesso. Com 12 lojas espalhadas pelo Sul do Brasil, o Balanceado é uma marca que está sempre atenta as novas tendências de saudabilidade e necessidades de sustentabilidade, com inovações constantes no seu mix de produtos, buscando sempre o melhor para os seus clientes, para o planeta e é claro, para os seus franqueados. O faturamento médio anual de uma franquia Balanceado é de R$1.000.000,00, com uma lucratividade de até 25%, payback de 24 a 36 meses e investimento médio de 450mil (incluindo a taxa de franquia).', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/bc1cd03e-07f8-4872-b598-576d1c8891c3.jpg', 7, NULL, NULL, '2026-03-09 01:26:46.393', 'https://franquias.portaldofranchising.com.br/franquia-balanceado/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76z200l3eh0skwcz8z65', 'CENTRO BRITÂNICO', 'centro-britanico', NULL, 'Educação', 'Idiomas', 'Cursos de Idiomas', 2005, 2007, NULL, '2026-04-01 02:00:08.709', '2025-08-05 22:20:28.431', 796, NULL, 1, 1969, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ed1bdc75-4e6f-4bf8-8ade-776233bb3870.jpg', 24, NULL, NULL, '2026-03-09 17:53:57.626', 'https://franquias.portaldofranchising.com.br/franquia-centro-britanico-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76z900l4eh0sglgepcyd', 'ORTOESTÉTICA', 'ortoestetica', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Clínica Odontológica', 2011, 2015, NULL, '2026-04-01 02:00:08.719', '2025-08-05 22:20:28.438', 797, NULL, 1, 2005, 'Ortoestética é a maior rede orofacial do Brasil que tem como embaixadora da marca a artista Claudia Leitte, além de parceria com os maiores fornecedores do segmento. A ortoestética possui royalties fixo, sem cobrança sobre o percentual do faturamento e com taxa de aquisição justa, acessível e facilitada. \nA marca oferece modelo 2 em 1: saúde e estética, nos formatos express, standard e premium. Segundo a revista de empreendedorismo, Pequenas Empresas & Grande Negócios, a franquia está entre as melhores para se investir em 2021. Aproveite!', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3661c540-cd58-44da-b65f-b6d4a32e0441.jpg', 85, NULL, NULL, '2026-03-09 01:28:08.500', 'https://franquias.portaldofranchising.com.br/franquia-ortoestetica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '250000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76zg00l5eh0sq111300n', 'JUMPER PROFISSÕES E IDIOMAS LTDA', 'jumper-profissoes-e-idiomas-ltda', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Um modelo de negócio completo e lucrativo! Com a Jumper, você tem a chance de abrir uma escola com cursos na área de idiomas, tecnologia, administração, industrial, saúde e beleza em um só lugar.', 2009, 2018, '[\"https://www.youtube.com/watch?v=121_3fxTujQ\"]', '2026-04-01 02:00:08.729', '2025-08-05 22:20:28.445', 798, NULL, 1, 2003, 'A Jumper Profissões e Idiomas é uma Franquia com 18 anos de história, mais de 150 franquias pelo Brasil, conta com os melhores cursos do mercado, atende todas as idades e gêneros com um portifólio completo, opções das formações na área de Beleza, Idiomas, Industriais, Saúde, Negócios & Business e Idiomas. As Escolas da rede têm como os principais diferenciais, serem centros aplicadores do teste do TOEIC (Test Of English for International Communication) e a Formação do Executivo JR (Curso voltado para formação de executivos e empreendedores, sendo a pioneira no Brasil. Modelo de franquia A Jumper! trabalha com um modelo inovador de negócio, com valores de investimento que partem de R$ 129 mil. São três modelos de franquias: Express, Standard e Premium. O modelo Express é voltado para cidades acima de 20 mil habitantes, enquanto o modelo Standard é indicado para cidades acima de 40 mil habitantes. Já a franquia Premium deve ser instalada, preferencialmente, em cidades acima de 100 mil habitantes. A proposta de retorno é atrativa: com taxa de lucro entre 30% e 40%, o payback parte de seis meses. O faturamento médio é de R$ 50 mil. Suporte e treinamento A Jumper Escolas oferece suporte completo desde a compra da franquia, disponibilizamos Setor jurídico para orientações sobre todos os aspectos legais. Desenvolvimento de Franquias, auxilia desde a busca do imóvel, contratação e treinamento de toda a equipe e Franqueado, check list, pré e pós inauguração e todas as ações do zero ao 100% da Franquia. Agência própria de Marketing, terá uma agencia exclusiva da marca, fazendo campanhas ilimitadas, personalizadas para a região do franqueado. Setor pedagógico irá acompanhar todo o desenvolvimento da escola, é responsável pela busca incansável por inovações nas áreas de cursos, metodologias e as tendências do mercado. Além de disponibilizar um consultor por 30 dias imerso na unidade sem custo nenhum ao franqueado.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b425e4c1-2a7d-48fc-8d63-e6b635980405.jpg', 29, NULL, NULL, '2026-03-09 01:28:47.123', 'https://franquias.portaldofranchising.com.br/franquia-jumper-profissoes-e-idiomas-ltda-servicos-educacionais/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '186999.71', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76zm00l6eh0sf1b8cx0u', 'JORGE BISCHOFF', 'jorge-bischoff', NULL, 'Moda', 'Calçados', 'CONSULTORIA EM GESTAO EMPRESARIAL, COMERCIO VAREJISTA DE CALÇADOS E ACESSÓRIOS', 2008, 2010, '[\"https://www.youtube.com/watch?v=Xd7B9xGNPHs\",\"https://www.youtube.com/watch?v=qZGhHY_0Skc\",\"https://www.youtube.com/watch?v=vHVe8E5WANs\",\"https://www.youtube.com/watch?v=zhzODbdsa4Q\"]', '2026-04-01 02:00:08.739', '2025-08-05 22:20:28.450', 799, NULL, 1, 2003, 'Há 16 anos no mercado de franchising, a JORGE BISCHOFF conta com uma consolidada rede, com mais de 120 lojas exclusivas em operação, em todas as regiões do Brasil. Duas lojas-conceito são as grandes vitrines da marca. Elas estão localizadas na Rua Oscar Freire, nos Jardins, em São Paulo/SP e na cidade turística de Gramado, na Serra Gaúcha, entregando toda experiência de lifestyle da grife aos seus visitantes. As demais lojas da rede apresentam layout estratégico com foco em vendas, produtos em evidência e experiência sensorial e de consumo, que conquista e fideliza clientes. Entre os diferenciais competitivos da franquia JORGE BISCHOFF destacam-se: o maior markup de preços do segmento, o alto poder de fidelização dos clientes e a ausência de cobrança da taxa de propaganda. A JORGE BISCHOFF também investe na implementação de estratégias omnichannel, proporcionando praticidade na jornada de compra do cliente e experiências personalizadas, além de oferecer vantagem competitiva significativa para a loja. Como marca de lifestyle, a JORGE BISCHOFF tem uma linha ampla de produtos, que vai além do mix de sapatos, bolsas e acessórios – femininos e masculinos – com lançamentos e novidades chegando nas lojas constantemente. Nas coleções especiais o destaque vai para: SAY YES (noivas); LUXO LEGÍTIMO (pele original de python); VIAGENS (malas e mochilas); MONOGRAMA (itens com a exclusiva estampa Monograma JB); ESSÊNCIAS (aromatizadores de ambiente com o perfume da loja); BISCHOFF WINES (espumantes exclusivos da marca). Além da rede de lojas de franchising, a JORGE BISCHOFF também tem atuação global, estando presente em mais de 60 países nos cinco continentes, somando cerca de 600 pontos de venda em todo o mundo.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8456e0a6-9ea6-4ebd-9302-4da375559029.svg', 130, NULL, NULL, '2026-03-09 01:29:51.848', 'https://franquias.portaldofranchising.com.br/franquia-jorge-bischoff-acessorios-pessoais-e-calcados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '600000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76zr00l7eh0seu7or33i', 'ROBOMIND', 'robomind', NULL, 'Educação', 'EDUCAÇÃO', 'Fundada em 2014, em Blumenau (SC), a Robomind foi criada por educadores comprometidos com uma missão clara: promover o empoderamento intelectual dos estudantes por meio da Robótica Educacional.', 2021, 2022, NULL, '2026-04-01 02:00:08.749', '2025-08-05 22:20:28.456', 800, NULL, 1, 2014, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4b67eb8d-58d8-4b10-bfff-e6aa548cb39a.svg', 35, NULL, NULL, '2025-09-10 18:59:25.000', 'https://franquias.portaldofranchising.com.br/franquia-robomind/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
