INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza770800laeh0s091ug5aq', 'USINA HAMBURGUERIA GOURMET', 'usina-hamburgueria-gourmet', NULL, 'Alimentação', 'Bares e Restaurantes', 'Hamburgueria artesanal nascida em 2016 com serviço de delivery e salão, com seis lojas no Rio de Janeiro. Eleita por 3 anos consecutivos como top 3 do Rio de Janeiro.', 2020, 2025, NULL, '2026-04-01 02:00:08.770', '2025-08-05 22:20:28.473', 803, NULL, 1, 2016, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b675d266-e68c-4511-bf62-ac93070970b4.png', 6, NULL, NULL, '2026-03-09 01:38:12.709', 'https://franquias.portaldofranchising.com.br/franquia-usina-hamburgueria-gourmet-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza770e00lbeh0smruzf4r1', 'ESCOLA NUTRIDINHOS', 'escola-nutridinhos', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Clinica de nutrição infantil, com metodologia exclusiva de atendimento em grupo, voltada para Seletividade alimentar', 2024, 2025, NULL, '2026-04-01 02:00:08.780', '2025-08-05 22:20:28.478', 804, NULL, 1, 2021, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/21f48554-0959-471d-ab66-d45d85de9255.png', 4, NULL, NULL, '2026-03-09 01:38:34.426', 'https://franquias.portaldofranchising.com.br/franquia-escola-nutridinhos-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza770j00lceh0saf3r2z4n', 'ESPAÇO FACIAL', 'espaco-facial', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Franquia de Harmonização facial e corporal, como aplicação de botox, preenchimento, bioestimuladores de colágeno e etc.', 2019, 2023, NULL, '2026-04-01 02:00:08.790', '2025-08-05 22:20:28.483', 805, NULL, 1, 2019, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/02c02e6e-e451-423f-9453-4efcb80afb25.png', 20, NULL, NULL, '2026-03-09 01:38:57.770', 'https://franquias.portaldofranchising.com.br/franquia-espaco-facial/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '270000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza770o00ldeh0solzoid7m', 'O BOTICÁRIO', 'o-boticario', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'COMÉRCIO DE COSMÉTICOS E PERFUMARIA', 1980, 1992, NULL, '2026-04-02 13:13:57.947', '2025-08-05 22:20:28.489', 806, NULL, 1, 1977, 'A Franquia O Boticário está há mais de 35 anos no sistema de Franchising. Hoje somos a maior rede de franquias do Brasil e a maior do mundo em perfumaria e cosméticos.  Para conseguir este marco, a parceria com nossos franqueados é fundamental.  Esse é um dos motivos pelos quais eles têm a preferência na abertura de novas lojas. \n  NOSSA HISTÓRIA Somos otimistas, alquimistas e apaixonados Acreditamos que a beleza tem o poder de transformar acontecimentos simples em momentos mágicos.  Afinal, de que outra forma conseguiríamos transformar uma batedeira em uma fábrica que espalha beleza por todo o Brasil e vários países pelo mundo? Para explicar esta história, temos que voltar ao início.  Tudo começou em 1977, quando o recém-formado bioquímico Miguel Krigsner resolveu abrir sua própria farmácia de manipulação na rua Saldanha Marinho, centro de Curitiba. O nome do negócio foi uma homenagem aos antigos farmacêuticos, que manipulavam medicamentos de forma artesanal.  Assim nasceu O Boticário.  Ao perceber que a maioria dos clientes eram mulheres, Miguel colocou seu lado alquimista em ação e criou cremes faciais à base de algas marinhas e colágeno, que misturava em uma batedeira de bolos nos fundos de sua botica.  O sucesso das fórmulas se espalhou pela cidade e mudou para sempre os rumos do negócio. Em 1979, a trajetória de Miguel Krigsner se cruza com a de outro empreendedor.  Ao ouvir falar que Silvio Santos havia desistido de abrir uma marca de perfumaria no Brasil e possuía 60 mil frascos em forma de ânfora, mas que a oferta era tudo ou nada, apostou no otimismo: mesmo sem ter o dinheiro ou espaço para armazená-las, fez uma oferta para levar todas sob a condição de devolvê-las se não conseguisse pagá-las.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5bb51cb1-6c61-4bed-9d10-a55dad351432.png', 4051, NULL, NULL, '2026-03-09 01:39:23.573', 'https://franquias.portaldofranchising.com.br/franquia-boticario-valor/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9bfea048-53e5-4138-83eb-88353e37b5f8.jpg\"]', 1, 3, 3, 1, 'MAINTAIN', 1, 1, '[\"RANKING_CATEGORIA\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza770u00leeh0s4glhgujk', 'ASTRAL', 'astral', NULL, 'Casa e Construção', 'Construção e Reforma', 'Desinsetização, Desratização, Descupinização, Controle de mosquitos, Antimofo, Limpeza e Desinfecção de caixas d’água, Saneamento vegetal, Manejo de fauna silvestre Sanitização de Ambientes.', 1996, 1997, '[\"https://www.youtube.com/watch?v=bHRtKf4rt5g\"]', '2026-04-01 02:00:08.811', '2025-08-05 22:20:28.494', 807, NULL, 1, 1983, 'A Astral atua há mais de 40 anos no mercado de controle de pragas e vetores urbanos e é LÍDER na América Latina.\n \nDurante a sua trajetória, se multiplicou em tamanho, investiu em tecnologia avançada, mas manteve a mesma qualidade no serviço e no atendimento que fez da empresa a líder do setor em toda a América Latina, especializada em contratos de médio e de grande porte.\n \nNossa trajetória de sucesso teve início em 1983, na cidade mineira de Uberlândia. Hoje, a Rede Astral está distribuída em 20 estados brasileiros, localizados em cidades do norte ao sul do país, ultrapassando a marca das 43 unidades fraqueadas.\n \nAlém disso, possui mais de 10.000 pontos atingidos em contratos, 21 Selos de Excelência em Franchising e lucro líquido médio de 30%.\n \nSeu processo de Expansão vai Brasil a fora, a marca é licenciada para atuar na Europa e está em processo de licenciamento para atuar nos EUA.\n \nA franquia Astral é uma empresa que se reinventa e oferece aos clientes novas soluções para atender as exigências do mercado.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c8875254-593a-4809-93d7-fa7bf9d8ffc3.png', 38, NULL, NULL, '2026-03-09 01:40:24.153', 'https://franquias.portaldofranchising.com.br/franquia-astral-limpeza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '237000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771000lfeh0soi7gv38c', 'CADILE\'S ESPORTES', 'cadile-s-esportes', NULL, 'Moda', 'Calçados', 'A Cadile\'s Esportes atua no segmento de varejo esportivo, com foco em experiência e nas melhores marcas de esporte do mundo, com Nike, Adidas, Puma, Vans e muito outras marcas desejo! Um show de loja!', 2023, 2023, '[\"https://www.youtube.com/watch?v=vZMNmDGtSlc\",\"https://www.youtube.com/watch?v=8921L9DCc-4\"]', '2026-04-01 02:00:08.824', '2025-08-05 22:20:28.500', 808, NULL, 1, 1996, 'A Cadile\'s é uma empresa fundada em 1996 na cidade de Ijuí - RS, especializada na venda de calçados e artigos esportivos, inicialmente suas operações eram todas dedicadas à sapataria, onde vendia-se calçados fashion, social e esportes. Entretanto, desde sua criação, a empresa tem se dedicado a oferecer produtos de qualidade e um atendimento diferenciado aos seus clientes. Porém, após uma viagem para a NRF em 2018, a maior feira de varejo do mundo em Nova York (EUA), foi criado um novo formato de loja, a Cadile’s Esportes, inovadora e disruptiva, eficiente e rentável, no modelo ideal de arquitetura, design, combinações, marcas e espaços físicos. Em novembro do mesmo ano é inaugurada um show de loja, com slogan Movimento é Vida. Após um ano de testes e projeto piloto, houve uma boa resposta do mercado e da metodologia aplicada ao negócio, fazendo com que todas lojas Cadile’s mudassem de perfil Cadile’s Calçados (Sapatarias - Próprias) para Cadile’s Esportes, uma transformação empresarial completa.   A trajetória ascendente, com a inauguração contínua de lojas, levou a Cadile’s a mudar seu modelo de expansão, optando em 2023 pelo franchising. Com o apoio das maiores marcas do mundo do esporte, como Nike, Adidas, Puma, Vans, Asics, Fila, New Balance e outras, todas são homologadas para que os franqueados possam oferecer produtos de desejo e com alto ticket médio. PRINCIPAIS VANTAGENS COMPETITIVAS Atende todas idades e classes sociais, praticantes de esporte, pessoas que gostam de usar as melhores marcas do mundo e que valorizam a qualidade dos produtos. Mix completo com calçados, vestuário e acessórios para as categorias: Corrida, Casual, Treino, Futebol, Basquete, Volei e outras! As melhores negociações do mercado com as marcas (Markup elevado) e acesso à segmentação de produtos especiais. Prateleira Infinita com estoque de todas lojas integrados e também estoque de algumas marcas. Os melhores sistemas da atualidade. Hoje, a Cadile’s Esportes é reconhecida como uma das melhores lojas de esporte do Sul do Brasil, com pontos de vendas diferenciados que dão visibilidade aos produtos mais desejados pelos clientes.  Uma marca em crescimento e que está inovando o segmento de esportes, o modelo Cadile’s Esportes é projetado para cidades acima de 60 mil habitantes. Possuindo hoje lojas de rua e Shopping Center. Contando com lojas de 150 m² a 250 m², o modelo envolve muita inovação e tecnologia, tendo como principais objetivos a maximização das vendas, rentabilidade da operação e a experiência do cliente. O segmento de esportes apresenta diversos desafios e a Cadile’s Esportes foi projetada para solucionar, são eles: Acesso às melhores marcas e segmentações de produtos Alto ticket médio + produto de desejo = Otimização da equipe Maior rentabilidade para o franqueado Encantamento: Atendimento ágil e personalizado para o cliente', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f184ee9d-d8c2-4319-9021-83cfe11c4eb6.png', 13, NULL, NULL, '2026-03-09 01:41:08.482', 'https://franquias.portaldofranchising.com.br/franquia-cadiles-esportes/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1a9f7cb2-3e99-4d20-9bbb-afabd9f762e7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/db9a1404-147c-4d1f-a82f-95049bd10dc9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9808238a-12b4-453f-85c5-f386bdd141b4.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '569000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771500lgeh0s0zkz01qw', 'CHOCOLATE LUGANO', 'chocolate-lugano', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Contempla um mix de negócios, associando a tradicional loja de chocolates artesanais à uma cafeteria e espaço para a venda de presentes e souvenirs, proporcionando estímulo ao aumento do ticket médio.', 2018, 2019, NULL, '2026-04-01 02:00:08.834', '2025-08-05 22:20:28.505', 809, NULL, 1, 1976, 'Desde 1976, transformamos qualidade e carinho na mais deliciosa experiência dos chocolates de Gramado. Com mais de 150 franquias, a Lugano está presente em todos os estados do Brasil, sendo assim reconhecida pela sua excelência em chocolates finos. Produzimos mensalmente mais de 100 toneladas de chocolate, com uma enorme variedade de barras de chocolate, trufas, bombons, kits para presente e uma linha completa de chocolates zero açúcar e sem lactose. Nossos modelos de franquias, além da clássica e completa linha de chocolates, também oferece um completo cardápio de cafeteria, com: cafés clássicos e autoriais, chocolates quentes, lanches salgados e sobremesas com muito chocolate.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8a5640f3-9a79-4e99-ad95-1363450417b4.png', 133, NULL, NULL, '2025-07-10 11:39:41.000', 'https://franquias.portaldofranchising.com.br/franquia-chocolate-lugano-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771a00lheh0s8i0ymns9', 'BILLY THE GRILL', 'billy-the-grill', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Billy é a marca que conquista as praças de alimentação com o cheirinho de churrasco. O Churrasco na Pedra é o carro-chefe do cardápio, que traz também opções variadas de pratos e acompanhamentos.', 2010, 2012, NULL, '2026-04-01 02:00:08.846', '2025-08-05 22:20:28.511', 810, NULL, 1, 2010, 'O Xerife da Praça de Alimentação \nUma história digna de heróis do velho oeste \nO churrasco na pedra logo fez sucesso em 2010, quando nasceu a primeira loja Billy The Grill em São Gonçalo, segundo município mais populoso do Estado do Rio de Janeiro. Mas bem antes disso, iniciamos nossa trajetória empreendedora através de uma rede de franquias no segmento de alimentação. Esta experiência foi o alicerce para nossa história de sucesso e de superação.  \nEngenheiros de formação, Luiz Felipe Costa e Luiz Sergio Costa, irmãos empreendedores, viram na franquia a oportunidade de construir a própria trajetória e desenvolver suas carreiras com sucesso. Buscaram no franchising o suporte necessário que compensaria sua pouca experiência no segmento. Infelizmente não fizeram uma escolha acertada em seu parceiro de negócio. Não houve suporte ou treinamento e, depois de longos meses sem apoio, quase viram todo o investimento da família se perder. \nNo entanto, herdaram do pai, Seu Sérgio, a garra e a coragem de seguir em seu propósito e decidiram criar seu próprio plano de negócio e marca. Arregaçaram as mangas, foram para a cozinha, buscaram as melhores receitas da família, conversaram com clientes da praça de alimentação, voltaram para a sala de aula e pediram muita ajuda a quem surgia. Tudo para fazer o negócio gerar resultado. O plano de crescimento desenhado em um guardanapo depois de quase 10 anos parece uma trajetória épica.  \nCom um tempero único e refeições completas, o Billy The Grill é a pedida ideal para se sentir mais próximo de casa. Nossa comida é fresca e de verdade e, nossa apresentação e serviço são dignos dos heróis do faroeste. Nossos pratos são preparados diariamente por cozinheiros, com carinho e dedicação. E nosso churrasco na pedra faz a diferença no dia a dia, levando uma pitada de emoção na correria da semana. É uma experiência para nossos clientes diariamente carregar suas pedras cobertas com belos cortes de carne, fritas e outros complementos. É incrível sentir aquele cheirinho de churrasco no meio da praça de alimentação! \nO Billy é para aqueles que querem se conectar com um lugar de cuidado, com sabores únicos e ao mesmo tempo familiares. Seja um amigo, um familiar ou um desconhecido: nós pensamos que todos ao nosso redor merece respeito e carinho. Acreditamos que ao ajudar, somos também ajudados e, por isso, damos sempre o nosso melhor. \nSomos uma família. Fazemos parte de um time que acredita em relações verdadeiras e estamos juntos no desenvolvimento e aprendizado de cada um. Queremos que as pessoas se sintam bem quando provam da nossa comida caseira, que os sabores e temperos os levem para um lugar de afeto e memória.  Por isso, bem-vindo à Casa do Churrasco na Pedra. Bem-vindo ao Billy The Grill.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/55c9eba2-7628-4429-9139-b91bad663e11.jpg', 52, NULL, NULL, '2026-03-09 01:42:54.038', 'https://franquias.portaldofranchising.com.br/franquia-billy-the-grill-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '750000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771g00lieh0ssipdrtms', 'CAFÉ CONCEITO', 'cafe-conceito', NULL, 'Alimentação', 'Bares e Restaurantes', 'Cafeteria especializada em bebidas à base de café e pequenos lanches para o dia a dia. Cardápio de bebidas com mais de 100 combinações diferentes e diversas opções de comidinhas doces e salgadas.', 2022, 2023, NULL, '2026-04-01 02:00:08.857', '2025-08-05 22:20:28.516', 811, NULL, 1, 2017, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6a6a00c4-0193-4500-8ccd-f51684e3b7e8.jpg', 26, NULL, NULL, '2026-03-09 01:44:22.088', 'https://franquias.portaldofranchising.com.br/franquia-cafe-conceito/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '178900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771l00ljeh0svkov51d1', 'CHOE\'S ORIENTAL GOURMET', 'choe-s-oriental-gourmet', NULL, 'Alimentação', 'Bares e Restaurantes', 'Restaurante Self Service de culinária Oriental', 2025, 2025, NULL, '2026-04-01 02:00:08.881', '2025-08-05 22:20:28.522', 812, NULL, 1, 2011, '', NULL, 'ESPÍRITO SANTO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c77ff7d2-adaf-4e3d-9299-55d4d67d3614.png', NULL, NULL, NULL, '2026-03-09 01:44:44.603', 'https://franquias.portaldofranchising.com.br/franquia-choes-oriental-gourmet/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771q00lkeh0sew9c1thr', 'BOTOESTHETIC HARMONIZAÇÃO FACIAL', 'botoesthetic-harmonizacao-facial', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Invista na franquia BotoEsthetic! Você terá acesso a um modelo de negócio consolidado e todo o suporte necessário para se tornar um empreendedor de sucesso no mercado que mais cresce no país!', 2021, 2023, NULL, '2026-04-01 02:00:08.895', '2025-08-05 22:20:28.527', 813, NULL, 1, 2019, '', NULL, 'PARAÍBA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/902e0f75-3453-4a9b-b521-0c3a461b7973.png', 19, NULL, NULL, '2026-03-09 01:45:03.237', 'https://franquias.portaldofranchising.com.br/franquia-botoesthetic-harmonizacao-facial-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771w00lleh0sw5psjnxk', 'LIVIA PÃES', 'livia-paes', NULL, 'Alimentação', 'PADARIAS', 'Mini padaria é um ramo que não tem crise, produtos consumidos por todos. Nossos pães e doces são de excelente qualidade. Atividade fácil de exercer, poucos colaboradores e lucros satisfatórios.', 2022, 2023, NULL, '2026-04-01 02:00:08.905', '2025-08-05 22:20:28.532', 814, NULL, 1, 2009, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1961d9da-3e32-41d1-807b-2e4859924963.jpg', 5, NULL, NULL, '2025-07-10 09:53:54.000', 'https://franquias.portaldofranchising.com.br/franquia-livia-paes-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza772100lmeh0s0cd3s58q', 'BIOMA SALON', 'bioma-salon', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Hair Spa focado em cabelos saudáveis através de um ecossistema de beleza regenerativa com propósito de consolidar uma comunidade capaz de mudar a indústria em busca de um futuro mais sustentável.', 2023, 2024, NULL, '2026-04-01 02:00:08.915', '2025-08-05 22:20:28.538', 815, NULL, 1, 1987, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/39e1b5ca-d0d5-441d-86a6-19f29af6825d.png', NULL, NULL, NULL, '2026-03-09 01:45:50.750', 'https://franquias.portaldofranchising.com.br/franquia-bioma-salon/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '440000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza772600lneh0syq1ajbel', 'GRID TIE SOLAR', 'grid-tie-solar', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Na Grid Tie Solar nós ajudamos os clientes a produzir uma energia limpa e sustentável a um custo inferior ao que pagariam a distribuidora por uma energia poluente.', 2021, 2022, '[\"https://www.youtube.com/watch?v=sG8pTlXnUOc\",\"https://www.youtube.com/watch?v=iJH_RdhWuSg\",\"https://www.youtube.com/watch?v=gxg2094e6p4\",\"https://www.youtube.com/watch?v=Fgy6rVOTYAg\"]', '2026-04-01 02:00:08.925', '2025-08-05 22:20:28.543', 816, NULL, 1, 2016, 'A Grid Tie Solar, é um modelo de negócio no ramo de energia fotovoltaica, criado nos mais altos padrões, que oferece aos seus clientes serviços de alta qualidade com preços acessíveis, empregando até então as melhores tecnologias disponíveis no mercado. \nO objetivo é contribuir na produção de energia limpa para estabelecimentos comerciais, industriais e residências a um custo inferior ao que pagariam à concessionária por uma energia poluente. \nForam desenvolvidos protocolos de atendimento e realização de procedimentos para que o cliente tenha a melhor e mais agradável experiência, com segurança, conforto e bem-estar. \nNosso compromisso é com a excelência no desenvolvimento e instalação de projetos para captação de energia solar, assegurando qualidade em todas as unidades, de maneira uniforme. \nChegamos para deixar nossa marca no mercado de energia solar fotovoltaica, pois somos diferentes, únicos: Construímos relações de confiança; Entregamos alto valor com preços competitivos; Promovemos qualidade de vida e bem-estar. Operando desde 2016 com unidade própria, a partir de 2021 a Grid Tie Solar adotou o modelo de franquia empresarial como estratégia de expansão do negócio.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/839884a4-3300-4bd1-b6f3-e14c3acce900.jpg', 12, NULL, NULL, '2026-03-09 01:46:13.721', 'https://franquias.portaldofranchising.com.br/franquia-grid-tie-solar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza772b00loeh0se3uonrfo', 'BREAD KING', 'bread-king', NULL, 'Alimentação', 'PADARIAS', 'Padaria Congelada', 2022, 2023, NULL, '2026-04-01 02:00:08.944', '2025-08-05 22:20:28.548', 817, NULL, 1, 2022, 'Inovação, sendo 1º modelo de padaria congelada do Brasil;\n\t  Diferentes modelos de negócio. Desde lojas convencionais até projetos em containers. \n\tAs lojas Bread King possuem formatos específicos para cidades de todos os tamanhos;\n\t  Fábrica própria (situada em SC), garantindo excelência no padrão de qualidade e segurança no fornecimento aos franqueados;\n\t  Logística de entrega 100% própria, garantindo qualidade e pontualidade;\n\t  Programa de fidelidade implantado através do App do Clube Bread King;\n\t  Baixíssimo custo operacional, operação que requer pouca mão de obra.\n\t  Mix com mais de 150 produtos exclusivos;', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/688864d8-ad4a-4102-8527-64001394b6e1.png', 36, NULL, NULL, '2026-03-09 01:47:02.141', 'https://franquias.portaldofranchising.com.br/franquia-bread-king/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '750000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
