INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza772n00lqeh0sqjp26gcl', 'BEAN GO! Fast Real Food', 'bean-go-fast-real-food', NULL, 'Alimentação', 'Bares e Restaurantes', 'Venda de refeições no sistema TO GO, servidas em copos de papel. Em especial, feijoada e produtos com feijão e pulses. Sistema sem utilização de cozinha ou cocção no local.', 2022, 2023, NULL, '2026-04-01 02:00:08.980', '2025-08-05 22:20:28.560', 819, NULL, 1, 2022, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/44e2a0da-28f8-4d10-a9f6-35f1b3327a05.png', 1, NULL, NULL, '2026-03-09 01:48:02.644', 'https://franquias.portaldofranchising.com.br/franquia-bean-go-fast-real-food/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza772t00lreh0s9i5u3rk5', 'LYPEDEPYL', 'lypedepyl', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Rede de clínicas de depilação avançada a laser com foco no atendimento humanizado, protocolos exclusivos, com uso de alta tecnologia associada à dermocosméticos garantindo resultados de excelência.', 2022, 2023, '[\"https://www.youtube.com/watch?v=20WRa5urPqo\",\"https://www.youtube.com/watch?v=XDDpzbJOXuU\"]', '2026-04-01 02:00:08.990', '2025-08-05 22:20:28.566', 820, NULL, 1, 2022, 'A LypeDepyl é uma Rede pioneira de franquias de depilação avançada a laser que está chegando em todo o Brasil para mostrar um jeito inovador de cuidarmos da sua pele e fazer escolhas seguras, sem culpa e com liberdade! \nNascemos do desejo de oferecer um tratamento completo, atuando além da depilação a laser. \nTrabalhamos e prezamos por um atendimento humanizado, e especializado, que foca na sua individualidade e opção de escolha. \nNo nosso protocolo de tratamento cuidamos da pele em todos os momentos, na pré-depilação, durante e após a sessão. \nSomos pioneiros em oferecer uma linha de dermocosméticos com componentes naturais e sustentáveis para uso profissional e home care.  – Meu objetivo com a LypeDepyl, foi trazer o que a tecnologia tem de melhor, com uma linha exclusiva de dermocosméticos e, ter em clínica, profissionais qualificadas e preparadas para atender cada cliente de maneira diferenciada, proporcionando resultados efetivos e bem-estar durante os tratamentos. Chegamos para nos diferenciar no segmento e mostrar que depilar pode ser uma experiência para quem preza por autocuidado e liberdade – explica a fundadora da Rede - Leydejota', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/89935eaf-eeb4-4f94-97ed-1df5361c3a80.svg', 34, NULL, NULL, '2026-03-09 01:48:31.690', 'https://franquias.portaldofranchising.com.br/franquia-lypedepyl/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '309000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza773300lseh0sp2sbwesm', 'TEA SHOP', 'tea-shop', NULL, 'Alimentação', 'Mercados e Distribuição', 'Rede espanhola de lojas de chás gourmet e acessórios', 1996, 2016, '[\"https://www.youtube.com/watch?v=-Rp_9eRgLXI\",\"https://www.youtube.com/watch?v=K7QyVBjk7b0\",\"https://www.youtube.com/watch?v=GNfgEv3JThE\"]', '2026-04-01 02:00:09.000', '2025-08-05 22:20:28.575', 821, NULL, 1, 1990, 'Há mais de 10 anos criando raízes no Brasil, a Tea Shop oferece muito mais do que chás premium e acessórios de qualidade. Oferecemos experiências multissensoriais que proporcionam bem-estar, saúde e sabor para quem aprecia os benefícios dessa bebida milenar. Original da Espanha, contamos com a expertise e os selos de qualidade de uma marca que atua no mercado dos chás e infusões há 30 anos e está presente em cinco países. No Brasil, contamos com mais de 40 operações, um e-commerce e o Tea Club, nosso clube de assinatura de chás. Nossas mais de 130 mesclas de chás e infusões são naturais e produzidas artesanalmente e contamos também com alimentos especiais que têm o chá como ingrediente. A Tea Shop chegou ao país em maio de 2013 via Porto Alegre. A ideia empreendedora partiu do CEO Michel Bitencourt, que teve a ideia de trazer a marca para o Brasil durante um curso de MBA em Barcelona. Foi lá que conheceu a matriz e o modelo de negócio da rede, hoje com mais de 100 lojas em quatro países – além da Espanha e do Brasil, está presente na Itália e Portugal. DIFERENCIAIS PRESENÇA INTERNACIONAL Original da Espanha, a Tea Shop já criou raízes no Brasil, e também está presente na Argentina, Itália e Portugal. MERCADO CRESCENTE Iniciando com apenas uma loja em Porto Alegre, hoje somos mais de 40 operações de sucesso distribuídas pelo Brasil. ATENDIMENTO ESPECIALIZADO Nossa equipe de profissionais é altamente qualificada, especialista em orientar e encantar sobre o apaixonante mundo dos chás. LOJAS APAIXONANTES Nossas lojas oferecem uma experiência multissensorial única, em um ambiente agradável e sofisticado. No Tea Room (sala de chás), os clientes podem desfrutar de um delicioso momento do chá. COMPROMENTIMENTO COM NOSSA ESSÊNCIA Acreditamos que chás de alta qualidade são capazes de proporcionar mais sabor, bem-estar e saúde no dia a dia das pessoas. Além de ser uma bebida versátil, que pode ser preparada de diversas maneiras. VOCÊ PODE TER TRÊS (4) NEGÓCIOS EM (1) Loja Alimentação Corporativo Carrinho para venda (Take Away) e, divulgação da sua marca', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/59ac1bd7-e0d7-490b-87fe-51ebbfcac845.png', 34, NULL, NULL, '2026-03-09 01:49:22.898', 'https://franquias.portaldofranchising.com.br/franquia-tea-shop/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '150000', NULL, NULL, NULL, '45000', NULL, '6', '2', '290000', '10000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza773c00lteh0s3ffcod61', 'AÇAILAND', 'acailand', NULL, 'Alimentação', 'Bares e Restaurantes', 'Self-Service três sabores de açaí. Com mais de trinta acompanhamentos, frutas e caldas.', 2018, 2022, NULL, '2026-04-01 02:00:09.012', '2025-08-05 22:20:28.584', 822, NULL, 1, 2018, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/85cb83e9-fa3f-4146-9732-7d1e6e6e22e5.jpg', 11, NULL, NULL, '2026-03-09 01:50:30.031', 'https://franquias.portaldofranchising.com.br/franquia-acailand/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza773o00lueh0stp58zxt6', 'BROWBAR - BAR DE SOBRANCELHA', 'browbar-bar-de-sobrancelha', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Especializado em Design de Sobrancelhas, depilação facial e serviços extras em esmalteria e escovaria expressa.', 2015, 2016, '[\"https://www.youtube.com/watch?v=8yI6JdgJsKs\"]', '2026-04-01 02:00:09.023', '2025-08-05 22:20:28.596', 823, NULL, 1, 2013, 'O conceito da franquia Browbar surgiu nas grandes lojas de departamendo de Londres e conquistou as principais metrópoles do mundo. Adaptada às necessidades do mercado brasileiro, surgiu a Browbar, uma beauty store especializada nas artes ds sobrancelhas. \nHoje a Browbar é uma rede de franquias de serviços expressos de beleza, que oferece além do Bar de Sobrancelhas, outras marcas como Nails, Dry e Depilway, proporcionando mais opções aos clientes e gerando mais receita para o negócio.', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c79ee24a-59db-4787-86ee-64e45ffc130f.jpg', 45, NULL, NULL, '2026-03-09 01:50:53.047', 'https://franquias.portaldofranchising.com.br/franquia-browbar-bar-de-sobrancelha-beleza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '175000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza773v00lveh0sbeenkc64', 'BELLA CAPRI PIZZARIA', 'bella-capri-pizzaria', NULL, 'Alimentação', 'Bares e Restaurantes', 'Comércio de Pizzas', 2007, 2007, '[\"https://www.youtube.com/watch?v=EmfMJdS9HT8\",\"https://www.youtube.com/watch?v=0raduMX5SEo\",\"https://www.youtube.com/watch?v=0DLOy8OQQ50\"]', '2026-04-01 02:00:09.035', '2025-08-05 22:20:28.603', 824, NULL, 1, 1998, 'A franquia Bella Capri foi fundada em 1998 em Mirassol (SP) pelo irmão de Guto, Nivaldo Covizzi. Os dois são filhos de Nivaldo Covizzi, falecido em 2022. A família comandou um negócio de doces na região de São José do Rio Preto (SP) antes da criação da pizzaria. Até a chegada de Guto, em 2003, a franquia Bella Capri se desenvolveu como uma empresa familiar. MERCADO CRESCE, MESMO EM MOMENTOS DE CRISE! O Segmento Fatura mais de 60bi ao ano, e mais de 60 milhões ao dia no Brasil, somos o segundo maior consumidor de pizzas do mundo, é uma paixão nacional. Entre os nossos diferenciais estão: CENTRAL DE DISTRIBUIÇAÕ E LOGISTICA DE ABASTECIMENTO DAS LOJAS: Temos mais de 4.000m² de área, com mais de 2.000m² de camaras frias e estoque seco, entregamos 99% dos insumos utilizados no preparo das pizzas. CENTRAL DE ATENDIMENTO E RELACIONAMENTO: Nós cuidamos da venda das pizzas de ponta a ponta para o nosso franqeuado, todos os pedidos da rede são centralizados na nossa central. APLICATIVO PRÓPRIO: Mais de 60% das vendas da rede, tem acontecido dentro do nosso próprio aplicativo. Diferenciais que tonam a nossaa operação; ENXUTA, FACIL DE OPERAR E ALTAMENTE LUCRATIVA.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/dc41ee5f-6130-4b4d-b746-bd0106f104c8.png', 53, NULL, NULL, '2026-03-09 01:51:30.679', 'https://franquias.portaldofranchising.com.br/franquia-bella-capri-pizzaria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '435481.28', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
