INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza774a00lxeh0sp7290f00', 'CLEANNOW', 'cleannow', NULL, 'Limpeza e Conservação', 'Serviços de Limpeza', 'Formalização do serviço de faxina com fornecimento de produtos e equipamentos. Especializada em ambientes comerciais de pequeno e médio porte.', 2015, 2017, NULL, '2026-04-01 02:00:09.057', '2025-08-05 22:20:28.618', 826, NULL, 1, 2014, '', NULL, 'SANTA CATARINA', 1, NULL, 10, NULL, NULL, '2026-03-09 01:52:45.994', 'https://franquias.portaldofranchising.com.br/franquia-cleannow/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '10000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza774h00lyeh0s8sk9z9yh', 'C\'CLEAN LAVANDERIA SELF-SERVICE', 'c-clean-lavanderia-self-service', NULL, 'Limpeza e Conservação', 'Lavanderia', 'Lavanderia Self Service multi segmento Lavanderia auto-atendimento', 2021, 2021, '[\"https://www.youtube.com/watch?v=xKPdsAxAh2Q\",\"https://www.youtube.com/watch?v=S_36f957Hao\",\"https://www.youtube.com/watch?v=FmyIwuHxJlU\",\"https://www.youtube.com/watch?v=8o7WPTpJkic\"]', '2026-04-01 02:00:09.069', '2025-08-05 22:20:28.625', 827, NULL, 1, 2021, 'C’Clean é a franquia mais inovadora do segmento de Lavanderias Self Service.  \nA nossa obsessão é atender cada vez melhor as necessidades dos brasileiros na lavagem e secagem de roupas através de integração de tecnologia. \nA inovação faz parte do nosso DNA. \nA C’Clean Lavanderia Self Service está sendo pioneira do segmento de lavanderia self service no Brasil em trazer uma operação com as melhores maquinas industriais no mundo, acompanhado por um sabão e amaciante industrial de alta performance 3 em 1 (detergente, branqueador neutro, amaciante), tudo operacionalizado por um App customizado e exclusivo. \nAtravés da tecnologia, o modelo de gestão da franquia é ágil e efetivo, podendo ser conduzido à distância. \nO acompanhamento dos indicadores de desempenho da loja se faz pelo back office do App, podendo também seguir ao vivo a utilização das maquinas pelos usuários. \nO modelo de negocio possibilita também uma possível expansão da loja através de uma configuração evolutiva do layout, caso seja de interesse do(a) franqueado(a).', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0c85d80f-587f-43ab-a0eb-02bdc20a2458.jpg', 31, NULL, NULL, '2026-03-09 01:53:10.640', 'https://franquias.portaldofranchising.com.br/franquia-c-clean/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza774t00lzeh0sujs7v8xc', 'CÓDIGO GIRLS', 'codigo-girls', NULL, 'Moda', 'Vestuários', 'Moda Feminina Teen', 2005, 2009, '[\"https://www.youtube.com/watch?v=5ZkufzXd8A4\",\"https://www.youtube.com/watch?v=J_LSs24bImE\"]', '2026-04-01 02:00:09.079', '2025-08-05 22:20:28.638', 828, NULL, 1, 1995, 'Atuando há mais de 20 anos no seguimento de moda e varejo, a “Código Girls” conta com mais de 65 lojas, sendo a maioria em Shopping Centers. É um empreendimento voltado para o mercado Teen feminino, com mix de produtos diferenciados entre vestuário, calçados, acessórios, cosméticos e perfumes, seguindo as tendências  de moda com inovação, contamos  com roupas descontraídas que agregam conforto, qualidade, beleza e preço justo. Com fábrica de 3.000 m2 instalada em Guarulhos (SP), a Franquia Código Girls é a marca das garotas com identidade própria, antenadas com a moda e que se preocupam com o que vestem. A Código Girls não vende para multimarcas,  o abastecimento das lojas é semanal e com peças exclusivas. Contamos com equipe de profissionais qualificados para prestar suporte total ao franqueado. Estamos estruturados e  em expansão em ritmo acelerado para todo o Brasil.', NULL, 'SÃO PAULO', 1, NULL, 28, NULL, NULL, '2026-03-09 01:53:54.410', 'https://franquias.portaldofranchising.com.br/franquia-codigo-girls-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '370000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza775500m0eh0s2petkfie', 'FERRACINI', 'ferracini', NULL, 'Moda', 'CALÇADOS', 'Calçados Masculinos', 2024, 2025, NULL, '2026-04-01 02:00:09.089', '2025-08-05 22:20:28.650', 829, NULL, 1, 1984, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d38f391b-de1d-4358-8842-6cf3360c098b.png', 10, NULL, NULL, '2025-08-29 11:08:38.000', 'https://franquias.portaldofranchising.com.br/franquia-ferracini/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza775c00m1eh0ss88syvuu', 'CLUBE 04', 'clube-04', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'O Clube04 Pet Store revolucionou a maneira de cuidar dos pets, tornando-se referência nacional em bem-estar, carinho e qualidade. Centro de estética, produtos diferenciados e cuidados veterinários.', 2020, 2023, '[\"https://www.youtube.com/watch?v=PvwipJ4JOIg\"]', '2026-04-01 02:00:09.098', '2025-08-05 22:20:28.656', 830, NULL, 1, 2017, 'Clube04 Pet Store: Transformando a Relação entre Humanos e seus Pets No Clube04 Pet Store, acreditamos que a relação entre os humanos e seus doguinhos pode ser transformada através de uma comunicação excelente e muito carinho. Nosso objetivo não é ser apenas mais um pet shop, mas sim criar experiências únicas que façam com que cada pet se sinta amado e compreendido por todos os membros do Clube04. Seja durante o banho ou ao experimentar nossos produtos cuidadosamente selecionados, buscamos proporcionar momentos e lembranças positivas para os nossos doguinhos. Orgulhamo-nos de ser a faísca que acende um movimento em todo o Brasil, inspirando pet shops e pais de pets a trilhar uma jornada de amor e cuidado. Clube04 Pet Store: Uma Revolução no Cuidado com os Pets Somos uma referência nacional no mercado pet e estamos revolucionando a maneira de cuidar dos nossos companheiros de quatro patas. Oferecemos um serviço diferenciado para garantir o bem-estar dos pets, incluindo: O Melhor Banho do Mundo com cromoterapia, feromonioterapia, música relaxante, secagem no colo, massagem relaxante e sem o uso de gaiolas. Centro de estética pet com produtos exclusivos e cuidados veterinários de alta qualidade. Números que Refletem Nosso Sucesso: Faturamento médio anual da franquia: R$ 1,2 milhão. Rentabilidade: superior a 20%. O mercado pet é um dos setores que mais cresce no Brasil, e o Clube04 Pet Store representa uma excelente oportunidade para quem deseja investir nesse segmento em plena ascensão. Suporte de Excelência para os Franqueados A franqueadora oferece suporte total para os franqueados, garantindo o sucesso da operação através de duas plataformas estratégicas: Universidade Corporativa Presencial: Um centro de treinamento de alto nível, com um auditório moderno e climatizado para até 150 pessoas, oferecendo uma infraestrutura completa, incluindo salas de reunião, espaço exclusivo para franqueados e estacionamento próprio. Universidade Corporativa EAD: Plataforma online com materiais estratégicos essenciais para a operação da franquia, como manuais, peças personalizáveis para ações comerciais, campanhas de marketing, vídeos de treinamentos e muito mais! Liderança e Credibilidade O Clube04 Pet Store é conduzido por grandes nomes do mercado: Sidney Kalaes – Presidente do Grupo Kalaes, holding multissetorial de franquias, com mais de 31 anos de experiência no setor. Líder e fundador de diversas franqueadoras de sucesso. Ana Paula Shinzaki – Idealizadora e fundadora do Clube04, com formação em Marketing pela USP e mais de 8 anos de experiência em marketing criativo e inteligência de mercado. Fábio Aydar – Fundador do Clube04, formado em Marketing pela USP, com experiência em empresas como Natura e Hypera, atuando em planejamento estratégico e demanda. Venha fazer parte dessa rede de sucesso!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/72f2c449-8a58-42e1-8bb8-66f4ecf179d4.jpeg', 27, NULL, NULL, '2026-03-09 01:54:56.558', 'https://franquias.portaldofranchising.com.br/franquia-clube-04/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '282291', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
