INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza775s00m4eh0smiftdhg1', 'DISAPAR', 'disapar', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Comércio varejista e atacadista de Ferramentas, Equipamentos, Soldas, Abrasivos, EPIs, Parafusos, Tintas Automotivas e Industriais, Utilidades e Elétrica.', 2020, 2020, '[\"https://www.youtube.com/watch?v=7sdVB9_zADQ\",\"https://www.youtube.com/watch?v=azg6QLMRAXc\",\"https://www.youtube.com/watch?v=CmVJRFZ0lD4\",\"https://www.youtube.com/watch?v=_d7P694ULBo\",\"https://www.youtube.com/watch?v=lxc8HORUDAo\"]', '2026-04-01 02:00:09.127', '2025-08-05 22:20:28.672', 833, NULL, 1, 1990, 'Uma empresa fundada em 1990, no Oeste de Santa Catarina! Surgiu com a necessidade regional em produtos de alta qualidade linha de tintas automotivas, equipamentos de proteção individual (EPIs), ferramentas e parafusos. Ao longo dos anos, fomos ampliando nossa linha de produtos e hoje fornecemos, também, máquinas e equipamentos, soldas e abrasivos, produtos elétricos e uma linha de bazar. Ao todo, são mais de 40 mil itens oferecidos em nossas lojas e site, que são constantemente atualizados.\n  Nossa equipe hoje conta com 60 colaboradores diretos, nas cidades Chapecó-SC e Joaçaba-SC e mais de 20 representantes que atuam nos três estados do sul. Todos alinhados com a nossa proposta de distribuir tecnologia em suprimentos industriais, no comércio atacadista e varejista, com mercadorias nacionais e importadas.\n  Pensando no compromisso que temos em distribuir produtos de qualidade para nossa cidade e região, buscamos sempre os melhores fornecedores. Prezamos por manter produtos de qualidade, que atendam às necessidades dos clientes, com preços justos.  Temos uma equipe preparada sempre participando de treinamentos técnicos sobre os produtos, para que possam oferecer, além de informações primárias, recomendações sobre o uso correto dos produtos, para que o cliente possa ter mais produtividade e segurança.\n   A assistência técnica especializada também é um diferencial da Disapar, e temos uma equipe de técnicos nas linhas de EPIs, tintas automotivas, abrasivos e máquinas de solda preparada para ir até o cliente e orientar o melhor uso do produto. O ponto comercial da Disapar é outro diferencial, porque é de fácil localização, pensado estrategicamente para facilitar a vida do cliente que vem até a loja. A logística de transportadoras também é facilitada por conta desse fator, e podemos enviar nossos produtos para todo o Brasil.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8e69b56a-f2d1-44d4-9334-6009b922fa35.jpg', 7, NULL, NULL, '2026-03-09 01:57:01.708', 'https://franquias.portaldofranchising.com.br/franquia-disapar-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '589212', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
