INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza776l00m9eh0shid9ohtd', 'DIPZ - BATATA FRITA EM CONE', 'dipz-batata-frita-em-cone', NULL, 'Alimentação', 'Bares e Restaurantes', 'Operação modelo grab and go de venda de batata-frita no cone e acompanhamentos. Temos 3 modelos de negócios: lojas, quiosques e express (lojas em terminais urbanos)', 2022, 2023, '[\"https://www.youtube.com/watch?v=0XSt_oFtHP8\"]', '2026-04-01 02:00:09.177', '2025-08-05 22:20:28.701', 838, NULL, 1, 2012, 'A Dipz surgiu no Brasil, em 2012, com o conceito grab and go, compre a comida e continue sua caminhada com ela na mão. Para isso, desenvolvemos uma série de inovações sempre pensando na praticidade do nosso consumidor. A primeira delas foi a criação de uma embalagem única para servir a deliciosa batata e seus molhos de forma prática. Ela foi projetada e patenteada pela Dipz como fórmula exclusiva da marca, o que impede a reprodução sem prévia autorização. Outra inovação importante foi a utilização de equipamentos específicos para possibilitar a instalação de unidades Dipz em quiosques, tornando ainda mais fácil que nosso cliente nos encontre nos shopping centers. De 2012 para cá já são 22 unidades no Estado de São Paulo, dentre Lojas de Shoppings, Quiosques e Lojas Express nos terminais. Além disso, entramos 2025 com foco em expansão. Hoje já temos 3 franquias localizadas no Shopping Campo Limpo, Terminal Rodoviário da Lapa e Shopping Litoral Plaza na Praia Grande.   Ainda surfando na jornada digital do nosso consumidor, estamos implantando os tótens de autoatendimento e os pedidos de retirada em loja, com o pagamento pelo APP Dipz. Nossa proposta é continuar a trilhar um caminho de crescimento sólido, preocupando-nos, sobretudo, com a qualidade do produto, o respeito ao cliente e o desenvolvimento da nossa rede de parceiros.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d8581835-7274-413f-97c3-bfaa8cc695d0.png', NULL, NULL, NULL, '2026-03-09 01:59:07.923', 'https://franquias.portaldofranchising.com.br/franquia-dipz-batata-frita-em-cone/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '255000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
