INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza777h00meeh0sngvdzd6f', 'BATERAS BEAT MUSIC SCHOOL', 'bateras-beat-music-school', NULL, 'Educação', 'EDUCAÇÃO', 'Maior Rede de Escolas de Música da América Latina com 45 Unidades no Brasil, Itália, USA e China. Metodologia Inovadora e modelo de negócio completo com diferencial no suporte e na lucratividade.', 2002, 2020, NULL, '2026-04-01 02:00:09.224', '2025-08-05 22:20:28.733', 843, NULL, 1, 1992, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9c9ac7e8-fa80-4942-b104-a8a50274173d.jpeg', 47, NULL, NULL, '2025-11-27 18:23:44.000', 'https://franquias.portaldofranchising.com.br/franquia-bateras-beat-music-school-servicos-educacionais/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '210000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza777m00mfeh0sy68lx7qm', 'FASTFRAME - MOLDURA NA HORA', 'fastframe-moldura-na-hora', NULL, 'Casa e Construção', 'ARTIGOS PARA O LAR', 'Serviços e produtos de molduraria caracterizado pela busca constante de inovação e tecnologia.', 1995, 1997, '[\"https://www.youtube.com/watch?v=YvRgvdoIZSk\",\"https://www.youtube.com/watch?v=5AO6Tw5JU_I\"]', '2026-04-01 02:00:09.234', '2025-08-05 22:20:28.738', 844, NULL, 1, 1983, 'FastFrame / Moldura na Hora A maior rede de molduraria rápida do mundo A FastFrame / Moldura na Hora é uma rede americana líder mundial em molduras, pôsteres e espelhos, com mais de 100 lojas no mundo todo. Chegou ao Brasil em 1996 com um sistema especializado em prestações de serviços de emolduração em apenas uma hora. Trouxe também produtos inovadores de alta qualidade, que estabelecem um forte diferencial competitivo através da utilização de sofisticados equipamentos e materiais. Este ano a rede recebeu pela 14ª vez a chancela do Selo de Excelência em Franchising, que é fornecido para franquias aprovadas em pesquisas e análises de satisfação dos franqueados em relação à franqueadora, tudo averiguado pela Comissão de Ética da ABF (Associação Brasileira de Franchising). Obteve a aceitação de mais de 90% dos franqueados. No ano de 2016, 2017, 2020 e 2021 a FastFrame | Moldura na Hora recebeu o prêmio Pequenas Empresas Grandes Negócios a cotação 5 estrelas no ranking das melhores franquia do Brasil, da Editora Globo. Hoje, o crescimento é visível, com o aumento expressivo do número de lojas que atingem as principais cidades e capitais do país. A FastFrame / Moldura na Hora é líder por ser especialista no que faz, e também por oferecer um atendimento impecável a seus clientes, através de funcionários especialmente treinados e matéria prima de primeira linha. Também se destaca por trabalhar com produtos inovadores e sempre divulgar novas tendências e artistas. A partir de produtos customizados, oferece a solução adequada para projetos de decoração corporativos (hotéis e empresas) e residências. A rede é a primeira do ramo a oferecer o serviço `Museum Quality`, que está dentro dos padrões internacionais de conservação para total proteção dos trabalhos emoldurados. Todos os produtos utilizados seguem um exemplo mundial de qualidade e que evitam o aparecimento de fungos, cupins e o amarelamento das obras. Possui ainda uma enorme variedade de produtos e itens exclusivos, que você só encontra na FastFrame / Moldura na Hora. A rede oferece um serviço inédito no país: a FastFrame Digital, que consiste em um banco de dados com mais de 20 mil imagens com temas variados. Utiliza moderna tecnologia para impressão de pôsteres, escaneamento e tratamento de imagens, duplicação e ampliação em variados formatos, cores e mídias e está sempre antenada nas tendências. Ao realizar um serviço, alia ótimos produtos com qualidade e agilidade. Os clientes podem retirar o pedido em uma hora ou então contar com a comodidade do serviço de entrega. As lojas possuem um ar jovial e um ambiente convidativo que remetem a uma galeria de arte, devido aos quadros originais e às obras em série nas versões gravuras e pôsteres. Oferece produtos e serviços da mais alta qualidade, pois busca sempre oferecer o melhor para os clientes. Com um rigoroso critério de seleção, homologa somente fornecedores que atendam aos mais exigentes padrões de qualidade. Busca empresas que, assim como a FastFrame / Moldura na Hora, tenham por objetivo a excelência em seus produtos e serviços. Os funcionários são treinados e supervisionados de perto por profissionais experientes, garantindo um serviço à altura da rede.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f8ddaefd-d824-4a7b-9d8c-7d05e5dc1203.jpg', 49, NULL, NULL, '2025-08-29 11:28:05.000', 'https://franquias.portaldofranchising.com.br/franquia-fastframe-decoracao/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a9483a5c-81c6-4b74-a1d3-83e401acea5b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cd65d26a-1eb2-407b-86b9-295b06fcc218.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/09530ab6-b549-4856-8f66-ca4d6193980b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ccd2d49c-2d75-4b02-9f6b-68985ad66ed0.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza777s00mgeh0sdn4dnv66', 'FORUM', 'forum', NULL, 'Moda', 'Vestuários', 'Referência no mercado de jeanswear com peças originais e criativas, a Forum apresenta um momento fresh, moderno e com lifestyle urbano, além de uma rica curadoria em clássicas alfaiatarias.', 1985, 2012, NULL, '2026-04-01 02:00:09.243', '2025-08-05 22:20:28.744', 845, NULL, 1, 1981, '“FRANQUIA FORUM – A MARCA PIONEIRA DE JEANSWEAR NACIONAL \n A Forum traz em seu DNA jeanswear, coleções com pegada contemporânea, sofisticada e cool, apresentando a cada temporada looks cheios de personalidade. \nÉ referência em estilo e comportamento, sendo a marca de vestuário mais citada em pesquisas de opinião no Brasil e vencedora por anos do prêmio de empresa mais admirada do segmento. \nUma marca para homens e mulheres urbanos com um lifestyle jovem, bem informados e que usam a moda como forma de expressão. \nPertencentes as classes A e B, são referência de estilo em seu círculo de relacionamento.   Vantagens em ser um franqueado FORUM: \n- Marca de moda mais lembrada pelo público\n- Experiência de 35 anos de mercado\n- Projeto arquitetônico padronizado\n- Análise e consultoria para a definição do ponto comercial\n- Moderno software de gestão\n- Expertise dos melhores Consultores de Franquias do mercado\n- Treinamentos de vendas e produtos, para a capacitação de equipe\n- Acesso ao Guia Visual da marca e Visual Merchandising\n- Apoio a materiais de marketing e ações de varejo\n- Amplo material estratégico para fomentar as vendas\n- Condições comerciais mais favoráveis\n- Suporte nos pedidos de compra\n- Diversificado mix de produtos, com mais de 800 itens por coleção\n- Suporte do Grupo AMC Têxtil, proprietária da marca, o maior gestor de marcas da América Latina”', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/446e7ec4-bd5f-4415-bda7-464afabf2d4c.jpg', 11, NULL, NULL, '2026-03-09 02:01:57.336', 'https://franquias.portaldofranchising.com.br/franquia-forum-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '490000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza777x00mheh0s49kitb3d', 'MILON', 'milon', NULL, 'Moda', 'Vestuários', 'Milon pertence ao Grupo Kyly, uma das indústrias de vestuário mais importantes do país, e oferece agora ao mercado a oportunidade de parceria através do modelo de franquias em vestuário infantil.', 2016, 2017, '[\"https://www.youtube.com/watch?v=Un7FEGQWews\",\"https://www.youtube.com/watch?v=1GpyzC5WyKE\"]', '2026-04-01 02:00:09.252', '2025-08-05 22:20:28.749', 846, NULL, 1, 1985, 'GRUPO KYLY Presente no mercado desde 1985, produz confecções de alto valor agregado para os mais exigentes mercados. Atualmente, o Grupo Kyly conta com mais de 1.500 funcionários diretos e está entre as empresas de maior representatividade no vestuário infantil. Integridade, qualidade e sustentabilidade são os valores do Grupo, que busca colocá-los em prática através de ações de respeito e valorização das pessoas. Toda a experiência e competência de uma indústria sólida foram absorvidas pela Milon, que assim desenvolve confecções com leitura atual de moda e excelência em qualidade. O Grupo Kyly apresenta as franquias Milon. No mercado desde 2006, a Franquia Milon iniciou a abertura de suas lojas em 2010 para aproximar-se do consumidor e levar a experiência da marca para o ponto de venda. SOBRE A MILON A origem no nome da marca Milon foi inspirada em um vilarejo na região de Bordeaux, na França. A marca é conhecida pela inspiração europeia, estilo clássico e detalhes exclusivos. Veste desde recém-nascidos até o tamanho 14, além de uma linha completa de enxoval. LOJA A primeira loja da Milon foi aberta em 2010. Fundamentado em estudos de mercado e direcionado ao público da marca, o plano de expansão prevê para os próximos anos a abertura de franquias distribuídas nas principais cidades brasileiras. PRODUTO Em cada estação, peças são desenvolvidas especialmente para as lojas Milon, inspirados nas principais tendências de moda e em equilíbrio com as características da marca: clássico e encanto. Sempre atentos as necessidades do mercado além do estilo identificamos necessidades e trabalhamos com outras marcas que compõem nosso mix em formato de collab. Parceria como com a marca de calçados infantis Tip Toey Joey, marca que compõe nossos looks e permitem uma experiência de compra completa. Linhas especiais voltadas para ocasiões de uso e novidades das modelagens e tamanhos também estão em constante evolução. A Milon é uma das poucas marcas no Brasil a possuir o tamanho 5 dentro de sua grade de peças. COLEÇÕES Produtos exclusivos e repletos de detalhes diferenciados fazem da marca uma referência no mercado infantil. A Milon mescla com perfeição o moderno e o clássico, o básico e o sofisticado. VISUAL MERCHANDISING A Milon apresenta um modelo de loja que atende às necessidades e expectativas de seus consumidores, oferecendo excelente exposição dos produtos, atendimento especializado e completo material de apoio às vendas. DIFERENCIAIS A franqueadora tem como objetivo garantir o suporte e todas as ferramentas para o sucesso de todos os franqueados. Marca nacionalmente conhecida; Ampla variedade de produtos, com lançamentos constantes; Estilo, instalações e visual merchandising exclusivos; Equipe exclusiva de gerenciamento de marketing para franquias; Assessoria de comunicação especializada no segmento; Rede testada em operações próprias.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3d6e40fc-1728-49ae-a4d3-4d270509be3f.png', 120, NULL, NULL, '2026-03-09 02:02:46.138', 'https://franquias.portaldofranchising.com.br/franquia-milon-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
