INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza778700mjeh0sgltfw3fv', 'HOSTLY', 'hostly', NULL, 'Hotelaria e Turismo', 'HOSPEDAGEM', 'A Hostly é uma empresa especializada na gestão de locação de curta temporada, que tem como missão proporcionar as melhores experiências tanto para hóspedes quanto para proprietários.', 2024, 2025, NULL, '2026-04-01 02:00:09.272', '2025-08-05 22:20:28.759', 848, NULL, 1, 2023, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1e5858b5-5b11-4511-9bd2-8538b7523f68.png', 8, NULL, NULL, '2025-09-01 14:47:44.000', 'https://franquias.portaldofranchising.com.br/franquia-hostly/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza778d00mkeh0s9qnrigda', 'Giuliana Flores', 'giuliana-flores', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Comercio varejista', 2025, 2025, '[\"https://www.youtube.com/watch?v=1Q5FUNFj5A4\",\"https://www.youtube.com/watch?v=UezjRI21R5Y\",\"https://www.youtube.com/watch?v=7tdMcOcIUAE\",\"https://www.youtube.com/watch?v=bq3SoN5wLw8\"]', '2026-04-01 02:00:09.282', '2025-08-05 22:20:28.765', 849, NULL, 1, 1995, 'A Giuliana Flores é a maior floricultura online do Brasil, com mais de 30 anos de atuação no mercado de presentes.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f8be3f8c-3d8b-4d0a-9b32-87a3613f2477.png', NULL, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8e7a650d-4405-4660-af96-1faaa85d6ec4.jpg', '2026-03-09 02:04:45.101', 'https://franquias.portaldofranchising.com.br/franquia-giuliana-flores/', NULL, 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/47456f8f-0aa8-442e-8bdf-e94f16637a66.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/fc58256c-0670-467d-b153-d748ffcd81b5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4d1320b5-e45b-4135-837d-6915777a0539.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d3e22963-523d-4207-85dc-997e97c99f20.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/122cda55-8bb7-4a09-959e-933c4a9513c8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/fb78c640-0098-4fd5-a242-eb4882a3e4a1.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f42a4586-05e4-41e9-86dc-fb8ade6d57e7.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '270000', NULL, NULL, NULL, '30000', '130000', '8', NULL, '220000', '20000', 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza778j00mleh0sh6nip0v0', 'HOT N\' TENDER', 'hot-n-tender', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fast Food Especializado Em Frango Crocante. Hub de marcas, com varias cozinhas coletivas, entre elas frango crocante, mexicano, hamburguer, comida brasileira, comida saúdavel, entre outras.', 2015, 2015, '[\"https://www.youtube.com/watch?v=gTjTtt5tMME\",\"https://www.youtube.com/watch?v=Dq2acond_Rc\",\"https://www.youtube.com/watch?v=spEOFjHwzSg\"]', '2026-04-01 02:00:09.292', '2025-08-05 22:20:28.771', 850, NULL, 1, 1995, 'A Hot n´Tender  foi fundada em 1995, nos adaptamos a cultura brasileira e o nosso tempero é um sucesso!! Iniciamos a expansão da marca em 2015 e atualmente estamos com mais 50 lojas em 8 estados brasileiros, sendo eles: Rio de Janeiro, São Paulo, Minas Gerais, Espírito Santo Sergipe, Ceará, Pernambuco, Bahia e Rio Grande do Norte. Também contamos com 2 unidades nos EUA. Os nossos  deliciosos frangos crocantes são preparados com a nossa receita secreta! no melhor estilo americano e os baldes arrebatam multidões. Trabalhamos com um mix diversificado de produtos como: sanduíches, tábuas de petiscos, pratos prontos e porções de batata frita, mandioca e anéis de cebola. A HNT trabalha com uma  estratégia diversificada que permite aos nossos franqueados manter o faturamento ao longo de todo o dia, garantindo a máxima rentabilidade.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/22f75e2b-9f17-4e50-84a6-5f02e96cec20.jpg', 49, NULL, NULL, '2026-03-09 02:07:56.772', 'https://franquias.portaldofranchising.com.br/franquia-hotntender/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '250000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza778r00mmeh0sxwxpmb66', 'I\'M INSTITUTO MIX DE PROFISSÕES', 'i-m-instituto-mix-de-profissoes', NULL, 'Educação', 'Treinamento Profissional e Capacitação', 'Cursos profissionalizantes, Graduação e Cursos na área de trânsito', 2012, 2023, '[\"https://www.youtube.com/watch?v=VaYAteftr4M\",\"https://www.youtube.com/watch?v=A6qgWo4hXGM\",\"https://www.youtube.com/watch?v=2Zv8VcY5cf8\"]', '2026-04-01 02:00:09.302', '2025-08-05 22:20:28.779', 851, NULL, 1, 2012, 'História da franquia Instituto Mix de Profissões O Instituto Mix de Profissões foi fundado com o intuito de formar profissionais altamente qualificados que possam atuar em diversas áreas do mercado, tais como: saúde, beleza, tecnologia, idiomas, administração, construção civil, gastronomia, moda, indústria e mecânica, hotelaria e turismo. O IM traz uma grande variedade de cursos e assim consegue estar presente em um vasto número de nichos do mercado, envolvendo vários perfis de clientes de diferentes classes sociais, faixa etárias, sexo e estado civil. \nOpções de cursos não faltam! São mais de 200 à disposição do aluno! Isso porque o Instituto Mix está sempre buscando a excelência dos serviços prestados e o sucesso dos seus franqueados. \nHoje a marca está presente em todo território nacional e alcança a fantástica marca 600 unidades comercializadas no Brasil! A marca IM, que faz parte do mercado de franchising há mais de dez anos, tem acumulado conquistas! Em 2014 ganhou seu primeiro selo das melhores franquias da revista “Pequenas Empresas, Grandes Negócios”, e se manteve na liderança, tendo recebido o prêmio por dez anos consecutivos! Em 2015, 2016, 2017 e também em 2018, a marca também conquistou o Selo de Excelência da ABF. \nPorém em 2018 a comemoração foi ainda mais especial! O IM foi o grande destaque em sua categoria, sendo reconhecida como a melhor Franquia do Brasil.  Todos estes prêmios são resultados de muito trabalho que possibilitaram um crescimento vitorioso mesmo diante do cenário desafiador do país, com altíssimo nível de satisfação de seus franqueados. Esta satisfação vem do método testado e de suporte constante. O Instituto Mix de Profissões se difere de outras marcas quando o assunto é capacitação e qualificação dos seus franqueados e colaboradores, sendo uma das franquias destaque em suporte. \nContamos com a UCIM, a Universidade Corporativa Instituto Mix, local para a troca de experiências entre os profissionais e muitas formações para quem já está na rede e quem está chegando no IM. O Instituto Mix conta ainda com uma TV própria, a IMTV. Por meio dela franqueados e colaboradores recebem informações específicas sobre os setores da escola, como o setor pedagógico, comercial, gestão, marketing, mídias e também conteúdo jornalístico. Contamos ainda com nossa própria gráfica, a Editora IM, que imprime todas os nossos livros didáticos e muitos outros materiais. Com um baixo investimento podemos atingir tanto as pequenas cidades quanto grandes metrópoles. Para a franquia Instituto Mix o investimento é baixo, o suporte é constante e a rentabilidade é muito grande! E você? Quer se tornar um franqueado de sucesso também? Não perca tempo! Venha fazer parte desta rede de conquistas!', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/aa6ef722-7b88-4b85-a107-49a48646b70e.png', 284, NULL, NULL, '2026-03-09 02:08:39.338', 'https://franquias.portaldofranchising.com.br/franquia-instituto-mix-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '85327', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza778y00mneh0sdhm0degd', 'O FORNÊS PIZZARIA DELIVERY', 'o-fornes-pizzaria-delivery', NULL, 'Alimentação', 'Bares e Restaurantes', 'Pizzaria Delivery', 2019, 2021, NULL, '2026-04-01 02:00:09.311', '2025-08-05 22:20:28.787', 852, NULL, 1, 2019, 'O sucesso do hambúrguer artesanal do Burguês despertou nos donos da marca a vontade de levar a mesma qualidade de serviço para uma outra área de atuação – PIZZA! \nE foi daí que surgiu a ideia de criar o primo-pizza do Burguês – O Fornês, que já virou um sucesso e explodiu no Rio de Janeiro, com mais de 30 franquias já vendidas, 18 lojas já inauguradas e funcionando a todo vapor. \nRecentemente inauguramos uma unidade em Belo Horizonte, São Paulo e a expectativa é que a marca cresça cada vez mais no Brasil.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/381b5b93-8f56-495c-8d26-1300c9ca4d0e.png', 18, NULL, NULL, '2026-03-09 02:10:06.556', 'https://franquias.portaldofranchising.com.br/franquia-o-fornes-pizzaria-delivery/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '360000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza779500moeh0sacczp5fn', 'INPOT', 'inpot', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fresh Food - Saladeira, Sucos: O Inpot é uma opção de ponto de equilíbrio na sua alimentação diária. Uma forma de ter refeições preparadas com mais contato humano, menos industrial e mais consciente.', 2021, 2025, NULL, '2026-04-01 02:00:09.322', '2025-08-05 22:20:28.794', 853, NULL, 1, 2021, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/62d59e31-0406-4dd8-9784-80f23a945496.png', 1, NULL, NULL, '2026-03-09 02:10:43.563', 'https://franquias.portaldofranchising.com.br/franquia-inpot/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza779e00mpeh0s2jl44deb', 'IFINANCE', 'ifinance', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'A iFinance é especializada em gestão financeira para franquias e pequenos negócios. Com tecnologia e mão de obra especializada, oferece soluções para que pequenas empresários terceirizem o seu finance', 2023, 2025, NULL, '2026-04-01 02:00:09.332', '2025-08-05 22:20:28.802', 854, NULL, 1, 2018, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/46a04c9b-c726-45e9-b084-914328d33440.png', 23, NULL, NULL, '2026-03-09 02:11:04.038', 'https://franquias.portaldofranchising.com.br/franquia-ifinance-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza779n00mqeh0st3a3xn8e', 'FRANGO NO POTE', 'frango-no-pote', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Frango No Pote atua no segmento de alimentação desde 2012 com mais de 70 lojas em todas as regiões do Brasil, sendo considerada uma das maiores redes de franquia de frango frito do Brasil.', 2014, 2017, '[\"https://www.youtube.com/watch?v=-jjvNxcmfTM\"]', '2026-04-01 02:00:09.343', '2025-08-05 22:20:28.812', 855, NULL, 1, 2012, 'Em 2012, Carlos Augusto inicia a história da marca Frango no Pote. Ninguém imaginaria que um delivery na churrasqueira da casa do Carlão, como é conhecido, produziria uma poderosa rede de frango frito. No primeiro dia dessa inusitada trajetória o telefone tocou 5 vezes, uma surpresa total. O tempo foi passando, as vendas aumentando. Carlos Augusto pega suas economias e inaugura a 1a loja física no dia 16 de junho de 2012 em Arniqueiras, com padrão digno de franquia, no qual tornou-se mania entre os brasilienses. O sucesso foi tão certeiro que desde 2014 o Frango no Pote tornou-se a maior franquia de frango frito do Centro-Oeste, com mais de 20 lojas a pleno vapor (e sabor!). Ciente do potencial da marca e de toda sua imensa equipe, a rede caminha focada em atingir níveis nacionais. Em 2012, Carlos Augusto inicia a história da marca Frango no Pote. Ninguém imaginaria que um delivery na churrasqueira da casa do Carlão, como é conhecido, produziria um poderosa rede de frango frango frito. No primeiro dia dessa inusitada trajetória o telefone tocou 5 vezes, uma surpresa total. O tempo foi passando, as vendas aumentando. Carlos Augusto pega suas economias e inaugura a 1a loja física no dia 16 de junho de 2012 em Arniqueiras, com padrão digno de franquia, no qual tornou-se mania entre os brasilienses. O sucesso foi tão certeiro que desde 2014 o Frango no Pote tornou-se a maior franquia de frango frito do Centro-Oeste, com mais de 20 lojas a pleno vapor (e sabor!). Ciente do potencial da marca e de toda sua imensa equipe, a rede caminha focada em atingir níveis nacionais. O irresistível vai aterrissar em todo o Brasil e você pode fazer parte dessa história.', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/96df8961-c842-475c-a6d4-bea572c9c5ac.png', 58, NULL, NULL, '2026-03-09 02:11:27.310', 'https://franquias.portaldofranchising.com.br/franquia-frango-no-pote/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza779u00mreh0s8gu6pnz4', 'PLANETA IMAGINÁRIO', 'planeta-imaginario', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e Recreação', 'A MELHOR REDE DE ESPAÇO INFANTIL DO BRASIL EM SHOPPING CENTER. ENQUANTO AS CRIANÇAS BRINCAM E SE DIVERTEM, OS PAIS USUFRUEM DE MOMENTOS PESSOAIS.', 2011, 2015, '[\"https://www.youtube.com/watch?v=aQqDGq1Fdeo\"]', '2026-04-01 02:00:09.355', '2025-08-05 22:20:28.818', 856, NULL, 1, 2007, 'Conheça a história de 3 irmãs que com muito amor e empenho, alcançaram o sucesso! Desde sua chegada a Ribeirão Preto, uma das irmãs sentiu a necessidade de algo que a apoiasse no desenvolvimento dos seus filhos Nasceu assim, em 2007, um novo conceito em serviço de recreação infantil, o PLANETA IMAGINÁRIO, no Ribeirão Shopping. Aos poucos o cenário promissor proporcionou a abertura de novas unidades e iniciou a parceria entre as 3 irmãs.  Em 2010 foi inaugurada a unidade de Brasília-DF. A partir desta união a empresa alcançou ótimos resultados em um mercado carente de recreação e espaços infantis dentro de shoppings. O novo conceito permitia que os centros comerciais apostassem na marca e o PLANETA IMAGINÁRIO tornou-se alvo das REDES DE SHOPPINGS de todo o país. A ampliação da rede foi tão grande que se tornou inevitável a expansão da marca. Atualmente, o Planeta Imaginário tem 10 unidades espalhadas pelo Brasil e diversas oportunidades abertas em grandes shoppings. MISSÃO Encantar as crianças e proporcionar momentos de alegria e boas recordações, através de um mundo lúdico, enquanto os pais ou responsáveis desfrutam de tempo para assuntos pessoais. Ser um espaço de liberdade e expressão infantil. VISÃO Compromisso com o coração e a mente. Atenção, carinho e respeito com as crianças. Diversão com segurança. Beneficiar todos através de parcerias. Por que investir em uma franquia Planeta Imaginário? Experiência de sucesso de mais de 9 anos Excelente relacionamento com as administradoras de Shopping Center Vai participar de uma marca e de um sistema de gestão consolidado, de prestígio e de sucesso. Iniciará a operação com métodos profissionais de gestão e com acompanhamento. Contará com a experiência e apoio da Rede Planeta Imaginário para minimizar riscos. Porque você irá unir sonho, realização pessoal, profissional e financeira Vantagens de fazer parte da Rede Planeta Imaginário de Franquias? Conceito de vanguarda e prestação de serviço inovador. Marca respeitada e consolidada. Projeto de arquitetura inovador e seguro. Auxilio na negociação de ponto em shopping. Treinamento completo, padronização, metodologia, estratégia e gestão. Marketing ativo e inovador. Rápido retorno de investimento.', NULL, 'SÃO PAULO', 1, NULL, 13, NULL, NULL, '2026-03-09 02:12:26.775', 'https://franquias.portaldofranchising.com.br/franquia-planeta-imaginario-entretenimento-brinquedos-e-lazer/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '355000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
