.portaldofranchising.com.br/franquia-polo-wear/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '770000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
