INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77av00myeh0say74ssb1', 'LEADS2B', 'leads2b', NULL, 'Comunicação, Informática e Eletrônicos', 'Comunicação e Mídia', 'A Leads2b é uma plataforma de automação de marketing e vendas que ajuda empresas a gerar leads qualificados e otimizar seus processos comerciais.', 2025, 2025, NULL, '2026-04-01 02:00:09.422', '2025-08-05 22:20:28.856', 863, NULL, 1, 2017, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1bce45cc-bdb8-4e1b-8ba6-a834dcd04c85.png', 1, NULL, NULL, '2026-03-09 02:15:30.069', 'https://franquias.portaldofranchising.com.br/franquia-leads2b/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '60001', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77b000mzeh0smro7sq5o', 'COMPRE CERTO REDE DE DROGARIAS', 'compre-certo-rede-de-drogarias', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Franquia de Farmácias e Drogarias', 2012, 2016, '[\"https://www.youtube.com/watch?v=_OX94frJIfA\",\"https://www.youtube.com/watch?v=NViSvmP2I4g\",\"https://www.youtube.com/watch?v=-djTCkVjuqc\"]', '2026-04-01 02:00:09.432', '2025-08-05 22:20:28.861', 864, NULL, 1, 2010, 'Fundado em 2010, o Grupo Compre Certo, atua no segmento de franquias e marcas licenciadas, oferecendo soluções para uma melhor gestão de drogarias.  \nO Grupo Compre Certo é um dos mais prósperos do segmento Farma e vem assinalando índices positivos de crescimento e alto grau de satisfação junto aos seus franqueados e licenciados.  Crescimento Com faturamento acima de 16,2 milhões ao mês, são mais de 90 lojas distribuídas em 60 cidades de 12 estados brasileiros. \nCom crescimento acima do mercado nos últimos dois anos, nosso propósito é alcançar excelência em gestão para gerar prosperidade e saúde às pessoas.   Nossa missão: agregar valores a todos os nossos clientes e demais envolvidos para que possamos juntos prosperar no mercado farma. Nossa visão: sermos reconhecidos como a melhor franquia do segmento farma, inserindo cada vez mais tecnologia a serviço da melhor gestão. Nossos valores: Ética • Saúde • Respeito • Coerência • Prosperidade • Conhecimento • Transparência • Valorização do ser humano.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/90f3bbab-4567-48a7-ae12-8f23c62f098f.png', 90, NULL, NULL, '2026-03-09 02:15:52.372', 'https://franquias.portaldofranchising.com.br/franquia-compre-certo-rede-de-drogarias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77b700n0eh0sk8ko2r3i', 'POLPANORTE', 'polpanorte', NULL, 'Alimentação', 'Docerias, Padarias e Cafés', 'Revenda de açaís, cremes, sorbets, smoothies, sucos de polpas de frutas, outras bebidas e correlatos.', 2024, 2024, NULL, '2026-04-01 02:00:09.441', '2025-08-05 22:20:28.867', 865, NULL, 1, 2022, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5c349318-6b1d-40e8-808c-4e38b1056bda.png', 10, NULL, NULL, '2026-03-09 02:16:35.006', 'https://franquias.portaldofranchising.com.br/franquia-polpanorte/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '185000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77bc00n1eh0sfaoss4lt', 'STUDIO FISCAL - PLANEJAMENTO TRIBUTÁRIO', 'studio-fiscal-planejamento-tributario', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Planejamento Tributário e Auditoria Fiscal', 2008, 2010, NULL, '2026-04-01 02:00:09.451', '2025-08-05 22:20:28.872', 866, NULL, 1, 2006, 'Em 1996 foi criado o escritório de advocacia Monteiro Saran Advogados (hoje nomeado Braga Monteiro Advogados), tendo como sócio majoritário o Dr. José Carlos Braga Monteiro. Dois anos depois (1998), através do escritório, foi fundada a Studio Fiscal, que em 2004 foi formatada em modelo de franquia e em 2006 recebe a sua sede na cidade de Porto Alegre. A Studio Fiscal foi apresentada ao mercado em 2008 e em 2010 a já estava presente em 75% do mercado nacional. Em 2013 a empresa montou a sua segunda sede na cidade de São Paulo.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 57, NULL, NULL, '2026-03-09 02:16:56.704', 'https://franquias.portaldofranchising.com.br/franquia-studio-fiscal-planejamento-tributario-negocios-e-servicos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '50000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77bh00n2eh0sz1eqjfum', 'SUDOMED SEGURANÇA NO TRABALHO', 'sudomed-seguranca-no-trabalho', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Prestação de Serviços de Saúde e Segurança no Trabalho.', 2003, 2024, NULL, '2026-04-01 02:00:09.461', '2025-08-05 22:20:28.877', 867, NULL, 1, 2003, '', NULL, 'PARANÁ', 1, NULL, 16, NULL, NULL, '2026-03-09 02:17:33.468', 'https://franquias.portaldofranchising.com.br/franquia-sudomed-seguranca-no-trabalho-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '270000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77bm00n3eh0smpo7uop9', 'ODONTOTOP HOSPITAL DO DENTE', 'odontotop-hospital-do-dente', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Muito mais que clínica, um Hospital do Dente. Vamos além da odontologia para ser a maior e mais premiada rede de hospitais odontológicos do Brasil em 2026.', 2020, 2021, '[\"https://www.youtube.com/watch?v=cKzAaDXkNIY\",\"https://www.youtube.com/watch?v=4lAx3D9iUJo\",\"https://www.youtube.com/watch?v=ScXKq_dIPbU\",\"https://www.youtube.com/watch?v=zYhX9YcQrAM\"]', '2026-04-01 02:00:09.472', '2025-08-05 22:20:28.882', 868, NULL, 1, 2012, 'A OdontoTop é uma franquia de odontologia criada por dentistas, para dentistas. Nossos profissionais viveram e trabalharam em unidades próprias, testando, validando e estruturando um modelo de sucesso. Agora, compartilhamos toda essa experiência para que novos franqueados possam iniciar seus negócios com segurança, em uma rede grande, sólida e autossustentável. A OdontoTop oferece uma fórmula vencedora, que combina uma metodologia própria de atuação com um software de gestão exclusivo. Esse modelo comprovadamente funciona em qualquer localidade do Brasil, com todas as unidades inauguradas em plena atividade. Por que limitar-se a uma clínica odontológica quando você pode ter seu próprio Hospital do Dente? Oferecemos modelos de negócios para cidades a partir de 8 mil habitantes. A OdontoTop é a rede odontológica mais premiada do Brasil em 2024, ao receber o selo de Excelência em Franchising, concedido pela ABF, o selo de Melhores Franquias do Brasil, concedido pelo programa Pequenas Empresas & Grandes Negócios e o selo de Great Place to Work. Tenha seu próprio Hospital do Dente A estrutura é um grande diferencial, voltado para o conforto e comodidade dos pacientes, desde a recepção até as salas de atendimento. Cada projeto é cuidadosamente planejado para atender a demanda de tratamentos odontológicos de toda a região. Agora pense como um paciente: você faria uma cirurgia complexa em uma clínica simples ou em um hospital especializado? Contamos com um centro cirúrgico completo, equipado com monitor cardíaco hospitalar, oxigênio e raio-x panorâmico, ideal para procedimentos de grande complexidade, e ambientes pré e pós-operatórios. Nossos consultórios são padronizados para garantir excelência em todos os procedimentos realizados. Todo o Hospital do Dente é planejado e estruturado para atender às exigências de um negócio sustentável ao longo prazo, mantendo-se sempre atualizado e em conformidade com as normas da vigilância sanitária federal.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/74763ed9-ac55-4151-9368-99e4813c4a83.png', 76, NULL, NULL, '2026-03-09 02:18:06.708', 'https://franquias.portaldofranchising.com.br/franquia-odontotop-hospital-do-dente/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1001553.95', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77br00n4eh0s6qcu8pgq', 'IMPACTO PRIME', 'impacto-prime', NULL, 'Serviços Automotivos', 'Peças, Acessórios e Manutenção', 'Comércio de Pneus nacionais e importados Comércio de peças automotoras e manutenção preventiva em automóveis.', 2015, 2019, NULL, '2026-04-01 02:00:09.482', '2025-08-05 22:20:28.887', 869, NULL, 1, 1999, '', NULL, 'SÃO PAULO', 1, NULL, 104, NULL, NULL, '2026-03-09 02:19:10.133', 'https://franquias.portaldofranchising.com.br/franquia-impacto-prime/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '680000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77bw00n5eh0sdyd9etv9', 'PITICAS FRANQUEADORA', 'piticas-franqueadora', NULL, 'Moda', 'Vestuários', 'Camisetas e acessórios oficiais e licenciados do universo geek, super heróis, séries, personagens e bandas de rock.', 2011, 2013, '[\"https://www.youtube.com/watch?v=PNpQLQA2kSs\",\"https://www.youtube.com/watch?v=fu6cEA_n4kw\"]', '2026-04-01 02:00:09.492', '2025-08-05 22:20:28.892', 870, NULL, 1, 2010, 'A Piticas iniciou suas atividades em 2010, a partir da ideia dos irmãos Rossetti.  O objetivo inicial era oferecer ao consumidor final peças de moda criativa que brincava com marcas famosas. Com a consolidação no mercado, veio o licenciamento com os maiores players de entretenimento do mundo e, com isso, nos tornamos a maior referência em moda GEEK no Brasil.  Hoje, mais de 10 anos depois, a Piticas conta com mais de 400 pontos de vendas espalhados por todo o país. Oferecemos todo mês, novas estampas exclusivas e uma linha completa de mix de produtos para vestir seu lado fã! A Franquia Piticas ocupa o 43º lugar no ranking das maiores franquias do Brasil, com mais de 400 unidades franqueadas (ABF), e está entre as 5 mais amadas pelos Brasileiros (Revista exame). A franquia se destaca pela inovação em tecnologia, produção ágil com reposição semanal, e uma estrutura de franquia 100% focada no resultado dos nossos franqueados. Uma das grandes vantagens da franquia Piticas é sua produção 100% verticalizada, que garante a qualidade dos produtos, independência de fornecedores terceirizados, e dinamismo na produção de lançamentos.  HISTÓRIA DA MARCA A Piticas nasceu da ideia de dois irmãos, Vinicius e Felipe Rossetti, que após morarem por mais de uma década nos Estados Unidos, retornaram ao Brasil em busca de uma oportunidade empreendedora.  Os irmãos, que sempre foram fãs de cultura pop, em especial pelos filmes de super-heróis, séries e games, após analisar vários mercados, tiveram a visão de um negócio que ainda não era explorado no Brasil: o mercado de vestuário de peças licenciadas, inicialmente, camisetas. A marca que incialmente se consolidou através de pontos de quiosques, hoje já conta com + 03 modelos de negócio: store, XP e multimarcas. Com uma produção 100% verticalizada, e o foco no desenvolvimento da criatividade e atentos a cada detalhe, os irmãos fundaram a primeira loja em 2010, e desde então acompanham todas as etapas de produção, treinamento de funcionários e satisfação dos clientes, prezando por qualidade e criatividade em seus produtos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/882a0ac6-2d70-4a79-b1ac-7b93253cedd5.jpg', 220, NULL, NULL, '2026-03-09 02:19:36.180', 'https://franquias.portaldofranchising.com.br/franquia-piticas-franqueadora-moda/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2d1e8d91-0520-4e4a-b678-d8fa1e5204f1.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/74222833-c264-4106-8c68-e20a431cec0f.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '75000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77c100n6eh0sc04gvajc', 'LOUNGERIE INTIMATES', 'loungerie-intimates', NULL, 'Moda', 'VESTUÁRIO', 'Varejo de moda íntima.', 2015, 2023, NULL, '2026-04-01 02:00:09.501', '2025-08-05 22:20:28.897', 871, NULL, 1, 2011, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/56767cf2-414c-4019-b572-ef0368cbcabc.png', 123, NULL, NULL, '2026-01-26 09:48:50.000', 'https://franquias.portaldofranchising.com.br/franquia-loungerie-intimates-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '429000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77c600n7eh0sz89rv9pd', 'TWENTY FOUR SEVEN SIMPLE N\'CHIC', 'twenty-four-seven-simple-n-chic', NULL, 'Moda', 'VESTUÁRIO', 'Somos a marca do Coração! Espalhamos nosso lifestyle através das propostas dos nossos looks e mostramos o amor através do nosso time apaixonado e engajado em fazer do seu dia mais feliz.', 2017, 2024, NULL, '2026-04-01 02:00:09.510', '2025-08-05 22:20:28.902', 872, NULL, 1, 2017, '', NULL, 'SÃO PAULO', 1, NULL, 27, NULL, NULL, '2025-09-18 09:03:20.000', 'https://franquias.portaldofranchising.com.br/franquia-twenty-four-seven-simple-nchic-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '780000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cb00n8eh0spbnmz3sd', 'TELEVIDA PARA TODOS', 'televida-para-todos', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Telemedicina e consultas médicas presenciais', 2024, 2024, NULL, '2026-04-01 02:00:09.520', '2025-08-05 22:20:28.907', 873, NULL, 1, 2019, '', NULL, 'SÃO PAULO', 1, NULL, 4, NULL, NULL, '2026-03-09 02:21:14.246', 'https://franquias.portaldofranchising.com.br/franquia-televida-para-todos-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '19900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cg00n9eh0sprialfwe', 'TODOMODA', 'todomoda', NULL, 'Moda', 'Acessórios Pessoais', 'Líder no segmento de Acessórios de Moda e Lifestyle na América Latina, com mais de 800 lojas na região. Após excelente entrada no Brasil, lança seu modelo de franquias com lojas entre 35 e 45m2.', 2002, 2023, '[\"https://www.youtube.com/watch?v=DE-zDfrkv5k\"]', '2026-04-01 02:00:09.530', '2025-08-05 22:20:28.912', 874, NULL, 1, 1995, 'Aterrizamos no Brasil em 2019 e com o objetivo de construir também no país a sua liderança no segmento, a qual é mais do que comprovada na maioria dos países da América Latina. As nossas coleções são desenvolvidas de ponta a ponta com base em pesquisas de moda globais e adaptadas ao DNA da marca e de sua comunidade de clientes, os produtos são projetados contando com processos de sustentabilidade e “cruelty free”, a qual possui certificação, inspirando as novas gerações a escolherem produtos de forma mais consciente e responsável, com o objetivo de gerar um impacto positivo para o planeta. O objetivo da expansão de franquias da TODOMODA, assim como nos demais países onde a marca está presente, é de democratizar o acesso aos seus produtos e gerar conexão emocional com a sua comunidade de clientes, fazendo com que se sintam à vontade para expressar sua personalidade através dos acessórios, com inovação, tecnologia na personalização da experiência, muito cuidado e carinho no desenvolvimento dos produtos únicos e tudo dentro de um modelo de negócios inteligente, saudável e com muito suporte aos seus Franqueados. RAZÕES PARA SER UM FRANQUEADO TODOMODA Modelo de negócio inovador Tomada de decisão com dados real-time Planejamento de demanda com suporte de ferramentas de Inteligência Artificial Total suporte estratégico e operacional Customer Experience e integração de canais Retorno rápido do investimento Lucro entre 10% e 18% Custo-benefício Empresa sólida com know-how de mercado Omnicanalidade Modelo de inteligência baseado em Machine Learning Mais de 10 bilhões de dados combinados semanalmente para identificação de oportunidades em loja', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/af3851dc-fd6f-4783-aa7b-3b10f7b5ba27.png', 21, NULL, NULL, '2026-03-09 02:21:41.361', 'https://franquias.portaldofranchising.com.br/franquia-todomoda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '510000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cm00naeh0sh777zspt', 'GOLDKO', 'goldko', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Chocolateria e cafeteria premium com um mix exclusivo de produtos 100% sem açúcar.', 2023, 2022, '[\"https://www.youtube.com/watch?v=RtMT8wU-3bM\",\"https://www.youtube.com/watch?v=S5x9BVL98y4\",\"https://www.youtube.com/watch?v=zE2_rNWPZAg\",\"https://www.youtube.com/watch?v=ciMMsyRZ5bQ\"]', '2026-04-01 02:00:09.540', '2025-08-05 22:20:28.918', 875, NULL, 1, 2017, 'A franquia GoldKo nasceu em 2017 com o propósito de transformar a relação do brasileiro com o chocolate. Criada por uma família empreendedora com mais de 100 anos de experiência no setor — fundadora de uma das marcas de chocolate mais tradicionais do país — a GoldKo une sabor, saúde e sofisticação em um portfólio completo de chocolates zero adição de açúcares, com apelo premium e alto valor percebido. Com fábrica própria, controle total de produção e presença consolidada em grandes redes varejistas, a marca iniciou seu projeto de franquias em 2023, após validar com sucesso o modelo de operação com sua loja própria no Shopping Eldorado - aberta em 2021. O mercado de chocolates premium e saudáveis cresce acima da média do setor, impulsionado por um consumidor mais consciente, exigente e aberto a novas experiências. A GoldKo está perfeitamente posicionada nesse cenário, oferecendo um produto inovador e único, com forte poder de encantamento e recompra. Entre os principais diferenciais da franquia estão: Omnicanalidade real: cada unidade conta com loja física e e-commerce regional integrado, sem conflito de canal — todas as vendas online da região são faturadas pelo franqueado. Modelo de operação enxuto e escalável, ideal para shopping centers. Portfólio premiado, com produtos que unem prazer e saudabilidade. Fábrica própria, garantindo qualidade, abastecimento e inovação constante. Marca com propósito, forte conexão emocional com o consumidor e enorme potencial de expansão nacional. A franquia GoldKo é mais do que uma loja de chocolates — é um negócio de impacto, alinhado às novas demandas do consumidor e com estrutura sólida para crescer de forma acelerada.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/863980ed-318b-4326-8f79-2f2ca162cce8.jpeg', 16, NULL, NULL, '2026-03-09 02:22:35.937', 'https://franquias.portaldofranchising.com.br/franquia-goldko/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '340000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cr00nbeh0sf36lwb8v', 'SCHUTZ', 'schutz', NULL, 'Moda', 'CALÇADOS', 'A marca investe significativamente em pesquisas de tendências, desenvolvimento de material e tecnologia para a criação do seu portfólio. Sua missão é oferecer ao seu público um conceito de produtos.', 2010, 2015, NULL, '2026-04-01 02:00:09.549', '2025-08-05 22:20:28.923', 876, NULL, 1, 1995, '', NULL, 'SÃO PAULO', 1, NULL, 68, NULL, NULL, '2025-10-27 17:44:40.000', 'https://franquias.portaldofranchising.com.br/franquia-schutz-acessorios-pessoais-e-calcados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '760000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cx00nceh0s25f76uf3', 'V4 COMPANY', 'v4-company', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Modelo prestação de serviços de marketing digital através de escritórios independentes espalhados em todo Brasil.', 2017, 2019, '[\"https://www.youtube.com/watch?v=mTyZLCFxA_Q\",\"https://www.youtube.com/watch?v=QMQz2qXZUt8\"]', '2026-04-01 02:00:09.558', '2025-08-05 22:20:28.929', 877, NULL, 1, 2012, 'Junte-se ao melhor time de profissionais de marketing do Brasil. Trabalhe de qualquer lugar: nosso projeto foi construído para atuar a distância. Trabalhe de qualquer lugar do Brasil ou do mundo com a sua unidade. Fature com a V4: Até 50 clientes atribuídos em um prazo de 12 meses com ticket médio de R$3.500,00. Suporte nos projetos: Conte com a colaboração do time de Customer Success  em seus projetos no dia a dia. Nossa equipe presta o suporte necessário. Apoio administrativo: Suporte consultivo nos aspectos administrativos gerais do negócio e suporte ativo na cobrança e negociação de inadimplência. Negócio Inovador: A Franquia V4 é um modelo de negócio inovador, único, escalável que está revolucionando o mercado de marketing no país. Acessível: Com um custo de operação muito baixo, você pode começar o seu negócio com um escritório enxuto. Lucrativo: Um franqueado disciplinado pode ter um lucro de até 30% sobre o faturamento, já nos primeiros meses de atuação com os clientes. Escalável: A V4 oferece um plano de crescimento robusto, com um planejamento detalhado, que possibilita a escala do negócio.   VANTAGENS DE SER UM FRANQUEADO V4: Know How Compartilhado: Você ganhará uma formação completa Cientista do Marketing Digital, para aprender as técnicas e conceitos que já foram testadas e consolidadas na V4 Company. \nEsses ensinamentos são aplicados diariamente em nossos mais de 172 escritórios. Plano de crescimento agressivo: A V4 planeja crescer muito nos próximos anos, para se tornar uma das maiores franqueadoras do Brasil e você terá a oportunidade de crescer sua unidade junto com a gente. \nEm 2 anos, o nosso crescimento se mostra rápido e consistente e a tendência é continuarmos fortemente em ascensão, atingindo cada vez mais clientes e unidades. Até 20k de MRR (receita recorrente mensal): Após adquirir a Franquia, você  tem seus primeiros clientes garantidos pela V4 com um valor médio de serviço de R$ 4.000 por cliente. Após você  seguir o processo de prestação de serviço com excelência para esses primeiros clientes, poderemos continuar delegando clientes para sua unidade até alcançar seus objetivos de faturamento. IPO em 2030: O grande objetivo da V4 Company é chegar à marca de 100 mil clientes juntamente com a abertura de capital na bolsa de valores através de um IPO. Sem barreiras geográficas: Todo nosso sistema de prestação de serviço foi desenvolvido para ser realizado à  distância. \nSendo assim, você  pode atuar em qualquer lugar do Brasil. Já contamos com franqueados em todas as regiões do país. \nIndependente de quantas franquias já existirem na sua cidade, você pode fazer parte da V4 atendendo clientes de qualquer lugar. Auxílio total da matriz: Todas as unidades franqueadas têm livre acesso à toda equipe V4 matriz, bem como todas unidades franqueadas. \nTemos um canal de comunicação onde é possível solicitar apoio com os projetos, dúvidas sobre contratação de pessoas, cases de clientes, etc. \nA V4 Matriz acompanha o andamento dos projetos, os resultados dos mesmos, o desempenho do franqueado, acompanhamento dos processos e gestão da unidade. Torne-se um Equity Partner da V4 Company: O plano é anualmente premiar os melhores franqueados com participação em todo o negócio . Assim, além dos ganhos do negócio, você conquista um patrimônio de alto valor.\n  TEMPO PARA PAYBACK (retorno do investimento): FRANQUIA V4\n8 a 18 meses\nEm até 60 dias você recebe seus primeiros clientes, e somente com eles em 9 meses você já pode faturar \"de volta\" todo seu investimento. \nEm 12 meses de retenção do cliente, o payback é garantido dentro deste período citado acima.  OUTRAS FRANQUIAS\n36 a 48 meses Outras franquias do mercado apresentam um risco muito maior pois não existe nenhuma garantia de retorno, além de exigirem capital inicial muito maior.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b49582a8-0ed8-48fd-8d6d-9a372641bbf2.jpg', 273, NULL, NULL, '2026-03-09 02:23:53.499', 'https://franquias.portaldofranchising.com.br/franquia-v4-company/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 1, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77d300ndeh0sok8ovub4', 'ORAL CENTTER CLÍNICAS ODONTOLÓGICAS', 'oral-centter-clinicas-odontologicas', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'CLINICA ODONTOLOGICAS', 2022, 2023, '[\"https://www.youtube.com/watch?v=gTkSHWD5IT4\"]', '2026-04-01 02:00:09.568', '2025-08-05 22:20:28.935', 878, NULL, 1, 2020, 'SOBRE A ORAL CENTTER  CONEXÃO QUE NOS LEVA ALÉM!   Por que investir em odontologia? Fundada em 2020 pela dentista e empresária Priscila Gusmão, a Oral Centter nasceu da necessidade de criar um modelo de negócio responsável, que oferece suporte integral e auxilia os dentistas a conquistarem sua própria clínica. A experiência de Priscila como ex-franqueada de uma rede falida foi o ponto de partida para desenvolver uma proposta inovadora e sólida. Com foco nas classes C e D, a rede se destaca por validar unidades em cidades a partir de 15 mil habitantes, oferecendo soluções acessíveis e de qualidade em regiões pouco exploradas por grandes redes.   Expansão planejada e resultados sólidos A Oral Centter já possui 81 unidades, sendo 39 em operação, e segue um plano de expansão nos estados de Minas Gerais, Goiás e Nordeste. O objetivo é crescer com responsabilidade e garantir suporte completo ao franqueado, desde a assinatura do contrato até o dia a dia da operação.   Diferenciais que fazem a diferença Treinamentos semanais e mensais nas áreas comercial, clínica, gestão e finanças. Marketing completo e padronizado, gerenciado pela própria rede, sem necessidade de terceirização. Clínicas com faturamento médio de R$120.000,00 a R$140.000,00, oferecendo atendimento humanizado e uma experiência comparável ao público A.   Mais do que expandir, a Oral Centter tem como missão realizar sonhos: Dos dentistas que abrem suas clínicas próprias. Dos pacientes que encontram um atendimento acessível e de qualidade.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/24aedaf6-e817-40f5-a66b-daf7dfb27783.png', 59, NULL, NULL, '2026-03-09 02:25:45.869', 'https://franquias.portaldofranchising.com.br/franquia-oral-centter-clinicas-odontologicas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '235000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77db00neeh0s03kzu6ko', 'CASTILLA IDIOMAS', 'castilla-idiomas', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escola de idiomas com desenvolvimento linguístico e cultural.', 2021, 2022, '[\"https://www.youtube.com/watch?v=9PmDKMr3whg\",\"https://www.youtube.com/watch?v=q4a8pCejlYA\",\"https://www.youtube.com/watch?v=YnOVshepw5c\",\"https://www.youtube.com/watch?v=w9awREMTpYU\"]', '2026-04-01 02:00:09.578', '2025-08-05 22:20:28.943', 879, NULL, 1, 1996, 'Há 27 anos, o Castilla Idiomas tem sido a escola de idiomas que tem transformado muitas histórias através de um aprendizado rápido, melhor e completo. Todos os 7 idiomas são ensinados por meio de uma metodologia comunicativa, pois nossa principal meta é promover a aprendizagem da língua estrangeira com atividades que priorizem a comunicação que envolvem quatro competências: auditiva, oral, leitura e escrita. Atualmente temos 16 unidades no estado do Pará e duas unidades em Fortaleza, mais para nós o céu é o limite, o nosso objetivo é ter um Castilla Idiomas nos 4 cantos deste país. Nossos diferenciais: Metodologia de ensino de idiomas para Brasileiros.\n\tAs metodologias de ensino de Inglês, Espanhol e Francês são próprias do Castilla, contendo livros, áudios e vídeos animados.\n\tEsse material foi desenvolvido para o aprendizado de idiomas por Brasileiros.\n\t  Segundo idioma em 18 meses.\n\tNossa metodologia oferece cursos completos de idiomas em 18 meses.\n\t  Matrículas 365 dias por ano.\n\tO Castilla oferece os cursos Regulares e Flex (Inglês, Francês e Espanhol) o que proporciona matrículas 365 dias por ano.\n\t  Sistema Castillaflex de aulas on-line.\n\tO Castilla desenvolveu um sistema de marcação e acesso a aulas on-line para seus cursos Flex, o que possibilita aos alunos marcarem suas aulas e assistirem de qualquer lugar.\n\tAs unidades franqueadas compartilham as aulas e formam uma imensa estrutura de oferta diária de aulas.', NULL, 'PARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1f663392-a8f5-4a34-acc2-5c0dbe59724c.png', 15, NULL, NULL, '2026-03-09 02:26:40.373', 'https://franquias.portaldofranchising.com.br/franquia-castilla-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '62500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77dh00nfeh0sibsyj67t', 'YAKITAI', 'yakitai', NULL, 'Alimentação', 'Bares e Restaurantes', '1ª FRANQUIA DE COMIDA ORIENTAL 100% DELIVERY DO BRASIL! MODELO DE OPERAÇÃO SIMPLIFICADA COM DUAS MARCAS OPERANDO NA MESMA COZINHA.', 2021, 2023, NULL, '2026-04-01 02:00:09.587', '2025-08-05 22:20:28.949', 880, NULL, 1, 2020, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f2af4f30-e93a-4afb-a324-154578c98355.png', 11, NULL, NULL, '2026-03-09 02:27:34.268', 'https://franquias.portaldofranchising.com.br/franquia-yakitai/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '157000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77do00ngeh0sxmukzl98', 'BENGÔ', 'bengo', NULL, 'Alimentação', 'Docerias, Padarias e Cafés', 'A Bengô Açaí se estabeleceu como líder no Maranhão e, agora, estamos expandindo para mais 6 estados. Recorde de Vendas de Franquias, contabilizamos mais de 20 lojas vendidas em menos de um ano', 2023, 2023, NULL, '2026-04-01 02:00:09.596', '2025-08-05 22:20:28.956', 881, NULL, 1, 2015, '', NULL, 'MARANHÃO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6b0d498a-c380-4d59-aafd-68f2a284230d.png', 77, NULL, NULL, '2026-03-09 02:27:53.982', 'https://franquias.portaldofranchising.com.br/franquia-bengo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77dv00nheh0sl8qcpa7z', 'USINA DE MASSAS', 'usina-de-massas', NULL, 'Alimentação', 'Bares e Restaurantes', 'Restaurante especializado em massas e molhos.', 2012, 2012, NULL, '2026-04-01 02:00:09.606', '2025-08-05 22:20:28.963', 882, NULL, 1, 2002, 'A Usina de Massas foi inaugurada em 2002 com o objetivo de ser referência em massas e molhos na cidade de Porto Alegre. \nO projeto originou-se da necessidade percebida pelos dois sócios fundadores de ter um restaurante que reunisse ótima comida, excelente atendimento agregados a uma arquitetura acolhedora. Partindo desta percepção escolheu-se o segmento de massas e molhos pelo grande número de apreciadores dessa combinação e por entender que havia uma carência de propostas deste tipo no mercado de Porto Alegre. \nEssas premissas levaram à escolha de uma bela casa da década de 50, no charmoso bairro Moinhos de Vento, onde foi construída a Usina de Massas. A busca por encantar o cliente é alcançada através da ótima comida, atendimento profissionalizado e ambiente acolhedor. \nO restaurante possui sistema de delivery, loja com massas frescas, molhos congelados e take away. A Usina de Massas disponibiliza em seu website diversas informações como cardápio, carta de vinhos, produtos do Armazém da Usina, promoções e diversas informações úteis para seus clientes.\"', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5e36e6b9-4fe5-436d-8d4e-17406b9fd4e4.jpg', 21, NULL, NULL, '2026-03-09 02:28:13.803', 'https://franquias.portaldofranchising.com.br/franquia-usina-de-massas-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77e000nieh0shsrhpjgz', 'POPCORN GOURMET', 'popcorn-gourmet', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Seleção de matéria-prima de altíssima qualidade que garantem cobertura generosa, crocância e textura aveludada. Operação enxuta e produto pronto e As melhores Pipocas da vida.', 2016, 2022, '[\"https://www.youtube.com/watch?v=uoEsO6k3DI8\",\"https://www.youtube.com/watch?v=lXTTplTF3jY\",\"https://www.youtube.com/watch?v=1KDKpZxnOQw\",\"https://www.youtube.com/watch?v=cDz1uw-XN-s\"]', '2026-04-01 02:00:09.616', '2025-08-05 22:20:28.968', 883, NULL, 1, 2015, 'Mais que uma Pipoca, UMA EXPERIÊNCIA!  Aqui, somos viciados em qualidade, portanto, todo processo de fabricação das Pipocas passa por rígido controle de qualidade. Utilizamos as melhores matérias-primas no mercado, a fim de oferecer ao cliente a melhor experiência. Hoje, são 15 sabores das melhores Pipocas, sendo três deles homologados e licenciados pela Nestlé: Feito com Alpino, Feito com Sensação e Melhor com Ninho Trufado, o recordista de vendas.  Preocupada com sustentabilidade, nossa CEO e Chef Elaine Moura, criou várias outras receitas a partir de sobras de insumos deliciosos da fabricação de pipocas: Cappuccinos, Frapês, Chocolates, Cafés gelados, são algumas das receitas que deram início a nova rede da franquia de cafeterias, Pop Coffee.  Diferencial \nOs produtos são feitos a partir de técnicas diferenciadas, que garantem alta crocância. Além disso, são utilizadas matérias-primas de altíssima qualidade e técnica. E são feitos sem o uso de conservantes artificiais. Um produto completamente distintivo e superior à concorrência!    Sobre nós Ao falar da história da PopCorn Gourmet, não podemos deixar de mencionar a responsável pelo sucesso da marca: Chef Elaine Moura! Além de Chef de cozinha, Elaine é jornalista, mãe, empresária e fundadora da PopCorn Gourmet. Durante 19 anos ficou à frente de um dos mais luxuosos buffets de Goiânia, e em 2014 sentiu a necessidade de criar uma receita autoral que servisse de presente a seus clientes. \nSendo apaixonada por doces e pipocas, focou em pesquisas por mais de um ano até acertar a receita perfeita. Assim surgiu a PopCorn Gourmet, que em 2015, foi lançada pela Chef na CASACOR. O sucesso foi instantâneo, garantindo capa no principal jornal da cidade.  A PopCorn Gourmet  Devido ao grande sucesso na CASACOR, a Chef Elaine, em 2015, instalou quiosques de pipocas nos principais shoppings de Goiânia. Ao perceber que ganhou o público da cidade, decidiu em 2016, conquistar novos negócios inaugurando sua primeira unidade franqueada em Ribeirão Preto, de lá pra cá, somamos mais de 50 unidades no Brasil, fábrica e quiosque recém inaugurados em Miami e em breve fábrica em Portugal. Além do mercado de franquias, a marca agora comercializa seus produtos em embalagens Stand Up Pouch, que ocupam as gôndolas dos melhores supermercados e empórios do Brasil. \nTendo como principal ponto de venda a rede de supermercados Carrefour.', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3e20e6a5-aa97-4b4e-91d7-26a35f9752bf.jpg', 46, NULL, NULL, '2026-03-09 02:28:57.259', 'https://franquias.portaldofranchising.com.br/franquia-popcorn-gourmet/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '48000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
