INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77eg00nleh0sn2wiyvf0', 'SPLASH', 'splash', NULL, 'Casa e Construção', 'Construção e Reforma', 'COMÉRCIO E INSTALAÇÃO DE PISCINAS, EQUIPAMENTOS DE FILTRAGEM E ACESSÓRIOS', 2010, 2015, NULL, '2026-04-01 02:00:09.644', '2025-08-05 22:20:28.984', 886, NULL, 1, 1995, 'Com mais de 10 anos no mercado, e muitas inovações constantes, a Splash é um modelo de franquia que está presente em todo território nacional, marcando presença na maior rede de piscinas pré-fabricadas do mundo, a iGUi. A participação da Splash no mercado nacional conta com um crescimento gradativo, e constante, com mais de 500 lojas localizadas nas mais diferentes cidades, de capitais a cidades menores por todo o Brasil.  Atualmente nossa rede conta com mais de 20 fábricas de produção de piscinas pré-fabricadas, somente em território nacional. Trazendo confiança com qualidade, inovação e excelência ao nosso cliente. Com objetivos e iniciativas traçadas, a Splash conta com um crescimento e popularização da sua marca, cada vez mais constante entre as famílias brasileiras. Atualmente detendo o selo de excelência no franchising brasileiro.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4875b2d2-7088-46bd-808a-c1a728deb4c3.jpg', 564, NULL, NULL, '2026-03-09 02:30:59.787', 'https://franquias.portaldofranchising.com.br/franquia-splash/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9ca9331c-f57f-4de0-b7ac-6ec8b832d20c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/546ae28f-04b3-4915-84b7-8608f232b647.png\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '200000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77el00nmeh0sm9uelt8o', 'BASICOISAS EXPRESS', 'basicoisas-express', NULL, 'Alimentação', 'Mercados e Distribuição', 'Mercado autônomo para condomínios e empresas, aberto 24 hrs. Home market para comodidade de moradores e funcionários. Mini mercado inteligente automatizado. Mercado sem funcionários, tendência mundial', 2022, 2023, NULL, '2026-04-01 02:00:09.654', '2025-08-05 22:20:28.989', 887, NULL, 1, 2018, '', NULL, 'SANTA CATARINA', 1, NULL, 82, NULL, NULL, '2026-03-09 02:31:37.810', 'https://franquias.portaldofranchising.com.br/franquia-basicoisas-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '10100', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ep00nneh0sjo40pxw0', 'BURGER KING BRASIL', 'burger-king-brasil', NULL, 'Alimentação', 'Bares e Restaurantes', 'Uma empresa inovadora, conduzida por pessoas experientes que têm na qualidade dos produtos, na excelência do atendimento e na busca incessante por vantagens competitivas.', 2011, 2018, NULL, '2026-04-01 02:00:09.663', '2025-08-05 22:20:28.994', 888, 'df170f80-7453-425d-9613-b55ed556e14e', 1, 1953, 'Essa é a hora de se juntar a franquia Burger King Brasil. Fundado em 1954, o BURGER KING® é a segunda maior rede de hambúrgueres do mundo. Lar original do WHOPPER®, possui mais de 15 mil lojas, servindo mais de 11 milhões de consumidores por dia em mais de 100 países ao redor do mundo.  Aproximadamente 90% dos restaurantes BURGER KING® pertencem e são operados por franquias independentes, muitas delas administradas por empresas familiares que estão no ramo há décadas. A franquia Burger King do Brasil é um master franqueado do Burger King Corporation no país. Nossa marca está aqui desde 2004, quando inauguramos nosso primeiro restaurante no Shopping Ibirapuera, mas foi em 2011, após o Burger King Corporation ser adquirido pelo grupo 3G capital, que iniciamos a nossa operação própria aqui no país, através de uma joint venture entre Vinci Partners e 3G Capital. De 2011 para cá já crescemos muito, e nossos números comprovam isso. Somos uma empresa que em meados de 2011 possuía alguns colaboradores em São Paulo distribuídos entre 17 pontos de venda. Hoje, já somamos mais de 11 mil colaboradores e estamos presentes em todos os estados brasileiros, com mais de 600 pontos de venda. Acreditamos que o nosso bem mais valioso é a nossa Gente. Por isso, apostamos na carreira de nossos colaboradores, com o objetivo de impulsionar a visão de dono daqueles que, junto com a gente, acreditam em um Sonho Grande: ser a mais prazerosa experiência de alimentação. Para sustentar esse sonho, nos focamos em quatro pilares: sermos a marca de fast food preferida, mais rentável, com pessoas talentosas e com forte presença nacional.', 'What is Lorem Ipsum?\r\nLorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum.\r\n\r\nWhy do we use it?\r\nIt is a long established fact that a reader will be distracted by the readable content of a page when looking at its layout. The point of using Lorem Ipsum is that it has a more-or-less normal distribution of letters, as opposed to using \'Content here, content here\', making it look like readable English. Many desktop publishing packages and web page editors now use Lorem Ipsum as their default model text, and a search for \'lorem ipsum\' will uncover many web sites still in their infancy. Various versions have evolved over the years, sometimes by accident, sometimes on purpose (injected humour and the like).\r\n\r\n\r\nWhere does it come from?\r\nContrary to popular belief, Lorem Ipsum is not simply random text. It has roots in a piece of classical Latin literature from 45 BC, making it over 2000 years old. Richard McClintock, a Latin professor at Hampden-Sydney College in Virginia, looked up one of the more obscure Latin words, consectetur, from a Lorem Ipsum passage, and going through the cites of the word in classical literature, discovered the undoubtable source. Lorem Ipsum comes from sections 1.10.32 and 1.10.33 of \"de Finibus Bonorum et Malorum\" (The Extremes of Good and Evil) by Cicero, written in 45 BC. This book is a treatise on the theory of ethics, very popular during the Renaissance. The first line of Lorem Ipsum, \"Lorem ipsum dolor sit amet..\", comes from a line in section 1.10.32.\r\n\r\nThe standard chunk of Lorem Ipsum used since the 1500s is reproduced below for those interested. Sections 1.10.32 and 1.10.33 from \"de Finibus Bonorum et Malorum\" by Cicero are also reproduced in their exact original form, accompanied by English versions from the 1914 translation by H. Rackham.\r\n\r\nWhere can I get some?\r\nThere are many variations of passages of Lorem Ipsum available, but the majority have suffered alteration in some form, by injected humour, or randomised words which don\'t look even slightly believable. If you are going to use a passage of Lorem Ipsum, you need to be sure there isn\'t anything embarrassing hidden in the middle of text. All the Lorem Ipsum generators on the Internet tend to repeat predefined chunks as necessary, making this the first true generator on the Internet. It uses a dictionary of over 200 Latin words, combined with a handful of model sentence structures, to generate Lorem Ipsum which looks reasonable. The generated Lorem Ipsum is therefore always free from repetition, injected humour, or non-characteristic words etc.\r\n\r\n5\r\n\tparagraphs\r\n\twords\r\n\tbytes\r\n\tlists\r\n\tStart with \'Lorem\r\nipsum dolor sit amet...\'\r\n', 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4ac0a880-d7c9-4d6d-b4f4-ffda41af59ec.png', 1238, NULL, NULL, '2026-03-09 02:31:56.924', 'https://franquias.portaldofranchising.com.br/franquia-burger-king-valor/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2c20a79a-3105-4f24-814e-bbeb32f548ad.jpg\"]', 1, 5, 5, 1, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77eu00noeh0sauosdbze', 'EXPERIMENTO', 'experimento', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Educação Internacional e programas de intercâmbio cultural no mundo inteiro', 1998, 2004, NULL, '2026-04-01 02:00:09.672', '2025-08-05 22:20:28.998', 889, NULL, 1, 1964, 'A Experimento é a maior rede especializada exclusivamente em intercâmbio cultural. Desde 1964 atuando no país, é a pioneira no Brasil e, portanto, quem mais entende do assunto. Somos Experts em intercâmbio, com muito orgulho e paixão pelo o que fazemos. Atualmente contamos com mais 60 lojas, sendo 5 próprias. Além de ser membro das mais importantes federações internacionais, a Experimento é membro exclusivo da FEIL (Federation of the Experiment in International Living), primeira do mundo a promover vivência intercultural no mundo, em 1932. Também vem conquistando desde 2011 o Selo de Excelência em Franchising pela ABF e eleita a melhor Franquia de Cultura e Lazer do Brasil em 2015 e 2017, pelo Guia de Franquias Pequenas Empresas, Grandes Negócios. A franquia Experimento foi eleita por 5 anos consecutivos (2010 | 2011 | 2012 | 2013 e 2014), a melhor agência de intercâmbio da América Latina através do Star Awards for International Education, um prêmio internacional promovido pela Language Travel Magazine, em Londres. A votação é realizada pelas organizações educacionais internacionais, que elegem as melhores escolas e agências do mundo inteiro. Com a 5ª premiação, a Experimento se torna membro do seleto grupo STM Super Star Hall of Fame, honrada com o título perpetuamente.\n \nTambém vem conquistando desde 2011 o Selo de Excelência em Franchising pela ABF, incluindo o de 2016, o que certifica importância e satisfação dentre seus franqueados. Eleita a melhor Franquia de Cultura e Lazer do Brasil em 2015 e 2017, pelo Guia de Franquias Pequenas Empresas, Grandes Negócios.\n \nPara pessoas com perfil comercial e espírito empreendedor, a rede traz a grande chance de investir em um negócio em constante expansão. O mercado de educação internacional cresce em média 20% ao ano no Brasil e movimentou mais de US$ 1 bilhão no país em 2012, o que representa uma excelente oportunidade de negócio. O franqueado Experimento conta com completa estrutura à disposição para implantação e acompanhamento do novo negócio.\n \nA rede oferece programas que atendem aos mais altos padrões de qualidade. Isto significa programas de intercâmbio com as melhores instituições do mundo, atendimento realizado por profissionais qualificados no Brasil e no exterior, rede com mais de 50 lojas em todo o país e uma linha completa de produtos e serviços para que a viagem seja tranquila e segura.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/71de9122-bad9-4465-86e2-7694512edf60.png', 54, NULL, NULL, '2026-03-09 02:32:54.881', 'https://franquias.portaldofranchising.com.br/franquia-experimento-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ez00npeh0sm4th7vfe', 'ACADEMIA GAVIÕES', 'academia-gavioes', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Academias', 2019, 2020, NULL, '2026-04-01 02:00:09.681', '2025-08-05 22:20:29.004', 890, NULL, 1, 1974, 'Fundada como escola de Karatê em 1974, a Gaviões tem uma história de pioneirismo e sucesso. Pioneira na integração de modalidades e criação do conceito de academia multisserviços, integrando artes marciais, musculação, diversas modalidades fitness, pilates e também a primeira rede de academias a funcionar 24horas por dia no Brasil. \nNa vanguarda da inovação, é reconhecida por oferecer as maiores e mais completas salas de musculação de São Paulo e reconhecida como uma das escolas de artes marciais mais tradicionais da capital paulista.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/08e9771c-5bb3-4ce2-b079-54faa3577cb3.jpg', NULL, NULL, NULL, '2026-03-09 02:34:15.775', 'https://franquias.portaldofranchising.com.br/franquia-academia-gavioes/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '1085000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77f400nqeh0sx57vo81v', 'ACADEMIA CORPO E SAÚDE', 'academia-corpo-e-saude', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Academia', 2024, 2024, NULL, '2026-04-01 02:00:09.689', '2025-08-05 22:20:29.009', 891, NULL, 1, 1998, '', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2b4c6979-38ab-4a87-afcc-11340aa3a326.png', 23, NULL, NULL, '2026-03-09 02:34:50.835', 'https://franquias.portaldofranchising.com.br/franquia-academia-corpo-e-saude-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1000000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77f900nreh0sve79hh48', 'MUNDO TERRA', 'mundo-terra', NULL, 'Moda', 'Vestuários', 'Desde 1999 proporcionando conexões reais e verdadeiras experiências equipando nossos clientes para suas viagens e aventuras com mais conforto e segurança pelo nosso planeta, nosso Mundo Terra!', 2014, 2020, '[\"https://www.youtube.com/watch?v=gx5nSMNhbxo\"]', '2026-04-01 02:00:09.698', '2025-08-05 22:20:29.014', 892, NULL, 1, 1999, 'A MUNDO TERRA trouxe um pouco do mundo outdoor e do estilo de vida ao ar livre para cidade quando abriu sua primeira unidade em 1999 na Pedroso de Morais 1085 no coração de Pinheiros em Sampa! Produtos como acessórios calçados, equipamentos e vestuário para atividades e viagens de lazer e aventura estavam disponíveis aos entusiastas desse mercado que tinham dificuldade em encontrar esses produtos no Brasil.  Iniciamos milhares de clientes ao longo dos anos com informação, conforto e segurança em suas atividades que muitas vezes são verdadeiros projetos de vida, sonhos que se materializam. Somos especialistas, verdadeiramente, apaixonados pelo nosso mercado, a inovação está muito presente em nosso dia a dia. Curiosos! Estamos sempre procurando evoluir pensando com muito carinho nas pessoas que envolvem todo nosso ecossistema para que tenham uma experiência inesquecível, desde o nosso time, no carinho e cuidado dentro de casa nas informações que transmitimos consultoria dos produtos, serviço que entregamos para aliados ao planejamento e a preparação dos nossos clientes sejam fatores determinantes em suas conquistas! Juntos vamos engajar mais pessoas no estilo de vida ao ar livre e disseminar essa Cultura, impactando a vida das pessoas para que criem mais conexões, e que estas possam ser seu o “combustível” para que melhorem sua qualidade de vida, tragam mais saúde e bem-estar no longo prazo! Construímos assim uma sociedade mais humana, lindas histórias, contada por cada uma dessas pessoas, a cada momento mágico vivido, a cada novo suspiro pelo fato de ter feito algo novo pela primeira vez, e queremos que você venha participar dessa jornada conosco! Venha para o nosso Mundo!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2ac28dfd-c630-444a-a90d-96f5e19ce355.png', 6, NULL, NULL, '2026-03-09 02:35:11.891', 'https://franquias.portaldofranchising.com.br/franquia-mundo-terra/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '349000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ff00nseh0sr71i9fbc', 'PAZZI PER GELATO', 'pazzi-per-gelato', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Gelateria Artesanal', 2017, 2024, NULL, '2026-04-01 02:00:09.707', '2025-08-05 22:20:29.019', 893, NULL, 1, 2016, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/875ef6e5-8bd2-4772-8bff-f2bd881fcb20.png', 7, NULL, NULL, '2025-07-15 15:06:57.000', 'https://franquias.portaldofranchising.com.br/franquia-pazzi-per-gelato-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77fk00nteh0sap5ilbr4', 'SUPERRICO', 'superrico', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'A SuperRico é uma Plataforma de Saúde Financeira que conecta pessoas e planejadores financeiros. Através dos nossos serviços ajudamos os brasileiros a manterem uma boa saúde financeira.', 2021, 2022, '[\"https://www.youtube.com/watch?v=8f63aaDU-ZU\",\"https://www.youtube.com/watch?v=xumSh18DkqY\",\"https://www.youtube.com/watch?v=px9MuqjZUlQ\",\"https://www.youtube.com/watch?v=Gh6NLAt0Sp8\"]', '2026-04-01 02:00:09.716', '2025-08-05 22:20:29.024', 894, NULL, 1, 2017, 'A SuperRico nasceu em 2014 como um blog de conteúdo de educação financeira. Em 2016 se tornou uma empresa de prestação de serviços de planejamento financeiro para pessoas e famílias. A empresa tem a missão de tornar possível a todos os seres humanos a conquista e a manutenção do bem-estar financeiro. Nossa meta é democratizar o acesso à educação financeira e ao planejamento financeiro para que toda a sociedade brasileira conquiste e mantenha uma vida financeira saudável. Criamos uma plataforma de educação financeira e planejamento financeiro e desenvolvemos mecanismos que a tornasse disponível à sociedade de tal forma que todo cidadão possa ter acesso e se sinta motivado a utilizá-la para atingir um bom nível de bem-estar financeiro. Disseminamos nossa metodologia “Curva de Vitalidade Financeira®” por meio de ferramentas que possam ser utilizadas por todas as pessoas, fazendo parcerias com as mais variadas instituições e empresas, formando uma grande rede nacional onde todos serão beneficiados. A SuperRico sempre oferecerá aos seus clientes, aos planejadores financeiros e a sociedade em geral, soluções que melhor atendam às necessidades dessas pessoas, sem obter favorecimentos ou benefícios das empresas envolvidas no fornecimento desses produtos e serviços. Nossos valores: Pessoas comprometidas e engajadas Independência para alinhar interesses dos clientes e planejadores financeiros Transparência em tudo que fazemos Compromisso com a diversidade, equidade e inclusão  Cumprimento do código de ética Crescimento com responsabilidade social e sustentabilidade', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/81657fbb-a781-4db3-aeeb-24bc574e9fe3.jpg', 67, NULL, NULL, '2026-03-09 02:36:19.863', 'https://franquias.portaldofranchising.com.br/franquia-superrico/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '12500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77fp00nueh0slm01y1uu', 'Instituto Visão Solidária', 'instituto-visao-solidaria', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', '', 2022, 2022, '[\"https://www.youtube.com/watch?v=c1WRBqffMGc\",\"https://www.youtube.com/watch?v=ac11YAr5NpM\",\"https://www.youtube.com/watch?v=4Kri4nk1y3Q\",\"https://www.youtube.com/watch?v=LpJ7RnqLd5c\",\"https://www.youtube.com/watch?v=s1LNqa6548Q\"]', '2026-04-01 02:00:09.725', '2025-08-05 22:20:29.030', 895, NULL, 1, 2015, 'Fundado no ano de 2015, com o intuito de inovar e destacar-se no setor óptico, o Instituto Visão Solidária consolidou-se no mercado por comercializar produtos com preços acessíveis sem perder sua qualidade, possibilitando desta forma que seus clientes adquiram óculos de grau e de sol sem necessidade de gastos exorbitantes.', NULL, 'Mato Grosso', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/93c4d844-8978-473a-a95a-c826237c4cb7.jpg', 160, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ab7a7ba1-4ebc-44ae-bb2e-af327511950e.jpg', '2026-03-09 02:37:16.148', 'https://franquias.portaldofranchising.com.br/franquia-instituto-visao-solidaria/', NULL, 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d3d67e4d-272a-4190-9338-11ff5f9584b7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/554b4d57-40e1-4462-9a64-e54a60d212de.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b5af4f42-5a20-4e94-a0d5-0c62c2294dbe.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d3c95c9a-bb8f-4bd3-8c58-c4c43e00748f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/58b6534b-675e-4a5c-af0f-e077feadfd01.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/75253d58-1974-438e-8550-bbb563a591a8.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '200000', NULL, NULL, NULL, '65000', '90000', '5.5', NULL, '115000', '20000', 30);
