INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77gq00nxeh0s4fb39q96', 'REPARU\'S EXPRESS', 'reparu-s-express', NULL, 'Limpeza e Conservação', 'REPAROS', 'Reparos e customuização de roupas em geral de maneira rápida, prática e com foco na entrega para o cliente.', 2019, 2024, NULL, '2026-04-01 02:00:09.752', '2025-08-05 22:20:29.067', 898, NULL, 1, 2012, '', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c8641724-9f5a-4ed8-93c4-955d2bdd5921.svg', 4, NULL, NULL, '2025-09-09 16:36:47.000', 'https://franquias.portaldofranchising.com.br/franquia-reparus-express-limpeza-e-conservacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77h200nyeh0si74a4uuc', 'CAMERITE', 'camerite', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'A Inteligência Artificial para câmeras. Uma plataforma em rede de inteligência sobre vídeos, para detectar eventos e sugerir ações para empresas e forças de segurança.', 2019, 2019, '[\"https://www.youtube.com/watch?v=eR_QxmlMLlY\",\"https://www.youtube.com/watch?v=uWEHxN1LgQ0\",\"https://www.youtube.com/watch?v=Ju3_lPzdjRs\"]', '2026-04-01 02:00:09.761', '2025-08-05 22:20:29.078', 899, NULL, 1, 2016, 'A Camerite nasceu para resolver um problema simples e ignorado por anos, imagens eram usadas só para ver, não para entender.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cc74653d-a291-4d73-8f4b-5599b51ce5b8.png', 266, NULL, NULL, '2026-03-09 02:44:59.717', 'https://franquias.portaldofranchising.com.br/franquia-camerite/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '39000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77he00nzeh0s039ebu5w', 'SUPER VISÃO PERÍCIAS AUTOMOTIVAS', 'super-visao-pericias-automotivas', NULL, 'Serviços Automotivos', 'Peças, Acessórios e Manutenção', 'Fundada em 2005 e com mais de 200 unidades espalhadas por todo país, a Super Visão realiza mais de 97 mil laudos por mês com metodologia própria e é uma referência no mercado.', 2017, 2018, '[\"https://www.youtube.com/watch?v=onVV7D9-Fec\",\"https://www.youtube.com/watch?v=kYUd8pa8Bmw\",\"https://www.youtube.com/watch?v=43tCHkfXFt4\",\"https://www.youtube.com/watch?v=JtCEhaCWLPY\"]', '2026-04-01 02:00:09.774', '2025-08-05 22:20:29.090', 900, NULL, 1, 2005, 'A Super Visão Vistorias Automotivas é uma rede de franquias fundada em 2005 na cidade de São Paulo / SP, com o intuito de ajudar os clientes a adquirirem o seu automóvel com procedência e consequentemente diminuir o roubo e furto de veículos. Atualmente a rede Super Visão possui mais de 140 unidades distribuídas nas principais cidades do país e produz mensalmente mais de 80.000 laudos. A Super Visão preza pela qualidade de seus procedimentos e serviços e para garantir a seus clientes o melhor, todas suas unidades possuem certificado de qualidade ISO 9001 e seguro de responsabilidade cível. Emprega mais de 700 pessoas de forma direta e milhares de forma indireta e está em plena expansão.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/984711fb-1335-4e0b-acd9-8e7ed407f46d.jpg', 183, NULL, NULL, '2026-03-09 18:00:19.251', 'https://franquias.portaldofranchising.com.br/franquia-super-visao-pericias-automotivas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '180000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77hj00o0eh0ss5mycodp', 'CVC BRASIL', 'cvc-brasil', NULL, 'Hotelaria e Turismo', 'AGÊNCIAS DE TURISMO', 'AGÊNCIAS E OPERADORA DE TURISMO.', 2012, 2014, NULL, '2026-04-01 02:00:09.785', '2025-08-05 22:20:29.096', 901, NULL, 1, 1972, 'A CVC opera no mercado brasileiro há mais de 52 anos, sendo a maior operadora de viagens e líder na preferência do consumidor brasileiro. A CVC possui a maior rede de distribuição de produtos turísticos do varejo nacional, com mais de 1.280 agências exclusivas franqueadas. Conheça nossas lojas no Modelo Alvenaria, Modelo Modular e Modelo Quiosque. FAÇA PARTE DA MAIOR REDE DE FRANQUIAS DE TURISMO DO BRASIL', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/48c40aa4-f9cf-4a25-85c2-51b84c8e60af.jpg', 1361, NULL, NULL, '2026-02-24 14:17:03.000', 'https://franquias.portaldofranchising.com.br/franquia-cvc-turismo/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/21982d23-a31b-42ac-8568-37f02e041b76.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ca87424b-4420-4b33-86f0-9f19c73b1e77.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7ddd8454-3a9f-45a5-8f88-24d564eed247.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/44ee4fbf-0e93-401a-8e60-3dde58e38f3b.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '80000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77hq00o1eh0shnvmqaj7', 'PUBLICARGA', 'publicarga', NULL, 'Comunicação, Informática e Eletrônicos', 'Comunicação e Mídia', 'Publicidade digital em telas de totens carregadores de Celular e wi-fi marketing', 2025, 2025, NULL, '2026-04-01 02:00:09.802', '2025-08-05 22:20:29.102', 902, NULL, 1, 2024, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f675d103-1ce9-43b0-88ba-e380e02d165f.png', 7, NULL, NULL, '2026-03-09 18:00:53.313', 'https://franquias.portaldofranchising.com.br/franquia-publicarga/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77hw00o2eh0s7lviur15', 'IGUI', 'igui', NULL, 'Casa e Construção', 'Construção e Reforma', 'Comércio e Instalação de Piscinas pré Fabricadas, Equipamentos de Filtragem, Acessórios, Produtos químicos e Móveis para a área de Lazer', 2008, 2008, '[\"https://www.youtube.com/watch?v=TiiXRxm-mns\",\"https://www.youtube.com/watch?v=337uO_a7MRg\"]', '2026-04-01 02:00:09.812', '2025-08-05 22:20:29.108', 903, NULL, 1, 1995, 'Com quase 30 anos de mercado e muita inovação, a iGUi é “Líder Mundial no segmento de Piscinas Pré-fabricadas” e conta com mais de 1200 franquias em 54 países, fabricando cerca de 80.000 piscinas por ano em todo o Mundo.  A participação da iGUi no mercado interno e externo cresce progressivamente, hoje é uma das franqueadoras com maior número de lojas fora do Brasil, presente em 5 continentes.  A Rede oferece uma das melhores e mais lucrativas franquias, abastecidas por mais de 20 fábricas geograficamente distribuídas pelo Brasil. E com fábricas pelo mundo: Argentina, México, USA, Portugal e Paraguai.  A marca é membro da IFA (International Franchise Association) e detentora de variados prêmios que mostram e comprovam sua excelência.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/62611ad8-e080-497b-a8b1-45964cc40fda.png', 389, NULL, NULL, '2026-03-09 18:01:14.237', 'https://franquias.portaldofranchising.com.br/franquia-igui-lazer/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/abe46d3f-dcfd-45c7-8442-2bf24d94214a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f64d04ad-bfc3-4ddb-9b3d-a79860c021d2.png\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '2150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77i300o3eh0sot1tjpll', 'TODESCHINI', 'todeschini', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Prestação de serviços de projeto de interiores e montagem de móveis planejados.', 2017, 2017, '[\"https://www.youtube.com/watch?v=_atIfk9UjDE\"]', '2026-04-01 02:00:09.823', '2025-08-05 22:20:29.115', 904, NULL, 1, 1939, 'UMA DAS MAIORES FÁBRICAS DE MÓVEIS PLANEJADOS DA AMÉRICA LATINA \nParte de um grupo de negócios consolidado com empresas nos ramos mobiliário, pecuária, reflorestamento e financeira, a Todeschini é referência no país pela sua solidez, tradição, confiança e capacidade de honrar seus investidores. • Parque fabril de 125 mil m²\n• Produção de 600 ton/dia\n• Certificações internacionais ISO 9001 e 14001\n• Máquinas de altíssimo padrão\n• Logística eficiente\n• 92 lojas no Brasil\n• Presença em 7 países', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8256e11f-0f2c-42cf-a90f-505f1627186b.svg', 100, NULL, NULL, '2026-03-09 18:01:50.449', 'https://franquias.portaldofranchising.com.br/franquia-todeschini-moveis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '1780000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
