INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ip00o7eh0s8ja640r7', 'MAISLASER DEPILAÇÃO', 'maislaser-depilacao', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A Maislaser by Ana Hickmann é uma franquia lucrativa e consolidada em depilação e estética a laser, com operação simplificada, tecnologia exclusiva e rentabilidade acima de 30%, a maior do mercado!', 2018, 2019, '[\"https://www.youtube.com/watch?v=3-PcvjQYweY\"]', '2026-04-01 02:00:09.860', '2025-08-05 22:20:29.138', 908, NULL, 1, 2018, 'A Maislaser by Ana Hickmann é uma rede de clínicas reconhecida pela excelência em depilação e estética a laser, combinando tecnologia exclusiva e resultados comprovados. Nossos tratamentos são seguros, confortáveis e eficazes para todos os tons de pele, inclusive as bronzeadas. Depilação a laser: O equipamento exclusivo da Maislaser (Maistech) reúne as três principais tecnologias do mercado com três comprimentos de ondas que entregam melhor resultado e produtividade. MAIS seguro e confortável  MAIS eficaz / 1800W MAIS econômico MAIS rapidez na aplicação  MAIS autoestima e bem-estar Tratamentos dermato estéticos: A Maislaser também realiza mais de 22 protocolos para tratamentos dermato estéticos em todo o corpo. O equipamento exclusivo utiliza o laser Ndyag e atende os procedimentos mais procurados, como remoção de tatuagem e micropigmentação, clareamento íntimo e de manchas, tratamento para acne, melasma, rosácea, estrias, olheiras, cicatrizes, Peeling de Hollywood e muito mais. Os sócios: *Sidney Kalaes: presidente do Grupo Kalaes (Holding Multissetorial de Franquias), tem formação em administração de empresas e mais de 31 anos de experiência como líder, master e fundador de várias marcas de sucesso no mercado.  *Ana Hickmann: apresentadora e empresária de sucesso que traz para a Maislaser muita credibilidade, força, conhecimento, valor e exposição, proporcionando diferenciais e crescimento aos envolvidos no negócio.  *Wlamir Bello: fundador da rede Maislaser, empresário especialista em gestão empresarial, estratégia de negócios e marketing. Tem MBA em gestão empresarial e graduação em publicidade e propaganda.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/41abd10c-c802-4df0-b1ee-21e475ea8376.jpg', 190, NULL, NULL, '2026-03-09 03:09:09.513', 'https://franquias.portaldofranchising.com.br/franquia-maislaser-depilacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
