INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77j400oaeh0srfxgyvzr', 'BEM QUERER DONUTS', 'bem-querer-donuts', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'A Bem Querer consiste em uma loja especializada em donuts. O foco da marca é fornecer uma doce experiência. Para isso, as lojas são construídas com um visual temático e instagramavel.', 2022, 2022, NULL, '2026-04-01 02:00:09.888', '2025-08-05 22:20:29.152', 911, NULL, 1, 2019, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a224b715-0bd7-4a08-a8d0-78a75ea83b2a.jpg', 24, NULL, NULL, '2025-08-15 10:23:12.000', 'https://franquias.portaldofranchising.com.br/franquia-bem-querer-donuts-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77j900obeh0svve9utcq', 'ERA', 'era', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Consultoria em eficiência operacional, otimização de custos, soluções inovadoras em estratégia de negócios, gestão empresarial, otimização de processos e redução de custos', 1992, 2005, '[\"https://www.youtube.com/watch?v=4pmTpi9rM7M\",\"https://www.youtube.com/watch?v=Zz60nYjeSNU\"]', '2026-04-01 02:00:09.897', '2025-08-05 22:20:29.157', 912, NULL, 1, 1992, 'FAÇA PARTE DA REDE LÍDER EM CONSULTORIA EMPRESARIAL Expense Reduction Analysts (ERA) é uma das maiores  franquias  em Business Strategy, Eficiência Operacional  e  Gestão Empresarial, com mais de 700 consultores, presentes em mais de 35 países. Em 2019, 2020 e 2021 ERA foi ganhadora do “Selo de Excelência em Franchising – ABF”. Foi nomeada \" World-Class Franchise” \" pelo Franchise Research Institute em 2015, 2016 e 2017. Em 2018 & 2019, a ERA foi premiada como “Best White-Collar Franchise” pela Global Franchise Magazine. Prêmios esses que atestam a seriedade e comprometimento da ERA com seus franqueados ao redor do mundo. Ao longo desses 30 anos, atendemos mais de 5.000 clientes,  entregamos  mais de 30.000 projetos, dos mais diversos segmentos,  como por exemplo logística integrada, matriz energética, segurança patrimonial e muito mais. Essa diversificada atuação  faz da  ERA  a maior e mais experiente consultoria em gestão empresarial do mundo. Noss@  Consultor Ideal – Na Expense Reduction Analysts (ERA)  noss@ candidat@ ideal é inteligente, motivad@ e tem a disposição de seguir uma comprovada metodologia de 30 anos de mercado. Sente-se confortável quer seja com donos de empresas ou  executiv@s C-level. É abert@  a  trabalhar em parceria com outr@s franquead@s ERA, utilizando sua expertise amparad@ por nossa dinâmica de negócios.  Junte-se a nós para  o próximo passo em sua carreira, onde você será SENHOR DO SEU TEMPO e utilizará todo o conhecimento adquirido em sua carreira profissional. Você tem  desejo de assumir o controle do seu futuro? – Nossa rede global de mais de 700 consultores vem de muitas indústrias diferentes. O que tod@s têm em comum é o desejo de assumir o controle de suas vidas, ganhar o que merecem e alavancar  de forma significativa sua experiência profissional . Aprimore  suas habilidades com nosso conhecimento – Nós ajudamos a aprimorar  suas habilidades e potencializar seu conhecimento  para que você possa operar seu próprio negócio de consultoria ERA. Combinar sua ambição e expertise com nossa rede de Franquead@s, nossos  processos e  ferramentas é uma maneira comprovada de acelerar o seu caminho para o sucesso. Treinamento constante – ERA conta com uma exclusiva academia de treinamento de nível internacional (ERA Training Academy), que @ ajudará a  iniciar sua jornada de êxito como consultor@ de alto desempenho. Você trabalhará em estreita colaboração com nossas equipes de apoio  para desde o início empreender amparado por nossa experiencia.   E mais:  em nossa plataforma digital LearnUpon você terá acesso ilimitado  a conteúdo de melhores práticas, aprimoramento técnico e reciclagem constante para impulsionar seu negócio.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7a657c5e-9138-4f2d-bb57-bbb692e7820b.png', 11, NULL, NULL, '2026-03-09 18:10:20.423', 'https://franquias.portaldofranchising.com.br/franquia-era-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '316925', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77je00oceh0s5itttr4p', 'LOPES', 'lopes', NULL, 'Casa e Construção', 'Serviços e Imobiliárias', 'Intermediação imobiliária de venda e locação.', 2014, 2019, '[\"https://www.youtube.com/watch?v=7n1qRniB9-w\",\"https://www.youtube.com/watch?v=rz_h6XBCG7U\"]', '2026-04-01 02:00:09.906', '2025-08-05 22:20:29.162', 913, NULL, 1, 1935, 'Somos a maior franquia de imóveis da América Latina e oferecemos aos nossos franqueados oportunidades de negócios únicas, com a maior atratividade e capilaridade no mercado imobiliário. \nCom mais de 88 anos de história, somos referência no setor e especialistas em soluções em todos os segmentos, prestando assessoria a incorporadores, corretores, compradores e vendedores de lançamentos e imóveis prontos. \nDesde a abertura de capital, em 2006, já ajudamos mais de 500 mil famílias a encontrarem um lar, intermediando aproximadamente 493 mil unidades, que ultrapassam R$176 bilhões de VGV, nos mantendo como a líder de mercado.  \nE hoje, o site da Lopes é uma das maiores plataformas imobiliárias do Brasil, gerando mais de 15,5 mil leads por mês.  \nAlém de ser o maior portfólio da América Latina, com 250 mil imóveis prontos e lançamentos. \nAqui na Lopes 1 imóvel é vendido ou alugado a cada 3 horas! \nGraças a isso, temos sido a vencedora do TOP Imobiliário, na categoria de VGV, como a rede que mais realiza lançamentos, desde 1993. \nE tudo, porque não paramos no tempo. \nEstamos sempre investindo em tecnologias e inovando em ferramentas modernas que reforçam o papel da Lopes como referência no segmento. \nAcreditamos que dividir é multiplicar. \nE por isso, queremos dividir com você toda a nossa capacidade de se adaptar, nosso conhecimento e ferramentas exclusivas para corretores e imobiliárias. \nAjudar as pessoas a conquistarem o seu lugar é o que nos move em busca de soluções completas para criar experiências encantadoras.     Motivos para escolher a Rede Lopes: A marca mais reconhecida no mercado imobiliário; + de 88 anos de tradição em intermediações imobiliárias; + de 250 mil imóveis prontos e lançamentos; + de 14 mil corretores associados; Parceira dos maiores portais imobiliários; Parceira do Itaú, para financiamentos via CrediPronto.   Motivos para se tornar um franqueado da Rede Lopes: Ferramentas exclusivas que te ajudam a gerir o seu negócio; O maior potencial de Leads qualificados direcionados às franquias; Suporte completo para o Marketing da sua unidade; Capacitação do seu time de corretores e suporte contínuo; Workshops periódicos sobre diferentes assuntos; Know-How no mercado primário.   Principais dores do setor imobiliário: Não sei como me posicionar no ambiente digital imobiliário; Não consigo aumentar minha equipe de corretores; Tenho dificuldade em fazer a gestão da imobiliária e analisar meu desempenho; Preciso gerar mais leads e melhorar minha conversão de vendas; Gostaria de captar mais imóveis; Tenho dificuldade em participar e ter acesso aos lançamentos; Gostaria de compartilhar boas práticas com outros empresários do setor.   O que muda sendo franqueado da Rede Lopes: Resultados e lucratividade crescente; Diminuição no risco de investimento; Facilidade na gestão do negócio; Vantagem competitiva no mercado imobiliário.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/34e7f936-4faa-498d-9683-506decd93c39.jpg', 147, NULL, NULL, '2026-03-09 18:11:36.917', 'https://franquias.portaldofranchising.com.br/franquia-lopes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77jj00odeh0sv42tbcyx', 'SANCLÁ SAÚDE ANIMAL', 'sancla-saude-animal', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Franqueadora de Clínica veterinária 24 horas.', 2022, 2022, NULL, '2026-04-01 02:00:09.916', '2025-08-05 22:20:29.167', 914, NULL, 1, 2013, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/47427748-226d-4b0d-846d-7277eba6eea8.jpg', 17, NULL, NULL, '2026-03-09 18:13:02.491', 'https://franquias.portaldofranchising.com.br/franquia-sancla-saude-animal/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '482400', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77jo00oeeh0sn2o3h8pa', 'ATMO MÍDIA DIGITAL CORPORATIVA', 'atmo-midia-digital-corporativa', NULL, 'Comunicação, Informática e Eletrônicos', 'Comunicação e Mídia', 'Primeiramente somos apaixonados pelo que fazemos! Presente no mercado há mais de 30 anos oferecendo soluções em Eventos, TV Corporativa e Digital Signage. Amplo portifólio e cases de sucesso!', 2019, 2019, '[\"https://www.youtube.com/watch?v=Uj73LS76PGk\",\"https://www.youtube.com/watch?v=Zyg-3HtpaOo\",\"https://www.youtube.com/watch?v=58L0azvlU-o\"]', '2026-04-01 02:00:09.925', '2025-08-05 22:20:29.172', 915, NULL, 1, 1990, 'O modelo de franquia ATMO DIGITAL surgiu da ideia de favorecer e difundir serviços de alta qualidade, de forma regional, na área de Comunicação Corporativa com Soluções Áudio Visuais, TV Corporativa e Digital Signage.  \nNo mercado desde o ano de 1990, com mais de 2000 cidades atendidas em todo território nacional e mais de 10.000 eventos realizados, A ATMO DIGITAL alcançou amplo reconhecimento em comunicação dentro do universo corporativo. \nSer Franqueado ATMO é fazer parte de uma empresa que está no mercado há mais de 29 anos, sendo pioneira em Soluções para Comunicação Corporativa, sempre atuando com criatividade, inovação e qualidade na entrega final. \nSomos apaixonados pelo que fazemos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2b863aab-482a-4f83-8697-fc28c1db1cbd.jpg', 2, NULL, NULL, '2026-03-09 18:13:26.444', 'https://franquias.portaldofranchising.com.br/franquia-atmo-digital-corporativa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77jt00ofeh0s1ss6um2x', 'INSTITUTO EMBELLEZE', 'instituto-embelleze', NULL, 'Educação', 'EDUCAÇÃO', 'Formação profissional na área de beleza', 2003, 1993, '[\"https://www.youtube.com/watch?v=fEyXlvkSgXg\"]', '2026-04-01 02:00:09.934', '2025-08-05 22:20:29.177', 916, NULL, 1, 2003, 'Há mais de duas décadas, o Instituto Embelleze tem sido um pilar fundamental na capacitação de profissionais da beleza no Brasil. Com 22 anos de existência e uma história marcada pela excelência no ensino, o Instituto já formou mais de 2,5 milhões de alunos, oferecendo a eles as ferramentas e conhecimentos necessários para transformar suas vidas e as de outros. Presente em mais de 150 unidades espalhadas por 21 estados brasileiros e no exterior - 1 nos Estados Unidos e 1 na Costa Rica -, o Instituto Embelleze oferece uma vasta gama de cursos que atendem às demandas do mercado de beleza. São mais de 25 opções de formação, incluindo cursos profissionalizantes, especializações, cursos express e workshops. Entre os cursos mais procurados, estão os de cabelo e barbearia, manicure e pedicure e embelezamento do olhar (sobrancelhas e cílios). Ao longo dos anos, a instituição tem se consolidado como uma referência no mercado de beleza, tanto pela qualidade de seu ensino quanto pelo impacto social que promove. Ao formar profissionais altamente qualificados e comprometidos, o Instituto Embelleze contribui para o desenvolvimento do setor e para a realização dos sonhos de milhares de pessoas.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7d9b2fde-cf8d-471a-9e9b-ca190ea89a17.png', 232, NULL, NULL, '2025-07-18 09:54:10.000', 'https://franquias.portaldofranchising.com.br/franquia-instituto-embelleze-beleza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77jz00ogeh0s177glslo', 'GINÁSTICA DO CÉREBRO', 'ginastica-do-cerebro', NULL, 'Educação', 'Treinamento Profissional e Capacitação', 'Curso de estimulação cognitiva, workshops e palestras, atendimento em empresas e escolas. Tipo de atuação: 1 - Modalidade Física', 2014, 2015, '[\"https://www.youtube.com/watch?v=Iko_IXMu0tk\"]', '2026-04-01 02:00:09.943', '2025-08-05 22:20:29.184', 917, NULL, 1, 2012, 'A franquia GINÁSTICA DO CÉREBRO nasceu de estudos e pesquisas na área de neurociência e neuroaprendizagem e foi criada pensando em desenvolver um trabalho voltado para a potencialização das capacidades cognitivas e emocionais de todas as pessoas, de qualquer faixa etária, com ou sem problemas de aprendizagem, especialmente destinado à área lógico-matemática através do uso do soroban, ferramenta destinada para o trabalho mental com cálculos e raciocínio rápido, visando promover uma maior capacidade de concentração, o trabalho motor fino, atenção e agilidade. Por meio de diversos outros jogos que estimulam a memória e o raciocínio lógico, criamos um material de desafio gradativo para potencializar o cérebro integralmente.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5a696e53-ee8d-4fab-bcd0-4c02043f6f09.png', 23, NULL, NULL, '2026-03-09 18:14:11.513', 'https://franquias.portaldofranchising.com.br/franquia-ginastica-do-cerebro-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '90000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77k500oheh0s9m152nts', 'DAMÁSIO EDUCACIONAL', 'damasio-educacional', NULL, 'Educação', 'EDUCAÇÃO', 'Curso preparatório para Exame da Ordem, Concursos Públicos em geral, Pós-Graduação e Cursos de Extensão.', 2004, 2010, '[\"https://www.youtube.com/watch?v=5-P1qvlTCF0\"]', '2026-04-01 02:00:09.952', '2025-08-05 22:20:29.189', 918, NULL, 1, 1970, 'O Damásio Educacional, com sede em São Paulo/SP, é a expressão de mais de 40 anos de qualidade em cursos preparatórios para concursos jurídicos, públicos e Exame de Ordem, e oferece também cursos de Pós-Graduação em Direito. Possui altos índices de aprovação em concursos e no Exame de Ordem, tendo como grande diferencial o corpo docente, formado por professores, mestres e doutores altamente reconhecidos no mercado. A Pós-Graduação é certificada pela Faculdade Damásio, referência no ensino jurídico no Brasil e uma das seis faculdades de Direito na Cidade de São Paulo credenciadas com o selo OAB Recomenda.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7a58a489-faa9-41f9-90c6-91fec4d8aecf.png', 65, NULL, NULL, '2025-07-17 14:04:14.000', 'https://franquias.portaldofranchising.com.br/franquia-complexo-educacional-damasio-de-jesus-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77kb00oieh0s97w3qaj8', 'IDEAL DRESSES', 'ideal-dresses', NULL, 'Moda', 'Vestuários', 'Atelier especializado em confecção e aluguel de vestidos de noiva.', 2020, 2025, NULL, '2026-04-01 02:00:09.961', '2025-08-05 22:20:29.195', 919, NULL, 1, 2007, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4ee33ad5-476c-41d4-887c-639470ee6fa0.png', 9, NULL, NULL, '2026-03-09 18:14:55.130', 'https://franquias.portaldofranchising.com.br/franquia-ideal-dresses/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77kg00ojeh0se1p77f3b', 'GRUPO VILLELA AUDITORIA/CONSULTORIA EMPRESARIAL', 'grupo-villela-auditoria-consultoria-empresarial', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'teste', 2016, 2023, '[\"https://www.youtube.com/watch?v=Lc8DK-PX6xs\"]', '2026-04-01 02:00:09.970', '2025-08-05 22:20:29.200', 920, NULL, 1, 2005, 'Tenha sua franquia da primeira Fincare brasileira, especialista em cuidar da saúde financeira das empresas. O mercado brasileiro é vasto e diversificado, e na busca por soluções inovadoras, o Grupo Villela destaca-se como uma referência, atendendo empresas de todos os segmentos e portes. Somamos mais de 20 anos de experiência em renegociação bancária, regularização fiscal, alavancagem financeira e recuperação empresarial. Descubra o que faz da nossa franquia uma proposta única, e entenda por que tantos empreendedores têm alcançado sucesso e rentabilidade conosco. Ao se tornar um franqueado Grupo Villela, você adere a um modelo de negócio de sucesso, se posicionando estrategicamente em um mercado de enorme potencial, com diversas oportunidades de obter resultados financeiros extraordinários. Franquia Nacional Grupo Villela Mercados-alvo: atue em todos os segmentos de mercado e em todo o território nacional, abrindo um leque amplo de oportunidades. Plataforma de prospecção: tenha acesso a uma plataforma pronta, um app que entrega potenciais clientes diretamente em suas mãos. Produtos de alta demanda: ofereça soluções altamente buscadas, posicionando-se à frente da concorrência. Inteligência Artificial em vendas: adote um método inovador e exclusivo de vendas, potencializado pela Inteligência Artificial. Transforme sua operação em uma potência de vendas inigualável.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1c9a6910-a9e2-4648-826e-a889e2b8b848.png', 513, NULL, NULL, '2026-03-09 18:15:17.383', 'https://franquias.portaldofranchising.com.br/franquia-grupo-villela-auditoria-consultoria-empresarial/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77kl00okeh0s03othykg', 'INFINITIBANK PRIME', 'infinitibank-prime', NULL, 'Serviços e Outros Negócios', 'SERVIÇOS ADMINISTRATIVOS', 'Banco digital voltado para o mercado corporativo, trazendo soluções financeiras para o mercado de Premiação e também um banco voltado par o mercado Imobiliário.', 2018, 2022, NULL, '2026-04-01 02:00:09.980', '2025-08-05 22:20:29.205', 921, NULL, 1, 1998, '', NULL, 'SÃO PAULO', 1, NULL, NULL, NULL, NULL, '2025-07-17 14:29:42.000', 'https://franquias.portaldofranchising.com.br/franquia-infinitibank-prime-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77kq00oleh0sx284zi3k', 'ISORADIOLOGIA', 'isoradiologia', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Desde 1994, a ISO RADIOLOGIA (ISOORTHOGRAPHIC) é uma referência em Diagnósticos Por Imagem em Odontologia, conta hoje com 23 operações em plena expansão.', 2012, 2023, NULL, '2026-04-01 02:00:09.989', '2025-08-05 22:20:29.210', 922, NULL, 1, 1994, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8129a89d-2e8d-4a58-80a8-82d8d1894223.jpeg', 23, NULL, NULL, '2026-03-09 18:16:29.764', 'https://franquias.portaldofranchising.com.br/franquia-isoradiologia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77kv00omeh0si00yqbf1', 'LET\'S FRITAS', 'let-s-fritas', NULL, 'Alimentação', 'Bares e Restaurantes', 'Invista na Let’s Fritas, franquia de fast food com produtos de alta aceitação, sem sazonalidade, operação simples e alta lucratividade. Vamos juntos, do primeiro pedido ao sucesso!', 2025, 2025, NULL, '2026-04-01 02:00:09.999', '2025-08-05 22:20:29.215', 923, NULL, 1, 2021, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/94ad586d-f1d6-4be7-a2f8-b5404f63dbd7.png', 4, NULL, NULL, '2026-03-09 18:16:52.759', 'https://franquias.portaldofranchising.com.br/franquia-lets-fritas-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '129119', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77l000oneh0st46uwwx0', 'ALPHABETO', 'alphabeto', NULL, 'Moda', 'Vestuários', 'A Alphabeto veste criança como criança de 0 a 12 anos há mais de 20 anos por todo o Brasil com peças confortáveis, estilosas, a preço acessível e com a essência sempre lúdica e infantil.', 2008, 2012, NULL, '2026-04-01 02:00:10.009', '2025-08-05 22:20:29.220', 924, NULL, 1, 1978, 'A Alphabeto acredita na alegria e na delicadeza da infância, por isso a marca assume a missão de vestir criança como criança. \nA linha de produtos desenvolvida para meninos e meninas de 0 a 14 anos reflete estilo, conforto, preço acessível, essência infantil e o investimento em beneficiamentos: bordados à mão, “silks” diferenciados e estampas exclusivas são os hits da marca. \nTodas as peças são desenvolvidas de acordo com as tendências em voga na Moda nacional e internacional. \nCom uma coleção totalmente coordenável, é possível criar “looks” divertidos, nos quais todos os detalhes se combinam, sem perder o foco no desenvolvimento de peças confortáveis e resistentes que acompanham o ritmo das crianças. \nO produto Alphabeto é sinônimo de qualidade e vem conquistando cada vez mais clientes em todo o território nacional. \nA empresa foi fundada no ano de 1978, na cidade de São João Nepomuceno, em Minas Gerais, com o nome de Children. \nContava inicialmente com apenas 9 colaboradores, fornecendo para pequenos varejistas locais. \nCom a aceitação do produto, o crescimento foi rápido e em pouco tempo já fornecia peças para as grandes lojas de departamento brasileiras, como a C&A e a antiga Mesbla. Em 1996, foi inaugurada a 1ª loja exclusiva no Shopping Nova América, no Rio de Janeiro. \nA Alphabeto conta com parque fabril próprio e com o que há de maquinário mais avançado em termos de tecnologia no mundo. \nEm 2014, a fábrica produz mais de 90% de seus produtos internamente e possui em torno de 800 colaboradores, que são constantemente treinados para que todas as etapas do processo de produção sejam cumpridas com qualidade e rapidez. \nO processo de produção inclui tecelagem, onde é produzida a malha, lavanderia industrial, máquinas de bordado a laser e máquinas eletrônicas de estamparia. \nA Alphabeto consegue oferecer ao consumidor final ampla variedade de produtos a um preço final bastante acessível.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/579e5dba-6ad5-40dd-bc31-c6331b0f3655.jpg', 72, NULL, NULL, '2026-03-09 18:17:15.207', 'https://franquias.portaldofranchising.com.br/franquia-alphabeto/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
