INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77nc00ozeh0solby70wm', 'Libero Corretora', 'libero-corretora', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', '', 2021, 2022, '[\"https://www.youtube.com/watch?v=6V69gRDw9eU\",\"https://www.youtube.com/watch?v=c_Mu1cVkRk8\",\"https://www.youtube.com/watch?v=nitijV8XwHA\",\"https://www.youtube.com/watch?v=8Jh5k2MlFa8\",\"https://www.youtube.com/watch?v=rg2VwMZKe-Q\"]', '2026-04-01 02:00:10.133', '2025-08-05 22:20:29.305', 936, NULL, 1, 2015, 'Somos a única franquia do mercado que cuida do cliente final. Isso é liberdade, isso é ser Líbero, com segurança entregamos um serviço de excelência. \nTemos um  Backoffice completo, com especialistas trabalhando para o franqueado, temos gratuitamente o curso SUSEP, garantindo a habilitação e autoridade no mercado. \nPossuímos uma plataforma Líbero Academy para capacitação contínua do franqueado;\nTemos suporte 24h para o franqueado e para o cliente final;\nApresentamos gestão jurídica, financeira e operacional centralizada na franqueadora, com cobrança ativa e acompanhamento de sinistros realizados pela franqueadora.', NULL, 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5b34fdac-c832-40b1-aa73-6f49c8f1d8a8.png', 198, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/66bcc9f9-98f1-4676-ad33-9b887a2ccb0c.jpg', '2026-03-09 18:21:11.081', 'https://franquias.portaldofranchising.com.br/franquia-libero-corretora/', 'Fixo Mensal', 'Vendas Líquidas', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/73aef6ae-89ad-4124-a107-a852833bf0df.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/47416ba2-71c3-4b1a-9c47-08a448b7fefb.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/af959c86-7875-45b0-a975-c696b2aa1502.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/37b5c66d-4672-4e9e-82c4-35c520b83364.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/32e6ddc7-5528-4cbf-a823-68b185e3fbc2.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/03517c8c-f084-4c51-ab05-97c06d703381.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '80000', NULL, NULL, NULL, '55000', NULL, '15', NULL, '15000', '10000', 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ni00p0eh0svehp3rqs', 'TRANSDESK', 'transdesk', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'A Transdesk evoluiu de serviços para caminhoneiros à uma consultoria especializada, oferecendo soluções integradas e expandindo sua presença nacional com uma rede de franquias.', 2023, 2024, NULL, '2026-04-01 02:00:10.142', '2025-08-05 22:20:29.310', 937, NULL, 1, 2008, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fc4f7b61-88e7-47db-b426-899a790c151a.png', 59, NULL, NULL, '2025-12-26 16:56:07.000', 'https://franquias.portaldofranchising.com.br/franquia-transdesk-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '35000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77no00p1eh0skunjrdnv', 'TURQUESA ESMALTERIA', 'turquesa-esmalteria', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A Turquesa Beleza & Bem-Estar oferece a melhor experiência ao cliente que procura serviços diferenciados para unhas, como também serviços complementares: depilação, sobrancelhas, cabelo e estética.', 2015, 2018, NULL, '2026-04-01 02:00:10.152', '2025-08-05 22:20:29.316', 938, NULL, 1, 2014, 'Lutamos pela democratização da beleza proporcionando um ambiente diferenciado, acolhedor e acessível à todos. \nUm salão de beleza completo onde a cliente desfruta momentos de relaxamento e descontração, enquanto cuida de toda sua beleza. \nE para quem quer empreender no promissor segmento da beleza, a Turquesa oferece vários modelos de composição de serviços que vai desde manicure tradicional e unhas especiais, nosso carro chefe, bem como serviços de cabelo, embelezamento de olhar, depilação e estética. \nNossas referências são sempre ligadas à beleza e ao bem-estar por isso a cor  Turquesa que além de ser a cor preferida mundialmente, relaxa todo o sistema nervoso e acalma a mente. Com uma equipe especializada oferecemos um suporte integral para o franqueado gerir a sua loja, desde o atendimento até as suas redes sociais. \nIsso porque a Turquesa é gerida pelas suas próprias fundadoras que atuam há quase dez anos no negócio administrando uma rede de mais de 100 unidades espalhadas em todo o Brasil, gerando emprego para mais de mil profissionais da área de beleza. A equipe da franqueadora que assessora os franqueados são profissionais do franchising responsáveis pelo: Apoio na expertise pela busca de um bom ponto comercial; Projeto visual da loja feito por excelentes profissionais; Plano de negócio customizado para o contexto do mercado de atuação de cada franqueado, garantindo uma atuação mais sólida, mais assertiva, em busca da rentabilidade desejada; Uma equipe de gerenciamento de projeto que o ajudará na fase de implantação da sua unidade garantindo melhor êxito em todas as etapas até a inauguração; Treinamento gerencial intensivo aos franqueados recém-chegados à rede, ministrado presencialmente pelos próprios fundadores e parceiros na sede da franquedora. Ainda que o franqueado não tenha experiência no setor, ele sairá apto à gerir a sua própria loja com excelência;  Plataforma de treinamento on-line para reciclagem; Treinamento técnico intensivo para os profissionais de beleza selecionados, que acontece por três dias integrais e ministrado por treinadora exclusiva da rede Turquesa; Equipe interna de marketing de comunicação provendo aos franqueados todas artes, todo o material de comunicação online e offline para campanhas institucionais, varejo nacional com as suas datas comemorativas e campanhas e ações regionais; Consultor de operação responsável por acompanhar a performance das unidades e disseminar as boas práticas da rede. Estamos também com os melhores fornecedores homologados do segmento, com taxas exclusivas e preços mais acessíveis. \nPara você, futuro empreendedor que deseja atuar neste crescente e promissor segmento, a marca Turquesa Esmalteria & Beleza oferece um modelo de negócios sólido e validado, com todo apoio e proximidade da franqueadora. \nEmpreenda no segmento que mais cresce no Brasil! Seja um franqueado Turquesa.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5538ef5b-ce67-4981-9de9-36065ec3106e.png', 76, NULL, NULL, '2026-03-09 18:23:55.552', 'https://franquias.portaldofranchising.com.br/franquia-turquesa-esmalteria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '69000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77nu00p2eh0s1bpo0wtl', 'HOSPITAL VETERINÁRIO POPULAR', 'hospital-veterinario-popular', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Hosptial ou clinica Veterinária Popular, especifico para uma classe social.', 2024, 2025, NULL, '2026-04-01 02:00:10.161', '2025-08-05 22:20:29.322', 939, NULL, 1, 2024, '', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d3d8b9ed-8f82-409c-8228-b00fb45dbad3.png', 7, NULL, NULL, '2026-02-11 09:29:40.000', 'https://franquias.portaldofranchising.com.br/franquia-hospital-veterinario-popular-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '280000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77nz00p3eh0s7ywbw2pu', 'KUMON', 'kumon', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Método de estudo nas disciplinas: matemática, português, inglês e japonês', 1958, 2003, '[\"https://www.youtube.com/watch?v=to3DeCKixOs\",\"https://www.youtube.com/watch?v=nlpznBpjNWQ\"]', '2026-04-01 02:00:10.171', '2025-08-05 22:20:29.327', 940, NULL, 1, 1958, 'O Kumon é uma empresa que, por meio da educação, contribui para o desenvolvimento de milhões de crianças em todo o mundo. É a maior franquia de educação do país*, uma marca sólida e rentável que proporciona ao franqueado um retorno valioso: realização pessoal, profissional e financeira. O método Kumon foi idealizado em 1954, quando o Prof. Toru Kumon, professor de Matemática, criou um material didático com o intuito de desenvolver o seu filho, Takeshi, pela autoinstrução. Percebendo os resultados de Takeshi na escola, os pais dos outros alunos passaram a se interessar pelo método. Com o objetivo de proporcionar o melhor aprendizado para o próprio filho e para todas as crianças de todo o mundo, foi fundado o Kumon. Diferenciais da franquia Kumon: Presente em mais de 60 países; Marca consolidada há mais de 45 anos na América do Sul; Mais de 1500 unidades no Brasil; Mais de 175 mil alunos no país; *Maior franquia de educação do país (dados ABF/2024); Investimento inicial a partir de 50 mil; Diferenciais do método: Estudo individualizado O Kumon não se prende a idade ou serie escolar, mas sim, a capacidade individual do aluno, que começa no seu ponto ideal de conhecimento. Autodidatismo O método desenvolve a autonomia nos estudos, ou seja, a capacidade de o aluno prender por si. Material didático exclusivo Nosso material didático e estruturado para que o aluno inicie os conteúdos de um nível fácil e avance de forma gradativa, sem sobrecargas de acordo com a evolução do aluno. Orientadores/Franqueados O papel do franqueado Kumon que é o orientador da unidade, é fundamental, pois cabe a ele observar as habilidades individuais do aluno e ajudar a desenvolvê-las ao máximo. Gosto pelo aprendizado O aluno Kumon alcança a autoconfiança e o interesse em estudar e aprender, desenvolvendo consideráveis habilidades acadêmicas e pessoais.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9efbb79b-916e-462f-9015-d1783bf6fb8a.jpg', 1972, NULL, NULL, '2026-03-09 18:25:37.707', 'https://franquias.portaldofranchising.com.br/franquia-kumon-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '50000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ob00p5eh0shlthl57p', 'MCDONALD´S', 'mcdonald-s', NULL, 'Alimentação', 'Bares e Restaurantes', 'McDonald\'s é a maior e mais conhecida empresa de serviço rápido de alimentação do mundo. No Brasil, a rede é operada desde 2007 pela Arcos Dourados, franqueada da marca em toda América Latina.', 1955, 1992, NULL, '2026-04-01 02:00:10.181', '2025-08-05 22:20:29.339', 942, 'df170f80-7453-425d-9613-b55ed556e14e', 1, 1955, 'FRANQUIA McDONALD\'S BRASIL \nLíder no segmento de serviço rápido de alimentação, o McDonald\'s se destaca pela qualidade dos produtos e do atendimento. O McDonald\'s é a maior e mais conhecida empresa de serviço rápido de alimentação do mundo. Presente em 119 países, a rede possui mais de 36 mil restaurantes, onde trabalham 2 milhões de funcionários que alimentam diariamente mais de 70 milhões de clientes. No Brasil, a rede é operada desde 2007 pela Arcos Dourados, máster franqueada da marca McDonald\'s em toda a América Latina. O primeiro restaurante do Brasil foi inaugurado em 1979, em Copacabana, Rio de Janeiro. Uma das melhores empresas para trabalhar no Brasil e um dos maiores empregadores de jovens do país, o McDonald’s reforça seu compromisso com a segurança e a saúde do trabalhador e anuncia o apoio ao movimento Abril Verde, iniciativa que ressalta a discussão sobre a segurança e a saúde no ambiente de trabalho. \nLíder absoluto no segmento de restaurantes fast food, com produtos de qualidade reconhecida, o Mcdonald’s é hoje uma das melhores empresas para se trabalhar e uma das melhores franquias para administrar. De fato, foi o sistema de franquias que permitiu o McDonald’s a se tornar a rede de restaurantes de mais sucesso do planeta, com mais de 33.000 restaurantes e presença em 119 países.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/291c2953-38f1-4ee0-bb19-d7c9a0675ab2.jpg', 2779, NULL, NULL, '2026-03-09 18:28:05.677', 'https://franquias.portaldofranchising.com.br/franquia-mcdonalds-valor/', NULL, NULL, NULL, 1, 5, 5, 1, 'MAINTAIN', 0, 0, NULL, '2670000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77oh00p6eh0s8qmuaxtz', 'ACCORHOTELS', 'accorhotels', NULL, 'Hotelaria e Turismo', 'HOSPEDAGEM', 'Impulsionamos o mercado hoteleiro nas Américas, desenvolvendo hotéis Premium, Midscale e Economy de sucesso. Acesse nosso site, e conheça nossas marcas: https://all.accor.com/a/pt-br/brands.html', 1971, 2006, NULL, '2026-04-01 02:00:10.191', '2025-08-05 22:20:29.345', 943, NULL, 1, 1971, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/46b5e65e-1124-4d3e-a14f-f2557583604f.png', 183, NULL, NULL, '2026-01-16 10:30:49.000', 'https://franquias.portaldofranchising.com.br/franquia-accor-hospitality-hotelaria-e-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '8320000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77on00p7eh0sam4xd64r', 'PURIFIC', 'purific', NULL, 'Casa e Construção', 'Construção e Reforma', 'Purificadores de Água Portáteis, Residencial, Corporativo, Industrial.', 2003, 2006, NULL, '2026-04-01 02:00:10.200', '2025-08-05 22:20:29.351', 944, NULL, 1, 1998, 'Fundada em 1998, a sede da Purific está localizada na cidade de Maringá (PR). A empresa trabalha com o objetivo de produzir purificadores de alta tecnologia com valores acessíveis. \nConta com equipe altamente capacitada, formada por engenheiros químicos, além de convênio com a Universidade Estadual de Maringá (UEM). Juntos, eles desenvolvem a melhor tecnologia de purificadores e elementos filtrantes. \nA Purific do Brasil desponta com moderna tecnologia e grande variedade de produtos, realizando o lançamento de um produto por ano, a fim de atender às necessidades e exigências do mercado. \nCom tanto crescimento e evolução, para melhorar a demanda e transporte, a Purific do Brasil inaugurou um centro de distribuição e montagem na cidade de Balbinos (SP), com o objetivo de facilitar as entregas diretamente aos operadores logísticos, fazendo com que os produtos cheguem mais rápido a qualquer ponto do País. \nO centro de distribuição e montagem de Balbinos representa de forma significativa o crescimento de 50% no seu parque de máquinas, proporcionando aumento na fabricação dos produtos Purific e gerando empregos. \nAlém de oferecer completa linha de purificadores de alta tecnologia, a Purific está sempre acompanhando as tendências de mercado e preocupada com o meio ambiente, desenvolvendo produtos de qualidade com alta tecnologia e design moderno para atender e satisfazer nossos consumidores.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fe9e446e-cea2-4d79-9d13-4733aa2b2e55.jpg', 151, NULL, NULL, '2026-03-09 18:28:52.821', 'https://franquias.portaldofranchising.com.br/franquia-purific-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ot00p8eh0sabj7xsa7', 'NEW ERA', 'new-era', NULL, 'Moda', 'ACESSÓRIOS PESSOAIS', 'BONÉS, CONFECÇÃO, ACESSÓRIOS', 2006, 2016, '[\"https://www.youtube.com/watch?v=BCypao9t044\"]', '2026-04-01 02:00:10.208', '2025-08-05 22:20:29.357', 945, NULL, 1, 1920, 'A New Era está presente em mais de 125 países, e mais de 100 lojas pelo mundo, é fornecedora oficial dos bonés para as ligas de beisebol (MLB), basquete (NBA) e futebol americano (NFL), possui também uma linha de vestuário masculino e feminino traduzindo todo lifestyle dos esportes para o dia e a noite. Tem também a própria linha New Era Branded, que veste o consumidor da cabeça aos pés! Fundada em 1920 em Buffalo NY, a New Era caminha para o seu centenário, possui colaborações com as marcas mais desejadas do mundo, como Supreme, Moncler, Kenzo, New Balance, The North Face, além de coleções com Star Wars, Cartoon, Universal, entre outras... Desde 2012 presente no maior evento esportivo do mundo, o SUPER BOWL. As lojas no Brasil oferecem as coleções de vestuário, acessórios e calçados, além da sua famosa linha de bonés.', NULL, 'SÃO PAULO', 1, NULL, 139, NULL, NULL, '2026-01-16 10:35:42.000', 'https://franquias.portaldofranchising.com.br/franquia-new-era-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77oy00p9eh0s8nmq8slr', 'DOG KING', 'dog-king', NULL, 'Alimentação', 'Mercados e Distribuição', 'Franquias de Fast Food. A rede atua com um mix completo de hot dogs, burgers e batatas fritas. O \"carro chefe\" é o Dog Frango.', 2017, 2017, '[\"https://www.youtube.com/watch?v=jyCaEqva-oA\"]', '2026-04-01 02:00:10.218', '2025-08-05 22:20:29.363', 946, NULL, 1, 2006, 'Em 2011, com a forte cultura do consumo de cachorro-quente prensado no norte do Paraná, nasceu a primeira loja Dog King na cidade de Cambé. Após alguns anos de experiência no segmento de fast food, a marca decidiu ampliar a rede de lojas através do sistema de franquias. Com o avanço da rede, em 2017, a marca construiu a sua própria fábrica de proteínas homologada pelo SISBI-POA (Sistema Brasileiro de Inspeção de Produtos de Origem Animal), visando a padronização, qualidade e agilidade no fornecimento de insumos, através da centralização do processo logístico para seus franqueados.  A rede atua com um mix completo de hot dogs, burgers e batatas fritas. O \"carro chefe\" é o Dog Frango. A marca continua em processo de expansão e conta com uma estrutura completa para fornecer suporte aos seus franqueados: Centro de Treinamento; Suporte Operacional, em Gestão e Marketing; Fábrica de Proteínas Homologada; Escritório; Logística Própria. Hoje, a Dog King é a maior rede de franquias de Hot Dog do Brasil, reconhecimento construído com muita ética, respeito e integridade.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fd5e6fa8-613a-4217-96bc-8cd167f35002.jpg', 59, NULL, NULL, '2026-03-09 18:29:44.612', 'https://franquias.portaldofranchising.com.br/franquia-dog-king-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77p400paeh0scpkyuphl', 'MAPLE BEAR', 'maple-bear', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Maple Bear é uma rede de escolas de Ensino Infantil, Fundamental e Médio que oferece educação de excelência fundamentada na metodologia canadense bilíngue, classificada entre as melhores do mundo.', 2005, 2018, '[\"https://www.youtube.com/watch?v=-cnQUJ93qps\",\"https://www.youtube.com/watch?v=ub0eaN3At1U\",\"https://www.youtube.com/watch?v=2My5jrULIi0\",\"https://www.youtube.com/watch?v=gQyMRbili2Q\"]', '2026-04-01 02:00:10.228', '2025-08-05 22:20:29.368', 947, NULL, 1, 2005, 'ENSINO INFANTIL, FUNDAMENTAL E MÉDIO VERDADEIRAMENTE BILÍNGUE E MINISTRADO COM METODOLOGIA CANADENSE. A Maple Bear oferece o melhor da educação bilíngue canadense, preparando alunos para um mundo em que a imaginação, o raciocínio crítico, o multiculturalismo e a capacidade de integrar pessoas e disciplinas serão, cada vez mais, determinantes. São mais de 500 escolas de Ensino Infantil, Fundamental e Médio, em 30 países ao redor do mundo. No Brasil são mais de 140 escolas que não somente seguem, mas em muitos casos superam, as determinações do MEC, e oferecem ensino de excelência a 25 mil estudantes em todas as regiões do País', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/18e4e8df-f7eb-4de3-847f-6a144bb6b42a.png', 489, NULL, NULL, '2026-03-09 18:30:32.138', 'https://franquias.portaldofranchising.com.br/franquia-maple-bear/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '2612350', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77p900pbeh0se6mx9rjb', 'SUPER APRENDIZ', 'super-aprendiz', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escola de cursos profissionalizantes.', 2020, 2021, NULL, '2026-04-01 02:00:10.237', '2025-08-05 22:20:29.373', 948, NULL, 1, 2009, 'A franquia Super Aprendiz é uma escola de cursos profissionalizantes que capacita e qualifica estudantes, jovens e profissionais que desejam se preparar e especializar para o mercado de trabalho. Possuímos uma variedade incrível de conteúdos para formação de um profissional eficaz a partir de cursos profissionalizantes e programas de aprendizagem para o jovem que aspira sua evolução profissional, também contando com uma estrutura voltada para a empresa que busca qualificação para o seu quadro de funcionários. Muito mais que isso, contamos com uma proposta de qualificar pessoas de um  jeito inovador, jovial e descontraído prezando sempre pela competência e eficiência do conteúdo disponibilizado nos cursos. Invista em um negócio rentável e de grande demanda no mercado, enquanto a franqueadora fornecerá treinamento, suporte e assessoria de marketing que farão sua franquia alavancar com força e rapidez. Venha ganhar este mercado conosco!', NULL, 'ESPÍRITO SANTO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/034e82f7-0161-4c7d-a8b0-474d4d850cae.jpg', 16, NULL, NULL, '2026-03-09 18:31:11.428', 'https://franquias.portaldofranchising.com.br/franquia-super-aprendiz/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77pe00pceh0ss1y6u6nu', 'ATHIVOS CONSULTORIA E GESTÃO', 'athivos-consultoria-e-gestao', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Planejamento financeiro, gestão de carteira de investimentos, banco digital.', 2025, 2025, NULL, '2026-04-01 02:00:10.246', '2025-08-05 22:20:29.378', 949, NULL, 1, 2023, '', NULL, 'SÃO PAULO', 1, NULL, 41, NULL, NULL, '2026-03-09 18:31:48.814', 'https://franquias.portaldofranchising.com.br/franquia-athivos-consultoria-e-gestao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '6000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77pj00pdeh0sk5tbc8xj', 'REMAX', 'remax', NULL, 'Casa e Construção', 'Serviços e Imobiliárias', 'FRANQUIA IMOBILIÁRIA', 1973, 2010, '[\"https://www.youtube.com/watch?v=H4i1igfgruc\"]', '2026-04-01 02:00:10.256', '2025-08-05 22:20:29.383', 950, NULL, 1, 1973, 'A RE/MAX, líder do franchising imobiliário mundial, foi fundada em Denver, no Estado do Colorado (USA). Hoje a RE/MAX é a maior rede de franquias imobiliárias em números de transações no mundo, com mais de 9.000 franquias e 144.000 corretores a sua disposição. No Brasil, a RE/MAX atua desde 2009, com mais de 630 Franquias por todo o país. O diferencial da rede é bastante conhecido: “Ninguém vende mais imóveis no mundo do que a RE/MAX”. A franquia RE/MAX baseia-se em três fundamentos: máximo serviço para o cliente, máxima comissão para o corretor e máxima rentabilidade para o franqueado, numa atuação única onde “todos ganham”. Para ser um franqueado RE/MAX, o empresário não precisa ter conhecimento prévio do mercado imobiliário. A RE/MAX oferece: REDE MUNDIAL presente em mais de 110 países, mais de 144 mil corretores, o que permite um leque vasto de opções para compra ou venda de imóveis em qualquer lugar do Brasil e do mundo. TREINAMENTO constante dos brokers e corretores associados. UNIVERSIDADE RE/MAX, única no gênero em operação no mundo, o franqueado aprende e se mantem sempre atualizado nos procedimentos para de venda e captação de imóveis. PAR: Suporte ao franqueado por meio da transferência de Know-How. MARCA fortemente reconhecida no mundo. MAXPRO, um software que proporciona em tempo real todas as informações do negócio para o franqueado. CULTURA: Inovação na prestação de serviço por meio das melhores práticas mundiais, com foco no desenvolvimento e qualidade de vida. E mais: TAXA DE FRANQUIA a partir de $20 mil dólares. A operação nacional conta com 16 Masters Regionais distribuídas por todo o Brasil, oferecendo total suporte para sua operação. Se você procura um negócio que pode mudar o futuro da sua imobiliária ou uma área rentável em potencial, entre em contato conosco.   Processo de seleção da franquia REMAX Conheça abaixo quais são as etapas do processo de seleção da franquia RE/MAX: Contato Inicial Apresentação de venda de franquia Visita a um franqueado Planilha de viabilidade Envio da Circular de Oferta de Franquia (COF) Esclarecimento da COF Aprovação do Franqueado Assinatura do Contrato Perfil do franqueado REMAX Conheça abaixo o perfil que a franquia RE/MAX procura para seus franqueados: a) Saber delegar\nb) Gestão de talentos\nc) Bom relacionamento\nd) Valorização do compartilhamento\ne) Cooperação\nf) Empreendedor\ng) Dedicação e disponibilidade\nh) Autonomia\ni) Organização e responsabilidade\nj) Identificação com o modelo de negócio\nk) Flexibilidade para o aprendizado\nl) Possui recursos financeiros', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cd2dbd8b-9bed-4572-a352-b5fcb5119373.jpg', 623, NULL, NULL, '2026-03-09 18:32:09.167', 'https://franquias.portaldofranchising.com.br/franquia-remax-imobiliarias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '120000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77po00peeh0sumobv5u3', 'PETLAND', 'petland', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'A maior rede de Franquias de petshop do Brasil, com mais de 50 anos de história, presente em 19 países.', 1970, 2014, '[\"https://www.youtube.com/watch?v=jB02ZtqASm4\"]', '2026-04-01 02:00:10.266', '2025-08-05 22:20:29.389', 951, NULL, 1, 1967, 'A Petland é uma rede de franquias que nasceu nos EUA em 1967 com uma visão inspirada na magia da Disneyland. Fundada por Ed Kunzelman em Ohio, a Petland rapidamente se expandiu internacionalmente e hoje está presente em 19 países ao redor do mundo. Com quase 60 anos de experiência, nossa missão é proporcionar experiências memoráveis aos clientes que visitam nossas lojas, focando em transmissão de informação, uma experiência de compra única, responsabilidade social e preços justos. Somos uma empresa moderna e inovadora, comprometida em oferecer um ambiente seguro e confiável para nossos franqueados e clientes. Aterrissamos no Brasil em 2014 e já temos histórias incríveis para compartilhar! Somos a maior rede de pet shops do Brasil, com mais de 170 lojas espalhadas por 21 estados. Além de toda a experiência adquirida e transmitida por uma rede de quase 60 anos de história, o sucesso da Petland também é impulsionado pelo fato de o Brasil ser o 2º maior mercado consumidor de produtos para pets no mundo. O mercado pet também tem resistido às recentes crises econômicas, registrando um crescimento de mais de dois dígitos todos os anos. A tendência de humanização dos animais de estimação, tratados cada vez mais como membros da família, é um dos motores desse crescimento, mantendo o mercado sempre em busca de novos produtos e experiências para oferecer aos seus pets e tutores. Com um faturamento anual ultrapassando os R$ 35 bilhões, o mercado de Pet Shop se revela uma oportunidade incrível de investimento, atendendo a todas as classes sociais e a um público de todas as idades. A Petland se destaca no universo das franquias oferecendo uma variedade de formatos de lojas, desde unidades compactas até mega lojas, para atender às diferentes demandas e localidades. Na Petland, o bem-estar e a saúde dos pets sempre têm prioridade máxima. Em nossas franquias, nossa equipe é treinada para fornecer um atendimento centrado na educação, orientando os tutores sobre as 4 Necessidades Básicas de todo animal: nutrição, ambiente, comportamento e manutenção. Nossos colaboradores, os “Petlanders”, estão empenhados em fazer a combinação perfeita entre o animal e sua nova família, garantindo a satisfação de ambas as partes. Para aqueles que já possuem um pet, estamos comprometidos em expandir seu conhecimento e aprimorar esse relacionamento. No pilar responsabilidade social, mantemos parcerias com mais de 40 ONGs no Brasil. Todos os fins de semana, diversas lojas de nossa rede promovem eventos de adoção por todo o país. Além disso, anualmente realizamos o SRDay, um dia especial em que todas as 170 lojas da Petland promovem eventos de adoção simultaneamente. Essas ações refletem nosso compromisso com o bem-estar animal e a promoção da adoção responsável. Venha fazer parte da maior rede de Pet Shops do Brasil e nos ajude a transformar a vida de pets e pessoas!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d4f1fb9d-761a-49a5-a9f0-66b1205014dc.png', 168, NULL, NULL, '2026-03-09 18:33:33.400', 'https://franquias.portaldofranchising.com.br/franquia-petland-negocios-e-servicos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '135000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77pu00pfeh0srdmb4a6s', 'MAIS1', 'mais1', NULL, 'Alimentação', 'Bares e Restaurantes', 'Rede de cafeterias de cafés especiais e alimentos de alta qualidade. Gestão simplificada com a necessidade de apenas 3 colaboradores. Suporte total ao franqueado', 2019, 2020, '[\"https://www.youtube.com/watch?v=Q26g28o6kX4\",\"https://www.youtube.com/watch?v=96sQu13hbKE\",\"https://www.youtube.com/watch?v=a7OxXLtZozM\",\"https://www.youtube.com/watch?v=-IcNYgGsde8\"]', '2026-04-01 02:00:10.276', '2025-08-05 22:20:29.394', 952, NULL, 1, 2019, 'A REDE DE FRANQUIAS QUE MAIS CRESCEU NO BRASIL EM 2022 Com mais de 500 unidades já confirmadas no Brasil, a Mais 1 Café é uma rede de franquias que chegou ao mercado em 2019 e de lá pra cá tem se expandido e criado grandes parcerias, se tornando uma das principais redes de cafeterias e se consolidando como a marca mais jovem a entrar no ranking das 50 maiores franquias do país, tudo isto graças ao planejamento e plano de negócios bem estruturado. Só trabalhamos com produtos de altíssima qualidade, importados de diversos lugares do mundo, o café utilizado é da categoria especial, 100% arábica produzido nas melhores fazendas do país. Nos orgulhamos de parcerias oficiais de produtos com as principais marcas mundiais como Nestlé, Nutella, Ovomaltine e Forno de Minas, e de parcerias de marketing com Universal Studios, Gol Linhas aéreas entre outras. Dentro de todo esse cenário, a Mais1 se destaca pelo seu baixo valor de investimento inicial, alta rentabilidade, espaços compactos, número reduzido de funcionários e ainda todo o suporte oferecido pela rede franqueadora. Já somos mais de 500 unidades confirmadas no Brasil e continuamos crescendo de forma acelerada. Venha fazer parte desta história. Esperamos seu contato!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1db223fd-78c5-4605-8e8e-f2f3eea315f0.png', 502, NULL, NULL, '2026-03-09 18:35:06.185', 'https://franquias.portaldofranchising.com.br/franquia-mais1/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
