INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77qz00pmeh0sjz302odq', 'UCI UP', 'uci-up', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Somos uma franquia de crédito imobiliário, oferecendo serviços como financiamento, consórcios e Home Equity, com baixo investimento e alto potencial de lucro para empreendedores.', 2024, 2025, NULL, '2026-04-01 02:00:10.340', '2025-08-05 22:20:29.435', 959, NULL, 1, 2012, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/513c233e-d7ea-4b94-926d-eabdbea3db2a.png', 5, NULL, NULL, '2025-08-29 15:32:37.000', 'https://franquias.portaldofranchising.com.br/franquia-uci-up/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77r400pneh0s2s4y22we', 'STALKER', 'stalker', NULL, 'Moda', 'Vestuários', 'Vestuário', 2000, 1998, NULL, '2026-04-01 02:00:10.349', '2025-08-05 22:20:29.441', 960, NULL, 1, 1998, 'A STALKER chegou ao mercado brasileiro em julho de 1998. No seu décimo nono ano de existência, conta com 30 operações. A marca procura criar uma identidade para o público-alvo: o homem com espírito livre e jovem sem faixa etária dominante. A “Estrela” associa-se à posição, objetivos, traz alusão à liberdade de escolha, à aventura, traduz-se em bússola, horizonte. A palavra “STALKER” do inglês to stalk, que significa caçar, dá um caráter universal ao homem perseverante e atual, que “persegue” seus objetivos, caçador, homem moderno e livre. \nAtualmente faz parte do grupo Sand Beach, empresa com 31 anos de mercado. O grupo iniciou seu trabalho com uma fábrica de garagem, em Fortaleza (CE), voltada para a produção de bermudas (boardshorts) para os amigos e criou a marca MARESIA. A Sand Beach se tornou um dos maiores parques industriais do segmento, que atualmente consta com 20.000m², sendo 85% automatizados. São mais de 500 colaboradores diretos que respondem por uma produção que, somente na estamparia é de aproximadamente 10 mil peças completas por dia, podendo funcionar 24 horas durante os sete dias da semana. Um crescimento que também se expandiu em segmentos, trazendo para o grupo as marcas MARESIA Future, criada para levar toda a qualidade da MARESIA para as crianças, e a Black Box, que é mais voltada para a moda casual jovem e urbana.', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ef09255c-4cee-4852-8761-d79c12ad67c1.jpg', 20, NULL, NULL, '2026-03-09 18:42:47.813', 'https://franquias.portaldofranchising.com.br/franquia-stalker-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
