INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77rf00ppeh0s7254zzgf', 'BOTOLIFTING', 'botolifting', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'Venha fazer parte da rede de estética presente já em 10 estados Brasileiros com tecnologia de ponta, inovação contínua, suporte qualificado e acompanhamento estratégico para crescimento escalável.', 2021, 2025, NULL, '2026-04-01 02:00:10.369', '2025-08-05 22:20:29.452', 962, NULL, 1, 2019, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/db02a352-fa67-4c3f-9947-c17cccc8d6ed.png', 21, NULL, NULL, '2025-11-17 10:22:47.000', 'https://franquias.portaldofranchising.com.br/franquia-botolifting/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '233000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77rl00pqeh0sw317jd73', '10 PASTÉIS', '10-pasteis', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fast Food', 1996, 1998, NULL, '2026-04-01 02:00:10.378', '2025-08-05 22:20:29.457', 963, 'df170f80-7453-425d-9613-b55ed556e14e', 1, 1961, 'O empreendedor Marcos Nagano conta a história de sucesso, que tornou a 10 pastéis a maior rede de pastéis do Brasil Por trás de um grande empreendimento, há sempre mentes visionárias, e principalmente, empreendedoras. E com a franquia “10 Pastéis” não foi diferente. Até se consolidar como a maior rede de pastéis do Brasil, a empresa teve muita estratégia, planejamento e momentos de readequação para hoje em dia, continuar seu processo de expansão. E uma das mentes por trás do sucesso da marca é Marcos Nagano, 53 anos. Em sua vida pessoal, Nagano, que é natural de Presidente Prudente, em São Paulo, se mudou ainda adolescente para Curitiba, cidade que reside atualmente. Engenheiro Mecânico, ele já foi atleta, bancário, técnico das categorias de base da seleção brasileira de beisebol, trabalhou com sistemas e quando estava com a vida tranquila, sendo funcionário público, decidiu ser empreendedor. “Em 1993, a família do Rui Sasazawa, meu sócio na época, tinha uma pastelaria na rodoviária de Maringá. Ele se mudou para Curitiba e abriu a 10 Pastéis. Eu recebi o convite dele, e entrei no negócio para liderar a franqueadora”, relembra. Com a experiência de engenheiro, Nagano contratou uma consultoria, e desde o início, investiu em capacitação. “Queríamos que tudo acontecesse dentro de um padrão”, disse. E esta era justamente uma das características da 10 Pastéis, que mais tarde veio a ter na culinária, qualidades que diferenciasse dos concorrentes, como a massa de chocolate, de pimenta, pastel com bordas, etc. A vida não é uma constante Para Nagano, a vida funciona como uma linha inconstante, com variações tanto para cima, quanto para baixo. E a primeira variação negativa da empresa foi em 1996 quando o fundador da 10 Pastéis saiu do negócio. “Depois de 5 anos, o Rui saiu. Mas seguimos nosso planejamento, com o objetivo de dar sustentabilidade para a marca. Afinal, o segredo de uma franquia é fazer os franqueados ganharem dinheiro”, destacou. As armadilhas pelo caminho Ao estudar a história de empresas da menor para as grandes companhias, é comum haver tempos de prosperidade e crescimento mútuo, alternando com períodos de crise. Após um período de crescimento, em que chegou a mais de 60 lojas, a 10 Pastéis viu seu market share cair no mercado entre 2015 e 2016. Nagano lembra que o motivo foi a crise, mas ele deixa aquele momento de susto, como um grande aprendizado. “Quando tudo começa a dar certo no negócio, é quando você precisa tomar cuidado com cada passo que vai dar”. Pois nossa grande armadilha foi justamente essa, lembra. Hoje com 40 lojas abertas em nove estados do Brasil, a empresa já tem mais sete franquias em processo de abertura e projeto de expansão para 70 lojas. “O nosso objetivo é em três anos chegar a 100ª loja”, revelou. A experiência de quem deu certo Marcos Nagano nunca se contentou, sempre correndo atrás de seus sonhos. E para quem pretende empreender, ele deixa um conselho. “Primeiro acredite do sonho. Quem quer empreender, realmente tem que acreditar no sonho. Segundo, tem que ter um planejamento. Não só ter o sonho, mas saber fazer. E ter resiliência. Tendo tudo isso: objetivo e planejamento, não tem porque não tentar. O dar certo é uma consequência”, concluiu.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9fd5fe70-2ee5-4cdd-9429-3945ac17151c.png', 64, NULL, NULL, '2026-03-09 18:44:18.596', 'https://franquias.portaldofranchising.com.br/franquia-10-pasteis-salgados/', NULL, NULL, NULL, 1, 3.666666666666667, 11, 3, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
