INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77sc00pveh0smotsj632', 'T-DONUTS', 't-donuts', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Franqueamento de unidades de comercialização de doces', 2021, 2022, '[\"https://www.youtube.com/watch?v=CLfHrTC_zu8\",\"https://www.youtube.com/watch?v=IFJQvFy47kE\"]', '2026-04-01 02:00:10.428', '2025-08-05 22:20:29.484', 968, NULL, 1, 2021, 'Empreendedor de sucesso, Tiago Fernandes, o Tcar, é proprietário da loja de carros mais famosa do Brasil com +4 milhões de seguidores nas redes sociais, e em 2021 em meio à pandemia, decidiu diversificar seus investimentos e apostar no ramo alimentício. Foi então que a tdonuts nasceu e foi uma explosão de vendas na época. A esse sucesso associou-se Tiago Carvalho, empreendedor jovem e dinâmico, dono de uma rede de franquias odontológicas com mais de 30 unidades e faturamento anual que já supera a marca dos 30 milhões de reais. Após encontros de negócios, Tiago Carvalho e Tiago Fernandes, decidiram se tornar sócios da maior e melhor franquia de donuts do Brasil, a tdonuts. Única franquia 6 em 1 do Brasil, a  t.donuts é uma rede de lojas especializada em donuts, a nova “febre do brasileiro”! São diversos sabores, de rings clássicos aos recheados, ou melhor, muitooooo recheados, que encantam e deixam o cliente com gostinho de  “quero mais’. Além deles, a loja oferece em seu cardápio donuts salgados, donuts com sorvete, cafés, milkshakes e deliciosas sodas italianas. Perfeita para todas as horas do dia, e todos os gostos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ae2f7709-0667-4005-a7d0-6bfce1baf7b7.jpg', 8, NULL, NULL, '2026-03-09 18:47:08.605', 'https://franquias.portaldofranchising.com.br/franquia-t-donuts/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '80000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77sm00pxeh0shy1mv528', 'ORTHOCRIN', 'orthocrin', NULL, 'Casa e Construção', 'Móveis e Decoração', 'O Sistema de Franquias da ORTHOCRIN baseia- se no licenciamento aos franqueados do direito de uso da marca, que é conhecida, consolidada e com prestígio em todo o território nacional, associado ao uso de uma Metodologia de Trabalho padronizada para instalação, montagem, administração e operação de uma loja especializada na venda dos produtos da marca.', 2013, 2014, '[\"https://www.youtube.com/watch?v=8MJRgJFWuKc\",\"https://www.youtube.com/watch?v=Xmh2JiRiZBU\",\"https://www.youtube.com/watch?v=bWbe5jC_2v4\"]', '2026-04-01 02:00:10.437', '2025-08-05 22:20:29.494', 970, NULL, 1, 2013, 'Uma equilibrada mistura entre tradição e inovação, gestão familiar com renovação do mercado, tecnologia criada dentro da empresa com métodos internacionais. Assim podemos resumir a forma como a Orthocrin, uma das maiores empresas de colchões do Brasil, se posiciona no mercado. Com mais de 50 anos de atuação, a fábrica mineira se orgulha de sua história e mantém sempre o foco na qualidade e excelência de seus produtos. Todo esse cuidado e dedicação, contribuíram para a conquista de importantes certificações, como: Empresa Top Of Mind, Selo de Qualidade e Controle de Produção do Inmetro e Certificado Pró-Espuma. Hoje, a marca está presente nos Estados de Minas Gerais, Bahia, Espírito Santo, Goiás, Paraíba, Rio de Janeiro, Rio Grande do Norte, Sergipe e São Paulo, com mais de três mil pontos de vendas da marca, incluindo lojas credenciadas, multimarcas e franquias. Ao escolher uma franquia COLCHÕES ORTHOCRIN, o empreendedor passa a contar com uma metodologia de trabalho padronizada, preços competitivos e o fornecimento assegurado por uma das maiores indústrias de colchões do Brasil. Diferenciais que propiciam ao franqueado iniciar a gestão de sua loja com maiores chances de sucesso.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2b37a21f-1673-46bc-b1ca-3d7a74a017cd.png', 93, NULL, NULL, '2026-03-09 18:59:48.387', 'https://franquias.portaldofranchising.com.br/franquia-orthocrin/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '190000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
