INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77tx00q3eh0snnjkn2ep', 'GRAU PROFISSIONALIZANTE', 'grau-profissionalizante', NULL, 'Educação', 'EDUCAÇÃO', 'Formar e qualificar profissionais para o mercado de trabalho, a partir de cursos práticos e rápidos nas áreas de construção civil, indústria, negócios, e infraestrutura.', 2015, 2017, NULL, '2026-04-01 02:00:10.496', '2025-08-05 22:20:29.541', 976, NULL, 1, 2015, '', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ea92ddd6-9f8f-4fd3-9d34-4d899d605701.png', 134, NULL, NULL, '2025-09-30 19:32:25.000', 'https://franquias.portaldofranchising.com.br/franquia-grau-profissionalizante-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77u500q4eh0sn4iny7b3', 'JAH', 'jah', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'O JAH Açaí, Sorvetes e Picolés conta com mais de 180 unidades pelo Brasil, e uma oferta exclusiva em produtos através de um modelo self-service de negócio, à justo custo benefício aos nossos clientes.', 2016, 2018, '[\"https://www.youtube.com/watch?v=mHY4avCoiQc\",\"https://www.youtube.com/watch?v=K-aVOzoXda4\"]', '2026-04-01 02:00:10.506', '2025-08-05 22:20:29.549', 977, NULL, 1, 2009, 'Uma empresa que conduz o futuro com qualidade, sabores, pessoas e ideias. \nDe Conselheiro Lafaiete, interior de Minas Gerais, o JAH é uma rede de franquias de açaí, sorvetes e picolés que inovou ao desenvolver um negócio sob medida, que conversa com as necessidades do seu público-alvo.  O modelo self-service abriu portas para a expansão da rede que, hoje, está em 14 estados no país, compondo uma rede de mais de 150 unidades. \nO nosso diferencial conversa com diversos públicos e abraça dores de mercado, que enfrenta escassez de produtos de qualidade, feitos exclusivamente para os #JAHLovers - uma comunidade de cerca de dois milhões de pessoas alcançadas mensalmente através dos nossos canais digitais.  Opções veganas, sem lactose e sem adição de conservantes são alguns dos diferenciais do nosso negócio. \nSomos uma marca sólida, transparente em todos os processos que acredita que o sucesso individual de cada franqueado é um esforço diário.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/30f9d22a-cd3e-43dc-9158-18a88648cd8b.png', 152, NULL, NULL, '2026-03-09 19:10:13.439', 'https://franquias.portaldofranchising.com.br/franquia-jah/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9f54b656-044f-457a-ae0d-b186fbeb745a.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '299000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77uk00q6eh0sbd8x8lxl', 'CREDFÁCIL', 'credfacil', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Promoção e intermediação de créditos e financiamentos junto às instituições financeiras; Intermediação de consórcios.', 2009, 2022, NULL, '2026-04-01 02:00:10.516', '2025-08-05 22:20:29.564', 979, NULL, 1, 2004, 'A Credfácil se destaca como uma franquia de serviços financeiros, estabelecendo parcerias sólidas com os principais bancos e promotoras regulamentadas do Brasil. Em um mercado competitivo, oferecemos diversas modalidades de crédito altamente procuradas por milhões de brasileiros. O nosso diferencial reside no extenso know-how de 20 anos de mercado, uma experiência que compartilhamos com nossos franqueados para assegurar o êxito de seus empreendimentos. Valorizamos o crescimento conjunto, e para isso, proporcionamos produtos com excelentes comissões e grande demanda no mercado. Na Credfácil, acreditamos no seu sucesso, e por isso, adotamos o sistema de royalties. Este é um valor mensal que você paga para a franqueadora, e este investimento é integralmente revertido na disponibilização de ferramentas e recursos essenciais para fortalecer ainda mais a sua atuação. O lucro gerado é integralmente seu, permitindo que você se torne um empreendedor de sucesso. Nosso comprometimento vai além do início da sua franquia. Oferecemos treinamento e suporte especializado, mesmo para aqueles que não possuem conhecimento prévio no universo financeiro. Investir em uma franquia Credfácil proporciona diversas vantagens, tais como: Baixo custo operacional e ausência de capital de giro. Comissões pagas diariamente. Retorno rápido do investimento. Acesso a plataforma de marketing completa. Suporte operacional. Treinamentos na Universidade EAD. Equipe Comercial e Consultoria de campo. CRM para gestão e vendas. Ao escolher a Franquia CREDFÁCIL, você não apenas ingressa em um negócio promissor, mas também se une a uma rede comprometida com o seu crescimento e sucesso. Estamos aqui para guiá-lo em cada passo do caminho.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fe35ee39-5f3a-4cd3-9fd4-9395aa818b06.jpg', 1027, NULL, NULL, '2026-03-09 19:15:06.757', 'https://franquias.portaldofranchising.com.br/franquia-credfacil/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77uu00q7eh0ss6cvlyeq', 'Fast4you Home Market', 'fast4you-home-market', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', '', 2020, 2020, '[\"https://www.youtube.com/watch?v=SlvLtbBMn-U\",\"https://www.youtube.com/watch?v=eZMshXKOM5A\",\"https://www.youtube.com/watch?v=DvyxTatr2Jk\",\"https://www.youtube.com/watch?v=-nWdFyz5ViA\",\"https://www.youtube.com/watch?v=Igvi_fojThc\"]', '2026-04-01 02:00:10.525', '2025-08-05 22:20:29.574', 980, NULL, 1, 2020, 'A fast4you surgiu com o propósito de modernizar condomínios e empresas por meio de mercados autônomos 24h, oferecendo conveniência, segurança e tecnologia no dia a dia de moradores e colaboradores.', NULL, 'Santa Catarina', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4fd1db6e-fffa-4f38-a3e6-9ad88c78a9da.png', 541, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c6c9372d-da6d-4c26-8a33-7004573fb106.jpg', '2026-03-09 19:16:12.217', 'https://franquias.portaldofranchising.com.br/franquia-fast4you-home-market/', NULL, 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f84b61a8-3b5e-4c1c-a6bf-730f67351e49.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8fc67698-b6b4-43a5-8bab-47c546acfb62.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6f47d01e-4377-4242-be15-2909c25e0f6a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a835a39d-43ff-4b1b-9aa1-b0cd2ed320a0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/23535841-2fb1-4952-80e6-ea7f3cd8dada.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ba779ddb-9a8a-49b4-8033-51c65e6e54a2.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e179b542-eae9-4ad8-b3eb-9694263fec9d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/aac189b5-b788-4b14-8d8b-d7948c1cf7c6.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f35f3b3d-c0da-4897-bd35-81867073ae05.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '50000', NULL, NULL, NULL, '15000', NULL, '6', '0', '30000', '5000', 10);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77v800q9eh0sah7x5iut', 'AM/PM qa', 'am-pm-qa', 'Editado pela Pri QA', 'Alimentação', 'Mercados e Distribuição', 'LOJAS DE CONVENIÊNCIA qa ', 1980, 1990, NULL, '2026-03-16 15:45:42.781', '2025-08-05 22:20:29.588', 982, 'c6eb73ac-3110-437c-93d1-1f0eb31cd37f', 0, 1979, 'A AmPm faz parte do ecossistema de mobilidade da Ipiranga e é hoje a maior rede de lojas de conveniência do país, com mais de 1.500 unidades espalhadas pelo Brasil. A AmPm é também a maior rede nacional de padarias, com quase 800 unidades, e conta ainda com quatro Centros de Distribuição. Com o propósito de transformar a parada no melhor de cada jornada, a AmPm está no caminho sempre pronta para receber as pessoas.', 'testse da Descricao PRi QA', 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b438fc3b-6da5-4124-bc58-9b410afbd484.png', 1450, NULL, NULL, '2026-03-09 19:21:03.641', 'https://franquias.portaldofranchising.com.br/franquia-am-pm-ipiranga/', NULL, NULL, NULL, 1, 5, 10, 2, 'MAINTAIN', 3, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ve00qaeh0srmrjuzbm', 'STERNA CAFÉ', 'sterna-cafe', NULL, 'Alimentação', 'Bares e Restaurantes', 'Cafeteria especializada em cafés especiais cultivados no Brasil e nos principais países produtores. A experiência começa com um espresso, passando pelos principais métodos de extração internacionais.', 2015, 2016, '[\"https://www.youtube.com/watch?v=tEyLDngnTKc\"]', '2026-04-01 02:00:10.535', '2025-08-05 22:20:29.594', 983, NULL, 1, 2015, 'O mundo das viagens e novas experiências a partir de grãos selecionados de café, são a base do conceito da Sterna. Seus fundadores viajaram o mundo por mais de 60 países, vivenciando diferentes culturas e experimentando novos e inovadores sabores, principalmente por meio do café, bebida que é sinônimo de receptividade e acolhimento ao redor do globo. O nome Sterna é inspirado por uma ave de mesmo nome que ao longo de sua vida, percorre o equivalente a 60 voltas na Terra. Inspirados por isso, a Sterna Café nasceu em 2015 com a missão de levar todas essas experiências cafeinadas até o cliente. Uma cafeteria Sterna Café une a oferta de grãos de cafés especiais de várias regiões do Brasil e do mundo, com a extração por métodos internacionalmente conhecidos, sempre em um ambiente pensado para que o cliente tenha uma nova experiência a cada xícara de café. Assim como trabalhamos com os melhores cafés, oferecemos um cardápio variado e adaptável, elaborado para todos os momentos de venda, atendendo diferentes perfis de clientes e de acordo com o local de instalação da cafeteria. A franquia foi concebida com padrões arquitetônicos flexíveis para que possa ser facilmente implantada em diferentes locais como lojas de rua, edifícios comerciais, hospitais, galerias comerciais, residenciais short stay, universidades, aeroportos, rodoviárias, shopping centers, estações de metrô, strip malls, etc. Um formato que vem ganhando força dentro da rede é o modelo store in store, onde implantamos as nossas unidades em empresas que possuem sinergia com o nosso negócio, como salões de cabelereiro, escritórios comerciais, etc. Você pode ter uma cafeteria premium da Sterna Café nos formatos Loja e Quiosque, com as opções de modelo convencional e container. Atualmente a rede conta com mais de 50 unidades em funcionamento em SP (capital e interior), RJ (capital e Niterói), MG, DF, TO e PR (capital e Londrina). E seguimos crescendo! Vantagens de ser um franqueado Sterna: Apoio na localização e negociação do ponto comercial; Indicação de arquiteto homologado; Suporte completo na implantação da unidade; Treinamento completo para o franqueado; Treinamento operacional para toda a equipe; Apoio total na inauguração da loja; Manuais operacionais completos; Universidade Sterna Café; Fábrica de alimentos própria; Fornecedores homologados; Barista e nutricionista profissionais; Desenvolvimento de novos produtos; Consultoria de campo contínua; Agência de publicidade; Calendário anual de marketing Assessoria de imprensa; Marketing digital: Divulgação nas redes sociais; Convênios com instituições financeiras para financiamento; Associada à ABF', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5b954069-f5fd-4c52-9496-40a58dd5f828.jpg', 90, NULL, NULL, '2026-03-09 19:21:37.192', 'https://franquias.portaldofranchising.com.br/franquia-sterna-cafe-cafeterias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '389000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77vk00qbeh0saoijahzs', 'DENTELAR FRANCHISING', 'dentelar-franchising', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Rede de Clínicas Odontológicas com lucratividade acima da média. Fature R$ 100.000,00 no mês da sua inauguração. Seja Franqueado Dentelar e tenha uma clínica de Sucesso!', 2024, 2024, '[\"https://www.youtube.com/watch?v=Xy5KvtEN5C4\"]', '2026-04-01 02:00:10.545', '2025-08-05 22:20:29.600', 984, NULL, 1, 2012, 'História Dentelar: Dra. Elaine, nordestina e baiana, da cidade de Caetité, sempre sonhou em ser odontóloga. Após concluir o ensino médio, prestou vestibular em duas universidades, sendo aprovada em Belo Horizonte-MG e em Itaúna-MG. Optou por estudar em Itaúna devido às características de uma cidade do interior. Ao concluir a graduação, ela decidiu permanecer em Itaúna, onde iniciou sua carreira profissional em uma clínica local. O destino trouxe o mineiro Edgard para sua vida, e juntos decidiram viver em Itaúna. Posteriormente, decidiram empreender e abriram uma clínica própria. Edgard e Elaine se tornaram referência na cidade, onde se formavam longas filas na porta aguardando atendimento. O sucesso logo resultou na abertura da segunda unidade em Mateus Leme-MG. Nascia assim um modelo de negócio sólido, lucrativo, sustentável e replícavel! O crescimento continuou dando resultados excepcionais, e abriram mais três unidades, em Itaguara, Cláudio e Arcos. Agora a rede conta com cinco unidades próprias e se prepara para levar a Dentelar para todos os cantos do Brasil. A expansão por franquias busca entregar aos novos franqueados um know-how de sucesso desenvolvido, testado e validado ao longo de 12 anos. Como estratégia temos cidades de 30 a 100 mil habitantes para melhor performance das unidades. A Dentelar tem uma lucratividade acima da média, cerca de 30%. Além de faturar logo no primeiro mês R$ 100.000,00. Buscamos dentistas que busquem trocar os seus consultórios para clínicas lucrativas ou empresários que desejam investir em um dos setores que mais lucrativos do Brasil.   Perfil do Franqueado: Dentistas ou investidores que possuem interesse em investir como sócio operador ou sócio investidor em uma clínica Dentelar. O perfil ideal do franqueado para a Dentelar Franchising, preferencialmente, seja um dentista que demonstre habilidades clínica, juntamente com uma paixão pelo setor odontológico e um compromisso com a excelência no atendimento ao paciente. Além disso, é fundamental que o dentista possua um perfil de liderança e habilidades interpessoais para liderar e motivar a equipe, garantindo um ambiente de trabalho positivo e produtivo. O perfil gestor ou administrador deve ser um profissional com perfil executor, organizado e orientado para resultados. Deve possuir noções de gestão e administração, incluindo capacidade de planejamento, controle financeiro e estratégico.   Suporte: Suporte aos nossos franqueados é a nossa prioridade. Queremos construir uma rede com uma cultura forte, padrão e qualidade nos atendimentos. Nosso know-how conta com 12 anos de mercado e processos realmente testados e validados.  Além de manuais oferecemos assistência completa e treinamentos para você franqueado e sua equipe, além de suporte no processo de planejamento, execução e curadoria dos custos da implantação. Temos um time inteiramente capacitado para te auxiliar nessa nova jornada. Nossa equipe te acompanhará desde as escolha do ponto ao dia a dia da gestão de agendas, campanhas de marketing estruturadas e estrtégias para captação de pacientes, um suporte dedicado para melhor performance da sua unidade.   Padrão Dentelar: Nossa estrutura caracterizam-se pelos espaços aconchegantes, qualidade superior dos equipamentos e insumos, além do bom atendimento.', NULL, 'MINAS GERAIS', 1, NULL, 5, NULL, NULL, '2026-03-09 19:23:04.233', 'https://franquias.portaldofranchising.com.br/franquia-dentelar-franchising-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '302000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77vp00qceh0sfexhlgds', 'ODONTO SPECIAL', 'odonto-special', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Rede de clínicas odontológicas com atendimento completo, personalizado e de excelência, unindo tecnologia avançada a cuidados humanizados para transformar sorrisos.', 2018, 2019, '[\"https://www.youtube.com/watch?v=EJCqJu94oTk\"]', '2026-04-01 02:00:10.555', '2025-08-05 22:20:29.606', 985, NULL, 1, 2018, 'A Odonto Special by Sabrina Sato é uma rede de clínicas que oferece o que há de mais moderno em odontologia e estética facial. Contamos com uma equipe altamente qualificada e tecnologia de ponta para oferecer tratamentos completos: limpeza, clareamento, lentes de contato dental, aparelhos ortodônticos, implantes, próteses, tratamentos de canal, cirurgias, além de procedimentos de harmonização orofacial. Nosso compromisso é cuidar da saúde bucal e realçar a beleza do sorriso com conforto, segurança e excelência no atendimento. Com a Odonto Special, você terá a oportunidade de transformar sua clínica atual em uma marca estruturada ou abrir uma nova unidade, com suporte 360°. Números que refletem nosso sucesso: Faturamento médio anual da franquia: R$ 1.8 milhão. Rentabilidade: entre 20% e 30%. Diferencial exclusivo: Você não precisa ser dentista para investir na Odonto Special. A franqueadora oferece um modelo testado e comprovado, com apoio total, transferência de know-how e treinamentos que garantem o sucesso do franqueado. Invista em um dos setores que mais crescem no Brasil: o mercado odontológico — onde saúde, estética e alto potencial de lucro caminham juntos. Suporte de Excelência para os Franqueados: A franqueadora oferece suporte total para os franqueados, garantindo o sucesso da operação através de duas plataformas estratégicas: Universidade Corporativa Presencial: Um centro de treinamento de alto nível, com um auditório moderno e climatizado para até 150 pessoas, oferecendo uma infraestrutura completa, incluindo salas de reunião, espaço exclusivo para franqueados e estacionamento próprio. Universidade Corporativa EAD: Plataforma online com materiais estratégicos essenciais para a operação da franquia, como manuais, peças personalizáveis para ações comerciais, campanhas de marketing, vídeos de treinamentos e muito mais! Liderança e Credibilidade: A Odonto Special by Sabrina Sato é conduzida por grandes nomes do mercado: Sidney Kalaes – Presidente do Grupo Kalaes, holding multissetorial de franquias, com mais de 31 anos de experiência no setor. Líder e fundador de diversas franqueadoras de sucesso. Sabrina Sato – Com seu carisma inconfundível, a apresentadora e empresária transmite autenticidade e confiança, fortalecendo a credibilidade da marca junto ao público. Sua presença inspira autoestima e bem-estar, promovendo uma conexão genuína com os consumidores. Dr. Felipe Abreu – Sócio Fundador, Mestre e Especialista em odontologia (CRO/SP 110.635). É embaixador da Oral-B e tem mais de 19 anos de experiência na área. Venha fazer parte dessa rede de sucesso!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c5481bcc-0926-48f6-935f-c23326e412f3.jpg', 67, NULL, NULL, '2026-03-09 19:24:55.028', 'https://franquias.portaldofranchising.com.br/franquia-odonto-special/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '171300', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77vv00qdeh0sthmri8oe', 'ORAL UNIC IMPLANTES', 'oral-unic-implantes', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Clínica Odontológica Premium, com foco em implantes e experiência do paciente.', 2016, 2019, '[\"https://www.youtube.com/watch?v=TDAA-r8we0M\",\"https://www.youtube.com/watch?v=YB-CE7KIn90\"]', '2026-04-01 02:00:10.565', '2025-08-05 22:20:29.611', 986, NULL, 1, 2016, 'A Oral Unic nasceu em 2016, em Itajaí (SC), com o propósito de transformar vidas por meio de sorrisos e uma gestão de excelência. Em menos de 10 anos, nos consolidamos como a maior franquia de odontologia premium do Brasil, com mais de 300 clínicas em operação, faturamento superior a R$ 1 bilhão pelo segundo ano consecutivo e quatro conquistas do Selo de Excelência em Franchising da ABF. Oferecemos um modelo de negócio sólido, validado e de alta rentabilidade, com uma operação eficiente em um dos setores mais promissores do país. Nosso propósito não é ser apenas a maior, mas sim a melhor franquia odontológica do Brasil. E isso significa entregar o melhor suporte, a melhor implantação, os melhores treinamentos no maior centro de treinamento do franchising e as melhores ferramentas para que nossos franqueados cresçam com consistência e resultado.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/dd0952f4-a7be-4508-94d5-487b9d069212.png', 213, NULL, NULL, '2026-03-09 19:26:24.427', 'https://franquias.portaldofranchising.com.br/franquia-oral-unic-implantes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '614900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77w000qeeh0spgbf1pfy', 'PACÍFICO SEA FOOD', 'pacifico-sea-food', NULL, 'Alimentação', 'Bares e Restaurantes', 'Fast Food de Frutos do Mar com especialidade em Camarão.', 2021, 2022, '[\"https://www.youtube.com/watch?v=zjfY9mdDDl0\",\"https://www.youtube.com/watch?v=jDtUWIhKLdk\"]', '2026-04-01 02:00:10.575', '2025-08-05 22:20:29.617', 987, NULL, 1, 2012, 'O primeiro restaurante Pacífico começou a funcionar em dezembro de 2012, em Pernambuco. Não demorou muito para que o nosso segundo espaço fosse inaugurado no estado. O cardápio do Pacífico foi pensado para oferecer pratos saborosos e com ingredientes de alta qualidade, onde nossa especialidade é frutos do mar, sendo o camarão o nosso principal destaque. Hoje, o Pacífico já é uma marca consolidada na região do Nordeste, presente nos estados de PE, PB, RN e CE, e o sucesso é representado pelas mais de 6.000 refeições servidas mensalmente por cada unidade. O restaurante está em plena expansão e vem se destacando por suas inovações, como os já tradicionais festivais gastronômicos (cardápio temático com pratos exclusivos e temporários) e a Cozinha Show, um inovador sistema, onde os clientes podem ver suas refeições sendo preparadas com todo cuidado e carinho.', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/229546c8-58cd-40e9-9711-1a8813f46912.png', 10, NULL, NULL, '2026-03-09 19:27:11.256', 'https://franquias.portaldofranchising.com.br/franquia-pacifico-sea-food/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '395000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77w500qfeh0skwg2xd6b', 'VALE SAFE', 'vale-safe', NULL, 'Casa e Construção', 'Construção e Reforma', 'Comercialização de Equipamentos de Segurança e Proteção Individual e Coletivo. Roupas e calçados de proteção, luvas, óculos, etc. Placas de avisos, faixas de proteção, segurança no trabalho.', 2016, 2019, NULL, '2026-04-01 02:00:10.584', '2025-08-05 22:20:29.622', 988, NULL, 1, 2012, 'A primeira loja Vale Safe EPI’s nasceu em Taubaté – SP em 2012 a partir da ideia de dois irmãos, um técnico em segurança e outro advogado, que identificaram a necessidade ao prestar serviços de manutenção predial para um de seus clientes na cidade de Jundiaí. Ao perceber como são poucos os fornecedores de equipamentos de segurança e que não oferecem uma boa experiência de compras aos clientes bem como portfolio de produtos inadequado, eles decidiram investir nesse segmento. Com uma loja pequena os negócios foram acontecendo. Muita dificuldade para conhecer e comprar os produtos da maneira correta que o mercado demandava bem como dificuldades com os fornecedores quanto à preços e crédito fizeram parte do processo. Os números da unidade piloto impressionavam os sócios, e ainda impressionam. Crescimento acentuado em tempos de crise mostravam que aquele era o caminho. A ideia sempre foi ter mais unidades, mas como crescer rapidamente e organicamente com velocidade? Foi pensando assim que surgiu a ideia de entrar no franchising em 2016, quando formataram o negocio para receber franqueados e, inclusive quando chegou o primeiro. Agora com alto volume de compras e bom histórico de crédito juntamente ao reconhecimento dos fornecedores inclusive percebida com a participação da maior feira de segurança da América Latina, a FISP 2018. A Vale Safe, hoje pode oferecer uma vantagem muito competitiva ao seus franqueados, aliando uma experiência diferenciada de atendimento, grandes margens nos produtos por meio do exclusivo clube de compras que só os franqueados da rede têm acesso e um know-how completo de produtos numa franquia realmente estável e diferenciada.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/42908bed-f288-477c-9540-92a6124af6bf.png', 46, NULL, NULL, '2026-03-09 19:27:51.738', 'https://franquias.portaldofranchising.com.br/franquia-vale-safe/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '185000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77wa00qgeh0sm55wyqac', 'VALISERE', 'valisere', NULL, 'Moda', 'Vestuários', 'Comércio de moda íntima e acessórios', 2010, 2011, '[\"https://www.youtube.com/watch?v=dEJhTRvv_ZY\"]', '2026-04-01 02:00:10.594', '2025-08-05 22:20:29.627', 989, NULL, 1, 1939, 'A Valisere foi lançada no Brasil em 1934 pelo Grupo Rhodia e, desde então, destaca-se entre as marcas mais importantes no segmento de lingerie do país Em 1986, foi adquirida pelo Grupo Rosset, maior grupo têxtil da América Latina, dando início à revitalização da marca. A Valisere começou a ditar moda no segmento e usar um marketing mais agressivo para conquistas o público jovem, lançando a lendária propaganda “O primeiro sutiã a gente nunca esquece”.    Com posicionamento voltado à informação de moda, é citada como sinônimo de qualidade, conforto e estilo em todo o Brasil. Desenvolve, a cada coleção, novos materiais e modelagens que a colocam à frente do que há de mais novo no mercado.    A renda, utilizada na maioria dos produtos, tornou-se parte do seu DNA. Estampas marcantes e inovadoras, acabamentos de qualidade, modelagens confortáveis e exclusivas, fazem parte da história dos produtos Valisere.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a551103c-7523-414e-92c7-478b2813f7a3.jpg', 49, NULL, NULL, '2026-03-09 19:28:58.643', 'https://franquias.portaldofranchising.com.br/franquia-valisere-vestuario/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c549ed3c-e413-4926-8443-0ea984465e1d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/26cd5655-1714-4688-8248-3c08f34d041c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a1f23c84-f55f-42c6-a102-f2399af9eff2.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/18d93485-3213-4d3f-9362-f1bd160b5365.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77wf00qheh0soy6z8icf', 'CENTURY 21 BRASIL', 'century-21-brasil', NULL, 'Casa e Construção', 'Serviços e Imobiliárias', 'Franquias Imobiliárias', 1971, 2024, '[\"https://www.youtube.com/watch?v=v1efoR1Z_Bw\",\"https://www.youtube.com/watch?v=jt0ivCTL4tg\",\"https://www.youtube.com/watch?v=WTO3zTioO9g\"]', '2026-04-01 02:00:10.603', '2025-08-05 22:20:29.632', 990, NULL, 1, 1971, 'História da Franquia A CENTURY 21® teve início em 1971 na Califórnia, EUA, revolucionando o mercado imobiliário com um Sistema de Franquias que trouxe confiabilidade à figura dos corretores de imóveis. Ao longo de 50 anos, a franquia se expandiu para 86 países, com mais de 14.000 agências e 150.000 corretores filiados, tornando-se a maior rede imobiliária do mundo. No Brasil, a CENTURY 21® oferece uma combinação de tecnologia avançada, treinamentos contínuos e consultoria estratégica, criando um Business Plan eficaz para o sucesso duradouro de nossos franqueados no mercado imobiliário. Com anos de experiência no mercado de franquias, nossas agências se destacam como referências sólidas nas regiões onde operam. Isso garante aos franqueados e corretores uma rentabilidade consistente, enquanto proporcionam aos clientes experiências extraordinárias. Mercado A CENTURY 21® Brasil está inserida em um mercado dinâmico, utilizando plataformas digitais inovadoras para simplificar a busca de imóveis e proporcionar experiências personalizadas para os clientes. A rede tem como pilar central a tecnologia, colocando seus corretores em posição privilegiada para atender às necessidades do mercado moderno. Além disso, os franqueados recebem capacitação e treinamentos constantes, destacando-se no setor imobiliário. Diferenciais 1. Marca Reconhecida: Força e reconhecimento da marca CENTURY 21® que beneficiam a visibilidade e atratividade perante os clientes. 2. Ecossistema completo e eficaz: Franqueados da CENTURY 21® Brasil usufruem de um sistema abrangente que incorpora tecnologia avançada, treinamento contínuo e suporte constante. 3. Investimento em tecnologia: Plataformas digitais inovadoras simplificam processos e melhoram a experiência do cliente. 4. Consultoria Dedicada: Apoio de consultores de campo desde a implantação até as operações diárias, proporcionando segurança e orientação tanto para franqueados quanto para corretores. 5. Treinamento constante: A CENTURY 21® investe intensamente em treinamento para manter seus profissionais atualizados e líderes no setor. 6. Marketing Eficaz: Estratégias de marketing da CENTURY 21® Brasil elevam a visibilidade e atração de clientes. 7. Banco de Dados Compartilhado: Acesso a um banco de dados nacional e internacional expandindo oportunidades de negócios. 8. Parcerias Estratégicas: Colaboração com parceiros de negócios para aumentar conexões e oportunidades no mercado. Junte-se à rede CENTURY 21 Brasil e inicie seu negócio como parte de uma multinacional que traz consigo o selo de líder imobiliária, reconhecida por sua excelência e preferida pelos clientes. Torne-se um empreendedor de sucesso com o apoio de uma marca globalmente renomada.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/eedf5b74-f955-4cfe-b827-2e91dfc5d6f2.png', 6, NULL, NULL, '2026-03-09 19:29:45.540', 'https://franquias.portaldofranchising.com.br/franquia-century-21-brasil/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77wl00qieh0sk2hi6ine', 'BROOMER MEN´S WEAR', 'broomer-men-s-wear', NULL, 'Moda', 'Vestuários', 'Comercialização de produtos de moda masculina, acessórios e cuidados pessoais.', 2000, 2006, '[\"https://www.youtube.com/watch?v=4R6SgPfBB0I\",\"https://www.youtube.com/watch?v=yYC7cOMGTMk\"]', '2026-04-01 02:00:10.612', '2025-08-05 22:20:29.637', 991, NULL, 1, 1998, 'A Franquia Broomer Men´S Wear é uma empresa de vestuário masculino, que atua desde 1989 no mercado de moda, tendo iniciado suas atividades em São Paulo e consolidando seu sucesso durante todos esses anos no estado de Pernambuco, Alagoas, Paraíba e expandindo recentemente para o Ceará e a Bahia. Procurando ampliar seu mercado de atuação e aumentar a abrangência de sua marca, a BROOMER buscou no Sistema de Franquias a melhor estratégia para atingir esse objetivo. Esta estratégia, porém, somente foi adotada em larga escala após mais de 17 anos de amadurecimento da marca e dos processos administrativos e comerciais em suas lojas-piloto. A BROOMER, associada da ABF - Associação Brasileira de Franchising - é uma franquia totalmente formatada e oferece todo o suporte operacional e mercadológico aos seus Franqueados, conforme descrição mais adiante. Missão Proporcionar a satisfação das necessidades de apresentação pessoal, do público masculino de classes A e B. Proporcionar a satisfação da necessidade de as pessoas presentearem, oferecendo um composto ideal de valor (prestígio e preço). Proporcionar lucros crescentes e boa qualidade de vida aos seus sócios através de programas de aperfeiçoamento e de expansão sólidos e consistentes, através de parcerias qualificadas e de longo prazo, assim como a utilização de tecnologia de ponta. Proporcionar aos seus parceiros (funcionários, franqueados e fornecedores) um ambiente saudável de trabalho para realização de suas metas pessoais. Se tornar a empresa a oferecer o melhor composto de valor do mercado aos clientes. Se tornar a melhor empresa de franquia dentro do setor de atuação. Visão A proposta de trabalho da BROOMER, desde sua fundação, é disponibilizar para seus clientes produtos que oferecem conforto, qualidade e design contemporâneo, com preços competitivos. A filosofia dominante nas lojas BROOMER é oferecer total satisfação, através de um atendimento pessoal, voltado para as necessidades específicas de cada cliente. O posicionamento mercadológico é orientado pela qualidade dos tecidos e o cuidado na confecção dos produtos, assim como por cortes confortáveis e design contemporâneo, em sintonia com a tendência da moda internacional. A política de preços é proporcionar números competitivos dentro de um composto de valor, compatíveis com a qualidade oferecida. O conceito de produto da BROOMER é orientado pelas últimas tendências da moda mundial, com a preocupação em adaptá-los ao nosso clima e ao estilo de vida do homem brasileiro. A BROOMER acompanha os acontecimentos do mundo da moda, como feiras, desfiles, entre outros eventos, e desenvolve, em conjunto com seus fornecedores, os produtos de cada linha e coleção. Os produtos são produzidos por uma rede de fornecedores capacitados e especializados, autorizados a confeccioná-los com a marca BROOMER. Suporte ao Franqueado A filosofia da BROOMER é vê-lo como um parceiro de longo prazo, cujo sucesso individual implica no sucesso de toda a rede. Todo o esforço é feito para maximizar sua satisfação e a probabilidade de sucesso de seu investimento. Como franqueado da Broomer você terá acesso aos seguintes serviços: Suporte na escolha de ponto comercial. Planejamento financeiro e Estudo de Viabilidade Econômica. Projeto executivo de arquitetura e projeto luminotécnico. Indicação de fornecedores de obras e equipamentos. Planejamento inicial de compras e pedidos de mercadorias. Acompanhamento da implantação. Treinamentos administrativo, comercial e de produtos. Apoio na seleção inicial e treinamento de pessoal para o quadro de vendas. Apoio na criação da campanha publicitária de inauguração. Apoio na inauguração da unidade. Manuais do Franqueado', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e8fb38e1-f393-4ac5-ab81-ab3eb8920c30.jpg', 12, NULL, NULL, '2026-03-09 19:31:27.745', 'https://franquias.portaldofranchising.com.br/franquia-broomer-mens-wear/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77wq00qjeh0s0bq36q5y', 'ESTETIC FACE', 'estetic-face', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'FRANQUIA DE PROCEDIMENTOS ESTÉTICOS EM HARMONIZAÇÃO FACIAL E CORPORAL', 2019, 2020, NULL, '2026-04-01 02:00:10.622', '2025-08-05 22:20:29.643', 992, NULL, 1, 2018, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5be596b9-9e2c-4891-bf0f-8faa2208258d.png', 32, NULL, NULL, '2025-08-07 09:19:07.000', 'https://franquias.portaldofranchising.com.br/franquia-estetic-face/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77wx00qkeh0sxjf1cxu6', 'LISÔ LASER', 'liso-laser', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'Clínica de Depilação a Laser.', 2022, 2023, '[\"https://www.youtube.com/watch?v=TgmUcj7_2ek\",\"https://www.youtube.com/watch?v=ZU-OrTalgSM\"]', '2026-04-01 02:00:10.630', '2025-08-05 22:20:29.649', 993, NULL, 1, 2021, 'A Lisô Laser é a franquia de depilação a laser que mais cresce no Brasil. Faz parte da We Scale, o maior ecossistema de franquias da América Latina, responsável por marcas como Oral Unic. Com tecnologia 4D exclusiva, operação simplificada e suporte completo, a Lisô oferece um modelo atrativo, escalável e com alto potencial de faturamento.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a78af741-ae62-424c-ba8c-0788df193532.png', 30, NULL, NULL, '2025-10-22 10:36:40.000', 'https://franquias.portaldofranchising.com.br/franquia-liso-laser/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77x200qleh0sjfmyynqp', 'DROGARIAS ÓTIMA FARMA', 'drogarias-otima-farma', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'Uma Rede de Franquias de Drogarias pautada na transparência, profissionalismo e tecnologia, para o crescimento e desenvolvimento de empresários que já atuam no ramo farma e novos empresários.', 2016, 2019, '[\"https://www.youtube.com/watch?v=zkyHsH6Uc-4\",\"https://www.youtube.com/watch?v=gz0BOZM459E\",\"https://www.youtube.com/watch?v=FQnXn73Vtfw\"]', '2026-04-01 02:00:10.640', '2025-08-05 22:20:29.654', 994, NULL, 1, 2016, 'Em dezembro de 2015, Marcelo Ferreira e Juarez Ricardo de Souza, dois empresários com vasta experiência no mercado farmacêutico, com vivência em consultoria empresarial e know-how no sistema de franquias, idealizaram a Rede de Franquias Ótima Farma. No final de 2016, foi inaugurada a Central de Gestão Ótima Farma (sede da franqueadora) e vêm expandindo sua atuação em número de unidades. Atualmente, a franquia possui lojas ativas em sua capital mineira Belo Horizonte, grande BH, São Paulo, Rio de Janeiro, dentre outras cidades. Tendo atuado nos últimos 30 anos no mercado farmacêutico, nossos gestores conhecem a fundo todo o trabalho de expansão e gestão de drogarias. Dessa forma, nosso maior diferencial é poder oferecer aos nossos franqueados todo o suporte necessário para que sua drogaria/farmácia opere de forma competitiva frente a concorrência. Em 2019 passou a integrar o seletivo grupo de associados da ABF (Associação Brasileira de Franchising). No início de 2022, a Ótima Farma foi chancelada pela Associação Brasileira de Franchising (ABF) com o Selo de Excelência que se trata da maior honraria do mercado de franquias Brasileiro. Esta certificação carrega uma história de três décadas e desde então, reconhece o quanto as Franquias têm se destacado e se desenvolvido no país. O Selo de Excelência contribui de maneira ímpar para a Rede Ótima Farma se destacar no meio farmacêutico e continuar sendo referência de qualidade, eficiência do setor e sobretudo alcançar novos territórios. Em 2023 no mês de abril passa a integrar maior federação de farmácia do Brasil, à Febrafar. A Federação Brasileira das Redes Associativas e Independentes de Farmácias, Febrafar, é uma sociedade civil sem fins lucrativos criada em fevereiro de 2000, tendo seu DNA formado por premissas fundamentadas em três fortes pilares: A cultura empreendedora; O relacionamento colaborativo; Atuação visionária. A grandeza em números da Febrafar impressiona: 66 redes de farmácias, com lojas em 26 estados e no Distrito Federal. As mais de 17 mil lojas integradas às redes associadas à Febrafar, em 26 estados + DF, atendem clientes em mais de 3.000 municípios. Em julho de 2023 inicia uma parceria (fusão) com o Grupo Farma. Um grupo com 23 anos no mercado Farma, se uni a Ótima Farma, passando a ser chamada de Grupo Ótima. O Grupo Ótima no mês de setembro/23, já conta com 301 operações em 10 Estados.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e8e0ca68-86bc-424c-82a7-b5c68dff0b56.png', 31, NULL, NULL, '2026-03-09 19:33:48.864', 'https://franquias.portaldofranchising.com.br/franquia-drogarias-otima-farma/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
