INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77xd00qneh0sctflkm7x', 'AGGRO NUTRIÇÃO INTELIGENTE NO CAMPO', 'aggro-nutricao-inteligente-no-campo', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'A Aggro é uma franquia de loja agropecuária, com fábrica própria de nutrição animal e três formatos de operação (campo, express e megastore), atendendo o produtor rural em todas as áreas.', 2020, 2021, NULL, '2026-04-01 02:00:10.658', '2025-08-05 22:20:29.665', 996, NULL, 1, 2020, '', NULL, 'SÃO PAULO', 1, NULL, 40, NULL, NULL, '2025-10-29 14:53:03.000', 'https://franquias.portaldofranchising.com.br/franquia-aggro-nutricao-inteligente-no-campo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '19800', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77xi00qoeh0s9446z3ld', 'QUALITÉ ODONTOLOGIA', 'qualite-odontologia', NULL, 'Saúde, Beleza e Bem Estar', 'ODONTOLOGIA', 'Clínicas Odontológicas', 2022, 2023, NULL, '2026-04-01 02:00:10.667', '2025-08-05 22:20:29.670', 997, NULL, 1, 2016, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d3721c71-63b5-4cd2-b622-bd396880d5d6.png', 4, NULL, NULL, '2025-07-24 13:27:35.000', 'https://franquias.portaldofranchising.com.br/franquia-qualite-odontologia-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77xn00qpeh0s8wqw2yma', 'QG JEITINHO CASEIRO', 'qg-jeitinho-caseiro', NULL, 'Alimentação', 'Bares e Restaurantes', 'Rede de restaurantes especializada no preparo de pastéis, grelhados, frango frito, sanduíches, petiscos com sabor e temperos caseiros.', 2009, 2010, NULL, '2026-04-01 02:00:10.677', '2025-08-05 22:20:29.675', 998, NULL, 1, 1981, 'Somos apaixonados pela arte de cozinhar com temperos frescos, e por cuidar, promover o bem-estar e prolongar a vida das pessoas! \nTemos orgulho em seguir receitas caseiras, testadas pelo tempo e por cozinheiros de mão cheia. Com uma já consolidada experiência em rede de Fast Food, o Grupo QG vem investindo estrategicamente na expansão de suas marcas com foco em inovação e excelência no fornecimento de produtos e atendimento aos seus clientes. \nA franquia QG JEITINHO CASEIRO é desenvolvida através da operação de um estabelecimento comercial no segmento de comida caseira de rápido atendimento, que comercializa alimentos e bebidas em geral, tendo como diferencial a qualidade superior de seus serviços e produtos. \nContamos com 6 modelos de negócios, sendo eles: Container, Shopping e Hipermecado, Loja de Rua, Dark Kitchen (Somente delivery), Double (Cozinha dupla) e Carrinho. Nossos modelos de negócio possibilitam integrar em ambientes de grande fluxo de pessoas como: Shoppings, Hipermercados, Lojas de Rua, Centros Comerciais, Open Mall e outros.\n  10 diferenciais da nossa franquia:  Tradição, com mais de 40 anos no ramo alimentício;\n\t   Somos 3 em 1: QG Jeitinho Caseiro, Chicken Lovers e Bupaqê! 3 cozinhas que atendem a todos os públicos. Menus que contam com pastéis, grelhados, saladas, frango no balde, petiscos, sanduíches gourmets, x-tudo, bebidas e muito mais.\n\t   Qualidade reconhecida pelos consumidores;\n\t   Preços competitivos para uma alimentação no dia-a-dia;\n\t   Vencedora do Selo de Excelência em Franchising pela ABF em 2013, 2014, 2015, 2016, 2017, 2019, 2020 e também vencedora do prêmio “Melhores Franquias do Brasil” pela Pequenas Empresas & Grandes negócios em 2013, 2018, 2019, 2020, 2021 e 2022.\n\t  Oportunidade do franqueado expandir em conjunto com a marca;\n\t  Marca associada à ABF;\n\t  Lucratividade de até 25%;\n\t  Suporte total ao franqueado por Whatsapp, telefone, e-mail e extranet. Além de consultorias presenciais para aprimorar a operação e os resultados da unidade franqueada;\n\t  Possui fábrica própria para garantir sabor exclusivo das marcas.', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a51e6434-81d1-4806-a453-c40db380d6ef.png', 52, NULL, NULL, '2026-03-09 19:35:54.255', 'https://franquias.portaldofranchising.com.br/franquia-qg-jeitinho-caseiro-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '460000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77xs00qqeh0sjp3c8tr2', 'AMAZON SPA', 'amazon-spa', NULL, 'Casa e Construção', 'Construção e Reforma', 'Revenda de banheiras e SPAS de hidromassagem', 2017, 2019, '[\"https://www.youtube.com/watch?v=1r7mqoXEyWI\"]', '2026-04-01 02:00:10.686', '2025-08-05 22:20:29.681', 999, NULL, 1, 2001, 'A Indústria Água Nativa, fundadora da rede de franquias Amazon Spa, nasceu em 2001 em Curitiba no PR, fundada por Edson Schneider. \nAté 2001, Edson trabalhava com piscinas, porém sua inquietação e visão de futuro lhe levou a construir de forma artesanal o primeiro Ofurô da Água Nativa. \nO sucesso de vendas foi imediato, a produção foi crescendo e houve a necessidade de mais espaço físico. \nEm 2003 a Água Nativa foi levada para uma sede definitiva em Campina Grande do Sul/PR, onde contou com mais espaço para ampliação da fábrica. \nTrata-se de 10.000 m² onde se preserva parte da área como reserva ambiental, traduzindo uma preocupação da Água Nativa com o crescimento sustentável. \nEm 2004 banheiras e SPAs entraram na linha de produção. Em 2010, os produtos até então fabricados somente em Gel Coat, passaram a ser fabricados também em acrílico, uma tecnologia mais moderna.  \nA primeira loja Amazon SPA, que foi uma loja piloto, inaugurada em 2008 e administrada pela Fábrica Água Nativa até 2018. \nA segunda loja foi criada em 2013 e foi administrada pela Fábrica Água Nativa até 2016 com o objetivo de conhecer as necessidades do varejo.  \nA Indústria Água Nativa operou duas lojas próprias no varejo com o objetivo de conhecer o varejo, as necessidades do consumidor final e adequar as lojas ao sistema de Franquias. \nAtualmente ambas as lojas são Franquias operadas por Franqueados. \nEm 2020, a Água Nativa - usando a marca Amazon SPA, estava definitivamente preparada para dar início a abertura de mercado com franquias. \nAtualmente a marca possui 4 lojas Amazon SPA franqueadas.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b9a82366-01fd-455e-979c-deaca2ee66cf.jpg', 9, NULL, NULL, '2026-03-09 19:37:16.437', 'https://franquias.portaldofranchising.com.br/franquia-amazon-spa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '67700', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77xx00qreh0swkvjog9z', 'ALLMAT', 'allmat', NULL, 'Casa e Construção', 'Construção e Reforma', 'Franquia de lojas de materiais de construção.', 2025, 2025, NULL, '2026-04-01 02:00:10.695', '2025-08-05 22:20:29.686', 1000, NULL, 1, 2025, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d1e67c2f-8784-414e-9182-e3a5c1cabd61.png', 4, NULL, NULL, '2026-03-09 19:38:23.073', 'https://franquias.portaldofranchising.com.br/franquia-allmat/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77y300qseh0sbr6fe45f', 'FOR RENTAL', 'for-rental', NULL, 'Casa e Construção', 'Construção e Reforma', 'Somos uma empresa especializada em aluguel de equipamentos para construção civil, limpeza e jardinagem um dos principais pilares do PIB Nacional', 2015, 2016, '[\"https://www.youtube.com/watch?v=ZiFOVU4f76I\",\"https://www.youtube.com/watch?v=yMsywvJtOlU\"]', '2026-04-01 02:00:10.705', '2025-08-05 22:20:29.691', 1001, NULL, 1, 2015, 'Obrigado pelo seu interesse em conhecer a For Rental. Nossa Empresa foi criada com muito amor e dedicação. Nossa história foi escrita com ética, com responsabilidade social, pela paixão ao trabalho, devotada à sustentabilidade, à inovação, manifestada na excelência do atendimento ao cliente, no respeito humano.  História escrita por Daniel Rodrigues de Souza com expertise de 30 anos no segmento de Franchising, desde sua constituição foi planejada para fazer parte do seguimento de Franchising no Brasil no segmento de Aluguel de Equipamentos para Construção, Limpeza e jardinagem um dos setores que mais cresce no mundo. \nUma Empresa Genuinamente Brasileira, que tem em sua Missão, Visão e Valores zelar por um Brasil melhor, com mais condições de igualdade para todos, viabilizando para empreendedores e investidores de ter seu próprio negócio com maiores chances de sucesso em um mercado duro em uma relação “ganha & ganha” e duradora.  Negócio Aluguel de equipamentos para: Construção; Limpeza; Jardinagem.\n\t  Experiência dos proprietários da For Rental: 30 anos de experiência no Franchising; \n\t  Diferencias For Rental: Todos modelos começam com o mesmo investimento “Start” de negócio, facilitando o início do negócio com investimentos reduzidos projetando investimentos gradativos; Quadro de funcionários baixo. Taxa de Retorno sobre o investimento total de 6%; Investimento totalmente customizado por mercado; Margem acima do mercado de 20 a 40% ou de R$ 16.000,00 a R$ 32.000,00 por mês; Suporte presencial Pré e Pós- inauguração; Os primeiros seis meses de atividade da unidade, nós não cobramos Royalties*; Não cobramos fundo de propaganda; O Royalty é cobrado somente sobre Faturamento de Locação os outros faturamentos, Frete, Serviços e Manutenção de Equipamentos não são cobrados Royalties, sendo totalmente livre para o Franqueado; Garantia de proposta de recompra de sua unidade após o período mínimo de dois anos de atividade caso não tenha atingindo a margem líquida proposta mínima de 20%, com base na avaliação feita pela Franqueadora de uma proposta utilizando dados do Software de Gestão For Rental caso a unidade não esteja atingido o payback proposto pela Franqueadora em contrato 24 a 36 meses; Plano de expansão interna: Queremos que nossos franqueados tenham amplitude em sua região com a preferência de territórios próximos aumentando seu raio de atuação e de maneira que tenhamos menos franqueados com mais franquias;  Ponto de equilíbrio em aproximadamente nove meses; Payback de equipamentos aproximadamente em 12 meses; Sábado e Domingo estará em sua casa cuidando de seu maior bem, sua Família.     *Com o pagamento integral da Taxa de Franquia   Não seja mais um Franqueado, seja “O Franqueado” For Rental   “Dê uma Oportunidade ao seu Sucesso”', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1384563c-73c1-41cc-910f-04447848fa21.jpg', 19, NULL, NULL, '2026-03-09 19:38:42.762', 'https://franquias.portaldofranchising.com.br/franquia-for-rental/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '190000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77y900qteh0s1pvz5pou', 'HAVAIANAS', 'havaianas', NULL, 'Moda', 'CALÇADOS', 'Loja exclusiva de produtos Havaianas, coleção de sandálias, chinelos e acessórios.', 2008, 2009, NULL, '2026-04-01 02:00:10.714', '2025-08-05 22:20:29.698', 1002, NULL, 1, 1962, 'SOBRE A FRANQUIA HAVAIANAS Simples, cool, intensa e democrática, assim é Havaianas, a sandália mais famosa do mundo que desde 1962 faz parte da vida dos brasileiros. Atualmente nossas sandálias são exportadas para mais de 120 países. São cerca de 200 modelos, que somados as cores e estilos, chegam a mais de 1.200 sandálias diferentes. Não importa a classe social, o estilo, o sexo ou a idade, você sempre encontrará uma Havaianas para fazer a sua cabeça. INFORMAÇÕES DA FRANQUIA As lojas Havaianas foram idealizadas para oferecer aos consumidores uma experiência completa com a marca. O modelo de franquia foi adotado porque acreditamos que empresários locais que se identifiquem com a marca e com nosso negócio podem agregar conhecimento e experiência regional, fundamental para o sucesso das lojas. INVESTIMENTO: Taxa de Franquia = R$ 45.000,00 (quarenta e cinco mil reais); Instalação da Loja: De 255.000,00 a 800.000,00 (Duzentos e cinquenta e cinco mil reais a Oitocentos mil reais). INVESTIMENTO TOTAL: (incluindo taxa de franquia + instalação + estoque) De R$ 300.000,00 a R$ 845.000,00 (média) Não cobramos royalties; O franqueado destinará 2% de seu faturamento bruto mensal para investimento em MKT local para divulgação de sua loja ( A franqueadora não recolherá esse valor); Pay Back estimando: de 12 a 36 meses; Custo do ponto comercial (luvas) não está incluído no investimento e no cálculo de pay back (retorno).', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/09c5ac55-4c85-4ba2-bd85-172cb9e7144e.jpg', 712, NULL, NULL, '2026-02-05 15:48:53.000', 'https://franquias.portaldofranchising.com.br/franquia-havaianas-valor/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4cfa89cd-63cd-44b4-b516-a02f7504261c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/345b39fa-edb6-44f7-9ad0-b2230a23080a.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '235000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
