INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77yq00qweh0sk8vd8h1z', '4ESTYLO’S', '4estylo-s', NULL, 'Alimentação', 'Bares e Restaurantes', 'Pizzaria', 2020, 2025, NULL, '2026-04-01 02:00:10.743', '2025-08-05 22:20:29.714', 1005, NULL, 1, 2010, '', NULL, 'CEARÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2229bb24-0203-41b6-9d76-a4967d66b128.png', 15, NULL, NULL, '2026-03-09 19:40:57.597', 'https://franquias.portaldofranchising.com.br/franquia-4estylos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77yv00qxeh0s1jke0r6u', 'O BURGUÊS', 'o-burgues', NULL, 'Alimentação', 'Bares e Restaurantes', 'O Burguês iniciou sua operação com uma loja em 2017. Com produtos de alta qualidade e um modelo de negócio de administração simples. Hoje se consolida como a maior hamburgueria delivery do Brasil.', 2018, 2019, NULL, '2026-04-01 02:00:10.754', '2025-08-05 22:20:29.719', 1006, NULL, 1, 2017, 'Criado com o intuito de inovar no serviço delivery do mercado de hambúrgueres no Rio de Janeiro, O Burguês iniciou sua operação com uma loja em fevereiro de 2017. \nProdutos de alta qualidade aliados a um modelo de negócio de administração simples e de baixo risco fizeram a marca superar as expectativas do segmento, e alcançar, em 3 anos, um crescimento meteórico em número de lojas. \nEm 2020 passamos a operar com 21 lojas, sendo 6 fora do Rio (3 em São Paulo, 1 em Brasília/DF, 1 em Vitória/ES e 1 em Belo Horizonte/MG). \nHoje nos consolidamos como a maior hamburgueria delivery do Brasil, inseridos de acordo com a ABRASEL (Associação de Bares e Restaurentes) em um mercado que só vem crescendo, o de conveniência (delivery), com um faturamento estimado em R$ 20 milhões em 2020. \nSomos Key account de um dos principais aplicativos delivery da atualidade, tendo promoções personalizadas entre outras vantagens.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0497805e-5ae3-46ff-a7cc-1fa45ace38a1.png', 59, NULL, NULL, '2026-03-09 19:42:14.001', 'https://franquias.portaldofranchising.com.br/franquia-o-burgues/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '450000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77z100qyeh0s1irb5njw', 'GOLLOG', 'gollog', NULL, 'Serviços e Outros Negócios', 'Logística e Operações', 'Transporte de cargas', 2005, 2011, NULL, '2026-04-01 02:00:10.764', '2025-08-05 22:20:29.725', 1007, NULL, 1, 2001, 'Só a Gollog, serviço de cargas da GOL, conta com a infraestrutura de uma das maiores companhias aéreas do país em seu negócio. \nSão mais de 100 unidades que atendem cerca de 3.500 cidades em todo o Brasil.  Marca Conhecida \nCrescimento 2 vezes maior que a dos principais concorrentes Mais de 1 milhão de encomendas emitidas anualmente Sete bases internacionais: Buenos Aires, Rosário e Córdoba (Argentina), Assunção (Paraguai), Santa Cruz de la Sierra (Bolívia), Santiago (Chile) e Montevidéu (Uruguai). \nE as vantagens não param por aí, como franqueado Gollog você ainda conta com benefícios de orientação e assessoria, antes e após a inauguração da sua franquia.  Antes da Abertura \n - Uso da marca Gollog;\n - Treinamento de pré-inauguração;\n - Orientação e suporte na aquisição de todos os equipamentos e materiais padronizados, junto a fornecedores licenciados;\n - Fornecimento dos Manuais de identidade visual (papelaria/veículos/uniformes);\n - Orientação ao Franqueado na reforma, construção ou adaptação do imóvel onde será instalada sua Franquia, garantindo que o mesmo esteja conforme os padrões da rede Gollog;\n - Após a Inauguração Consultoria de campo com visitas periódicas de acompanhamento e assessoria, para garantir a padronização da rede e o desenvolvimento da Franquia;\n - Apoio através de treinamentos e reciclagens; Assessoria, desenvolvimento, aperfeiçoamento e fornecimento do software utilizado pelo Sistema Gollog e outros instrumentos necessários à administração da Franquia;\n - Coordenação de toda propaganda e promoção da marca e da rede Gollog;\n - Desenvolvimento constante de novas técnicas de gestão e de atuação, para manter a rede atualizada às necessidades dos clientes;  Escolha entre 4 modalidades de franquia: \nCentro Operacional \n - Venda de carga expressa e convencional;\n - Coletas domiciliares;\n - Triagem, manuseio de cargas fracionadas e outros objetos;\n - Entrega domiciliar, ao cliente destinatário, de cargas ;  Loja \n - Venda de carga expressa e convencional;\n - Coletas domiciliares;\n - Remessa de volumes para os Terminais Operacionais Comerciais;\n - Informatização das operações;  Quiosque Gollog \nSó a Gollog, serviço de cargas da GOL, conta com a infraestrutura de uma das maiores companhias aéreas do país em seu negócio. \nSão mais de 100 unidades que atendem cerca de 3.500 cidades em todo o Brasil.  Marca Conhecida \nCrescimento 2 vezes maior que a dos principais concorrentes Mais de 1 milhão de encomendas emitidas anualmente Sete bases internacionais: Buenos Aires, Rosário e Córdoba (Argentina), Assunção (Paraguai), Santa Cruz de la Sierra (Bolívia), Santiago (Chile) e Montevidéu (Uruguai). \nE as vantagens não param por aí, como franqueado Gollog você ainda conta com benefícios de orientação e assessoria, antes e após a inauguração da sua franquia.  Antes da Abertura \n - Uso da marca Gollog;\n - Treinamento de pré-inauguração;\n - Orientação e suporte na aquisição de todos os equipamentos e materiais padronizados, junto a fornecedores licenciados;\n - Fornecimento dos Manuais de identidade visual (papelaria/veículos/uniformes);\n - Orientação ao Franqueado na reforma, construção ou adaptação do imóvel onde será instalada sua Franquia, garantindo que o mesmo esteja conforme os padrões da rede Gollog;\n - Após a Inauguração Consultoria de campo com visitas periódicas de acompanhamento e assessoria, para garantir a padronização da rede e o desenvolvimento da Franquia;\n - Apoio através de treinamentos e reciclagens; Assessoria, desenvolvimento, aperfeiçoamento e fornecimento do software utilizado pelo Sistema Gollog e outros instrumentos necessários à administração da Franquia;\n - Coordenação de toda propaganda e promoção da marca e da rede Gollog;\n - Desenvolvimento constante de novas técnicas de gestão e de atuação, para manter a rede atualizada às necessidades dos clientes;  Escolha entre 4 modalidades de franquia: \nCentro Operacional \n - Venda de carga expressa e convencional;\n - Coletas domiciliares;\n - Triagem, manuseio de cargas fracionadas e outros objetos;\n - Entrega domiciliar, ao cliente destinatário, de cargas ;  Loja \n - Venda de carga expressa e convencional;\n - Coletas domiciliares;\n - Remessa de volumes para os Terminais Operacionais Comerciais;\n - Informatização das operações;  Quiosque \n - Venda  Container \n - Venda  Container \n - Venda', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/81a34907-b5e9-4c07-b106-2211c5783faf.png', 130, NULL, NULL, '2026-03-09 19:42:54.633', 'https://franquias.portaldofranchising.com.br/franquia-gollog/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '139312.5', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77z600qzeh0s6mr8324j', 'MONSTER DOG', 'monster-dog', NULL, 'Alimentação', 'Bares e Restaurantes', 'Ramo alimentício de comida rápida vendendo hot-dog, hambúrgueres, salgados, pão de queijo, refrigerantes e sucos. Pontos entre 2,5m² e 100m², segmentado à classe B, C e D, ao público em geral.', 2016, 2018, NULL, '2026-04-01 02:00:10.775', '2025-08-05 22:20:29.730', 1008, NULL, 1, 2002, 'A marca Monster Dog foi criada em 2007 com sua primeira loja no terminal rodoviário urbano Vila Nova Cachoeirinha, atualmente além dessa contamos com mais duas unidades da marca no mesmo local. O Monster Dog surgiu com a idéia de unificar a comida rápida de rua com a qualidade e garantia de marcas reconhecidas no mercado. Sempre servindo os melhores lanches com qualidade, agilidade, simpatia e o diferencial de ter preços acessíveis.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0f04b2f8-8cc6-4f68-86e6-812c4435f4fb.jpg', 60, NULL, NULL, '2026-03-09 19:45:06.045', 'https://franquias.portaldofranchising.com.br/franquia-monster-dog/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zb00r0eh0sxp8j6nl4', 'BISCOITÊ', 'biscoite', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Biscoitos especiais para presentes e cafeteria.', 2018, 2021, NULL, '2026-04-01 02:00:10.785', '2025-08-05 22:20:29.735', 1009, NULL, 1, 2012, 'A Biscoitê é uma boutique de biscoitos finos. Das receitas às embalagens, tudo é criado com tempo, cuidado e dedicação. \nAs receitas são inspiradas em diferentes culturas e preparadas com ingredientes da melhor qualidade. \nCriada desde 2012 com outro nome, a Biscoitê transformou-se em um case de sucesso a partir de 2016. \nSendo a única franquia do Brasil a atuar no mercado de biscoitos, mercado este, maior que o de chocolate, chegando a ter mais de R$20 bilhões vendidos todos os anos no mundo. \nCom o propósito de transformar a vida das pessoas através de momentos, biscoitos e presentes feitos com amor e unindo-se a uma identidade consolidada, um forte marketing, fidelização de produtos e lançamentos, seu ticket médio de faturamento é 3x maior que o de uma cafeteria.  \nPreocupada em atender todos os públicos, a Biscoitê se diferencia pela grande quantidade de tipos de biscoitos. \nAlém dos tradicionais, existe a linha kids, a zero (glutén e lactose) e salgados e muito mais. \nA Biscoitê não vende só produtos, vende momentos e, pensando nisso, a linha de biscoitos sazonais proporciona experiências incríveis nas datas comemorativas mais marcantes do ano, como Natal, Páscoa, Dia das Mães, Dia dos Pais, Dia dos Professores, entre outros.  \nCom a Biscoitê, a oportunidade de faturamento pode acontecer de diversas maneiras: vendas por delivery, parceria com lojistas, vendas corporativas, além da presença em eventos. \nO franqueado da Biscoitê conta com todo o suporte e treinamento para que sua loja tenha o mais excelente serviço que a boutique tem a oferecer.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ce581b0a-5c78-4d66-8ed3-fc5d838086dc.jpg', 63, NULL, NULL, '2026-03-09 19:45:37.372', 'https://franquias.portaldofranchising.com.br/franquia-biscoite/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zg00r1eh0smiu6yd5i', 'BIO MUNDO', 'bio-mundo', NULL, 'Alimentação', 'Mercados e Distribuição', 'suplementos, produtos naturais e a granel.', 2017, 2018, '[\"https://www.youtube.com/watch?v=NrOFA7TdEBk\"]', '2026-04-01 02:00:10.795', '2025-08-05 22:20:29.741', 1010, NULL, 1, 2015, 'Nascida em 2015, a Bio Mundo já nasceu sendo um tremendo sucesso: somente no primeiro ano como franquia já foram mais de 23 operações ativas, representando um recorde do período quando se fala em franquias de alimentação saudável. Atualmente, já são mais de 150 franquias franqueados na rede, presentes em mais de 17 estados do país.  \nAlém disso, a franquia já foi premiada com o Selo de Excelência em Franchising dado pela Associação Brasileira de Franquias (ABF).  Isso porque a Bio Mundo é a loja de produtos naturais mais completa do mercado. \nO seu mix de produtos consiste em mais de 10 mil itens entre 3 principais categorias: a linha a granel, a linha de nutrição espotiva esportiva e os produtos naturais.  \nEssa diversificação permite atrair mais clientes em suas lojas e, consequentemente, garante um maior faturamento para os seus franqueados. Sendo uma rede especialista em pontos de loja física, a franquia trabalha com lojas  entre 45m² a 100m², adaptados de acordo com a realidade do local, seja na rua, shopping, aeroporto, centros comerciais, galerias e hipermercados. Ter uma franquia Bio Mundo é ter nas mãos a oportunidade de trabalhar com produtos de alta qualidade, recebendo suporte completo da franqueadora.', NULL, 'DISTRITO FEDERAL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/28e65033-3cc2-4c55-89e0-13798e77370b.jpg', 151, NULL, NULL, '2026-03-09 19:46:33.264', 'https://franquias.portaldofranchising.com.br/franquia-bio-mundo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '285000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zl00r2eh0sxk2yky32', 'MEGA VISAO FRANQUIAS LTDA', 'mega-visao-franquias-ltda', NULL, 'Saúde, Beleza e Bem Estar', 'ÓTICAS', 'saude visual', 2023, 2025, NULL, '2026-04-01 02:00:10.806', '2025-08-05 22:20:29.745', 1011, NULL, 1, 2008, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9aea7aff-8886-49cc-85f9-c4a62ebdd938.png', 3, NULL, NULL, '2025-07-28 08:28:17.000', 'https://franquias.portaldofranchising.com.br/franquia-mega-visao-franquias-ltda-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zr00r3eh0sge8bqk5l', 'BOALI', 'boali', NULL, 'Alimentação', 'Bares e Restaurantes', 'Segmento de \"healthy fast food\" com cardápio completo que abrange saladas, wraps, bowls, crepes, burritos, sucos e sobremesas com foco na saudabilidade, sustentabilidade e praticidade.', 2007, 2016, '[\"https://www.youtube.com/watch?v=pQ_BcarSQJk\",\"https://www.youtube.com/watch?v=bAEwka1Qd_Q\",\"https://www.youtube.com/watch?v=DQhq-xw_QMc\"]', '2026-04-01 02:00:10.816', '2025-08-05 22:20:29.752', 1012, NULL, 1, 2007, 'Nossa história começa em 2006 quando 4 amigos se unem com um objetivo em comum que é transformar os hábitos alimentares da população, e trouxeram para o Brasil a primeira rede de alimentação saudável do mundo, a Marca Americana Salad Creations. Em 2007 foi inaugurada a primeira loja conceito em um Shopping Center localizado na zona oeste da capital paulistana. Após uma grande experiência em gestão de rede de alimentação saudável e varejo, em 2015 os sócios fundam a BOALI com o propósito de universalizar o acesso a alimentação saudável e transformar hábitos e fazer o bem por meio da comida. A Marca BOALI é derivada da união das palavras “boa” e “alimentação”, foi criada para ser um sinônimo de comida gostosa, saudável, prática e acessível.    Nascida com o intuito de oferecer uma relação sustentável e saudável à sociedade e à natureza, a Franqueadora busca constantemente, por meio da criatividade e inovação no desenvolvimento dos produtos comercializados, contribuir com a possibilidade de implantar um novo mundo, em que o respeito ao meio ambiente e às pessoas, reflitam à comercialização de uma alimentação saborosa e saudável. Nosso cardápio é, portanto, composto por ingredientes nobres e de alta qualidade, e nossos pratos são elaborados com o objetivo de atender ao público de maneira geral. Por esta razão, a BOALI considera-se uma Marca democrática, abrangente e plural. Somos feitos de pessoas e focados em transformar a vida das pessoas. Vamos juntos inspirar mudanças e promover o bem com otimismo e vitalidade. BOALI Uma marca 100% brasileira Gente de verdade, fazendo COMIDA DE VERDADE e com um propósito de verdade', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0c2b72fd-8ba9-45e1-a2da-ee0b517a852b.png', 97, NULL, NULL, '2026-03-09 19:47:40.905', 'https://franquias.portaldofranchising.com.br/franquia-boali-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '264000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zw00r4eh0s48acn33g', 'DEEP FREEZE', 'deep-freeze', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Alimentos Congelados Artesanais Deep Freeze', 2016, 2017, NULL, '2026-04-01 02:00:10.826', '2025-08-05 22:20:29.757', 1013, NULL, 1, 1982, '', NULL, 'RIO DE JANEIRO', 1, NULL, 7, NULL, NULL, '2025-08-22 18:20:22.000', 'https://franquias.portaldofranchising.com.br/franquia-deep-freeze-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '315000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza780200r5eh0smmdiibiw', 'GRUPO TUDODVET', 'grupo-tudodvet', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', 'FARMÁCIA DE MANIPULAÇÃO VETERINÁRIA', 2019, 2023, NULL, '2026-04-01 02:00:10.835', '2025-08-05 22:20:29.762', 1014, NULL, 1, 2014, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/40980478-82ba-4136-8bb9-53d221f27fc4.png', 3, NULL, NULL, '2026-03-09 19:49:01.127', 'https://franquias.portaldofranchising.com.br/franquia-grupo-tudodvet-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza780700r6eh0sg38i8dno', 'BONAPARTE', 'bonaparte', NULL, 'Alimentação', 'Bares e Restaurantes', 'O requinte e a criatividade de suas receitas inovaram o conceito de refeições rápidas. Utilizando ingredientes nobres com rigor e padronização no preparo dos pratos de alto padrão.', 1998, 1995, NULL, '2026-04-01 02:00:10.844', '2025-08-05 22:20:29.767', 1015, NULL, 1, 1998, 'O Restaurante Bonaparte surgiu em março de 1998, com a certeza de que fast-food não precisava ser sinônimo de pratos mal apresentados, falta de requinte e criatividade. \nO propósito do restaurante é atender às necessidades do consumidor de fast-food, preenchendo uma lacuna existente. \nSeu maior trunfo está na racionalização do cardápio e na otimização do espaço físico. \nAs cozinhas dos restaurantes Bonaparte foram planejadas para dar ao cliente total visibilidade do que se passa no seu interior. \nSeu projeto arquitetônico é limpo e moderno, priorizando materiais como aço inoxidável, vidro e cerâmica, para facilitar a limpeza. \nA qualidade do atendimento também é prioridade no Bonaparte. Seus funcionários são bem treinados e têm total compromisso com a satisfação do cliente. \nTudo para oferecer o melhor serviço e as melhores refeições. \nJunte sabor e praticidade, acrescente qualidade em tudo e ponha uma grande porção de clientes satisfeitos. \nEssa é a receita de sucesso do Bonaparte. \nSeu cardápio variado, que vai de carnes, risotos, saladas e frutos do mar, é a melhor pedida para quem quer fazer um bom negócio.', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c886c108-94f4-46ed-8124-09d32ce8de49.png', 13, NULL, NULL, '2026-03-09 19:49:24.794', 'https://franquias.portaldofranchising.com.br/franquia-bonaparte-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
