INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza780g00r8eh0s06o5rwxv', 'PAPA\'S HOT DOG', 'papa-s-hot-dog', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'Venda de hot dog artesanais e petiscos', 2022, 2022, NULL, '2026-04-01 02:00:10.862', '2025-08-05 22:20:29.777', 1017, NULL, 1, 2012, '', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/37abd0c2-5bea-42d4-b6f1-25f9d4e7e4b3.png', NULL, NULL, NULL, '2025-09-12 14:48:56.000', 'https://franquias.portaldofranchising.com.br/franquia-papas-hot-dog-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
