INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781100rceh0svdvf89mt', 'CORRETORPRO', 'corretorpro', NULL, 'Casa e Construção', 'IMOBILIÁRIAS', 'Franquia imobiliária especializada em intermediação de imóveis, lançamentos, estruturação de empreendimentos e serviços financeiros ao cliente final.', 2025, 2025, NULL, '2026-04-01 02:00:10.903', '2025-08-05 22:20:29.797', 1021, NULL, 1, 2015, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c8a5f241-1efe-4f40-a649-6bf8b936b191.png', NULL, NULL, NULL, '2025-07-29 11:04:45.000', 'https://franquias.portaldofranchising.com.br/franquia-corretorpro-casa-e-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781500rdeh0sfa93o2kk', 'BRASTEMP', 'brastemp', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Locação de Purificadores e Prestação de Serviço', 2014, 2017, NULL, '2026-04-01 02:00:10.913', '2025-08-05 22:20:29.802', 1022, NULL, 1, 1954, 'A Brastemp é uma das marcas mais fortes, conhecidas e respeitadas do Brasil, e líder absoluta em preferência na categoria de eletrodomésticos.1 Ao perceber uma crescente procura por Purificadores de Água no Brasil, a Brastemp realizou uma análise criteriosa deste mercado no país, identificando uma grande oportunidade de negócio: levar água pura de verdade aos seus consumidores por meio de assinatura mensal.  A ideia foi um grande sucesso. O que levou a Brastemp aderir ao sistema de franquia para melhor administrar e atender a demanda de expansão deste serviço e modelo de negócio pioneiro para todo o Brasil.  1Fonte: pesquisa da revista Forbes.', NULL, 'SÃO PAULO', 1, NULL, 18, NULL, NULL, '2026-03-09 19:55:27.815', 'https://franquias.portaldofranchising.com.br/franquia-brastemp-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '180000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781b00reeh0spp6dpsox', 'APOLAR IMÓVEIS', 'apolar-imoveis', NULL, 'Casa e Construção', 'Serviços e Imobiliárias', 'Franquia Imobiliária', 1995, 2011, '[\"https://www.youtube.com/watch?v=9Or4cOlvgSw\",\"https://www.youtube.com/watch?v=aPWtMK7N_d0\",\"https://www.youtube.com/watch?v=CfW0-eElJyE\",\"https://www.youtube.com/watch?v=hmdJHWmmcV8\"]', '2026-04-01 02:00:10.923', '2025-08-05 22:20:29.807', 1023, NULL, 1, 1969, 'Com mais de meio século de atuação no mercado imobiliário, 68 franquias e mais 20 pontos de atendimento, somos a Apolar Imóveis. \nPioneira no Brasil na área de franquias, sendo uma das líderes do setor imobiliário no sul do país. \nNascemos de um sonho, aparentemente distante de ser alcançado, mas possível de ser realizado. \nCom persistência e dignidade, chegamos aonde queríamos, somos sinônimo de felicidade. \nNosso modelo rentável de negócio, proporciona aos nossos parceiros o sucesso que eles almejam. \nSomos uma rede de imobiliárias organizadas em forma de franquias, tendo por objetivo o sucesso de todo o ecossistema, buscando permanentemente a complementaridade, o aumento da produtividade e velocidade dos negócios através da união com parceiros e entre parceiros. \nSomos a rede com maior número de vendas compartilhadas, afinal, nossa missão é proporcionar a melhor experiência para nossos clientes e o trabalho em rede possibilita que nosso público tenha acesso a mais de 5 mil imóveis com gestão exclusiva e que ele possa negociar em qualquer localidade onde há uma loja Apolar, independente de cidade ou estado. \nInvestimos em tecnologia, usabilidade e inovação, pois o futuro é agora e o sucesso não espera. Nossos parceiros contam com o apoio de um departamento especializado e um software diferenciado, criado e desenvolvido pela Apolar, onde o usuário tem acesso a todas as ferramentas imobiliárias em um só lugar. \nNossa variedade de serviços, torna a Apolar uma referência no segmento. \nAtuamos no setor de Venda, Locação, Consórcio, Short Stay, Real Estate Triple A, Built For Business, Lançamentos, Feirão Apolar e Apolar Procura. \nTudo idealizado para auxiliar no êxito nas negociações de nossos parceiros. \nO trabalho da diretoria da Apolar é fortalecer o mercado imobiliário, onde atuamos em todos os órgãos do setor, buscando e apoiando os avanços do segmento. \nSomos uma marca de sucesso, somos a Apolar Imóveis.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/259eaee5-3f75-4014-81a5-cd2c1a13abd0.png', 78, NULL, NULL, '2026-03-09 19:56:02.714', 'https://franquias.portaldofranchising.com.br/franquia-apolar-imoveis-imobiliarias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '99000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781g00rfeh0sz4706juu', 'CAPITANO', 'capitano', NULL, 'Alimentação', 'Mercados e Distribuição', 'Franquias de Peixarias e Distribuidoras de Pescados - Lojas para atender Varejo e Atacado da sua cidade com os melhores peixes e frutos do mar do Brasil! Produtos já limpos e embalados', 2021, 2022, '[\"https://www.youtube.com/watch?v=vMyc_s3V57o\",\"https://www.youtube.com/watch?v=U4s3l1txCP4\",\"https://www.youtube.com/watch?v=kFchjXOWYbo\"]', '2026-04-01 02:00:10.932', '2025-08-05 22:20:29.812', 1024, NULL, 1, 2003, 'A CAPITANO é uma distribuidora de pescados que atua há mais de 40 anos nos mercados brasileiro e internacional, fornecendo cortes de peixes e frutos do mar em geral de alta qualidade, atendendo desde consumidores residenciais e varejistas, até grandes redes de mercados e outros atacadistas. Nossa sede é localizada em Cabo Frio (RJ), onde recebemos boa parte dos pescados que comercializamos e cuidadmos de todas as etapas de produção. Desde a descarga dos pescados frescos dos barcos, passando pelas etapas de seleção de qualidade e processamento da proteína, até a distribuição e venda direta nos PDVs da marca. Os modelos de loja da Capitano contém produtos 100% limpos e embalados, que entregam uma qualidade idêntica ao peixe fresco, recém saído do mar. Com técnicas próprias e uma metodologia desenvolvida há décadas, somos reconhecidos pela excelência dos cortes que preparamos e pela eficiência no atendimento a diversos segmentos de food service distintos: bares, restaurantes, hoteis, pousadas, quiosques, mercados e mais. Polvo, Lagosta, Vieiras, Salmão, Camarão, Tilápia e tudo o que você precisa do mar, você encontra na Capitano!', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ceb4d9f6-a744-49fc-bb47-36258a0b7cde.jpg', 9, NULL, NULL, '2026-03-09 19:57:10.755', 'https://franquias.portaldofranchising.com.br/franquia-capitano/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '92500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781l00rgeh0sexevad0g', 'NOCTA', 'nocta', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'A Nocta atua no mercado há 20 anos com abrangência nacional, comercializando planos de saúde, odontológico, seguros e outros ramos, oferecendo as melhores soluções a todos perfis de clientes.', 2023, 2024, NULL, '2026-04-01 02:00:10.941', '2025-08-05 22:20:29.817', 1025, NULL, 1, 2005, '', NULL, 'SÃO PAULO', 1, NULL, 12, NULL, NULL, '2025-08-20 22:38:21.000', 'https://franquias.portaldofranchising.com.br/franquia-nocta-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '9990', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781q00rheh0saeuhnjj7', 'DEPYL ACTION', 'depyl-action', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Cuidados com pele, pelo e embelezamento do olhar', 1996, 2005, '[\"https://www.youtube.com/watch?v=bne3Mci-w_s\",\"https://www.youtube.com/watch?v=qEGc19Kzxys\",\"https://www.youtube.com/watch?v=a2ugsaV2DL8\",\"https://www.youtube.com/watch?v=uGPkeHrcwvg\",\"https://www.youtube.com/watch?v=OJ6dGxGrHCc\"]', '2026-04-01 02:00:10.951', '2025-08-05 22:20:29.823', 1026, NULL, 1, 1983, 'Nossa história começa em 1983, na cidade de Balneário Camboriú (SC), com a Arcangel, uma fábrica de cera depilatória nascida do sonho de Dona Glaci Van Straten de mudar a experiência de depilação, considerada por ela, naquela época, um verdadeiro sofrimento. Tínhamos um produto tão bom (cera morna) e fazíamos isso com tanto amor, que mudamos esse paradigma da depilação, antes percebida como um momento “doloroso”, para ser considerada uma experiência de bem-estar, conforto e autoestima. A partir disso, em 1996, começa a trajetória da rede Depyl Action Franchising, no segmento de saúde, beleza e bem-estar.  Hoje, após mais de 25 anos de caminhada, comemoramos o reconhecimento público de seguir atuando no mercado como a Mais Completa Franquia de Depilação do Brasil. Oferecemos 3 segmentos de serviços: clássicos, artísticos e tecnológicos, que englobam e 11 especialidades focadas em atender demandas de cuidados com o pelo e a pele de mulheres e homens, da adolescência à melhor idade, de maneira única, diversa e plural. Somos uma empresa pioneira, mas que não para de evoluir. Inovamos no relacionamento com franqueados, oferecendo consultoria contínua sobre o negócio, treinamentos para equipes de colaboradores (cursos e atualização), além de oferecer todo o suporte necessário para quem entra para o nosso time. São mais de 3 mil clientes atendidos por dia, em 103 lojas espalhadas pelo Brasil e fora dele (Venezuela), com 77 franqueados apaixonados.    A 115° unidade da Depyl Action abriu suas portas em julho de 2020, no tradicional bairro Jardim Paulista, capital de São Paulo. A franqueada Manuela Penna segue à frente do negócio, ao lado da sócia Jaqueline Paiva, fortalecendo ainda mais a rede no estado, que já conta com outras unidades localizadas em Campinas, Tatuapé, Itaim Bibi, Ribeirão Preto, Araraquara, Santos, São Caetano do Sul, São José dos Campos, São Paulo e Sorocaba).  Saúde, beleza e bem-estar: serviços e produtos em um segmento promissor  A Depyl Action é mais que depilação, oferecemos soluções personalizadas para o cuidado com o pelo e a pele. Além de um atendimento de excelência, focado na experiência do cliente, trabalhamos com um vasto portfólio de serviços clássicos (epilação com cera morna - fórmula exclusiva e pioneira no país, epilação com linha, aparo de pelos e esfoliação corporal), tecnológicos (laser, luz pulsada, clareamento e rejuvenescimento) e artísticos (embelezamento  das sobrancelhas, embelezamento dos cílios e coloração dos pelos). Os serviços são realizados em cabines exclusivas e climatizadas, com toda a segurança, discrição, assepsia e higiene necessárias para que as pessoas tenham a chance de conhecer o que é bem-estar de verdade!  Excelência em Franchising São 21 prêmios da ABF, colecionados com muito orgulho desde o ano de 2004. Em 2015, também recebemos um reconhecimento muito importante: 10 anos consecutivos com o Selo de Excelência em Franchising, uma verdadeira honra, resultado de um trabalho realizado com muito empenho e transparência.  Onde estamos? Estamos em 24 estados brasileiros e no Distrito Federal.  Nossa sede fica em Belo Horizonte (Minas Gerais): Rua Sergipe, 1430, 17º andar. Telefone: (31) 3222-7701', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/11507ecd-6929-48a5-a10c-86898f97b358.jpg', 90, NULL, NULL, '2026-03-09 19:58:24.431', 'https://franquias.portaldofranchising.com.br/franquia-depyl-action-beleza/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/66a6b106-6055-4583-9fa3-f0535988d8a5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/fb33641a-d022-4a08-8478-25bad2e99972.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/730255bf-82bf-4d1a-9779-bc3d1cc9e146.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8f5dde22-75aa-49ce-9cc1-77f0c44afc7b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d22cb373-c538-4a81-a31c-876d1620dc3c.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '380000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
