INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza782m00rneh0soufaaekw', 'AUXILIADORA PREDIAL', 'auxiliadora-predial', NULL, 'Casa e Construção', 'Serviços e Imobiliárias', 'Franquia de imobiliária', 2007, 2008, NULL, '2026-04-01 02:00:11.011', '2025-08-05 22:20:29.854', 1032, NULL, 1, 1931, 'A Auxiliadora Predial agregou seus mais de 80 anos de experiência no mercado imobiliário ao modelo de negócio de sucesso nos EUA e Europa e com grande potencial de crescimento no Brasil. \nModelo estruturado na Lei de Franquias Brasileiras, em que o franqueado recebe todo o know-how e suporte necessários para a operação e gestão do seu próprio negócio especializado no serviço de intermediação de compra e venda de imóveis. \n                                    \nO sistema de franquias da Auxiliadora Predial, em que as agências operam dentro de um mesmo conceito, possibilita que todas as lojas possuam uma carteira de imóveis interligada, gerando maiores possibilidades de negócios. \nO franqueado inicia o negócio com todo o suporte e experiência que só uma rede de 80 anos de mercado pode oferecer.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/174fcbcc-7e19-4e75-9eea-53090119ce35.png', 84, NULL, NULL, '2026-03-09 20:07:34.817', 'https://franquias.portaldofranchising.com.br/franquia-auxiliadora-predial-imobiliarias/', NULL, NULL, '[]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '130000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza782r00roeh0s76imcyos', 'JUST GO FIT', 'just-go-fit', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Franquia home based onde franqueador ensina o franqueado a importar da China, viabiliza o operacional logístico de separação dos pedidos e oferece mentoria de como vender nos principais MarketPlaces.', 2024, 2025, NULL, '2026-04-01 02:00:11.020', '2025-08-05 22:20:29.860', 1033, NULL, 1, 2024, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/aebb6c23-7449-4f06-bb31-ad77f8af788b.png', 15, NULL, NULL, '2026-03-09 20:08:10.134', 'https://franquias.portaldofranchising.com.br/franquia-just-go-fit/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza782x00rpeh0sci3uichc', 'RED BALLOON', 'red-balloon', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escola Bilíngue para crianças de 2 a 5 anos e escola de inglês para criança de 3 a 17 anos', 1999, 2000, NULL, '2026-04-01 02:00:11.029', '2025-08-05 22:20:29.865', 1034, NULL, 1, 1969, 'A Red Balloon oferece no mesmo espaço físico, dois modelos de negócio distintos e complementares: o curso livre de inglês e a escola bilingue Escola Bilíngue (turno): A Bilingual School é destinada ao ensino infantil para crianças de 2 a 5 anos e oferece currículo bilingue de verdade com 50% em inglês e 50% em português. Aliada a metodologia que consolidou a Red Balloon como referência no ensino de inglês para este público, a escola infantil bilíngue permite imersão ainda maior no idioma e passa a ser a primeira escola do país a utilizar o currículo internacional de Oxford. English Program (contraturno): O English Program da Red Balloon corresponde a modalidade de curso livre, mas é muito mais do que um curso tradicional. Isso porque, além de utilizar uma metodologia lúdica única. O English Program permite mais flexibilidade as famílias com cargas horarias que vão de 3 até 20 horas semanais, elas podem escolher a opção que mais se enquadra nas suas necessidades. Números que provam que nosso modelo de negócio: NPS das famílias de +80, há mais de 6 anos seguidos LTV (life time value) de 5,5 anos, muito superior a outros cursos de inglês Taxa de retenção de 85%, sendo taxa de retenção similar a escola regular + de 90% de aprovação nos exames de Cambridge, maior que a média nacional de aprovação. Lucro líquido em torno dos 35% do faturamento Modelo de negócio estável, seguro e duradouro', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cdbcd669-dfe6-431b-a438-29b623c50a2c.jpg', 73, NULL, NULL, '2026-03-09 20:08:33.434', 'https://franquias.portaldofranchising.com.br/franquia-red-balloon-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '700000.01', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783300rqeh0sqsig0617', 'SANTA LOLLA', 'santa-lolla', NULL, 'Moda', 'CALÇADOS', 'Calçados e Acessórios Femininos', 2004, 2007, '[\"https://www.youtube.com/watch?v=KcOiPgfvOdM\"]', '2026-04-01 02:00:11.039', '2025-08-05 22:20:29.872', 1035, NULL, 1, 2002, 'Sócios da Franquia Santa Lolla, os irmãos Rubens, Vanessa e Fábio Martinez começaram a trilhar sua trajetória no varejo na década de 90, quando abriram sua primeira loja multimarcas de sapatos, motivados pelo interesse comum pelo universo dos calçados. A vontade de criar suas próprias coleções, impulsionou o surgimento da marca Santa Lolla, em 2002. Dois anos depois, após com ainda mais know how, inauguraram a primeira franquia Santa Lolla. Crescendo de forma sustentável com 140 lojas até agosto desse ano, e uma expansão programada de mais 15 lojas para 2017. Com 15 anos no mercado, a Santa Lolla firmou-se como uma das principais referências de moda no Brasil, antecipando e criando tendências com um time afiado que cria cinco coleções por ano, cerca de sete mil novos itens que abastecem constantemente as lojas, para atender o público cada vez mais informado e ávido por novidades. A empresa nasceu e segue com a missão de aliar conforto e moda para uma mulher sexy, segura, independente e poderosa. Marketing e Visual Merchandising A Santa Lolla conta com uma equipe especializada na criação e desenvolvimento das estratégias de comunicação e marketing para a marca. • Marketing forte e inovador • Plano de comunicação nacional e multicanal • Suporte ao franqueado para ações personalizadas • Materiais de apoio para franqueados e equipe • Visual Merchandising com vitrines especiais • Visual Merchandising com exposição de produto dinâmico Seja um franqueado: (11) 3046-3301 | franquia@santalolla.com.br', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7afe0225-a249-4375-a583-0b0dda0e92c2.jpg', 315, NULL, NULL, '2026-01-20 11:44:20.000', 'https://franquias.portaldofranchising.com.br/franquia-santa-lolla-moda/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e9590611-f90c-46d2-8d61-c5a1d7730cc8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c541fd7f-8c62-42de-b25a-8a4574b4d849.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2a1ae876-4d03-4614-a3ff-aaee6cbf15e4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2b0628e0-62a9-4573-9563-1ce2a3a48116.jpg\"]', 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '540000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783900rreh0sbpejyvvf', 'SPA EXPRESS', 'spa-express', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Estéticos e Bem-Estar', 'Microfranquia modelo homeoffice que presta serviços de estética e bem-estar em domicílio.', 2014, 2019, '[\"https://www.youtube.com/watch?v=Ap0rB7FCV2k\",\"https://www.youtube.com/watch?v=vE1K4geRrt8\"]', '2026-04-01 02:00:11.049', '2025-08-05 22:20:29.877', 1036, NULL, 1, 2011, 'Desde 2011 atuando no mercado de João Pessoa - PB, o SPA Express nasceu com o propósito de levar bem-estar aos seus clientes.  Numa sala de consultório médico, a ideia surgiu enquanto Luciana esperava sua hora de atendimento. Ela pensou em como seria interessante ter ali mesmo um serviço de manicure express. \nE, logo, a ideia saiu do papel! Firmando parcerias com clínicas médicas, os serviços de manicure chegaram nestes centros para otimizar o tempo das mulheres. A inovação do serviço alinhada ao bom atendimento resultou no reconhecimento e sucesso da marca SPA Express e, logo, a empresa estendeu os serviços para o atendimento domiciliar. Assim, o SPA Express passou a levar não só os serviços de manicure como também procedimentos estéticos corporais, faciais, serviços exclusivos de Dia de Noiva, SPA Day, entre outros, para a casa/hotel/trabalho dos clientes. Com o passar do tempo, os tratamentos estéticos corporais e faciais assumiram uma fatia majoritária no faturamento do negócio e o foco do SPA Express acompanhou esta tendência. Hoje em dia, a Franquia se especializou neste segmento específico e eliminou o atendimento de manicure do seu mix de serviços. Em razão de toda a experiência acumulada nos serviços prestados em domicílio durante esse tempo e objetivando a expansão da sua marca, em 2014 o SPA Express aderiu ao Sistema de Franchising e já conta com mais de 44 franquias espalhadas pelo Brasil oferecendo uma proposta home office inovadora com pequeno investimento inicial e baixo custo fixo mensal. Hoje somos a MAIOR franquia de SPA em domicílio do Brasil! \nVem fazer parte dessa história de sucesso que ainda está só começando!', NULL, 'PARAÍBA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d9f8aa45-1c74-45c4-bcab-2b3ceeee0386.jpg', 20, NULL, NULL, '2026-03-09 20:09:34.805', 'https://franquias.portaldofranchising.com.br/franquia-spa-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '29640', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783f00rseh0saim4s773', 'VIDA CARD', 'vida-card', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'CARTÃO DE SAÚDE ASSOCIADO A CLÍNICA MÉDICA E ODONTOLÓGICA', 2019, 2021, '[\"https://www.youtube.com/watch?v=lnuyU1mGZuM\",\"https://www.youtube.com/watch?v=7pRIgAGEFhQ\"]', '2026-04-01 02:00:11.061', '2025-08-05 22:20:29.883', 1037, NULL, 1, 2008, 'OLÁ INVESTIDOR(A)! \nSEJA MUITO BEM VINDO AO SEU NOVO NEGÓCIO, O VIDA CARD! \nA REDE DE FRANQUIAS DA ÁREA DA SAÚDE QUE MAIS CRESCE NO BRASIL. \nSurgia há mais de 11 anos o embrião do negócio que se tornaria o Vida Card. \nUm grupo de religiosos, unidos a profissionais de saúde e membros da comunidade, iniciaram um pequeno projeto social oferecendo as pessoas serviços de saúde com preços acessíveis. \nO marco inicial ocorreu com um grupo de médicos e uma máquina de ultrassom, oferecendo atendimento à população de baixa renda. Logo o projeto foi ganhando proporção, unindo cada vez mais profissionais de saúde e clientes.  \nEm outubro de 2015, com uma estrutura física que já não comportava o seu tamanho, o projeto ganhou uma casa nova, um Centro de Saúde de 700 m², com uma estrutura moderna e equipada para melhor atender a população.  \nA reestruturação do pequeno projeto social o qual era conhecido inicialmente, foi coordenado pelos sócios fundadores da franqueadora Vida Card, Anna Kuerten, Eduardo Saibt, Luciano de Medeiros e Luiz Felipe Durand. \nNeste processo, o projeto não só ganhou uma nova estrutura física, como também uma gestão profissional e o seu nome: Vida Card. \nApós dois anos de validação do novo formato de negócio na unidade Vida Card de Santa Maria/RS, nasceu a Franqueadora Vida Card, com a sua primeira unidade franqueada na cidade de Alegrete/RS, que no mês de junho/22 completou 3 anos de atividades atingindo o número expressivo de associados.  \nNestes três anos são 30 unidades Vida Card em funcionamento no Rio Grande do Sul, Santa Catarina, Paraná, com mais 22 unidades em implantação. \nJunte-se a nós e venha fazer parte desta história de sucesso e crescimento.  - Estrutura\nCom unidades que podem variar entre 120m² a 400m², com destaque para área comercial e o centro de saúde totalmente padronizadas, a rede busca proporcionar um atendimento de excelência em todas as suas Unidades. \nA equipe de implantação da franqueadora acompanha o novo franqueado em todos as etapas de construção da sua unidade, desde o seu projeto de arquitetura, elaboração de estratégias operacionais e comerciais até o evento de inauguração.  \nDepois o suporte da Franqueadora Vida Card continua com a consultoria de gestão, time de marketing, comercial e rede de atendimento.  - Tecnologia\nO franqueado faz a gestão da sua Unidade através de um software de gestão integral (comercial, financeiro e Centro de saúde), que também disponibiliza um acompanhamento da performance da unidade através de um painel de indicadores.\n  - Serviços \nOs Clientes das franquias Vida Card encontram todas as especialidades em um só lugar, uma ampla rede interna e externa contendo diversas especialidades médicas, odontológicas e de serviços, além de encontrar saúde de qualidade por um preço acessível, usufruem de uma estrutura moderna e muito bem equipada para recebe-los, com centro de Saúde próprio, agilidade no agendamento de consultas e exames, e valores de planos assistenciais familiares que cabem no bolso.  Conheça a franquia VIDA CARD e seja Franqueado de um Negócio Sólido, Rentável e Recorrente!', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c9f0aab1-5563-4363-980a-beba3d7eddbc.jpg', 33, NULL, NULL, '2026-03-09 20:10:47.662', 'https://franquias.portaldofranchising.com.br/franquia-vida-card/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783k00rteh0su5a586v3', 'SUCO BAGAÇO', 'suco-bagaco', NULL, 'Alimentação', 'Bares e Restaurantes', 'Sucos e lanches', 2006, 2012, NULL, '2026-04-01 02:00:11.071', '2025-08-05 22:20:29.889', 1038, NULL, 1, 2000, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b066d370-6a92-48db-8217-98feb98195d2.svg', 77, NULL, NULL, '2026-03-09 20:12:37.461', 'https://franquias.portaldofranchising.com.br/franquia-suco-bagaco-bebidas-e-salgados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, NULL, '185000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783p00rueh0sppsszuu5', 'L\'OCCITANE', 'l-occitane', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Perfumaria e Cosméticos com alma francesa e coração brasileiro, marca celebra as diversas belezas do Brasil em todos os seus produtos.', 1976, 2022, '[\"https://www.youtube.com/watch?v=RlwemzLwY9w\"]', '2026-04-01 02:00:11.084', '2025-08-05 22:20:29.894', 1039, NULL, 1, 1976, 'L\'Occitane au Brésil: a França na essência, Brasil por natureza. A história do Grupo L’Occitane teve início em 1967 com a criação da L’Occitane en Provence, fundada por Olivier Baussen. A marca se expandiu por meio da produção de sabonetes em barra e cremes corporais, tudo inspirado na natureza, segredo de todos os nossos produtos. Há mais de 40 anos vivemos este sonho, compartilhado com o mundo todo. O Grupo atualmente é composto por oito marcas. Além da L’Occitane en Provence, a outra única marca fundada pelo grupo foi a L’Occitane au Brésil. A L’Occitane au Brésil, com alma francesa e coração brasileiro, celebra as diversas belezas do Brasil em todos os seus produtos. A marca nasceu em 2013 com o propósito de celebrar as diversas belezas do Brasil por meio de uma perspectiva única: o olhar do francês com o sorriso do olhar brasileiro, enaltecendo a alegria, tradições, cores, ingredientes, cheiros, texturas e pessoas que fazem do Brasil uma nação querida em todos os cantos do mundo – uma celebração do Brasil aos olhos da França. Com valores de autenticidade, sensorialidade e respeito, a marca conta com comunidades produtoras parceiras espalhadas ao redor do país em cadeias sustentáveis, trazendo ingredientes de origem nacional para todos os mais de 200 produtos do portfólio, e artistas que celebram a franco-brasilidade com ilustrações exclusivas.  Nossos compromissos é surpreender os nossos clientes com uma experiência autêntica, levar alegria & diversão e envolver os clientes com nossas texturas, sensorialidade e histórias verdadeiras UM NOME FORTE A L\'Occitane au Brésil tem um nome altamente reconhecível para clientes brasileiros e estrangeiros, aliada à herança do Grupo L\'OCCITANE UM GRUPO CONDUZIDO PELO CRESCIMENTO O Grupo L\'OCCITANE teve um crescimento de 15% no Brasil em seu último ano fiscal (2021), reforçando a influência de suas marcas entre os clientes brasileiros. Filosofia de Negócio Parceria; Transparência; Comunicação frequente e permanente; Comprometimento com o negócio Suporte da Franqueadora Oferecemos suporte contínuo ao franqueado, auxiliando em diferentes etapas do processo: Pré Inauguração Direito de uso da marca e adesão ao sistema de franquias; Todo know-how; Assessoria e apoio na escolha do ponto; Projeto arquitetônico; Treinamento inicial do franqueado e da primeira equipe; Manual de operação e gestão da loja; Apoio na montagem e inauguração da loja. Pós Inauguração Acompanhamento e suporte operacional por meio de consultoria de campo; Treinamento de reciclagem e para lançamento de novos produtos; Portal de pedidos  Portal do franqueado  SAF (sistema de atendimento ao franqueado) Convenção de franqueados;', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d3be271d-aa9a-42d3-b8f4-88ea530bedda.jpg', 291, NULL, NULL, '2026-03-09 20:12:59.315', 'https://franquias.portaldofranchising.com.br/franquia-loccitane/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783w00rveh0sszmw973e', 'DENTAL ARTE', 'dental-arte', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Clínicas Odontológicas', 2016, 2015, '[\"https://www.youtube.com/watch?v=UlOwG5kOP6U\"]', '2026-04-01 02:00:11.096', '2025-08-05 22:20:29.900', 1040, NULL, 1, 2002, 'A Dental Arte é uma das marcas de clínicas odontológicas mais conhecidas do Rio Grande do Sul. A rede nasceu em Alvorada, no ano de 2002, com o propósito de tornar acessível a todos uma odontologia de excelente qualidade, com atendimento acolhedor e humanizado. O trabalho árduo e dedicado das Dras. Alessandra Batista e Adriane Afonso logo gerou reconhecimento e o “jeito Dental Arte de atender” conquistou a região metropolitana de Porto Alegre. Em menos de dois anos, a marca cresceu e chegou ao centro histórico da capital com a já consagrada unidade da Andradas. Nos anos seguintes foram abertas mais duas clínicas próprias, em Cachoeirinha e Novo Hamburgo. Após 13 anos de muito sucesso e reconhecimento no coração dos gaúchos, as diretoras da Rede perceberam que estava no momento de compartilhar seu know-how e expertise no segmento odontológico. As primeiras franquias foram vendidas muito rapidamente para dentistas que já atendiam na Dental Arte e constataram o potencial da marca e sua credibilidade por um serviço odontológico de qualidade e referência. Em 8 anos como rede de franquias odontológicas, a Dental Arte obteve um crescimento acentuado em número de clínicas abertas, inclusive mantendo constância de crescimento durante a pandemia da Covid-19. Com 21 anos de mercado e mais de 2 milhões de sorrisos transformados, a Rede Dental Arte conta com mais de 40 unidades espalhadas em 4 estados brasileiros, sendo eles: Rio Grande do Sul, Santa Catarina, Bahia e São Paulo.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/59592536-5564-4779-b1db-34e8f8390360.jpg', 36, NULL, NULL, '2026-03-09 20:14:41.618', 'https://franquias.portaldofranchising.com.br/franquia-dental-arte-odontologia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza784200rweh0sedp2k67k', 'MAIS FINISHINGS', 'mais-finishings', NULL, 'Casa e Construção', 'Construção e Reforma', 'Mais de 20 anos como referência em revestimentos, louças e metais de alto padrão. Curadoria exclusiva de produtos nacionais e internacionais. Pioneiros em grandes formatos e atendimento diferenciado.', 2024, 2024, '[\"https://www.youtube.com/watch?v=PQPXSla8uAs\"]', '2026-04-01 02:00:11.112', '2025-08-05 22:20:29.906', 1041, NULL, 1, 2003, 'Mais Finishings – há 21 anos transformando revestimentos em arte para o lar Na Mais Finishings cada detalhe é uma fonte de inspiração para transformar projetos em verdadeiras obras de arte. Fundada em 2003 pelo casal Sandra e Nelson Feuer, hoje a empresa já se consolidou como referência nacional no setor de revestimentos, louças e metais de alto padrão criando um conceito de atendimento voltado para a experiência do cliente. \"Acreditamos que cada projeto é uma oportunidade única de expressar o estilo e a personalidade de nossos clientes. Nosso objetivo é oferecer não apenas produtos, mas experiências personalizadas que resultem na satisfação de cada pessoa que levou a Mais Finishings para sua casa\", completa Sandra Feuer. A Mais Finishings nasceu com o propósito de inovar, integrar e oferecer  mais em acabamentos como parte essencial de cada projeto. A marca se dedica a oferecer soluções completas e personalizadas, e um de seus principais diferenciais é o atendimento especializado em suas lojas. Nossos showroons são projetados para simular espaços residenciais inteiramente funcionais. A equipe de consultores está sempre atenta às tendências de mercado, proporcionando uma consultoria individualizada que garante que cada projeto respeite o estilo e as necessidades de cada cliente, sem falar em oferecer as melhores soluções para cada ambiente. Com o objetivo de expandir sua atuação e levar seu conceito e produtos para mais regiões do Brasil, a Mais Finishings anuncia a abertura de seu modelo de franquias. A iniciativa busca empreendedores que compartilhem seus valores e estejam comprometidos em oferecer excelência no atendimento e produtos de alto padrão, além de proporcionar acesso a uma curadoria criteriosa de produtos. Além disso, a Mais Finishings disponibiliza serviços exclusivos, incluindo simulações em 3D, cortes personalizados e assentamento especializado. Sua curadoria abrange revestimentos, louças e metais das principais capitais do design mundial, reforçando seu compromisso com a inovação e qualidade. Atualmente, a Mais Finishings opera quatro lojas em São Paulo e uma no Rio de Janeiro, consolidando-se como uma referência no setor de revestimentos no Brasil.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d70e50bf-22fb-4d4b-b8ab-66c6b51c821e.svg', NULL, NULL, NULL, '2026-03-09 20:15:46.265', 'https://franquias.portaldofranchising.com.br/franquia-mais-finishings-casa-e-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '560000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza784700rxeh0s9ttksail', 'UNHAS CARIOCAS', 'unhas-cariocas', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Franquia de esmalteria que contempla em seu catálogo: tratamento das unhas com técnica exclusiva, depilação com cera única e serviços de estética corporal, além de ter linha de produtos exclusiva.', 2017, 2019, '[\"https://www.youtube.com/watch?v=CexP5eEb-cA\"]', '2026-04-01 02:00:11.125', '2025-08-05 22:20:29.912', 1042, NULL, 1, 2017, 'A Unhas Cariocas é a rede de franquia de esmalterias que se tornou referência no mercado de beleza no Brasil, expandindo com MAIS DE 80 UNIDADES, entre 2017, quando inaugurada, e 2022. Através dos métodos únicos e exclusivos de nossos serviços, como a cutilagem através do Emoliente e da Cureta, que não agride a pele durante a remoção da cutícula, nossa linha de produtos exclusivos, além da nossa depilação 80% menos dor, atendemos mais de 30 MIL CLIENTES, faturamos MAIS DE 12 MILHÕES DE REAIS e inauguramos 21 NOVAS UNIDADES apenas em 2022. Disponível atualmente em 30+ cidades e 10+ estados pelo Brasil, a Unhas Cariocas carrega a missão de levar ainda mais autoestima para a mulher, através de seus valores: agilidade, biossegurança e claro, qualidade. Visando assim, tornar-se a maior e melhor empresa de cuidado e tratamento das unhas e serviço estéticos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2ad563c7-84f8-4569-8ffe-7a229c2c1c1b.jpg', 89, NULL, NULL, '2026-03-09 20:17:04.113', 'https://franquias.portaldofranchising.com.br/franquia-unhas-cariocas/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '155000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza784d00ryeh0s1pi0yqn4', 'LAVE & PEGUE LAVANDERIA', 'lave-pegue-lavanderia', NULL, 'Limpeza e Conservação', 'LAVANDERIAS', 'A 1° Lavanderia express automatizada com serviço de atendimento, unindo praticidade, tecnologia e cuidado humano no dia a dia dos clientes.', 2022, 2022, NULL, '2026-04-01 02:00:11.139', '2025-08-05 22:20:29.917', 1043, NULL, 1, 2020, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/59c5e319-96df-4898-b2b5-c68d95cb5f0a.jpg', 190, NULL, NULL, '2025-11-11 16:58:11.000', 'https://franquias.portaldofranchising.com.br/franquia-lave-pegue-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '138000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza784i00rzeh0sv1ip1cru', 'AÇAÍ FRUIT SHOW', 'acai-fruit-show', NULL, 'Alimentação', 'Docerias, Padarias e Cafés', 'Rede de franquias especializada em açaí, com produção própria, suporte completo ao franqueado e modelo de operação padronizado, lucrativo e fácil de replicar.', 2024, 2025, NULL, '2026-04-01 02:00:11.150', '2025-08-05 22:20:29.922', 1044, NULL, 1, 2016, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/afef473f-a87b-445a-afd2-3aa95f7cdd64.png', 27, NULL, NULL, '2026-03-09 20:18:11.830', 'https://franquias.portaldofranchising.com.br/franquia-acai-fruit-show/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '270000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza784n00s0eh0sel81b9cu', 'AFFEROLAB', 'afferolab', NULL, 'Educação', 'Treinamento Profissional e Capacitação', 'Somos a Franquia Oficial Afferolab, consultoria de aprendizagem voltada ao desenvolvimento de lideranças, times e estratégias de upskill. Oferecemos soluções com metodologia própria e de alto impacto.', 2025, 2025, NULL, '2026-04-01 02:00:11.161', '2025-08-05 22:20:29.927', 1045, NULL, 1, 1992, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e0a0de3c-ae5e-40b5-99f8-2a65c8b8e210.png', 2, NULL, NULL, '2026-03-09 20:18:31.420', 'https://franquias.portaldofranchising.com.br/franquia-afferolab/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '70000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza784s00s1eh0s1skycsta', 'DIVINA TERRA', 'divina-terra', NULL, 'Alimentação', 'Mercados e Distribuição', 'LOJAS DE PRODUTOS NATURAIS E SUPLEMENTAÇÃO', 2017, 2019, '[\"https://www.youtube.com/watch?v=QuHtHrey3sQ\",\"https://www.youtube.com/watch?v=U1Z92D4IJ10\",\"https://www.youtube.com/watch?v=y8xk8w4jFFY\",\"https://www.youtube.com/watch?v=cEwZ7higMt4\"]', '2026-04-01 02:00:11.172', '2025-08-05 22:20:29.932', 1046, NULL, 1, 2011, 'A Divina Terra nasceu para promover saúde e bem-estar, com produtos naturais e um modelo de franquia acessível e sustentável. O mercado de saudabilidade cresce a cada ano, e a Divina Terra se destaca com produtos de qualidade, foco na vida saudável e inovações no mercado saudável. Mix variado, suporte completo ao franqueado e foco em sustentabilidade.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e868ac77-7447-4e2e-9a05-a4140a3c08ce.png', 79, NULL, NULL, '2026-03-09 20:18:53.758', 'https://franquias.portaldofranchising.com.br/franquia-divina-terra/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza784x00s2eh0s2pi48yyf', 'ARABI\'S ESFIHARIA', 'arabi-s-esfiharia', NULL, 'Alimentação', 'Bares e Restaurantes', 'Rede de fast-food, especializada em comida árabe.', 2012, 2015, NULL, '2026-04-01 02:00:11.182', '2025-08-05 22:20:29.937', 1047, NULL, 1, 2009, 'Nascemos em Nova Esperança/PR e nossa empresa começou bem pequena como a maioria dos negócios no Brasil. Percebemos que tínhamos um excelente produto em mãos, buscamos consultoria para expansão e a recomendação foi o sistema de franquias. Possuímos lojas em 7 estados brasileiros (PR, SC, MS, MT, GO, RS e SP), estamos crescendo, lançando novos produtos e inovando para atender cada vez melhor os nossos franqueados e consumidores.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/21172e16-c40f-4885-bdd3-704b625d8af9.png', 50, NULL, NULL, '2026-03-09 20:19:21.810', 'https://franquias.portaldofranchising.com.br/franquia-arabis-esfiharia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza785200s3eh0sd4yvcnk5', 'CLÍNICA DA CIDADE', 'clinica-da-cidade', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Centro médico com padrão de atendimento particular, oferece consultas e exames a preços acessíveis, tudo em um único lugar. Perfeita para quem não tem plano de saúde. Isso é Medicina Acessível.', 2017, 2018, '[\"https://www.youtube.com/watch?v=nUtuR1-MJVQ\"]', '2026-04-01 02:00:11.194', '2025-08-05 22:20:29.943', 1048, NULL, 1, 2003, 'A Clínica da Cidade foi fundada em 2003, na cidade de Campinas, e já está presente em 10 estados, sendo 7 operações próprias e 45 franquias, com modelo de expansão implementado a partir de 2018. \nAtualmente a rede conta com mais de 500 colaboradores e 2.000 médicos parceiros prestadores de serviço. Trouxemos um conceito disruptivo antevendo uma tendência de comportamento, que é o modelo de pagamento por serviço prestado. \nNós enxergamos, há mais de 20 anos, que o futuro da prestação de serviço na saúde é on demand. Por isso, somos a única rede de clínicas especializada nesse formato e atuamos como a 4ª via do setor de saúde, oferecendo uma solução que vai além da saúde pública, planos de saúde e cartões de desconto. Entendemos que a realidade do orçamento familiar brasileiro mudou muito com a pandemia, inflação e a diminuição do poder aquisitivo, e encaixar as mensalidades de planos de saúde já não é uma realidade. \nNosso modelo de negócio garante uma rentabilização saudável para nossos franqueados e um atendimento humanizado e de qualidade para os nossos pacientes em um setor não afetado por tendências macroeconômicas. Com o envelhecimento populacional cada vez maior e um número crescente de brasileiros sem acesso à saúde, a Clínica da Cidade oferece a solução, com o propósito de democratizar o acesso a saúde no Brasil e impactar positivamente milhões de pessoas, com atendimento médico de excelência, clínicas com design acolhedor e equipamentos de última geração, sempre com rapidez e preço justo. De fato, somos a transformação que a saúde precisa! Fazemos parte de um ecossistema de saúde que oferece solução para a necessidade das pessoas. Somos a transformação que nosso sistema de saúde precisa! Conheça a Clínica da Cidade!   Porque adquirir uma franquia Clínica da Cidade? - Rede de clínicas All In One, com todos os tipos de tratamentos, são mais de 20 especialidades, laboratórios e exames de imagem.\n  Com isso você atende os mais diferentes públicos de forma acessível. - Poderosos instrumentos de marketing à disposição do franqueado para atrair clientes e manter sua clínica sempre cheia. - Suporte de toda montagem do negócio, fornecedores homologados, transferência de know-how, software de gestão de processos, equipe para orientação técnica e visitas de consultor.  O investimento certo para a rentabilidade que você procura!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/254f35e5-78b6-49ad-9876-d4e8a1e6199a.jpg', 45, NULL, NULL, '2026-03-09 20:19:51.213', 'https://franquias.portaldofranchising.com.br/franquia-clinica-da-cidade/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '770000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza785800s4eh0so21dskmq', 'Brazil Health', 'brazil-health', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Franquia de Corretora de seguros e consultoria', 2025, 2025, '[\"https://www.youtube.com/watch?v=VNTBcLg9AJA\",\"https://www.youtube.com/watch?v=HsmAcWOCL9I\",\"https://www.youtube.com/watch?v=jSRosqdNodY\",\"https://www.youtube.com/watch?v=2BDKkwXcIGE\"]', '2026-04-01 02:00:11.205', '2025-08-05 22:20:29.948', 1049, NULL, 1, 2025, '', NULL, NULL, 1, NULL, 59, NULL, NULL, '2026-03-09 20:21:17.779', 'https://franquias.portaldofranchising.com.br/franquia-brazil-health/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza785d00s5eh0s707w4n77', 'YES! COSMETICS', 'yes-cosmetics', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Cosméticos e perfumaria.', 2015, 2016, '[\"https://www.youtube.com/watch?v=tF2dBIKhWKA\",\"https://www.youtube.com/watch?v=cagc8onT_GQ\",\"https://www.youtube.com/watch?v=fIRvrEKxh4s\"]', '2026-04-01 02:00:11.216', '2025-08-05 22:20:29.953', 1050, NULL, 1, 2000, 'Da maquiagem ao skincare, da perfumaria ao autocuidado. Somos uma marca brasileira, de cosméticos 100% veganos e cruelty-free, que leva beleza e bem-estar de um jeito acessível e democrático a todas as regiões do Brasil. Somos uma rede de franquias que acredita no poder da diversidade e no empreendedorismo que prospera. Nossa história começou em 2000, na Venda Direta. Em pouco tempo, investimos em operações próprias e, em 2016, após um período de aprendizado e amadurecimento, demos um passo decisivo rumo ao franchising. Com mais de 20 anos de trajetória no cenário nacional, seguimos conquistando novos públicos com produtos de qualidade, o melhor custo-benefício, e um modelo de negócio rentável, estruturado e sustentável. Com dois formatos de investimento, quiosque e loja, aqui você encontra oportunidades a partir de R$109 mil para empreender em um dos mercados que mais crescem no mundo!  Nosso modelo de franquia foi pensado para oferecer segurança e suporte a quem deseja ingressar no setor de Higiene Pessoal, Perfumaria e Cosméticos (HPPC): um segmento em constante crescimento, que se mantém aquecido o ano todo, com produtos não perecíveis e que fazem parte do dia a dia de todo mundo. Ao lado da Yes! Cosmetics você ainda garante outras vantagens!   Junto com você em cada etapa Nossa equipe acompanha cada fase do seu negócio, desde a implantação até o dia a dia da operação. Nos primeiros meses, você conta com o Suporte Berçário e, depois, seguimos com consultoria de campo regional, consultoria de estoque e abastecimento, agência interna de marketing, além de um software dedicado à gestão de materiais de divulgação, que traz mais agilidade e autonomia a cada franqueado.   Treinamento e Capacitação Oferecemos uma trilha de aprendizado que começa já nas primeiras reuniões até a imersão no Treinamento para Novos Franqueados (TFY). Acesso a manuais e materiais de apoio, lives estratégicas, orientação sobre produtos, técnicas de venda e gestão operacional, além da plataforma exclusiva Yes! Academy, para capacitar você e sua equipe ao longo de toda a jornada.   Nosso jeito de empreender Buscamos empreendedores que digam sim ao propósito da marca e percebam na Yes! Cosmetics uma oportunidade real de crescimento. Entre os principais atributos que valorizamos estão: Mentalidade empreendedora e de parceria Disponibilidade e energia pra fazer acontecer Respeito, disciplina e senso de responsabilidade Habilidade em se relacionar e liderar equipes Engajamento e foco na gestão do negócio Organização e capacidade de adaptação Diga sim a novas possibilidades com a Yes! Cosmetics Confira a seguir as etapas do nosso processo de seleção:', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/52eeee2a-6187-4d9a-877c-48b6acc25888.png', 1, NULL, NULL, '2026-03-09 20:28:18.676', 'https://franquias.portaldofranchising.com.br/franquia-yes-cosmetics-cosmeticos-e-perfumaria/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/18ca34e2-d11a-4e03-b2a6-d212a64b97a9.jpeg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/bb5a8d63-f93e-40a0-88db-ea0a3c85a822.jpeg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '155000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza785i00s6eh0sgiv9rpi4', 'MASTERPIECE', 'masterpiece', NULL, 'Alimentação', 'BARES', 'Rede de bares artesanais sustentáveis, com foco em chope premium, experiência de marca e operação padronizada, seguindo o modelo da Cervejaria Masterpiece.', 2025, 2025, NULL, '2026-04-01 02:00:11.226', '2025-08-05 22:20:29.958', 1051, NULL, 1, 1998, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ef0ab327-1f6d-4340-99d8-32b9ee700977.png', NULL, NULL, NULL, '2025-08-22 17:50:03.000', 'https://franquias.portaldofranchising.com.br/franquia-masterpiece-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza785n00s7eh0stjry92w7', 'KFC', 'kfc', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'O KFC é uma rede de restaurantes norte-americana, famosa pela Receita Secreta do delicioso frango do Coronel Sanders – grande sucesso feito à base de 11 ingredientes secretos.', 1952, 2021, NULL, '2026-04-01 02:00:11.236', '2025-08-05 22:20:29.963', 1052, NULL, 1, 1952, 'Ninguém sabe o segredo do nosso frango. Mas você pode participar da receita deste sucesso. A Franquia KFC é ideal para quem quer investir no mercado de fast-food ao lado de um dos maiores players do mercado mundial: A receita original ultrapassa 75 anos de tradição. Está em 3º lugar no ranking dos restaurantes mais valiosos do mundo. Já são 192 lojas no Brasil. Faz parte da IMC (International Meal Company), empresa de capital aberto, detentora também das marcas Pizza Hut, Frango Assado, Viena, entre outras.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3e81d9c6-ef22-4717-8e29-3d74ce905ac5.jpg', 197, NULL, NULL, '2025-09-03 12:06:42.000', 'https://franquias.portaldofranchising.com.br/franquia-kfc/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza785s00s8eh0svhwt1iy0', 'CENTER PANOS', 'center-panos', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Supermercado do Artesanato - Oferecendo mix de produtos para criação de peças de todas as técnicas artesanais, além de cursos para capacitação e arte terapia. Além de artigos de decoração.', 2012, 2014, '[\"https://www.youtube.com/watch?v=J0b-V6qhylE\"]', '2026-04-01 02:00:11.247', '2025-08-05 22:20:29.969', 1053, NULL, 1, 2005, 'Fundada em 2003 pelo empresário Ronaldo Aparecido Cordão, a Center Panos nasceu alinhada à sustentabilidade tendo por objetivo a inserção econômica, social e a terapia ocupacional por meio da comercialização de seus produtos, se tornando em curto prazo a franquia pioneira em distribuição de produtos para artesanato no Brasil. Após estudos, análises e pesquisas de mercado, a Center Panos criou um sistema que apresenta soluções para o desenvolvimento de artesanato e decoração baseados nas mais recentes tendências mundiais voltadas ao segmento de artesanato, contando com uma gama aproximadamente de 15.000 itens, divididos em: a) Tecidos e armarinho;\nb) Cama, mesa e banho;\nc) Pintura e apliques;\nd) MDF;\ne) Produtos para decoração em geral. Em 2013, com a união do empresário fundador Ronaldo Aparecido Cordão e uma indústria têxtil, a Center Panos iniciou sua expansão via franchising, contabilizando, atualmente, 22 unidades em funcionamento no Brasil.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1a9ce1a5-2210-4fb0-842d-036da6cfb34a.jpg', 50, NULL, NULL, '2026-03-09 20:30:09.349', 'https://franquias.portaldofranchising.com.br/franquia-center-panos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
