INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza786800sbeh0spdiui82m', 'PET ANJO', 'pet-anjo', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'A Pet Anjo tem como objeto o franqueamento de unidades estabelecidas em pontos estratégicos adjacentes ou dentro das lojas Cobasi para prestação de serviços veterinários ou banho e tosa.', 2022, 2025, NULL, '2026-04-01 02:00:11.279', '2025-08-05 22:20:29.984', 1056, NULL, 1, 2022, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a269c28f-7775-4ce8-bb54-8ca1c22d2e39.png', 275, NULL, NULL, '2025-08-01 10:25:45.000', 'https://franquias.portaldofranchising.com.br/franquia-pet-anjo/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza786c00sceh0sr9sg0649', 'PIRADINHOS', 'piradinhos', NULL, 'Moda', 'VESTUÁRIO', 'A franquia Piradinhos foi desenvolvida para pessoas de todo o Brasil que se identificam com o propósito da marca a investir em um negócio de baixo custo, excelente retorno e operação simples.', 2025, 2025, NULL, '2026-04-01 02:00:11.289', '2025-08-05 22:20:29.989', 1057, NULL, 1, 2025, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3b9da921-7783-47e7-afe2-a6d5a1b4fd87.png', 5, NULL, NULL, '2025-11-10 14:27:31.000', 'https://franquias.portaldofranchising.com.br/franquia-piradinhos-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '70000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza786h00sdeh0scph20ixt', 'RAHRA SEMIJOIAS', 'rahra-semijoias', NULL, 'Moda', 'ACESSÓRIOS PESSOAIS', 'Comércio de Semijoias com qualidade e garantia em todas as peças de até 10 anos. Uma marca que enaltece a força e a beleza das mulheres, elevando autoestima e individualidade de cada uma.', 2018, 2023, '[\"https://www.youtube.com/watch?v=uGJ72COmh6g\",\"https://www.youtube.com/watch?v=WIpeD22SRoE\",\"https://www.youtube.com/watch?v=Jrn8K3IF8qo\",\"https://www.youtube.com/watch?v=yMnORiI0lUs\"]', '2026-04-01 02:00:11.301', '2025-08-05 22:20:29.994', 1058, NULL, 1, 1988, 'Fundada há 35 anos por Solange Coelho, a RAHRA Semijoias nasceu com uma missão clara: inspirar mulheres a se expressarem plenamente, despertando sua autenticidade e confiança interior. Unimos moda, beleza, arte e lifestyle em peças exclusivas, projetadas para realçar e acompanhar cada momento especial na vida de nossas clientes. Com o passar dos anos, a RAHRA consolidou-se como uma das principais referências em semijoias no Brasil, ganhando a confiança e o carinho de suas clientes e revendedoras autônomas. Contamos com mais de 55 franquias em todo o país e um modelo de loja inovador, que se destaca pela arquitetura única no segmento. Nossas coleções são desenvolvidas com base em pesquisas globais de moda, adaptadas ao DNA da marca e às necessidades da nossa comunidade de clientes. Na RAHRA, ultrapassamos limites para alcançar nossos objetivos. Movidos pela paixão, continuamos a crescer e inovar, investindo em tecnologia para personalizar a experiência, cuidando do desenvolvimento de produtos únicos e oferecendo um modelo de negócios inteligente e saudável, com suporte integral aos nossos franqueados. RAZÕES PARA SER UM FRANQUEADO RAHRA - Royalties Free: Não cobramos royalties sobre faturamento da unidade. Uma oportunidade incrível para crescer e prosperar sem se preocupar com taxas extras. - Estoque inicial consignado: Rahra disponibiliza 100% do estoque inicial com carência de 12 meses. Ao final desse período você pode devolver tudo o que não vender. - Garantia e Qualidade: Oferecemos até 10 anos de garantia e realizamos atualizações constantes no processo produtivo, evoluindo diariamente a qualidade de nossos produtos. - Tratamento Especial: Nossas peças são livres de níquel e possuem 3 camadas de ouro com verniz protetor. Utilizamos uma tecnologia exclusiva de tratamento antialérgico, com 99% de aprovação. - Sempre na Moda: Realizamos lançamentos de novas coleções todos os meses e apresentamos novos modelos a cada 15 dias, garantindo que você esteja sempre na moda. RAHRA é mais do que uma marca de semijoias; é um movimento que celebra a individualidade e a diversidade feminina. Junte-se a nós nessa jornada.', NULL, 'MINAS GERAIS', 1, NULL, 64, NULL, NULL, '2025-09-18 10:14:27.000', 'https://franquias.portaldofranchising.com.br/franquia-rahra-semijoias-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '143490', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza786o00seeh0sx6mbogtb', 'MAMMA MIA EXPRESS', 'mamma-mia-express', NULL, 'Alimentação', 'Bares e Restaurantes', 'Operação Fast Food de Galeto e Massas típicas do sul do Brasil', 2012, 2013, NULL, '2026-04-01 02:00:11.310', '2025-08-05 22:20:30.001', 1059, NULL, 1, 1985, 'Sabor, o segredo do Mamma Mia No Galeto Mamma Mia, todos acreditam que as fartas refeições em família, com a culinária típica dos imigrantes italianos, podem e devem ser desfrutadas por todos. E que suas receitas tradicionais são a melhor razão para alegres encontros, brindes e sorrisos de satisfação.   O clima de suas casas é sempre acolhedor e conquista as pessoas que apreciam o comer e viver bem. O segredo desde o início está no sabor e no atendimento. Servir o cliente o mais rapidamente possível para que ele tenha tempo para degustar o sabor único dos pratos do Mamma Mia.\n  O sonho de um menino, o começo  Mamma Mia! Esta expressão italiana que demonstra admiração e encantamento trouxe nome e inspiração para o sonho de um menino que aos 11 anos já queria tocar seu próprio negócio. Julinho Cavichioni primeiro cuidou de uma lanchonete. Aos 16 anos foi emancipado pelos pais, para realizar o sonho de abrir o restaurante Mamma Mia. Com o grande movimento do restaurante, quis conhecer de onde vinham seus clientes. Para isto, o jovem corria até o estacionamento e olhava os carros. As placas de Porto Alegre indicavam que a expansão de seu restaurante deveria começar por lá. Assim, em 1986, abriu mais um Mamma Mia, desta vez na capital gaúcha. O sonho continua O espírito empreendedor segue no DNA do Mamma Mia que está prestes a abrir a sua sexta operação.   Uma marca altamente conhecida no sul do Brasil, que transpõe barreiras e acessibiliza o verdadeiro sabor da culinária dos imigrantes italianos presentes na serra gaúcha. Franquias do Galeto Mamma Mia: uma história de 39 anos que está só começando.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/39142e16-264f-43df-9a00-886b3c15fd73.jpg', 29, NULL, NULL, '2026-03-09 20:31:32.969', 'https://franquias.portaldofranchising.com.br/franquia-mamma-mia-express-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza786u00sfeh0s9fkv3fom', 'Chilli Beans', 'chilli-beans', NULL, 'Moda', 'Vestuários', 'Comercio varejista', 2001, 2009, '[\"https://www.youtube.com/watch?v=PP6juABGC9s\"]', '2026-04-01 02:00:11.320', '2025-08-05 22:20:30.007', 1060, NULL, 1, 1996, 'A Chilli Beans nasceu nos anos 90, quando Caito Maia teve a ideia de vender óculos trazidos de Venice no porta-malas do seu carro e passou a participar de feiras alternativas como o Mercado Mundo Mix. \nEm 2000 foi inaugurado o primeiro quiosque e, em 2002, a primeira loja. Desde então, a marca cresceu de forma impressionante, conquistando mais de 1.200 pontos de venda em 22 países e se tornando a maior marca de óculos da América Latina. \nHoje, a Chilli Beans é reconhecida não apenas pelo seu tamanho, mas também pela inovação constante: lança 10 novos modelos de óculos todas as semanas, possui colab’s exclusivas e se destaca como referência em moda, música, arte e lifestyle.  \nSer um franqueado Chilli Beans significa fazer parte de uma marca consolidada, que oferece formatos variados de franquia, adaptados a diferentes perfis de investidores. É a oportunidade de empreender com o suporte de uma rede forte e preparada, que já provou seu sucesso no varejo. \nEscolher a Chilli Beans como franquia é investir em um negócio próspero, com uma marca amada pelo público, que une atitude, inovação e resultados.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e660af9b-b523-4331-bb87-239729b14fdc.png', 1253, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/527775e8-b0ed-484b-8cf7-51d6c9c7746d.jpg', '2026-03-09 20:32:29.329', 'https://franquias.portaldofranchising.com.br/franquia-chilli-beans-acessorios-pessoais/', 'Vendas', 'Compras', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3f8b8f7b-0f4c-44fb-9d3b-7c5e79e128ee.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/67191ad9-754c-4a2a-be43-9899c7dd7289.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1151cd59-91ec-490b-833f-cd347aba0441.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2bf87f85-d66f-4371-b115-6fbeadea9739.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6fa1d5e8-64a9-417c-9f1c-921022fc8416.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7c1e0bb0-d794-4a02-b115-6b4b7e0e20d6.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/fcd62c07-05da-4ac6-aeff-c0cccb06b813.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d14b4c06-27a9-4041-9bb0-5721fe6c6818.jpg\"]', 1, 5, 5, 1, NULL, 0, 0, NULL, '180000', NULL, NULL, NULL, '15000', '95000', '15', '3', '135000', '30000', 18);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza787100sgeh0sagwg59we', 'Di Blasi Pizzas Artesanais', 'di-blasi-pizzas-artesanais', NULL, 'Alimentação', 'Bares e Restaurantes', 'Comercio varejista', 2021, 2026, '[\"https://www.youtube.com/watch?v=mOT7Ck9w-UY\",\"https://www.youtube.com/watch?v=nK74S8PP1so\",\"https://www.youtube.com/watch?v=j25xWvMbeYk\",\"https://www.youtube.com/watch?v=Ge-mgQpyXsw\"]', '2026-04-01 02:00:11.329', '2025-08-05 22:20:30.013', 1061, NULL, 1, 2025, 'As franquias Di Blasi oferecem uma maneira fácil para alcançar um rendimento sólido.', NULL, 'Rio de Janeiro', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f9a7fed0-9660-4ff1-b18c-c240609a9517.png', 42, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/71410fea-e4e9-4684-b097-64d4b03cdac9.jpg', '2026-03-09 20:37:39.689', 'https://franquias.portaldofranchising.com.br/franquia-di-blasi-pizzas-artesanais/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d607dc6a-543c-4f1e-9cb4-b27f8d8ce0d0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ea3cee0d-9278-40ea-bbc8-2d06ff7c3f25.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/daa72ea6-2ccf-4ade-8a63-1c1cc1e49b11.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ce8565a5-812f-44e7-9036-436f8d20bcd0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/68acc97f-9c97-4353-b572-babf7d639c78.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/620ebb39-b914-426b-af17-5f329780db62.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a9f5ba98-2233-4347-b03e-a1331809806f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d5bec6c3-0376-4c51-9328-82ee3ba78670.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5ff57da8-29ab-47de-9f1b-19bd91eff552.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '350000', NULL, NULL, NULL, '65000', '160000', '4', '2', '250000', '35000', 55);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza787600sheh0sfyvyra8o', 'THE KIDS CLUB - INGLÊS SÓ P/ CRIANÇAS', 'the-kids-club-ingles-so-p-criancas', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'INGLÊS PARA CRIANÇAS DE 18 MESES A 12 ANOS', 1990, 1995, '[\"https://www.youtube.com/watch?v=B7wW3uEn_po\",\"https://www.youtube.com/watch?v=7vQruW9Wg5U\",\"https://www.youtube.com/watch?v=7HuOodis12c\",\"https://www.youtube.com/watch?v=MATV9J2dN7Y\"]', '2026-04-01 02:00:11.338', '2025-08-05 22:20:30.019', 1062, NULL, 1, 1987, 'SOBRE A FRANQUIA THE KIDS CLUB Investimento inicial acessível Microfranquia em formato home-based Cursos anuais com RECEITA MENSAL RECORRENTE Metodologia internacional exclusiva No Brasil desde 1994, o THE KIDS CLUB é uma rede de franquias de origem inglesa, especializada no ensino de inglês para crianças de 18 meses a 12 anos de idade, e pioneira no Brasil no formato microfranquia home-based, com atuação sem ponto comercial e em parceria com Escolas Regulares. Oferecemos dois formatos de atuação, e o franqueado pode optar por um, ou pelos dois: - FORMATO HOME-BASED – sem necessidade de ponto comercial, podendo o franqueado administrar o negócio de casa. As aulas acontecem dentro de escolas de Educação Infantil e Ensino Fundamental I, através de parcerias. - FORMATO SEDE PRÓPRIA – modelo tradicional de escola de idiomas em um ponto comercial. Com uma proposta única e um modelo de negócio inovador, a franquia THE KIDS CLUB forma empreendedores, donos dos seus próprios negócios, com treinamentos, orientações, e sem muita burocracia.   INVESTIMENTO INICIAL Taxa de Franquia: R$ 12.500,00 Investimento Inicial total (incluindo a Taxa de Franquia e capital de giro): R$ 23.500,00, no formato home-based. Retorno do Investimento: 18 a 24 meses.   Estimativa de faturamento mensal: R$ 12.500,00 (considerando 50 alunos e uma mensalidade de R$ 250,00/aluno) Estimativa de lucratividade: 25% - 30% Possiblidade de receita recorrente – cursos anuais   VALORES DO SISTEMA Taxa de Royalties: 9% sobre mensalidades Fundo de Marca: R$ 200,00/mês Sistema de Gestão: R$ 200,00/mês   NOSSA METODOLOGIA Aulas para crianças de 18 meses a 12 anos de idade Aulas 100% em inglês, desde o primeiro dia Manuais do Professor exclusivos, com todas as aulas já preparadas Material didático de última geração, com uso de aplicativo e recursos tecnológicos Grade completa de cursos, com 11 níveis anuais Cursos curriculares, extracurriculares, e nosso exclusivo PROGRAMA BILÍNGUE, com aulas todos os dias, escolhidos de acordo com a necessidade de cada cliente Certificação Internacional para crianças Nossa metodologia prioriza a comunicação em inglês desde a primeira aula. Através de jogos, músicas e muita brincadeira, interagimos com o universo infantil, contextualizando o novo idioma, e criando uma aula divertida onde os alunos aprendem sem perceber. Com aulas 100% em inglês, nossos professores fluentes e treinados estimulam a participação dos alunos, criando um ambiente acolhedor, onde o uso do novo idioma se torna fácil e prazeroso. Nosso Material Didático foi desenvolvido em parceria com as melhores editoras internacionais, e é atualizado anualmente. Todos os professores e alunos têm acesso a plataformas digitais para realizarem atividades online. E somos hoje um Centro Autorizado para aplicação das Certificações Internacionais especializadas em crianças: PEIC YL – Pearson English International Certificate for Young Learners TOEFL Primary TOEFL Junior   EXCELÊNCIA EM FRANCHISING Em 2024, a rede THE KIDS CLUB completou 30 anos no Brasil, e foi chancelada com o 20º SELO DE EXCELÊNCIA EM FRANCHISING DA ABF, que atesta a satisfação dos franqueados com a marca e com a franqueadora.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/82dec213-3c24-4493-b760-990a5892652d.svg', 39, NULL, NULL, '2026-03-09 20:41:30.004', 'https://franquias.portaldofranchising.com.br/franquia-the-kids-club-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '13500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza787d00sieh0s5tgq9obp', 'CRESCI E PERDI', 'cresci-e-perdi', NULL, 'Moda', 'VESTUÁRIO', 'O modelo de negócio aposta em um consumo de moda infantil mais consciente e sustentável. Amplicando cada vez mais a moda circular, a rede agora é a líder no segmento.', 2017, 2023, NULL, '2026-04-01 02:00:11.347', '2025-08-05 22:20:30.025', 1063, NULL, 1, 2014, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3a4f148c-14d2-46b6-a012-f381bdb6725f.png', 674, NULL, NULL, '2026-02-02 15:16:53.000', 'https://franquias.portaldofranchising.com.br/franquia-cresci-e-perdi/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '275000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza787m00sjeh0sz8yqb1sc', 'STONE', 'stone', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'FRANQUIA DE PROSPECÇÃO DE VENDAS, PÓS VENDA E ENTREGA LOGÍSTICA DE SERVIÇOS DE ADQUIRÊNCIA.', 2018, 2019, '[\"https://www.youtube.com/watch?v=oq8h5VUnwzU\",\"https://www.youtube.com/watch?v=q34I3dvUo_M\"]', '2026-04-01 02:00:11.357', '2025-08-05 22:20:30.034', 1064, NULL, 1, 2012, 'A história da Stone começa antes mesmo do nascimento da empresa, há 19 anos, com o encontro dos dois sócios fundadores.  Com a abertura do mercado, eles viram a oportunidade de realizar o sonho de entrar no mercado de pagamentos com uma empresa brasileira, independente de bancos com abordagem inovadora e total foco nos empreendedores que movimentam a economia do país. As operações locais da Stone em todos os estados do país são fundamentais pra que a empresa seja classificada com o melhor atendimento do mercado.  A Stone busca empreendedores que estejam dispostos a levar a maneira mais justa e transparente de fazer negócio a ainda mais cidades. A ideia é que as franquias estimulem comércios e desenvolvimento locais, levando um serviço de excelência e o suporte real aos lojistas de todo o país.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a9e5f606-ef60-4aab-8502-7239b09d7e35.png', 313, NULL, NULL, '2026-03-09 20:43:36.249', 'https://franquias.portaldofranchising.com.br/franquia-stone/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '35000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza787v00skeh0sy3m48imt', 'CAFÉ DO PONTO', 'cafe-do-ponto', NULL, 'Alimentação', 'Bares e Restaurantes', 'Coffee Shops. Rede de cafeterias de cafés espressos especiais oferecendo excelência em seus produtos e serviços em um ambiente aconchegante, com opções de drinks quentes e gelados, salgados e doces', 1992, 1996, '[\"https://www.youtube.com/watch?v=Q7CK9h2ml6g\"]', '2026-04-01 02:00:11.366', '2025-08-05 22:20:30.043', 1065, NULL, 1, 1950, 'Prêmio 5 Estrelas entre as Melhores Franquias do Brasil pela PEGN A franquia Café do Ponto tem cotação 5 Estrelas no Prêmio As Melhores Franquias do Brasil, promovido pela Revista PEGN - Pequenas Empresas, Grandes Negócios, e conduzida pela Serasa Experian. \nNos últimos 5 anos, o Café do Ponto recebeu a cotação 5 Estrelas três vezes: 2018, 2020 e 2023. \nEsta Pesquisa/Prêmio da PEGN reflete a opinião dos nossos franqueados sobre a nossa marca em três quesitos principais:  - Qualidade da rede\n- Desempenho da rede\n- Satisfação do franqueado No mercado desde 1954, o Café do Ponto entende que tomar um bom café é um momento especial e, por isso, seleciona os melhores grãos e coloca todo o talento e especialidade, desde a colheita até chegar ao consumidor final. \nCom uma expansão gigantesca consistente desde seu ingresso no franchising em 1992, a marca possui mais de 40 unidades  em todas as regiões do Brasil. \nNo cardápio, um mix de produtos premium variados, com foco no café, frappés, doces e salgados. A franquia de cafeteria do Café do Ponto faz parte da JDE - Jacobs Douwe Egberts, uma das maiores empresas de cafés e chás do mundo. \nUm em cada três franqueados da rede possui mais de 15 anos de operação, o que faz dele um negócio próspero e rentável.  A franquia Café do Ponto é uma marca amada pelas pessoas que apreciam um café de qualidade.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ebedc3d5-39db-4074-9c86-4d3512e66f60.png', 41, NULL, NULL, '2026-03-09 20:44:14.722', 'https://franquias.portaldofranchising.com.br/franquia-cafe-do-ponto-bebidas-cafe-doces-e-salgados/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '260000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza788200sleh0s9afazzrz', 'QUIERO CAFÉ', 'quiero-cafe', NULL, 'Alimentação', 'Bares e Restaurantes', 'Um modelo que une café, restaurante e bar, com um ambiente aconchegante e acolhedor, com atendimento próximo e humano, senvindo a qualquer hora do dia, mais de 400 opções em seu cardápio.', 2016, 2019, '[\"https://www.youtube.com/watch?v=a6nTHbnjKSw\"]', '2026-04-01 02:00:11.378', '2025-08-05 22:20:30.051', 1066, NULL, 1, 2015, 'O Quiero Café surgiu em uma cidade pequena, no interior do Rio Grande do Sul, em Teutônia, a partir de uma ideia de dois jovens que procuravam trazer para a sua cidade um local que pudessem proporcionar um ambiente acolhedor, com produtos de qualidade, com atendimento próximo e verdadeiro, em que as pessoas pudessem trabalhar, fazer uma reunião, frequentar no seu cotidiano ou passar seus momentos especiais. \nA veia empreendedora, a experiência por ser da cidade e um pouco de receio se \"somente\" uma cafeteria daria certo, os fizeram desenvolver um cardápio com opções que começavam desde o café da manhã, passavam pelo almoço, café da tarde, happy hour, até chegar no jantar, algo que ao longo do tempo tornou-se uma identidade da marca, oferecendo aos clientes todas as opções do cardápio a qualquer hora do dia. Após 3 meses de planejamento, a primeira unidade inaugurou no dia 18 de setembro de 2015, desde o início conquistou muitos admiradores e clientes fiéis a marca. \nO desejo por proporcionar a melhor experiência, assumir as falhas do dia a dia, evoluir constantemente e sempre manter os pés no chão com muita humildade em cada novo passo dado, fortaleceram esta marca ao longo do tempo. Já no ano de 2016, nascia a ideia de expandir através do modelo de Franquias, para poder replicar a mesma experiência de Teutônia para outras cidades. \nCom o objetivo de consolidar o modelo e criar uma unidade conceito da marca, foi inaugurada em março de 2017 a segunda loja própria em Lajeado/RS, reforçando que a combinação de um ambiente acolhedor, com produtos de qualidade e um atendimento próximo e verdadeiro teriam seu espaço em qualquer lugar na rotina das pessoas. Ainda em 2017, em setembro foi inaugurada a primeira unidade franqueada na cidade de Santa Cruz do Sul/RS, sendo o passo inicial para a expansão da marca. \nDe 2018 a 2021 foram inauguradas 26 novas unidades, incluindo a primeira unidade no estado de SP, finalizando o ano de 2021 com 29 unidades em operação. Com a pandemia o processo de expansão das franquias desacelerou, mas apesar de todos os desafios deste período, todas as nossas unidades seguem abertas e em operação. \nA força e o engajamento de todos os franqueados e o relacionamento ainda mais próximo que a Franqueadora teve neste período foi determinante para juntos enfrentarem todas as dificuldades. \nA marca se orgulha de não ter nenhuma unidade encerrada desde a sua fundação em 2015, mesmo com cenário de pandemia presente na história.  Em 2022 e 2023 retornamos a um novo ritmo de crescimento, inaugurando 17 unidades em 2022 e 14 em 2023, alcançando a marca de 60 unidades operantes. No ano de 2024 chegamos a 65 unidades em operação, já no ano de 2025 inauguramos 13 unidades e finalizamos o ano com 78 unidades em operação, distribuídas em 5 estados: RS, SC, PR, SP e MG. Em 2026 projetamos alcançar 100 unidades operantes até o final do ano, mantendo a solidez dos resultados de toda a rede e com foco no crescimento das unidades já operantes em paralelo com o crescimento da rede.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4e655bdb-f651-4b43-8477-a6bb0a44b0ca.jpg', 81, NULL, NULL, '2026-03-09 20:45:15.309', 'https://franquias.portaldofranchising.com.br/franquia-quiero-cafe/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '750000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza788c00smeh0s2rk27sap', 'MODO CORRE', 'modo-corre', NULL, 'Serviços Automotivos', 'LOCAÇÃO DE VEÍCULOS', 'A Modo Corre é a melhor franquia para quem quer aproveitar o crescimento do delivery. Oferecendo locação de motos com planos flexíveis e tecnologia de ponta para a segurança e retorno do investimento.', 2024, 2024, NULL, '2026-04-01 02:00:11.390', '2025-08-05 22:20:30.061', 1067, NULL, 1, 2023, '', NULL, 'MATO GROSSO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/54e4df4f-a3c4-45b8-b9eb-f323f0f6e5a1.png', 5, NULL, NULL, '2025-09-09 14:24:39.000', 'https://franquias.portaldofranchising.com.br/franquia-modo-corre-servicos-automotivos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
