INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza788w00soeh0snl2hdo33', 'FIADORWEB', 'fiadorweb', NULL, 'Casa e Construção', 'Serviços e Imobiliárias', 'Franquia de Seguros e Garantias voltada para Imobiliárias, Administradoras de Condomínios e Construtoras.', 2018, 2019, NULL, '2026-04-01 02:00:11.410', '2025-08-05 22:20:30.081', 1069, NULL, 1, 2015, '', NULL, 'SÃO PAULO', 1, NULL, 551, NULL, NULL, '2026-03-09 20:46:53.102', 'https://franquias.portaldofranchising.com.br/franquia-fiadorweb/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '1500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789300speh0sdtdctgfy', 'PARK EDUCATION', 'park-education', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Educação', 2000, 2008, '[\"https://www.youtube.com/watch?v=Py3kasswNRU\",\"https://www.youtube.com/watch?v=yi7cJuIHdD4\",\"https://www.youtube.com/watch?v=uCH_gsm4y4c\"]', '2026-04-01 02:00:11.421', '2025-08-05 22:20:30.087', 1070, NULL, 1, 1996, 'Park | Escola do Futuro: Invista em Sucesso e Propósito na Educação A Park Education nasceu da visão inovadora de Eduardo Pacheco, que, ao retornar dos Estados Unidos, identificou a necessidade de transformar o ensino de idiomas no Brasil. Em 1996, ao ministrar aulas de inglês, Pacheco constatou que a abordagem tradicional deixava 95% dos alunos inseguros para se comunicarem, percebendo, assim, uma grande oportunidade de revolucionar o aprendizado. Junto com o experiente executivo Paulo Arruda, fundou e desenvolveu o Método Park – inspirado no processo natural de aquisição da língua materna – que coloca o aluno para falar antes de aprender as regras gramaticais. Com mais de 29 anos de história e uma trajetória marcada por resultados expressivos, a Park Education se consolidou como referência no setor educacional, impactando mais de 100.000 alunos e atingindo índices de aprovação de 98% e uma taxa de retenção de 95%. A partir de 2000, optamos pelo sistema de franquias para acelerar nossa expansão e levar nosso método inovador a diferentes regiões do Brasil. Hoje, a Park Education apresenta a Escola do Futuro – um modelo que une sucesso financeiro e impacto social, oferecendo: Educação Inovadora: Integração de tecnologia, ensino bilíngue, criatividade e habilidades socioemocionais para preparar os alunos para os desafios do mundo real. Impacto Social Positivo: Contribuição direta para a formação de líderes do amanhã, criando uma sociedade mais preparada e igualitária. Sucesso Financeiro: Modelo de negócio sólido, com investimento a partir de R$299K, retorno rápido, suporte operacional completo e estratégias de marketing inovadoras. Mercado em Crescimento: Aproveite a crescente demanda por educação de qualidade adaptada às novas realidades e posicione-se como líder no setor. Ao se tornar um franqueado da Park Education | Escola do Futuro, você investe em um negócio que vai além do lucro, deixando um legado transformador na educação e contribuindo para o desenvolvimento das próximas gerações. Junte-se a nós nessa revolução educacional e comece sua jornada de sucesso com propósito hoje.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9cf8e71e-023d-4016-bf30-a02a7f850b69.png', 47, NULL, NULL, '2026-03-09 20:47:16.664', 'https://franquias.portaldofranchising.com.br/franquia-park-education/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789900sqeh0s2brvq096', 'HELP MULTAS', 'help-multas', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'A Help Multas é uma empresa especialista em garantir o direito de dirigir dos motoristas, elaborando Recursos Administrativos contra multas de trânsito e processos de suspensão e cassação da CNH.', 2018, 2019, '[\"https://www.youtube.com/watch?v=RdGHF504cE8\"]', '2026-04-01 02:00:11.432', '2025-08-05 22:20:30.094', 1071, NULL, 1, 2016, 'Multa impossível de ganhar é aquela que você não recorre. Com esse mantra surgiu a Help Multas em 2016, uma empresa focada em otimizar o processo de realização de recursos de multas de trânsito, garantindo soluções ágeis. A Help Multas é um verdadeiro Oceano Azul no segmento de franquias, e investir nesse mercado irá fazer você ter muito mais sucesso como franqueado.  Com esse mercado atraente e cheio de oportunidades, nossos franqueados têm obtido retorno do investimento em um tempo médio de 06 à 12 meses, o que é fantástico para qualquer ramo de negócio. Com zero estoque, sistema operacional próprio e auxílio no alcance das metas da unidade, nosso modelo de negócio te ajuda a conquistar os resultados que você procura.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/90ce14f0-2f8a-4af5-8d89-e4f46d905aa7.png', 58, NULL, NULL, '2026-03-09 20:48:31.952', 'https://franquias.portaldofranchising.com.br/franquia-help-multas/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0176aa10-0b9f-47c7-8374-baf41f73db8f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1b66ef87-cdc7-4028-9b5b-05ecb5398f3d.png\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/78932273-9ef2-49ec-9064-5a7037f70a4f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cebca15a-edff-464c-8cd9-5f8a02be3745.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b3086349-a85c-4513-bcf6-44ac03bfbe99.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '124900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789g00sreh0s5uniqf9b', 'TOP ENERGY + ENERGIA SOLAR', 'top-energy-energia-solar', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Venda e instalação de equipamentos para geração de energia fotovoltaica, Bess (\"Battery Energy Storage System\" e sistema de irrigação.', 2023, 2024, NULL, '2026-04-01 02:00:11.442', '2025-08-05 22:20:30.100', 1072, NULL, 1, 2020, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9aa48f8c-666b-4ae9-8ae9-59335770dac2.png', 17, NULL, NULL, '2026-02-12 08:59:26.000', 'https://franquias.portaldofranchising.com.br/franquia-top-energy-energia-solar-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '11990', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789m00sseh0scxuv9e62', 'ODONTOCOMPANY', 'odontocompany', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Franquia de Clínica Odontológica', 2008, 2011, '[\"https://www.youtube.com/watch?v=gqA9E_jak6w\"]', '2026-04-01 02:00:11.451', '2025-08-05 22:20:30.106', 1073, NULL, 1, 1990, 'A OdontoCompany é líder absoluta no segmento de franquias odontológicas e uma das marcas mais reconhecidas da franchising brasileira, sendo referência em escala, rentabilidade e suporte ao franqueado. Para conhecer mais sobre o modelo de negócio e as oportunidades de expansão, a franqueadora disponibiliza informações completas em seu site oficial.  Com mais de 35 anos de história, a OdontoCompany nasceu em São José do Rio Preto (SP), idealizada pelo Dr. Paulo Zahr, e evoluiu para um modelo de franchising sólido, validado e altamente escalável, acompanhando a profissionalização e o crescimento do setor no Brasil. Com clínicas em operação em todo o Brasil, a rede conta com unidades estruturadas, profissionais experientes, infraestrutura moderna e alto padrão de biossegurança. O portfólio de serviços é completo e abrange desde a odontologia básica até as soluções estéticas mais avançadas, atendendo diferentes perfis de público com qualidade e padronização. Atualmente, a rede integra o Grupo SMZTO, fundado pelo empresário José Carlos Semenzato, jurado do Shark Tank Brasil e uma das principais referências do franchising nacional. A OdontoCompany também conta com o respaldo do Fundo L Catterton, o maior private equity do mundo focado em negócios de consumo, reforçando a governança, a solidez financeira e a visão de longo prazo da marca. Modelo de negócio e resultados O modelo de negócio da OdontoCompany se reflete diretamente em seus resultados. Atualmente, 60% dos franqueados possuem mais de uma unidade, evidenciando a escalabilidade da operação.  A franqueadora oferece suporte completo ao investidor, desde a implantação da clínica até a gestão diária da unidade, incluindo: Transferência de know-how validado Apoio na escolha do ponto comercial e montagem da unidade Fornecedores homologados Software de gestão e controle de indicadores Consultoria contínua e acompanhamento de performance Método próprio de captação de pacientes, garantindo agenda cheia ao longo do ano Além disso, a OdontoCompany é reconhecida como a rede odontológica que mais investe em mídia nacional, com campanhas institucionais, marketing digital e ações de fortalecimento de marca que impulsionam a geração de demanda para as unidades franqueadas.  Por que investir na franquia OdontoCompany? Marca premiada: eleita uma das Melhores Franquias do Brasil 2025 pela revista PEGN Baixo risco: modelo testado e validado em todos os estados do Brasil Marketing forte e centralizado Negócio escalável, ideal para investidores e profissionais da odontologia Alta rentabilidade, com lucratividade média entre 20% e 25% Retorno estimado em cerca de 18 meses  Como se tornar um franqueado O processo para se tornar franqueado é simples, estruturado e transparente, iniciando com o cadastro para recebimento da apresentação do negócio, seguido por análise de perfil, reunião estratégica, envio da Circular de Oferta de Franquia (COF) e formalização contratual. Para conhecer todos os detalhes sobre o modelo de franquia, formatos disponíveis e próximos passos, acesse o site oficial da OdontoCompany.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1544250b-821e-4cff-8d66-72568b79826b.jpg', 1138, NULL, NULL, '2026-03-09 20:49:34.116', 'https://franquias.portaldofranchising.com.br/franquia-odontocompany-odontologica/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6084daea-663f-4e75-9e6c-8912aefd7a4f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/540f57ae-95a5-4c97-85a6-0c2e83240976.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/bad1fb1a-7ebd-4f51-b077-9142eb10a421.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/10ec31f9-1557-41b0-a165-f49d2d2f4499.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5872c0fd-e4b8-4749-a1a0-ee404d27038b.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '358000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789s00steh0seisaug4c', 'LIEN CORRETORA DE SEGUROS', 'lien-corretora-de-seguros', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Corretores e agentes de seguros de autos, imóveis residenciais e comerciais, vida e planos de previdência complementar e de saúde. Consórcios e Financiamentos.', 2016, 2016, NULL, '2026-04-01 02:00:11.460', '2025-08-05 22:20:30.113', 1074, NULL, 1, 2010, 'Saber que seus bens estão seguros é viver com mais tranquilidade, podendo dedicar seu tempo no que mais importa para você. Pensando nisso a LIEN Corretora de Seguros trabalha oferecendo facilidade e transparência. Uma corretora atual que busca a melhoria contínua em seus processos e serviços. Nosso objetivo é proporcionar segurança e despreocupação, por isso contamos com uma consultoria especializada que visa orientar e apresentar a proposta de seguro mais adequada às suas necessidades, através de uma análise minuciosa para oferecer o melhor custo-benefício com a certeza de uma apólice bem elaborada. Conheça nossos serviços, faça um seguro com a LIEN. Trabalhamos com mais de 30 companhias de seguros, temos conhecimento em vários ramos do seguro, como automóvel, vida, empresas de pequeno, médio e grande risco, transporte nacional, transporte internacional, seguros garantia, seguro de responsabilidade civil entre outros.  Modelos de Franquias: HOME\nNão precisa de estrutura física, taxa fixa de R$150,00 no primeiro ano e R$300,00 nos demais, Na modalidade HOME não haverá exclusividade vinculadas à territorialidade sendo suas unidades ilimitadas. Na modalidade HOME, o Treinamento é destinado a 01 (um) usuário, podendo ser o próprio FRANQUEADO ou a seu colaborador.  STANDARD\nNecessário estrutura física conforme contrato. Cidades acima de 50.000 (cinquenta mil) habitantes poderão receber mais de uma unidade STANDARD, sempre cabendo à FRANQUEADORA, com base na viabilidade da franquia, a decisão de permitir ou não a implantação de outra franquia na mesma cidade. Taxa fixa de R$250,00 no primeiro ano e R$500,00 nos demais. Na modalidade STANDARD, o Treinamento é destinado a 02 (dois) usuários, podendo ser o próprio FRANQUEADO ou a seus colaboradores.  VANTAGENS\n30 seguradoras parceiras e 95 ramos de seguros, certificada ABF, duas modalidades de negócio, recursos que favorecem o retorno consistente e a lucratividade, suporte na cotação de seguros e gestão do negócio.  SUPORTE \nIlimitado, via e-mail, telefone e acesso remoto para ambas as modalidades.  TREINAMENTO Sistema LIEN   5:00 (Cinco horas) Sistema das Seguradoras  10:00 (Dez horas) \nSistema LIEN e sistema das Seguradoras é feito via telefone, e-mail e acesso remoto. Treinamentos sobre seguro são disponibilizados em vídeo das seguradoras e demais treinamentos serão dados pelas seguradoras que serão acordados com a LIEN para um grupo mínimo.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/86a3ec60-ad09-4c77-a375-77f6164104e0.jpg', 33, NULL, NULL, '2026-03-09 20:51:13.581', 'https://franquias.portaldofranchising.com.br/franquia-lien-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789y00sueh0s78197eko', 'LIFEFIT', 'lifefit', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Imersa na modernidade, inovação e focada no bem estar, a Rede Lifefit propõe um conceito diferenciado de academias. Com profissionais especializados, equipamentos e infraestrutura de ponta.', 2018, 2024, NULL, '2026-04-01 02:00:11.470', '2025-08-05 22:20:30.119', 1075, NULL, 1, 2013, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9b9c909d-d77b-4ac4-b666-89a2ff6ed5a9.png', 19, NULL, NULL, '2026-03-09 20:52:38.753', 'https://franquias.portaldofranchising.com.br/franquia-lifefit-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '4500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78a500sveh0s2nk9rt07', 'AGILIZE BRASIL CORRETORA DE SEGUROS', 'agilize-brasil-corretora-de-seguros', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'A Agilize Brasil é uma corretora de seguros multi ramos com +200 produtos, com modelo de franquia enxuto, suporte completo e alta rentabilidade. Ideal para quem busca empreender com segurança.', 2024, 2025, NULL, '2026-04-01 02:00:11.479', '2025-08-05 22:20:30.125', 1076, NULL, 1, 2023, '', NULL, 'SÃO PAULO', 1, NULL, 18, NULL, NULL, '2025-09-03 14:09:37.000', 'https://franquias.portaldofranchising.com.br/franquia-agilize-brasil-corretora-de-seguros-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '18900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ad00sweh0s0k9talgx', 'BOB´S', 'bob-s', NULL, 'Alimentação', 'Bares e Restaurantes', 'COMÉRCIO DE SANDUÍCHES, SORVETES, REFEIÇÕES RÁPIDAS E OUTROS PRODUTOS ASSEMELHADOS', 1984, 1994, '[\"https://www.youtube.com/watch?v=MZuS3oV7JEU\",\"https://www.youtube.com/watch?v=Z0MOD5ekJcc\"]', '2026-04-01 02:00:11.488', '2025-08-05 22:20:30.133', 1077, '43c1fff6-a024-4336-b5af-4cf21bc8c239', 1, 1952, 'Pioneirismo, criatividade e qualidade são as características que marcaram o Bob\'s desde sua fundação, em 1952, no burburinho de Copacabana, Rio de Janeiro. Rapidamente virou mania entre os cariocas com a sua primeira loja na Rua Domingos Ferreira, lançando o hot-dog, o hambúrguer, o milkshake e o sundae. De lá pra cá, O Bob’s só fez crescer, vendendo o que há de mais saboroso em hambúgueres e sundaes, além do inigualável milkshake de ovomaltine. Em 1984, a rede iniciou seu sistema de franquias, com a abertura de duas unidades em Vitória (ES). Atualmente, a rede conta com mais de 1.000 pontos de venda em todas as capitais do Brasil. Esse sucesso não é por acaso. Afinal, as receitas do Bob’s foram desenvolvidas por décadas, procurando atender sempre o paladar dos brasileiros. Por isso, o Bob’s é nacionalmente reconhecido por seus produtos de excelente qualidade e sabor tipicamente brasileiro. O esforço do Bob`s nos últimos anos tem sido premiado, conquistando pelo 13º ano consecutivo o Selo de Qualidade ABF - Associação Brasileira de FRANCHISING. Conquistam o referido Selo as empresas franqueadoras que são aprovadas por seus franqueados nos mais diversos fatores, averiguados por um instituto de pesquisa independente contratado pela ABF. Esta é a maior prova do sucesso da parceria do Bob`s e seus franqueados. A franquia BOB´s tem modelos de negócio que se adaptam ao potencial de consumo de cada região. A estimativa do investimento vai depender da localização do ponto de venda, da área a ser ocupada e do tipo de loja (rua, shopping center, drive thru) sendo o quiosque uma opção disponível apenas para franqueados que já possuem loja em outro formato. O investimento mínimo depende do tamanho e necessidade de cada ponto.', 'Esse é um teste de descrição feito pelo QA', 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d586184d-3656-4ad8-9ae3-f7edcfbfbf17.jpg', 1029, NULL, NULL, '2026-03-09 20:53:27.500', 'https://franquias.portaldofranchising.com.br/franquia-bobs-valor/', NULL, NULL, NULL, 1, 5, 5, 1, NULL, 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78aj00sxeh0sp1mji85w', 'PIZZARIA A ESPERANÇA', 'pizzaria-a-esperanca', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO COMPLETO', 'Pizzaria Tradicional em sistema de salão e de entregas.', 2025, 2025, NULL, '2026-04-01 02:00:11.498', '2025-08-05 22:20:30.139', 1078, NULL, 1, 1957, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5fb50c54-5caa-4fc8-bdce-924f4a5f6748.png', NULL, NULL, NULL, '2025-09-16 10:25:56.000', 'https://franquias.portaldofranchising.com.br/franquia-pizzaria-a-esperanca/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ao00syeh0sqzujhuyg', 'Café Cultura', 'cafe-cultura', NULL, 'Alimentação', 'Bares e Restaurantes', 'Comercio varejista', 2025, 2025, '[\"https://www.youtube.com/watch?v=WaxHrlfr_jo\",\"https://www.youtube.com/watch?v=n9-Q6WOfkcg\",\"https://www.youtube.com/watch?v=C6r2aeAlxn0\",\"https://www.youtube.com/watch?v=C6r2aeAlxn0\"]', '2026-04-01 02:00:11.508', '2025-08-05 22:20:30.144', 1079, NULL, 1, 2004, '', NULL, 'Santa Catarina', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e9039dae-34fa-4474-b740-24e4dcf05c81.svg', 47, NULL, NULL, '2026-03-09 20:54:42.541', 'https://franquias.portaldofranchising.com.br/franquia-cafe-cultura/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f2999b20-b92a-49a1-8203-03bc147d890d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1edaa83a-5a8c-4dde-86f4-66b3c66be35c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/931f68f5-33bd-412b-9ce7-c9a2d7549531.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5ef09165-50d8-4617-9850-18dcdb7bab0d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/90bf8f23-417b-4714-b227-a9ce7d4ab412.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8e9fa991-dcc6-4712-9be9-44f62ae9675c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4374a02b-9bf4-4541-80ab-d5252d3ee7ed.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9ce81c16-0f61-4b50-9b40-8251dd50e694.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cfa4f17b-541a-4872-90c2-a859b5f17404.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '490000', NULL, NULL, NULL, '60000', NULL, '5', '1.5', '400000', '30000', 50);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78at00szeh0sfjtzeyx8', 'JOHNNY ROCKETS', 'johnny-rockets', NULL, 'Alimentação', 'Bares e Restaurantes', 'Rede americana de restaurante casual dining, temático, especializado em Hamburgueres , Sanduiches e Milk Shakes', 1990, 2017, NULL, '2026-04-01 02:00:11.519', '2025-08-05 22:20:30.149', 1080, NULL, 1, 1986, 'Conheça o Johnny Rockets – Uma verdadeira viagem no tempo Fundado em 1986, na vibrante cidade de Los Angeles, Estados Unidos, o Johnny Rockets traz um conceito nostálgico e tradicional dos anos 50. Conhecido por seus pratos icônicos, garçons dançantes e hamburgueres exclusivos, o Johnny Rockets vem  encantando gerações em mais de 20 países, tendo o Brasil como o maior destaque operacional fora dos Estados Unidos. Além de diversas premiações dentro e fora do Brasil, conquistou na década de 90, o prêmio de Melhor Hambúrguer e o Melhor Shake do Mundo eleito por 5 vezes consecutivas. No Brasil, o Johnny Rockets acumula 3 selos de excelência em franchising (2021, 2022 e 2023), concedidos pela ABF - Associação Brasileira de Franchising. Focado no conceito de restaurantes fast-casual, o Johnny Rockets é um lugar para aproveitar com a família e amigos, contando com um cardápio bem variado e adaptado as exigências do paladar brasileiro, carne Angus, músicas tradicionais, ambientes descontraídos e alegres e muito mais. Nossos franqueados amam o Johnny Rockets! Confira depoimentos de quem tem uma franquia Johnny Rockets e venha fazer parte dessa história.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fa71034a-0f87-45cd-a33b-e50472ff87e5.jpg', 36, NULL, NULL, '2026-03-09 21:01:55.481', 'https://franquias.portaldofranchising.com.br/franquia-johnny-rockets/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ay00t0eh0sd7939v9r', 'CUORDICREMA', 'cuordicrema', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'A primeira e a maior rede de Franquias de Gelato italiano do Brasil Os principais valores da marca, são tradição, inovação, gosto e saúde, proporcionando as clientes a melhor experiencia de consumo.', 2015, 2017, NULL, '2026-04-01 02:00:11.530', '2025-08-05 22:20:30.154', 1081, NULL, 1, 2012, 'Conheça a Cuor di Crema – A paixão em forma de gelato A Cuor di Crema nasceu de um sonho empreendedor de um italiano e uma brasileira, que juntos abriram o mercado de gelateria no Brasil, oferecendo todo o conceito tradicional\nitaliano para o clima tropical do Brasil. Investir na Cuor di Crema é acreditar na verdadeira arte de fazer gelato. É oferecer para as pessoas um pedacinho da Itália em cada sabor, com autenticidade, eficiência e qualidade. Um dos diferenciais da Cuor di Crema é a receita exclusiva feita na própria loja entre 5 e 7 minutos. Garantindo o frescor e a consistência que o verdadeiro gelato italiano deve ter. 100% natural Rico em vitaminas Sem adição de gordura, aromatizantes e conservantes Saudável Opções zero açúcar e zero lactose Opção de gelatos para pet. E com um ambiente aconchegante e acolhedor, a Cuor di Crema oferece a verdadeira e autêntica tradição italiana, que vem conquistando e fidelizando clientes desde 2012. Nossos franqueados amam a Cuor di Crema! Confira depoimentos de quem tem uma franquia Cuor di Crema e venha fazer parte dessa história.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b65ac6bb-c394-4e68-939d-5565b722d9d5.jpg', 14, NULL, NULL, '2026-03-09 21:02:50.184', 'https://franquias.portaldofranchising.com.br/franquia-cuordicrema-docerias-e-sorveterias/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78b300t1eh0suj0yqx1n', 'OMO LAVANDERIA', 'omo-lavanderia', NULL, 'Limpeza e Conservação', 'Lavanderia', 'Serviços de Lavanderia e Higienização de Estofados', 2020, 2021, '[\"https://www.youtube.com/watch?v=WlOS6QpxACQ\"]', '2026-04-01 02:00:11.539', '2025-08-05 22:20:30.159', 1082, NULL, 1, 2020, 'OMO Lavanderia é a rede de lavanderias da marca mais amada do Brasil, com mais de 200 lojas espalhadas pelo país. Com dois modelos de negócio — Self-Service e Especializada — atende a diferentes perfis de investidores e consumidores, unindo conveniência, eficiência e cuidado profissional com as roupas. O grande diferencial da franquia está no suporte completo ao franqueado: da implantação ao acompanhamento próximo da operação. Além disso, OMO Lavanderia é a única rede com um selo de programa exclusivo de lavagem, desenvolvido junto aos fabricantes das máquinas e testado com rigor técnico para garantir performance, cuidado e padronização em todas as unidades. Uma franquia sólida, reconhecida e alinhada aos novos hábitos de consumo — ideal para quem busca empreender com confiança e o respaldo de uma marca de renome.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ebe1da18-c437-406b-94f0-210f04404498.jpg', 199, NULL, NULL, '2026-03-09 21:03:34.011', 'https://franquias.portaldofranchising.com.br/franquia-omo-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '160000', NULL, NULL, NULL, '25000', NULL, '5', '2', '115000', '20000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78b800t2eh0skoec5uew', 'F.A COLCHÕES', 'f-a-colchoes', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Loja de colchoes, produtos para o sono e complementos para o quarto', 2024, 2023, '[\"https://www.youtube.com/watch?v=0i9IQ8Gegw4\",\"https://www.youtube.com/watch?v=gq07M3KNNJU\",\"https://www.youtube.com/watch?v=F94KiUAy2xw\"]', '2026-04-01 02:00:11.549', '2025-08-05 22:20:30.165', 1083, NULL, 1, 1964, 'A F.A. Colchões nasceu em 1964 com o propósito de transformar o mercado de colchões, oferecendo qualidade e conforto. Com um parque industrial moderno e mais de 100 lojas, a marca é reconhecida pela inovação e excelência, sendo uma das cinco empresas do setor com o selo Pró-Espuma (INER). Com um modelo de vendas híbrido (loja física e online) e forte suporte logístico, garantimos uma operação ágil e eficiente para nossos franqueados.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/db6b5194-aef5-45c8-9fe8-5d859fe7a21f.png', 2, NULL, NULL, '2026-03-09 21:04:10.473', 'https://franquias.portaldofranchising.com.br/franquia-fa-colchoes/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78be00t3eh0sxi1i4ws6', 'MANA POKE', 'mana-poke', NULL, 'Alimentação', 'Bares e Restaurantes', 'POKE', 2020, 2022, '[\"https://www.youtube.com/watch?v=P6m1g75Mv4k\",\"https://www.youtube.com/watch?v=OIea6rKfs6c\"]', '2026-04-01 02:00:11.559', '2025-08-05 22:20:30.170', 1084, NULL, 1, 2018, 'A rede de franquias Mana Poke, especializada em culinária havaiana completou 4 anos e já é considerada a maior do Brasil. \nApós a primeira unidade em Campinas/SP, os sócios decidiram levar a experiência da culinária havaiana como uma opção saudável para todo território nacional. \nA operação no modelo de fast casual reduz os custos com mão de obra e facilita a operação. \nO ambiente das lojas traz uma atmosfera leve e agradável, lembrando o lifestyle havaiano muito presente na marca e contribuindo com o engajamento dos clientes, que se tornam “fans” da marca ao se identificar de uma forma real. \nHoje, a rede já se faz presente em praticamente todos os grandes centros do interior de São Paulo, com unidades na capital do estado, Minas Gerais, Rio de Janeiro, Goiás e Paraná. \nA maior parte dos franqueados já possui mais de uma loja. \nA missão da Mana Poke é popularizar o acesso à alimentação saudável, oferecendo preço justo e qualidade aos clientes. \nAlém disso, quer ser referência em poke no Brasil, tendo como valores a experiência do cliente, o trabalho em equipe e a valorização de todos os parceiros. \nO investimento inicial para quem quer se tornar um franqueado da marca é a partir de R$ 390 mil. \nO valor inclui taxa de franquia e capital de giro. \nO retorno do investimento é previsto em até 24 meses com faturamento médio de R$ 150 a R$ 600 mil por mês. \nVenha ser um Franqueado da Rede Mana Poke, uma das maiores tendências gastronômicas no Brasil! \nUma ótima opção para quem quer um investimento seguro com uma empresa séria e que traz bons resultados!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/803bc686-170d-4536-8626-e65fecf90f65.jpg', 69, NULL, NULL, '2026-03-09 21:04:44.742', 'https://franquias.portaldofranchising.com.br/franquia-mana-poke/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '490000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78bk00t4eh0spv3nxr2z', 'GERMAN FINANCIAL', 'german-financial', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Consultoria financeira 360º para pessoas físicas e jurídicas.', 2023, 2023, NULL, '2026-04-01 02:00:11.568', '2025-08-05 22:20:30.176', 1085, NULL, 1, 2023, '', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6d5495fa-335b-4932-ad57-41c9fed0703e.png', 123, NULL, NULL, '2026-03-09 21:05:47.272', 'https://franquias.portaldofranchising.com.br/franquia-german-financial/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78bp00t5eh0s37tou2ow', 'MUNDO ANIMAL LANCHONETE TEMÁTICA', 'mundo-animal-lanchonete-tematica', NULL, 'Alimentação', 'Bares e Restaurantes', 'Lanchonete Temática', 2018, 2020, '[\"https://www.youtube.com/watch?v=ESlaRUgDUP0\",\"https://www.youtube.com/watch?v=WEj3hV7lYX0\",\"https://www.youtube.com/watch?v=HwkFAr6w4i8\",\"https://www.youtube.com/watch?v=1rHbEFQONlM\"]', '2026-04-01 02:00:11.578', '2025-08-05 22:20:30.182', 1086, NULL, 1, 2011, 'Nascemos para proporcionar uma experiência inesquecível e repleta de diversão, em um ambiente temático inspirado na selva! Desde a decoração, feita com móveis desenvolvidos de maneira artesanal, até o cardápio com pratos imensamente deliciosos que levam nomes de animais e são perfeitos para dividir com quem se ama, tudo na Mundo Animal é pensado para que você viva uma verdadeira imersão em um mundo de muitas aventuras, alegrias e sabores.\n \nA primeira unidade da nossa selva foi fundada em junho de 2011 com uma equipe muito modesta e espaço limitado em Capão da Canoa - RS. O rápido sucesso permitiu ampliar a estrutura, conquistar novos parceiros e expandir para diferentes regiões no Brasil. Hoje estamos em 16 estados do Brasil, nos quatro cantos do país. E não vamos parar por aí! Queremos ir além, sempre oferecendo a pessoas de todas as idades a oportunidade de desbravar uma selva de delícias, estimulando, fortalecendo e valorizando vínculos familiares. Afinal, sua família é a nossa família.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8946968b-c83c-4d9d-a45d-d320ddf001be.png', 68, NULL, NULL, '2026-03-09 21:06:09.299', 'https://franquias.portaldofranchising.com.br/franquia-mundo-animal-lanchonete-tematica/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '865000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78bv00t6eh0s75g6yatp', 'PORTOBELLO SHOP', 'portobello-shop', NULL, 'Casa e Construção', 'Construção e Reforma', 'Loja Especializada em Revestimentos Cerâmicos', 1998, 2004, NULL, '2026-04-01 02:00:11.587', '2025-08-05 22:20:30.187', 1087, NULL, 1, 1979, 'Como parte integrante do grupo Portobello S.A., a Portobello Shop S.A., nasceu em 1.998, trazendo para o mercado um novo conceito: além de uma linha exclusiva de produtos de alta qualidade, oferece ao cliente atendimento personalizado e serviços que auxiliam no momento da decisão e facilitam o desenvolvimento da obra. \nA busca por tendências, novidades, revisão de conceito, criação de soluções e design inovadores, resultou a criação da maior e melhor rede de lojas especializadas em revestimentos cerâmicos no Brasil, a Portobello Shop. \nHoje, com mais de 110 lojas instaladas em todo o Brasil, operadas por mais de 60 Franqueados, a Portobello Shop tornou-se um sucesso, com a atuação de suas lojas nos Formatos Compacto, Tradicional e Empório.      \nAs lojas oferecem um pacote de serviços de acordo com as necessidades de cada cliente:  Produtos exclusivos\nA rede possui uma linha de produtos exclusiva e extremamente variada, que através de suas infinitas combinações, possibilita ambientes totalmente personalizados.  Atendimento especializado\nPara auxiliar os clientes na concretização do projeto de seu sonho, as lojas contam com uma Equipe de Arquitetos e Projetistas.  Medição da obra\nVerificação das medidas corretas dos ambientes a serem revestidos, garantindo a precisão na metragem a ser comprada.  Orçamento\nQuantificação exata do revestimento cerâmico a ser utilizado, evitando sobras e transtornos de complementação, traduzindo no conforto do planejamento financeiro da obra.  Acompanhamento\nProfissionais especializados verificam o desenvolvimento da obra no ato da instalação do produto, minimizando os erros de aplicação ou do não cumprimento do projeto especificado. Os clientes recebem o manual técnico Portobello Shop para facilitar o esclarecimento de dúvidas, bem como auxiliar com dicas de manutenção e limpeza.  Assessoria técnica\nTodas as lojas possuem um assistente técnico especializado, que além de tirar dúvidas de como proceder quanto à utilização do produto, é a interface entre o cliente e a Portobello Shop na resolução de eventuais problemas relativos ao produto e seu uso.  Simulação de ambientes por computador - 3D - Promob\nOs projetos de paginação auxiliam na visualização da melhor composição do revestimento cerâmico, maximizando a possibilidade de combinação nos seus vários formatos e peças especiais, aumentando o grau de certeza no momento da escolha do cliente.  Logística de entregas programadas\nAtravés destes serviços, o cliente tem a comodidade de programar a data de chegada do material em sua obra, respeitando o seu melhor momento para este recebimento, minimizando as chances de perda ou quebra da mercadoria.           Histórico \nDesde então a empresa apresentou um crescimento rápido, sólido e planejado, que pode ser observado no quadro cronológico:  1977 – Início da construção da Cerâmica Portobello, no município de Tijucas (SC).  1979 – Início da produção da Cerâmica Portobello. 1980 – Equipe: 250 colaboradores.  1981 – Início das exportações. Abertura da primeira filial em São Paulo.  1982 – Substituição do combustível GLP (Gás Liquefeito de Petróleo) por Gás Pobre, oriundo de carvão vegetal / Instalação do 1º computador – Labo 8032 (64kb de memória) / Fundação da Adec.  1983 – Equipe: 624 colaboradores / A empresa participa da 1ª Feira Internacional, no Panamá. Descoberta de jazidas na região de Dr. Pedrinho, Campo Alegre e São Bento do Sul (SC).  1984 – Lançamento da linha Carga Pesada: intensivo trabalho de marketing / Criação do CCQ – Círculos de Controle de Qualidade.  1987 – Ampliação do parque fabril, aumentando a produção para 1 milhão de m²/mês / Início da parceria com o Senai: cursos de Técnicos Ceramistas e Aprendizagem Industrial Mecânica.  1988 – Equipe ultrapassa mil funcionários / Primeira participação na Feira de Bologna, Itália.  1989 – Criação do Departamento Técnico.  1990 – Criação da Portobello América / Abertura de 12 filiais, no interior de SP, RJ e na região Nordeste.  2011 – Conquistamos pelo sexto ano consecutivo, do Selo de Excelência em Franchising 2011 pela ABF – Associação Brasileira de Franchising, e do Prêmio em 2º lugar – no segmento Casa, Decoração e Presentes, pela Revista PEGN – Pequenas Empresas Grandes Negócios – Editora Globo.  2012 – Selo de Excelência em Franchising – 2012 pela ABF – Associação Brasileira de Franchising. E também, o Prêmio de Melhor Franquia (1º. Lugar) no segmento Casa, Decoração e Presentes, pela Revista PEGN – Pequenas Empresas Grandes Negócios – Editora Globo.  2013 – Selo de Excelência em Franchising – 2013 pela ABF – Associação Brasileira de Franchising.', NULL, 'SANTA CATARINA', 1, NULL, 161, NULL, NULL, '2026-03-09 21:06:56.428', 'https://franquias.portaldofranchising.com.br/franquia-portobello-shop-construcao/', NULL, NULL, '[]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '541000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78c000t7eh0sr0pni9nr', 'PIZZA HUT', 'pizza-hut', NULL, 'Alimentação', 'Bares e Restaurantes', 'Criada em 1958 nos EUA, a Pizza Hut é a maior rede de pizzaria do mundo com presença em 100 países, com mais de 16 mil restaurantes distribuídos pelos cinco continentes.', 1970, 2021, NULL, '2026-04-01 02:00:11.596', '2025-08-05 22:20:30.193', 1088, NULL, 1, 1958, 'A primeira loja foi inaugurada em maio de 1958, por dois irmãos, lá no Kansas. Hoje, a rede é uma ótima oportunidade de negócio, fazendo muito sucesso por aqui: É a 7ª marca mais querida pelos brasileiros.* São mais de 260 lojas distribuídas por todo o país. Faz parte da IMC (International Meal Company), empresa de capital aberto, detentora também das marcas KFC, Frango Assado, Viena, entre outras. E a tendência é que a marca cresça ainda mais: O Brasil é o 4º país que mais consome fast food.** A expectativa é que o Brasil se torne um dos maiores mercados de Pizza Hut. A melhor fatia de um mercado de milhões pode ser sua. Fontes: *Segundo o ranking anual Brand Finance Restaurant/2022. ** EAE Bussiness School.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/40ecb8f4-58ca-4971-b120-b9a0b9e79774.jpg', 269, NULL, NULL, '2026-03-09 21:09:36.865', 'https://franquias.portaldofranchising.com.br/franquia-pizza-hut/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '1185000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78c700t8eh0szheawvbp', 'DF DR. FISCAL', 'df-dr-fiscal', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Franquia de consultoria empresarial com ênfase em soluções tributárias, estabelecida desde 2017 e com mais de 325 unidades espalhadas pelo Brasil, oferecendo serviços únicos e inovadores.', 2017, 2018, '[\"https://www.youtube.com/watch?v=8maKZzrwVJA\"]', '2026-04-01 02:00:11.605', '2025-08-05 22:20:30.199', 1089, NULL, 1, 2017, 'A Dr Fiscal surgiu do GFBR - Grupo Fiscal do Brasil, Conglomerado de empresas com mais de 15 anos de experiência na área fiscal e tributária. Luis Wulff, seu fundador, identificou que dos 4 trilhões de créditos a recuperar, boa parte se encontrava nos microempreendedores e pequenas empresas. A partir desse conceito foi fundada a Dr Fiscal, empresa focada em melhorar a saúde tributária e fiscal de empresas que atuam no regime do Simples Nacional. Nossa estrutura de regras fiscais formatadas em uma modelagem de algoritmo possui hoje 5 milhões de regras fiscais e mais de 32 milhões de produtos, permitindo aos empresários do Simples Nacional a correta emissão das suas NFes e também a acuracidade no pagamento dos tributos, evitando riscos com a fiscalização. Com mais de 7.086.597 de empresas optantes pelo regime, nosso modelo de franquia tem demonstrado exito em todo o mercado brasileiro.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4566fe2e-6d0e-45dc-984c-daff168ae204.jpg', 140, NULL, NULL, '2026-03-09 21:10:18.626', 'https://franquias.portaldofranchising.com.br/franquia-df-dr-fiscal/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '30000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ce00t9eh0s9xnn36ci', 'DNTBRAS', 'dntbras', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'Somos uma das maiores redes de odontologia do páis. Específicos em todos os produtos e serviços odontológicos junto de procedimentos estéticos.', 2022, 2023, '[\"https://www.youtube.com/watch?v=InjGXQZHUJA\"]', '2026-04-01 02:00:11.614', '2025-08-05 22:20:30.206', 1090, NULL, 1, 2007, 'Faça parte de um dos mercados que mais cresce no Brasil, faturando em média R$ 150 mil por mês, com até 30% de lucratividade! Os franqueados além de usufruírem de uma marca consolidada, contam com uma franqueadora muito bem estruturada que fornece todo suporte comercial, técnico e administrativo necessário para o sucesso da sua clínica.', NULL, 'MARANHÃO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9db0ee04-bbb1-4f60-87ff-f87e0907fc53.jpg', 54, NULL, NULL, '2026-03-09 21:11:02.394', 'https://franquias.portaldofranchising.com.br/franquia-dntbras/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
