INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78cy00tceh0ssn8k87r4', 'AÇAÍ SUNSET', 'acai-sunset', NULL, 'Alimentação', 'Bares e Restaurantes', 'Franquia de Fresh Food de Açaí, com operação híbrida (no Copo e Self service), sistema ágil e descomplicado. Nosso propósito é entregar Saúde e Felicidade Dentro e Fora do Copo.', 2021, 2021, NULL, '2026-04-01 02:00:11.642', '2025-08-05 22:20:30.227', 1093, '43c1fff6-a024-4336-b5af-4cf21bc8c239', 1, 2017, '', NULL, 'MARANHÃO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f061b275-9de2-4468-ab7d-a743321e3a06.png', 10, NULL, NULL, '2026-03-09 21:11:59.967', 'https://franquias.portaldofranchising.com.br/franquia-acai-sunset/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
