INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78da00teeh0s9y6gabo9', 'AGAXTUR VIAGENS', 'agaxtur-viagens', NULL, 'Hotelaria e Turismo', 'AGÊNCIAS DE TURISMO', 'Agência de Viagens especialista em Viagens Incríveis independente do destino, tamanho ou da finalidade da Viagem.', 2014, 2016, NULL, '2026-04-01 02:00:11.661', '2025-08-05 22:20:30.238', 1095, NULL, 1, 1953, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b5b4b628-b2ca-4ee9-8acf-c516a8258383.svg', 30, NULL, NULL, '2026-02-05 16:27:32.000', 'https://franquias.portaldofranchising.com.br/franquia-agaxtur/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '135000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78dg00tfeh0sg8mt35nd', 'VEST CASA', 'vest-casa', NULL, 'Casa e Construção', 'Móveis e Decoração', 'A VestCasa é uma loja de varejo especializada no segmento de produtos decorativos para o lar, com artigos de cama, mesa, banho e decoração.', 2009, 2009, NULL, '2026-04-01 02:00:11.671', '2025-08-05 22:20:30.245', 1096, NULL, 1, 2008, 'A VestCasa é uma loja de varejo especializada no segmento de cama, mesa, banho e decoração.          \n  Em 2008, em meio à crise mundial, os irmãos Ahmad e Mohamad Yassin juntamente com o sócio Amado Pineschi buscaram alternativas para se manter competitivos no mercado. \nCom o surgimento da marca VestCasa e agregando valor aos produtos produzidos na fábrica, em pouco tempo caímos no gosto do consumidor. Com 10 lojas próprias abertas em apenas um ano, optamos pelo modelo de franquias para acelerar a expansão da rede.\n  \n  Atualmente, a marca conta com mais de 100 lojas espalhadas por São Paulo, Rio de Janeiro e Minas Gerais. \nOs planos para o futuro são ousados: Serão 400 até 2015 em todo o Brasil. \nO projeto de expansão visa também lojas de bairro e atuação em cidades pequenas. \nA VestCasa veio para substituir lojas pequenas do segmento por lojas organizadas, ou seja, custo benefício para investidores e para consumidores.     \n\t\t\tVÍDEO', NULL, 'SÃO PAULO', 1, NULL, 141, NULL, NULL, '2026-03-09 21:12:42.039', 'https://franquias.portaldofranchising.com.br/franquia-vest-casa-decoracao-e-presentes/', NULL, NULL, '[\"http://www.tribecca.com.br/centraldeservicos/img//%7B712EFDB1-3AA1-488D-A8CF-CFC71C5047B5%7D_vest_casa_01.png\",\"http://www.tribecca.com.br/centraldeservicos/img//%7BB3B309C7-F0D8-42AD-9C30-7A44D60E65BE%7D_vest_casa_02.png\",\"http://www.tribecca.com.br/centraldeservicos/img//%7B92EBF4A5-F0A1-4937-8A16-9E6B3E71EB87%7D_vest_casa_03.png\",\"http://www.tribecca.com.br/centraldeservicos/img//%7BE46A19B8-D470-4333-A4CD-6635F4D63426%7D_vest_casa_04.png\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '550000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78dm00tgeh0stlx63327', 'FACILITOY', 'facilitoy', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e Recreação', 'Locação de brinquedos infantis', 2022, 2023, NULL, '2026-04-01 02:00:11.680', '2025-08-05 22:20:30.250', 1097, NULL, 1, 2020, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1cf0f621-40bf-4e66-a7a2-b4ae7b23eca5.png', 11, NULL, NULL, '2026-03-09 21:13:24.033', 'https://franquias.portaldofranchising.com.br/franquia-facilitoy/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '39990', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78dr00theh0swaxbkdoj', 'BIBI', 'bibi', NULL, 'Moda', 'CALÇADOS', 'Loja de Calçados e Acessórios Infantis.', 2008, 2010, '[\"https://www.youtube.com/watch?v=pLIdARMBfC0\",\"https://www.youtube.com/watch?v=V1OGjmQ_id8\",\"https://www.youtube.com/watch?v=wNFEkl_9fWc\"]', '2026-04-01 02:00:11.690', '2025-08-05 22:20:30.255', 1098, NULL, 1, 1949, 'Fundada em 1949, a Bibi é pioneira na fabricação de calçados infantis no Brasil. Com indústria própria, atua por meio do modelo de franquias há mais de 15 anos. Especialista no público infantil, a marca desenvolve produtos com tecnologia que visam contribuir para o crescimento saudável de crianças de 0 a 9 anos em diferentes fases do desenvolvimento. Além disso, a Bibi tem atuação global, está presente em mais de 60 países nos cinco continentes e soma 152 lojas espalhadas por todo Brasil e em países da América Latina. Ambientada no universo infantil de Baby, cada loja harmoniza produtos para todas as fases de desenvolvimento da criança, seja ela Baby, Mini ou Kids. Além de transformar o momento da compra em uma experiência sensorial e fluída de consumo. Para isso, a rede investe em conceitos de transformação digital para que os consumidores optem pelo físico ou digital, proporcionando praticidade na jornada de compra. A Bibi possui um mix de calçados e acessórios com linhas exclusivas, coleções inovadoras e um calendário de vitrines e ações, criando a sensação de uma nova loja a cada visita. Mais que uma operação infantil, a Bibi é um ponto de experiência da marca com o seu consumidor. Com o propósito de fazer o bem, um passinho por vez, a empresa visa o incentivo às práticas sustentáveis, o estímulo ao desenvolvimento saudável das gerações futuras, e o cumprimento das suas responsabilidades sociais para a construção de um mundo melhor. Há mais de 70 anos a bibi decidiu olhar o mundo pela perspectiva da criança para fazer o bem para elas, porque fazendo o bem pra elas, elas fazem o bem para o mundo.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/60cb4f86-80e2-451a-a26e-8d01d24471f1.jpg', 148, NULL, NULL, '2026-01-12 12:27:17.000', 'https://franquias.portaldofranchising.com.br/franquia-bibi/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '380000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78dw00tieh0szvg24q4k', 'VIDA LEVE', 'vida-leve', NULL, 'Alimentação', 'Bares e Restaurantes', 'Alimentação Saudável!', 2019, 2019, NULL, '2026-04-01 02:00:11.699', '2025-08-05 22:20:30.261', 1099, NULL, 1, 2015, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0f0eab46-b758-4be5-a032-67741e7811eb.png', 80, NULL, NULL, '2026-03-09 21:13:45.341', 'https://franquias.portaldofranchising.com.br/franquia-vida-leve/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '169900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78e100tjeh0szgkmhqye', 'M1 MOTORS', 'm1-motors', NULL, 'Serviços e Outros Negócios', 'CONSULTORIAS', 'Consultoria Automotiva', 2022, 2022, NULL, '2026-04-01 02:00:11.709', '2025-08-05 22:20:30.266', 1100, NULL, 1, 2020, 'A Inovação do Mercado Automotivo! A primeira loja de carros presente no mundo digital e nos maiores pontos de circulação da cidade. Oferecemos um modelo inovador para o setor automotivo. Vamos transformar a forma como os brasileiros compram e vendem veículos, somos uma facilitadora e oferecemos uma experiência diferenciada. Com mais de 4 anos de atuação no mercado automotivo, e 27 anos de experiencia do fundador da marca, o grupo M1 consolidou-se como referência ao desenvolver um estoque 100% online que proporciona praticidade na escolha, para comprar ou vender um carro. Nossa equipe é formada por profissionais especializados, focados em maximizar a lucratividade de cada parceiro franqueado. Fazer parte da nossa rede é integrar um modelo de negócio que busca constantemente tecnologia de ponta e se mantém à frente do mercado, garantindo a satisfação dos consumidores e o crescimento sustentável de franqueados e clientes. Com um know-how de qualidade, inspirado nas tendências globais, e utilizando o conceito de Auto Broker, amplamente utilizado nos EUA e em outros países de primeiro mundo, realizamos transações de compra e venda de veículos de forma rápida e sem complicações. Nossos franqueados estão prontos para compreender as expectativas dos clientes e oferecer soluções personalizadas para cada necessidade. Esperamos você como um franqueado M1 MOTORS. Missão: Revolucionar o mercado automotivo brasileiro, e criar um ambiente que preza pelo bem-estar e satisfação do cliente. Visão: Ser referência no Brasil como a melhor escolha para quem deseja comprar, vender ou trocar de carro, promovendo um crescimento conjunto e sustentável. Valores: Respeito, ética, transparência, inovação e compromisso com a credibilidade e a confiança.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/121596c7-7ed5-4028-877a-9084faeda835.svg', NULL, NULL, NULL, '2025-08-18 13:06:28.000', 'https://franquias.portaldofranchising.com.br/franquia-m1-motors/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78e800tkeh0s3h0vbi4t', 'FOZ SUSTENTÁVEL', 'foz-sustentavel', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Invista no seu futuro e no futuro do planeta com a Foz. Gere lucro enquanto economiza com o nosso método exclusivo e tecnologias inovadoras. Junte-se a sustentabilidade lucrativa à prova de crises.', 2019, 2024, '[\"https://www.youtube.com/watch?v=EvEcJWGYGmA\",\"https://www.youtube.com/watch?v=jX3ub0HhMJY\",\"https://www.youtube.com/watch?v=LcO31YfMt3o\",\"https://www.youtube.com/watch?v=oDIgdowz5mY\"]', '2026-04-01 02:00:11.719', '2025-08-05 22:20:30.272', 1101, NULL, 1, 2016, 'Transforme desperdício de água em lucro. Seja pioneiro com a Foz Sustentável! Você sabia que o Brasil desperdiça mais de 6 TRILHÕES de litros de água e movimenta mais de R$70 BILHÕES de reais ao ano? Se não sabia, você não está sozinho. Enquanto todos falam de energia solar, poucos percebem que a água também precisa de uma revolução. A Foz Sustentável está liderando essa mudança transformando desperdício em lucro, tanto para unidades próprias quanto para unidades franqueadas. Com mais de 9 anos de experiência de mercado e mais de 30 milhões de reais economizados, a Foz desenvolveu um modelo de franquia barata com atuação exclusiva chamada de “Economia por Performance”, permitindo que os clientes economizem até 80% de água e 30% na energia de bombeamento sem precisar investir nada. Isso significa que toda a economia gerada é compartilhada entre o cliente e a franquia, garantindo uma receita recorrente e acumulativa, além de outras formas de ganhos como por exemplo, a Venda do Projeto e Gestão Foz 4.0. Através de um modelo Robusto e Seguro, as franquias baratas da Foz oferecem: Negócio validado com métodos exclusivos. Tecnologias inovadoras com produção própria. Retorno expressivo com margens de lucro de 30% para Venda do Projeto e 75% para Economia por Performance. Mercado pouco explorado com alta demanda e baixa concorrência. Equipamentos sem custo para o franqueado. Sem estoque: envio de equipamentos por conta da franqueadora. Franquia Barata com baixo investimento e grande retorno. Sustentabilidade Lucrativa: ganhe dinheiro enquanto ajuda o planeta. “O Nosso modelo exclusivo permite que empresas e condomínios economizem até 80% no ponto de água sem precisar investir nem um centavo. Em troca, a economia gerada é dividida entre o cliente e a franquia, gerando uma receita previsível, recorrente e cumulativa.” Imagine, por exemplo, um condomínio ou empresa que paga R$16 mil por mês na conta de água. Com a Foz, se reduzirmos esse custo em 50%, metade fica com o cliente e metade com a franquia e o franqueado, sem que o cliente precise investir nada em contratos que variam de 3 a 5 anos. Ou seja, um único cliente que gerar R$2.000 por mês seguindo o plano de aquisição de 4 clientes/mês ou 48 clientes no total, é possível atingir R$100.000 por mês de recorrência, R$1.200.000 faturados, com uma estrutura enxuta de uma franquia barata. A franqueadora decidiu em 2024 que abriria novas unidades Brasil afora, o mercado está praticamente inexplorado e entrar agora é uma grande oportunidade. As primeiras 20 unidades já foram adquiridas, e já restam poucas oportunidades para algumas regiões. Garanta sua franquia antes que sua região seja totalmente ocupada. O que os franqueados estão dizendo: \"Comecei minha franquia com 2 reais no bolso. 3 meses depois já faturei R$12.000, que deu para cobrir investimentos. Tenho muitos prédios em recorrência que me dá tranquilidade no final do mês.\" - Markus Lebre, 30 anos. “Nesse negócio conseguimos gerar economia para o cliente, recorrência para nós e temos um amplo leque de atuação. Negócios locais, condomínios, hospitais, hotéis, faculdades, indústrias e mais um monte.” - Victor Melo, 28 anos. Aproveite um oceano azul de oportunidades com um negócio altamente lucrativo, escalável e sustentável com a franquia barata da Foz: Baixe a apresentação agora, entenda como a franquia funciona e como você pode lucrar muito enquanto ajuda o planeta.', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9b5f00a8-edbc-499e-8656-16516486b057.jpeg', 20, NULL, NULL, '2025-09-06 00:00:12.000', 'https://franquias.portaldofranchising.com.br/franquia-foz-sustentavel/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ee00tleh0socniwt7g', 'SORRIDENTS', 'sorridents', NULL, 'Saúde, Beleza e Bem-Estar', 'Odontologia', 'A Sorridents é uma das maiores e mais conceituadas redes de clínicas odontológicas do mundo. Fundada em 1995, a Sorridents nasceu com o objetivo de trazer a todos o direito fundamental de sorrir.', 2005, 2008, '[\"https://www.youtube.com/watch?v=-nd899AmhRk\",\"https://www.youtube.com/watch?v=Lje18ToyqI0\",\"https://www.youtube.com/watch?v=6fDTFLYhqDk\"]', '2026-04-01 02:00:11.729', '2025-08-05 22:20:30.278', 1102, NULL, 1, 1995, 'SEJA MUITO BEM VINDO À FRANQUIA SORRIDENTS\n  A REDE DE CLÍNICAS ODONTOLÓGICAS MAIS PREMIADA DO BRASIL!  \n  A franquia Sorridents é a mais premiada rede de clínicas odontológicas do Brasil.   Fundada em 1995, a rede completou 25 anos de sucesso e referência no segmento odontológico com mais de 4,5 milhões de pacientes atendidos!\n  O setor de clínicas odontológicas possui uma enorme oportunidade de negócio, existem mais de 20 milhões de brasileiros que ainda não tiveram nenhuma experiência com o cirurgião dentista e este segmento possui uma das maiores rentabilidades do setor do Franchising.\n  Mas por que Sorridents?\n  A Sorridents em suas duas décadas e meia de história acumulou experiência suficiente para ganhar 9 vezes o prêmio de Melhor Franquia do Brasil, além de ter recebido diversos outros destaques como ter por recebido por 10 anos consecutivos o Selo de Excelência e estar no ranking Top 25 do Franchising Brasileiro. \nIsso significa uma grande engrenagem com um time de especialistas e infraestrutura completa para auxiliar as Unidades da rede e seus franqueados a potencializar a gestão do seu negócio através do Porque Sorridents!  \nA franqueadora trabalha para trazer a rede inovação e estrutura, sempre com novos projetos, parcerias e ferramentas que agreguem ainda mais valor ao trabalho e serviço oferecido nas clínicas, assim oferecemos ao franqueado:  - Marca\n  O apoio de um nome fortalecido há 25 anos sobre os seus sólidos pilares com a missão de propiciar acesso a uma odontologia moderna com conforto, conveniência e qualidade com 95% de pacientes satisfeitos.   Reconhecida pelos maiores veículos de mídias especializada como a Melhor Franquia do Brasil no segmento de saúde e bem-estar, além de constante visibilidade e relevância no dia a dia do consumido em matérias na Exame, Veja, GloboNews, Portal Terra, e outros importantes veículos.\n  - Estrutura \nCom clínicas térreas com mais de 180 m2 e padronizadas, a rede busca proporcionar um atendimento de excelência em todas as suas Unidades.   A equipe de implantação da franqueadora acompanha o novo franqueado em todos as etapas de construção da sua loja, desde o seu projeto de arquitetura a festa de inauguração. Depois suporte continua com consultores de campo, time de marketing, call center, jurídico e muito mais.  - Tecnologia \nO franqueado faz a gestão de sua Unidade no Sistema SISO e acompanha sua performance no BI Sorridents.   Além de rentabilizar o seu negócio com as ferramentas exclusivas da marca como o Cartão de Crédito Sorridents, onde o paciente pode parcelar seus tratamentos em até 18 vezes.  - Serviços  \nO paciente Sorridents encontra todas as especialidades em um só lugar e mais que isso, oferecemos um cuidado especial, tratando-o como único, ouvindo a sua necessidade, explicando o seu problema e mostrando a melhor solução e o quando é importante tratar, esse é o jeito de ser Sorridents! \n  Seja um Franqueado Sorridents! \nConheça mais sobre o negócio Sorridents.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3f81e60e-7d0e-451c-8cd4-15893702fe9e.jpg', 391, NULL, NULL, '2026-03-09 21:14:28.560', 'https://franquias.portaldofranchising.com.br/franquia-sorridents-odontologica/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0df12db1-16f6-4034-aca2-096ea2613947.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '460000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ek00tmeh0sobea7riz', 'VIVENDA DO CAMARÃO', 'vivenda-do-camarao', NULL, 'Alimentação', 'Bares e Restaurantes', 'Culinária Rápida de Frutos do Mar', 1998, 1996, '[\"https://www.youtube.com/watch?v=o8veMMbic64\"]', '2026-04-01 02:00:11.738', '2025-08-05 22:20:30.284', 1103, NULL, 1, 1984, 'A Vivenda do Camarão surgiu com o intuito de oferecer a sofisticação e a qualidade do camarão a preços acessíveis. No dia 12 de junho de 1984, no bairro paulistano de Moema, foi inaugurado o primeiro restaurante da rede. Uma simples faixa na rua anunciando `CAMARÃO A PREÇO JUSTO` foi o suficiente para que se formasse uma fila de clientes esperando para conhecer a grande novidade. A partir de então, com fila de espera diariamente, fez-se necessária a abertura de mais um restaurante, dessa vez no bairro dos Jardins, em São Paulo. O sucesso se consolidou e apareceu o convite para a Praça Gourmet do Shopping Morumbi, onde foi criado, então, o conceito de Vivenda do Camarão Express, possibilitando a abertura de novos estabelecimentos e a consolidação da rede nos principais shoppings. Diante disso, fez-se necessária a construção da atual CPA - Central Processadora de Alimentos, situada em Cotia, na Grande São Paulo, onde são processadas cerca de 2000 toneladas de pescados por ano, que se transformar em todos os pratos oferecidos pelas lojas. Dotada de equipamentos exclusivos e de altíssima tecnologia, permite mais agilidade na produção e garante um excelente controle de qualidade. Oferecendo a mesma qualidade exigida pelos importadores, mas a preços populares, a Vivenda do Camarão leva ao alcance de todos o riquíssimo valor proteico e as baixas calorias do camarão. É muito importante destacar que os camarões utilizados pela Vivenda são cultivados em fazendas especializadas e não recebem nenhum tipo de conservante. Trata-se de um alimento altamente saudável, sem químicas e da mais alta qualidade. Oferecendo a mesma qualidade exigida pelos importadores, mas a preços populares, a franquia Vivenda do Camarão leva ao alcance de todos o riquíssimo valor proteico e as baixas calorias do camarão. É muito importante destacar que os camarões utilizados pela Vivenda são cultivados em fazendas especializadas e não recebem nenhum tipo de conservante. Trata-se de um alimento altamente saudável, sem químicas e da mais alta qualidade. Tudo isso garantiu a certificação para exportação de alimentos prontos para os EUA (FDA) e para a Comunidade Europeia, algo inédito para frutos do mar em todo o hemisfério sul. Mais uma prova de que a Vivenda do Camarão está compromissada com a máxima qualidade em todos os produtos que oferece. A Vivenda do Camarão recebeu pelo 10º ano consecutivo o Selo de Excelência em Franchising da ABF, o ISO 9000 das franquias. A rede também foi condecorada com o troféu Hors Concours na categoria Restaurante do Prêmio Alshop, por ganhar três vezes consecutivas, pelo voto do consumidor, além de ter ficado em 2º lugar no prêmio cedido pela PEGN no quesito Melhores Franquias do Brasil. Em 2011 recebeu o título inédito de Melhor Franqueadora do Ano, entre todas as categorias, também cedido pela ABF. Em 2017, recebemos mais um reconhecimento, fomos vencedores no Prêmio ABF + RDI Desing, na categoria Ouro, como melhor Visual Merchandising de loja. Com uma marca conhecida e apreciada em todo o país, atualmente a rede tem mais de 150 lojas da Vivenda do Camarão nas principais cidades brasileiras, além do Paraguai. Com uma marca conhecida e apreciada em todo o país, atualmente a rede tem mais de 150 lojas da Vivenda do Camarão nas principais cidades brasileiras, além do Paraguai e Portugal.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/771621a4-a0c0-40bf-8a47-da0f827b3de8.jpg', 158, NULL, NULL, '2026-03-09 21:15:56.721', 'https://franquias.portaldofranchising.com.br/franquia-vivenda-do-camarao-alimentacao/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b0922ee3-f8b8-4081-9a29-49e44dd25814.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
