INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ew00toeh0svxv7re78', 'BOTOCENTER', 'botocenter', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Clínica de estética especializada na aplicação de Toxina Botulínica (Botox) e outros injetáveis faciais.', 2021, 2022, NULL, '2026-04-01 02:00:11.758', '2025-08-05 22:20:30.296', 1105, NULL, 1, 2019, '', NULL, 'SÃO PAULO', 1, NULL, 74, NULL, NULL, '2026-03-09 21:22:29.482', 'https://franquias.portaldofranchising.com.br/franquia-botocenter-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '122000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78f100tpeh0slr2w5zj8', 'GiO Estética Avançada', 'gio-estetica-avancada', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A GiO Estética Avançada é uma franquia de depilação a laser, estética facial e corporal que une alta tecnologia a baixos custos para o cliente.', 2014, 2014, '[\"https://www.youtube.com/watch?v=N8giRCchC_w\",\"https://www.youtube.com/watch?v=_hWmNxAc0ws\",\"https://www.youtube.com/watch?v=dHdmXEbFyGA\",\"https://www.youtube.com/watch?v=M-NCvmDUr2Y\"]', '2026-04-01 02:00:11.768', '2025-08-05 22:20:30.302', 1106, NULL, 1, 2007, 'SEJA BEM VINDO À GiO Estética Avançada\nTudo em um só lugar\n  Por que estética? Nascida do desejo de oferecer a melhor tecnologia em depilação a laser e estética facial e corporal com valores indiscutivelmente acessíveis, a GiO Estética Avançada iniciou sua trajetória a partir da sociedade entre 2 esteticistas com espírito empreendedor e a estrela global Giovanna Antonelli. Desde 2013, com unidades bem estruturadas em diferentes cidades e estados do território nacional, a rede de clínicas não parou de crescer e está cada vez mais presente em todo o país, levando ainda mais bem-estar e autoestima tanto para homens quanto para mulheres com máxima segurança, conforto, eficácia e acessibilidade. Hoje, a rede de franquias de estética e depilação a laser faz parte do grupo Salus Participações, dona também da marca Sorridents e holding de saúde consolidada no mercado, o que qualifica ainda mais seu plano de expansão, multiplicando suas unidades de forma sólida, responsável e seletiva. Os brasileiros estão cada vez mais preocupados com a aparência Segundo a ABF (Associação Brasileira de Franchising), o setor de beleza e estética movimentou mais de 55 bilhões de reais no último ano*.   Franquias de estética nunca estiveram tão em alta! Mesmo em tempos de crise, o mercado de saúde, beleza e bem-estar figura entre as maiores ascensões do segmento de franquias, registrando um crescimento de 17,5% no ano de 2023*. *Fonte: ABF – Associação Brasileira de Franchising  POR QUE GiO Estética Avançada? Suporte completo da implantação à gestão diária da sua clínica Geomarketing, projeto arquitetônico, manuais de suporte jurídico, operacional, comercial, de atendimento e gestão, modelo de negócio descomplicado. Tudo o que você precisa para se tornar referência em sua região Treinamentos para sua equipe, total acesso às ações promocionais da rede e consultores de campo sempre à disposição para sugerir soluções e analisar o sucesso do seu negócio.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1970bf60-77f5-4b16-9a9a-87696888b73a.png', 230, NULL, NULL, '2026-03-09 21:22:52.327', 'https://franquias.portaldofranchising.com.br/franquia-gio-estetica-avancada-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '620000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
