INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ga00tweh0se5o8pdko', 'CASA DE MADRINHA', 'casa-de-madrinha', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e Recreação', 'A Casa de Madrinha tem compromisso em fazer de cada festa um evento único, realizando sonhos e proporcionando momentos inesquecíveis aos seus clientes.', 2021, 2023, NULL, '2026-04-01 02:00:11.835', '2025-08-05 22:20:30.346', 1113, NULL, 1, 2017, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/29076df6-435c-415b-b891-4ffc9c3f0bf6.jpg', 3, NULL, NULL, '2026-03-09 21:26:05.580', 'https://franquias.portaldofranchising.com.br/franquia-casa-de-madrinha/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '767000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78gk00txeh0sbqrgxtcf', 'LIVRARIA E PAPELARIA NOBEL', 'livraria-e-papelaria-nobel', NULL, 'Entretenimento e Lazer', 'BRINQUEDOS E LAZER', 'Livros, Papelaria, Revistas e Presentes', 1992, 1993, NULL, '2026-04-01 02:00:11.844', '2025-08-05 22:20:30.356', 1114, NULL, 1, 1943, 'A Livraria Nobel foi fundada em São Paulo no ano de 1943 pelo imigrante italiano Cláudio Milano e logo se especializou na venda e edição de apostilas escolares. Desde o princípio se destacou pela qualidade e profissionalismo em suas atividades. Hoje, a empresa é formada pela rede de lojas e pelas editoras Nobel, Marco Zero, Studio Nobel, publicando livros sobre as mais diversas áreas do conhecimento. Trabalhando com sistemas de franquia desde 1992, a Nobel é hoje a maior rede de livrarias do Brasil com mais de 100 franquias distribuídas pelo país. Franquia: Em 1992, a Nobel optou pelo sistema de Franchising para a expansão de sua rede de livrarias e papelarias, seguindo sua filosofia de contínua preocupação com a qualidade dos serviços prestados aos seus clientes. Essa decisão foi fruto da constatação de que a presença do `dono` franqueado em sua loja aumenta muito a fidelidade da clientela, a produtividade do trabalho dos funcionários, a qualidade das compras e, como conseqüência, o volume das vendas e dos lucros. O Sistema Nobel de Franchising é baseado nos três fatores que realmente importam numa franquia: força da marca, know-how e melhores condições de compra em rede. A marca Nobel existe desde 1943 e está em permanente evidência, seja pelas dezenas de lojas em funcionamento, seja pela propaganda contínua da Editora Nobel e do rede como um todo. A rede Nobel tem hoje um volume de compras que possibilita descontos melhores junto aos fornecedores do que obteria qualquer loja isoladamente, prazos especiais de pagamento e grande variedade de livros em consignação - o que diminui o risco e o capital inicial necessário para a formação de estoque. Tudo isso sem qualquer obrigação para o franqueado de compra mínima ou de cotas, atuando cada franquia como unidade livre e independente, definindo seu próprio mix de produtos. Nobel Mega Store A partir de 1998, seguindo uma tendência mundial, a Nobel começou a ampliar o conceito de seu negócio para um modelo de entretenimento. A loja aumentou sua área física, disponibilizando uma maior variedade e quantidade de estoque, deixando de ser um local apenas para compras e passando a ser uma destinação importante para famílias que buscam novas opções de lazer e cultura. Assim, além de produtos tradicionais, começou a vender em sua rede de lojas produtos culturais complementares aos livros tais como CDs musicais, vídeos, DVDS, revistas, brinquedos educativos e produtos multimídia, agregando valor às suas lojas e trazendo uma maior satisfação aos seus clientes. Surgiu assim o conceito da Nobel Mega Store, em que, cada loja adota o sistema de auto-serviço, onde o cliente dispõe de vários espaços temáticos, tais como área de acesso à lnternet, Café para momentos agradáveis de leitura, área infantil com atividades educativas, área especial para palestras e noite de autógrafos e muito mais, transformando o ato comprar em um momento de lazer, entretenimento e magia.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2b26bb63-b188-4401-99e7-1d53e2041d04.jpg', 151, NULL, NULL, '2025-08-05 15:44:50.000', 'https://franquias.portaldofranchising.com.br/franquia-livraria-e-papelaria-nobel-livrarias/', NULL, NULL, '[\"http://www.tribecca.com.br/centraldeservicos/img/{5E989A41-7F90-4A33-AB6C-12616C76AA7A}_Cópia%20de%20historia%20nobel.jpg\",\"http://www.tribecca.com.br/centraldeservicos/img/{BF502141-D7C3-4478-82CC-9D24F630E004}_nobel%20loja.jpg\",\"http://www.tribecca.com.br/centraldeservicos/img/{C3DDE117-3493-4432-AD18-95755078FEFF}_Cópia%20de%20nobel%20express.jpg\",\"http://www.tribecca.com.br/centraldeservicos/img/{30B7784E-506E-4BCF-B162-81EE84535D80}_nobel%20mega%20storm.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78hd00tzeh0shn5tk1te', 'LUMAVI FRANCHISING', 'lumavi-franchising', NULL, 'Casa e Construção', 'CONSTRUÇÃO', 'Somos uma rede de franquias com o foco na entrega de soluções em iluminação ao consumidor final. Do produto ao projeto luminotécnico e produtos direto da fábrica, sem que você precise de estoque.', 2021, 2022, NULL, '2026-04-01 02:00:11.853', '2025-08-05 22:20:30.385', 1116, NULL, 1, 1992, 'A Lumavi, fundada em 1992 por Caubi Camargo e hoje tendo como gestores seus dois filho, Matheus e Vitor, é a única indústria de iluminação no mercado de franquias. Com uma estrutura de 11.000 m², e mais de 30 franqueados atuantes, a Lumavi tem como missão democratizar o acesso a iluminação de qualidade a todos. Com diversos cases de sucesso e alimentando 100% do mercado de construção civil, a Lumavi busca agora expandir sua marca, para cada vez mais se consolidar como A MAIOR EMPRESA DE ILUMINAÇÃO DO BRASIL. Venha fazer parte de um mercado que movimenta Bilhões ao ano e cresce em média 140% ano ano.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1fb4c5cc-4ca3-4d26-83e2-7c6ca1f5c733.png', 76, NULL, NULL, '2025-09-29 17:03:16.000', 'https://franquias.portaldofranchising.com.br/franquia-lumavi-franchising/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78hk00u0eh0s8weeqhad', 'HOPE LINGERIE', 'hope-lingerie', NULL, 'Moda', 'Vestuários', 'comércio varejista de artigos do vestuário feminino, na linha de lingerie e acessórios, bem como produtos do vestuário masculino, na linha de cuecas, pijamas, camisetas, samba canção, etc.', 2005, 2007, NULL, '2026-04-01 02:00:11.862', '2025-08-05 22:20:30.393', 1117, NULL, 1, 1966, 'Com expertise de 18 anos no mercado de franquias, a HOPE é referência no segmento de moda íntima. Os pilares da marca são guiados pelo conforto, qualidade e inovação, que acompanham mulheres e homens em todos os momentos da vida. Com cases icônicos de marketing, foi pioneira em trazer grandes nomes para as suas campanhas e inovar no lançamento de coleções sustentáveis, pautadas pelo pilar ESG. Atualmente, a HOPE possui 211 operações em todo o território brasileiro.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d9c112fd-ba74-4b74-b6fc-5a56ea351683.png', 304, NULL, NULL, '2026-03-09 21:29:03.649', 'https://franquias.portaldofranchising.com.br/franquia-hope-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '310000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78hq00u1eh0sv93yjshq', 'SELFIT', 'selfit', NULL, 'Saúde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'ACADEMIA DE MUSCULAÇÃO E GINÁSTICA LOWCOST-HIGHVALUE', 2019, 2018, '[\"https://www.youtube.com/watch?v=XBCsxMFxP6E\"]', '2026-04-01 02:00:11.872', '2025-08-05 22:20:30.398', 1118, NULL, 1, 2012, 'Sendo referência no modelo High Value, Low Price (HVLP), uma proposta que une estrutura moderna, tecnologia e acolhimento com planos acessíveis e sem burocracia, a Selfit Academias é uma das maiores redes de academias do Brasil. Desde 2012, quando nasceu em Salvador (BA), a Selfit tem crescido exponencialmente. A partir de 2015, com a entrada do fundo H.I.G. Capital, a expansão ganhou ainda mais força, consolidando a marca como uma das principais do setor fitness na América Latina. Hoje, a Selfit conta com mais de 160 unidades entre próprias e franqueadas, presentes em todas as regiões do país. A marca também é reconhecida por sua inovação: além da infraestrutura completa com áreas exclusivas para musculação, cardio, cross training e aulas coletivas. Em 2021, a Selfit investiu na startup Weburn, reforçando seu ecossistema digital com treinos online, dicas de alimentação e bem-estar, permitindo ao aluno treinar de onde estiver. E no segundo semestre de 2024, a marca foi certificada com o selo Great Place to Work (GPTW), que reconhece as melhores culturas organizacionais do Brasil. Com planos a partir de R$ 99,90, sem anuidade, sem fidelidade e sem surpresinhas, a Selfit promove uma jornada acessível para os alunos e, ao mesmo tempo, uma oportunidade sólida de investimento para franqueados. O objetivo é claro: democratizar o acesso à atividade física com qualidade e preço justo. Seja como franqueado ou sócio investidor, fazer parte da Selfit é integrar uma marca que cresce com propósito, com um modelo escalável, alto potencial de retorno e suporte completo da franqueadora. Selfit, a academia do seu jeito.', NULL, 'PERNAMBUCO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5ac8f703-f754-4918-8cc9-8e229dbb8695.jpg', 188, NULL, NULL, '2026-03-09 21:29:38.185', 'https://franquias.portaldofranchising.com.br/franquia-selfit/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '1050000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
