INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfop30000eh0s24eg5w8c', 'Carol Coxinhas', 'carol-coxinhas', NULL, 'Alimentação', 'Bares e Restaurantes', 'Comercio varejista', 2025, 2025, '[\"https://www.youtube.com/watch?v=fWG8-VJbst4\",\"https://www.youtube.com/watch?v=CtHhh5EcyWE\",\"https://www.youtube.com/watch?v=QYlbbZCvmWw\",\"https://www.youtube.com/watch?v=ihEOCxlfAYA\",\"https://www.youtube.com/watch?v=_wcYVrWN4f8\"]', '2026-04-01 02:00:11.945', '2025-08-11 01:37:23.269', 1126, NULL, 1, 2015, 'Deixa eu te contar o que é a Carol Coxinhas, é o porque nosso modelo de negócio, é ideal para você!', NULL, 'Minas Gerais', 1, NULL, 73, NULL, NULL, '2026-03-09 21:32:25.317', 'https://franquias.portaldofranchising.com.br/franquia-carol-coxinhas/', 'Compras', 'Compras', NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '85000', NULL, NULL, NULL, '15000', NULL, '5', '2.5', '65000', '5000', 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfoql0001eh0sd5rh290z', 'CEOPAG', 'ceopag', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Somos uma Rede de Franquias de Meios de Pagamentos (Fintech). Aplicativo, maquininha, delivery e outros.', 2019, 2019, '[\"https://www.youtube.com/watch?v=F0bzHH-_zQQ\",\"https://www.youtube.com/watch?v=D3a0g5QwT3Q\",\"https://www.youtube.com/watch?v=VpRATwiptr4\"]', '2026-04-01 02:00:11.955', '2025-08-11 01:37:23.325', 1127, NULL, 1, 2019, 'A CEOPAG, é uma fintech (empresa de tecnologia e inovação aplicadas na solução de serviços financeiros), de alta tecnologia criada para revolucionar o mercado de meios de pagamento. Com foco no PMEs e MEIs, a CEOPAG, une quatro segmentos que mais crescem no Brasil: a Maquininha, Banco Digital, App Delivery de Tudo e Telemedicina. Presente em 23 estados, mais 250 cidades e mais de 350 franquias; a CEOPAG oferece um atendimento humanizado e presencial através de sua Rede de Franquias, com produtos de alta tecnologia. No modelo de negócios da CEOPAG, o franqueado é responsável pela prospecção, cadastramento e o atendimento às empresas que utilizarão os meios de pagamentos. Nossa ideia é democratizar totalmente o modelo de pagamentos por meios eletrônicos, e com isso gerar mais oportunidades de negócios para todos. O franqueado além de entrar para um time de sucesso com baixo investimento inicial, receberá treinamento, suporte e consultoria totalmente humanizada. A Ceopag tem 2 modalidades de Franquia, de acordo com seu perfil: Franquia Home Nacional: Investimento de R$19.990,00. Atua na prospecção de clientes podendo ter somente o titular de contrato como operador da Franquia. Estimativa de Lucro Líquido de R$5.000,00 à R$7.000,00 mensal a partir do 6º mês, com crescimento recorrente de acordo com trabalho e dedicação do Franqueado. Retorno do Investimento de 3 à 6 meses.\n\t  Franquia FDA Nacional: Investimento à partir de R$100.000,00. Atua como Máster Franqueado Nacional, vendendo Franquias e gerando receita sobre as vendas e produtividade de todos os franqueados vinculados à sua Máster, além de ganhar uma Franquia Full para operar também. Estimativa de Lucro Líquido de R$20.000,00 à R$25.000,00 mensal a partir do 6º mês, com crescimento recorrente de acordo com trabalho e dedicação do FDA Máster. Retorno do Investimento de 12 à 18 meses.\n\t  Invista em um negócio que realmente funciona. \nCom um pequeno investimento inicial, você tem um retorno real e formas de crescimento recorrente. \nFranquia com baixo investimento e alta lucratividade, sem a necessidade de ponto fixo e funcionários. Faça parte dessa Franquia de sucesso! Preencha o formulário e saiba mais sobre este modelo de negócio.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b6dd7b53-501f-4045-8c34-c4e99c97950a.jpg', 717, NULL, NULL, '2026-03-09 21:38:05.626', 'https://franquias.portaldofranchising.com.br/franquia-ceopag/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '21490', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfor30002eh0sujtevmg0', 'Seguralta - Bolsa De Seguros', 'seguralta-bolsa-de-seguros', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Franquia', 2009, 2009, '[\"https://www.youtube.com/watch?v=RWukLA9ln5Y\",\"https://www.youtube.com/watch?v=IY1hM4T1Xws\"]', '2026-04-01 02:00:11.965', '2025-08-11 01:37:23.343', 1128, NULL, 1, 1971, '', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/58d1e5ef-d16a-4150-9993-3b9488084775.jpg', 1832, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d5290775-0a6e-4c95-826e-8b8bf6e10b69.jpg', '2026-03-09 21:39:30.435', 'https://franquias.portaldofranchising.com.br/franquia-seguralta-servicos/', 'Fat. Líq.', 'Fat. Líq.', NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '55000', NULL, NULL, NULL, '40000', '50000', NULL, '5', '5000', '10000', 35);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mforf0003eh0s3ssetfrt', 'SKYONE', 'skyone', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Tecnologia da Informação', 2024, 2024, '[\"https://www.youtube.com/watch?v=TcjEwws_D_c\",\"https://www.youtube.com/watch?v=ZwZ0ZLiwvx4\"]', '2026-04-01 02:00:11.975', '2025-08-11 01:37:23.355', 1129, NULL, 1, 2013, 'Desde 2013, temos como objetivo simplificar o dia a dia e aumentar a produtividade de nossos clientes. Ao longo desse caminho, nossa missão se materializou em um ecossistema robusto e inovador. Estamos presentes em mais de 35 países, transformando a realidade de empresas líderes em seus segmentos. Oferecemos uma plataforma única e completa que abrange: Computação em Nuvem; Dados e Inteligência Artificial; Cibersegurança; Marketplace; Serviços; Por que ser um Franqueado Skyone? Parceria sólida: Construímos relações baseadas em transparência, confiança e suporte contínuo. Sucesso mútuo: Nossa visão de médio e longo prazo visa o sucesso tanto da Skyone quanto de nossos franqueados. Recompensas tangíveis: Oferecemos recompensas palpáveis pelo desempenho e sucesso dos franqueados. Impacto no futuro: Juntos, podemos impactar o amanhã com uma plataforma única e infinitas possibilidades. Valor único: A Skyone oferece uma proposta de valor sólida, criando uma jornada de parceria única e vantajosa.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/468162a3-8d2e-432b-9bcd-acda9bf3199b.svg', NULL, NULL, NULL, '2026-03-09 21:45:33.953', 'https://franquias.portaldofranchising.com.br/franquia-skyone/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '15000', NULL, NULL, NULL, '40000', NULL, '10', '2', NULL, NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mforn0004eh0skcp6umab', 'Inverno D\'italia Coffee', 'inverno-d-italia-coffee', NULL, 'Alimentação', 'Bares e Restaurantes', 'Comercio varejista', 11, 16, '[\"https://www.youtube.com/watch?v=X6FbtSvCibo\"]', '2026-04-01 02:00:11.986', '2025-08-11 01:37:23.363', 1130, NULL, 1, 100, 'O café está na nossa história e no nosso sangue. Há mais de 100 anos a nossa família trabalha com o café, em suas diversas etapas. A nossa tradição familiar e nosso sustento se deu por meio desse cultivo.', NULL, 'São Paulo', 1, NULL, 52, NULL, NULL, '2026-03-09 21:46:24.717', 'https://franquias.portaldofranchising.com.br/franquia-inverno-ditalia-coffee/', NULL, 'Fixo Mensal', NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '89000', NULL, NULL, NULL, '15000', '65000', '0', '0', '65000', '9000', 12);
