 NULL, NULL, '30000', '120000', '10.62', '0', '134000', '25000', 90);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfosa0006eh0s5rlgsa9b', 'Casa Do Celular', 'casa-do-celular', NULL, 'Tecnologia', 'Telefonia', 'Franquia', 2009, 2025, '[\"https://www.youtube.com/watch?v=tnTJHHsk4H0\"]', '2026-04-01 02:00:12.007', '2025-08-11 01:37:23.386', 1132, NULL, 1, 2009, 'A Casa do Celular tem uma história e proposta inovadora de negócio, desenhada com o objetivo de vender não somente produtos, mas excelência no que faz. \nA Casa do Celular, em atuação no mercado desde o ano de 2009, foi idealizada e fundada pelo Sr. Darlan Almeida, hoje ainda Presidente atuante na empresa. \nO início das atividades se deu na cidade de Santarém no estado do Pará, com um quadro de 03 funcionários, tendo a frente seu fundador. \nCom ideias visionarias e pensamento empreendedor, a rede Casa do Celular conseguiu enxergar além de seu tempo, apostando em um futuro promissor no meio de telecomunicações, mais especificamente em aparelhos de telefonia celular. \nApós se aprofundar no conhecimento de aparelhos e suas tecnologias, a rede Casa do Celular investiu tempo e dedicação na busca de conhecimento não apenas de tecnologia, como também de mercado.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3d2b910c-86d3-4fb8-b694-c2f5ef96e3fd.jpg', 170, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/486f0404-3387-42f4-bad0-2e30f2c9affa.jpg', '2026-03-09 21:57:10.563', 'https://franquias.portaldofranchising.com.br/franquia-casa-do-celular/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e474ff1e-fd86-4e5e-824f-517e3d796621.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/773afc45-4f1a-4b4d-91bd-60442079bb0f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/93b6e7a5-2ed6-4cd3-844f-3dd7544dc517.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e3328d50-3be7-4b0b-affb-e9be7eb4a2ba.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cf271b46-96bc-4931-8250-6a9a3128d30d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/426ebce4-2bdd-429b-a978-e9dea596047e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4d7457af-b29d-45ae-b563-a3c97e1cbf91.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/09b51674-c5f1-4693-ad24-305f13fe524e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3d410cdd-990f-48c2-8e13-1b1b73c70f18.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '150000', NULL, NULL, NULL, '30000', NULL, '3.5', '2', '120000', NULL, 3535);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfosj0007eh0sy8tdgyz7', 'TEM JEITO', 'tem-jeito', NULL, 'Moda', 'VESTUÁRIO', 'Consertamos e ajustamos roupas, serviços como Barra de calça, troca de zíper, ajustes em vestidos, ternos, todos os tipos de roupas, incluindo serviços têxteis para cortinas toalhas, fronhas e outros', 2020, 2025, '[\"https://www.youtube.com/watch?v=Thq3icV1fBk\",\"https://www.youtube.com/watch?v=0XbjcwHPNKc\"]', '2026-04-01 02:00:12.017', '2025-08-11 01:37:23.395', 1133, NULL, 1, 2015, 'A Tem Jeito é uma franquia inovadora no setor de costura e customização de roupas, fundada em 2015 em Campina Grande (PB) pelo empresário Evandro de Macedo Filho. Ele identificou uma lacuna no mercado para ajustes rápidos e de qualidade, criando um modelo de negócio que alia eficiência e excelência no atendimento. Em 2020, a marca ingressou no sistema de franchising, possibilitando a expansão do negócio. Atualmente, a rede conta com 18 unidades, sendo 6 próprias e 12 franqueadas, consolidando-se como a primeira franquia do Brasil especializada em ajustes e customizações de roupas com um atendimento ágil e diferenciado.', NULL, 'PARAÍBA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/28b5148e-d7df-4123-b73c-0d570bd0624e.png', 15, NULL, NULL, '2025-10-23 12:00:29.000', 'https://franquias.portaldofranchising.com.br/franquia-tem-jeito/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfosw0008eh0szs1miplu', 'INSTITUTO DOS ÓCULOS', 'instituto-dos-oculos', NULL, 'Saúde, Beleza e Bem-Estar', 'ÓTICAS', 'Comércio varejista de óculos.', 2014, 2018, '[\"https://www.youtube.com/watch?v=xWbDTXBR91I\"]', '2026-04-01 02:00:12.028', '2025-08-11 01:37:23.408', 1134, NULL, 1, 2010, 'Fundada em Curitiba em 2010, a rede Instituto dos Óculos nasceu com o objetivo de disponibilizar produtos de qualidade com preço acessível e enfoque popular. A empresa trabalha com a venda de óculos de grau, óculos solares e lentes de contato. Em 2014, foi formalizado o processo de Franquias, com o propósito de expandir a marca e angariar empreendedores que buscam negócios lucrativos e que se preocupam com a responsabilidade social. O Instituto dos Óculos se vê como sinônimo de acessibilidade e estilo de vida. Acessibilidade se dá pela democratização de óculos de qualidade a preços reduzidos. \nO estilo de vida se encontra na cultura da empresa, onde o trabalho é valorizado, mas não superestimado. A rede de franquias Instituto dos Óculos tem uma visão integral da vida, de modo que em todas as suas operações, é levado em consideração as famílias e a saúde pessoal de seus colaboradores e parceiros. Atualmente, a empresa conta com 45 unidades franqueadas e 15 unidades da família fundadora, bem como um laboratório de lentes de tecnologia Freeform alemã, além de produtos homologados e com alto controle de qualidade. Com uma marca de 13 anos de existência e uma administração de 30 anos de experiência no ramo ótico, a rede está preparada a expandir-se para todos os estados do Brasil e convida você a fazer parte dessa caminhada.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/472e41e0-2315-47a0-867c-259333c1dd60.jpg', 56, NULL, NULL, '2026-03-09 21:59:54.988', 'https://franquias.portaldofranchising.com.br/franquia-instituto-dos-oculos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '165000', NULL, NULL, NULL, '35000', '0', '4', '3', '130000', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfot50009eh0szijciqer', 'Óticas Diniz', 'oticas-diniz', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Comercio varejista', 2026, 2026, '[\"https://www.youtube.com/watch?v=T_X2cVT2ykQ\",\"https://www.youtube.com/watch?v=0uszWqykTaI\",\"https://www.youtube.com/watch?v=1POasDY67zs\",\"https://www.youtube.com/watch?v=QYtNQq5DRjc\"]', '2026-04-01 02:00:12.040', '2025-08-11 01:37:23.417', 1135, NULL, 1, 1992, 'Marca forte e consolidada, há 32 anos de tradição no mercado.', NULL, 'São Paulo', 1, NULL, 1, NULL, NULL, '2026-03-09 22:00:44.884', 'https://franquias.portaldofranchising.com.br/franquia-oticas-diniz-oculos/', 'Fixo Mensal', 'Fixo Mensal', NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '330000', NULL, NULL, NULL, '80000', NULL, '0', '0', '250000', NULL, 35);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfote000aeh0sqiujdi4j', 'COLCHÕES ORTOBOM', 'colchoes-ortobom', NULL, 'Casa e Construção', 'Móveis e Decoração', 'Comercialização de colchão e produtos para o sono', 1992, 2008, '[\"https://www.youtube.com/watch?v=Z1I08eSzV1o\"]', '2026-04-02 13:13:56.139', '2025-08-11 01:37:23.427', 1136, NULL, 1, 1969, 'Fundada há 50 anos em São Paulo, a Ortobom iniciou suas atividades no ramo metalurgico fabricando camas, mesas para televisão, etc. Com o passar dos anos, a empresa começou a comprar blocos de espuma para a confecção de colchões que, harmoniosamente, se casavam com essas camas, visando aumentar seu ramo de atividades. \nEm 1992 a Ortobom ingressou no segmento de franchising, trabalhando com a missão de oferecer o máximo de bem-estar, conforto e saúde para os clientes. Hoje, a empresa atingiu marcas impressionantes, como a de maior fabricante de colchões da América Latina e a maior franquia de colchões do mundo, com mais de 2.400 unidades no Brasil, além de lojas no Paraguai, Uruguai e Bolívia. \nMesmo com todo esse crescimento, a Ortobom investe intensamente em programas de treinamento para suas equipes e toda a rede de franquias, pois a excelência no atendimento deve ser primorosa em todos os aspectos. \nA marca está presente em todos os estados brasileiros, com mais de 2.300 unidades de franquias, além de lojas no Paraguai, Uruguai e Bolívia. Representada com 12 fábricas e seis mil pessoas envolvidas no processo de produção, comercializa mais de 200 variedades de produtos, todos submetidos a testes rigorosos que confirmam sua resistência e durabilidade.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cff4e953-b765-47aa-8792-c58ebcaee73f.jpg', 2399, NULL, NULL, '2026-03-09 22:07:49.751', 'https://franquias.portaldofranchising.com.br/franquia-colchoes-ortobom-moveis/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 1, '[\"RANKING_CATEGORIA\"]', '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfotq000beh0s81a909nw', 'Farmácia Artesanal', 'farmacia-artesanal', NULL, 'Saúde, Beleza e Bem-Estar', 'Farmácias e Manipulação', '', NULL, 2018, '[\"https://www.youtube.com/watch?v=okONt-xrUZU\",\"https://www.youtube.com/watch?v=HkcHI5gda8o\",\"https://www.youtube.com/watch?v=5AHh-owuQtI\",\"https://www.youtube.com/watch?v=VgIePNZ8k3Q\"]', '2026-04-01 02:00:12.062', '2025-08-11 01:37:23.438', 1137, NULL, 1, 1981, 'A Farmácia Artesanal foi idealizada a partir do sonho do farmacêutico e presidente do Grupo Artesanal, Evandro Tokarski, de levar saúde e bem-estar às pessoas.', NULL, 'Goiás', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/86eaa9ac-6c59-4da3-b18f-c7ee9e83c1e1.png', 91, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6fbc7be8-603c-469e-b39e-17610431435a.jpg', '2026-03-09 22:08:46.299', 'https://franquias.portaldofranchising.com.br/franquia-farmacia-artesanal-beleza/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/eea3f2e3-869d-45eb-922d-ba447933d215.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e0e2698a-9aad-4c31-b3d3-8fad7a50e71d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b36b5621-87df-4554-8f5b-7ddac657901b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8a21ddba-f168-441b-bddc-4a0bda33e25e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4c66dcd4-cd44-48f8-a995-13caa21f1313.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/38de3124-8910-42ea-8729-d96d5fcff942.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/157e3d60-9007-4e35-85cc-a2d82421c8ab.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2c078b92-8b86-4d28-b2f4-56592117c88b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a0bf7599-71f2-4bfe-ab3e-6749abd70532.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '190000', NULL, NULL, NULL, '60000', '190000', '5', '1.75', '130000', NULL, 110);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfou0000ceh0s33mv27f5', 'Óticas Carol', 'oticas-carol', NULL, 'Saúde, Beleza e Bem-Estar', 'Óticas', 'Comercio varejista', 2006, 2006, '[\"https://www.youtube.com/watch?v=41CEdCg_2uo\"]', '2026-04-01 02:00:12.072', '2025-08-11 01:37:23.448', 1138, NULL, 1, 2006, 'Com mais de 27 anos de história, a Óticas Carol é uma marca genuinamente brasileira que, hoje integrada ao Grupo EssilorLuxottica, está presente em 540 cidades do país, com mais de 1400 lojas, oferecendo um portfólio diversificado de lentes, armações e óculos de sol.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fecfee2d-4e60-4cf3-8140-2cbcb1b41a66.png', 1408, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/be2aee41-ecdc-4781-b0f8-0038d1b9cb95.jpg', '2026-03-09 22:14:31.602', 'https://franquias.portaldofranchising.com.br/franquia-oticas-carol/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3b223ce8-8345-4e6f-a08c-76ff52c7a287.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/eca1f65a-cc54-4bd0-8881-54bc939c552e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/65c163c7-f2d5-47fb-af41-0c40868eb9ea.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0b6767bb-7257-4eea-877c-83e20faa388d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/126a2bea-6bf0-40dd-a3f2-9621f5039ea2.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6e1dd084-dccf-4188-8412-c2546de79e26.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c0ae9512-387a-4638-9880-bd0c027ad780.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '310000', NULL, NULL, NULL, '50000', NULL, '2.5', '4', '180000', '80000', 35);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfoub000deh0s4m5dxhmv', 'LOVE GIFTS', 'love-gifts', NULL, 'Casa e Construção', 'Móveis e Decoração', 'LOJA DE PRESENTES CRIATIVOS, DECORAÇÃO CRIATIVA, PAPELARIA FINA E UTILIDADES', 2016, 2020, '[\"https://www.youtube.com/watch?v=msyAyUlrxSY\",\"https://www.youtube.com/watch?v=pzgB_xnFU-s\",\"https://www.youtube.com/watch?v=aw9fw7zpePY\",\"https://www.youtube.com/watch?v=VRqUXtJTzyQ\"]', '2026-04-01 02:00:12.081', '2025-08-11 01:37:23.459', 1139, NULL, 1, 2014, 'Tendo a Disney como inspiração, Fábio Farias traz um mix de itens, criatividade e alegria para presentear com afeto e significado. Uma loja com estilo próprio e oferece muitas opções de presentes e decorações criativas para diversos públicos em um só lugar. Entre papelaria,decoração,utilidades e muito mais. Focando no acompanhamento completo do franqueado onde passa por todos os treinamentos que rege a marca e um suporte para desenvolver toda a dinâmica com eficácia. Contamos com a love experience que é o nosso jeito Love Gifts de ser e enaltecer sua experiência de compra. Pra você que quer empreender em um mercado dinâmico,criativo e com uma excelente margem de lucro. Venha ser um franqueado de sucesso.', NULL, 'PARAÍBA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/21c882df-eb69-4c20-81a2-7d1b96450112.jpg', 58, NULL, NULL, '2026-03-09 22:17:47.293', 'https://franquias.portaldofranchising.com.br/franquia-love-gifts/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5f480bc6-a82b-4274-8ebd-45dbb96d68c1.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4c4c0ef7-c832-49f6-ab65-b1f92f7d674d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4143dd8b-7cbe-4931-9496-8df6c0c3a26e.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '19900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfouk000eeh0snnqqolek', 'Dryclean Usa', 'dryclean-usa', NULL, 'Limpeza e Conservação', 'Lavanderia', 'Franquia', NULL, 9, NULL, '2026-04-01 02:00:12.091', '2025-08-11 01:37:23.468', 1140, NULL, 1, NULL, 'A DRYCLEAN USA oferece uma gama de opções ao investidor, em função do potencial do mercado e de seu perfil de clientela, conforme segue:  Loja padrão A: é a lavanderia top do mercado, uma loja completa de grande capacidade, \nÉ a lavanderia ideal para mercados exigentes (capitais) e de grandes cidades, com R$ 285.000 de investimento (Taxa inicial de franquia + pacote de equipamentos) Loja padrão B: é a lavanderia top do mercado, porém sem cabideiro rotativo, de capacidade e posicionamento idêntico a loja A, com investimento de R$ 265.000 (Taxa inicial de franquia + pacote de equipamentos) Loja padrão C: é a lavanderia ideal para mercados médios, cidades de 100 a 200.000 habitantes, onde há uma demanda grande de lavagens delicadas, com investimento reduzido de R$ 225.000 (Taxa inicial de franquia + pacote de equipamentos) Loja padrão D: é a lavanderia ideal para mercados pequenos com investimento de R$ 165.000 (Taxa inicial de franquia + pacote de equipamentos)', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b3734d74-2406-4032-a460-5ad5d4b4ae9f.jpg', 199, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7b191adb-631c-4881-b36a-7b4e8c2ef748.jpg', '2026-03-09 22:18:27.120', 'https://franquias.portaldofranchising.com.br/franquia-dryclean-lavanderia/', 'Faturamento', 'Faturamento', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/73344d67-73eb-4024-8f1e-28e989798783.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/230c6de2-cd09-4fc1-b269-40134f2aa452.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b2f75f7d-4636-44c0-9e5f-15ba018f52c3.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/667c9dbe-7bb2-46e7-b21e-b2babaab2d99.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/35535ce9-15fd-4f76-be7c-c6d193f1b59e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/73e6c3e7-3285-4b88-807b-8aaea8f0309d.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '260000', NULL, NULL, NULL, '45000', '75000', '5', '2', '175000', '40000', 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfour000feh0slkhkup2b', 'Br Mania', 'br-mania', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', '', 1994, 2014, '[\"https://www.youtube.com/watch?v=Aa0Gu290vko\",\"https://www.youtube.com/watch?v=kZIvjdXZPI0\"]', '2026-04-01 02:00:12.101', '2025-08-11 01:37:23.475', 1141, NULL, 1, NULL, 'Conheça a surpreendente história dessa franquia', NULL, 'Rio de Janeiro', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/87ca1a94-a405-49f1-a7aa-c37d0b12e8be.png', 1517, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3fe736bd-8455-4359-aa7b-eb557ad0c50d.jpg', '2026-03-09 22:19:14.290', 'https://franquias.portaldofranchising.com.br/franquia-br-mania-conveniencia/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c4937892-e3f0-4556-93a9-4de39a189e93.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c86a67a1-900a-43a9-89bd-b3a6005a58d5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/17ee7ee5-1788-40ee-bff6-68fc1834d6c7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/64d0838c-7ddc-4234-b389-bc56940a91b4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/78cea911-f52e-47ba-b389-0a529da86caf.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '295000', NULL, NULL, NULL, '55000', '135000', '5', '2', '200000', '40000', 15);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfoux000geh0szsu6zjha', 'CARTÃO BE HAPPY BENEFÍCIOS', 'cartao-be-happy-beneficios', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Cartão de Multibenefícios', 2023, 2024, NULL, '2026-04-01 02:00:12.111', '2025-08-11 01:37:23.481', 1142, NULL, 1, 2023, 'Somos uma rede de benefícios e saúde com o intuito de entregar além de benefícios diversos nas maiores redes do varejo brasileiro, cuidamos da saúde das pessoas. Levamos benefícios no varejo, farmácias, lazer e muito mais. Como franquia levamos para os novos franqueados independência financeira, com gestão simples e organizada, suporte diário, receita recorrente e no desenvolvimento humano e empreendedor das pessoas. Nossos diferenciais Independência financeira; Gestão simples e eficiente; Sistema intuitivo: pensado para facilitar sua gestão; Aplicativo para seus clientes; Suporte e apoio completo para sua franquia; Receita recorrente mensal; Tenha sua própria rede de parceiros; Serviços exclusivos para seus clientes; Descontos, benefícios e vantagens em + de 100 parceiros nacionais; E muito mais!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f39d9b72-819a-4c72-ac88-49e3c8d422f4.png', 12, NULL, NULL, '2026-03-09 22:26:48.494', 'https://franquias.portaldofranchising.com.br/franquia-cartao-be-happy-beneficios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '8000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfov3000heh0swa7sylej', 'Constance', 'constance', NULL, 'Moda', 'Calçados', '', NULL, 2018, '[\"https://www.youtube.com/watch?v=8jhODy-Kde8\",\"https://www.youtube.com/watch?v=xeQvLBX1Ppk\"]', '2026-04-01 02:00:12.124', '2025-08-11 01:37:23.488', 1143, NULL, 1, NULL, 'Com um investimento total a partir de R$450 mil e R$850 mil, dependendo do modelo de loja, e retorno de faturamento entre 36 meses, os franqueadores contam com atendimento personalizado, prático e eficiente, através de canais como ligações, e-mail e Whatsapp. Além de transparência, agilidade, inovação e suporte contínuo, a Constance prioriza o reconhecimento, o desenvolvimento e o sucesso do cliente em toda a sua jornada e para isso, se transformar digitalmente e investir em pessoas, é necessário e imprescindível. A Constance é uma franquia reconhecida e premiada pelas mais importantes premiações: Melhor Franquia de Calçados do Brasil, por cinco anos consecutivos, pela revista Pequenas Empresas & Grande Negócios (PEGN), além de receber o selo de Excelência em Franchising da Associação Brasileira de Franchising (ABF).', NULL, 'Minas Gerais', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0d014925-1bed-465a-a71a-9c9e3203e60b.png', 369, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/635dcc92-0dbd-43b4-9363-d0d524373916.jpg', '2026-03-09 22:27:29.363', 'https://franquias.portaldofranchising.com.br/franquia-constance-acessorios-pessoais-e-calcados/', 'Compras', 'Compras', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/14f34824-dbe6-4d51-83bf-d8bd998a659e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1fb1d8ff-8c4f-4445-8c00-7c44aa17288f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/92787106-5efc-4dac-b9bf-d4d6741dc087.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e29e9761-2ddc-4996-8cc7-b1e5edc0a747.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4ad8c700-24cd-4eb4-83ad-745c68d718cf.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d42190fc-fba4-4c35-afa3-213ba6b7288f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3f98a98b-69fc-4ffa-980c-c114fb4ec811.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/40cd3182-e42f-4094-9fd1-0198d2e2a199.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9bd6bcdd-9ad2-4bdc-9c25-e74605a9b696.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '320000', NULL, NULL, NULL, '69000', '250000', '14', '3', '201000', '50000', 100);
