https://apifranchise.mindconsulting.com.br/uploads/franchises/2f5198ba-fb8e-43ea-a660-58d89a627202.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d88b5014-f19e-46ac-8afd-edb9236cc789.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c38905f4-57e6-4a2c-b570-be3ec6aad8ca.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ba2423f1-a240-4dce-89b8-3d2c9d0cf1d4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8581eb9a-10a0-491e-888e-c4a3353e6d0a.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '90000', NULL, NULL, NULL, '30000', NULL, '5', '1', '30000', '30000', 0);
