INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfoyy0013eh0st1a1xyxn', 'Dr. Exame', 'dr-exame', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'Comercio varejista', NULL, NULL, NULL, '2026-04-01 02:00:12.343', '2025-08-11 01:37:23.627', 1165, NULL, 1, 2017, 'O DR.EXAME nasceu de uma startup criada em 2017 a fim de proporcionar à população brasileira o acesso à saúde com valores reduzidos. \nAtuamos no seguimento de agendamento de CONSULTAS e EXAMES, com atendimento em uma ampla rede de clinicas e laboratórios particulares espalhados por todo Brasil. \nO nosso foco e oportunidade está na grande massa da população que não possui plano particular de saúde ou que estão esperando a muito tempo pelo atendimento do setor público, o que atualmente representa mais de 75% do mercado brasileiro. \nFaça parte desta história de sucesso!', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/81d91b76-5fc5-46f4-acdb-21b6dee6c9bd.jpg', 78, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8a48de32-bdd1-44f8-8053-0e6da3c14e39.jpg', '2026-03-10 00:09:59.132', 'https://franquias.portaldofranchising.com.br/franquia-dr-exame/', NULL, 'Fat. Total', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e429f6d7-a059-40b7-9ec3-5eb75fd1f9ee.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '134000', NULL, NULL, NULL, '59000', '100000', '5', '0', '25000', '50000', 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfoz50014eh0s5tn6qavg', 'LEBRIJU', 'lebriju', NULL, 'Moda', 'ACESSÓRIOS PESSOAIS', 'Venda de bijuterias, semi joias e acessórios de moda femininos', 2021, 2021, '[\"https://www.youtube.com/watch?v=OnJ0u9TI2Fk\"]', '2026-04-01 02:00:12.353', '2025-08-11 01:37:23.633', 1166, NULL, 1, 2016, 'Somos a mais completa rede de franquias de acessórios, voltada para o público feminino, com peças como: bijuterias, semijoiais, prata, lenços, bolsa, chapéu, prata, aço inoxidável, que unem design, elegância, qualidade. Negócio escalável. Fature mais de 1 milhão por ano! Todo mundo compra acessórios de moda! DIFERENCIAIS DA LEBRIJU: PRODUTO E QUALIDADE: Os produtos Lebriju são cuidadosamente escolhidos pelo nosso setor de CURADORIA E TENDÊNCIA DE MODA um amplo portifólio, com qualidade e variedade que surpreende, agrada e fideliza nossos clientes. Nosso objetivo é de promover o sucesso da marca e de nossas unidades franqueadas. FACILIDADE DE ABASTECIMENTO: A Lebriju adota uma estratégia de abastecimento semanal para suas unidades em todo o Brasil, com cerca de 200 novos modelos lançados todo mês, garantindo que as clientes encontrem novidades nas lojas toda semana. ARQUITETURA: A arquitetura de nossas lojas e quiosques, além de muito bonita é fundada no bem-estar, acolhimento, modernidade e, acima de tudo, funcionalidade. A cliente tem uma experiência de compra positiva, dentro de um ambiente lindo, acolhedor e fluido. MODELOS DE NEGÓCIOS LEBRIJU: Com investimento completo a partir de R$ 170 mil que incluí: mobiliário, estoque inicial, projeto arquitetônico e taxa de franquia, você pode ter um quiosque no Shopping da sua cidade. Ou, com investimento a partir de R$ 390 mil, uma loja em Shopping Center com mix completo e excelente rentabilidade. Fature mais de 1 milhão ao ano!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d1ab5f67-aa59-4c2d-83bf-b788a512b097.png', 7, NULL, NULL, '2026-02-04 10:17:23.000', 'https://franquias.portaldofranchising.com.br/franquia-lebriju-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '170000', NULL, NULL, NULL, '50000', '0', '4', '2', '280000', '60000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfozb0015eh0s4gmb8f8b', 'VIA CERTA EDUCAÇAO PROFISSIONAL', 'via-certa-educacao-profissional', NULL, 'Educação', 'Ensino e Formação Acadêmica', 'Escola de Cursos Profissionalizantes e Idiomas.', 2014, 2019, '[\"https://www.youtube.com/watch?v=H6CdCLKdmCM\",\"https://www.youtube.com/watch?v=bvSvz_mktzU\",\"https://www.youtube.com/watch?v=PjYgrN9FfWQ\",\"https://www.youtube.com/watch?v=UKIjJfnWDVI\"]', '2026-04-01 02:00:12.363', '2025-08-11 01:37:23.639', 1167, NULL, 1, 2012, 'Através da união de três sócios, com mais de 20 anos de experiência no ramo de educação profissionalizante, em maio de 2012 nascia, em Birigui /SP, a rede de ensino profissionalizante Via Certa. A partir de uma única escola, a Via Certa surgiu com o objetivo de levar conhecimento para todas as pessoas que buscam crescer profissionalmente e atualizar seus conhecimentos. O sucesso do método Via Certa gerou um avanço vertiginoso, ampliando a escola para uma rede de franquias presente em diversas cidades do Brasil, oferecendo mais de 30 opções de cursos nas áreas de Administração e Negócios, Indústria e Energia, Informática, Inglês, Preparatório, Saúde, Beleza e Estética. Com uma metodologia totalmente diferenciada, a Via Certa conta com cursos que acompanham as características particulares de cada aluno, preparando-o para aproveitar totalmente o seu aprendizado através de um ensino individualizado, no ritmo de cada aluno, trazendo assim uma aprovação de 95% dos alunos. Atualmente, metade das vagas disponíveis no mercado de trabalho não são preenchidas, pois os candidatos não possuem os pré-requisitos mínimos necessários exigidos pelas empresas. Os cursos da Via Certa entram para suprir esses pré-requisitos exigidos pelo mercado de trabalho, tornando os alunos aptos a ingressarem em um novo emprego ou ainda na promoção de sua carreira. Desenvolvida no modelo de franquia, a Via Certa Educação Profissional representa uma excelente oportunidade para aqueles que querem investir em um novo negócio na área da Educação Profissionalizante. Oferecemos ao empreendedor todo o apoio necessário para seu desenvolvimento, como suporte no setor de recursos humanos, comercial, financeiro e Marketing. O Grupo Via Certa investe constantemente na formação de seus franqueados, professores e demais colaboradores, por meio de treinamentos específicos, para que eles possam entregar o que há de melhor ao aluno, garantindo seu sucesso no mercado de trabalho.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c2782501-8fa8-48df-baf7-e3b398699bf2.jpg', 61, NULL, NULL, '2026-03-10 00:12:36.224', 'https://franquias.portaldofranchising.com.br/franquia-via-certa-educacao-profissional/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '120000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfozh0016eh0smaw9vjx6', 'Sóbrancelhas', 'sobrancelhas', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'Comercio varejista', 2013, 2017, '[\"https://www.youtube.com/watch?v=X045S4zT6K4\",\"https://www.youtube.com/watch?v=JYgHjpyxVrA\",\"https://www.youtube.com/watch?v=Dp1jxS8-kEA\",\"https://www.youtube.com/watch?v=yQ3zXqkgkAQ\"]', '2026-04-01 02:00:12.372', '2025-08-11 01:37:23.645', 1168, NULL, 1, 2013, 'A Sóbrancelhas é uma empresa especializada no embelezamento do olhar e da face. Fundada pela empresária Luzia Costa, com mais de 20 anos de experiência no mercado de empreendedorismo e estética, desenvolveu uma visão empreendedora e percebeu a necessidade do mercado no setor beleza, voltado para o serviço personalizado para sobrancelhas.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/98787a09-44fe-47f3-a0b3-3563cf302276.png', 135, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/74dc96fb-f4d7-4013-abbe-15559b4ac684.jpg', '2026-03-10 00:13:42.719', 'https://franquias.portaldofranchising.com.br/franquia-sobrancelhas-estetica/', 'Fixo Mensal', 'Fat. Total', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3c7c36b1-b72a-4f26-9962-107f4862b6ef.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/be2da0fc-8b20-4cda-98e0-17736a94b609.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/621d2b94-5a26-4ed0-9052-d8fd3e1dd86b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6589bb77-145a-40fc-a783-57f1f0ffe5ec.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/947c16c4-a503-4c5b-b768-8b6e28a082c1.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b20ee8cd-adb6-443c-9f08-8732c50e6142.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5e3066b1-8e08-486a-86c6-3f028d307bb7.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '193662', NULL, NULL, NULL, '45000', '67795', '0', '0', '118662', '30000', 25);
