,\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4745c9a7-7852-456b-8f0c-3e3613732df8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/fa1cf9c0-328f-40bf-aa09-3b781de5e302.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8c57f64c-a711-444d-994a-6f35459806be.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/64af6dc1-5133-4cc0-9a8c-cd88362ec581.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2e9770c9-7f87-44cc-b3f2-27ef9c594a60.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5fc86c4c-7ae4-4b7a-91ca-705732fe5de3.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b08112a0-88e9-4e13-b793-7e64d4197d35.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp0b001beh0s0tzggbnr', 'DEKRA', 'dekra', NULL, 'Serviços Automotivos', 'Locação de veículos', 'VISTORIAS PARA SEGURO, VISTORIA CAUTELAR DE AVALIAÇÃO E TRANSFERÊNCIA EM AUTOS', 1996, 1998, '[\"https://www.youtube.com/watch?v=DtZ3HI0LNFM\"]', '2026-04-01 02:00:12.418', '2025-08-11 01:37:23.676', 1173, NULL, 1, 1986, 'Torne-se um Franqueado DEKRA e Invista em um Negócio Sólido e Lucrativo! Construir um negócio próprio é mais do que empreender. É transformar sonhos em realidade, ter um propósito profissional e fazer parte de algo maior. A DEKRA, multinacional alemã com 100 anos de história, é líder global em vistorias veiculares e referência no setor. Como a primeira e maior rede de franquias do segmento no Brasil, acumulamos mais de 25 anos de experiência no franchising, oferecendo um modelo de negócio sólido, estruturado e consolidado. Nosso propósito vai além dos negócios. Nossa visão é clara: ser o parceiro global para um mundo mais seguro e sustentável. Como franqueado DEKRA, você se une a uma marca que valoriza inovação, excelência e credibilidade, entregando um serviço essencial para milhões de pessoas e contribuindo para a segurança no mercado automotivo. Se você busca um negócio estruturado, um mercado em crescimento e o suporte de uma marca reconhecida mundialmente, esta é a sua oportunidade. Acima de 80 unidades e mais de 200 postos credenciados no Brasil Marca global presente em 60 países Retorno do investimento em média de 24 a 26 meses Taxa de Franquia a partir de R$ 65.000 Agora é sua chance de fazer parte dessa história de sucesso!    Modelos de Negócio Flexíveis para Diferentes Mercados Sabemos que cada região tem suas particularidades. Por isso, a DEKRA oferece modelos de franquia flexíveis, adaptáveis a diferentes demandas e perfis de mercado: Mercado P – Ideal para cidades menores, com menor fluxo de vistorias. Mercado M – Perfeito para regiões de médio porte, com demanda crescente. Mercado G – Modelo robusto, para grandes cidades e alto volume de vistorias. Independente do porte da sua cidade, a DEKRA tem um modelo ideal para você!   Um Negócio Seguro e Rentável O setor de vistorias veiculares está em plena expansão. Com o aumento da venda de veículos seminovos e usados, cresce também a necessidade de laudos confiáveis e empresas de referência no mercado. A DEKRA se destaca por oferecer um modelo estruturado, processos padronizados e a credibilidade de uma multinacional. Como franqueado, você terá um negócio consolidado, escalável e lucrativo, em um setor que zela pela qualidade dos serviços. Invista em um negócio de alto valor agregado e crescimento contínuo!   Modelo de Negócio Estruturado Sabemos que previsibilidade e segurança financeira são essenciais ao investir em um novo negócio. Por isso, oferecemos um modelo de franquia transparente e acessível: Taxa de Franquia: A partir de R$ 65.000 Taxa de Royalties: variável conforme o volume de produção, pensamos no desenvolvimento de nossos franqueados Taxa de Publicidade: Não há Capital de Giro: Variável, conforme operação e região Retorno do Investimento: Em média, 24 a 26 meses Área Média da Unidade: 375 m² Com um modelo de operação simplificado e suporte completo, você terá todo o respaldo necessário para crescer.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9acc425f-7496-4534-86bc-fdd9235d0fa0.png', 81, NULL, NULL, '2026-03-10 00:41:45.576', 'https://franquias.portaldofranchising.com.br/franquia-dekra/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cf6fe5ad-9922-40a5-aec7-78affbf06d07.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '135000', NULL, NULL, NULL, '65000', NULL, '9', '0', '70000', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp0i001ceh0sz1bswi0x', 'REDE CARTÓRIO FÁCIL', 'rede-cartorio-facil', NULL, 'Serviços e Outros Negócios', 'SERVIÇOS ADMINISTRATIVOS', 'Trabalhamos com arbitragem e mediação e assessoria, trazendo soluções na prestação de serviços Cartorários e de outros Registros Públicos, bem como na Pesquisa de Bens Patrimoniais, etc', 2014, 2015, '[\"https://www.youtube.com/watch?v=zkwactpKwCM\"]', '2026-04-01 02:00:12.427', '2025-08-11 01:37:23.682', 1174, NULL, 1, 2013, 'A RCFÁCIL É UMA EMPRESA DE FRANCHISING COM SEDE EM GOIÂNIA Especializada na gestão e intermediação de documentos e serviços. Nosso propósito é simplificar o acesso e a entrega de documentos em órgãos públicos em todo o território nacional. Oferecemos uma ampla gama de soluções, incluindo Intermediação Cartorária em âmbito nacional e internacional, além de serviços de crédito, seguros e certificação digital. Graças a sua abrangência e excelência, a RCFácil tornou-se referência como a franquia de serviços mais completa do Brasil.', NULL, 'GOIÁS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d7d26d9c-7d35-4bfd-9664-3117e0efc4bb.png', 36, NULL, NULL, '2025-09-04 09:58:18.000', 'https://franquias.portaldofranchising.com.br/franquia-rede-cartorio-facil/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp0o001deh0s39dkzyrs', 'Fini', 'fini', NULL, 'Alimentos', 'Doces', 'Comercio varejista', 2020, 2020, NULL, '2026-04-01 02:00:12.437', '2025-08-11 01:37:23.688', 1175, NULL, 1, 1970, 'De origem espanhola, desde a década de 70 a Fini faz parte do Grupo Sánchez Cano. \nCom presença mundial em mais de cem países, a empresa conquistou a posição de uma das principais produtoras mundiais de balas de gelatina, marshmallows, regalizes e chicles. \nNo Brasil, a Fini lançou a Linha Bem-Estar, balas enriquecidas com ativos funcionais como cálcio, colágeno, fibras e vitaminas. \nCom um DNA que busca surpreender seus consumidores, teve origem artesanal e hoje está presente no varejo, em franquias, e-commerce, cinemas e parques de todo o País.', NULL, NULL, 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/eb2e6cdf-6058-40cb-a972-ffe5c2e99f00.jpg', 420, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ce2fee2a-bb70-477a-b7d2-fa98f4cddc7f.png', '2026-03-10 00:43:22.734', 'https://franquias.portaldofranchising.com.br/franquia-fini-doces/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0299e1a3-b25a-4213-a550-80b28eae271e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1f4089c2-c6b5-4e58-8bff-5b9b2e7ca7e2.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/938d3558-300e-49b5-883e-1110ea0a5727.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d0bfc931-634a-4e76-b6ce-e4d7a0848882.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp0w001eeh0smrd6wqnb', 'PRUDENTIAL', 'prudential', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Seguros de Vida Individual', 2004, 2021, '[\"https://www.youtube.com/watch?v=oOzLWUJ34qU\"]', '2026-04-01 02:00:12.447', '2025-08-11 01:37:23.696', 1176, NULL, 1, 1998, 'A Prudential do Brasil é uma subsidiária da Prudential Financial, Inc, uma das maiores e mais antigas instituições financeiras do mundo.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b0ff9140-1117-49e4-b400-d31ba04bceeb.jpg', 2310, NULL, NULL, '2026-03-10 00:46:55.653', 'https://franquias.portaldofranchising.com.br/franquia-prudential/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '48000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp14001feh0swydlfb9f', 'KOOKABU', 'kookabu', NULL, 'Moda', 'Vestuários', 'A Kookabu é uma rede de moda bebê e infantil do grupo Brascol, que oferece aos seus franqueados um modelo de negócio no qual ele contará com toda estrutura e irá operar com mais de 1,5 milhão de peças', 2022, 2022, '[\"https://www.youtube.com/watch?v=t5KF3FOJrd8\",\"https://www.youtube.com/watch?v=4q68ZBJ100U\"]', '2026-04-01 02:00:12.456', '2025-08-11 01:37:23.704', 1177, NULL, 1, 2021, 'Na Kookabu, nosso propósito é vestir a infância com amor e qualidade, de forma democrática.  Com custo-benefício e uma ampla variedade de opções, a Kookabu, torna a moda infantil acessível a todas as famílias. Nossa missão é ser a escolha confiável para mamães e papais que buscam roupas duráveis, cheias de personalidade e que não pesem no orçamento. Acreditamos que toda criança merece se sentir especial, e estamos aqui para fazer isso acontecer! A marca foi desenvolvida pelo Grupo Brascol, que conta com mais de 35 anos de experiência, sendo o maior distribuidor do segmento bebê e infantojuvenil do Brasil. Tenha à disposição as melhores indústrias do Brasil e amplie a variedade de opções para compor o mix ideal para a sua loja. Componha seu mix de produto de forma mais aderente às peculiaridades da sua região, considerando costumes, clima, e poder aquisitivo. Tenha à sua disposição todo o estoque do Brascol e reponha produtos de forma prática e ágil, minimizando significativamente os riscos que o franqueado assumiria em um modelo de franquia tradicional.  Ganhe mais assertividade nas compras: menor índice de liquidação, com um melhor resultado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/77644ca4-0dac-49ed-a9b4-748ffc630b46.jpg', 8, NULL, NULL, '2026-03-10 00:51:53.374', 'https://franquias.portaldofranchising.com.br/franquia-kookabu/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '199990', NULL, NULL, NULL, '50000', NULL, '0', '0', '85000', '64990', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp1d001geh0sz8s5pmoo', 'Multicoisas', 'multicoisas', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', 'Comercio varejista', 2004, 2004, NULL, '2026-04-01 02:00:12.466', '2025-08-11 01:37:23.713', 1178, NULL, 1, 1984, 'A Multicoisas, fundada em 1984 por Lindolfo Martin e Elza Martin em Campo Grande - MS, é uma rede de franquias com um conceito inovador, reconhecida por sua especialização em soluções para o cotidiano das pessoas.', NULL, 'Mato Grosso do Sul', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2364027a-583e-456b-909e-21073ad94e50.jpg', 177, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/972e1466-88a1-4d0e-bee1-45af3b76ada0.jpg', '2026-03-10 00:52:39.385', 'https://franquias.portaldofranchising.com.br/franquia-multicoisas/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e792efee-84f7-4dea-afd0-e249e1156001.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5ee41244-0286-414b-97ba-79873f1b7b2b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b757f2a8-531a-45ad-8f0f-777cb177fdb8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b65a17ac-0f28-46a2-85d8-b423d828f7c2.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4ff6c28b-8748-468d-a3c2-86e29223b255.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/78654ebc-4865-4df6-8b6d-3d24ed28037e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3b8fbd17-3756-4aa5-8e1e-f4b164231c2b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/fdb6bbfd-27f5-4c79-b5a8-f4c4e006e06a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6369c6e5-6700-4c69-8caa-fc46b427368d.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '350000', NULL, NULL, NULL, '75000', NULL, '5', '1', '255000', '20000', 45);
