INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp2c001keh0sy0n1ba9q', 'China In Box', 'china-in-box', NULL, 'Serviços e Outros Negócios', 'Consultorias e Serviços Empresariais', 'Comercio varejista', 2021, 2025, '[\"https://www.youtube.com/watch?v=dj5L9oRTwUY\",\"https://www.youtube.com/watch?v=DxDqKd6wBhI\",\"https://www.youtube.com/watch?v=DVPCOJs-jlI\",\"https://www.youtube.com/watch?v=pkjezJLuxSo\"]', '2026-04-01 02:00:12.506', '2025-08-11 01:37:23.748', 1182, NULL, 1, 1992, 'Por mais de três décadas, o China In Box revolucionou o mercado brasileiro ao oferecer comida chinesa de qualidade através de um serviço de delivery exemplar.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3fae9a8f-4127-4139-ab05-b593b8172643.png', 142, NULL, NULL, '2026-03-10 01:14:51.487', 'https://franquias.portaldofranchising.com.br/franquia-china-in-box-alimentacao/', 'Fat. Líq.', 'Fat. Líq.', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/36386357-b959-46d0-aa97-b4860e0d5de7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a79bfdcb-48ed-4d67-8e06-5747d9252dce.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f3748612-ad62-40d5-a7c5-16fffa48d480.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/52c8faca-773f-445d-a047-c80a5ed7fc73.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f0cf2bb1-feeb-4d5e-b522-cc010dfd1f6c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/698f8f1f-849a-4462-9333-a7e022e76a03.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d0d3c91d-337a-4e2f-b38a-045fdcdadff1.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6faefb1b-40bc-4091-92e8-26d96291844c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/41227b8a-a251-4982-9daa-8f4f779053e9.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '600000', NULL, NULL, NULL, '80000', '250000', '6', '3.5', '400000', '120000', 80);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp2i001leh0sbm0xit5j', 'PLENA FACE', 'plena-face', NULL, 'Saúde, Beleza e Bem-Estar', 'Cosméticos e Perfumarias', 'A Plena Face é uma rede de franquias especializada em Estética Facial, focada na democratização da beleza, com uma equipe de profissionais altamente qualificados, especializados em Harmonização.', 2022, 2022, '[\"https://www.youtube.com/watch?v=WE6t5KKEaag\",\"https://www.youtube.com/watch?v=vLn-us4y7Ho\",\"https://www.youtube.com/watch?v=DWUlg2kBvak\",\"https://www.youtube.com/watch?v=JJihhLCmYD8\"]', '2026-04-01 02:00:12.516', '2025-08-11 01:37:23.754', 1183, NULL, 1, 2019, 'A Plena Face foi lançada em 2021 com o intuito de valorizar a beleza natural de cada indivíduo através de técnicas de harmonização facial e corporal. Não somos apenas \"mais uma\" rede de harmonização. Nosso foco é realçar a naturalidade e as marcas que a experiência de vida traz para cada pessoa. NOSSA HISTÓRIA A Plena Face nasceu do sonho de Thais, que sempre foi apaixonada pelo mercado de beleza desde que entrou para este mercado, quando começou como trainee na Natura em 2004. Acreditamos na valorização do “eu” de cada indivíduo e sabemos da importância do respeito às suas raízes, opiniões, individualidades e traços. Em 2010, decidida a empreender no ramo da beleza, Thais deixou seu emprego e, junto com seu sócio Vinícius, iniciou a master franquia na área de depilação. A combinação de suas experiências em franquias e no ramo da estética resultou na criação da Plena Face. Nossa clínica traz um ambiente aconchegante e inclusivo, sem a ostentação comum em muitas clínicas, para que pessoas de todas as classes sociais, gêneros e etnias se sintam representadas, especialmente a idade mais madura, conhecida como idade prateada. Nosso maior desejo é compartilhar esse conhecimento de 20 anos de história e pioneirismo com o mundo e transformar a vida de empreendedoras e empreendedores que sonham em ter seu próprio negócio. Cada detalhe do nosso ambiente foi pensado para despertar os 5 sentidos dos clientes, proporcionando uma experiência completa com sons, aromas e produtos exclusivos. A Plena Face oferece um mix de serviços completo, aliado às tecnologias mais inovadoras do mercado. São mais de 20 tipos de procedimentos estéticos minimamente invasivos a preços acessíveis, com condições de pagamento facilitadas, incluindo toxina botulínica, bioestimuladores e preenchedores. Além disso, agregamos equipamentos inovadores como Lavieen e Ultraformer III. Estamos em constante busca das inovações e tendências do mercado. Trabalhamos com os melhores fornecedores homologados, nacionais e internacionais, garantindo a qualidade e rastreabilidade de todos os produtos aplicados em nossos clientes. Essa abordagem, aliada ao poder de negociação com fornecedores, resulta em preços competitivos para os clientes e margens atrativas para os franqueados. O modelo de negócio da Plena Face é robusto e rentável, com baixo custo operacional e uma ampla variedade de procedimentos. Nossa equipe especializada oferece suporte integral aos franqueados, desde o atendimento e vendas até a gestão de pessoas e redes sociais.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c809d2f9-6771-48d6-85ac-b0d0061e2620.jpg', 5, NULL, NULL, '2026-03-10 01:21:25.153', 'https://franquias.portaldofranchising.com.br/franquia-plena-face/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
