nchises/43b48cbf-46a0-41b4-9368-10af49a68e03.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/33249bb0-a972-4208-88f6-ae77272ae18a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f8335547-1115-4379-a9c2-aa4766333631.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ac85ac70-67cf-4fcd-800b-304ff6ca612e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8d59c2b9-f484-43a4-834b-66cdaad4f608.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d8c283df-0144-4011-a906-8cb0b11a46d7.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '145000', NULL, NULL, NULL, '25000', NULL, '0', '0.05', '120000', NULL, 60);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp4j001xeh0sipaj7let', 'Sofá Novo De Novo', 'sofa-novo-de-novo', NULL, 'Serviços e Outros Negócios', 'Negócios Especializados', '', 2019, 2025, '[\"https://www.youtube.com/watch?v=64w86L5NG5U\",\"https://www.youtube.com/watch?v=61brgRTP9bU\",\"https://www.youtube.com/watch?v=pwQmzzvZTEc\",\"https://www.youtube.com/watch?v=hNHW5s0e0cU\",\"https://www.youtube.com/watch?v=Rb-OU4JQ2IA\"]', '2026-04-01 02:00:12.632', '2025-08-11 01:37:23.828', 1195, NULL, 1, 2019, 'A maior rede de Higienização e blindagem de estofados do Brasil! \nCom quase 200 unidades já confirmadas no Brasil, a Sofá Novo de Novo uma rede de franquias que chegou ao mercado em 2019 e em menos de um ano se destacou por trazer um conceito muito consolidado em grandes capitais no Brasil: Home based. \nDe lá pra cá, tem se expandido e se tornou uma das maiores redes de higienização e blindagem conhecida em todo país. \nAlém disso, trabalhamos com produtos exclusivos e de altíssima qualidade, não inflamáveis e biodegradáveis, de nanotecnologia de alta secagem, e todos homologados pela ANVISA, maquinário de fabricação italiana de alta resistência. \nDentro de todo esse cenário, a Sofá Novo de Novo se destaca pelo seu baixo valor de investimento inicial, alta rentabilidade, sem espaço físico, número reduzido de funcionários e\nainda todo o suporte oferecido pela rede franqueadora. \nEssas características a tornam uma excelente oportunidade de negócio para quem busca um investimento seguro. \nA Sofá Novo de Novo está no centro de inúmeras tendências: franquia, modelo de negócio home based, e uso da tecnologia no atendimento. \nPor isso, a tendência é que a marca continue a trilhar caminhos promissores rumo ao sucesso absoluto. \nJá somos quase 200 unidades confirmadas no Brasil e continuamos crescendo de forma acelerada.  Esperamos seu contato!', NULL, NULL, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fc01a940-68b8-4c77-ba75-0cdc1a32a135.jpg', 144, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4db5d673-a9a7-49a3-8b68-29385a927902.jpg', '2026-03-10 02:20:44.403', 'https://franquias.portaldofranchising.com.br/franquia-sofa-novo-de-novo/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/dc5e1850-9deb-4e48-88a5-7843c451e9a8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e799eabd-f003-4f04-8195-b18c6e262832.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/baf43324-d236-42f5-b319-475cb17862b4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4324661f-d06b-490f-be6c-55d976260e16.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/562d256d-affd-49fc-9470-b91f361f3f04.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ccda7944-938e-4e22-8820-5b54ac529fa9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c003dcd9-3561-4d21-827d-74fef9111ff5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4090a796-a7ae-4ae5-acd2-8d990ad6ab26.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/37f02513-470c-4bda-90b8-51d0597d12d8.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
