INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp4v001zeh0s96onc1ob', 'NOVOFIO TRATAMENTOS CAPILARES', 'novofio-tratamentos-capilares', NULL, 'Saúde, Beleza e Bem-Estar', 'Serviços Médicos e Clínicas', 'CLÍNICAS DE TERAPIAS E TRANSPLANTES CAPILARES.', 2021, 2022, '[\"https://www.youtube.com/watch?v=4riPm5iht1o\",\"https://www.youtube.com/watch?v=DUNrxHqifV4\",\"https://www.youtube.com/watch?v=b8PQMDIH614\"]', '2026-04-01 02:00:12.652', '2025-08-11 01:37:23.840', 1197, NULL, 1, 2021, 'A Novofio nasceu da união de três grandes nomes do mercado: Dr. Marcos Kawasaki, referência em transplantes e tratamentos capilares. José Carlos Semenzato, investidor e especialista em franchising. Paulo Morais, cofundador da Espaçolaser, a maior rede de depilação do mundo. Com expertise médica, visão estratégica e know-how em franquias, a Novofio surge como a principal rede especializada em transplantes capilares e terapias inovadoras. Oportunidade de Mercado 42 milhões de brasileiros sofrem com calvície. 75% dos homens relatam perda de confiança devido à queda de cabelo. 1 a cada 2 homens até 50 anos apresenta alopecia. O termo \"transplante capilar\" é um dos mais buscados no Google. O setor cresce 4,5% ao ano, garantindo uma demanda constante. Seja pioneiro neste mercado promissor, oferecendo soluções inovadoras para um público altamente engajado!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1e14ccf3-1606-4bf0-84b7-da767b359a55.svg', 39, NULL, NULL, '2026-03-10 02:29:57.588', 'https://franquias.portaldofranchising.com.br/franquia-novofio-tratamentos-capilares/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '320000', NULL, NULL, NULL, '100000', NULL, '10', '2', '150000', '70000', 0);
