INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp6m0028eh0swy90law9', 'Spoleto', 'spoleto', NULL, 'Alimentação', 'Mercados e Distribuição', 'Comercio varejista', 2025, 2025, '[\"https://www.youtube.com/watch?v=LBmCEK_9gks\",\"https://www.youtube.com/watch?v=_NHv-Xb0GKQ\",\"https://www.youtube.com/watch?v=Ad0SwXhCYYY\",\"https://www.youtube.com/watch?v=DVPCOJs-jlI\"]', '2026-04-01 02:00:12.745', '2025-08-11 01:37:23.902', 1206, NULL, 1, 1992, 'O Spoleto é a maior rede de culinária italiana do Brasil, com mais de 350 restaurantes espalhados por 130 cidades e 25 estados. Desde sua fundação em 1992, a marca tem sido sinônimo de inovação no setor de alimentação, oferecendo uma experiência única aos seus clientes. Com um conceito moderno e tecnologia de ponta, o Spoleto permite que cada pessoa viva sua própria jornada gastronômica, criando pratos personalizados com ingredientes frescos e de qualidade.', NULL, 'Rio de Janeiro', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/9cdce604-f658-4360-b540-4fbed48b759c.jpg', 385, NULL, NULL, '2026-03-10 03:21:33.964', 'https://franquias.portaldofranchising.com.br/franquia-spoleto-alimentacao/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apif