INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp7w002feh0svp4rvvmr', 'TRANS OBRA', 'trans-obra', NULL, 'Casa e Construção', 'CONSTRUÇÃO', 'Locação de máquinas e equipamentos de pequeno porte para a construção civil, limpeza e jardinagem.', 2023, 2023, '[\"https://www.youtube.com/watch?v=fMXnOY_QXrE\",\"https://www.youtube.com/watch?v=RiqfJqnQ6-I\"]', '2026-04-01 02:00:12.827', '2025-08-11 01:37:23.948', 1213, NULL, 1, 2000, 'Por que a TRANS OBRA? Modelo 100% estruturado – Comece com tudo pronto! Processos otimizados, fornecedores homologados e uma operação enxuta. Suporte total – Não jogamos você na fogueira! Acompanhamos sua jornada para garantir que sua franquia cresça rápido. Alta demanda – A construção civil não para. E seus lucros também não! 38 unidades de sucesso – 21 próprias, 17 franquias e uma metodologia que funciona. Você + TRANS OBRA = SUCESSO Aqui, não tem achismo. O que oferecemos é um negócio formatado, validado e lucrativo. Sua dedicação + nosso know-how = sua franquia se tornando referência na sua região. Se você quer uma oportunidade real de crescimento e uma marca reconhecida nacionalmente ao seu lado, a hora é agora!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5d0786b4-cf45-4282-948f-693b6b84d63a.jpg', 31, NULL, NULL, '2026-02-06 00:00:58.000', 'https://franquias.portaldofranchising.com.br/franquia-trans-obra/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '380000', NULL, NULL, NULL, '50000', NULL, '6', '2', '310000', '20000', 0);
