INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp8f002ieh0s6x3zwpgt', 'Vazoli', 'vazoli', NULL, '', '', '', 2011, 2025, '[\"https://www.youtube.com/watch?v=Ge3Uhh6cxhU\",\"https://www.youtube.com/watch?v=Ju-HycCcnqM\",\"https://www.youtube.com/watch?v=CHNGbjwh2zk\"]', '2026-04-01 02:00:12.856', '2025-08-11 01:37:23.968', 1216, NULL, 1, 2008, 'Vazoli Franchising entra no mercado de franquias com projeto de expansão avançado Encontrar e repassar aos clientes as melhores taxas do mercado e oferecer sempre o produto mais adequado para atender as necessidades de cada um. Com essa premissa, a Vazoli se consolidou no mercado como uma das principais redes de serviços financeiros do País. Com seriedade, profissionalismo e estreito relacionamento com os principais bancos de crédito do Brasil, a Vazoli, nascida em Severínia, interior do Estado de São Paulo, atua no setor desde 2008 e em 2011, já com 10 unidades e com o processo de expansão acelerado, iniciou suas operações franqueadas. Em pouco mais de um ano, já possui mais de 40 unidades franqueadas em funcionamento e em fase de implantação. Segundo a Austin Rating, o setor de crédito no Brasil só tende a crescer. Com o cenário positivo, o setor de crédito tem sido um dos melhores investimentos do mercado de franquias. A venda de produtos como empréstimos, seguros e investimentos via terceiros (correspondentes bancários) está em alta e a estrutura oferecida pela rede de franquia garante as melhores negociações. A rede Vazoli oferece crédito pessoal, crédito consignado para aposentados e pensionistas do INSS, crédito consignado para servidores públicos, crédito imobiliário - financiamento e refinanciamento e compra de dívidas de outros bancos e cartões (consignados). A franquia Vazoli é considerada um negócio seguro e com rentabilidade rápida, uma vez que seu investimento inicial é baixo. \"Garantimos ao franqueado todo suporte técnico com treinamentos teóricos e práticos e materiais próprios que vão ajudar a administrar o negócio da melhor maneira para o sucesso imediato da unidade\", explica Eric Vaz de Lima, diretor da rede. Com um crescimento contínuo, a franquia vem se consolidando como uma das principais e mais competentes redes de serviços financeiros do mercado. Por meio de parcerias estratégicas, a Vazoli está sempre atenta ao que há de melhor em produtos financeiros assegurando maior rentabilidade para que seus franqueados se tornem empresários bem sucedidos e cresçam com a rede Vazoli.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0be10e48-3894-4f39-aaef-b7dcde1e3fe7.jpg', 87, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/eeb8a0a9-4d79-4b0c-bd74-cbc7ddf7fc84.jpg', '2025-10-31 15:41:37.000', 'https://franquias.portaldofranchising.com.br/franquia-vazoli-negocios/', '1/3 do Salário Mínimo Vigente', 'Faturamento', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/61b6fd75-1186-4f2f-834a-be420e4117b9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5f4909a7-3524-4ea7-97bf-f1d7502f3e49.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/71342ee5-6eea-4b27-b6d2-e9572b235afc.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7dd52916-5f71-46a8-be64-9151cd196826.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2da668f7-cf00-4920-81be-a80fed7bc3d9.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '24900', NULL, NULL, NULL, '24500', NULL, '1', '33.34', '150', '250', 25);
