INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp8r002keh0sgv2morjx', 'PIZZA CREK', 'pizza-crek', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'Pizza Crek, reinventou a Pizza. Pizzas Individuais enroladas. Cada \"pedaço\" um sabor. Baixo investimento e retorno rápido.', 2016, 2018, '[\"https://www.youtube.com/watch?v=fuAz4ThjBVU\",\"https://www.youtube.com/watch?v=81Y7Lc4kWjQ\",\"https://www.youtube.com/watch?v=04pC5XPB5kI\",\"https://www.youtube.com/watch?v=BVsXoFTsoJQ\"]', '2026-04-01 02:00:12.876', '2025-08-11 01:37:23.979', 1218, NULL, 1, 2013, 'Inovação e Excelência na Arte Fazer Pizza. A Pizza Crek revolucionou o mercado gastronômico brasileiro ao criar um conceito único de pizzas individuais, combinando praticidade, sabor e personalização em cada produto. Com uma trajetória inspiradora que começou na periferia de São Paulo, a marca hoje é referência nacional. Conceito Exclusivo e Diferenciação Nossa proposta vai além do convencional: não somos apenas mais uma pizzaria. Com uma massa exclusiva, extra fina e crocante, desenvolvida e aperfeiçoada. Oferecemos mais de 70 combinações de sabores criteriosamente elaboradas, divididas em três categorias principais: Pizzas Salgadas: opções tradicionais e criações exclusivas Pizzas Doces: sobremesas irresistíveis Linha Light: alternativas equilibradas. Temos a marivilhosa CREK PASTA. Todo o sabor da cozinha Italiana voce encontra na PIZZA CREK. Excelência em Cada Detalhe Nossa busca pela perfeição se reflete em cada aspecto Ingredientes selecionados de fornecedores certificados Processo de produção padronizado e rigorosamente controlado Embalagens desenvolvidas especialmente para preservar a crocância Treinamento constante das equipes de produção e atendimento Serviço Primum de Eventos Como líder no segmento de eventos com pizza no Brasil, oferecemos: Estrutura completa com equipamentos profissionais Equipe especializada e uniformizada Cardápio personalizado conforme o perfil do evento Atendimento para diversos portes de eventos: Eventos pequenos (30 a 100 pessoas) Eventos médios (100 a 500 pessoas) Eventos corporativos (500 a 10.000+ pessoas) Casamentos, formaturas e confraternizações Reconhecimento e Expansão Presente em mais de 15 estados brasileiros Prêmios Internacionais Premiações no setor de franchising Cases de sucesso em importantes veículos de comunicação Certificações de qualidade e segurança alimentar Compromisso com a Sustentabilidade Embalagens eco-friendly Gestão responsável de resíduos Política de compras de fornecedores locais Diferenciais Competitivos Produto patenteado e exclusivo Modelo de negócio escalável Suporte completo aos franqueados Centro de treinamento próprio Tecnologia própria de produção Sistema de gestão integrado', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f10f5669-58db-4010-b5e5-328f4ac84a9d.jpg', 71, NULL, NULL, '2026-01-20 15:44:33.000', 'https://franquias.portaldofranchising.com.br/franquia-pizza-crek/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '200000', NULL, NULL, NULL, '55000', '0', '6', '1', '180000', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp8x002leh0scwp4tz5e', 'Tintas Mc', 'tintas-mc', NULL, 'Tintas', 'Varejo', 'Comercio varejista', 2025, 2025, '[\"https://www.youtube.com/watch?v=cosOsrmXDFw\",\"https://www.youtube.com/watch?v=ICialjL7vbk\",\"https://www.youtube.com/watch?v=Ep41JmaE5Mg\",\"https://www.youtube.com/watch?v=gJyh1UDV1pc\"]', '2026-04-01 02:00:12.886', '2025-08-11 01:37:23.986', 1219, NULL, 1, 1964, 'A Tintas MC foi fundada em 16 de abril de 1964, em São Paulo, por Manoel dos Santos Sá, e seus dois irmãos, Armando e Amilcar José de Sá, este último atuante na empresa até hoje, com o objetivo de criar uma grife no mercado varejista de tintas. Hoje a maior rede de lojas de tintas no Brasil, a Tintas MC tem como Missão “Tornar o Brasil um país mais colorido, sendo a primeira opção para quem pensa em comprar tinta”. A história da Tintas MC é um exemplo de vanguardismo, pioneirismo e uma incrível revolução no mercado especializado de varejo de tintas do Brasil. Nos dias de hoje as cores embelezam, marcam uma conquista, definem uma característica e a Tintas MC faz parte dessa história de evolução com um profundo conhecimento dos desejos de seu consumidor.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f2bfd073-2dc9-4b7f-83c2-6fa2291634ef.png', 230, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b9b50168-175c-4fb6-922b-718ee6b4941a.jpg', '2025-11-25 10:17:27.000', 'https://franquias.portaldofranchising.com.br/franquia-tintas-mc/', 'Compras', 'Compras', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9a370abb-f483-4019-a149-de6fdb5d4b79.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/581522f5-2460-40cc-9aa0-1e5a52a41c4a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1915f9a4-7656-4158-b7c7-41ec5e53eefb.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/46cb633a-72f3-4d07-9d7a-210a33024088.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/30e8a671-b53e-440d-9a2b-a5d36873e90e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7b7ad645-71b0-4b8a-b4b3-fb3e9fe767ce.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2636b932-1095-4f3a-9eef-5929b918262c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d8b8c41b-7464-4dbb-9959-e2f26b4c9eea.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2328d426-bc28-42a2-9805-974d93876724.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '260000', NULL, NULL, NULL, '50000', '250000', '5', '1.5', '150000', '60000', 200);
