INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp9f002oeh0sxbi04qnc', 'Minha Quitandinha', 'minha-quitandinha', NULL, '', '', '', 2021, 2021, NULL, '2026-04-01 02:00:12.917', '2025-08-11 01:37:24.003', 1222, NULL, 1, 2020, 'Nós somos o novo varejo!', NULL, 'Santa Catarina', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/776f4a94-d4b5-4976-9d4a-09a1931fb696.png', 769, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e20c9014-d4ae-4a96-903f-817890cac579.jpg', '2026-02-13 09:56:32.000', 'https://franquias.portaldofranchising.com.br/franquia-minha-quitandinha/', NULL, 'Fat. Total', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/648904b0-a3c7-4e0c-a77b-14b8a7ea20b5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cb481f6e-6a94-414c-b711-ac9ccad585c0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6aa03238-01ef-4e32-841d-86737b92988c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/50085e9a-0265-4721-86f8-f75ee8fb6564.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/54d061bc-ccea-4244-a147-ee7d7a9c0a72.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0c3013a3-fbec-4ab4-8984-e4000f243332.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/033216f9-605a-4445-894b-8fe4172c69bd.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1c7038e5-8575-4082-8a38-d533fa30d62e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1f87ee2c-b622-4430-a0e0-6b552b123fde.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '52000', NULL, NULL, NULL, '25000', NULL, '6', '0', NULL, '27000', 5);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp9k002peh0s5z27otf7', 'Market4u', 'market4u', 'São Paulo', 'Alimentos', 'Outros', 'Comercio varejista', NULL, 2020, '[\"https://www.youtube.com/watch?v=VipqolkXVdI\",\"https://www.youtube.com/watch?v=g2yeN90HjtE\",\"https://www.youtube.com/watch?v=mgOvJYQ-KGI\",\"https://www.youtube.com/watch?v=YpnsrA4G844\",\"https://www.youtube.com/watch?v=Qv9YLcF6ErA\"]', '2026-04-01 02:00:12.927', '2025-08-11 01:37:24.008', 1223, 'df170f80-7453-425d-9613-b55ed556e14e', 1, NULL, 'Especialista em mercados autônomos instalados em condomínios e empresas, o market4u é sinônimo de inovação e praticidade. Nossa rede oferece uma experiência única de compra, com tecnologia exclusiva e operação 24h, atendendo à crescente demanda por comodidade. Somos líderes no segmento de mercados autônomos e referência em um modelo de franquias que combina alta rentabilidade e simplicidade operacional. O market4u é reconhecido por iniciativas que destacam nosso compromisso com tecnologia e suporte constante aos franqueados em todas as etapas da operação. Invista em uma marca consolidada, premiada com o Selo de Excelência em Franchising da ABF e que conta com uma equipe de 300 especialistas dedicados ao sucesso do franqueado. O market4u em números: Perfil do franqueado Market4u: No market4u, valorizamos o senso de dono e a dedicação de cada franqueado. Com um suporte completo, do treinamento inicial à operação do dia a dia, oferecemos uma jornada segura, eficiente e com retorno acelerado para quem quer empreender com autonomia. Processo de seleção da Franquia Market4u: Escolha o market4u e faça parte da maior rede de mercados autônomos do Brasil. É a segurança e a inovação que seu investimento merece! Franquia com relevância nacional', NULL, 'Paraná', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/821bf2d3-ff72-4ee7-88db-3e512604fc88.png', 2185, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fab33e80-5155-477e-b872-7acc816c677a.jpg', '2025-10-02 15:43:52.000', 'https://franquias.portaldofranchising.com.br/franquia-market4u/', NULL, 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8fa8a916-86ce-4966-8747-42534d4ceaf5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8b2609a1-3be0-404e-82f9-58ffcd6543c5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/89f104b7-d6bb-418c-a8cb-06f6a1aded43.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6bb2776e-3764-4ed0-a0a8-705d69c35740.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/856d8af8-bc42-4652-bcf0-71b93c3ededc.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/62ba162b-3cf9-4519-bd6b-33f5cf6b8ca0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4732afab-5277-4bba-9125-5756cf698e8a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2591da1c-8d44-45e5-b681-99ab1eb34e4e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a4fe1d1a-cd11-4dd5-8e68-71d0a59d4898.jpg\"]', 1, 3, 3, 1, NULL, 0, 0, NULL, '80000', '100000', 12, 16, '50000', NULL, '6', '0', '30000', NULL, 0);
