s/cae9d1b4-9207-466a-849e-cb3d4a70507b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ccd37a5c-3922-4265-aab0-52be9dca6e48.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b7ca1785-1f09-4eac-85c7-05142ce6fa5d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/effd875f-e186-4bf9-b6cd-01860ee35e34.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/04624b96-f589-4fa2-a0d0-ddf10af64617.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cce77ecc-bd40-46fc-a85a-76bc6d3d8178.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ee956fde-1318-41e2-a951-9266ea7c9d9e.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '210000', NULL, NULL, NULL, '60000', '125000', '5', '1', '150000', NULL, 120);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpaf002reh0sf7qu4vx6', 'Puket', 'puket', NULL, 'Roupas', 'Meias e Lingerie', 'Comercio varejista', 2003, 2025, NULL, '2026-04-01 02:00:12.949', '2025-08-11 01:37:24.039', 1225, NULL, 1, 1988, 'A Puket nasceu em 1988, e de lá pra cá, virou sinônimo de produtos divertidos, alegres, feitos para seres bem-humorados de 0 a 104 anos.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/405cb526-f28f-4233-a043-6ed5403e602b.png', 192, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6d8a2c39-91e3-4a33-a80d-f336b9469632.jpg', '2026-02-12 16:51:16.000', 'https://franquias.portaldofranchising.com.br/franquia-puket/', 'Sobre o preço de venda dos produtos', 'Sobre o preço de venda dos produtos', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8c6ed243-3fbb-490a-955f-272243bdac1b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e022aea3-c9e8-4d81-8669-b3374b8bd25b.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '368000', NULL, NULL, NULL, '48000', NULL, '1.5', '2.5', '280000', '40000', 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpal002seh0sua4u8acw', 'FLYWORLD O SEU AMIGO DE VIAGENS', 'flyworld-o-seu-amigo-de-viagens', NULL, 'Hotelaria e Turismo', 'AGÊNCIAS DE TURISMO', 'Hotelaria e Turismo', 2013, 2014, '[\"https://www.youtube.com/watch?v=aEWkaAmHZrE\",\"https://www.youtube.com/watch?v=3CaOvrkwRXU\",\"https://www.youtube.com/watch?v=nyhiHMokjn4\",\"https://www.youtube.com/watch?v=fHCoSpIXcD4\"]', '2026-04-01 02:00:12.959', '2025-08-11 01:37:24.045', 1226, NULL, 1, 1997, 'A Flyworld é a primeira microfranquia de turismo do Brasil, com mais de 30 anos de experiência no setor e um modelo de negócio feito para quem sonha em empreender com liberdade, propósito e rentabilidade. Criada a partir da trajetória do seu fundador e CEO, Paulo Atencia, a Flyworld nasceu do desejo de compartilhar conhecimento com pessoas apaixonadas por viagens — e que querem transformar essa paixão em um negócio lucrativo. Desde 2013, levamos essa visão para todo o país com um modelo de franquia leve, acessível e de alta performance. Somos associados à ABF desde 2014, o que reforça nossa credibilidade no mercado de franchising. Mais do que uma franquia, a Flyworld é uma escolha inteligente para quem quer empreender no turismo com estrutura, liberdade e segurança. Mais de 30 anos de experiência Nosso fundador e CEO, Paulo Atencia, carrega uma trajetória sólida no turismo e traz essa bagagem para o dia a dia da rede. Toda a metodologia, processos e suporte da Flyworld são construídos com base em décadas de prática real — e isso faz diferença. Modelo de negócios flexível Acreditamos que uma agência em Home Office ou em um Ponto Físico, necessitam do mesmo suporte, expertise e apoio. Por isso, nosso modelo de negócio é único e você escolhe se irá empreender em home office ou loja física. E o melhor: se quiser mudar depois, não paga nada a mais por isso. Liberdade real para empreender do seu jeito Na Flyworld, o franqueado é dono de verdade. Você tem autonomia para escolher os fornecedores do nosso portfólio com quem vai trabalhar, decidir os tipos de viagem que quer vender e construir a sua própria carteira de clientes. A franqueadora está ao seu lado — não no seu caminho. Marketing estratégico para destacar a sua unidade Nosso time de marketing oferece consultoria para posicionar sua agência, ajuda na produção de conteúdo, materiais personalizados, campanhas locais e muito mais. Não importa se você está começando ou já tem experiência: vamos te ajudar a se destacar. Mix completo de produtos e serviços turísticos Na Flyworld, você pode atender qualquer perfil de cliente, do lazer ao corporativo, com soluções completas em um só lugar. Isso aumenta seu ticket médio e fideliza seu cliente, que não precisa buscar outros canais. Mais facilidade para ele, mais vendas para você. Expansão com propósito e critério Não buscamos ter centenas de unidades a qualquer custo. Crescemos com critério, escolhendo franqueados comprometidos e regiões com real potencial. Nossa meta é que cada unidade da Flyworld seja lucrativa e duradoura.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/49b649f0-9e58-46c4-b584-d86eb7e91a60.png', 36, NULL, NULL, '2026-01-22 09:44:51.000', 'https://franquias.portaldofranchising.com.br/franquia-flyworld/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '18250', NULL, NULL, NULL, '18250', NULL, '0', '0', NULL, NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpar002teh0shgkwvk4f', 'SEGENERGY', 'segenergy', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Energia Solar - Aeólica - Hidrogênio Verde - Mercado livre de energia', 2019, 2022, '[\"https://www.youtube.com/watch?v=57FsfIDvPog\",\"https://www.youtube.com/watch?v=yeyz40o668g\",\"https://www.youtube.com/watch?v=yIus3C4E89s\",\"https://www.youtube.com/watch?v=FvxE4Fhc_Mk\"]', '2026-04-01 02:00:12.971', '2025-08-11 01:37:24.051', 1227, NULL, 1, 2017, 'A SegEnergy é uma empresa brasileira especializada em soluções integradas de energia solar, diferenciada pela qualidade desde o primeiro contato até o pós-venda. Nosso objetivo, tornar a energia solar acessível para todos - uma alternativa viável, sustentável e rentável - nos tornou referência no mercado por desenvolvermos, implantarmos e gerenciarmos sistemas que aliam eficiência econômica e compromisso ambiental. Sonhos não são inacessíveis quando o investimento é feito com quem sabe realizá-los! Vantagens de fazer parte da SegEnergy: Mais de 7.500 sistemas instalados; Mais de 400 unidades espalhadas em todo território nacional; Suporte comercial individual especializado; MBA de Vendas; Gestão de engenharia com mais de 8 anos de atuação no setor; Gestão de marketing com calendários mensais para redes sociais + solicitações individuais personalizadas; Acesso a plataforma de CRM e dimensionamento SegSystem; Capital de giro baixo; Sem necessidade de estoque; Payback rápido; Segmento em alta no Brasil e no mundo; Fornecedores com equipamentos de alta qualidade. Por que escolher a SegEnergy: Franchising de destaque: fazemos parte do Grupo Zanon - holding de franquias, uma das maiores e melhores no mercado, com atuação a nível nacional e internacional. Flexibilidade de atuação: oferecemos os modelos home based e loja, com oportunidades de você trabalhar em casa ou local fixo. Facilidade de acesso a informações da rede: possuímos uma plataforma exclusiva e de fácil uso para você encontrar e solicitar pedidos personalizados, e receber avisos e informações internas e de fornecedores. Suporte e time comercial: oferecemos um time comercial especializado para te auxiliar e incentivar à alcançar seus objetivos, com disponibilidade para vídeo chamadas se necessário. Diferentes áreas de atuação: residencial, comercial, industrial, rural, mercado livre, autoprodutor e cooperativa.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/85f60c56-d900-4558-9d39-ad601cca39e2.jpg', 347, NULL, NULL, '2026-02-13 13:56:11.000', 'https://franquias.portaldofranchising.com.br/franquia-segenergy/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '40000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpax002ueh0shx9ipd8z', 'ORTHOPRIDE', 'orthopride', NULL, 'Saúde, Beleza e Bem Estar', 'ODONTOLOGIA', 'Tratamento ortodontia e estética', 2011, 2013, NULL, '2026-04-01 02:00:12.982', '2025-08-11 01:37:24.057', 1228, NULL, 1, 2009, 'A Orthopride nasceu para oferecer aos pacientes, mais qualidade de vida, mais saúde e muitos sorrisos no dia a dia. Fundada em 2009, a Orthopride tem marcado presença no cenário da ortodontia e da estética orofacial, proporcionando sorrisos confiantes e transformando vidas. Esta história é permeada por inovação, comprometimento com a excelência e um impacto positivo nos negócios. A jornada de sucesso da Orthopride iniciou seus passos com a primeira clínica inaugurada em Duque de Caxias, Rio de Janeiro, concebida com foco em tratamentos ortodôntico e de e?stética, desenvolvendo um processo de produção próprio e atendimento personalizado que fizeram-na atingir a marca de 2 mil pacientes logo no primeiro ano de funcionamento. Em 2012 deu início à sua operação no franchising brasileiro, e em 2016 ganhou seu primeiro Selo de Excelência em Franchising, da Associação Brasileira de Franchising (ABF). Sua expansão foi expressiva a partir de então, e hoje já são mais de 200 unidades da franquia. Nossas unidades são projetadas para oferecer comodidade aos pacientes, através de um atendimento personalizado, tecnologia de ponta e profissionais capacitados para fazer o melhor. Assim, procuramos levar a nossa filosofia em cada atendimento, proporcionando uma experiência positiva a quem nos procura. Somos a rede de franquias do ramo de ortodontia e estética orofacial que mais cresce no Brasil. Presente em 18 estados, hoje cuidamos de mais de 250 mil sorrisos em todo o Brasil. Não é à toa que 70% dos nossos franqueados possuem mais de uma unidade, com um total de falências ZERO!', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7aca8d75-649c-47c2-9530-4003d6860dbd.jpg', 204, NULL, NULL, '2026-01-08 17:07:01.000', 'https://franquias.portaldofranchising.com.br/franquia-orthopride-odontologia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '525000', NULL, NULL, NULL, '85000', '0', '7', '3', '290000', '150000', 0);
