ds/franchises/850aebad-c93d-49b1-8536-e41a2b78495a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d8ed55e6-ada5-4eed-bcec-58436cabe537.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a8c9eda4-de44-41d2-85c3-5649bb57aa45.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '250000', NULL, NULL, NULL, '50000', NULL, '8.5', '6', '200000', NULL, 22);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpbr002zeh0slyt4n0ju', 'GUA.CO', 'gua-co', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO COMPLETO', 'Restaurante Fast Casual de cozinha mexicana e americana saudável, com foco em qualidade e produtos frescos para refeições rápidas do dia a dia.', 2017, 2021, '[\"https://www.youtube.com/watch?v=_KnZekkygek\",\"https://www.youtube.com/watch?v=2xtko2p-wJY\",\"https://www.youtube.com/watch?v=uyLkR7z06zg\"]', '2026-04-01 02:00:13.033', '2025-08-11 01:37:24.088', 1233, NULL, 1, 2016, 'O GUA.CO foi fundado em 2016 em Campinas (SP) e rapidamente se tornou uma love brand graças ao seu posicionamento disruptivo e criativo. Apesar de atualmente a expansão estar focada no Sudeste, a marca já conquistou fãs por todo o Brasil, ansiosos por novas unidades em suas cidades. Acreditamos no poder da comida fresca preparada de forma caseira, com amor e carinho. Combinamos elementos simples que juntos se transformam em algo especial. A origem do nome do restaurante remete ao guacamole, uma receita asteca típica elaborada de quatro ingredientes que quando misturados se elevam a outro patamar. Usamos avocados, o abacate mexicano, na preparação de nosso guacamole e nós mesmos monitoramos o amadurecimento da fruta. Temos o compromisso em servir comida saudável e autêntica. Todos nossos ingredientes são preparados diariamente à mão, com vegetais frescos, temperos e folhas colhidos de hortas da região. Nossas tortillas e taco shells são legítimos e de matéria prima importada, garantindo a textura e o sabor autêntico da massa que se encontra na culinária mexicana e nos restaurantes mexicanos do sul e oeste dos Estados Unidos. O segmento fast-casual é o que mais cresce no mundo gastronômico. Entre eles, os de culinária mexicana são os mais populares, tendo o burrito como seu principal produto. Temos a produção diária de um restaurante casual dining, e ao mesmo tempo servimos a comida rapidamente como no fast-food. Dessa forma garantimos a qualidade e a agilidade do serviço.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2f7744d2-7ea1-481b-b89c-e32bab3719f8.jpg', 15, NULL, NULL, '2026-01-28 16:17:42.000', 'https://franquias.portaldofranchising.com.br/franquia-guaco/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '750000', NULL, NULL, NULL, '60000', NULL, '5', '2', '560000', '130000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpbx0030eh0sk1q53kle', 'Alphagraphics', 'alphagraphics', NULL, 'Serviços', 'Gráfica e Impressão', 'Comercio varejista', 1997, 2025, '[\"https://www.youtube.com/watch?v=LRowYfXOaYI\",\"https://www.youtube.com/watch?v=KAGMcjLdfm0\",\"https://www.youtube.com/watch?v=Rz-mmxiDUGw\"]', '2026-04-01 02:00:13.044', '2025-08-11 01:37:24.093', 1234, NULL, 1, 1997, 'A AlphaGraphics é a melhor oportunidade para investimento no setor. Experiência: Modelo testado e aprovado, com mais de 50 anos de mercado, sendo mais de 30 no Brasil; Global e Local: Fazemos parte de um grupo presente em mais de 50 países e mais de 3000 franqueados entre todas as marcas no nosso sistema. Dentro de cada AlphaGraphics você encontra um franqueado especializado nas necessidades de sua região; O que oferecemos: A AlphaGraphics oferece serviços e soluções personalizadas de impressão, sinalização e marketing que fazem nossos clientes serem notadas e a fazerem negócios; B2B e B2C: Nosso grande alvo são soluções para empresas e devem ser nossa prioridade. Mas sempre temos soluções que atendem as necessidades dos consumidores finais. Conseguimos encantar a todos; e Reconhecimento: Diversos prêmios dos setores de franchising, gráfico e marketing dão destaque à força da marca AlphaGraphics.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/069833ec-b663-44db-b669-e182516b13b6.svg', 25, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/836f437e-4578-4750-9f3c-149ed5efc0af.jpg', '2026-02-04 17:01:58.000', 'https://franquias.portaldofranchising.com.br/franquia-alphagraphics-grafica/', 'Fat. Bruto', 'Fat. Líq.', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/bb72360e-7b4d-4062-aa22-a0d8ce7cc980.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/64945dbe-f993-42cc-a8c5-162e68687991.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/12d9d9c5-07fd-4d14-9c32-7101c464d295.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f92e75be-b251-4a1a-b404-6e8d6a8d6494.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0aa4edd6-9cff-462f-a40a-a2aee7172f44.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/09d37594-4b7f-4c18-a411-9dd7c0b978db.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/42d44ed8-e714-43ad-8e0d-3dc48a3c4c81.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/313f136f-f58a-4115-9083-653c5ede8fc5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8aaf70e8-b7c6-4661-bb78-361a9ca4edeb.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '400000', NULL, NULL, NULL, '70000', NULL, '5', '2', '230000', '100000', 70);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpc20031eh0s3xpwxbr1', 'Majô Beauty Club', 'majo-beauty-club', NULL, 'Bebidas', '', 'Comercio varejista', NULL, 2020, '[\"https://www.youtube.com/watch?v=TSSb10r5ucA\",\"https://www.youtube.com/watch?v=vuwY2b1sekU\",\"https://www.youtube.com/watch?v=K4HCdKyx6jA\",\"https://www.youtube.com/watch?v=TSSb10r5ucA\",\"https://www.youtube.com/watch?v=Qx8oh1Pf_EU\"]', '2026-04-01 02:00:13.055', '2025-08-11 01:37:24.098', 1235, NULL, 1, 2020, 'A Majô Beauty Club nasceu do desejo da CEO e fundadora da marca, Claudia Vobeto, de criar um projeto com tecnologia e inovação. Defensora do sistema de franquias ético e transparente, a idealizadora atua há mais de 14 anos no segmento de beleza e também é diretora de capacitação da Associação Brasileira de Franchising – ABF. Visionária, Claudia Vobeto criou a rede para atender uma demanda do setor em constante expansão: qualidade e respeito pelos clientes. A rede segue em constante evolução e reflete diretamente as expectativas do mercado e do segmento. Assim, a Majô Beauty Club tem o propósito genuíno de criar experiências inesquecíveis e que vão além da prestação de serviços. Promovemos o bem-estar aos nossos clientes que, na grande maioria, tem pouco tempo para si mesmos. Com atendimento expresso, atendemos sem hora marcada para serviços do dia a dia, como depilação, manicure e sobrancelhas. E para serviços agendados, temos o aplicativo próprio Majô. São mais de 200 procedimentos de beleza, mais de 20 protocolos exclusivos e uma linha completa de produtos Majô. Além disso, temos o Beauty Blue – o único clube de beleza select do Brasil – com vantagens e descontos exclusivos para os Clientes Select Majô. Com mais de 130 mil atendimentos no ano, trazemos soluções para o dia a dia dos clientes com beleza da cabeça aos pés.', NULL, 'Goiás', 1, NULL, 22, NULL, NULL, '2025-09-15 16:35:46.000', 'https://franquias.portaldofranchising.com.br/franquia-majo-beauty-club-saude-beleza-e-bem-estar/', 'Fat. Bruto', 'Fat. Bruto', NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '297000', NULL, NULL, NULL, '58000', '260000', '6', '2', '189000', '50000', 40);
