-4c8a-8cae-b9f0d1af3fee.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/653b61ef-5b93-4cf4-8690-e705a6eb6611.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/bb8e7b2d-210c-4333-8667-87b44cac9d60.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/28473ad5-3363-4ab9-8794-d1f9e66f01ab.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/eff083ef-ec3a-4040-9aa6-4e16ed39ec51.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/86e828e2-d2d8-42c1-b8d3-85057bacc309.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpci0034eh0s2il8exw7', 'Magrass', 'magrass', NULL, 'Saúde', 'Emagrecimento', 'Serviços', 2007, 2025, NULL, '2026-04-01 02:00:13.084', '2025-08-11 01:37:24.114', 1238, NULL, 1, 2007, 'A NOVA CIÊNCIA DA TRANSFORMAÇÃO HUMANA A Magrass é a maior rede de clínicas de emagrecimento saudável e estética avançada da América Latina, com 18 anos de experiência e centenas de unidades em todo o Brasil e exterior. Somos especialistas em protocolos ultrapersonalizados que unem nutrição, estética corporal e facial, acompanhamento médico, ciência genética e tecnologias de ponta para oferecer soluções integrativas e eficazes. Com foco em bem-estar e transformação real de vidas, nossos tratamentos combinam técnicas seguras, acompanhamento profissional e inovações proporcionando resultados duradouros e sustentáveis. Mais do que emagrecer, a razão da nossa existência é transformar realidades com base na ciência, na tecnologia e no cuidado humano. Nosso compromisso é elevar a autoestima, a qualidade de vida e a confiança de cada cliente — sempre com respaldo científico, acolhimento humanizado e uma abordagem 100% ultrapersonalizada. Na Magrass não vendemos emagrecimento, nossa proposta é entregar Transformação Definitiva. Medicina Evolutiva = Tirzepatida + NutriGenética + Protocolo Magrass + Estética Moderna', NULL, 'Santa Catarina', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3761195e-012b-418e-9c12-01206cfa12d1.png', 183, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4c53d997-9094-425f-9cb3-5dd828324041.jpg', '2025-11-19 15:56:52.000', 'https://franquias.portaldofranchising.com.br/franquia-magrass-estetica/', 'Faturamento', 'Faturamento', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/332e14ec-88c7-41c4-9aa1-deadadd9d3dd.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/738faf98-336a-4239-b072-c63a2b96fa6c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/660a9820-fa22-4c9d-8c0d-9462047876e5.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/67b43036-6551-4da6-b442-8b2aa1a997ca.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '290000', NULL, NULL, NULL, '50000', NULL, '0', '0', '180000', '60000', 90);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpcn0035eh0s9ahdmwe4', 'URBAN MOTION', 'urban-motion', NULL, 'Entretenimento e Lazer', 'BRINQUEDOS E LAZER', 'Parque de Trampolins e Festas', 2024, 2025, '[\"https://www.youtube.com/watch?v=0Fzq1sErHsQ\"]', '2026-04-01 02:00:13.094', '2025-08-11 01:37:24.119', 1239, NULL, 1, 2016, 'Urban Motion: Uma Trajetória de Sucesso e Inovação no Entretenimento A Urban Motion surgiu no Brasil com uma proposta ousada e inovadora: replicar um bem-sucedido modelo de entretenimento americano focado em parques de trampolins. Desde sua concepção, a empresa encontrou um público receptivo, consolidando-se como um símbolo de celebração e lazer em território nacional. Marcos de Crescimento e Resiliência A jornada da Urban Motion teve início em 2016 com a inauguração da primeira unidade, introduzindo um conceito inédito de parque de trampolins no país, unindo diversão e atividade física para todas as idades. A expansão foi rápida, com aberturas no Shopping Morumbi Town em 2017 e no Shopping Tucuruvi em 2018, solidificando a presença da marca. Um marco crucial foi em 2019, com a introdução do conceito de festas nos parques. A criação de salões de eventos dedicados resultou na realização de mais de 1.100 celebrações, posicionando a Urban Motion como referência em eventos memoráveis. O ano de 2020 apresentou desafios significativos com a pandemia de COVID-19. A empresa demonstrou notável capacidade de adaptação, fechando temporariamente algumas unidades e pivotando para um modelo de festas delivery, garantindo a continuidade da celebração. A retomada em 2021 focou na revitalização da operação no Morumbi Town, resultando em um crescimento notável, superando os volumes de festas pré-pandemia. Em 2022, o crescimento superou 100%, pavimentando o caminho para 2023, ano em que a empresa alcançou seu maior crescimento histórico de faturamento, superando consistentemente os resultados anteriores. Essa trajetória é um testemunho da habilidade da Urban Motion em transformar desafios em oportunidades. O Modelo de Negócios e o Potencial das Franquias O sucesso da Urban Motion é fundamentado na fusão da paixão brasileira por festas com o conceito dinâmico de entretenimento em trampolins. A empresa oferece um ambiente único, proporcionando experiências de alta adrenalina em circuitos urbanos e consolidando-se como um local ideal para a realização de festas sofisticadas e envolventes. Com o objetivo de ampliar sua atuação e solidificar a marca, o Sistema de Franquias URBAN MOTION foi estabelecido. Reconhecido como um dos modelos mais estruturados e lucrativos do mercado, o sistema visa a uma parceria sólida com franqueados, que, por meio de seu comprometimento e excelência operacional, podem edificar seus empreendimentos. A padronização da marca é garantida por meio de procedimentos detalhados e manuais de operação e gestão acessíveis a toda a rede. Essa uniformidade é vital para o crescimento consistente e rápido da rede de franquias, fortalecendo a marca e otimizando o retorno para cada franqueado. A Urban Motion é mais que um espaço de entretenimento; é um modelo de negócio robusto e inovador que continua a expandir sua presença e impacto.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/318cf71b-4a9c-4b6e-ad88-f956d2fd8194.png', 3, NULL, NULL, '2026-01-28 00:00:08.000', 'https://franquias.portaldofranchising.com.br/franquia-urban-motion/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '1600000', NULL, NULL, NULL, '100000', NULL, '7', '3', '1000', '500000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpcs0036eh0sftes1xhk', 'MALWEE KIDS', 'malwee-kids', NULL, 'Moda', 'VESTUÁRIO', 'Comercialização de vestuário infantil', 2013, 2013, NULL, '2026-04-01 02:00:13.106', '2025-08-11 01:37:24.124', 1240, NULL, 1, 1968, 'Somos a Malwee Kids, franquia do Grupo Malwee, uma das maiores empresas de moda do Brasil e referência em sustentabilidade. Com mais de 10 anos de mercado, um layout de loja exclusivo, encantador e um mix de alto giro, entregamos aos nossos consumidores uma solução completa e confortável para atender as fases mais importantes de desenvolvimento das crianças. A nossa marca está em todo o Brasil, somos a marca TOP OF MIND em resposta espontânea e detemos o maior share de mercado das marcas e vestuário infantil para as classes B/C + de consumo, com um alto recall de marca no segmento infantil e produtos de uso contínuo dentro do contexto familiar! Hoje, estamos em todas as regiões brasileiras, com lojas em São Paulo, Rio de Janeiro, Bahia, Pernambuco, Espírito Santo, Rondônia, Goiás, Maranhão, Paraná, Pará, Alagoas, Sergipe e Distrito Federal. Entregamos muito mais que roupas para o segmento infantil, nós oferecemos experiência e confiança para o cuidador, com roupas que vão do tamanho 0 ao 18 e trazem conforto, sustentabilidade e estilo para compor os looks dos pequenos. Com várias unidades operando desde o início de nossa jornada no franchising, e com diversos operadores com múltiplas unidades, proporcionamos uma oportunidade de negócio sólida e com alto retorno, sendo a opção ideal para investidores que buscam sucesso nos negócios.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/29010f01-cba2-408d-b834-654e84149d50.png', 27, NULL, NULL, '2026-02-10 18:21:52.000', 'https://franquias.portaldofranchising.com.br/franquia-malwee-kids/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '285000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpcw0037eh0soymx5p69', 'EVOSOLAR', 'evosolar', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Serviços de Projeto & Instalação de Energia Solar Fotovoltaica', 2020, 2023, '[\"https://www.youtube.com/watch?v=1mcusLRkQgM\",\"https://www.youtube.com/watch?v=BlH8roGy_3A\"]', '2026-04-01 02:00:13.115', '2025-08-11 01:37:24.129', 1241, NULL, 1, 2018, 'Ao adquirir uma Franquia Evosolar, você estará 100% apto para atuar em um dos mercados que mais cresce no Brasil, Energia Solar. Fundada em 2018, A Evosolar, hoje conta com mais de 50 franquias ativas e aproximadamente 4.500 projetos fotovoltaicos já realizados. Com atuação já registrada em mais 200 cidades nas suas áreas de atuação. Os franqueados da Evosolar contam com todo apoio necessário desde a implementação do modelo de negócio, até o acompanhamento diário para seu crescimento e sucesso. Possuímos equipe dedicada a cuidar de cada franqueado para que tenha uma atenção de forma personalizada. Nosso diferenciais: Suporte de Engenharia Possuímos uma equipe técnica de engenheiros altamente capacitada, proporcionando um suporte constante aos franqueados na negociação e instalação dos sistemas fotovoltaico. Marca Consolidada A Evosolar já possui uma marca consolidada e reconhecida no mercado Brasileiro, o que se torna um grande diferencial competitivo ao franqueado. Cursos e Treinamentos O franqueado terá uma área de treinamentos com vídeos online para capacitar você e a sua equipe mesmo à distância. Marketing e Vendas Contamos com uma geração de leads (possíveis clientes) automática e ótima visibilidade na internet. Utilizamos as ferramentas mais modernas de marketing digital para facilitar a geração de novos negócios aos franqueados. Expertise Comercial O modelo de negócios que a Evosolar transmite aos franqueados possui uma taxa de conversão 4x maior que a média nacional das empresas do setor. Portfólio de Fornecedores A Evosolar dispõe de um grande leque de fornecedores. Onde, as melhores oportunidades de descontos em equipamentos e materiais necessários para a instalação estão disponíveis, garantindo ótimas oportunidades para seus franqueados. Pós-vendas Possuímos uma equipe técnica especializada em pós-vendas de energia solar, onde realizamos o acompanhamento e monitoramento de todos os projetos. Garantimos o treinamento dos franqueados nesta área o que se torna um diferencial de mercado para o mesmo.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/ca3d517b-0f6f-4c3f-bca9-c2169def72bf.png', 52, NULL, NULL, '2026-02-05 15:34:17.000', 'https://franquias.portaldofranchising.com.br/franquia-evosolar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '24900', NULL, NULL, NULL, '29900', NULL, '4', '1', '10000', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpd10038eh0s2engs1mr', 'Plie', 'plie', NULL, 'Vestuário', 'Lingerie', 'Comercio varejista', 2025, 2025, NULL, '2026-04-01 02:00:13.126', '2025-08-11 01:37:24.134', 1242, NULL, 1, 2002, 'Criada há 23 anos e 100% brasileira, a Plié é referência quando o assunto é shapewear, mas traz sua tecnologia e conforto também para outras linhas, como fitness e pijamas, sempre respeitando as diferentes curvas femininas em produtos que acompanham todos os momentos do dia a dia da mulher.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e51911f5-f941-4c6e-8ff3-fb64ac4d2c43.jpg', 43, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/47d1efd9-9281-4c26-a931-58b4cb4c3b3e.jpg', '2026-01-19 10:28:00.000', 'https://franquias.portaldofranchising.com.br/franquia-plie/', NULL, 'cobrado sobre preço de venda dos produtos', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f3cf31ef-6a8b-4593-97c6-6011d1a1e811.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e2c95961-dff7-45b9-b26b-250fe0d92ea7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/dcafd63f-ac90-4255-be8c-7139c20d73c0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ceca6ff5-0115-456c-a548-05d02c3ead3d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ae74028b-fcf0-4a97-91be-e9bb170c79a1.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/94632ec4-3f44-4ec3-9210-0db9444b8cb0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ef07a798-fe1a-4223-90fa-117ea5db1b3a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e847b41f-d0fd-424e-9d87-fb16a49d3fa9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/fcf29c13-6d33-472e-a81e-67fb766f2196.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '425000', NULL, NULL, NULL, '25000', '170000', '5', '0', '350000', '50000', 40);
