ps://apifranchise.mindconsulting.com.br/uploads/franchises/ab3b9f48-9ed3-4f41-982a-2bca6628ba4f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6b1626ae-3e67-42a1-993a-f75f293ae790.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/dfcef61c-7dbe-43a6-9c7c-3e71e83f518b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/63fbee20-1805-43ea-ab2b-de9460e7b524.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9c64e6e8-65ae-4ce4-9087-36f6e74abed7.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '85000', NULL, NULL, NULL, '35000', NULL, '0', '0', '20000', '30000', 25);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpdc003aeh0sd23m81i3', 'CROSBY', 'crosby', NULL, 'Moda', 'VESTUÁRIO', 'A Crosby foi fundada em 2015 pelos Irmãos Crosby, Fábio e Felipe Azevedo, começou em uma garagem e agora possui + de 120 lojas em todo Brasil!', 2017, 2024, '[\"https://www.youtube.com/watch?v=ImNNd_8TyWA\"]', '2026-04-01 02:00:13.147', '2025-08-11 01:37:24.144', 1244, NULL, 1, 2015, 'Experiência CROSBY Nos últimos anos, enfrentamos de frente grandes desafios como a pandemia e as crises econômicas. Foi justamente nesses momentos que mostramos nossa força: sabemos lidar com adversidades e transformá-las em oportunidades. Além disso, a forma como cuidamos dos nossos franqueados faz toda a diferença. Nosso compromisso com o sucesso resulta em um crescimento duas vezes maior do que o das demais franquias do mercado. Investir em uma marca que dobra de tamanho é o caminho! Inovação contínua em produto e logística Investimos constantemente em tecnologia e processos logísticos para garantir eficiência e agilidade em toda a operação. Agilidade na entrega O produto certo, no momento certo garantindo reposição rápida e assertiva para maximizar suas vendas. Gestão inteligente com tecnologia exclusiva Nossos franqueados contam com sistemas exclusivos que otimizam a operação e proporcionam um controle de estoque preciso e estratégico. Ferramentas de vendas que geram resultado Desenvolvemos soluções práticas e estratégias comerciais para impulsionar as vendas e manter sua loja sempre em alta performance.', NULL, 'RIO GRANDE DO NORTE', 1, NULL, 90, NULL, NULL, '2025-11-04 19:07:31.000', 'https://franquias.portaldofranchising.com.br/franquia-crosby/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '228000', NULL, NULL, NULL, '28000', NULL, '0', '3', '160000', '40000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpdg003beh0sacg8z52f', 'Limpeza Com Zelo', 'limpeza-com-zelo', NULL, 'Serviços', 'Limpeza', 'Comercio varejista', 2004, 2004, '[\"https://www.youtube.com/watch?v=vc3s7Hc8ZZU\",\"https://www.youtube.com/watch?v=duteoE-B3eY\",\"https://www.youtube.com/watch?v=JeVYCHXysRQ\",\"https://www.youtube.com/watch?v=iga6imzR6Yw\"]', '2026-04-01 02:00:13.158', '2025-08-11 01:37:24.149', 1245, NULL, 1, 2004, 'A Limpeza com Zelo é uma rede de franquias de limpeza residencial e comercial que oferece aos seus franqueados uma garantia de faturamento mínimo, assegurada em contrato e personalizada de acordo com a necessidade de cada um.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8e62e267-2435-4efe-9a59-05bbfc2fcfca.jpg', 108, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f2f7ea46-c8ec-43d3-944f-c52c6a596326.jpg', '2026-01-06 17:10:21.000', 'https://franquias.portaldofranchising.com.br/franquia-limpeza-com-zelo-limpeza/', NULL, 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0fa319c0-8919-4176-8e5f-ac1f5749aa82.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9028a277-fa6f-41ad-ac2b-12e93a4245b4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4cb2da77-4d6c-419f-82af-47b18bb788e3.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/aecf1842-6906-4dfd-a59e-63d333aeab9c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d904dc3b-ff44-4712-a261-0c2288a10ab6.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ee1807af-9024-4452-a7ed-636db5c39cc3.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/32dc25e5-50fe-42c0-b0c5-2917d1657781.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3f47bb8c-b5c5-4e2a-a6d4-7eac14e5a640.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '165000', NULL, NULL, NULL, '120000', '85000', '4', '0', '30000', '15000', 20);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpdl003ceh0s5k6heoaw', 'Terça Da Serra Casa De Repouso', 'terca-da-serra-casa-de-repouso', NULL, 'Saúde', 'Serviços para Idosos', 'Serviços', NULL, 2020, '[\"https://www.youtube.com/watch?v=LDuhZNbIi7U\"]', '2026-04-01 02:00:13.168', '2025-08-11 01:37:24.153', 1246, NULL, 1, NULL, 'Bem-vindo à Terça da Serra Residenciais Sênior – Um lugar repleto de histórias', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/643b5932-4610-4a06-bb73-5b1ba3e90376.png', 97, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5bf05aff-0053-4482-b6cb-e85ef4cc55bf.jpg', '2025-07-29 00:00:34.000', 'https://franquias.portaldofranchising.com.br/franquia-terca-da-serra-casa-de-repouso/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a8961605-d979-4c2b-a6f2-0bd7d2e4a32e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/332d51fc-a3d3-49f9-8738-90911c4381bb.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2b636ced-cb7d-4118-ae42-d20f6a291c61.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6506deee-683f-427f-823f-8fe9029b2ee0.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e7bb8961-4300-4bc7-a3c2-44a6fa2b74e8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/dbe75c0e-0989-479d-af88-c4d91ed97c15.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0618cdf8-bd1e-4c01-b48a-eb900999d6d7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2cce5e33-9bf0-4002-9cfa-c19753deea06.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1e69e876-069c-453d-8774-5ef2443616ab.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '858000', NULL, NULL, NULL, '98000', '0', '6', '2', '690000', '70000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpdq003deh0su6wlvm1s', 'BAYARD', 'bayard', NULL, 'Saúde, Beleza e Bem Estar', 'ESPORTE E RECREAÇÃO', 'Comercio de artigos esportivos e acessórios', 2020, 2023, '[\"https://www.youtube.com/watch?v=XxOtDNVdQ8s\"]', '2026-04-01 02:00:13.180', '2025-08-11 01:37:24.158', 1247, NULL, 1, 1955, 'A Bayard é uma empresa familiar fundada em 1955 e consolidada no varejo de artigos esportivos. Nosso compromisso é oferecer A Melhor seleção de pessoas, produtos, marcas e modalidades esportivas. Investimentos constantemente no treinamento da nossa equipe para proporcionar uma experiência de compra única, com atendimento próximo e especializado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fe6fbe13-3a57-45ec-8df3-c59ee51dbdab.png', 8, NULL, NULL, '2025-11-15 00:00:23.000', 'https://franquias.portaldofranchising.com.br/franquia-bayard/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '1000000', NULL, NULL, NULL, '100000', NULL, '5', '0', '600000', '300000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpdv003eeh0ss21f2hlw', 'Omie', 'omie', NULL, 'Software', 'Gestão', 'Tecnologia', NULL, 2024, NULL, '2026-04-01 02:00:13.191', '2025-08-11 01:37:24.163', 1248, NULL, 1, 2013, 'Fundada em 2013 por Marcelo Lombardo e Rafael Olmos, a Omie tem o propósito de destravar o crescimento de todos os tipos de negócios, oferecendo um sistema de gestão inovador, completo e ilimitado, ancorada em quatro grandes pilares: Gestão, por meio do software; Educação, por meio da Omie.Academy; Finanças, por meio das funcionalidades de um banco digital, além de linhas de crédito e soluções para apoio à gestão de PMEs, como o Itaú Meu Negócio gestão by Omie; e Comunidade, por meio de um ecossistema que conecta clientes, fornecedores e prestadores de serviços. Líder do segmento, a empresa conta com mais de 23 mil escritórios contábeis parceiros, mais de 150 mil clientes, cerca de 1700 colaboradores e mais de 120 unidades de franquias no país.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1b98ccfb-c106-44c2-a926-fd5cf8fc2b1f.png', 112, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/fff25611-1f02-4624-a0e8-f5e5d3738af4.jpg', '2025-10-01 10:50:11.000', 'https://franquias.portaldofranchising.com.br/franquia-omie/', 'Fat. Bruto', NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3bd48fcd-2528-49ea-91cd-51a65c47b0f7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d4b3155e-6fd1-4d2f-a7c5-d1fce29c1603.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7150bccf-14af-471b-b462-2add30f74b28.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '121000', NULL, NULL, NULL, '40000', NULL, '0', '2', '1000', '80000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpe0003feh0squ2aefyb', 'BARBEARIA BLACK ZONE', 'barbearia-black-zone', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'Cuidado de Beleza Masculina', 2023, 2025, NULL, '2026-04-01 02:00:13.202', '2025-08-11 01:37:24.168', 1249, NULL, 1, 2020, 'Inovando o Mercado de Barbearias A Black Zone nasceu em meio à pandemia, impulsionada pelo desafio de oferecer uma experiência única e acessível aos seus clientes. Desde o início, o propósito sempre foi claro: democratizar o segmento de barbearia, unindo gestão eficiente, excelência no atendimento e preços justos. Com uma estrutura sólida e foco em resultados, a Black Zone se destacou por seus diferenciais competitivos: gestão moderna, operação sem sazonalidade, baixa necessidade de estoque e um investimento inicial acessível. O modelo permite retorno em média a partir do 12º meses, com rentabilidade entre 15% e 25%, além de uma fácil escalabilidade. Hoje, a Black Zone é referência no mercado, transformando o conceito de barbearia em um negócio lucrativo e sustentável para seus investidores.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/bc5bb481-5a3b-4d33-96ae-2e2abca4e19c.png', 29, NULL, NULL, '2026-02-02 13:51:29.000', 'https://franquias.portaldofranchising.com.br/franquia-barbearia-black-zone/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
