g.com.br/uploads/franchises/47d90501-6175-4bc9-8d43-42b3d361df70.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/df7d7578-421a-45b9-a026-6714b270cbe6.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e34e8f41-9b91-41ca-9280-6a39bf76ac3c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8bc1f47a-362c-4154-aa03-dc276245bfcc.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '450000', NULL, NULL, NULL, '85000', '150000', '0', '2', '365000', NULL, 100);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpeb003heh0s3upkkf14', 'School Of Rock', 'school-of-rock', NULL, 'Serviços', 'Educação', 'Comercio varejista', 2013, 2022, NULL, '2026-04-01 02:00:13.223', '2025-08-11 01:37:24.179', 1251, NULL, 1, 2002, 'A primeira unidade da School of Rock no Brasil abriu em São Caetano do Sul, no ABC Paulista, em 2013, e logo em seguida mais uma escola em São Paulo, a unidade de Moema. Em 2017 assinamos o contrato de Master Franqueado e, de lá para cá, só crescemos: temos 65 unidades assinadas no Brasil. Em 2019 começamos nossa expansão para o continente Europeu, adquirindo os direitos de comercialização e suporte para Portugal e Espanha nos tornando Master Franquia destes países. Nosso desempenho como franqueadores tem sido constantemente reconhecido através de prêmios nacionais e internacionais. Recentemente recebemos o Selo de Excelência em Franchising concedido pela ABF (Associação Brasileira de Franchising). Sabemos o que é necessário para ter uma franquia de sucesso e temos mais de vinte anos de experiência no mercado.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2199d647-0a1f-4b9e-b880-b1fc8bb46ab2.svg', 60, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a59d0530-e80d-4b0b-934a-51be6fd3ac43.jpg', '2026-01-28 17:32:23.000', 'https://franquias.portaldofranchising.com.br/franquia-school-of-rock/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4e373fc5-d827-486b-9c38-519da2e2c164.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f40af9e6-38ce-4b83-99ec-bd6035030ddc.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b4d03b68-bd56-4587-88a2-be7620ef4f93.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d3b645fe-24d3-4e7d-9dd6-0194a1ff95fd.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/2e04a6cf-b9e4-4c28-a851-672e06ed99b4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/ba1e7e0d-3fc6-49ac-9d51-f59dae4cc29c.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8737c867-ee8f-4a80-926d-228cadde644d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4084a805-442d-46e7-ab5f-1e3bb23fb9d4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6feafe36-714a-4726-80e8-57dcacd58eae.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '585000', NULL, NULL, NULL, '215000', '125000', '8', '3', '300000', '70000', 250);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpeg003ieh0sz50yve2r', 'ADCOS', 'adcos', NULL, 'Saúde, Beleza e Bem Estar', 'COSMÉTICOS E PERFUMARIA', 'DERMOCOSMÉTICOS, COSMÉTICO, BELEZA, SAÚDE, ESTÉTICA, SKINCARE, TRATAMENTO, FACIAL', 2003, 2004, NULL, '2026-04-01 02:00:13.234', '2025-08-11 01:37:24.185', 1252, NULL, 1, 1993, 'Criada em 1993 por Ada Mota, a ADCOS é uma marca brasileira de dermocosméticos que traz em seu DNA a eficácia comprovada de seus produtos para tratamento da pele. Empreendedorismo, pesquisa, tecnologia e ciência foram os parâmetros seguidos desde sempre e que a tornaram uma marca genuína e de sucesso. Dia após dia, vem se tornando referência no ramo da saúde, beleza e estética. Ada Mota é farmacêutica e bioquímica, com mestrado em Dermocosmética em Paris, onde acompanhou de perto o surgimento do conceito do Dermocosmético, com a exigência de que as empresas comprovassem cientificamente a eficácia de seus produtos. Ainda em Paris, participou de um estudo da melhoria da cosmética de pomadas utilizadas em pacientes internados por doenças dermatológicas no Hospital Saint-Louis, experiência que direcionou e inspirou a preocupação da ADCOS com a eficácia associada ao sensorial agradável dos produtos. A marca é pioneira em protetores solares em formato Stick, há quase 10 anos, desde 2014. Além disso, é expert na estabilização da Vitamina C em dermocosméticos para a pele brasileira, se tornando referência no mercado há 30 anos e traz em seu portfólio diferentes texturas e para diferentes tipos de pele. Seu portfólio conta com cerca de 200 produtos para tratamentos faciais e corporais, nos segmentos home care e profissional, todos isentos de testes em animais e com eficácia comprovada, bem como alinhados às últimas tendências da cosmetologia mundial. A ADCOS tem como propósito, ao desenvolver seus produtos, a busca pelas melhores formulações, pois a marca acredita que é importante cuidar de seus consumidores como cuidariam de um familiar querido, como é o caso do Elastcrem, produto desenvolvido pela própria Dra. Ada em sua gestação gemelar. Todos os cosméticos e dermocosméticos da marca são desenvolvidos por dermatologistas e farmacêuticos com o cuidado de serem os melhores produtos focados em tratamentos, para o skincare e clima brasileiro, usando ingredientes biocompatíveis, oferecendo aos consumidores máxima eficácia, ampla gama de texturas e tonalidades. A ADCOS possui fortes investimentos em inovação, o que faz com que produtos icônicos lançados há 30 anos, como o Reduxcel corporal, se mantenham relevantes até hoje, com grande reconhecimento dos consumidores por sua ação comprovada na redução de medidas e celulite. A ADCOS oferece ao consumidor uma experiência exclusiva em dermocosméticos dentro do seu ambiente de lojas físicas. O atendimento oferecido pelas dermoconsultoras permite a recomendação de uma rotina totalmente personalizada, focada no skincare ideal para cada tipo de pele, desde tratamentos a protocolos específicos de cuidados, sempre de acordo com a necessidade do consumidor, possibilitando sentir na pele o sensorial dos produtos, sua textura, testar a tonalidade adequada para sua pele, tudo isso antes de comprá-los. Reconhecida por seu compromisso com a saúde da pele facial e corporal dos brasileiros, a ADCOS se orgulha do seu projeto para conscientização e tratamento do câncer de pele em parceria com PAD-UFES (Programa de Assistência Dermatológica e Cirúrgica à População Rural Vulnerável e com Câncer de Pele do Espírito Santo). Um programa desenvolvido pela Universidade Federal do Espírito Santo com a Secretaria Estadual da Saúde, onde a ADCOS auxilia o projeto através de doações de produtos e hospedagem de equipes e transporte de acadêmicos para os municípios atendidos. Em 2022, ao todo, foram realizadas 2072 consultas, 875 cirurgias e 6049 crioterapias. Nos últimos anos, a marca investiu em um modelo de negócios multicanal, com lojas, farmácias e e-commerce que totalizam 147 lojas pelo Brasil, divididas entre 90 franquias e 54 lojas próprias nos segmentos de clientes finais e profissionais. Mais de mil farmácias no país e 650 colaboradores, sendo 75% do quadro da empresa composto por mulheres.', NULL, 'ESPÍRITO SANTO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a361eed3-a146-442a-9c28-e0b2e05646b9.png', 158, NULL, NULL, '2025-12-15 14:39:22.000', 'https://franquias.portaldofranchising.com.br/franquia-adcos-beleza-e-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '590000', NULL, NULL, NULL, '50000', '0', '55', '0', '490000', '40000', 0);
