INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpfc003oeh0sas27q35j', 'Açaí Da Barra', 'acai-da-barra', NULL, '', '', '', 2015, 2025, '[\"https://www.youtube.com/watch?v=B0FgBIvnpmw\",\"https://www.youtube.com/watch?v=O0NINtJrk0w\",\"https://www.youtube.com/watch?v=kuaM5aEnX-o\"]', '2026-04-01 02:00:13.296', '2025-08-11 01:37:24.216', 1258, NULL, 1, 2015, 'Imagine uma saborosa experiência em que você pode se deliciar com açaí e sorvete, servidos de forma rápida e sem limites de acompanhamentos, tudo do jeitinho que você preferir.', NULL, 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/89e5434d-864f-4001-9e71-d2e0dedb461f.jpg', 287, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a0e6667f-65f4-43cf-a8a7-e6589b984d44.jpg', '2026-02-02 15:14:45.000', 'https://franquias.portaldofranchising.com.br/franquia-acai-da-barra/', 'Vendas Brutas', 'Compras', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6c65db3c-d093-4eb5-a672-2a4d8e8b25a1.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/fb2cdb3f-2ca3-47be-8cf5-68f936bfcbb9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/23105933-28b7-46dc-9238-59233d0469f7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a45b0d47-c514-4445-af70-25517ac49be4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a3a18cb9-2dd9-4a02-8643-7b3e8af27ab3.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a8961e0b-20a1-49af-9fe7-6b14c19f4cec.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7cbb04a3-3f1f-42ac-a61e-43121d9be232.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0d8c6afc-bd09-45eb-9794-a571d33fc599.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1d3c752f-1e58-4b6c-bb90-48ae177711a9.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '255000', NULL, NULL, NULL, '60000', NULL, '0', '0', '195000', NULL, 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpfh003peh0s6e7io81b', 'BUBBLE MIX TEA', 'bubble-mix-tea', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'A Bubble Mix é a rede de franquias pioneira no segmento de Bubble Tea no Brasil. Somos uma marca especializada em produtos à base de chá e café.', 2016, 2018, '[\"https://www.youtube.com/watch?v=NFoM2ZxXsqo\",\"https://www.youtube.com/watch?v=di8Ru6jwGFY\"]', '2026-04-01 02:00:13.306', '2025-08-11 01:37:24.221', 1259, NULL, 1, 2014, 'Pioneira no Brasil e Líder no Mercado A Bubble Mix Tea trouxe para o Brasil a bebida que é tendência global: o Bubble Tea, criado em Taiwan nos anos 80. Oferecendo uma combinação deliciosa de chás, cafés, e ingredientes exclusivos, como pérolas de tapioca e poppings, a marca se destacou por sua qualidade, inovação e experiência sensorial única. Fundada em 2014, a Bubble Mix Tea foi a primeira marca a adaptar o conceito de Bubble Tea ao gosto brasileiro. Participou do Shark Tank Brasil em 2017, ganhando destaque nacional. Reconhecida com o Selo de Excelência em Franchising em 2020 - 2022 - 2024, consolidando-se como referência no segmento. Em 2023, deu início à sua expansão internacional, marcando um novo capítulo em sua trajetória de sucesso. Com mais de 100 unidades em operação ou implantação, a marca é líder absoluta na América do Sul. Por Que Escolher a Bubble Mix Tea? Mercado em Expansão: O setor de Bubble Tea cresce de forma acelerada em todo o mundo, e o Brasil segue a tendência, com consumidores buscando experiências gastronômicas inovadoras. Modelo de Negócio Validado: Após dois anos de testes e ajustes, o modelo foi estruturado para garantir lucratividade e escalabilidade, com faturamento médio atraente para os franqueados. Baixo Investimento, Alto Retorno: Investimento inicial a partir de R$ 119.000 Lucro médio entre 15% e 25% Retorno estimado entre 12 e 24 meses Inovação Constante: Oferecemos sabores exclusivos, como chás tropicais e toppings diferenciados, além de lançamentos regulares que atraem novos públicos. O Melhor Suporte para Seu Sucesso Na Bubble Mix Tea, você não estará sozinho. Nossa equipe acompanha cada etapa do processo para garantir o sucesso do seu negócio. Treinamento Completo: Aprenda tudo sobre marketing, gestão operacional, administrativa e estratégias para maximizar os resultados da sua franquia. Acompanhamento Personalizado: Desde a escolha do ponto comercial até o pós-inauguração, estamos ao seu lado para garantir uma transição tranquila e operações eficientes. Logística Facilitada: Com um centro de distribuição próprio, garantimos que sua unidade tenha acesso rápido e padronizado a todos os produtos. Quem Pode Ser um Franqueado Bubble Mix Tea? Buscamos parceiros que: Tenham mais de 21 anos e residam na cidade onde será instalada a unidade. Disponham de recursos próprios e tempo para se dedicar ao negócio. Possuam espírito empreendedor e gostem de trabalhar com o público. Como Funciona o Processo de Seleção? Formulário de Interesse: Preencha online e tire suas dúvidas iniciais. Análise de Viabilidade Financeira: Descubra como o negócio pode funcionar para você. Circular de Oferta de Franquia (COF): Receba todos os detalhes da operação e tenha 10 dias para análise. Pré-Contrato: Garanta sua franquia com o pagamento da taxa e a definição do ponto comercial. Contrato Final e Implantação: Estruture sua loja e esteja pronto para começar!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/8cf35714-8d77-4af2-9e0b-125f139ef008.png', 81, NULL, NULL, '2025-12-29 00:00:08.000', 'https://franquias.portaldofranchising.com.br/franquia-bubble-mix-tea/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '130000', NULL, NULL, NULL, '45000', NULL, '5', '2', '165000', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpfl003qeh0stottezgi', 'Chiquinho Sorvetes', 'chiquinho-sorvetes', NULL, 'Alimentos', 'Sobremesas', 'Comercio varejista', 2025, 2025, '[\"https://www.youtube.com/watch?v=lp4vFmBRZWE\",\"https://www.youtube.com/watch?v=lt9-g2aAhTQ\",\"https://www.youtube.com/watch?v=GHEbhjBHOd0\",\"https://www.youtube.com/watch?v=g1IAVxFkHWw\"]', '2026-04-01 02:00:13.317', '2025-08-11 01:37:24.226', 1260, NULL, 1, 1982, 'A Chiquinho é uma rede de franquias com 43 anos no setor de sobremesas e com mais de 720 unidades espalhadas pelo Brasil. A marca possui um histórico consolidado e know-how capaz de garantir a excelência nos processos, além de contar com receitas de qualidade, ingredientes selecionados e parcerias com marcas renomadas nacionalmente e internacionalmente. Atualmente, são mais de 100 produtos no cardápio que atendem públicos de todos os gostos. O plano de desenvolvimento da marca promove a abertura de lojas em todas as regiões e firma nossa presença de marca nacionalmente. É por isso que somos reconhecidos ano após ano por entidades referências do franchising.', NULL, 'São Paulo', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/e2ab5750-af4d-473b-b6fa-a5cf22d901d5.png', 1029, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/4f1e8829-3755-438d-bb56-eb9766dd5058.jpg', '2026-01-12 12:03:12.000', 'https://franquias.portaldofranchising.com.br/franquia-chiquinho-sorvetes/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7dd4803c-5319-41ec-845e-f3a223747739.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '465000', NULL, NULL, NULL, '35000', '19000', '5', '2', '400000', '30000', 35);
