INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpib0045eh0sk5th0jfm', 'ICE CREAM ROLL', 'ice-cream-roll', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'A Ice Roll a maior rede de Sorvete na Chapa do mundo com um modelo de negócio perfeito para você crescer, investimento atrativo lucratividade acima da média. Saiba mais no Portal do Franchising', 2017, 2023, '[\"https://www.youtube.com/watch?v=YHZccP5YEzQ\",\"https://www.youtube.com/watch?v=erxH93d00fo\"]', '2026-04-01 02:00:13.464', '2025-08-11 01:37:24.324', 1275, NULL, 1, 2017, 'A Ice Roll é famosa pelo sorvete de rolinho ou sorvete na chapa, como quiser chamar !! Foi pioneira em trazer a ideia para o Brasil em 2017 e foi um sucesso. O primeiro quiosque da rede foi inaugurado no mesmo ano, em Indaiatuba, é o ponto onde se concentra a base da Ice Cream Roll e onde também nascem as novidades. Os famosos rolinhos conquistaram a todos e hoje, com quase 6 anos de mercado, a Ice Roll conta com mais de 80 unidades pelo Brasil inteiro e segue expandindo suas operações !! História da Ice Cream Roll A história da marca começa em 2017 com um engenheiro observador que tinha muita vontade de empreender. Depois de viajar pela Tailândia e descobrir as delícias do sorvete de lá, a vontade ganhou forma, sabor e ingredientes especiais. Nada mais gostoso que realizar um propósito. Foi assim que a Ice Cream Roll trouxe uma experiência única, marcante e personalizada para o país que mais consome sorvete no mundo. Olhando para esse mercado que cresce a cada ano, estruturamos um modelo de negócios de operação simplificada e eficiente para quem busca investir em franquias ou micro franquias. Diferenciais Planejado para oferecer muito mais que sabor ao cliente, o quiosque foi projetado para que o processo de produção artesanal do sorvete, que desperta a curiosidade, seja acompanhado de perto. O cliente vê cada ingrediente selecionado, vê a mistura rítmica da massa pelas espátulas e a cuidadosa formação de cada rolinho. O grande diferencial é a excelência em qualidade, é feito na hora, com ingredientes fresquinhos e massa aerada, com textura única, o sorvete na chapa é irresistível, tanto pelo sabor quanto pelo preparo. À base de leite sem corantes ou conservantes, a Ice Cream Roll é a melhor maneira de saciar essa água na boca que você está sentindo agora. São mais de 1400 combinações possíveis para você montar do jeito que o seu coração mandar!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/09f0851a-39b1-4c1a-b3ed-174412d64ed2.png', 60, NULL, NULL, '2026-01-23 07:50:45.000', 'https://franquias.portaldofranchising.com.br/franquia-ice-cream-roll/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '119000', NULL, NULL, NULL, '60000', '0', '5', '0', '101000', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpij0046eh0sv07i84ak', 'Arezzo', 'arezzo', NULL, '', '', '', NULL, NULL, '[\"https://www.youtube.com/watch?v=JUJa4e6zLCA\"]', '2026-04-01 02:00:13.475', '2025-08-11 01:37:24.332', 1276, NULL, 1, 1972, 'Fundada em 1972 pelos irmãos Anderson e Jefferson Birman, a Arezzo comemora 30 anos de uma história dedicada a arte de transitar pelo mundo da moda e traduzir tendências para mulheres da vida real. Hoje, a Arezzo é a maior marca de varejo de calçados femininos fashion da América Latina e conta com quase 450 lojas em sua rede de franquias, estando presente em mais de 270 cidades em todos os estados brasileiros. Criadora da famosa Anabela, a Arezzo é a primeira marca de um grupo que hoje conta com mais de 20 marcas, 1000 lojas, atendendo ao público feminino e masculino, vestindo mulheres e homens dos pés a cabeça.', NULL, 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f4dad57b-45cd-4df6-8bb2-a0bb21029bae.png', 424, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/b08a82e9-1e4b-4bcd-bde0-926f2b38fd43.jpg', '2025-12-08 10:50:10.000', 'https://franquias.portaldofranchising.com.br/franquia-arezzo/', 'Compras', 'Compras', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e251b6d4-649e-4305-a8aa-86d32ed947d8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5e6786da-51fa-4087-a85a-2ad4ef2148cc.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8d123941-965e-42f8-bdb4-f2bfc9056c0b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/242e0589-fd00-41cb-a207-eaaee054c062.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/44af360f-d942-4a5b-9d7a-d855db64b985.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b6a07f3e-bab1-4a68-8a44-f0be5711bf1a.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '500000', NULL, NULL, NULL, '50000', '160000', '38.74', '3', '280000', '170000', 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpir0047eh0smrba2fg6', 'QÓCULOS', 'qoculos', NULL, 'Saúde, Beleza e Bem Estar', 'ÓTICAS', 'VIEMOS PARA MUDAR O MERCADO ÓTICO! UM CONCEITO MODERNO E DESCOMPLICADO QUE OFERECE AOS CONSUMIDORES UMA EXPERIÊNCIA DE COMPRA INOVADORA E AOS FRANQUEADOS MAIOR EFICIÊNCIA OPERACIONAL E RENTABILIDADE.', 2018, 2020, NULL, '2026-04-01 02:00:13.485', '2025-08-11 01:37:24.339', 1277, NULL, 1, 2014, 'A QÓculos nasceu em 2014 como uma ótica online, se consolidando entre as 3 maiores do Brasil em 2015. A partir de 2018 iniciou sua expansão para o varejo através de lojas físicas com o sistema de franquias. Seus principais diferenciais estão nas vantagens às quais os franqueados têm acesso: - Alto know-how no ramo ótico e de franquias - Divulgação massiva em mídias on/offline - Melhores negociações com fornecedores - Treinamento e gestão - Marcas exclusivas com excelente markup - Estrutura omnichannel e e-commerce compartilhado com os franqueados - Ferramentas digitais de apoio à operação: estoque online, orçamento digital, espelho virtual, tabela de preços online, roleta da sorte. Além disso, a segmentação do público reflete suas instalações. O modelo QÓculos se adapta facilmente à shopping centers, grandes e pequenos centros comerciais e lojas de rua. Se apresenta em dois formatos: - Multimarcas: lojas de 35 a 75m2 com mix de produtos customizado ao público da região, contando com um portfólio das melhores marcas mundiais e atendendo todos os públicos. - Outlets: lojas de rua a partir de 60m2 instaladas em regiões com alto fluxo de pessoas atendendo ao público que busca baixo preço e qualidade. Trazendo em seu DNA toda sinergia que um sistema de franquias inteligente e moderno proporciona, a QÓculos foi criada para mudar o mercado ótico e oferecer aos consumidores uma experiência de compra inovadora, resultando em maior eficiência operacional e rentabilidade aos franqueados. Aliando a expertise da equipe com a experiência de mais de 25 anos em expansão de franquias e notório know-how de seus fundadores, obtidos através de franquia anterior em que chegou a atingir mais de 600 lojas abertas, a QÓculos se consolida no mercado em rápido crescimento, performando entre as melhores franquias do Brasil.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/09e3420a-d44f-4cca-abc9-690d7b8857f7.svg', 116, NULL, NULL, '2026-01-22 19:36:47.000', 'https://franquias.portaldofranchising.com.br/franquia-qoculos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '220000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
