INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpk6004eeh0sv4dl7wmh', 'ENJOEI', 'enjoei', NULL, 'Moda', 'VESTUÁRIO', 'loja de moda circular', 2024, 2024, NULL, '2026-04-01 02:00:13.558', '2025-08-11 01:37:24.391', 1284, NULL, 1, 2009, 'Depois de realizar um IPO na B3 com um valuation de R$ 1,13 bilhão, abrir o próprio centro logístico em Cabreúva/SP, a internet ficou pequena demais pro enjoei e iniciamos a operação de nossas 3 lojas físicas, consolidando nossa presença no varejo físico e dando largada à nossa expansão. O mercado de produtos usados no varejo físico é hoje 3 vezes maior que o mercado digital, onde atuamos com liderança e pioneirismo. Em moda e vestuário o potencial é ainda maior, na ordem de mais de 4 vezes que o existente em e-commerce e marketplaces. Dada a estatura da marca, nossa especialização e expertise singular no comércio de venda e compra de roupas usadas, enxergamos a oportunidade única na captura de um mercado que tem perspectiva de crescimento orgânico de 8% ao ano nesta década. Além do mercado em pleno crescimento, uma franquia enjoei não depende de shopping centers, conta com a governança de uma empresa de capital aberto e com a força da marca que é líder no segmento, possui a expertise de compra e de curadoria, e o diferencial nos pagamentos via pix na compra de produtos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/dc8fbe77-ce7d-4158-99b5-24ae332a226a.png', 4, NULL, NULL, '2025-12-03 15:47:10.000', 'https://franquias.portaldofranchising.com.br/franquia-enjoei/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '550000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpkc004feh0sy4cyjfdi', 'Oculum', 'oculum', NULL, '', '', '', NULL, 2025, '[\"https://www.youtube.com/watch?v=7_X1JbzhzHw\"]', '2026-04-01 02:00:13.569', '2025-08-11 01:37:24.397', 1285, NULL, 1, NULL, 'A franquia Oculum é mais que uma ótica — é uma rede premium com quase três décadas de experiência, que une beleza, inovação e precisão óptica em cada detalhe.', NULL, 'Pernambuco', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3d1259a4-6ee3-4a51-9276-59bc8497ce4a.jpg', 50, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3ce2b0c6-187b-4f5d-9c7c-b2c9a124d1f1.jpg', '2025-11-13 18:06:22.000', 'https://franquias.portaldofranchising.com.br/franquia-oculum/', 'Fat. Bruto', 'Fat. Bruto', NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '520000', NULL, NULL, NULL, '80000', NULL, '5', '2', '240000', '200000', 40);
