INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpkw004jeh0s55kpnasi', 'Capodarte', 'capodarte', NULL, '', '', '', 1991, 2025, '[\"https://www.youtube.com/watch?v=EYXMDHMsF9Q\"]', '2026-04-01 02:00:13.614', '2025-08-11 01:37:24.417', 1289, NULL, 1, 1992, 'Na Capodarte, cada detalhe do projeto de franquias é planejado para oferecer o máximo de resultados. Mais de 30 anos de tradição.', NULL, 'Rio de Janeiro', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/42e68f1d-f1db-4bf9-9ee9-11c441c4211a.png', 42, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/999fef6a-97d5-4642-b8ca-d7018e9578a5.jpg', '2026-01-23 17:25:06.000', 'https://franquias.portaldofranchising.com.br/franquia-capodarte/', 'Compras', 'Compras', NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '504000', NULL, NULL, NULL, '44000', NULL, '30', '3.3', '360000', '100000', 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpl2004keh0skn3bu3ws', 'USAFLEX', 'usaflex', NULL, 'Moda', 'CALÇADOS', 'Calçados, Bolsas e Acessórios.', 2015, 2016, '[\"https://www.youtube.com/watch?v=0DD-C8TvDug\",\"https://www.youtube.com/watch?v=7EaCZT3q12I\",\"https://www.youtube.com/watch?v=3KMEKfTluXo\",\"https://www.youtube.com/watch?v=dSFX6sxEedQ\"]', '2026-04-01 02:00:13.625', '2025-08-11 01:37:24.422', 1290, NULL, 1, 1998, 'Guiada por uma tradição de excelência e paixão pelo conforto, a Usaflex vem expandindo sua atuação para que mais empreendedores possam se beneficiar do know how adquirido pela marca. Oferecemos uma possibilidade de investimento seguro, rentável e descomplicado, que difunde e compartilha o sucesso da Usaflex através de um sistema de franquias. Com 9 anos de atuação, o canal de Franquias da Usaflex, se tornou como a primeira rede de calçados femininos de conforto e moda do Brasil, destacando-se pela qualidade, conforto e inovação de seus produtos. Ao longo dos últimos anos a marca constrói uma sólida rede de franquias, que desde 2019 recebe anualmente o selo de excelência da ABF (Associação Brasileira de Franchising). A estratégia de expansão da marca foi cuidadosamente planejada, com foco em um modelo de franquia que proporcione um suporte robusto e completo aos franqueados. Além disso, a Usaflex soube se reinventar ao longo dos anos, investindo em tecnologia e marketing para atingir novos públicos e aumentar a sua presença no mercado nacional e internacional. O sucesso da Usaflex pode ser atribuído a sua constante busca por excelência, adaptabilidade as tendências do mercado e ao forte compromisso com a satisfação do cliente. Com uma rede com mais de 340 lojas ativas em todas as regiões do Brasil, a Usaflex não só fortaleceu a sua marca, como também criou uma plataforma para quem deseja empreender no setor de calçados, conquistando a confiança dos franqueados e tornando-se um exemplo no franchising Brasileiro.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a0cbfac0-88a1-4123-81d7-98d8901034c6.png', 394, NULL, NULL, '2026-02-23 13:59:09.000', 'https://franquias.portaldofranchising.com.br/franquia-usaflex/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '430000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
