c580e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e5631027-2a04-4650-bd21-d76cba15499d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d448e45e-9dda-4dc5-be9b-2a945b3316a8.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/d12fa2c0-33d5-4fdc-ae24-228b8c0912b4.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b90dd9e4-48f8-4442-a37f-73691ccbb64d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6a5e5979-a80c-4e8a-99b6-6d67dac5f990.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/21b9d61c-6354-423a-9783-ad555472efb6.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '580000', NULL, NULL, NULL, '55000', '210000', '5', '2', '495000', '30000', 30);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpmf004ueh0sjwl3h7qv', 'Cacau Show', 'cacau-show', 'São Paulo', '', '', '', NULL, 2008, '[\"https://www.youtube.com/watch?v=bJ2pw45Vz64\",\"https://www.youtube.com/watch?v=6DrUi0w2su0\",\"https://www.youtube.com/watch?v=ZtnANADhMnk\",\"https://www.youtube.com/watch?v=8XjnTH1BjlE\",\"https://www.youtube.com/watch?v=zonJVZVmSI8\"]', '2026-04-02 13:17:12.859', '2025-08-11 01:37:24.472', 1300, '0165862e-523b-4bef-a4ae-c8c449dce62b', 1, NULL, 'Especialista em chocolates com diferentes intensidades de sabor, a Cacau Show está em constante inovação e oferece uma variedade de produtos para todos os gostos e momentos, além de ser líder do segmento e dona de produtos de alto giro. Com +14 milhões de seguidores nas redes sociais, estamos presente nos maiores meios de comunicação do país, sendo o maior anunciante de chocolate do país, com mais de vinte campanhas de publicidade no ano. Invista em uma marca consolidada no mercado nacional de franquias, que já recebeu diversos prêmios ao longo dos anos. É a segurança e solidez que seu investimento precisa, com modelos de negócio de acordo com o seu perfil.', 'Sobre a franquia CACAU SHOW\r\nFundação da franquia Cacau Show\r\n\r\nEspecialista em chocolates com diferentes intensidades de sabor, a Cacau Show está em constante inovação e oferece uma variedade de produtos para todos os gostos e\r\nmomentos, além de ser líder do segmento e dona de produtos de alto giro.\r\n\r\n\r\nCom +14 milhões de seguidores nas redes sociais, estamos presente nos maiores meios de comunicação do país, sendo o maior anunciante de chocolate do país, com mais de vinte campanhas de publicidade no ano.\r\n\r\nInvista em uma marca consolidada no mercado nacional de franquias, que já recebeu diversos prêmios ao longo dos anos.\r\n\r\nhttps://static.portaldofranchising.com.br/central/material-de-clientes/cacau-show/mini-site/cacaushowpremios.jpg', 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/12be6b1b-b569-4918-bff7-87c5555aca80.jpg', 4661, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6b5a99fd-f0ae-4410-91d2-92c18fb3cd7c.jpg', '2025-10-02 14:08:03.000', 'https://franquias.portaldofranchising.com.br/franquia-cacau-show-valor/', 'Faturamento', 'Compras', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/c5605fe7-1463-4ffd-a5fb-1e19acec2baf.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f33ce61c-2ea9-44e8-8b78-d08b77087217.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/1a9e84ba-33aa-44fc-916d-b5a671dc09fb.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/7f6c3eac-0af6-4dc5-a960-86a5f4fc726a.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/bcd31162-1910-4e2c-bddf-848f00514ae3.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e22c56c7-b42b-4674-a7fb-03e10cee88cb.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/22e8d5ba-24b1-4fb4-8019-7d0f87b36f37.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8a110e7c-f4c4-463f-8c5a-1806b845019d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/22836986-d078-47a1-8c3d-b5dfc7c4f4f6.jpg\"]', 1, 4.714285714285714, 33, 7, NULL, 3, 1, '[\"RANKING_CATEGORIA\",\"QUIZ\",\"HOME_DESTAQUES\"]', '310000', NULL, NULL, NULL, '40000', NULL, '0', '0', '230000', '40000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpmk004veh0saeiqdj06', 'DECOR COLORS', 'decor-colors', NULL, 'Casa e Construção', 'CONSTRUÇÃO', 'Empresa especializada em revestimento e decoração.', 2021, 2022, '[\"https://www.youtube.com/watch?v=LdPMkF17Gk8\",\"https://www.youtube.com/watch?v=EDhVzcyWm_k\",\"https://www.youtube.com/watch?v=jqQ7_no5cgo\"]', '2026-04-01 02:00:13.746', '2025-08-11 01:37:24.476', 1301, NULL, 1, 2021, 'A DECOR COLORS é uma solução inovadora para transformar o mercado de revestimentos e tintas, oferecendo produtos de fácil aplicação e resultado diferenciado. Ficou ainda mais conhecida através de sua participação no programa SHARK TANK BRASIL, onde obteve investimento recorde junto ao Sr. JOÃO APOLLINÁRIO, presidente e fundador da POLISHOP (conhecida rede de varejo do País). A solução DECOR COLORS foi criada pelo empresário LEONARDO JOSÉ DA SILVEIRA ARRUDA, comerciante de sucesso que desenvolveu o produto/marca própria de revestimentos, com aparência de cimento queimado. LEONARDO JOSÉ DA SILVEIRA ARRUDA, em 2010, fundou a loja de tintas e revestimentos denominada LÉO TINTAS. Para alavancar as vendas, LEONARDO idealizou oferecer produtos diferenciados que suprissem a demanda do mercado. Para tanto, desenvolveu a marca DECOR COLORS, com diferentes soluções de pinturas com efeito \"cimento queimado\", bem como espátulas especiais para a aplicação do produto. Os produtos da DECOR COLORS possuem excelente aceitação pelo mercado, através de vendas realizadas em todo Brasil. Nas redes sociais, a marca já conta com milhares de seguidores, em razão da qualidade do produto e pela facilidade da aplicação. Ainda, o negócio está em constante evolução, tendo sido introduzidos novos produtos recentemente, como a Solução Total, Quartzo e outros. Após os investimentos realizados pelo Sr. JOÃO APOLLINÁRIO na empresa, a DECOR COLORS obteve melhorias significativas na distribuição, nos processos de instalação no mercado, tendo sido desenvolvido o modelo de franquia mais adequado para o negócio.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/16001c00-9d72-4457-aba3-97acff0baa49.png', 637, NULL, NULL, '2026-02-06 10:50:26.000', 'https://franquias.portaldofranchising.com.br/franquia-decor-colors/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '62845', NULL, NULL, NULL, '15000', '0', '40', '3', '2500', '1000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpmp004weh0sunn48ok6', 'Drs. Protect', 'drs-protect', NULL, 'Seguros', 'Corretora de seguros', 'Serviços', NULL, 2021, '[\"https://www.youtube.com/watch?v=qA0mhfJvbkI\"]', '2026-04-01 02:00:13.757', '2025-08-11 01:37:24.481', 1302, NULL, 1, 2016, 'Diga uma coisa: você gostaria de testar um modelo de negócios ANTES de investir e virar franqueado?', NULL, NULL, 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cb2e3714-0eac-478d-b0a0-0fee11fbc8c3.jpg', 14, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a9765686-906e-452f-bd15-a92693f98da0.jpg', '2025-08-07 16:19:53.000', 'https://franquias.portaldofranchising.com.br/franquia-drs-protect/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpmt004xeh0sf5i9r84d', 'EMPÓRIO ESSENZA', 'emporio-essenza', NULL, 'Saúde, Beleza e Bem Estar', 'COSMÉTICOS E PERFUMARIA', 'A Empório Essenza tem a natureza e os vinhedos da Serra Gaúcha como sua principal fonte de inspiração para desenvolver fórmulas inovadoras oriundas da cadeia produtiva do vinho e da uva.', 2011, 2014, '[\"https://www.youtube.com/watch?v=lH5cAIt_-tE\"]', '2026-04-01 02:00:13.770', '2025-08-11 01:37:24.485', 1303, NULL, 1, 2005, 'Empório Essenza: Transforme a Essência da Serra Gaúcha em um Negócio de Sucesso Seja o embaixador de uma marca que encanta clientes e oferece alta rentabilidade no próspero mercado de bem-estar e sofisticação. Nascida no coração da Serra Gaúcha, a Empório Essenza é mais do que uma franquia de cosméticos e aromas; é um convite para um estilo de vida. Traduzimos a beleza e a riqueza dos vinhedos em produtos de alta qualidade que criam conexões emocionais duradouras com os consumidores. Para o investidor, isso representa uma oportunidade alinhada a um propósito claro, sustentada por uma demanda crescente e um modelo de negócio já validado no mercado. Nossas lojas vão além da venda de produtos, elas proporcionam experiências sensoriais marcantes, que atraem continuamente novos clientes e cultivam uma fidelização sólida e duradoura. A Oportunidade: Por que investir na Empório Essenza? Mercado em Ascensão: O setor de cosméticos e bem-estar é um dos mais resilientes e lucrativos do varejo. Você investirá em um segmento com público cativo e crescente. Diferencial Exclusivo: Nossas fórmulas, enriquecidas com ativos da uva e do vinho, contam uma história única que nos posiciona em um patamar de exclusividade, longe da concorrência comum. Marca Consolidada: Com mais de 20 anos de história, somos uma marca com forte reconhecimento, sinônimo de qualidade, elegância e confiança. Alta Rentabilidade: Oferecemos um modelo de negócio otimizado, com excelente margem de lucro e um portfólio de produtos diversificado que atende a múltiplos desejos de consumo, de cuidados pessoais a decoração de ambientes.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 45, NULL, NULL, '2025-10-27 08:31:22.000', 'https://franquias.portaldofranchising.com.br/franquia-emporio-essenza/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '166500', NULL, NULL, NULL, '18000', '0', '30', '2', '191800', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpmy004yeh0ssv6g6wrm', 'Microlins', 'microlins', NULL, '', '', '', NULL, 2003, '[\"https://www.youtube.com/watch?v=zbPi5KgVuiU\",\"https://www.youtube.com/watch?v=Vszctr2JBJA\",\"https://www.youtube.com/watch?v=qGZpP17bjUo\",\"https://www.youtube.com/watch?v=WfHGRar-gsk\",\"https://www.youtube.com/watch?v=I3UoH5E1p7I\"]', '2026-04-01 02:00:13.781', '2025-08-11 01:37:24.491', 1304, NULL, 1, NULL, 'Microlins é sinônimo de tradição e excelência A Microlins, que está entre as 50 maiores franquias do Brasil em 2024, é a líder em seu segmento e possui mais de 30 anos de experiência transformando vidas. Isso mesmo!', NULL, 'São Paulo', NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/deffc070-4e58-4926-9def-26566f8375c6.jpg', 385, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/240af8a7-6345-4972-a0e4-d183b35a53b5.jpg', '2026-01-28 16:29:20.000', 'https://franquias.portaldofranchising.com.br/franquia-microlins-educacao-e-treinamento/', 'Fat. Bruto', 'Fat. Bruto', '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/80c5b834-7075-4eb2-b01f-5f33a73bb7e9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b1499d00-d19d-43fb-a1d3-d01786fae287.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/cec784ec-a935-479e-a63c-b25bea685eb9.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/70bc036d-dd4e-4d58-b6e3-a1454575aa09.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0a793020-c1d9-4ad8-a8f7-07e348b0f7fb.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/3c5aa585-b2a6-498b-93f8-5161715f8541.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5e9f464f-ecf7-4a52-aa7c-6d8e993979bc.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/e5c8a246-baae-4337-9a75-71c403ca9fbe.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '147000', NULL, NULL, NULL, '24000', '150000', '2', '2', '90000', '33000', 80);
