INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpnt0054eh0sg4z7p7dk', 'ESPETTO CARIOCA', 'espetto-carioca', NULL, 'Alimentação', 'BARES', 'Somos uma rede de bares e restaurantes especializados em petiscos no \"espetto\", levando o lifestyle carioca que está em nosso sobrenome e principalmente em nosso DNA ao público em geral.', 2012, 2014, '[\"https://www.youtube.com/watch?v=uXkTQScRsh4\"]', '2026-04-01 02:00:13.840', '2025-08-11 01:37:24.521', 1310, NULL, 1, 2010, 'Quem é que não gosta de sentar para tomar um chopp bem gelado e comer aquele espettinho feito direto na brasa do carvão? O Espettinho, tão famoso nas esquinas do Rio de Janeiro, veio das carrocinhas da rua para dentro de um bar com clima agradável, perfeito para unir amigos e família bem ao estilo de vida carioca, com um toque de sofisticação. São mais de 50 sabores de Espettos, dos mais Tradicionais aos Premium e Exóticos, passando por sabores Vegetarianos, Doces e Fritos. A marca Espetto Carioca nasceu em 2010 e inaugurou sua primeira franquia em 2012.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a0ddca1a-ed94-47bd-8bc0-84e395e2a6cc.png', 38, NULL, NULL, '2026-01-29 09:40:36.000', 'https://franquias.portaldofranchising.com.br/franquia-espetto-carioca-alimentacao/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/9874bed5-97e7-4072-aa7f-af1926a0f8ce.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '295000', NULL, NULL, NULL, '65000', NULL, '5', '2', '690000', '50000', 0);
