INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mrx35005deh0s7n2zr1r5', 'DI SANTINNI', 'di-santinni', NULL, 'Moda', 'CALÇADOS', 'A Di Santinni é a maior Franqueadora de Calçados Multimarcas. Atua com o público feminino, masculino e infantil. E com a sua tecnologia própria DS SMART.', 2003, 2021, '[\"https://www.youtube.com/watch?v=6n8FufSkTVA\",\"https://www.youtube.com/watch?v=XNMlhNQfyHE\"]', '2026-04-01 02:00:13.934', '2025-08-11 01:46:54.018', 1319, NULL, 1, 1980, 'A Di Santinni surgiu com uma pequena fábrica de calçados em 1980. Motivados pela paixão em trazer para o mercado uma marca com modelos exclusivos e preços justos, buscamos novos horizontes e partimos de vez para o varejo com nossa primeira loja no Rio de Janeiro, no Norte Shopping em 1986. Acreditamos na história que construímos. Nossa comunidade é a inspiração para tudo o que fazemos. Trabalhamos para entregar a melhor experiência e acreditamos que preços acessíveis com facilidade de pagamento abrem mais portas. A trajetória ascendente, com a inauguração contínua de lojas, levou a Di Santinni a mudar seu modelo de expansão, optando em 2003 pelo franchising. São 21 anos de parceria com empreendedores que enxergaram no poder da marca, na qualidade dos produtos e na franquia a oportunidade de crescer seu patrimônio e mudar de vida. VANTAGENS COMPETITIVAS Atende ao maior público consumidor da categoria no Brasil (Classes B, C e D) Mix de produtos que atende todos os públicos e ocasiões Marcas e produtos exclusivos Melhores preços de aquisição e venda do mercado Cartão próprio, que oferece maior crédito e prazo de pagamento para o cliente Tecnologia proprietária 3 Centros de Distribuição próprios, com frota própria de caminhão Com fabricação própria, e revendendo as principais marcas de calçados do mercado, a Di Santinni se estruturou mais ainda para o crescimento, com ações de relevância para o desenvolvimento do negócio, como: Lançamento do cartão de crédito próprio (DS Card) em 2012; Criação do DS LAB em 2017, com tecnologia de automação no ponto de venda; Inauguração do novo centro de distribuição em 2022. Hoje, a Di Santinni é reconhecida como uma das maiores multimarcas de calçados do Brasil, com um ponto de venda diferenciado que dá visibilidade aos produtos mais desejados pelos clientes. É uma marca em franca ascensão e que está inovando o segmento de calçados, DS Smart DS SMART é o nome do atual modelo de franquia da Di Santinni. Contando com lojas a partir de 130 m², este modelo envolve muita inovação e tecnologia, tendo como principais objetivos as melhorias de performance de vendas, rentabilidade da operação e experiência do cliente. O segmento de calçados apresenta diversos desafios e a DS SMART foi desenvolvida para resolvê-los, são eles: Acuracidade de estoque Maior precisão na escala de funcionários Atendimento mais rápido e personalizado para o cliente Maior rentabilidade para o franqueado A tecnologia proprietária possibilita a rápida implementação de soluções exclusivas para a evolução contínua da operação do franqueado.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c22f4d9a-8990-41e5-9ab0-5b1efa116f43.jpg', 128, NULL, NULL, '2026-01-23 07:55:05.000', 'https://franquias.portaldofranchising.com.br/franquia-di-santinni/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '585000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mrx3b005eeh0s1xfy8t1r', 'SOLARPRIME', 'solarprime', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'FRANQUIA DE ENERGIA SOLAR FOTOVOLTAICA E DEMAIS SOLUÇÕES EM ENERGIA RENOVÁVEL', 2016, 2020, '[\"https://www.youtube.com/watch?v=_mHhT_xHfSo\",\"https://www.youtube.com/watch?v=NItDgJ6uUN8\",\"https://www.youtube.com/watch?v=qRhZ-Hcxc90\",\"https://www.youtube.com/watch?v=tZKV_FQY13A\"]', '2026-04-01 02:00:13.944', '2025-08-11 01:46:54.023', 1320, NULL, 1, 2016, 'A Solarprime é a maior e mais reconhecida franqueadora de energia solar do Brasil, a única do setor no TOP 50 da ABF, 4 Estrelas pela Pequenas Empresas & Grandes Negócios e com a melhor reputação pelos clientes no Reclame AQUI. Em parceria com as maiores e melhores fornecedoras do setor de energia, e com uma linha própria de equipamentos fotovoltaicos, a Solarprime diferencia-se no mercado como especialista em pequenas, médias e grandes usinas geradoras de energia solar. A franquia Solarprime é multiprodutos, com soluções em energia limpa que se encaixam nas necessidades de clientes residenciais, comerciais, industriais e rurais, incluindo geração distribuída, assinatura de energia solar, mercado livre de energia e carregadores para veículos elétricos. Criada por empreendedores visionários, a Solarprime transforma economia em mais qualidade de vida aos seus clientes. Desde 2016 no modelo de franchising, a Solarprime foi a primeira rede de franquias do segmento. Venha para a Solarprime e faça parte dessa rede de sucesso!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/c92ffc62-b2c6-4c41-a6e1-521a9286cd37.jpg', 450, NULL, NULL, '2026-01-22 17:40:42.000', 'https://franquias.portaldofranchising.com.br/franquia-solarprime/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '17000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mrx3g005feh0s5f7q77z3', 'HIGH LINE AMERICAN SCHOOL', 'high-line-american-school', NULL, 'Educação', 'EDUCAÇÃO', 'Escola de Educação Básica. Bilíngue e com metodologia americana.', 2025, 2025, NULL, '2026-04-01 02:00:13.954', '2025-08-11 01:46:54.028', 1321, NULL, 1, 2004, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/56086e97-6fc8-4f09-a39d-955e4f1a4e49.png', 1, NULL, NULL, '2025-08-22 17:16:47.000', 'https://franquias.portaldofranchising.com.br/franquia-high-line-american-school-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme80t4ue005geh0swrih9mf5', 'SOULIER', 'soulier', NULL, 'Moda', 'CALÇADOS', 'Calçados, Bolsas e Acessórios Femininos.', 2018, 2019, '[\"https://www.youtube.com/watch?v=hbuiorNE3Kc\",\"https://www.youtube.com/watch?v=sKAKVQ36Zgw\"]', '2026-04-01 02:00:13.964', '2025-08-12 01:07:31.510', 1322, NULL, 1, 1982, 'DESDE DE 1982 LEVAMOS CONFORTO E COR AOS PÉS DE MULHERES INDEPENDENTES, QUE SABEM ONDE PISAM. Criamos sempre um ambiente alegre, onde a felicidade passe pelo produto e equipe até chegar às nossas clientes. Produto: Prezamos pelo conforto. Nosso elo de qualidade é o pisar macio. E nossos pilares são: Feito à mão Couro Conforto Estampa exclusiva Feito no Brasil Atemporal Clube Soulier: O CLUBE SOULIER AUMENTA SUA TAXA DE RETORNO EM 20% AS CLIENTES BONIFICADAS QUE RETORNAM, GASTAM 4X O VALOR DO BÔNUS EM MÉDIA! O faturamento das lojas crescem de 10% a 15% em menos de 3 meses através de um bônus futuro concedido aos seus clientes. Marca consolidada e experiência Desde 1982 temos experiência em desenvolvimento, fabricação e comercialização de toda linha de calçados e acessórios femininos. As melhores redes já foram nossas clientes. Gestão simples e descomplicada Nossa Equipe de Gestão é altamente qualificada e disponível. Utilizamos os melhores softwares e ferramentas do varejo para que cada franqueado possa focar mais no que é primordial: encantar nossos clientes e gerar lucro. Mix de produtos diferenciado com bossa carioca Nossos produtos são 100% exclusivos e nos destacamos pelo conforto associado ao uso de cores, materiais e estampas especiais que remetem ao estilo do viver bem cada dia. Além da variedade de modelos, o nosso mix de preços é completo e competitivo, podendo atender a diversas ocasiões para uso pessoal ou para presentear. Margem de lucratividade superior ao do segmento 14% de lucro esperado com um retorno mais rápido do investimento.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/29923de7-e950-4cf6-b090-f47333cedb7d.jpg', 21, NULL, NULL, '2026-01-12 00:00:10.000', 'https://franquias.portaldofranchising.com.br/franquia-soulier/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '370000', NULL, NULL, NULL, '60000', '0', '16', '6', '250000', '60000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme80t4vg005heh0sus3xh0y8', 'KLIN', 'klin', NULL, 'Moda', 'CALÇADOS', 'Marca de calçados infantis, sempre preocupada com o caminhar saudável dos pequenos e se consolidou como líder na produção e venda de calçados infantis no Brasil pela qualidade e tecnologia.', 2022, 2022, '[\"https://www.youtube.com/watch?v=J_rOuID6H4g\",\"https://www.youtube.com/watch?v=fZsjfzdDnA8\"]', '2026-04-01 02:00:13.975', '2025-08-12 01:07:31.564', 1323, NULL, 1, 1983, 'A franquia Klin nasceu em um novo tempo, com um modelo de negócio leve, digital e sustentável, pensado para o varejo do futuro. Com mais de 40 anos de história no mercado infantil, aliamos tradição e inovação para oferecer uma operação ágil, integrada ao e-commerce e voltada para o relacionamento próximo com o consumidor. Nossas lojas funcionam como centros de experiência e distribuição, sem a necessidade de estruturas complexas ou caixas físicos. O atendimento é feito no celular, ao lado do cliente, com suporte de ferramentas como vendas via WhatsApp, live commerce e entregas rápidas por motoboy. Franqueados Klin contam com um modelo de abastecimento flexível, inteligência artificial para gestão do ponto de venda, e apoio constante em marketing digital. Tudo isso com baixo investimento inicial, rápido ponto de equilíbrio e alta atratividade no segmento infantil — um dos mais resilientes e promissores do varejo. Invista em um negócio preparado para o presente e o futuro. Seja um franqueado Klin.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/20acc6ce-4a3a-4bba-82ea-d3d4baa9694f.svg', 11, NULL, NULL, '2026-01-22 17:57:31.000', 'https://franquias.portaldofranchising.com.br/franquia-klin/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '155000', NULL, NULL, NULL, '65000', '0', '5', '1', '90000', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme80t4vp005ieh0si8jxl8hc', 'Biomovement', 'biomovement', NULL, 'Energia', 'Energia Renovável', 'Distribuição', NULL, 2025, '[\"https://www.youtube.com/watch?v=VGT0JJVLiSk\",\"https://www.youtube.com/watch?v=WyHWYYX6Trs\",\"https://www.youtube.com/watch?v=EB5uf9Bgpc8\",\"https://www.youtube.com/watch?v=8zVkMliQXYY\",\"https://www.youtube.com/watch?v=1LDMpxrpfVE\"]', '2026-04-01 02:00:13.985', '2025-08-12 01:07:31.574', 1324, NULL, 1, NULL, 'A BioMovement é distribuidora oficial da tecnologia israelense HomeBiogas no Brasil e nasceu com o propósito de levar soluções sustentáveis, acessíveis e de alto impacto para residências, comércios e propriedades rurais.', NULL, NULL, 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/5159dce7-f978-4160-828e-4cfd3ea0d773.svg', 47, NULL, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/a120dccd-dfa0-444c-a05b-4bdeff02070d.jpg', '2025-09-04 00:00:16.000', 'https://franquias.portaldofranchising.com.br/franquia-biomovement/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/44d771ae-a224-4950-92f9-fc5396c1f47b.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5ea05e3f-d583-4b5a-b480-56766b40aa18.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6aa411eb-2041-43f8-89ab-bb1c7f2a3712.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6ea7b660-078c-4411-816b-9e9c9ff5f4cc.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/63f3d20e-260a-45ea-8438-c558906e1df3.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/5646f04a-01c2-4351-ab25-34c7d9853f7f.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/0248a521-5059-46ee-89ff-cef42cfc5016.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/4fa1cb2c-9ad8-4750-b8f6-ac8f8bc04857.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/db8a1562-ef44-4e97-9a2d-150126cf61ba.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
