INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme9gkn7z005meh0spo80lf5t', 'SUSHIJAPA CHAN', 'sushijapa-chan', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO COMPLETO', 'Restaurante de culinária oriental', 2013, 2017, '[\"https://www.youtube.com/watch?v=WhJhXvoRL7o\",\"https://www.youtube.com/watch?v=ocOkFDgdkik\",\"https://www.youtube.com/watch?v=Txh30zfm3kU\",\"https://www.youtube.com/watch?v=Gt-823NjZew\"]', '2026-04-01 02:00:14.026', '2025-08-13 01:16:35.470', 1328, NULL, 1, 2012, 'A história do Sushi Japa Chan começou em 2012 em Belo Horizonte. A primeira loja surgiu no bairro Coração Eucarístico na zona oeste da capital mineira. A novidade fez sucesso entre os moradores e principalmente estudantes frequentadores do bairro universitário. Sempre focado em trazer qualidade e um ambiente descontraído, o restaurante se mostrou uma ótima opção no segmento de culinária oriental, se transformou em um ponto de encontro e o sucesso se espalhou por toda a cidade. Em 2018 a rede já conta com 18 unidades na região metropolitana de Belo Horizonte.', NULL, 'MINAS GERAIS', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d19a58d2-c50f-4708-a83a-3e54f5aea646.jpg', 13, NULL, NULL, '2025-09-08 12:51:55.000', 'https://franquias.portaldofranchising.com.br/franquia-sushijapa-chan-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
