INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmekcj61h0000eh0stltpp22q', 'INTIMMI CARE', 'intimmi-care', NULL, 'Saúde, Beleza e Bem Estar', 'SERVIÇOS MÉDICOS', 'Clinica especializada em Procedimentos Íntimos femininos e Menopausa. Protocolos personalizados de laser íntimo, Radiofrequência e Ultrasson Microfocado íntimo,Clareamento e preenchimento,e menopausa', 2022, 2025, NULL, '2026-04-01 02:00:14.153', '2025-08-20 16:08:56.021', 1342, NULL, 1, 2021, '', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/1bc25baa-143e-4a2e-b510-53941b1d62ad.png', NULL, NULL, NULL, '2025-05-22 09:59:12.000', 'https://franquias.portaldofranchising.com.br/franquia-intimmi-care-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmekvwcaf0001eh0s97uq10lg', 'VA VAAPTY', 'va-vaapty', NULL, 'Serviços Automotivos', 'SERVIÇOS AUTOMOTIVOS', 'Franquia de intermediação de venda de veículos, conectando pessoas que desejam vender seus carros com uma rede de compradores exclusivos. Negociação rápida, fácil e sem burocracia. Seja um franqueado!', 2021, 2021, NULL, '2026-04-01 02:00:14.164', '2025-08-21 01:11:03.351', 1343, NULL, 1, 2020, 'A MAIOR FRANQUIA EM INTERMEDIAÇÕES DE VENDA DE VEÍCULOS NO BRASIL QUEM SOMOS? A Vaapty foi estabelecida em junho de 2020, impulsionada pela vasta experiência de mercado do seu sócio fundador Ycaro Rafael Azevedo, que possui mais de 20 anos de experiência no setor automotivo. Com o objetivo de transformar a forma como as pessoas vendem seus veículos, tornando o processo inovador, seguro e livre de burocracia, a Vaapty se tornou a pioneira no Brasil no segmento de intermediação de vendas de veículos. Até o momento, já foram vendidas mais de 150 unidades em todo o país. PORQUE A VAAPTY É UM BOM NEGÓCIO? Em tempos de crise econômica, as pessoas procuram obter capital vendendo seus veículos. Por outro lado, quando a economia está em alta, as pessoas tendem a trocar de carro e as empresas renovam suas frotas, por isso, a Vaapty é um excelente negócio para qualquer momento econômico. DIFERENCIAIS VAAPTY Plataforma exclusiva Vaapty com mais de 30 mil lojista em todo o Brasil. Universidade Corporativa Suporte contínuo e humanizado Retorno rápido Ações motivacionais Mentorias periódicas Força de vendas STORE Nosso negócio possibilita ganhos ilimitados, atingido seu payback em até 10 meses. Capital médio para investimento 197mil SEJA UM FRANQUEADO MILIONÁRIO!', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/6c453020-ab04-40de-849b-4db123fdfdf9.jpg', 145, NULL, NULL, '2025-10-31 10:50:57.000', 'https://franquias.portaldofranchising.com.br/franquia-va-vaapty/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '245000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmekvwcb80002eh0smr3j889n', 'S PARFUM & COSMETICS', 's-parfum-cosmetics', NULL, 'Saúde, Beleza e Bem Estar', 'COSMÉTICOS E PERFUMARIA', 'Franquia internacional de perfumes premium. Com mais de 830 unidades no mundo, a marca chega ao Brasil trazendo um modelo consolidado e fragrâncias exclusivas com essências importadas da França.', 2014, 2025, NULL, '2026-04-01 02:00:14.175', '2025-08-21 01:11:03.379', 1344, NULL, 1, 2014, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/76995298-4a15-40da-9792-5b28b95eac41.png', 1, NULL, NULL, '2025-10-03 11:56:09.000', 'https://franquias.portaldofranchising.com.br/franquia-s-parfum-cosmetics-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmembbtp40007eh0sw94ltza6', 'LILICA & TIGOR', 'lilica-tigor', NULL, 'Moda', 'VESTUÁRIO', 'Somos uma empresa nacional de indústria e franquias de moda infantil, com personagens de forte identificação com o público infantil entre 0 a 12 anos.', 2000, 2004, '[\"https://www.youtube.com/watch?v=3pvNOXMSfoo\",\"https://www.youtube.com/watch?v=dP6iOx9SqeE\",\"https://www.youtube.com/watch?v=Cc4J_EmQKnQ\",\"https://www.youtube.com/watch?v=V2gLj-s0XVo\"]', '2026-04-01 02:00:14.185', '2025-08-22 01:10:46.168', 1349, NULL, 1, 1964, 'As marcas Lilica Ripilica e Tigor T. Tigre pertencem à Marisol, a maior indústria e rede de moda infantil do Brasil. Lançada há 31 anos, a marca Lilica Ripilica já estampou a capa da Vogue e apresentou coleções na São Paulo Fashion Week, principal semana de moda do Brasil. Tigor T. Tigre, no mercado desde 1993, já transportou seu tigre das estampas para uma montanha-russa no Beto Carrero World, o maior parque de diversões da América Latina. Desde 2000, as marcas estão à venda nas lojas Lilica&Tigor, conhecidas por mais de 102 milhões de brasileiros, segundo o Datafolha. A operação de franquias, em atuação há 23 anos, é marcada por inovações alinhadas às tendências de mercado. Repaginadas em 2023, as lojas têm detalhes lúdicos que evidenciam as peças. O novo projeto arquitetônico dá ênfase aos personagens, que assumem o papel de manequins e vestirão os lançamentos das duas marcas infantis. As mudanças foram planejadas para aprimorar a experiência dos clientes, além de aproximar as novas gerações da loja física. Mix diverso de produtos Além das coleções têxteis, as marcas Lilica Ripilica e Tigor T. Tigre lançam, anualmente, duas coleções de calçados, que permitem a compra de looks completos para crianças de 0 a 12 anos. Em adição, o mix de produtos oferece meias, óculos de sol e mochilas dos personagens. Lilica&Tigor é resultado de quase seis décadas de expertise Gestora das marcas Lilica Ripilica, Tigor T. Tigre, Marisol, Hapier, Pakalolo Soul e Lov.it, a catarinense Marisol S.A. surgiu em 1964 como uma fabricante de roupas de praia e chapéus. Hoje, a empresa dedica-se a criar produtos pensados para o futuro da infância e é referência no segmento infantil. Anualmente, são cerca de 15 milhões de peças produzidas.', NULL, 'SANTA CATARINA', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7d9ba5aa-c7e6-4106-ab87-70227867f2d9.png', 28, NULL, NULL, '2026-01-28 11:47:01.000', 'https://franquias.portaldofranchising.com.br/franquia-lilica-e-tigor-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '360000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmembg8l90008eh0sjd7xitqa', 'BESPEAK', 'bespeak', NULL, 'Educação', 'EDUCAÇÃO', 'A Bespeak é uma franquia de escolas de oratória, com cursos 100% práticos, turmas exclusivas, metodologia única e suporte completo, focada em transformar comunicação pessoal e profissional.', 2022, 2024, '[\"https://www.youtube.com/watch?v=kjqyogmTgOQ\",\"https://www.youtube.com/watch?v=qoh6aOplOIY\",\"https://www.youtube.com/watch?v=TWB2M_ybAGU\"]', '2026-04-01 02:00:14.195', '2025-08-22 01:14:12.093', 1350, NULL, 1, 2010, 'A Bespeak é a melhor escola de oratória do Brasil. Com mais de 15 anos de experiência prática, desenvolvemos uma metodologia autoral 100% focada em prática, transformação e protagonismo do aluno, validada por mais de 5 mil alunos e mais de 100 empresas atendidas. Oferecemos cursos em três formatos — imersão, programas de 2 e 4 meses — além de treinamentos para crianças e soluções corporativas personalizadas para setores como agronegócio, direito, varejo e política. Atendemos públicos das classes A e B, com diferentes opções de tempo e investimento. Mais do que cursos, criamos uma comunidade forte e engajada por meio do nosso Clube de Oratória, com encontros, desafios, eventos e trilhas contínuas de desenvolvimento — que fidelizam alunos e posicionam a Bespeak como referência nacional em comunicação prática. Nosso modelo de franquia foi desenhado para ser inteligente, enxuto e altamente lucrativo, com sede física obrigatória + atuação regional com escola móvel, permitindo expansão territorial real sem concorrência interna. Diferenciais que tornam a franquia Bespeak única: Sistema próprio e automatizado, que reduz trabalho operacional e dá escala. Time de vendas da franqueadora atua de forma contínua, gerando matrículas e permitindo operar com equipe reduzida. Custo operacional enxuto, com uso intensivo de tecnologia e estrutura compartilhada. Franqueado como professor, aumentando a margem de lucro e autoridade local. Exclusividade por região, e não apenas por cidade, garantindo proteção e crescimento sustentável. Sem venda casada de material didático — aqui, vendemos conhecimento e transformação. Portfólio completo: cursos infantis, adultos, empresariais e por nicho, com opções adaptadas a diferentes públicos. Clube ativo e crescente, que gera recorrência e fortalece a comunidade. Suporte premium e próximo da franqueadora, com foco total na qualidade de cada unidade — não na expansão desenfreada da rede. A Bespeak une excelência pedagógica, inteligência operacional e um modelo de negócio feito para quem quer impactar vidas com oratória e construir um negócio sólido, escalável e respeitado.', NULL, 'RIO GRANDE DO SUL', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/adaef088-e794-4bf9-bd3f-eff81a6f5aed.png', 2, NULL, NULL, '2025-10-09 00:00:37.000', 'https://franquias.portaldofranchising.com.br/franquia-bespeak/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
