uploads/franchises/b990ca02-6185-4789-b5d6-4df09bc78b18.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/69621ac7-a4f3-4027-8a90-935280e88681.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '950000', NULL, NULL, NULL, '120000', NULL, '10', '2', '760000', '70000', 850);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmetgixow000aeh0s8l7b47zk', 'CEBRALOG', 'cebralog', NULL, 'Educação', 'EDUCAÇÃO', 'Cursos personaliados em diversas áreas, voltado para empresas industriais, de serviços e de comércio de todos os setores.', 2016, 2025, NULL, '2026-04-01 02:00:14.216', '2025-08-27 01:10:39.247', 1352, NULL, 1, 2001, 'O CEBRALOG atua como uma verdadeira “Universidade Corporativa Sob Medida”, oferecendo soluções educacionais e de capacitação em mais de 60 áreas de conhecimento, voltadas a empresas de todos os portes e setores - indústria, comércio e serviços. Nosso modelo de franquia é home-based (FHB), garantindo ao franqueado um negócio de baixo custo operacional, alta escalabilidade e suporte integral. Com uma trajetória iniciada em 2001 e centenas de clientes atendidos em todo o Brasil, o CEBRALOG combina tradição e inovação, posicionando-se como referência em educação corporativa para profissionais de todos os níveis, do estagiário ao presidente. As áreas de atuação incluem temas de alta relevância e atualização constante, como: Transformação digital e inovação: Agile & Scrum, Big Data, IoT, Blockchain, Inteligência Artificial, Machine Learning, RPA. Gestão empresarial: Governança Corporativa, Indicadores de Performance, Project Finance, Compras, Custos, Contabilidade Gerencial, BPM. Operações e Supply Chain: Logística, Compras Diretas e Indiretas, Manutenção, Produção, Sustentabilidade, Indústria 4.0. Competências humanas e organizacionais: Ética Profissional, Comportamentais, Recursos Humanos, Vendas, Marketing, Gestão de Crises.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/796f553a-72da-436e-8d93-78c1fcf0388d.png', 1, NULL, NULL, '2025-12-08 20:01:51.000', 'https://franquias.portaldofranchising.com.br/franquia-cebralog/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '10000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
