INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmexqvdt3000jeh0sax3b34p7', 'ACHEI NO TOTEM', 'achei-no-totem', NULL, 'Comunicação, Informática e Eletrônicos', 'COMUNICAÇÃO', 'A Achei no Totem é uma franquia de mídia indoor digital, que gera receita recorrente com a venda de anúncios em totens instalados em locais de grande circulação.', 2013, 2025, NULL, '2026-04-01 02:00:14.275', '2025-08-30 01:11:20.871', 1361, NULL, 1, 2013, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0969da3c-175c-41b0-b8d2-4a280e092ce3.png', 25, NULL, NULL, '2026-02-24 14:48:03.000', 'https://franquias.portaldofranchising.com.br/franquia-achei-no-totem-comunicacao-informatica-e-eletronicos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '5200', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmexqvdtb000keh0s4eu9tjvu', 'BABBO GIOVANNI FRANQUIAS', 'babbo-giovanni-franquias', NULL, 'Alimentação', 'RESTAURANTES DE SERVIÇO RÁPIDO', 'pizzaria com delivery', 2017, 2021, NULL, '2026-04-01 02:00:14.285', '2025-08-30 01:11:20.880', 1362, NULL, 1, 2013, '', NULL, 'SÃO PAULO', 1, NULL, 13, NULL, NULL, '2025-09-03 18:01:21.000', 'https://franquias.portaldofranchising.com.br/franquia-babbo-giovanni/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmf21euhv000leh0s3v2etpjm', 'APTK', 'aptk', NULL, 'Alimentação', 'BARES', 'Loja de coquetéis engarrafados e acessórios de coquetelaria. Diversas opções de drinks clássicos, autorais e collabs. Presentes memoráveis e opções personalizadas do melhor da coquetelaria brasileira.', 2022, 2023, '[\"https://www.youtube.com/watch?v=ftPd2Bw5nR4\"]', '2026-04-01 02:00:14.295', '2025-09-02 01:17:29.826', 1363, NULL, 1, 2016, 'Tenha uma franquia da Rede APTK e faça história conosco. A APTK Spirits está selecionando pessoas interessadas em ser franqueadas das lojas APTK Spirits, para atuação em diversas regiões do país. Oferecemos um modelo de negócio extremamente atrativo, com uma relação de serviços e suporte para contribuir com sua performance. Hoje, a Rede APTK conta com aproximadamente 20 lojas presentes nos estados de SP, RJ, DF, RS, BH e PR. Em nossos PDVs, você encontra coquetéis engarrafados exclusivos, de produção própria, acessórios premium de coquetelaria e uma seleção de gelos gourmet. É uma oportunidade única para iniciar seu negócio próprio no inovador segmento de coquetéis prontos para beber, a categoria de bebidas alcoólicas que mais cresce no mundo todo. Para facilitar a ocupação de pontos nos diversos territórios mapeados por nós, dispomos de dois formatos de franquias: lojas e quiosques. Perfil* - Lojas: 35 m² e Quiosques: 20 m² *Necessidade de ponto de hidráulica. Procuramos pessoas com vivência comercial, preferencialmente no varejo bares/restaurantes, coquetelaria e alta gastronomia, e que preencham as qualidades abaixo: Residir na região da franquia; Disponibilidade para dedicação integral à loja; Conhecimento do mercado regional; Desejável experiência no varejo; Excelente relacionamento interpessoal; Habilidade gerencial; Capacidade de vendas; Gestão de equipe de vendas;', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2e80db15-dd3e-4ffb-8604-07739b2cb7b5.jpg', 11, NULL, NULL, '2025-09-12 09:51:57.000', 'https://franquias.portaldofranchising.com.br/franquia-aptk/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
