ps://apifranchise.mindconsulting.com.br/uploads/franchises/1e02160e-81f9-4a86-93e1-a678a785dc6d.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/91d2dbcf-3913-4163-96e5-536b8217b925.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/dd239f47-d606-49c7-b010-877da263f973.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f38db47b-3e92-43ee-8b00-91ab56c401ab.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/b1ac4e3f-1dbf-4566-a16f-ea8c86692d0e.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '14900', NULL, NULL, NULL, '14900', NULL, '0', '0', NULL, NULL, 1);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmf4w9pjm0002eh0s59jl678x', 'MR. CHENEY COOKIES', 'mr-cheney-cookies', NULL, 'Alimentação', 'DOCERIAS E SORVETERIAS', 'Cookies e doces americanos (American Treats)', 2007, 2005, '[\"https://www.youtube.com/watch?v=eQe8SzZK8ps\",\"https://www.youtube.com/watch?v=Lqki4L_VVmM\"]', '2026-04-01 02:00:14.324', '2025-09-04 01:16:50.576', 1366, NULL, 1, 2004, 'Produtos com receita original californiana, marca premiada com 2 selos de excelência em franchising. A mais 18 anos no ramo de franquias, atualmente contabilizando 80 operações em 12 Estados. A rede que trouxe o verdadeiro cookie americano para o Brasil se une a um dos grupos que mais cresce no franchising nacional. Com essa novidade, unimos a tradição e o sabor inconfundível do Mr. Cheney à força, estrutura e inteligência de crescimento da Hypper,já reponsável pela operação da Crepefy, Frutassa e T.Donuts. Mais que expansão, essa nova fase representa evolução — com mais suporte, inovação e oportunidades para franqueados e amantes da marca.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/30ed9fa1-b005-4894-ab21-3d0d42e7403d.png', 57, NULL, NULL, '2025-12-14 16:57:25.000', 'https://franquias.portaldofranchising.com.br/franquia-mr-cheney-cookies/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '124000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmf6bkx1x0000eh0skvzxmz9u', 'SORRIFÁCIL CLÍNICA DENTÁRIA', 'sorrifacil-clinica-dentaria', NULL, 'Saúde, Beleza e Bem Estar', 'ODONTOLOGIA', 'Prestação de serviços odontológicos com clínicas multidisciplinares.', 2016, 2018, '[\"https://www.youtube.com/watch?v=J_3xNjw4G6s\",\"https://www.youtube.com/watch?v=47gNGT3NcoY\"]', '2026-04-01 02:00:14.333', '2025-09-05 01:13:13.940', 1368, NULL, 1, 2006, 'Com 15 anos de história e mais de 100 clínicas odontológicas distribuídas pelo território nacional e uma no Uruguai, a SORRIFÁCIL – A maior rede própria de clínicas odontológicas do país – surgiu do anseio de dois jovens dentistas recém-formados em tornar a odontologia acessível a todas as classes sociais, atendendo desde crianças até idosos. A primeira clínica da rede abriu suas portas no mês de junho de 2006 na cidade de Gravataí, no Estado do Rio Grande do Sul. A SORRIFÁCIL segue seu plano de expansão embasado em valores como a acessibilidade aos produtos, serviços odontológicos e saúde bucal, qualidade e confiança, a fim de tornar a odontologia facilitada para todos e todas. A SORRIFÁCIL acredita tanto em seu modelo que é a maior rede de clínicas odontológicas com unidades próprias do país. A filosofia inicial da SORRIFÁCIL é: “Vendemos o que operamos”. A SORRIFÁCIL busca parceiros franqueados que proporcionem a seus pacientes bem-estar e saúde humanizados. Além da transferência de know-how, assessoria especializada e apoio ao FRANQUEADO, a SORRIFÁCIL, através de seu modelo de negócios, adota, como de fato vem adotando, um posicionamento diferenciado em relação ao mercado, visando melhorar a qualidade de vida de nossos pacientes e FRANQUEADOS em todos os aspectos possíveis. Seja um franqueado Sorrifácil e venha fazer parte da nossa família!', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/80bfa15c-afb8-40c9-91f4-d1b014af07d1.jpg', 107, NULL, NULL, '2025-09-17 17:03:55.000', 'https://franquias.portaldofranchising.com.br/franquia-sorrifacil-clinica-dentaria-odontologia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmfewao870000eh0sxqkkr8nz', 'LIZ LINGERIE', 'liz-lingerie', NULL, 'Moda', 'VESTUÁRIO', 'Roupas Íntimas, esporte, praia, vestuário e acessórios.', 2012, 2014, NULL, '2026-04-01 02:00:14.343', '2025-09-11 01:15:17.286', 1370, NULL, 1, 1989, 'A LIZ Uma marca, três palavras: Solução, Conforto e Paixão! \"Quando se veste uma lingerie Liz, é assim... Você se sente diferente...\" Declaração espontânea de muitas de nossas consumidoras, simplesmente pelo fato de que: conforto não se vê, se sente. E a Franquia Liz é mesmo assim, elaborada desde o fio de nossas maravilhosas e exclusivas microfibras até os milímetros que fazem toda a diferença no vestir. Uma equipe de verdadeiras experts, que trabalha com um olho na emoção e outro na tecnologia, a fim de atender e acompanhar com excelência as necessidades da mulher contemporânea. Especializada em lingeries, a Liz tem como um de seus grandes diferenciais a inovação em seus produtos, sempre com foco em alta tecnologia, altíssima qualidade, respeito ao meio ambiente e colaboradores. Pioneira no desenvolvimento de sutiãs com diferentes tamanhos de bojo (A, B, C, D, DD, F e G) no Brasil. A Liz também exporta seus produtos para mais de 30 países. As lojas contam também com a Liz Easywear, linha elaborada com o incomparável algodão Pima Peruano. Produtos versáteis para ficar em casa, relaxar, sair e até dormir. Além da venda de lingeries Liz e da linha Liz Easywear, outra marca presente na franquia é a In.Joy, com conceito mais fashion e antenado na moda, voltado para mulheres que gostam de cor, estampas e constantes novidades. A marca possui a mesma tecnologia, qualidade e padrão de excelência da Liz. Outro diferencial presente na loja é o serviço de Consultoria Liz Fit Sense, oferecido para todas as clientes, com objetivo de proporcionar a segurança de adquirir o sutiã no estilo e tamanho corretos para o seu tipo de corpo. Um sutiã Liz, com toda a sua tecnologia, modelagem e solução precisa ser vestido em seu tamanho perfeito! Fit Sense é um serviço da Liz conceituado em 2007, que capacita tecnicamente profissionais de vendas para oferecerem às consumidoras a experiência de provar e usar o sutiã no tamanho correto. VANTAGENS DE SER UM FRANQUEADO LIZ - Marca consagrada, com alta fidelização de clientes. - Linha de produtos consistente, de alto giro, não perecível. - Produtos campeões de venda desde 1999. - 52% dos produtos na curva A. - Baixo nível de mark-down. - Excelente rentabilidade. O PROJETO DAS LOJAS LIZ – ARQUITETO MAURÍCIO QUEIROZ O renomado designer de consumo Maurício Queiroz assina o projeto das lojas Liz. Contrastando com o tom suave de base, o negro do mobiliário destaca os produtos iluminados individualmente nos gaveteiros com frente de vidro – ou expostos em araras. O mobiliário é modular e presa pela versatilidade em atender um público diverso e poder assumir diferentes formas e contextos. “A loja representa o espírito da marca: contemporânea, atemporal, confortável e funcional”, afirma Queiroz, que também é responsável pelos projetos da Vivara, Montblanc, I-Stick e Etna, entre outros. O GRUPO CMR A Liz pertence ao grupo CMR, fundado em 1989. Uma empresa de capital nacional com foco em tecnologias inovadoras, qualidade premium, responsabilidade social e ambiental. Ética e seu forte branding consagram suas marcas no mercado nacional e internacional. Informações sobre Franquias Liz: comercialfranquializ@cmrcia.com.br (11) 3818-0360', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/7b977785-d67f-49e8-b929-92541ad88dbf.jpg', 34, NULL, NULL, '2025-11-13 09:25:24.000', 'https://franquias.portaldofranchising.com.br/franquia-liz-vestuario/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/a86461f9-d5cf-4612-a58d-88f98b9cffa7.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/6ba0d3ff-3265-48b6-a3cf-e23be3e96c49.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/f6f8657b-24bd-4be9-8683-0939116e195e.jpg\",\"https://apifranchise.mindconsulting.com.br/uploads/franchises/015a2262-3677-4248-a02b-385b7c2d9b90.jpg\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, '430000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmfhr2pjk0000eh0s7l9403yy', 'MOTOCHEFE BRASIL', 'motochefe-brasil', NULL, 'Serviços e Outros Negócios', 'OUTROS NEGÓCIOS', 'Marketing direto Serviços combinados de escritório e apoio administrativo', 2024, 2025, NULL, '2026-04-01 02:00:14.353', '2025-09-13 01:12:26.190', 1371, NULL, 1, 2024, '', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/0adaca8f-561c-4572-94f6-1a82f6a8e216.png', 3, NULL, NULL, '2025-10-03 16:40:30.000', 'https://franquias.portaldofranchising.com.br/franquia-motochefe-brasil-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmfm1cik90001eh0siderj2l4', 'POLISHOP', 'polishop', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'Empresa varejista de categorias como: Saúde e Bem Estar, Beleza, Fitness, Eletrodomésticos e Casa & Cozinha', 2024, 2024, '[\"https://www.youtube.com/watch?v=8nS64I6ykys\",\"https://www.youtube.com/watch?v=E2H2Sin2ODI\",\"https://www.youtube.com/watch?v=PlsJOWKxCqA\",\"https://www.youtube.com/watch?v=RlrkLDhAnLA\"]', '2026-04-01 02:00:14.363', '2025-09-16 01:11:04.569', 1372, NULL, 1, 1999, 'Brasil em 1999 por João Appolinário. A empresa começou com o objetivo de oferecer produtos inovadores que resolvessem problemas do dia a dia. Desde então, expandiu-se para diversos canais de venda: TV, internet, lojas físicas, franquias, catálogos e televendas. Com uma abordagem multicanal pioneira, a Polishop se destacou por investir fortemente em demonstrar os benefícios dos produtos em detalhes, uma estratégia que se provou eficaz no convencimento do consumidor. Com presença nacional por meio de lojas físicas, e-commerce próprio e redes sociais. Diferenciais da Polishop Multicanalidade (Omnichannel) - Atuamos de forma integrada em vários canais (TV, internet, lojas, call center), permitindo ao consumidor comprar onde e como quiser. Produtos Exclusivos e Inovadores - Comercializamos itens diferenciados, muitas vezes exclusivos no Brasil, voltados para bem-estar, saúde, fitness, culinária e beleza. Marketing Forte e Demonstrativo - Utilizamos infomerciais e vídeos demonstrativos para mostrar o funcionamento e os benefícios reais dos produtos. Marca Própria e Parcerias Globais - Trabalhamos com marcas próprias (como a AirFryer by Polishop) e temos parcerias com empresas internacionais, trazendo produtos que normalmente não estão disponíveis no varejo tradicional. Experiência do Cliente - As lojas da Polishop funcionam também como showrooms, onde o cliente pode experimentar os produtos antes de comprar.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/d951bb74-9d23-4216-9250-0704b8591324.svg', 44, NULL, NULL, '2025-09-22 09:40:01.000', 'https://franquias.portaldofranchising.com.br/franquia-polishop/', NULL, NULL, '[\"https://apifranchise.mindconsulting.com.br/uploads/franchises/8a5af927-eb8a-4018-a67a-cb273684214a.png\"]', 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmfngtkcj0002eh0s3gi4jkqu', 'LAUNDRY IN BOX', 'laundry-in-box', NULL, 'Limpeza e Conservação', 'LAVANDERIAS', 'Armários inteligentes conectados a lavanderias profissionais', 2018, 2025, NULL, '2026-04-01 02:00:14.372', '2025-09-17 01:12:00.441', 1373, NULL, 1, 2015, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/cbe94c12-df20-454d-93f0-825d3486c5b1.png', 11, NULL, NULL, '2026-02-24 14:46:01.000', 'https://franquias.portaldofranchising.com.br/franquia-laundry-in-box-limpeza-e-conservacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '15200', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmfqbe3ny0003eh0s4koa4a5w', 'TACO', 'taco', NULL, 'Moda', 'VESTUÁRIO', 'Loja de moda jovem básica, unissex e acessórios.', 1998, 2015, '[\"https://www.youtube.com/watch?v=B6-RkeQCXjI\",\"https://www.youtube.com/watch?v=dqxWSd39480\",\"https://www.youtube.com/watch?v=vbuCrajkpTo\",\"https://www.youtube.com/watch?v=tPjgtCdxWVY\"]', '2026-04-01 02:00:14.382', '2025-09-19 01:03:19.434', 1374, NULL, 1, 1985, 'NOSSA HISTÓRIA DESDE 1985, COM MUITA DEDICAÇÃO PARA TORNAR A MODA BÁSICA ACESSÍVEL PARA TODO O BRASIL. A TACO é uma história que alcançou importante crescimento em 40 anos de existência, tornando-se uma empresa de vanguarda e a líder em moda básica. Com um estilo que veio das ruas, uma linguagem própria e inovadora, a TACO criou sua reputação de sucesso e confiança pela qualidade dos seus produtos, pelo preço acessível e bom atendimento. PRESENÇA NACIONAL A TACO está presente em todas as regiões do país, com mais de 120 pontos de vendas espalhados por todo o território nacional. Nossa logística é eficaz e entregamos em todo o Brasil com consistência e agilidade. NOSSOS DIFERENCIAIS MODELO SELL OUT O royalty é cobrado apenas se o franqueado vender, garantindo transparência e impulsionando o desempenho da franquia. MARCA SÓLIDA E EXPERIENTE Com 40 anos de história, a TACO tem 120 lojas em todo o Brasil e opera diretamente a metade delas. Diversos franqueados operam há mais de 20 anos, evidenciando a solidez e a consistência do negócio. ESTOQUE INTELIGENTE Tecnologia exclusiva de BI que dispensa showroom, garantindo reposição automática, eficiente e assertiva do mix de produtos na loja. MODA BÁSICA Nossos produtos possuem alta demanda e venda ao longo do ano todo, independentemente de coleções ou tendências passageiras. FUNDO DE PROPAGANDA Investimento 100% focado na divulgação local, com apoio e suporte especializado de marketing da TACO, sem custos adicionais. CARTÃO TACO Solução financeira exclusiva que amplia o crédito, o poder de compra ao consumidor e fideliza os clientes, sem risco para o franqueado.', NULL, 'RIO DE JANEIRO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/3033f4bc-99c7-4784-9161-97a6706903e1.png', 114, NULL, NULL, '2025-10-25 00:00:07.000', 'https://franquias.portaldofranchising.com.br/franquia-taco/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
