INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmhk2ejhi0004eh0su2a6xzcz', 'ACADEMIA DO ROCK', 'academia-do-rock', NULL, 'Educação', 'EDUCAÇÃO', 'Escola de Música. Aulas de violão, guitarra, baixo, bateria, gaita de boca, piano, teclado, ukulele e canto, prática de bandas e eventos.', 2015, 2025, '[\"https://www.youtube.com/watch?v=f-yxp7_68eI\",\"https://www.youtube.com/watch?v=LQ1sUzC5j6c\",\"https://www.youtube.com/watch?v=-C4y-17XG9I\",\"https://www.youtube.com/watch?v=0V4ZMvmAYs0\",\"https://www.youtube.com/watch?v=q7xTW6DDefw\"]', '2026-04-01 02:00:14.833', '2025-11-04 01:24:31.014', 1425, 'ee8fc575-ddee-43fe-bec8-b5f90fe96627', 1, 2014, 'Mais do que música, aqui ensinamos Rock’n’Roll! Desde cantar a tocar um instrumento, nossa missão é preparar o aluno para subir no palco e dar um verdadeiro show. Do Blues ao Rock, a nossa metodologia é voltada para despertar a paixão pela música e, mais do que isso, adquirir confiança para dominar seu instrumento em diversos níveis. Tudo isso praticando com outros alunos e aprendendo na prática a tocar em uma banda. Confira aí: Garagem É na garagem que tudo começa. Aqui, você vai entrar no mundo do rock com as primeiras noções musicais já na prática. Vai aprender as músicas que mais curte em aulas individuais, ou tocando com outros alunos do mesmo nível para começar a sentir o gostinho de estar em uma banda. Todo grande rock star um dia deu suas primeiras notas, agora é a sua vez. Stage É aqui que você vai começar as mostrar as técnicas que aprendeu, em um repertório consistente para subir no palco de verdade. Isso para você desenvolver mais confiança tanto em casa, quanto numa banda. Esse é módulo para aprimorar e afinar o seu talento para dar o próximo passo. Arena Aqui a coisa começa a ficar séria. Para quem já toca e domina melhor o instrumento, é a hora de focar em performance de palco. Você vai aprender todas as ferramentas de criação musical, técnicas de palco como execução, dinâmica e performance. É a partir daqui que você vira um profissional. Agora é só conquistar o mundo. Projeto de Banda Para tocar bem um instrumento não tem jeito: você precisa tocar em uma banda. Ela que vai te ajudar a desenvolver a sua técnica, bem como melhorar a sua performance, seu ouvido e a interação com outros músicos. Material Didático Todas as apostilas são contextualizadas no Rock. Elas contam a história do seu instrumento, seus principais ícones e, é claro, a teoria básica voltada para o tocar. Além disso, possuem exercícios para você desenvolver sua habilidade e praticar com confiança. Eventos semestrais Os eventos semestrais ajudam a integrar os alunos, além de colaborar para a troca de experiências entre eles. É por isso que a Academia do Rock oferece dois festivais de banda: o Rock Hour, para alunos de todas as idades e o Rock Kids para alunos até 13 anos. Assim, além das aulas práticas e teóricas, todos podem ganhar confiança e aprender ainda mais em apresentações com plateias de verdade. Aulas On-line A Academia do Rock pode te ensinar a ser um roqueiro onde você estiver. Nas modalidades EAD, ou Videoconferência, é possível ter acesso aos mesmos métodos e apostilas que nas aulas presenciais, além dos mesmos professores. Informe-se e faça sua matrícula. Não deixe a distância atrapalhar o seu sonho.', NULL, 'PARANÁ', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/f62be58a-d972-47f8-8a29-c878a14487d4.png', 4, NULL, NULL, '2026-01-09 15:46:14.000', 'https://franquias.portaldofranchising.com.br/franquia-academia-do-rock/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '395000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
