INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmimopv5k026feh0swr927yxf', 'BEAUTYPARIS', 'beautyparis', NULL, 'Saúde, Beleza e Bem Estar', 'COSMÉTICOS E PERFUMARIA', 'Centro de Distribuição de Cosméticos e Perfumaria', 2014, 2025, NULL, '2026-04-01 02:00:15.101', '2025-12-01 02:04:25.591', 1548, NULL, 1, 2011, 'A EMPRESA: A marca BeautyParis já é bem conhecida do mercado dos cosméticos profissionais. Nossos produtos são fabricados a partir de extratos naturais e foram lançados e comercializados junto ao mercado de profissionais (salões de cabeleireiros), em todo o Brasil desde o ano de 2011. A aceitação da marca e seus produtos foram espetaculares de forma que a marca decidiu lançar uma linha destinada aos consumidores finais. Com o mesmo carinho, dedicação e profissionalismo, a marca BeautyParis se preparou para se lançar no mercado de franquias. Isso porque o conhecimento de cada passo do processo de criação dos produtos bem como dos seus lançamentos, observando o Feedback do mercado, testando formas comerciais utilizando-se dos salões de cabeleireiros tradicionais são agora aproveitados e somados ao know-how da BeautyParis. O Sistema de Franquias da BeautyParis é fruto desse trabalho de “laboratório” realizado junto aos cabeleireiros de todo o país. Assim os franqueados da Rede BeautyParis podem se beneficiar de todo o conhecimento e experiência da marca. A FRANQUIA A Franquia BeautyParis destaca-se pelo nicho de mercado em que está inserida: Tratamento de Cabelos! Contudo, não desprezamos as outras áreas do segmento, como a perfumaria, maquiagem e linha de produtos para o corpo. Isso porque a marca pretende atender os clientes em todas as suas necessidades o que além de se posicionar como uma marca completa, também agrega valor ao negócio franqueado, vez que eleva consideravelmente o valor do ticket de compras, gerando mais lucros para o franqueado. Além disso, a marca está em constante desenvolvimento de novos produtos e prevê o lançamento de mais 50 (cinquenta) novos produtos ainda no ano de 2014. A BeautyParis inova também no formato da operação, lançando as Lojas com Salão de Beleza, onde a cliente trata do seu cabelo como num salão de cabeleireiro comum, porém sendo atendida não por cabeleireiros comuns, mas por técnicos em cabelos. Ela trata do cabelo no salão e ainda leva pra casa os produtos da mesma linha para continuar o tratamento em casa, e isso proporciona um resultado mais duradouro para os seus cabelos.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/2ad5ed48-4868-49ef-a98d-a4bf81bb52e7.png', 1, NULL, NULL, '2025-12-15 07:08:40.000', 'https://franquias.portaldofranchising.com.br/franquia-beautyparis/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '68500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmipjeoan0001eh0soecs4x3n', 'VERIDIANA QUIRINO SEMJOIAS', 'veridiana-quirino-semjoias', NULL, 'Moda', 'ACESSÓRIOS PESSOAIS', 'Venda varejo através de lojas físicas Venda direta Atacado', 2023, 2025, NULL, '2026-04-01 02:00:15.112', '2025-12-03 01:59:03.935', 1550, NULL, 1, 2007, '', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/dc98d9f6-1488-46d5-a5d1-0aa3fd6a4969.png', 628, NULL, NULL, '2025-12-02 18:24:38.000', 'https://franquias.portaldofranchising.com.br/franquia-veridiana-quirino-semjoias-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmiqytcrj0008eh0sqj6r23i1', 'Maislaser by Ana Hickmann', 'maislaser-by-ana-hickmann', NULL, 'Saúde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'A Maislaser by Ana Hickmann é uma franquia lucrativa e consolidada em depilação e estética a laser, com operação simplificada, tecnologia exclusiva e rentabilidade acima de 30%, a maior do mercado!', 2018, 2019, '[\"https://www.youtube.com/watch?v=3-PcvjQYweY\"]', '2026-04-01 02:00:15.126', '2025-12-04 01:58:09.247', 1551, NULL, 1, 2018, 'A Maislaser by Ana Hickmann é uma rede de clínicas reconhecida pela excelência em depilação e estética a laser, combinando tecnologia exclusiva e resultados comprovados. Nossos tratamentos são seguros, confortáveis e eficazes para todos os tons de pele, inclusive as bronzeadas. Depilação a laser: O equipamento exclusivo da Maislaser (Maistech) reúne as três principais tecnologias do mercado com três comprimentos de ondas que entregam melhor resultado e produtividade. MAIS seguro e confortável MAIS eficaz / 1800W MAIS econômico MAIS rapidez na aplicação MAIS autoestima e bem-estar Tratamentos dermato estéticos: A Maislaser também realiza mais de 22 protocolos para tratamentos dermato estéticos em todo o corpo. O equipamento exclusivo utiliza o laser Ndyag e atende os procedimentos mais procurados, como remoção de tatuagem e micropigmentação, clareamento íntimo e de manchas, tratamento para acne, melasma, rosácea, estrias, olheiras, cicatrizes, Peeling de Hollywood e muito mais. Os sócios: *Sidney Kalaes: presidente do Grupo Kalaes (Holding Multissetorial de Franquias), tem formação em administração de empresas e mais de 31 anos de experiência como líder, master e fundador de várias marcas de sucesso no mercado. *Ana Hickmann: apresentadora e empresária de sucesso que traz para a Maislaser muita credibilidade, força, conhecimento, valor e exposição, proporcionando diferenciais e crescimento aos envolvidos no negócio. *Wlamir Bello: fundador da rede Maislaser, empresário especialista em gestão empresarial, estratégia de negócios e marketing. Tem MBA em gestão empresarial e graduação em publicidade e propaganda.', NULL, 'SÃO PAULO', 1, 'https://apifranchise.mindconsulting.com.br/uploads/franchises/de3f1ab8-72d5-492e-a445-a64488e82d23.jpg', 195, NULL, NULL, '2026-02-23 14:02:37.000', 'https://franquias.portaldofranchising.com.br/franquia-maislaser-by-ana-hickmann-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, NULL, '361000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
